      real function ran183(ix,iy,iz)
!
!     Algorithm AS 183 Appl. Statist. (1982) vol.31, no.2
!
!     Returns a pseudo-random number rectangularly distributed
!     between 0 and 1.   The cycle length is 6.95E+12 (See page 123
!     of Applied Statistics (1984) vol.33), not as claimed in the
!     original article.
!
!     IX, IY and IZ should be set to integer values between 1 and
!     30000 before the first entry.
!
!     Integer arithmetic up to 30323 is required.
!
      integer ix, iy, iz
!
      ix = 171 * mod(ix, 177) - 2 * (ix / 177)
      iy = 172 * mod(iy, 176) - 35 * (iy / 176)
      iz = 170 * mod(iz, 178) - 63 * (iz / 178)
!
      if (ix .lt. 0) ix = ix + 30269
      if (iy .lt. 0) iy = iy + 30307
      if (iz .lt. 0) iz = iz + 30323
!
!     If integer arithmetic up to 5212632 is available, the preceding
!     6 statements may be replaced by:
!
!     ix = mod(171 * ix, 30269)
!     iy = mod(172 * iy, 30307)
!     iz = mod(170 * iz, 30323)
!
      ran183 = mod(float(ix) / 30269. + float(iy) / 30307. +   &
                              float(iz) / 30323., 1.0)
      return
      end
      FUNCTION RANDDP(R)
!CCCC RENAME TO AVOID CONFLICT WITH INTRINSIC RAND FUNCTION
!CCCC FUNCTION RAND(R)
!***BEGIN PROLOGUE  RAND
!***DATE WRITTEN   770401   (YYMMDD)
!***REVISION DATE  820801   (YYMMDD)
!***CATEGORY NO.  L6A21
!***KEYWORDS  RANDOM NUMBER,SPECIAL FUNCTION,UNIFORM
!***AUTHOR  FULLERTON, W., (LANL)
!***PURPOSE  Generates a uniformly distributed random number.
!***DESCRIPTION
!
!      This pseudo-random number generator is portable among a wide
! variety of computers.  RAND(R) undoubtedly is not as good as many
! readily available installation dependent versions, and so this
! routine is not recommended for widespread usage.  Its redeeming
! feature is that the exact same random numbers (to within final round-
! off error) can be generated from machine to machine.  Thus, programs
! that make use of random numbers can be easily transported to and
! checked in a new environment.
!      The random numbers are generated by the linear congruential
! method described, e.g., by Knuth in Seminumerical Methods (p.9),
! Addison-Wesley, 1969.  Given the I-th number of a pseudo-random
! sequence, the I+1 -st number is generated from
!             X(I+1) = (A*X(I) + C) MOD M,
! where here M = 2**22 = 4194304, C = 1731 and several suitable values
! of the multiplier A are discussed below.  Both the multiplier A and
! random number X are represented in double precision as two 11-bit
! words.  The constants are chosen so that the period is the maximum
! possible, 4194304.
!      In order that the same numbers be generated from machine to
! machine, it is necessary that 23-bit integers be reducible modulo
! 2**11 exactly, that 23-bit integers be added exactly, and that 11-bit
! integers be multiplied exactly.  Furthermore, if the restart option
! is used (where R is between 0 and 1), then the product R*2**22 =
! R*4194304 must be correct to the nearest integer.
!      The first four random numbers should be .0004127026,
! .6750836372, .1614754200, and .9086198807.  The tenth random number
! is .5527787209, and the hundredth is .3600893021 .  The thousandth
! number should be .2176990509 .
!      In order to generate several effectively independent sequences
! with the same generator, it is necessary to know the random number
! for several widely spaced calls.  The I-th random number times 2**22,
! where I=K*P/8 and P is the period of the sequence (P = 2**22), is
! still of the form L*P/8.  In particular we find the I-th random
! number multiplied by 2**22 is given by
! I   =  0  1*P/8  2*P/8  3*P/8  4*P/8  5*P/8  6*P/8  7*P/8  8*P/8
! RAND=  0  5*P/8  2*P/8  7*P/8  4*P/8  1*P/8  6*P/8  3*P/8  0
! Thus the 4*P/8 = 2097152 random number is 2097152/2**22.
!      Several multipliers have been subjected to the spectral test
! (see Knuth, p. 82).  Four suitable multipliers roughly in order of
! goodness according to the spectral test are
!    3146757 = 1536*2048 + 1029 = 2**21 + 2**20 + 2**10 + 5
!    2098181 = 1024*2048 + 1029 = 2**21 + 2**10 + 5
!    3146245 = 1536*2048 +  517 = 2**21 + 2**20 + 2**9 + 5
!    2776669 = 1355*2048 + 1629 = 5**9 + 7**7 + 1
!
!      In the table below LOG10(NU(I)) gives roughly the number of
! random decimal digits in the random numbers considered I at a time.
! C is the primary measure of goodness.  In both cases bigger is better.
!
!                   LOG10 NU(I)              C(I)
!       A       I=2  I=3  I=4  I=5    I=2  I=3  I=4  I=5
!
!    3146757    3.3  2.0  1.6  1.3    3.1  1.3  4.6  2.6
!    2098181    3.3  2.0  1.6  1.2    3.2  1.3  4.6  1.7
!    3146245    3.3  2.2  1.5  1.1    3.2  4.2  1.1  0.4
!    2776669    3.3  2.1  1.6  1.3    2.5  2.0  1.9  2.6
!   Best
!    Possible   3.3  2.3  1.7  1.4    3.6  5.9  9.7  14.9
!
!             Input Argument --
! R      If R=0., the next random number of the sequence is generated.
!        If R .LT. 0., the last generated number will be returned for
!          possible use in a restart procedure.
!        If R .GT. 0., the sequence of random numbers will start with
!          the seed R mod 1.  This seed is also returned as the value of
!          RAND provided the arithmetic is done exactly.
!
!             Output Value --
! RAND   a pseudo-random number between 0. and 1.
!***REFERENCES  (NONE)
!***ROUTINES CALLED  (NONE)
!***END PROLOGUE  RAND
      DATA IA1, IA0, IA1MA0 /1536, 1029, 507/
      DATA IC /1731/
      DATA IX1, IX0 /0, 0/
!***FIRST EXECUTABLE STATEMENT  RAND
      IF (R.LT.0.) GO TO 10
      IF (R.GT.0.) GO TO 20
!
!           A*X = 2**22*IA1*IX1 + 2**11*(IA1*IX1 + (IA1-IA0)*(IX0-IX1)
!                   + IA0*IX0) + IA0*IX0
!
      IY0 = IA0*IX0
      IY1 = IA1*IX1 + IA1MA0*(IX0-IX1) + IY0
      IY0 = IY0 + IC
      IX0 = MOD (IY0, 2048)
      IY1 = IY1 + (IY0-IX0)/2048
      IX1 = MOD (IY1, 2048)
!
 10   RANDDP = IX1*2048 + IX0
      RANDDP = RANDDP / 4194304.
      RETURN
!
 20   IX1 = INT(AMOD(R,1.)*4194304. + 0.5)
      IX0 = MOD (IX1, 2048)
      IX1 = (IX1-IX0)/2048
      GO TO 10
!
      END FUNCTION RANDDP
      SUBROUTINE RANERR(X,Y,N,IWRITE,TEMP1,MAXNXT,YOUT,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE SAMPLE RANDOM ERROR
!              QUANTITY BETWEEN TWO SETS OF DATA.  THE RANDOM ERROR
!              QUANTITY IS DEFINED AS:
!
!                 [(X(i) - Y(i) - (Xmed - Ymed)]
!
!              BETWEEN THE 2 SETS OF DATA IN THE INPUT VECTORS X AND Y.
!              THE SAMPLE RANDOM ERROR QUANTITY WILL BE A SINGLE
!              PRECISION VALUE.
!
!              NOTE THAT THE X AND Y VALUES ARE PAIRED.  THE
!              RANDOM ERROR QUANTITY IS USED IN TWO SAMPLE
!              PROFICENCY STUDIES.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED) OBSERVATIONS
!                                WHICH CONSTITUTE THE FIRST SET
!                                OF DATA.
!                     --Y      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED) OBSERVATIONS
!                                WHICH CONSTITUTE THE SECOND SET
!                                OF DATA.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X, OR EQUIVALENTLY,
!                                THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR Y.
!     OUTPUT ARGUMENTS--YOUT   = THE SINGLE PRECISION VECTOR OF THE
!                                COMPUTED SAMPLE RANDOM ERROR QUANTITIES
!                                BETWEEN THE 2 SETS OF DATA
!                                IN THE INPUT VECTORS X AND Y.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE RANDOM ERROR QUANTITIESY BETWEEN THE 2 SETS
!             OF DATA IN THE INPUT VECTORS X AND Y.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--MEDIAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--"Standard Practice for Statistical Analysis of
!                 One-Sample and Two-Sample Interlaboratory Proficiency
!                 Testing Programs", 2006, ASTM International, 100 Barr
!                 Harbor Drive, PO BOX C700, West Conshohoceken, PA
!                 19428-2959, USA.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGYS
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGYS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2014/12
!     ORIGINAL VERSION--DECEMBER  2014.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(*)
      DIMENSION TEMP1(*)
      DIMENSION YOUT(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='RANE'
      ISUBN2='RR  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'NERR')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF RANERR--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,N
   52   FORMAT('IBUGA3,N = ',A4,2X,I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
         WRITE(ICOUT,56)I,X(I),Y(I)
   56    FORMAT('I,X(I),Y(I) = ',I8,2G15.7)
         CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               *******************************************
!               **  COMPUTE THE RANDOM ERROR QUANTITY    **
!               *******************************************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.LT.1)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN RANDOM ERROR QUANTITY--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE RESPONSE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      IS LESS THAN 1.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE NUMBER OF OBSERVATIONS HERE = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!               ************************************************
!               **  STEP 2--                                  **
!               **  COMPUTE THE RANDOM ERROR QUANTITIES.      **
!               ************************************************
!
      CALL MEDIAN(X,N,IWRITE,TEMP1,MAXNXT,XMED,IBUGA3,IERROR)
      CALL MEDIAN(Y,N,IWRITE,TEMP1,MAXNXT,YMED,IBUGA3,IERROR)
      XYMED=XMED - YMED
      DO 200 I=1,N
        YOUT(I)=(X(I) - Y(I)) - XYMED
  200 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF RANERR--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR,XMED,YMED
 9012   FORMAT('IERROR,XMED,YMED = ',A4,2X,2G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 9013 I=1,N
          WRITE(ICOUT,9015)I,YOUT(I)
 9015     FORMAT('I,YOUT(I) = ',I8,2X,G15.7)
          CALL DPWRST('XXX','BUG ')
 9013   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE RANERR
      SUBROUTINE RANGDP(X,N,IWRITE,XRANGE,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE
!              SAMPLE RANGE
!              OF THE DATA IN THE INPUT VECTOR X.
!              THE SAMPLE RANGE = SAMPLE MAX - SAMPLE MIN.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XRANGE = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE RANGE.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE RANGE.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--KENDALL AND STUART, THE ADVANCED THEORY OF
!                 STATISTICS, VOLUME 1, EDITION 2, 1963, PAGE 338.
!               --DAVID, ORDER STATISTICS, 1970, PAGE 10-11.
!               --SNEDECOR AND COCHRAN, STATISTICAL METHODS,
!                 EDITION 6, 1967, PAGE 39.
!               --DIXON AND MASSEY, INTRODUCTION TO STATISTICAL
!                 ANALYSIS, EDITION 2, 1957, PAGE 21.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--JUNE      1972.
!     UPDATED         --JUNE      1974.
!     UPDATED         --APRIL     1975.
!     UPDATED         --SEPTEMBER 1975.
!     UPDATED         --NOVEMBER  1975.
!     UPDATED         --JUNE      1979.
!     UPDATED         --AUGUST    1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --NOVEMBER  2009. RENAME "RANGE" TO "RANGDP".  THIS
!                                       IS SIMPLY TO AVOID COMPILATION
!                                       ISSUES WITH VERSION 11 OF THE
!                                       INTEL COMPILER ON WINDOWS
!                                       (CONFLICTS WITH INTRINSIC
!                                       RANGE FUNCTION EVEN IF AN
!                                       EXTERNAL STATEMENT IS USED)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='RANG'
      ISUBN2='E   '
      IERROR='NO'
!
      XMIN=0.0
      XMAX=0.0
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF RANGE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,N
   52   FORMAT('IBUGA3,N = ',A4,2X,I10)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
         WRITE(ICOUT,56)I,X(I)
   56    FORMAT('I,X(I) = ',I8,G15.7)
         CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               *********************
!               **  COMPUTE RANGE  **
!               *********************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN RANGE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS IN THE RESPONSE ',   &
               'VARIABLE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,115)
  115   FORMAT('      MUST BE 1 OR LARGER.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE NUMBER OF OBSERVATIONS = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(N.EQ.1)THEN
        XRANGE=0.0
        GO TO 800
      ENDIF
!
      HOLD=X(1)
      DO 135 I=2,N
      IF(X(I).NE.HOLD)GO TO 139
  135 CONTINUE
      XRANGE=0.0
      GO TO 9000
  139 CONTINUE
!
!               **************************
!               **  STEP 2--            **
!               **  COMPUTE THE RANGE.  **
!               **************************
!
      XMIN=X(1)
      XMAX=X(1)
      DO 200 I=2,N
        IF(X(I).LT.XMIN)XMIN=X(I)
        IF(X(I).GT.XMAX)XMAX=X(I)
  200 CONTINUE
      XRANGE=XMAX-XMIN
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
  800 CONTINUE
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)N,XRANGE
  811   FORMAT('THE RANGE OF THE ',I8,' OBSERVATIONS = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF RANGE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)XMIN,XMAX,XRANGE,IERROR
 9014   FORMAT('XMIN,XMAX,XRANGE,IERROR = ',3G15.7,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE RANGDP
      SUBROUTINE RANK(X,N,IWRITE,XR,XS,MAXOBV,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE RANKS (IN ASCENDING ORDER)
!              THE N ELEMENTS OF THE SINGLE PRECISION VECTOR X,
!              AND PUTS THE RESULTING N RANKS INTO THE
!              SINGLE PRECISION VECTOR XR.
!     NOTE--THIS ROUTINE IN JJF8 HAS BEEN MODIFIED
!           FOR DATAPLOT
!           FROM THE SAME-NAME SUBROUTINE IN JJF6 IN 3 IMPORTANT WAYS--
!           1)  THE UPPER LIMIT (IUPPER) HAS BEEN
!               REDUCED FROM 7500 TO 1000
!           2)  THE VECTOR XS HAS HAD ITS DIMENSION
!               CHANGED FROM 7500 TO 1000.
!           3)  THE VECTOR XS HAS BEEN TAKEN OUT OF COMMON.
!              THIS SUBROUTINE GIVES THE DATA ANALYST
!              THE ABILITY TO (FOR EXAMPLE) RANK THE DATA
!              PRELIMINARY TO CERTAIN DISTRIBUTION-FREE
!              ANALYSES.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                OBSERVATIONS TO BE RANKED.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XR     = THE SINGLE PRECISION VECTOR
!                                INTO WHICH THE RANKS
!                                FROM X WILL BE PLACED.
!     OUTPUT--THE SINGLE PRECISION VECTOR XR
!             CONTAINING THE RANKS
!             (IN ASCENDING ORDER)
!             OF THE VALUES
!             IN THE SINGLE PRECISION VECTOR X.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THE MAXIMUM ALLOWABLE VALUE OF N
!                   FOR THIS SUBROUTINE IS 7500.
!     OTHER DATAPAC   SUBROUTINES NEEDED--SORT.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     COMMENT--THE RANK OF THE FIRST ELEMENT
!              OF THE VECTOR X
!              WILL BE PLACED IN THE FIRST POSITION
!              OF THE VECTOR XR,
!              THE RANK OF THE SECOND ELEMENT
!              OF THE VECTOR X
!              WILL BE PLACED IN THE SECOND POSITION
!              OF THE VECTOR XR,
!              ETC.
!     COMMENT--THE SMALLEST ELEMENT IN THE VECTOR X
!              WILL HAVE A RANK OF 1 (UNLESS TIES EXIST).
!              THE LARGEST ELEMENT IN THE VECTOR X
!              WILL HAVE A RANK OF N (UNLESS TIES EXIST).
!     COMMENT--ALTHOUGH RANKS ARE USUALLY (UNLESS TIES EXIST)
!              INTEGRAL VALUES FROM 1 TO N, IT IS TO BE
!              NOTED THAT THEY ARE OUTPUTED AS SINGLE
!              PRECISION INTEGERS IN THE SINGLE PRECISION
!              VECTOR XR.
!              XR IS SINGLE PRECISION SO AS TO BE
!              CONSISTENT WITH THE FACT THAT ALL
!              VECTOR ARGUMENTS IN ALL OTHER
!              DATAPAC SUBROUTINES ARE SINGLE PRECISION;
!              BUT MORE IMPORTANTLY, BECAUSE TIES FREQUENTLY
!              DO EXIST IN DATA SETS AND SO SOME OF THE
!              RESULTING RANKS WILL BE NON-INTEGRAL
!              AND SO THE OUTPUT VECTOR OF RANKS MUST NECESSARILY
!              BE SINGLE PRECISION AND NOT INTEGER.
!     COMMENT--THE INPUT VECTOR X REMAINS UNALTERED.
!     COMMENT--THE FIRST AND THIRD ARGUMENTS IN THE
!              CALLING SEQUENCE MAY
!              BE IDENTICAL; THAT IS, AN 'IN PLACE'
!              RANKING IS PERMITTED.
!              THE CALLING SEQUENCE
!              CALL RANK(X,N,X) IS VALID, IF DESIRED.
!     COMMENT--THE SORTING ALGORTHM USED HEREIN
!              IS THE QUICKSORT.
!              THIS ALGORTHIM IS EXTREMELY FAST AS THE
!              FOLLOWING TIME TRIALS INDICATE.
!              THESE TIME TRIALS WERE CARRIED OUT ON THE
!              UNIVAC 1108 EXEC 8 SYSTEM AT NBS
!              IN AUGUST OF 1974.
!              BY WAY OF COMPARISON, THE TIME TRIAL VALUES
!              FOR THE EASY-TO-PROGRAM BUT EXTREMELY
!              INEFFICIENT BUBBLE SORT ALGORITHM HAVE
!              ALSO BEEN INCLUDED--
!              NUMBER OF RANDOM         QUICKSORT       BUBBLE SORT
!               NUMBERS SORTED
!                N = 10                 .002 SEC          .002 SEC
!                N = 100                .011 SEC          .045 SEC
!                N = 1000               .141 SEC         4.332 SEC
!                N = 3000               .476 SEC        37.683 SEC
!                N = 10000             1.887 SEC      NOT COMPUTED
!     REFERENCES--CACM MARCH 1969, PAGE 186 (QUICKSORT ALGORITHM
!                 BY RICHARD C. SINGLETON).
!               --CACM JANUARY 1970, PAGE 54.
!               --CACM OCTOBER 1970, PAGE 624.
!               --JACM JANUARY 1961, PAGE 41.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--JUNE      1972.
!     UPDATED         --JANUARY   1975.
!     UPDATED         --NOVEMBER  1975.
!     UPDATED         --JANUARY   1977.
!     UPDATED         --MARCH     1979.
!     UPDATED         --AUGUST    1981.
!     UPDATED         --MARCH     1982.
!     UPDATED         --MAY       1982.
!     UPDATED         --JUNE      1990. TEMPORARY ARRAYS TO GARBAGE COMMON
!     UPDATED         --JANUARY   2007. PASS XS AS ARGUMENT
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION XR(*)
      DIMENSION XS(MAXOBV)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='RANK'
      ISUBN2='    '
      IERROR='NO'
      IUPPER=MAXOBV
!
      K=0
      RPREV=0.0
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF RANK--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)N,IUPPER,IBUGA3
   53   FORMAT('N,IUPPER,IBUGA3 = ',2I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               **********************************
!               **  COMPUTE THE RANKED VALUES.  **
!               **********************************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.LT.1 .OR. N.GT.IUPPER)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN RANK--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)IUPPER
  113   FORMAT('      THE NUMBER OF OBSERVATIONS IS LESS THAN 1 OR ',   &
               'OR LARGER THAN ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,118)N
  118   FORMAT('      THE NUMBER OF OBSERVATIONS IS ',I8)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(N.EQ.1)THEN
        XR(1)=1.0
        GO TO 9000
      ENDIF
!
      HOLD=X(1)
      DO 133 I=2,N
        IF(X(I).NE.HOLD)GO TO 139
  133 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,135)
  135 FORMAT('***** WARNING IN RANK--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,136)HOLD
  136 FORMAT('      THE RESPONSE VARIABLE HAS ALL ELEMENTS = ',G15.7)
      CALL DPWRST('XXX','BUG ')
      AVRANK=(AN+1.0)/2.0
      DO 137 I=1,N
        XR(I)=AVRANK
  137 CONTINUE
      GO TO 9000
  139 CONTINUE
!
!               ***************************************************
!               **  STEP 2--                                     **
!               **  FIRST SORT THE DATA FROM THE INPUT VECTOR X  **
!               **  INTO THE INTERMEDIATE STORAGE VECTOR XS.     **
!               ***************************************************
!
      CALL SORT(X,N,XS)
!
!               ****************************************************************
!               **  STEP 3--
!               **  NOW DETERMINE THE RANKS.
!               **  THE BASIC ALGORITHM IS TO TAKE A GIVEN ELEMENT
!               **  IN THE ORIGINAL INPUT VECTOR X,
!               **  AND SCAN THE SORTED VALUES IN THE XS VECTOR
!               **  UNTIL A MATCH IS FOUND;
!               **  WHEN A MATCH IS FOUND, THEN THE RANK FOR THAT
!               **  VALUE IN THE XS VECTOR IS DETERMINED.
!               **  THAT RANK IS THEN WRITTEN INTO THAT POSITION
!               **  IN THE OUTPUT Y VECTOR WHICH CORRESPONDS TO THE POSITION OF
!               **  GIVEN ELEMENT OF INTEREST IN THE ORIGINAL X VECTOR.
!               **  THE CODE IS LENGTHENED FROM THIS BASIC ALGORITHM
!               **  BY A SECTION WHICH CUTS DOWN THE SEARCH IN THE XS VECTOR,
!               **  AND BY A SECTION WHICH OBVIATES (UNDER CERTAIN CIRCUMSTANCES
!               **  THE NEED FOR RECALCULATING THE RANK OF AN ELEMENT IN XS.
!               ****************************************************************
!
      NM1=N-1
      XPREV=X(1)
      DO 700 I=1,N
        JMIN=1
        IF(X(I).GT.XPREV)THEN
          JMIN=K
          IF(JMIN.LT.N)GO TO 790
          IF(JMIN.EQ.N)GO TO 820
!
          IERROR='YES'
          IBRAN=1
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,111)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,781)IBRAN
  781     FORMAT('      IMPOSSIBLE BRANCH CONDITION AT BRANCH POINT = ',   &
                 I8)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,782)JMIN
  782     FORMAT('JMIN = ',I8)
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ENDIF
        IF(I.EQ.1)GO TO 790
        IF(X(I).EQ.XPREV)THEN
          XPREV=X(I)
          XR(I)=RPREV
          GO TO 880
        ENDIF
!
  790   CONTINUE
        DO 800 J=JMIN,NM1
          IF(X(I).NE.XS(J))GO TO 800
          JP1=J+1
          DO 900 K=JP1,N
            IF(XS(K).NE.XS(J))GO TO 950
  900     CONTINUE
          K=N+1
  950     CONTINUE
          AVRANK=J+K-1
          AVRANK=AVRANK/2.0
          XPREV=X(I)
          XR(I)=AVRANK
          GO TO 880
  800   CONTINUE
  820   CONTINUE
        J=N
        K=N+1
        IF(X(I).EQ.XS(J))GO TO 850
!
        IERROR='YES'
        IBRAN=2
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,881)IBRAN
  881   FORMAT('      IMPOSSIBLE BRANCH CONDITION AT BRANCH POINT = ',   &
               I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,882)X(I),XS(I)
  882   FORMAT('X(I) = ',E15.7,'   XS(J) = ',E15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
!
  850   CONTINUE
        XPREV=X(I)
        XR(I)=N
  880   CONTINUE
        RPREV=XR(I)
  700 CONTINUE
!
      XMIN=XS(1)
      XMAX=XS(N)
!
!               ******************************
!               **  STEP 4--                **
!               **  WRITE OUT A FEW LINES   **
!               **  OF SUMMARY INFORMATION  **
!               **  ABOUT THE CODING.       **
!               ******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        AI=1
        WRITE(ICOUT,912)XS(1),AI
  912   FORMAT('THE MINIMUM (= ',E15.7,' ) HAS RANK ',F10.0)
        CALL DPWRST('XXX','BUG ')
        AI=N
        WRITE(ICOUT,913)XS(N),AI
  913   FORMAT('THE MAXIMUM (= ',E15.7,' ) HAS RANK ',F10.0)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF RANK--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA3,IERROR
 9012   FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        DO 9015 I=1,N
          WRITE(ICOUT,9016)I,X(I),XR(I),XS(I)
 9016     FORMAT('I,X(I),XR(I),XS(I) = ',I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
 9015   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE RANK
      SUBROUTINE RANKI(X,N,IWRITE,XR,XS,ITAG,MAXOBV,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE RANKS (IN ASCENDING ORDER)
!              THE N ELEMENTS OF THE SINGLE PRECISION VECTOR X,
!              AND PUTS THE RESULTING N RANKS INTO THE
!              SINGLE PRECISION VECTOR XR.
!
!              THIS IS A VARIANT OF RANK THAT HANDLES TIES
!              DIFFERENTLY.  FOR EXAMPLE, IT THERE IS A TIE BETWEEN
!              RANK 7 AND RANK 8, THE RANK SUBROUTINE WILL ASSIGN
!              A RANK OF 7.5 TO BOTH.  THIS ROUTINE WILL ASSIGN
!              A RANK OF 7 AND A RANK OF 8 (IT WILL MAINTAIN THE
!              ORIGINAL ORDER).  THE "RANK INDEX" IS TYPICALLY USED
!              AS AN INDEX TO ANOTHER VECTOR, SO WE WANT ALL RANKS
!              TO BE UNIQUE INTEGERS.
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                OBSERVATIONS TO BE RANKED.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XR     = THE SINGLE PRECISION VECTOR
!                                INTO WHICH THE RANKS
!                                FROM X WILL BE PLACED.
!     OUTPUT--THE SINGLE PRECISION VECTOR XR CONTAINING THE RANKS
!             (IN ASCENDING ORDER) OF THE VALUES
!             IN THE SINGLE PRECISION VECTOR X.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THE MAXIMUM ALLOWABLE VALUE OF N
!                   FOR THIS SUBROUTINE IS 7500.
!     OTHER DATAPAC   SUBROUTINES NEEDED--SORT.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     COMMENT--THE RANK OF THE FIRST ELEMENT OF THE VECTOR X
!              WILL BE PLACED IN THE FIRST POSITION OF THE VECTOR XR,
!              THE RANK OF THE SECOND ELEMENT OF THE VECTOR X WILL BE
!              PLACED IN THE SECOND POSITION OF THE VECTOR XR, ETC.
!     COMMENT--THE SMALLEST ELEMENT IN THE VECTOR X
!              WILL HAVE A RANK OF 1 AND
!              THE LARGEST ELEMENT IN THE VECTOR X
!              WILL HAVE A RANK OF N.
!     COMMENT--ALTHOUGH RANKS ARE USUALLY (UNLESS TIES EXIST)
!              INTEGRAL VALUES FROM 1 TO N, IT IS TO BE
!              NOTED THAT THEY ARE OUTPUTED AS SINGLE
!              PRECISION INTEGERS IN THE SINGLE PRECISION
!              VECTOR XR.
!              XR IS SINGLE PRECISION SO AS TO BE
!              CONSISTENT WITH THE FACT THAT ALL
!              VECTOR ARGUMENTS IN ALL OTHER
!              DATAPAC SUBROUTINES ARE SINGLE PRECISION;
!              BUT MORE IMPORTANTLY, BECAUSE TIES FREQUENTLY
!              DO EXIST IN DATA SETS AND SO SOME OF THE
!              RESULTING RANKS WILL BE NON-INTEGRAL
!              AND SO THE OUTPUT VECTOR OF RANKS MUST NECESSARILY
!              BE SINGLE PRECISION AND NOT INTEGER.
!     COMMENT--THE INPUT VECTOR X REMAINS UNALTERED.
!     COMMENT--THE FIRST AND THIRD ARGUMENTS IN THE
!              CALLING SEQUENCE MAY
!              BE IDENTICAL; THAT IS, AN 'IN PLACE'
!              RANKING IS PERMITTED.
!              THE CALLING SEQUENCE
!              CALL RANK(X,N,X) IS VALID, IF DESIRED.
!     COMMENT--THE SORTING ALGORTHM USED HEREIN
!              IS THE QUICKSORT.
!              THIS ALGORTHIM IS EXTREMELY FAST AS THE
!              FOLLOWING TIME TRIALS INDICATE.
!              THESE TIME TRIALS WERE CARRIED OUT ON THE
!              UNIVAC 1108 EXEC 8 SYSTEM AT NBS
!              IN AUGUST OF 1974.
!              BY WAY OF COMPARISON, THE TIME TRIAL VALUES
!              FOR THE EASY-TO-PROGRAM BUT EXTREMELY
!              INEFFICIENT BUBBLE SORT ALGORITHM HAVE
!              ALSO BEEN INCLUDED--
!              NUMBER OF RANDOM         QUICKSORT       BUBBLE SORT
!               NUMBERS SORTED
!                N = 10                 .002 SEC          .002 SEC
!                N = 100                .011 SEC          .045 SEC
!                N = 1000               .141 SEC         4.332 SEC
!                N = 3000               .476 SEC        37.683 SEC
!                N = 10000             1.887 SEC      NOT COMPUTED
!     REFERENCES--CACM MARCH 1969, PAGE 186 (QUICKSORT ALGORITHM
!                 BY RICHARD C. SINGLETON).
!               --CACM JANUARY 1970, PAGE 54.
!               --CACM OCTOBER 1970, PAGE 624.
!               --JACM JANUARY 1961, PAGE 41.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010.6
!     ORIGINAL VERSION--JUNE      2010.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
!
      DIMENSION X(*)
      DIMENSION XR(*)
      DIMENSION XS(*)
      INTEGER   ITAG(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='RANK'
      ISUBN2='I   '
      IERROR='NO'
!
      IUPPER=MAXOBV
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF RANK--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)IBUGA3,N,IUPPER
   53   FORMAT('IBUGA3,N,IUPPER = ',A4,2X,2I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
         WRITE(ICOUT,56)I,X(I)
   56    FORMAT('I,X(I) = ',I8,E15.7)
         CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               **********************************
!               **  COMPUTE THE RANKED VALUES.  **
!               **********************************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.LT.1 .OR. N.GT.IUPPER)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN RANK INDEX--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)IUPPER
  113   FORMAT('      THE NUMBER OF OBSERVATIONS IS LESS THAN ONE ',   &
               'OR LARGER THAN ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,118)N
  118   FORMAT('***** THE NUMBER OF OBSERVATIONS IS ',I8)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(N.EQ.1)THEN
        XR(1)=1.0
        GO TO 9000
      ENDIF
!
      HOLD=X(1)
      DO 135 I=2,N
      IF(X(I).NE.HOLD)GO TO 139
  135 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,136)
  136 FORMAT('***** WARNING IN RANK INDEX--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,138)HOLD
  138 FORMAT('      THE RESPONSE VARIABLE HAS ALL ELEMENTS = ',G15.7)
      CALL DPWRST('XXX','BUG ')
      DO 137 I=1,N
        XR(I)=REAL(I)
  137 CONTINUE
      GO TO 9000
  139 CONTINUE
!
!               ***************************************************
!               **  STEP 2--                                     **
!               **  FIRST SORT THE DATA FROM THE INPUT VECTOR X  **
!               **  INTO THE INTERMEDIATE STORAGE VECTOR XS.     **
!               ***************************************************
!
      CALL SORT(X,N,XS)
      DO 210 I=1,N
        ITAG(I)=0
  210 CONTINUE
!
!               ********************************************************
!               **  STEP 3--                                          **
!               **  NOW DETERMINE THE RANKS.                          **
!               **  THE BASIC ALGORITHM IS TO TAKE A GIVEN ELEMENT    **
!               **  IN THE ORIGINAL INPUT VECTOR X,                   **
!               **  AND SCAN THE SORTED VALUES IN THE XS VECTOR       **
!               **  UNTIL A MATCH IS FOUND;                           **
!               **  WHEN A MATCH IS FOUND, THEN THE RANK FOR THAT     **
!               **  VALUE IN THE XS VECTOR IS DETERMINED.             **
!               **  THAT RANK IS THEN WRITTEN INTO THAT POSITION      **
!               **  IN THE OUTPUT Y VECTOR WHICH CORRESPONDS TO THE   **
!               **  POSITION OF GIVEN ELEMENT OF INTEREST IN THE      **
!               **  ORIGINAL X VECTOR.  TIES ARE HANDLED BY           **
!               **  KEEPING A TAG VECTOR WHICH IDENTIFIES WHETHER A   **
!               **  MATCHED ELEMENT HAS BEEN PREVIOUSLY IDENTIFIED.   **
!               ********************************************************
!
      DO 700 I=1,N
        DO 800 J=1,N
          IF(X(I).EQ.XS(J) .AND. ITAG(J).EQ.0)THEN
            XR(I)=REAL(J)
            ITAG(J)=1
            GO TO 700
          ENDIF
  800   CONTINUE
  700 CONTINUE
!
      XMIN=XS(1)
      XMAX=XS(N)
!
!               ******************************
!               **  STEP 4--                **
!               **  WRITE OUT A FEW LINES   **
!               **  OF SUMMARY INFORMATION  **
!               **  ABOUT THE CODING.       **
!               ******************************
!
      IF(IFEEDB.EQ.'OFF')GO TO 990
      IF(IWRITE.EQ.'OFF')GO TO 990
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      AI=1
      WRITE(ICOUT,912)XS(1),AI
  912 FORMAT('THE MINIMUM (= ',E15.7,' ) HAS RANK ',F10.0)
      CALL DPWRST('XXX','BUG ')
      AI=N
      WRITE(ICOUT,913)XS(N),AI
  913 FORMAT('THE MAXIMUM (= ',E15.7,' ) HAS RANK ',F10.0)
      CALL DPWRST('XXX','BUG ')
  990 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF RANK--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA3,IERROR
 9012   FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)N
 9013   FORMAT('N = ',I8)
        CALL DPWRST('XXX','BUG ')
        DO 9015 I=1,N
         WRITE(ICOUT,9016)I,X(I),XR(I),XS(I)
 9016    FORMAT('I,X(I),XR(I),XS(I) = ',I8,3E15.7)
         CALL DPWRST('XXX','BUG ')
 9015  CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE RANKI
      SUBROUTINE RANK2(Y1,GROUP,N,IWRITE,Y2,TEMP1,TEMPR,XIDTEM,ITEMP1,   &
                       MAXOBV,   &
                       ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE RANKS BASED ON TWO VARIABLES
!     INPUT  ARGUMENTS--Y1     = THE SINGLE PRECISION VECTOR CONTAINING
!                                THE RESPONSE VARIABLE TO BE RANKED.
!                     --GROUP  = THE SINGLE PRECISION VECTOR CONTAINING
!                                THE GROUP-ID VARIABLE TO BE RANKED.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--Y2     = THE SINGLE PRECISION VECTOR
!                                CONTAINING THE RANKED VALUES OF
!                                THE RESPONSE VARIABLE.
!     OUTPUT--THE SINGLE PRECISION VECTORS Y2 CONTAINING
!             THE RANKED VECTORS.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     OTHER DATAPAC   SUBROUTINES NEEDED--RANK, SORT.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2008.12
!     ORIGINAL VERSION--NOVEMBER  2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION Y1(*)
      DIMENSION Y2(*)
      DIMENSION GROUP(*)
      DIMENSION TEMP1(*)
      DIMENSION TEMPR(*)
      DIMENSION XIDTEM(*)
!
      INTEGER ITEMP1(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='RANK'
      ISUBN2='2   '
      IERROR='NO'
      IWRITE='OFF'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'ANK2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF RANK2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3
   52   FORMAT('IBUGA3 = ',A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)N
   53   FORMAT('N = ',2I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,GROUP(I),Y1(I)
   56     FORMAT('I,GROUP(I),Y1(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!    ********************************************
!    **  STEP 1--                              **
!    **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!    ********************************************
!
      AN=N
!
      IF(N.LT.1)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN RANK2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      THE NUMBER OF RESPONSE VALUES IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,115)N
  115   FORMAT('      THE NUMBER OF RESPONSE VALUES IS ',I8)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(N.EQ.1)THEN
        Y2(1)=1.0
        GO TO 9000
      ENDIF
!
!     ***************************************************
!     **  STEP 2--                                     **
!     **  DETERMINE DISTINCT VALUES OF FIRST VARIABLE  **
!     **  (THE GROUP-ID VARIABLE)                      **
!     ***************************************************
!
      CALL DISTIN(GROUP,N,IWRITE,XIDTEM,NDIST,IBUGA3,IERROR)
      IF(N.EQ.NDIST)THEN
        DO 1010 I=1,N
          Y2(I)=1.0
 1010   CONTINUE
        GO TO 9000
      ELSEIF(NDIST.EQ.1)THEN
        CALL RANK(Y1,N,IWRITE,Y2,TEMP1,MAXOBV,IBUGA3,IERROR)
        GO TO 9000
      ENDIF
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'ANK2')THEN
        WRITE(ICOUT,1091)
 1091   FORMAT('AFTER DETERMINE DISTINCT VALUES OF VARIABLE ONE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1092)NDIST
 1092   FORMAT('NDIST = ',I8)
        CALL DPWRST('XXX','BUG ')
        DO 1099 I=1,NDIST
        WRITE(ICOUT,1093)I,XIDTEM(I)
 1093   FORMAT('I,XIDTEM(I) = ',I8,G15.7)
        CALL DPWRST('XXX','BUG ')
 1099   CONTINUE
      ENDIF
!
!     ****************************************************
!     **  STEP 3--                                      **
!     **  NOW RANK THE SECOND VARIABLE FOR COMMON       **
!     **  VALUES OF FIRST VARIABLE.                     **
!     ****************************************************
!
!
      CALL SORT(XIDTEM,NDIST,XIDTEM)
!
      DO 2110 ISET=1,NDIST
        HOLD=XIDTEM(ISET)
!
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'ANK2')THEN
          WRITE(ICOUT,2111)ISET,ISTRT,HOLD
 2111     FORMAT('AT 2110: ISET,ISTRT,HOLD = ',2I8,G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        ICNT=0
        DO 2120 I=1,N
          IF(GROUP(I).EQ.HOLD)THEN
            ICNT=ICNT+1
            TEMP1(ICNT)=Y1(I)
            ITEMP1(ICNT)=I
          ENDIF
 2120   CONTINUE
        CALL RANK(TEMP1,ICNT,IWRITE,TEMP1,TEMPR,MAXOBV,IBUGA3,IERROR)
        DO 2160 J=1,ICNT
          IINDX=ITEMP1(J)
          Y2(IINDX)=TEMP1(J)
 2160   CONTINUE
 2110 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'ANK2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF RANK2--')
        CALL DPWRST('XXX','BUG ')
        DO 9015 I=1,N
          WRITE(ICOUT,9016)I,GROUP(I),Y1(I),Y2(I)
 9016     FORMAT('I,GROUP(I),Y1(I),Y2(I) = ',I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
 9015   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE RANK2
      SUBROUTINE RANK3(Y1,GROUP1,GROUP2,N,IWRITE,Y2,   &
                       TEMP1,TEMPR,XIDTEM,XIDTE2,ITEMP1,   &
                       MAXOBV,   &
                       ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE RANKS BASED ON TWO VARIABLES
!     INPUT  ARGUMENTS--Y1     = THE SINGLE PRECISION VECTOR CONTAINING
!                                THE RESPONSE VARIABLE TO BE RANKED.
!                     --GROUP1 = THE SINGLE PRECISION VECTOR CONTAINING
!                                THE FIRST GROUP-ID VARIABLE TO BE
!                                RANKED.
!                     --GROUP2 = THE SINGLE PRECISION VECTOR CONTAINING
!                                THE SECOND GROUP-ID VARIABLE TO BE
!                                RANKED.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--Y2     = THE SINGLE PRECISION VECTOR
!                                CONTAINING THE RANKED VALUES OF
!                                THE RESPONSE VARIABLE.
!     OUTPUT--THE SINGLE PRECISION VECTORS Y2 CONTAINING
!             THE RANKED VECTOR.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     OTHER DATAPAC   SUBROUTINES NEEDED--RANK, SORT.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2008.12
!     ORIGINAL VERSION--DECEMBER  2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION Y1(*)
      DIMENSION Y2(*)
      DIMENSION GROUP1(*)
      DIMENSION GROUP2(*)
      DIMENSION TEMP1(*)
      DIMENSION TEMPR(*)
      DIMENSION XIDTEM(*)
      DIMENSION XIDTE2(*)
!
      INTEGER ITEMP1(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='RANK'
      ISUBN2='3   '
      IERROR='NO'
      IWRITE='OFF'
!
      N1=0
      N2=0
      NDIST=0
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'ANK3')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF RANK2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3
   52   FORMAT('IBUGA3 = ',A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)N
   53   FORMAT('N = ',2I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,GROUP1(I),GROUP2(I),Y1(I)
   56     FORMAT('I,GROUP1(I),GROUP2(I),Y1(I) = ',I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!    ********************************************
!    **  STEP 1--                              **
!    **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!    ********************************************
!
      AN=N
!
      IF(N.LT.1)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN RANK2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      THE NUMBER OF RESPONSE VALUES IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,115)N
  115   FORMAT('      THE NUMBER OF RESPONSE VALUES IS ',I8)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(N.EQ.1)THEN
        Y2(1)=1.0
        GO TO 9000
      ENDIF
!
!     ***************************************************
!     **  STEP 2--                                     **
!     **  DETERMINE DISTINCT VALUES OF FIRST VARIABLE  **
!     **  (THE GROUP-ID VARIABLE)                      **
!     ***************************************************
!
      CALL DISTIN(GROUP1,N,IWRITE,XIDTEM,NDIST1,IBUGA3,IERROR)
      CALL DISTIN(GROUP2,N,IWRITE,XIDTE2,NDIST2,IBUGA3,IERROR)
      IF(N1.EQ.NDIST1 .AND. N2.EQ.NDIST2)THEN
        DO 1010 I=1,N
          Y2(I)=1.0
 1010   CONTINUE
        GO TO 9000
      ELSEIF(NDIST1.EQ.1 .AND. NDIST2.EQ.1)THEN
        CALL RANK(Y1,N,IWRITE,Y2,TEMP1,MAXOBV,IBUGA3,IERROR)
        GO TO 9000
      ENDIF
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'ANK3')THEN
        WRITE(ICOUT,1091)
 1091   FORMAT('AFTER DETERMINE DISTINCT VALUES OF VARIABLE ONE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1092)NDIST
 1092   FORMAT('NDIST = ',I8)
        CALL DPWRST('XXX','BUG ')
        DO 1099 I=1,NDIST
        WRITE(ICOUT,1093)I,XIDTEM(I),XIDTE2(I)
 1093   FORMAT('I,XIDTEM(I),XIDTE2(I) = ',I8,2G15.7)
        CALL DPWRST('XXX','BUG ')
 1099   CONTINUE
      ENDIF
!
!     ****************************************************
!     **  STEP 3--                                      **
!     **  NOW RANK THE SECOND VARIABLE FOR COMMON       **
!     **  VALUES OF FIRST VARIABLE.                     **
!     ****************************************************
!
!
      CALL SORT(XIDTEM,NDIST1,XIDTEM)
      CALL SORT(XIDTE2,NDIST2,XIDTE2)
!
      DO 2110 ISET1=1,NDIST1
        HOLD1=XIDTEM(ISET1)
!
        DO 2120 ISET2=1,NDIST2
          HOLD2=XIDTEM(ISET2)
!
          IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'ANK3')THEN
            WRITE(ICOUT,2121)ISET1,ISET2,HOLD1,HOLD2
 2121       FORMAT('AT 2120: ISET1,ISET2,HOLD1,HOLD2 = ',2I8,2G15.7)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
          ICNT=0
          DO 2130 I=1,N
            IF(GROUP1(I).EQ.HOLD1 .AND. GROUP2(I).EQ.HOLD2)THEN
              ICNT=ICNT+1
              TEMP1(ICNT)=Y1(I)
              ITEMP1(ICNT)=I
            ENDIF
 2130     CONTINUE
          CALL RANK(TEMP1,ICNT,IWRITE,TEMP1,TEMPR,MAXOBV,   &
                    IBUGA3,IERROR)
          DO 2160 J=1,ICNT
            IINDX=ITEMP1(J)
            Y2(IINDX)=TEMP1(J)
 2160     CONTINUE
 2120   CONTINUE
 2110 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'ANK3')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF RANK3--')
        CALL DPWRST('XXX','BUG ')
        DO 9015 I=1,N
          WRITE(ICOUT,9016)I,GROUP1(I),GROUP2(I),Y1(I),Y2(I)
 9016     FORMAT('I,GROUP1(I),GROUP2(I),Y1(I),Y2(I) = ',   &
                 I8,4G15.7)
          CALL DPWRST('XXX','BUG ')
 9015   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE RANK3
      SUBROUTINE RANKCM(X,Y,N,IWRITE,XTEMP,YTEMP,XTEMP2,   &
      MAXNXT,XYRACM,   &
      IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE
!              RANK COMOVEMENT COEFFICIENT
!              BETWEEN THE 2 SETS OF DATA IN THE INPUT VECTORS X AND Y.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS
!                                WHICH CONSTITUTE THE FIRST SET
!                                OF DATA.
!                     --Y      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS
!                                WHICH CONSTITUTE THE SECOND SET
!                                OF DATA.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X, OR EQUIVALENTLY,
!                                THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR Y.
!     OUTPUT ARGUMENTS--XYRACM = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED RANK COMOVEMENT
!                                COEFFICIENT BETWEEN THE 2 SETS OF DATA
!                                IN THE INPUT VECTORS X AND Y.
!                                THIS SINGLE PRECISION VALUE
!                                WILL BE BETWEEN -1.0 AND 1.0
!                                (INCLUSIVELY).
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             RANK COMOVEMENT COEFFICIENT BETWEEN THE 2 SETS
!             OF DATA IN THE INPUT VECTORS X AND Y.
!     OTHER DATAPAC   SUBROUTINES NEEDED--RANK AND SORT.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--AN INDEX FOR COMOVEMENT OF TIME SEQUENCES
!                 WITH GEOPHYSICAL APPLICATIONS:  A WORKING PAPER
!                 (PENN STATE INTERFACE CONFERANCE ON ASTRONOMY
!                 AUGUST 11-14, 1991)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--91.8
!     ORIGINAL VERSION--AUGUST    1991.
!     UPDATED         --JANUARY   2007.  CALL LIST TO RANK
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRIT2
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DXI
      DOUBLE PRECISION DXIM1
      DOUBLE PRECISION DYI
      DOUBLE PRECISION DYIM1
      DOUBLE PRECISION DDELX
      DOUBLE PRECISION DDELY
      DOUBLE PRECISION DSUMX
      DOUBLE PRECISION DSUMY
      DOUBLE PRECISION DSUMXY
      DOUBLE PRECISION DSQRTX
      DOUBLE PRECISION DSQRTY
!
      DIMENSION X(*)
      DIMENSION Y(*)
!
      DIMENSION XTEMP(*)
      DIMENSION YTEMP(*)
      DIMENSION XTEMP2(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='RANK'
      ISUBN2='CM  '
      IERROR='NO'
!
      DN=0.0D0
      DSUMX=0.0D0
      DSUMY=0.0D0
      DSUMXY=0.0D0
!
      IF(IBUGA3.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF RANKCM--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGA3
   52 FORMAT('IBUGA3 = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)N
   53 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 55 I=1,N
      WRITE(ICOUT,56)I,X(I),Y(I)
   56 FORMAT('I,X(I),Y(I) = ',I8,2E15.7)
      CALL DPWRST('XXX','BUG ')
   55 CONTINUE
   90 CONTINUE
!
!               ********************************************
!               **  COMPUTE RANK COMOVEMENT  COEFFICIENT  **
!               ********************************************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(2.LE.N.AND.N.LE.MAXNXT)GO TO 119
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,111)
  111 FORMAT('***** ERROR IN RANKCM--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,112)
  112 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,113)
  113 FORMAT('      IN THE VARIABLE FOR WHICH')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,114)
  114 FORMAT('      THE RANK COMOVEMENT COEFFICIENT IS TO BE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,115)MAXNXT
  115 FORMAT('      MUST BE BETWEEN 2 AND ',I8,' (INCLUSIVELY).')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,116)
  116 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,117)N
  117 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS HERE = ',I8,   &
      '.')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
  119 CONTINUE
!
      IF(N.EQ.2)GO TO 120
      GO TO 129
  120 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,121)
  121 FORMAT('***** NON-FATAL DIAGNOSTIC IN RANKCM--',   &
      'THE THIRD INPUT ARGUMENT (N) HAS THE VALUE 2')
      CALL DPWRST('XXX','BUG ')
      XYRACM=0.0
      GO TO 9000
  129 CONTINUE
!
      HOLD=X(1)
      DO 135 I=2,N
      IF(X(I).NE.HOLD)GO TO 139
  135 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,136)HOLD
  136 FORMAT('***** NON-FATAL DIAGNOSTIC IN RANKCM--',   &
      'THE 1ST INPUT ARGUMENT (A VECTOR) HAS ALL ELEMENTS = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      XYRACM=0.0
      GO TO 9000
  139 CONTINUE
!
      HOLD=Y(1)
      DO 145 I=2,N
      IF(Y(I).NE.HOLD)GO TO 149
  145 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,146)HOLD
  146 FORMAT('***** NON-FATAL DIAGNOSTIC IN RANKCM--',   &
      'THE 2ND INPUT ARGUMENT (A VECTOR) HAS ALL ELEMENTS = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      XYRACM=0.0
      GO TO 9000
  149 CONTINUE
!
!               *************************************************
!               **  STEP 2--                                   **
!               **  COMPUTE THE RANK COMOVEMENT  COEFFICIENT.  **
!               *************************************************
!
      IWRIT2=IBUGA3
      CALL RANK(X,N,IWRIT2,XTEMP,XTEMP2,MAXNXT,IBUGA3,IERROR)
      CALL RANK(Y,N,IWRIT2,YTEMP,XTEMP2,MAXNXT,IBUGA3,IERROR)
!
      DN=N
      DSUMX=0.0D0
      DSUMY=0.0D0
      DSUMXY=0.0D0
      DO 300 I=2,N
      IM1=I-1
      DXI=XTEMP(I)
      DXIM1=XTEMP(IM1)
      DDELX=DXI-DXIM1
      DYI=YTEMP(I)
      DYIM1=YTEMP(IM1)
      DDELY=DYI-DYIM1
      DSUMX=DSUMX+DDELX**2
      DSUMY=DSUMY+DDELY**2
      DSUMXY=DSUMXY+DDELX*DDELY
  300 CONTINUE
      DSQRTX=0.0
      IF(DSUMX.GT.0.0D0)DSQRTX=DSQRT(DSUMX)
      DSQRTY=0.0
      IF(DSUMY.GT.0.0D0)DSQRTY=DSQRT(DSUMY)
      XYRACM=DSUMXY/(DSQRTX*DSQRTY)
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'OFF')GO TO 890
      IF(IWRITE.EQ.'OFF')GO TO 890
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,811)N,XYRACM
  811 FORMAT('THE RANK COMOVEMENT COEFFICIENT OF THE ',I8,   &
      ' OBSERVATIONS = ',E15.7)
      CALL DPWRST('XXX','BUG ')
  890 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF RANKCM--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGA3,IERROR
 9012 FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)N
 9013 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9014)DN,DSUMX,DSUMY,DSUMXY
 9014 FORMAT('DN,DSUMX,DSUMY,DSUMXY = ',4D15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)XYRACM
 9015 FORMAT('XYRACM = ',E15.7)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE RANKCM
      SUBROUTINE RANCOM(K,N,ISEED,X,ITEMP1)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM COMPOSITION
!              OF THE INTEGER N INTO K NON-NEGATIVE INTEGERS.
!     INPUT  ARGUMENTS--K      = THE INTEGER NUMBER DENOTING THE
!                                NUMBER OF ELEMENTS IN THE
!                                COMPOSITION
!                     --N      = THE INTEGER NUMBER BEING COMPOSED.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST K)
!                                INTO WHICH THE GENERATED
!                                RANDOM COMPOSITION IS PLACED.
!     OUTPUT--A RANDOM COMPOSITION OF THE INTEGER N INTO K ELEMENTS.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.   HOWEVER, K <= N.
!     OTHER DATAPAC   SUBROUTINES NEEDED--RANKSB.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCE: NIJENHUIS, ALBERT AND WILF, HERBERT S., 'COMBINATORIAL
!                ALGORITHMS', ACADEMIC PRESS, 1975, CH. 6, P. 48.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2008/5
!     ORIGINAL VERSION--MAY       2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DIMENSION X(*)
      INTEGER   ITEMP1(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(K.LT.1)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)K
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(N.LT.1)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,48)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(K.GT.N)THEN
        WRITE(ICOUT,25)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,26)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)K
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,48)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR--FOR THE RANDOM COMPOSITION OF N, THE')
    6 FORMAT('      REQUESTED NUMBER OF ELEMENTS IS NON-POSITIVE.')
   15 FORMAT('***** ERROR--FOR THE RANDOM COMPOSITION OF N, THE ',   &
             'VALUE OF N IS NON-POSITIVE.')
   25 FORMAT('***** ERROR--FOR THE RANDOM COMPOSITION OF N INTO ',   &
             'K ELEMENTS,')
   26 FORMAT('      K IS GREATER THAN N.')
   47 FORMAT('***** THE VALUE OF K IS ',I8)
   48 FORMAT('***** THE VALUE OF N IS ',I8)
!
!     GENERATE A RANDOM COMPOSITION OF N INTO K ELEMENTS
!
      NTEMP1=N+K-1
      NTEMP2=K-1
      CALL RANKSB(NTEMP2,NTEMP1,ISEED,X,ITEMP1)
      CALL SORT(X,NTEMP2,X)
      DO 100 I=1,NTEMP2
        ITEMP1(I)=INT(X(I)+0.5)
  100 CONTINUE
!
      ITEMP1(K)=N+K
      L=0
      DO 200 I=1,K
        M=ITEMP1(I)
        ITEMP1(I)=M-L-1
        L=M
  200 CONTINUE
!
      DO 300 I=1,K
        X(I)=REAL(ITEMP1(I))
  300 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE RANCOM
      SUBROUTINE RANKCR(X,Y,N,IRCRTA,IWRITE,XTEMP,YTEMP,XTEMP2,MAXNXT,   &
                        XYRACR,STATCD,PVAL,PVALLT,PVALUT,   &
                        CUTU90,CUTU95,CTU975,CUTU99,CTU995,CTU999,   &
                        CUTL90,CUTL95,CTL975,CUTL99,CTL995,CTL999,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE SPEARMAN RANK CORRELATION
!              COEFFICIENT BETWEEN THE 2 SETS OF DATA IN THE INPUT
!              VECTORS X AND Y.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS
!                                WHICH CONSTITUTE THE FIRST SET
!                                OF DATA.
!                     --Y      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS
!                                WHICH CONSTITUTE THE SECOND SET
!                                OF DATA.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X, OR EQUIVALENTLY,
!                                THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR Y.
!     OUTPUT ARGUMENTS--XYRACR = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SPEARMAN RANK CORRELATION
!                                COEFFICIENT BETWEEN THE 2 SETS OF DATA
!                                IN THE INPUT VECTORS X AND Y.
!                                THIS SINGLE PRECISION VALUE
!                                WILL BE BETWEEN -1.0 AND 1.0
!                                (INCLUSIVELY).
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SPEARMAN RANK CORRELATION COEFFICIENT BETWEEN THE 2 SETS
!             OF DATA IN THE INPUT VECTORS X AND Y.
!     OTHER DATAPAC   SUBROUTINES NEEDED--RANK AND SORT.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DSQRT.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--KENDALL AND STUART, THE ADVANCED THEORY OF
!                 STATISTICS, VOLUME 2, EDITION 1, 1961, PAGES 476-477.
!               --SNEDECOR AND COCHRAN, STATISTICAL METHODS,
!                 EDITION 6, 1967, PAGES 193-195.
!               --DIXON AND MASSEY, INTRODUCTION TO STATISTICAL
!                 ANALYSIS, EDITION 2, 1957, PAGES 294-295.
!               --MOOD AND GRABLE, 'INTRODUCTION TO THE THEORY
!                 OF STATISTICS, EDITION 2, 1963, PAGE 424.
!               --W. J. CONOVER, "PRACTICAL NON-PARAMETRIC
!                 STATISTICS", THIRD EDITION, WILEY, 1999,
!                 PP. 318-322.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--JUNE      1972.
!     UPDATED         --OCTOBER   1974.
!     UPDATED         --JANUARY   1975.
!     UPDATED         --SEPTEMBER 1975.
!     UPDATED         --NOVEMBER  1975.
!     UPDATED         --FEBRUARY  1976.
!     UPDATED         --JUNE      1979.
!     UPDATED         --JULY      1979.
!     UPDATED         --JULY      1981.
!     UPDATED         --AUGUST    1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --JANUARY   2007. CALL LIST TO RANK
!     UPDATED         --FEBRUARY  2013. RETURN CRITICAL VALUES FOR
!                                       SMALL SAMPLES, CDF/PVALUES
!                                       FOR LARGE SAMPLES
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IRCRTA
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRIT2
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DX1
      DOUBLE PRECISION DX2
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DSUM12
      DOUBLE PRECISION DMEAN1
      DOUBLE PRECISION DMEAN2
!
      DIMENSION X(*)
      DIMENSION Y(*)
!
      DIMENSION XTEMP(*)
      DIMENSION YTEMP(*)
      DIMENSION XTEMP2(*)
!
      DIMENSION WP900(30)
      DIMENSION WP950(30)
      DIMENSION WP975(30)
      DIMENSION WP990(30)
      DIMENSION WP995(30)
      DIMENSION WP999(30)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      DATA WP900/   &
        -9.9999,-9.9999,-9.9999, 0.8000, 0.7000, 0.6000, 0.5357, 0.5000,   &
         0.4667, 0.4424, 0.4182, 0.3986, 0.3791, 0.3626, 0.3500, 0.3382,   &
         0.3260, 0.3148, 0.3070, 0.2977, 0.2909, 0.2829, 0.2767, 0.2704,   &
         0.2646, 0.2588, 0.2540, 0.2490, 0.2443, 0.2400/
!
      DATA WP950/   &
        -9.9999,-9.9999,-9.9999, 0.8000, 0.8000, 0.7714, 0.6786, 0.6190,   &
         0.5833, 0.5515, 0.5273, 0.4965, 0.4780, 0.4593, 0.4429, 0.4265,   &
         0.4118, 0.3994, 0.3895, 0.3789, 0.3688, 0.3597, 0.3518, 0.3435,   &
         0.3362, 0.3299, 0.3236, 0.3175, 0.3113, 0.3059/
!
      DATA WP975/   &
        -9.9999,-9.9999,-9.9999,-9.9999, 0.9000, 0.8286, 0.7500, 0.7143,   &
         0.6833, 0.6364, 0.6091, 0.5804, 0.5549, 0.5341, 0.5179, 0.5000,   &
         0.4853, 0.4696, 0.4579, 0.4451, 0.4351, 0.4241, 0.4150, 0.4061,   &
         0.3977, 0.3894, 0.3822, 0.3749, 0.3685, 0.3620/
!
      DATA WP990/   &
        -9.9999,-9.9999,-9.9999,-9.9999, 0.9000, 0.8857, 0.8571, 0.8095,   &
         0.7667, 0.7333, 0.7000, 0.6713, 0.6429, 0.6220, 0.6000, 0.5794,   &
         0.5637, 0.5480, 0.5333, 0.5203, 0.5078, 0.4963, 0.4852, 0.4748,   &
         0.4654, 0.4564, 0.4481, 0.4401, 0.4320, 0.4251/
!
      DATA WP995/   &
        -9.9999,-9.9999,-9.9999,-9.9999,-9.9999, 0.9429, 0.8929, 0.8571,   &
         0.8167, 0.7818, 0.7455, 0.7203, 0.6978, 0.6747, 0.6500, 0.6324,   &
         0.6152, 0.5975, 0.5825, 0.5684, 0.5545, 0.5426, 0.5306, 0.5200,   &
         0.5100, 0.5002, 0.4915, 0.4828, 0.4744, 0.4665/
!
      DATA WP999/   &
        -9.9999,-9.9999,-9.9999,-9.9999,-9.9999,-9.9999, 0.9643, 0.9286,   &
         0.9000, 0.8667, 0.8364, 0.8112, 0.7857, 0.7670, 0.7464, 0.7265,   &
         0.7083, 0.6904, 0.6737, 0.6586, 0.6455, 0.6318, 0.6186, 0.6070,   &
         0.5962, 0.5856, 0.5757, 0.5660, 0.5567, 0.5479/
!
      ISUBN1='RANK'
      ISUBN2='CR  '
!
      IERROR='NO'
!
      DN=0.0D0
      DMEAN1=0.0D0
      DMEAN2=0.0D0
      DSUM12=0.0D0
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'NKCR')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF RANKCR--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N
   52   FORMAT('IBUGA3,ISUBRO,N = ',2(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I),Y(I)
   56     FORMAT('I,X(I),Y(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  COMPUTE RANK CORRELATION COEFFICIENT  **
!               ********************************************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.LT.1 .OR. N.GT.MAXNXT)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN RANK CORRELATION--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS IN THE RESPONSE ',   &
               'VARIABLES')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,115)MAXNXT
  115   FORMAT('      MUST BE BETWEEN 1 AND ',I8,' (INCLUSIVELY).')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE NUMBER OF OBSERVATIONS  = ',I8)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(N.EQ.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,121)
  121   FORMAT('***** WARNING IN RANK CORRELATION--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,123)
  123   FORMAT('      THE NUMBER OF OBSERVATIONS IS ONE.')
        CALL DPWRST('XXX','BUG ')
        XYRACR=1.0
        GO TO 9000
      ENDIF
!
      HOLD=X(1)
      DO 135 I=2,N
       IF(X(I).NE.HOLD)GO TO 139
  135 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,121)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,136)HOLD
  136 FORMAT('      THE FIRST RESPONSE VARIABLE HAS ALL ELEMENTS = ',   &
             G15.7)
      CALL DPWRST('XXX','BUG ')
      XYRACR=1.0
      GO TO 9000
  139 CONTINUE
!
      HOLD=Y(1)
      DO 145 I=2,N
        IF(Y(I).NE.HOLD)GO TO 149
  145 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,121)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,146)HOLD
  146 FORMAT('      THE SECOND RESPONSE VARIABLE HAS ALL ELEMENTS = ',   &
             G15.7)
      CALL DPWRST('XXX','BUG ')
      XYRACR=1.0
      GO TO 9000
  149 CONTINUE
!
!               *************************************************
!               **  STEP 2--                                   **
!               **  COMPUTE THE RANK CORRELATION COEFFICIENT.  **
!               *************************************************
!
      IWRIT2='OFF'
      CALL RANK(X,N,IWRIT2,XTEMP,XTEMP2,MAXNXT,IBUGA3,IERROR)
      CALL RANK(Y,N,IWRIT2,YTEMP,XTEMP2,MAXNXT,IBUGA3,IERROR)
!
      DN=N
      DSUM1=0.0D0
      DSUM2=0.0D0
      DO 200 I=1,N
        DX1=XTEMP(I)
        DX2=YTEMP(I)
        DSUM1=DSUM1+DX1
        DSUM2=DSUM2+DX2
  200 CONTINUE
      DMEAN1=DSUM1/DN
      DMEAN2=DSUM2/DN
!
      DSUM1=0.0D0
      DSUM2=0.0D0
      DSUM12=0.0D0
      DO 300 I=1,N
        DX1=XTEMP(I)
        DX2=YTEMP(I)
        DSUM1=DSUM1+(DX1-DMEAN1)*(DX1-DMEAN1)
        DSUM2=DSUM2+(DX2-DMEAN2)*(DX2-DMEAN2)
        DSUM12=DSUM12+(DX1-DMEAN1)*(DX2-DMEAN2)
  300 CONTINUE
      DSQRT1=0.0
      IF(DSUM1.GT.0.0D0)DSQRT1=DSQRT(DSUM1)
      DSQRT2=0.0
      IF(DSUM2.GT.0.0D0)DSQRT2=DSQRT(DSUM2)
      XYRACR=DSUM12/(DSQRT1*DSQRT2)
!
!               *************************************************
!               **  STEP 2B--                                  **
!               **  NOW COMPUTE CDF, PVALUE, AND CRITICAL      **
!               **  VALUES.                                    **
!               *************************************************
!
!     USE TABLED CRITICAL VALUES FROM TABLE A10 OF CONOVER FOR N <= 30.
!     OTHERWISE, USE
!
!           W(p) = Z(p)/SQRT(N-1)
!
      AN=REAL(N)
      ANUM=1.0
      DENOM=SQRT(AN-1.0)
      AFACT=ANUM/DENOM
      ATEMP=XYRACR/AFACT
      CALL NORCDF(ATEMP,STATCD)
      PVALLT=STATCD
      PVALUT=1.0 - STATCD
      PVAL=2.0*MIN(PVALLT,PVALUT)
!
      IF(N.GT.30 .OR. IRCRTA.EQ.'NORM')THEN
        P=0.90
        CALL NORPPF(P,CUTU90)
        P=0.95
        CALL NORPPF(P,CUTU95)
        P=0.975
        CALL NORPPF(P,CTU975)
        P=0.99
        CALL NORPPF(P,CUTU99)
        P=0.995
        CALL NORPPF(P,CTU995)
        P=0.999
        CALL NORPPF(P,CTU999)
        CUTU90=AFACT*CUTU90
        CUTU95=AFACT*CUTU95
        CTU975=AFACT*CTU975
        CUTU99=AFACT*CUTU99
        CTU995=AFACT*CTU995
        CTU999=AFACT*CTU999
      ELSE
        CUTU90=WP900(N)
        CUTU95=WP950(N)
        CTU975=WP975(N)
        CUTU99=WP990(N)
        CTU995=WP995(N)
        CTU999=WP999(N)
      ENDIF
      CUTL90=-CUTU90
      CUTL95=-CUTU95
      CTL975=-CTU975
      CUTL95=-CUTU95
      CTL995=-CTU995
      CTL999=-CTU999
      IF(CUTU90.LT.-9.0)CUTU90=CPUMIN
      IF(CUTU95.LT.-9.0)CUTU95=CPUMIN
      IF(CTU975.LT.-9.0)CTU975=CPUMIN
      IF(CUTU99.LT.-9.0)CUTU99=CPUMIN
      IF(CTU995.LT.-9.0)CTU995=CPUMIN
      IF(CTU999.LT.-9.0)CTU999=CPUMIN
      IF(CUTL90.GT.9.0)CUTL90=CPUMIN
      IF(CUTL95.GT.9.0)CUTL95=CPUMIN
      IF(CTL975.GT.9.0)CTL975=CPUMIN
      IF(CUTL99.GT.9.0)CUTL99=CPUMIN
      IF(CTL995.GT.9.0)CTL995=CPUMIN
      IF(CTL999.GT.9.0)CTL999=CPUMIN
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)N,XYRACR
  811   FORMAT('THE RANK CORRELATION COEFFICIENT OF THE ',I8,   &
               ' OBSERVATIONS = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'NKCR')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF RANKCR--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR
 9012   FORMAT('IERROR = ',A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)DN,DMEAN1,DMEAN2,DSUM12
 9014   FORMAT('DN,DMEAN1,DMEAN2,DSUM12 = ',4D15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)XYRACR
 9015   FORMAT('XYRACR = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE RANKCR
      SUBROUTINE RANKCV(X,Y,N,IWRITE,XTEMP,YTEMP,XTEMP2,   &
      MAXNXT,XYRACV,   &
      IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE
!              SPEARMAN RANK COVARIANCE COEFFICIENT
!              BETWEEN THE 2 SETS OF DATA IN THE INPUT VECTORS X AND Y.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS
!                                WHICH CONSTITUTE THE FIRST SET
!                                OF DATA.
!                     --Y      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS
!                                WHICH CONSTITUTE THE SECOND SET
!                                OF DATA.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X, OR EQUIVALENTLY,
!                                THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR Y.
!     OUTPUT ARGUMENTS--XYRACV = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SPEARMAN RANK COVARIANCE
!                                COEFFICIENT BETWEEN THE 2 SETS OF DATA
!                                IN THE INPUT VECTORS X AND Y.
!                                THIS SINGLE PRECISION VALUE
!                                WILL BE BETWEEN -1.0 AND 1.0
!                                (INCLUSIVELY).
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SPEARMAN RANK COVARIANCE COEFFICIENT BETWEEN THE 2 SETS
!             OF DATA IN THE INPUT VECTORS X AND Y.
!     OTHER DATAPAC   SUBROUTINES NEEDED--RANK AND SORT.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--KENDALL AND STUART, THE ADVANCED THEORY OF
!                 STATISTICS, VOLUME 2, EDITION 1, 1961, PAGES 476-477.
!               --SNEDECOR AND COCHRAN, STATISTICAL METHODS,
!                 EDITION 6, 1967, PAGES 193-195.
!               --DIXON AND MASSEY, INTRODUCTION TO STATISTICAL
!                 ANALYSIS, EDITION 2, 1957, PAGES 294-295.
!               --MOOD AND GRABLE, 'INTRODUCTION TO THE THEORY
!                 OF STATISTICS, EDITION 2, 1963, PAGE 424.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--JUNE      1972.
!     UPDATED         --OCTOBER   1974.
!     UPDATED         --JANUARY   1975.
!     UPDATED         --SEPTEMBER 1975.
!     UPDATED         --NOVEMBER  1975.
!     UPDATED         --FEBRUARY  1976.
!     UPDATED         --JUNE      1979.
!     UPDATED         --JULY      1979.
!     UPDATED         --JULY      1981.
!     UPDATED         --AUGUST    1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --JANUARY   2007.  CALL LIST TO RANK
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRIT2
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DX1
      DOUBLE PRECISION DX2
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DSUM12
      DOUBLE PRECISION DMEAN1
      DOUBLE PRECISION DMEAN2
!
      DIMENSION X(*)
      DIMENSION Y(*)
!
      DIMENSION XTEMP(*)
      DIMENSION YTEMP(*)
      DIMENSION XTEMP2(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='RANK'
      ISUBN2='CV  '
      IERROR='NO'
!
      DN=0.0D0
      DMEAN1=0.0D0
      DMEAN2=0.0D0
      DSUM12=0.0D0
!
      IF(IBUGA3.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF RANKCV--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGA3
   52 FORMAT('IBUGA3 = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)N
   53 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 55 I=1,N
      WRITE(ICOUT,56)I,X(I),Y(I)
   56 FORMAT('I,X(I),Y(I) = ',I8,2E15.7)
      CALL DPWRST('XXX','BUG ')
   55 CONTINUE
   90 CONTINUE
!
!               ********************************************
!               **  COMPUTE RANK COVARIANCE  COEFFICIENT  **
!               ********************************************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(1.LE.N.AND.N.LE.MAXNXT)GO TO 119
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,111)
  111 FORMAT('***** ERROR IN RANKCV--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,112)
  112 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,113)
  113 FORMAT('      IN THE VARIABLE FOR WHICH')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,114)
  114 FORMAT('      THE RANK COVARIANCE COEFFICIENT IS TO BE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,115)MAXNXT
  115 FORMAT('      MUST BE BETWEEN 1 AND ',I8,' (INCLUSIVELY).')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,116)
  116 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,117)N
  117 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS HERE = ',I8,   &
      '.')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
  119 CONTINUE
!
      IF(N.EQ.1)GO TO 120
      GO TO 129
  120 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,121)
  121 FORMAT('***** NON-FATAL DIAGNOSTIC IN RANKCV--',   &
      'THE THIRD INPUT ARGUMENT (N) HAS THE VALUE 1')
      CALL DPWRST('XXX','BUG ')
      XYRACV=0.0
      GO TO 9000
  129 CONTINUE
!
      HOLD=X(1)
      DO 135 I=2,N
      IF(X(I).NE.HOLD)GO TO 139
  135 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,136)HOLD
  136 FORMAT('***** NON-FATAL DIAGNOSTIC IN RANKCV--',   &
      'THE 1ST INPUT ARGUMENT (A VECTOR) HAS ALL ELEMENTS = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      XYRACV=0.0
      GO TO 9000
  139 CONTINUE
!
      HOLD=Y(1)
      DO 145 I=2,N
      IF(Y(I).NE.HOLD)GO TO 149
  145 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,146)HOLD
  146 FORMAT('***** NON-FATAL DIAGNOSTIC IN RANKCV--',   &
      'THE 2ND INPUT ARGUMENT (A VECTOR) HAS ALL ELEMENTS = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      XYRACV=0.0
      GO TO 9000
  149 CONTINUE
!
!               *************************************************
!               **  STEP 2--                                   **
!               **  COMPUTE THE RANK COVARIANCE  COEFFICIENT.  **
!               *************************************************
!
      IWRIT2=IBUGA3
      CALL RANK(X,N,IWRIT2,XTEMP,XTEMP2,MAXNXT,IBUGA3,IERROR)
      CALL RANK(Y,N,IWRIT2,YTEMP,XTEMP2,MAXNXT,IBUGA3,IERROR)
!
      DN=N
      DSUM1=0.0D0
      DSUM2=0.0D0
      DO 200 I=1,N
      DX1=XTEMP(I)
      DX2=YTEMP(I)
      DSUM1=DSUM1+DX1
      DSUM2=DSUM2+DX2
  200 CONTINUE
      DMEAN1=DSUM1/DN
      DMEAN2=DSUM2/DN
!
      DSUM12=0.0D0
      DO 300 I=1,N
      DX1=XTEMP(I)
      DX2=YTEMP(I)
      DSUM12=DSUM12+(DX1-DMEAN1)*(DX2-DMEAN2)
  300 CONTINUE
      XYRACV=DSUM12/DN
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'OFF')GO TO 890
      IF(IWRITE.EQ.'OFF')GO TO 890
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,811)N,XYRACV
  811 FORMAT('THE RANK COVARIANCE COEFFICIENT OF THE ',I8,   &
      ' OBSERVATIONS = ',E15.7)
      CALL DPWRST('XXX','BUG ')
  890 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF RANKCV--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGA3,IERROR
 9012 FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)N
 9013 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9014)DN,DMEAN1,DMEAN2,DSUM12
 9014 FORMAT('DN,DMEAN1,DMEAN2,DSUM12 = ',4D15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)XYRACV
 9015 FORMAT('XYRACV = ',E15.7)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE RANKCV
      SUBROUTINE RANKSB(K,N,ISEED,X,ITEMP1)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM K-SUBSET OF
!              AN N-SET.
!     INPUT  ARGUMENTS--K      = THE INTEGER NUMBER DENOTING THE
!                                SIZE OF THE SUBSET.
!                     --N      = THE INTEGER NUMBER DENOTING THE
!                                SIZE OF THE N-SET.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST K)
!                                INTO WHICH THE GENERATED
!                                RANDOM K-SUBSET OF THE N-SET WILL BE
!                                PLACED.
!     OUTPUT--A RANDOM K-SUBSET OF AN N-SET.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.   HOWEVER, K <= N.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCE: NIJENHUIS, ALBERT AND WILF, HERBERT S., 'COMBINATORIAL
!                ALGORITHMS', ACADEMIC PRESS, 1975, CH. x, p. 43.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2008/5
!     ORIGINAL VERSION--MAY       2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      INTEGER   ITEMP1(*)
!
      INTEGER IX
      INTEGER R
      INTEGER DS
      INTEGER P
      INTEGER S
      INTEGER C
!
      DIMENSION U(1)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(K.LT.1)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)K
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(K.GT.N)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)K
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,48)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR--FOR THE RANDOM K-SET OF THE N-SET, ',   &
             'K IS NON-POSITIVE.')
   15 FORMAT('***** ERROR--FOR THE RANDOM K-SET OF THE N-SET, ',   &
             'K IS LARGER THAN N.')
   47 FORMAT('***** THE VALUE OF K IS ',I8)
   48 FORMAT('***** THE VALUE OF N IS ',I8)
!
!     GENERATE A RANDOM SUBSET OF N ELEMENTS
!
      I=0
      R=0
      NTEMP=1
      M0=0
      M=0
!
      C=K
      DO 100 I=1,K
        ITEMP1(I)=(I-1)*N/K
  100 CONTINUE
!
  110 CONTINUE
      CALL UNIRAN(NTEMP,ISEED,U)
      IX=1 + INT(REAL(N)*U(1))
      L=1 + (IX*K-1)/N
      IF(IX.LE.ITEMP1(L))GO TO  110
      ITEMP1(L)=ITEMP1(L)+1
      C=C-1
      IF(C.NE.0)GO TO  110
      P=0
      S=K
!
      DO 200 I=1,K
        M=ITEMP1(I)
        ITEMP1(I)=0
        IF(M.EQ.(I-1)*N/K) GO TO  200
        P=P+1
        ITEMP1(P)=M
  200 CONTINUE
!
  300 CONTINUE
      L=1 + (ITEMP1(P)*K-1)/N
      DS=ITEMP1(P) - (L-1)*N/K
      ITEMP1(P)=0
      ITEMP1(S)=L
      S=S-DS
      P=P-1
      IF(P.gt.0)GO TO  300
      L=K
!
  400 CONTINUE
      IF(ITEMP1(L).EQ.0)GO TO  500
      R=L
      M0=1 + (ITEMP1(L)-1)*N/K
      M=ITEMP1(L)*N/K - M0 + 1
!
  500 CONTINUE
      CALL UNIRAN(NTEMP,ISEED,U)
      IX=M0 + INT(REAL(M)*U(1))
      I=L
!
  600 CONTINUE
      I=I+1
      IF(I.LE.R)GO TO  800
!
  700 CONTINUE
      ITEMP1(I-1)=IX
      M=M-1
      L=L-1
      IF(L.EQ.0)THEN
        DO 900 I=1,K
          X(I)=REAL(ITEMP1(I))
  900   CONTINUE
        GO TO 9000
      ENDIF
      GO TO  400
!
  800 CONTINUE
      IF(IX.LT.ITEMP1(I)) GO TO  700
      IX=IX+1
      ITEMP1(I-1)=ITEMP1(I)
      GO TO  600
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE RANKSB
      SUBROUTINE RANLUX(RVEC,LENV)
!         Subtract-and-borrow random number generator proposed by
!         Marsaglia and Zaman, implemented by F. James with the name
!         RCARRY in 1991, and later improved by Martin Luescher
!         in 1993 to produce "Luxury Pseudorandom Numbers".
!     Fortran 77 coded by F. James, 1993
!
!       references:
!  M. Luscher, Computer Physics Communications  79 (1994) 100
!  F. James, Computer Physics Communications 79 (1994) 111
!
!   LUXURY LEVELS.
!   ------ ------      The available luxury levels are:
!
!  level 0  (p=24): equivalent to the original RCARRY of Marsaglia
!           and Zaman, very long period, but fails many tests.
!  level 1  (p=48): considerable improvement in quality over level 0,
!           now passes the gap test, but still fails spectral test.
!  level 2  (p=97): passes all known tests, but theoretically still
!           defective.
!  level 3  (p=223): DEFAULT VALUE.  Any theoretically possible
!           correlations have very small chance of being observed.
!  level 4  (p=389): highest possible luxury, all 24 bits chaotic.
!
!!!! ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
!!!!  Calling sequences for RANLUX:                                  ++
!!!!      CALL RANLUX (RVEC, LEN)   returns a vector RVEC of LEN     ++
!!!!                   32-bit random floating point numbers between  ++
!!!!                   zero (not included) and one (also not incl.). ++
!!!!      CALL RLUXGO(LUX,INT,K1,K2) initializes the generator from  ++
!!!!               one 32-bit integer INT and sets Luxury Level LUX  ++
!!!!               which is integer between zero and MAXLEV, or if   ++
!!!!               LUX .GT. 24, it sets p=LUX directly.  K1 and K2   ++
!!!!               should be set to zero unless restarting at a break++
!!!!               point given by output of RLUXAT (see RLUXAT).     ++
!!!!      CALL RLUXAT(LUX,INT,K1,K2) gets the values of four integers++
!!!!               which can be used to restart the RANLUX generator ++
!!!!               at the current point by calling RLUXGO.  K1 and K2++
!!!!               specify how many numbers were generated since the ++
!!!!               initialization with LUX and INT.  The restarting  ++
!!!!               skips over  K1+K2*E9   numbers, so it can be long.++
!!!!   A more efficient but less convenient way of restarting is by: ++
!!!!      CALL RLUXIN(ISVEC)    restarts the generator from vector   ++
!!!!                   ISVEC of 25 32-bit integers (see RLUXUT)      ++
!!!!      CALL RLUXUT(ISVEC)    outputs the current values of the 25 ++
!!!!                 32-bit integer seeds, to be used for restarting ++
!!!!      ISVEC must be dimensioned 25 in the calling program        ++
!!!! ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
!
!  MAY 2003: MODIFIED SLIGHTLY FOR INCORPORATION INTO DATAPLOT.
!            MOSTLY JUST THE I/O.
!
      DIMENSION RVEC(LENV)
      DIMENSION SEEDS(24), ISEEDS(24), ISDEXT(25)
      PARAMETER (MAXLEV=4, LXDFLT=3)
      DIMENSION NDSKIP(0:MAXLEV)
      DIMENSION NEXT(24)
      PARAMETER (TWOP12=4096., IGIGA=1000000000,JSDFLT=314159265)
      PARAMETER (ITWO24=2**24, ICONS=2147483563)
      SAVE NOTYET, I24, J24, CARRY, SEEDS, TWOM24, TWOM12, LUXLEV
      SAVE NSKIP, NDSKIP, IN24, NEXT, KOUNT, MKOUNT, INSEED
      INTEGER LUXLEV
      LOGICAL NOTYET
!
      INCLUDE 'DPCOP2.INC'
!
      DATA NOTYET, LUXLEV, IN24, KOUNT, MKOUNT /.TRUE., LXDFLT, 0,0,0/
      DATA I24,J24,CARRY/24,10,0./
!                               default
!  Luxury Level   0     1     2   *3*    4
      DATA NDSKIP/0,   24,   73,  199,  365 /
!orresponds to p=24    48    97   223   389
!     time factor 1     2     3     6    10   on slow workstation
!                 1    1.5    2     3     5   on fast mainframe
!
!  NOTYET is .TRUE. if no initialization has been performed yet.
!              Default Initialization by Multiplicative Congruential
      IF (NOTYET) THEN
         NOTYET = .FALSE.
         JSEED = JSDFLT
         INSEED = JSEED
!CCCC    WRITE(6,'(A,I12)') ' RANLUX DEFAULT INITIALIZATION: ',JSEED
         LUXLEV = LXDFLT
         NSKIP = NDSKIP(LUXLEV)
         LP = NSKIP + 24
         IN24 = 0
         KOUNT = 0
         MKOUNT = 0
!CCCC    WRITE(6,'(A,I2,A,I4)')  ' RANLUX DEFAULT LUXURY LEVEL =  ',
!CCCC+        LUXLEV,'      p =',LP
            TWOM24 = 1.
         DO 25 I= 1, 24
            TWOM24 = TWOM24 * 0.5
         K = JSEED/53668
         JSEED = 40014*(JSEED-K*53668) -K*12211
         IF (JSEED .LT. 0)  JSEED = JSEED+ICONS
         ISEEDS(I) = MOD(JSEED,ITWO24)
   25    CONTINUE
         TWOM12 = TWOM24 * 4096.
         DO 50 I= 1,24
         SEEDS(I) = REAL(ISEEDS(I))*TWOM24
         NEXT(I) = I-1
   50    CONTINUE
         NEXT(1) = 24
         I24 = 24
         J24 = 10
         CARRY = 0.
         IF (SEEDS(24) .EQ. 0.) CARRY = TWOM24
      ENDIF
!
!          The Generator proper: "Subtract-with-borrow",
!          as proposed by Marsaglia and Zaman,
!          Florida State University, March, 1989
!
      DO 100 IVEC= 1, LENV
      UNI = SEEDS(J24) - SEEDS(I24) - CARRY
      IF (UNI .LT. 0.)  THEN
         UNI = UNI + 1.0
         CARRY = TWOM24
      ELSE
         CARRY = 0.
      ENDIF
      SEEDS(I24) = UNI
      I24 = NEXT(I24)
      J24 = NEXT(J24)
      RVEC(IVEC) = UNI
!  small numbers (with less than 12 "significant" bits) are "padded".
      IF (UNI .LT. TWOM12)  THEN
         RVEC(IVEC) = RVEC(IVEC) + TWOM24*SEEDS(J24)
!        and zero is forbidden in case someone takes a logarithm
         IF (RVEC(IVEC) .EQ. 0.)  RVEC(IVEC) = TWOM24*TWOM24
      ENDIF
!        Skipping to luxury.  As proposed by Martin Luscher.
      IN24 = IN24 + 1
      IF (IN24 .EQ. 24)  THEN
         IN24 = 0
         KOUNT = KOUNT + NSKIP
         DO 90 ISK= 1, NSKIP
         UNI = SEEDS(J24) - SEEDS(I24) - CARRY
         IF (UNI .LT. 0.)  THEN
            UNI = UNI + 1.0
            CARRY = TWOM24
         ELSE
            CARRY = 0.
         ENDIF
         SEEDS(I24) = UNI
         I24 = NEXT(I24)
         J24 = NEXT(J24)
   90    CONTINUE
      ENDIF
  100 CONTINUE
      KOUNT = KOUNT + LENV
      IF (KOUNT .GE. IGIGA)  THEN
         MKOUNT = MKOUNT + 1
         KOUNT = KOUNT - IGIGA
      ENDIF
      RETURN
!
!           Entry to input and float integer seeds from previous run
      ENTRY RLUXIN(ISDEXT)
         TWOM24 = 1.
         DO 195 I= 1, 24
           NEXT(I) = I-1
           TWOM24 = TWOM24 * 0.5
  195    CONTINUE
         NEXT(1) = 24
         TWOM12 = TWOM24 * 4096.
!CCCC WRITE(6,'(A)') ' FULL INITIALIZATION OF RANLUX WITH 25 INTEGERS:'
!CCCC WRITE(6,'(5X,5I12)') ISDEXT
      DO 200 I= 1, 24
        SEEDS(I) = REAL(ISDEXT(I))*TWOM24
  200 CONTINUE
      CARRY = 0.
      IF (ISDEXT(25) .LT. 0)  CARRY = TWOM24
      ISD = IABS(ISDEXT(25))
      I24 = MOD(ISD,100)
      ISD = ISD/100
      J24 = MOD(ISD,100)
      ISD = ISD/100
      IN24 = MOD(ISD,100)
      ISD = ISD/100
      LUXLEV = ISD
        IF (LUXLEV .LE. MAXLEV) THEN
          NSKIP = NDSKIP(LUXLEV)
!CCCC     WRITE (6,'(A,I2)') ' RANLUX LUXURY LEVEL SET BY RLUXIN TO: ',
!CCCC+                         LUXLEV
        ELSE  IF (LUXLEV .GE. 24) THEN
          NSKIP = LUXLEV - 24
!CCCC     WRITE (6,'(A,I5)') ' RANLUX P-VALUE SET BY RLUXIN TO:',LUXLEV
        ELSE
          NSKIP = NDSKIP(MAXLEV)
          WRITE(ICOUT,999)
  999     FORMAT(1X)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,201)
  201     FORMAT('***** ERROR FROM LUXURY RANDOM NUMBER GENERATOR--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,202)LUXLEV
  202     FORMAT('      ILLEGAL LUXURY LEVEL: ',I5)
          CALL DPWRST('XXX','BUG ')
!CCCC     WRITE (6,'(A,I5)') ' RANLUX ILLEGAL LUXURY RLUXIN: ',LUXLEV
          LUXLEV = MAXLEV
        ENDIF
      INSEED = -1
      RETURN
!
!                    Entry to ouput seeds as integers
      ENTRY RLUXUT(ISDEXT)
      DO 300 I= 1, 24
         ISDEXT(I) = INT(SEEDS(I)*TWOP12*TWOP12)
  300 CONTINUE
      ISDEXT(25) = I24 + 100*J24 + 10000*IN24 + 1000000*LUXLEV
      IF (CARRY .GT. 0.)  ISDEXT(25) = -ISDEXT(25)
      RETURN
!
!                    Entry to output the "convenient" restart point
      ENTRY RLUXAT(LOUT,INOUT,K1,K2)
      LOUT = LUXLEV
      INOUT = INSEED
      K1 = KOUNT
      K2 = MKOUNT
      RETURN
!
!                    Entry to initialize from one or three integers
      ENTRY RLUXGO(LUX,INS,K1,K2)
         IF (LUX .LT. 0) THEN
            LUXLEV = LXDFLT
         ELSE IF (LUX .LE. MAXLEV) THEN
            LUXLEV = LUX
         ELSE IF (LUX .LT. 24 .OR. LUX .GT. 2000) THEN
            LUXLEV = MAXLEV
!CCCC       WRITE (6,'(A,I7)') ' RANLUX ILLEGAL LUXURY RLUXGO: ',LUX
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,301)
  301       FORMAT('***** ERROR FROM LUXURY RANDOM NUMBER GENERATOR--')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,302)LUX
  302       FORMAT('      ILLEGAL LUXURY LEVEL: ',I7)
            CALL DPWRST('XXX','BUG ')
         ELSE
            LUXLEV = LUX
            DO 310 ILX= 0, MAXLEV
              IF (LUX .EQ. NDSKIP(ILX)+24)  LUXLEV = ILX
  310       CONTINUE
         ENDIF
      IF (LUXLEV .LE. MAXLEV)  THEN
         NSKIP = NDSKIP(LUXLEV)
!CCCC    WRITE(6,'(A,I2,A,I4)') ' RANLUX LUXURY LEVEL SET BY RLUXGO :',
!CCCC+        LUXLEV,'     P=', NSKIP+24
      ELSE
          NSKIP = LUXLEV - 24
!CCCC     WRITE (6,'(A,I5)') ' RANLUX P-VALUE SET BY RLUXGO TO:',LUXLEV
      ENDIF
      IN24 = 0
      IF (INS .LT. 0) THEN
!CCCC    WRITE (6,'(A)')
!CCCC+   ' Illegal initialization by RLUXGO, negative input seed'
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,401)
  401     FORMAT('***** ERROR FROM LUXURY RANDOM NUMBER GENERATOR--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,402)
  402     FORMAT('      NEGATIVE INPUT SEED: ')
          CALL DPWRST('XXX','BUG ')
      ENDIF
      IF (INS .GT. 0)  THEN
        JSEED = INS
!CCCC   WRITE(6,'(A,3I12)') ' RANLUX INITIALIZED BY RLUXGO FROM SEEDS',
!CCCC+      JSEED, K1,K2
      ELSE
        JSEED = JSDFLT
!CCCC   WRITE(6,'(A)')' RANLUX INITIALIZED BY RLUXGO FROM DEFAULT SEED'
      ENDIF
      INSEED = JSEED
      NOTYET = .FALSE.
      TWOM24 = 1.
         DO 325 I= 1, 24
           TWOM24 = TWOM24 * 0.5
         K = JSEED/53668
         JSEED = 40014*(JSEED-K*53668) -K*12211
         IF (JSEED .LT. 0)  JSEED = JSEED+ICONS
         ISEEDS(I) = MOD(JSEED,ITWO24)
  325    CONTINUE
      TWOM12 = TWOM24 * 4096.
         DO 350 I= 1,24
         SEEDS(I) = REAL(ISEEDS(I))*TWOM24
         NEXT(I) = I-1
  350    CONTINUE
      NEXT(1) = 24
      I24 = 24
      J24 = 10
      CARRY = 0.
      IF (SEEDS(24) .EQ. 0.) CARRY = TWOM24
!        If restarting at a break point, skip K1 + IGIGA*K2
!        Note that this is the number of numbers delivered to
!        the user PLUS the number skipped (if luxury .GT. 0).
      KOUNT = K1
      MKOUNT = K2
      IF (K1+K2 .NE. 0)  THEN
        DO 500 IOUTER= 1, K2+1
          INNER = IGIGA
          IF (IOUTER .EQ. K2+1)  INNER = K1
          DO 450 ISK= 1, INNER
            UNI = SEEDS(J24) - SEEDS(I24) - CARRY
            IF (UNI .LT. 0.)  THEN
               UNI = UNI + 1.0
               CARRY = TWOM24
            ELSE
               CARRY = 0.
            ENDIF
            SEEDS(I24) = UNI
            I24 = NEXT(I24)
            J24 = NEXT(J24)
  450     CONTINUE
  500   CONTINUE
!         Get the right value of IN24 by direct calculation
        IN24 = MOD(KOUNT, NSKIP+24)
        IF (MKOUNT .GT. 0)  THEN
           IZIP = MOD(IGIGA, NSKIP+24)
           IZIP2 = MKOUNT*IZIP + IN24
           IN24 = MOD(IZIP2, NSKIP+24)
        ENDIF
!       Now IN24 had better be between zero and 23 inclusive
        IF (IN24 .GT. 23) THEN
!CCCC      WRITE (6,'(A/A,3I11,A,I5)')
!CCCC+    '  Error in RESTARTING with RLUXGO:','  The values', INS,
!CCCC+     K1, K2, ' cannot occur at luxury level', LUXLEV
           IN24 = 0
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,501)
  501     FORMAT('***** ERROR FROM LUXURY RANDOM NUMBER GENERATOR--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,502)
  502     FORMAT('      ERROR IN RESTARTING WITH RLUXG0:')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,503)INS,K1,K2
  503     FORMAT('      THE VALUES ',3I11)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,504)LUXLEV
  504     FORMAT('      CANNOT OCCUR AT LUXURY LEVEL ',I5)
          CALL DPWRST('XXX','BUG ')
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE RANLUX
      SUBROUTINE RANMVN( N, LOWER, UPPER, INFIN, CORREL, MAXPTS,   &
                         ABSEPS, RELEPS, ERROR, VALUE, INFORM )
!
!     A subroutine for computing multivariate normal probabilities.
!     This subroutine uses the Monte-Carlo algorithm given in the paper
!     "Numerical Computation of Multivariate Normal Probabilities", in
!     J. of Computational and Graphical Stat., 1(1992), pp. 141-149, by
!          Alan Genz
!          Department of Mathematics
!          Washington State University
!          Pullman, WA 99164-3113
!          Email : alangenz@wsu.edu
!
!  Parameters
!
!     N      INTEGER, the number of variables.
!     LOWER  REAL, array of lower integration limits.
!     UPPER  REAL, array of upper integration limits.
!     INFIN  INTEGER, array of integration limits flags:
!            if INFIN(I) < 0, Ith limits are (-infinity, infinity);
!            if INFIN(I) = 0, Ith limits are (-infinity, UPPER(I)];
!            if INFIN(I) = 1, Ith limits are [LOWER(I), infinity);
!            if INFIN(I) = 2, Ith limits are [LOWER(I), UPPER(I)].
!     CORREL REAL, array of correlation coefficients; the correlation
!            coefficient in row I column J of the correlation matrix
!            should be stored in CORREL( J + ((I-2)*(I-1))/2 ), for J < I.
!     MAXPTS INTEGER, maximum number of function values allowed. This
!            parameter can be used to limit the time taken. A
!            sensible strategy is to start with MAXPTS = 1000*N, and then
!            increase MAXPTS if ERROR is too large.
!     ABSEPS REAL absolute error tolerance.
!     RELEPS REAL relative error tolerance.
!     ERROR  REAL estimated absolute error, with 99% confidence level.
!     VALUE  REAL estimated value for the integral
!     INFORM INTEGER, termination status parameter:
!            if INFORM = 0, normal completion with ERROR < EPS;
!            if INFORM = 1, completion with ERROR > EPS and MAXPTS
!                           function vaules used; increase MAXPTS to
!                           decrease ERROR;
!            if INFORM = 2, N > 100 or N < 1.
!
      EXTERNAL MVNFNC
      INTEGER N, INFIN(*), MAXPTS, MPT, INFORM, INFIS, IVLS
      DOUBLE PRECISION   &
           CORREL(*), LOWER(*), UPPER(*), MVNFNC,   &
           ABSEPS, RELEPS, ERROR, VALUE, D, E, EPS, MVNNIT
      IF ( N .GT. 100 .OR. N .LT. 1 ) THEN
         INFORM = 2
         VALUE = 0
         ERROR = 1
         RETURN
      ENDIF
      INFORM = INT(MVNNIT(N,CORREL,LOWER,UPPER,INFIN,INFIS,D,E))
      IF ( N-INFIS .EQ. 0 ) THEN
         VALUE = 1
         ERROR = 0
      ELSE IF ( N-INFIS .EQ. 1 ) THEN
         VALUE = E - D
         ERROR = 2E-16
      ELSE
!
!        Call then Monte-Carlo integration subroutine
!
         MPT = 25 + 10*N
         CALL RCRUDE(N-INFIS-1, MPT, MVNFNC, ERROR, VALUE, 0)
         IVLS = MPT
 10      EPS = MAX( ABSEPS, RELEPS*ABS(VALUE) )
         IF ( ERROR .GT. EPS .AND. IVLS .LT. MAXPTS ) THEN
            MPT = MAX( MIN( INT(MPT*(ERROR/(EPS))**2),   &
                            MAXPTS-IVLS ), 10 )
            CALL RCRUDE(N-INFIS-1, MPT, MVNFNC, ERROR, VALUE, 1)
            IVLS = IVLS + MPT
            GO TO 10
         ENDIF
         IF ( ERROR .GT. EPS .AND. IVLS .GE. MAXPTS ) INFORM = 1
      ENDIF
!
      RETURN
      END SUBROUTINE RANMVN
      SUBROUTINE RANMVT(N, NU, LOWER, UPPER, INFIN, CORREL, MAXPTS,   &
            ABSEPS, RELEPS, ERROR, VALUE, INFORM)
!
!     A subroutine for computing multivariate t probabilities.
!          Alan Genz
!          Department of Mathematics
!          Washington State University
!          Pullman, WA 99164-3113
!          Email : AlanGenz@wsu.edu
!
!  Parameters
!
!     N      INTEGER, the number of variables.
!     NU     INTEGER, the number of degrees of freedom.
!     LOWER  REAL, array of lower integration limits.
!     UPPER  REAL, array of upper integration limits.
!     INFIN  INTEGER, array of integration limits flags:
!            if INFIN(I) < 0, Ith limits are (-infinity, infinity);
!            if INFIN(I) = 0, Ith limits are (-infinity, UPPER(I)];
!            if INFIN(I) = 1, Ith limits are [LOWER(I), infinity);
!            if INFIN(I) = 2, Ith limits are [LOWER(I), UPPER(I)].
!     CORREL REAL, array of correlation coefficients; the correlation
!            coefficient in row I column J of the correlation matrix
!            should be stored in CORREL( J + ((I-2)*(I-1))/2 ), for J < I.
!     MAXPTS INTEGER, maximum number of function values allowed. This
!            parameter can be used to limit the time taken. A sensible
!            strategy is to start with MAXPTS = 1000*N, and then
!            increase MAXPTS if ERROR is too large.
!     ABSEPS REAL absolute error tolerance.
!     RELEPS REAL relative error tolerance.
!     ERROR  REAL, estimated absolute error, with 99% confidence level.
!     VALUE  REAL, estimated value for the integral
!     INFORM INTEGER, termination status parameter:
!            if INFORM = 0, normal completion with ERROR < EPS;
!            if INFORM = 1, completion with ERROR > EPS and MAXPTS
!                           function vaules used; increase MAXPTS to
!                           decrease ERROR;
!            if INFORM = 2, N > 20 or N < 1.
!
      DOUBLE PRECISION FNCMVT
      EXTERNAL FNCMVT
      INTEGER N, NU, INFIN(*), MAXPTS, INFORM, INFIS, MPT, IVLS
      DOUBLE PRECISION CORREL(*), LOWER(*), UPPER(*),   &
           ABSEPS, RELEPS, EPS, ERROR, VALUE, E, D, MVTNIT
      IF ( N .GT. 20 .OR. N .LT. 1 ) THEN
         INFORM = 2
         VALUE = 0
         ERROR = 1
         RETURN
      ENDIF
      INFORM = INT(MVTNIT(N,NU,CORREL,LOWER,UPPER,INFIN,INFIS,D,E))
      IF ( N-INFIS .EQ. 0 ) THEN
         VALUE = 1
         ERROR = 0.0D0
      ELSE IF ( N-INFIS .EQ. 1 ) THEN
         VALUE = E - D
         ERROR = 2E-16
      ELSE
!
!        Call the Monte-Carlo integration subroutine
!
         MPT = 25 + 10*N*N
         CALL RCRUDE(N-INFIS-1, MPT, FNCMVT, ERROR, VALUE, 0)
         IVLS = MPT
 10      EPS = MAX( ABSEPS, RELEPS*ABS(VALUE) )
         IF ( ERROR .GT. EPS .AND. IVLS .LT. MAXPTS ) THEN
            MPT = MAX(MIN( INT(MPT*(ERROR/(EPS))**2), MAXPTS-IVLS ), 10)
            CALL RCRUDE(N-INFIS-1, MPT, FNCMVT, ERROR, VALUE, 1)
            IVLS = IVLS + MPT
            GO TO 10
         ENDIF
         IF ( ERROR .GT. EPS .AND. IVLS .GE. MAXPTS ) INFORM = 1
      ENDIF
!
      RETURN
      END SUBROUTINE RANMVT
      SUBROUTINE RANPAR(K,N,ISEED,X,MULT,P)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM PARTITION
!              OF THE INTEGER N INTO K NON-NEGATIVE INTEGERS.
!     INPUT  ARGUMENTS--K      = THE INTEGER NUMBER DENOTING THE
!                                NUMBER OF ELEMENTS IN THE
!                                COMPOSITION
!                     --N      = THE INTEGER NUMBER BEING COMPOSED.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST K)
!                                INTO WHICH THE GENERATED
!                                RANDOM PARTITION IS PLACED.
!     OUTPUT--A RANDOM PARTITION OF THE INTEGER N INTO K ELEMENTS.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.   HOWEVER, K <= N.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCE: NIJENHUIS, ALBERT AND WILF, HERBERT S., 'COMBINATORIAL
!                ALGORITHMS', ACADEMIC PRESS, 1975, P. 75.
!
!                THE CODE BELOW IMPLEMENTS THE NIJENHUIS, ALBERT,
!                AND WILF ROUTINE.
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2008/5
!     ORIGINAL VERSION--MAY       2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      REAL X(*)
      REAL U(1)
      INTEGER MULT(*)
      INTEGER P(*)
!
      INTEGER D
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,48)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
   15 FORMAT('***** ERROR--FOR THE RANDOM PARTITION OF N, THE ',   &
             'VALUE OF N IS NON-POSITIVE.')
   48 FORMAT('***** THE VALUE OF N IS ',I8)
!
!     GENERATE A RANDOM PARTITION OF N INTO K ELEMENTS
!
      NTEMP=1
!
      P(1)=1
      M=1
      IF(N.EQ.1)GO TO 30
!
!     STEP 1: COMPUTE THE NUMBER OF PARTITIONS FOR I FOR
!             I = 1 TO N.
!
      DO 21 I=M,N
        ISUM=0
        DO 22 D=1,I
          IS=0
          I1=I
   24     CONTINUE
          I1=I1-D
          IF(I1.EQ.0)THEN
            IS=IS+1
          ELSEIF(I1.GT.0)THEN
            IS=IS+P(I1)
            GO TO 24
          ENDIF
          ISUM=ISUM + IS*D
   22   CONTINUE
        P(I)=ISUM/I
   21 CONTINUE
!
!     STEP 2: NOW COMPUTE THE RANDOM PARTITION
!
   30 CONTINUE
      M=N
      K=0
      DO 31 I=1,N
        MULT(I)=0
   31 CONTINUE
!
   40 CONTINUE
      CALL UNIRAN(NTEMP,ISEED,U)
      Z=U(1)*REAL(M*P(M))
      D=0
  110 CONTINUE
      D=D+1
      I1=M
      J=0
  150 CONTINUE
      J=J+1
      I1=I1-D
      IF(I1.LT.0)THEN
        GO TO 110
      ELSEIF(I1.EQ.0)THEN
        Z=Z-REAL(D)
        IF(Z.LE.0.0)GO TO 145
        GO TO 110
      ELSEIF(I1.GT.0)THEN
        Z=Z-REAL(D*P(I1))
        IF(Z.LE.0.0)GO TO 145
        GO TO 150
      ENDIF
!
  145 CONTINUE
      MULT(D)=MULT(D)+J
      K=K+J
      M=I1
      IF(M.NE.0)GO TO 40
!
      ICNT=0
      DO 200 I=1,N
        IF(MULT(I).GT.0)THEN
          DO 210 J=1,MULT(I)
            ICNT=ICNT+1
            X(ICNT)=REAL(I)
  210     CONTINUE
        ENDIF
  200 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE RANPAR
      SUBROUTINE RANPER(N,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM PERMUTATION OF SIZE N
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF ITEMS IN THE PERMUTATION.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM PERMUTATION WILL BE PLACED.
!     OUTPUT--A RANDOM PERMUTATION OF SIZE N
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     NOTE--THE BASIC ALGORITHM WAS ORIGINALLY SUGGESTED
!           BY DAN LOZIER OF THE NAT. BUR. OF STANDARDS.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--89/1
!     ORIGINAL VERSION--DECEMBER  1988.
!     UPDATED         --DECEMBER  1989.  OUTER LOOP+ FOR MORE RANDOMNESS
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!CCCC THE FOLLOWING DIMENSION WAS CHANGED DECEMBER 1989
!CCCC DIMENSION U(2)
      DIMENSION U(10)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      AN=N
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)GO TO 50
      GO TO 90
   50 WRITE(ICOUT, 5)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,47)N
      CALL DPWRST('XXX','BUG ')
      RETURN
   90 CONTINUE
    5 FORMAT('***** ERROR--THE FIRST ARGUMENT TO ',   &
             'RANPER IS NON-POSITIVE.')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
!
!     GENERATE A RANDOM PERMUTATION OF THE INTEGERS 1 TO N
!
!     START OFF WITH A RANDOM CYCLIC PERMUTATION
!
      CALL UNIRAN(10,ISEED,U)
      IFUDGE=INT(AN*U(10))
      IFUDGE=IFUDGE+1
      IF(IFUDGE.LE.1)IFUDGE=1
      IF(IFUDGE.GE.N)IFUDGE=N
      DO 1100 I=1,N
        IP=I+IFUDGE
        IF(IP.LE.N)X(I)=REAL(IP)
        IF(IP.GT.N)X(I)=REAL(IP-N)
 1100 CONTINUE
!
!CCCC THE FOLLOWING RANDOM NUMBER OF LOOPS WAS ADDED DECEMBER 1989
!CCCC BECAUSE OF 9 STRINGS OF 1,2 AND OTHER
!CCCC CORRELATED PATTERNS THAT DID NOT LOOK "RANDOM ENOUGH"
!
      NREP=2
      AREP=NREP
      CALL UNIRAN(NREP,ISEED,U)
      NLOOP=INT(AREP*U(NREP))
      NLOOP=NLOOP+1
      IF(NLOOP.LE.1)NLOOP=1
      IF(NLOOP.GE.NREP)NLOOP=NREP
!
!CCCC THE FOLLOWING "TRASHING" OF RANDOM NUMBERS WAS ADDED DECEMBER 1989
!CCCC BECAUSE OF 9 STRINGS OF 1,2 AND OTHER
!CCCC CORRELATED PATTERNS THAT DID NOT LOOK "RANDOM ENOUGH"
!
      DO 1150 ILOOP=1,NLOOP
      CALL UNIRAN(10,ISEED,U)
 1150 CONTINUE
!
!CCCC THE FOLLOWING OUTER LOOP WAS ADDED DECEMBER 1989
!CCCC BECAUSE OF 9 STRINGS OF 1,2 AND OTHER
!CCCC CORRELATED PATTERNS THAT DID NOT LOOK "RANDOM ENOUGH"
!
      DO 1200 ILOOP=1,NLOOP
      DO 1300 I=1,N
!CCCC THE FOLLOWING CALL WAS CHANGED DECEMBER 1989
!CCCC CALL UNIRAN(1,ISEED,U)
      CALL UNIRAN(NREP,ISEED,U)
!CCCC THE FOLLOWING LINE WAS CHANGED DECEMBER 1989
!CCCC U1=U(1)
      U1=U(ILOOP)
      PROD=AN*U1
      IPROD=INT(PROD)
      INDEX=IPROD+1
      IF(INDEX.LT.1)INDEX=1
      IF(INDEX.GT.N)INDEX=N
      HOLD1=X(I)
      HOLD2=X(INDEX)
      X(I)=HOLD2
      X(INDEX)=HOLD1
!CCCC WRITE(6,777)ISEED,U1
!C777 FORMAT('ISEED,U1 = ',I8,F10.4)
 1300 CONTINUE
 1200 CONTINUE
!
      CALL UNIRAN(5,ISEED,U)
      IFUDGE=INT(AN*U(5))
      IFUDGE=IFUDGE+1
      IF(IFUDGE.LE.1)IFUDGE=1
      IF(IFUDGE.GE.N)IFUDGE=N
      DO 1400 I=1,N
        IXI=INT(X(I)+0.5)
        IXIP=IXI+IFUDGE
        IF(IXIP.LE.N)X(I)=REAL(IXIP)
        IF(IXIP.GT.N)X(I)=REAL(IXIP-N)
 1400 CONTINUE
!
      RETURN
      END SUBROUTINE RANPER
      SUBROUTINE RANPE2(N,NKEEP,PVAL,NITER,IDIST,MAXNXT,ISEED,   &
                        Y,TAG,X,NOUT,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE GENERATES RANDOM PERMUTATIONs OF SIZE N
!              IN A SIMULATION CONTEXT.  SPECIFICALLY,
!
!              1) ONLY THE FIRST NKEEP (1 <= NKEEP <= N) VALUES ARE
!                 KEPT.
!
!              2) THERE IS A PROBABILITY OF SUCCESS DEFINED BY PVAL
!                 (0 < PVAL <= 1).  THE N POSSIBLE VALUES ARE DIVIDED
!                 INTO TWO GROUPS BASED ON PVAL. FOR EXAMPLE, IF N = 10
!                 AND PVAL = 0.5, THEN RANDOM PERMUTATION VALUES 1 TO 5
!                 WILL BE KEPT WHILE RANDOM PERMUTATION VALUES 6 TO 10
!                 WILL NOT BE KEPT.  IF ALL VALUES ARE TO BE KEPT, THEN
!                 SET PVAL TO 1.
!
!              3) THE PERMUTATIONS WILL BE GENERATED NITER TIMES.
!
!              4) IF IDIST = 1 THEN ONLY DISTINCT VALUES FOR THE RANDOM
!                 PERMUTATION WILL BE KEPT.  IF IDIST = 0, THEN NO CHECK
!                 FOR DISTINCT VALUES WILL BE MADE.
!
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER OF ITEMS IN
!                                THE PERMUTATION.
!                     --ISEED  = THE INTEGER VALUE OF THE SEED FOR THE
!                                RANDOM NUMBER GENERATOR.
!                     --NKEEP  = THE INTEGER VALUE THAT SPECIFIES HOW
!                                MANY RANDOM PERMUTATION VALUES WILL BE
!                                KEPT.
!                     --PVAL   = THE PROBABILITY OF SUCCESS FOR A GIVEN
!                                RANDOM PERMUTATION VALUE.
!                     --NITER  = THE INTEGER VALUE THAT SPECIFIES HOW
!                                MANY SETS OF PERMUTATIONS WILL BE
!                                GENERATED.
!                     --IDIST  = AN INTEGER VALUE THAT SPECIFIES WHETHER
!                                THE OUTPUT ARRAY WILL BE CHECKED FOR
!                                DISTINCT VALUES.
!                     --MAXNXT = THE INTEGER VALUE THAT SPECIFIES THE
!                                MAXIMUM SIZE OF THE OUTPUT ARRAYS.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR INTO WHICH
!                                THE GENERATED RANDOM PERMUTATIONS WILL
!                                BE PLACED.
!                     --TAG    = A SINGLE PRECISION VECTOR WHICH
!                                IDENTIFIES WHICH ITERATION THE RANDOM
!                                PERMUTATION CAME FROM
!     OUTPUT--A SET OF RANDOM PERMUTATIONS FROM MULTIPLE TRIALS.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     NOTE--THE RANDOM PERMUTATIONS ALGORITHM IS BASED ON A KNUTH
!           ALGORITHM (VOLUME 2, ALGORITM 3.4, P. 145) AS
!           ADAPTED BY H. D. KNOBLE (ROUTINE RPERM).  I DON'T HAVE
!           THE ORIGINAL RPERM SOURCE, THIS WAS ADAPTED FROM A
!           LISTING OF A FORTRAN 90 IMPLEMENTATION OF THAT ALGORITHM.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2017/08
!     ORIGINAL VERSION--AUGUST    2017.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION TAG(*)
      DIMENSION X(*)
!
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      DIMENSION U(100)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'NPE2')THEN
        WRITE(ICOUT,51)
   51   FORMAT('AT THE BEGINNING OF RANPE2')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)
   53   FORMAT('N,NKEEP,NITER,IDIST,PVAL = ',2I8,2I5,F10.5)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,101)
  101   FORMAT('***** ERROR IN THE SAMPLE RANDOM PERMUTATION--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,103)
  103   FORMAT('      THE SIZE OF THE RANDOM PERMUTATION, N, IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,105)N
  105   FORMAT('      THE VALUE OF N IS ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSEIF(N.GT.MAXNXT)THEN
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,107)MAXNXT
  107   FORMAT('      THE SIZE OF THE RANDOM PERMUTATION, N, IS ',   &
               'GREATER THAN ',I10,'.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,105)N
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSEIF(NKEEP.LT.1 .OR. NKEEP.GT.N)THEN
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      THE NUMBER OF VALUES TO KEEP, NKEEP,  FOR A ',   &
               'SINGLE ITERATION')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,115)N
  115   FORMAT('      IS LESS THAN ONE OR GREATER THAN ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)NKEEP
  117   FORMAT('      THE VALUE OF NKEEP IS ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSEIF(NITER.LT.1)THEN
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,123)
  123   FORMAT('      THE NUMBER OF ITERATIONS IS LESS THAN ONE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,127)NITER
  127   FORMAT('      THE NUMBER OF ITERATIONS IS ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSEIF(PVAL.LE.0.0 .OR. PVAL.GT.1.0)THEN
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,133)
  133   FORMAT('      THE PROBABILITY OF SUCCESS IS LESS THAN OR ',   &
               'EQUAL TO ZERO OR GREATER THAN ONE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,137)PVAL
  137   FORMAT('      THE PROBABILITY OF SUCCESS IS ',F10.5)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      AN=N
      NOUT=0
!
!     BASED ON PVAL, DETERMINE CUT-OFF FOR KEEPING
!     RANDOM PERMUTATION VALUE.
!
      IF(PVAL.GE.1.0)THEN
        NCUT=N
      ELSE
        AVAL=PVAL*AN
        NCUT=INT(AVAL+0.5)
      ENDIF
!
      DO 1000 ITER=1,NITER
!
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'NPE2')THEN
          WRITE(ICOUT,1001)ITER
 1001     FORMAT('AT LOOP 1000: ITER = ',I10)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
!       GENERATE A RANDOM PERMUTATION OF THE INTEGERS 1 TO N, BUT
!       ONLY GENERATE THE FIRST NKEEP VALUES
!
!       USE ALGORITHM DUE TO KNUTH TO GENERATE RANDOM PERMUTATIONS
!       OF SIZE N.
!
        DO 1110 I=1,N
          X(I)=REAL(I)
 1110   CONTINUE
!
        DO 1120 I=1,N,100
          M=MIN(N-I+1,100)
          CALL UNIRAN(M,ISEED,U)
          DO 1130 J=1,M
            IPJ=I+J-1
            K=INT(U(J)*(N-IPJ+1)) + IPJ
            ATEMP=X(IPJ)
            X(IPJ)=X(K)
            X(K)=ATEMP
 1130     CONTINUE
 1120   CONTINUE
!
!       NOW DETERMINE WHICH ONES TO KEEP
!
!          1) ONLY FIRST NKEEP VALUES CONSIDERED
!          2) ONLY KEEP IF VALUE IS < NCUT
!          3) CHECK IF VALUE HAS ALREADY BEEN SELECTED
!             IN PREVIOUS ITERATION
!
        IF(IDIST.EQ.0)THEN
          DO 2000 I=1,NKEEP
            IF(X(I).GT.NCUT)GO TO 2000
            IF(NOUT.GE.MAXNXT)THEN
              WRITE(ICOUT,101)
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,2001)
 2001         FORMAT('      THE MAXIMUM NUMBER OF OUTPUT POINTS (',I8,   &
                     ') HAS BEEN EXCEEDED.')
              CALL DPWRST('XXX','BUG ')
              IERROR='YES'
              GO TO 9000
            ENDIF
            NOUT=NOUT+1
            Y(NOUT)=X(I)
            TAG(NOUT)=REAL(ITER)
 2000     CONTINUE
        ELSE
          DO 3000 I=1,NKEEP
            IF(X(I).GT.NCUT)GO TO 3000
            IF(NOUT.GE.1)THEN
              DO 3100 J=1,NOUT
                IF(X(I).EQ.Y(J))GO TO 3000
 3100         CONTINUE
              IF(NOUT.GE.MAXNXT)THEN
                WRITE(ICOUT,101)
                CALL DPWRST('XXX','BUG ')
                WRITE(ICOUT,2001)
                CALL DPWRST('XXX','BUG ')
                IERROR='YES'
                GO TO 9000
              ENDIF
              NOUT=NOUT+1
              Y(NOUT)=X(I)
              TAG(NOUT)=REAL(ITER)
            ELSE
              NOUT=NOUT+1
              Y(NOUT)=X(I)
              TAG(NOUT)=REAL(ITER)
            ENDIF
 3000     CONTINUE
        ENDIF
!
 1000 CONTINUE
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'NPE2')THEN
        WRITE(ICOUT,9001)
 9001   FORMAT('AT THE END OF RANPE2')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9003)NOUT,NCUT,IERROR
 9003   FORMAT('NOUT,NCUT,IERROR = ',2I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        IF(NOUT.GE.1)THEN
          DO 9010 I=1,NOUT
            WRITE(ICOUT,9013)I,Y(I),TAG(I)
 9013       FORMAT('I,Y(I),TAG(I) = ',I8,2F15.1)
        CALL DPWRST('XXX','BUG ')
 9010     CONTINUE
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE RANPE2
      SUBROUTINE RANPE3(N,NITER,IDIST,MAXNXT,ISEED,               &
                        Y,TAG,X,BLOCK,DBLOCK,IBTAG,NBLOCK,NOUT,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE GENERATES RANDOM PERMUTATIONs OF SIZE N
!              IN A SIMULATION CONTEXT.  SPECIFICALLY,
!
!              1) ONLY THE FIRST NKEEP (1 <= NKEEP <= N) VALUES ARE
!                 KEPT.
!
!              2) THERE IS A PROBABILITY OF SUCCESS DEFINED BY PVAL
!                 (0 < PVAL <= 1).  THE N POSSIBLE VALUES ARE DIVIDED
!                 INTO TWO GROUPS BASED ON PVAL. FOR EXAMPLE, IF N = 10
!                 AND PVAL = 0.5, THEN RANDOM PERMUTATION VALUES 1 TO 5
!                 WILL BE KEPT WHILE RANDOM PERMUTATION VALUES 6 TO 10
!                 WILL NOT BE KEPT.  IF ALL VALUES ARE TO BE KEPT, THEN
!                 SET PVAL TO 1.
!
!              3) THE PERMUTATIONS WILL BE GENERATED NITER TIMES.
!
!              4) IF IDIST = 1 THEN ONLY DISTINCT VALUES FOR THE RANDOM
!                 PERMUTATION WILL BE KEPT.  IF IDIST = 0, THEN NO CHECK
!                 FOR DISTINCT VALUES WILL BE MADE.
!
!              NOTE: THIS IS A MODIFIED VERSION OF RANPE2.  THIS
!                    MODIFICATION INCLUDES A BLOCKING VARIABLE WHERE
!                    WE PERMUTE WITHIN A BLOCK, BUT NOT BETWEEN BLOCKS.
!                    ALSO, WE KEEP ALL N VALUES (I.E., NKEEP = N AND
!                    PVAL = 1, SO DON'T PASS THESE AS ARGUMENTS).
!
!                    IT IS ASSUMED THAT THE UNIQUE VALUES OF THE
!                    BLOCKING VARIABLE HAVE ALREADY BEEN DETERMINED
!                    AND THAT THE BLOCKING VARIABLE HAS BEEN SORTED.
!
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER OF ITEMS IN
!                                THE PERMUTATION.
!                     --ISEED  = THE INTEGER VALUE OF THE SEED FOR THE
!                                RANDOM NUMBER GENERATOR.
!                     --NKEEP  = THE INTEGER VALUE THAT SPECIFIES HOW
!                                MANY RANDOM PERMUTATION VALUES WILL BE
!                                KEPT.
!                     --PVAL   = THE PROBABILITY OF SUCCESS FOR A GIVEN
!                                RANDOM PERMUTATION VALUE.
!                     --NITER  = THE INTEGER VALUE THAT SPECIFIES HOW
!                                MANY SETS OF PERMUTATIONS WILL BE
!                                GENERATED.
!                     --IDIST  = AN INTEGER VALUE THAT SPECIFIES WHETHER
!                                THE OUTPUT ARRAY WILL BE CHECKED FOR
!                                DISTINCT VALUES.
!                     --MAXNXT = THE INTEGER VALUE THAT SPECIFIES THE
!                                MAXIMUM SIZE OF THE OUTPUT ARRAYS.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR INTO WHICH
!                                THE GENERATED RANDOM PERMUTATIONS WILL
!                                BE PLACED.
!                     --TAG    = A SINGLE PRECISION VECTOR WHICH
!                                IDENTIFIES WHICH ITERATION THE RANDOM
!                                PERMUTATION CAME FROM
!     OUTPUT--A SET OF RANDOM PERMUTATIONS FROM MULTIPLE TRIALS.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     NOTE--THE RANDOM PERMUTATIONS ALGORITHM IS BASED ON A KNUTH
!           ALGORITHM (VOLUME 2, ALGORITM 3.4, P. 145) AS
!           ADAPTED BY H. D. KNOBLE (ROUTINE RPERM).  I DON'T HAVE
!           THE ORIGINAL RPERM SOURCE, THIS WAS ADAPTED FROM A
!           LISTING OF A FORTRAN 90 IMPLEMENTATION OF THAT ALGORITHM.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2024/04
!     ORIGINAL VERSION--MARCH     2024.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION TAG(*)
      DIMENSION X(*)
      DIMENSION BLOCK(*)
      DIMENSION DBLOCK(*)
      DIMENSION IBTAG(*)
!
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      DIMENSION U(100)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'NPE3')THEN
        WRITE(ICOUT,51)
   51   FORMAT('AT THE BEGINNING OF RANPE3')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)N,NITER,IDIST,NBLOCK
   53   FORMAT('N,NITER,IDIST,NBLOCK = ',4I8)
        CALL DPWRST('XXX','BUG ')
        DO I=1,N
          WRITE(ICOUT,58)I,BLOCK(I)
   58     FORMAT('I,BLOCK(I) = ',I6,G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDDO
        DO I=1,NBLOCK
          WRITE(ICOUT,63)I,DBLOCK(I)
   63     FORMAT('I,DBLOCK(I) = ',I6,G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDDO
      ENDIF
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,101)
  101   FORMAT('***** ERROR IN THE SAMPLE RANDOM PERMUTATION (RANPE3)--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,103)
  103   FORMAT('      THE SIZE OF THE RANDOM PERMUTATION, N, IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,105)N
  105   FORMAT('      THE VALUE OF N IS ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSEIF(N.GT.MAXNXT)THEN
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,107)MAXNXT
  107   FORMAT('      THE SIZE OF THE RANDOM PERMUTATION, N, IS ',   &
               'GREATER THAN ',I10,'.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,105)N
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSEIF(NBLOCK.LT.2 .OR. NBLOCK.GT.N/2)THEN
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      THE NUMBER OF DISTINCT BLOCK VARIABLE VALUES')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,115)N
  115   FORMAT('      IS LESS THAN TWO OR GREATER THAN ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)NBLOCK
  117   FORMAT('      THE NUMBER OF DISTINCT BLOCK VALUES IS ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSEIF(NITER.LT.1)THEN
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,123)
  123   FORMAT('      THE NUMBER OF ITERATIONS IS LESS THAN ONE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,127)NITER
  127   FORMAT('      THE NUMBER OF ITERATIONS IS ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      AN=N
      NOUT=0
      NCUT=N
      NCOUNT=0
!
      DO 1000 ITER=1,NITER
        ICNT=0
        NCOUNT=0
        DO 1900 IBLOCK=1,NBLOCK
!
          IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'NPE3')THEN
             WRITE(ICOUT,1001)ITER,IBLOCK,NCOUNT
 1001        FORMAT('AT LOOP 1000: ITER,IBLOCK,NCOUNT = ',3I10)
             CALL DPWRST('XXX','BUG ')
          ENDIF
!
!         EXTRACT INDEX NUMBERS FOR THE BLOCK
!
          HOLD1=DBLOCK(IBLOCK)
          NTEMP=0
          DO KK=1,N
            IF(BLOCK(KK).EQ.HOLD1)THEN
              NTEMP=NTEMP+1
              IBTAG(NTEMP)=KK
            ENDIF
          ENDDO
!
          IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'NPE3')THEN
            WRITE(ICOUT,1055)NTEMP,NCOUNT,NOUT
 1055       FORMAT('NTEMP,NCOUNT,NOUT = ',3I8)
            CALL DPWRST('XXX','BUG ')
            DO II=1,NTEMP
              WRITE(ICOUT,1058)II,IBTAG(II)
 1058         FORMAT('II,IBTAG(II) = ',2I8)
              CALL DPWRST('XXX','BUG ')
            ENDDO
          ENDIF
!
          IF(NTEMP.LE.1)THEN
            WRITE(ICOUT,101)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1013)HOLD1
 1013       FORMAT('      BLOCK ',F10.2,' HAS LESS THAN 2 ',   &
                   'OBSERVATIONS.')
            CALL DPWRST('XXX','BUG ')
            IERROR='YES'
            GO TO 9000
          ENDIF
!
!         GENERATE A RANDOM PERMUTATION OF THE INTEGERS 1 TO NTEMP
!         (I.E., FOR THE BLOCK)
!
!         USE ALGORITHM DUE TO KNUTH TO GENERATE RANDOM PERMUTATIONS
!
          DO I=1,NTEMP
            X(I)=REAL(I)
          ENDDO
!
          DO I=1,NTEMP,100
            M=MIN(NTEMP-I+1,100)
            CALL UNIRAN(M,ISEED,U)
            DO J=1,M
              IPJ=I+J-1
              K=INT(U(J)*(NTEMP-IPJ+1)) + IPJ
              ATEMP=X(IPJ)
              X(IPJ)=X(K)
              X(K)=ATEMP
            ENDDO
          ENDDO
!
          IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'NPE3')THEN
            WRITE(ICOUT,1155)
 1155       FORMAT('AFTER 1120 LOOP')
            CALL DPWRST('XXX','BUG ')
            DO II=1,NTEMP
              WRITE(ICOUT,1158)II,IBTAG(II),X(II)
 1158         FORMAT('II,IBTAG(II),X(II) = ',2I8,G15.7)
              CALL DPWRST('XXX','BUG ')
            ENDDO
          ENDIF
!
!CCCC     IF(IDIST.EQ.0)THEN
            DO 2000 I=1,NTEMP
              IF(X(I).GT.NTEMP)GO TO 2000
              NOUT=NOUT+1
              IF(NOUT.GT.MAXNXT)THEN
                WRITE(ICOUT,101)
                CALL DPWRST('XXX','BUG ')
                WRITE(ICOUT,2001)MAXNXT
 2001           FORMAT('      THE MAXIMUM NUMBER OF OUTPUT POINTS (',I8,   &
                       ') HAS BEEN EXCEEDED.')
                CALL DPWRST('XXX','BUG ')
                IERROR='YES'
                GO TO 9000
              ENDIF
              Y(NOUT)=X(I)+REAL(NCOUNT)
              TAG(NOUT)=REAL(ITER)
!
              IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'NPE3')THEN
                WRITE(ICOUT,2155)I,NOUT,NCOUNT,Y(NOUT),TAG(NOUT)
 2155           FORMAT('2000 LOOP: I,NOUT,NCOUNT,Y(NOUT),TAG(NOUT) = ',   &
                       3I6,G15.7,F10.1)
                CALL DPWRST('XXX','BUG ')
              ENDIF
!
 2000       CONTINUE
!
!           NOTE: THIS SECTION OF CODE FOR DETERMINING UNIQUE
!                 PERMUTATIONS DOES NOT CURRENTLY WORK AS WE NEED
!                 TO TEST FOR ALL BLOCKS, NOT JUST THE CURRENT ONE.
!                 SO DO THE CHECK FOR ALL ITERATIONS.  THIS IS NOT
!                 PARTICULARLY EFFICIENT.
!
!CCCC     ELSE
!CCCC       DO3000I=1,NTEMP
!CCCC         IF(X(I).GT.NTEMP)GO TO 3000
!CCCC         IF(NOUT.GE.1)THEN
!CCCC           DO3100J=1,NOUT
!CCCC             IF(X(I).EQ.Y(J))GO TO 3000
!3100           CONTINUE
!CCCC           IF(NOUT.GE.MAXNXT)THEN
!CCCC             WRITE(ICOUT,101)
!CCCC             CALL DPWRST('XXX','BUG ')
!CCCC             WRITE(ICOUT,2001)
!CCCC             CALL DPWRST('XXX','BUG ')
!CCCC             IERROR='YES'
!CCCC             GO TO 9000
!CCCC           ENDIF
!CCCC           NOUT=NOUT+1
!CCCC           Y(NOUT)=X(I)+REAL(NCOUNT)
!CCCC           TAG(NOUT)=REAL(ITER)
!CCCC         ELSE
!CCCC           NOUT=NOUT+1
!CCCC           Y(NOUT)=X(I)+REAL(NCOUNT)
!CCCC           TAG(NOUT)=REAL(ITER)
!CCCC         ENDIF
!3000       CONTINUE
!CCCC     ENDIF
!
          IF(IBLOCK.LT.NBLOCK)NCOUNT=NCOUNT+NTEMP
!
 1900   CONTINUE
!
!       CHECK FOR UNIQUE BLOCK HERE
!
        NDUP=0
        IF(IDIST.EQ.1 .AND. ITER.GT.1)THEN
          IFLAG=0
          DO 4010 II=1,ITER-1
            ICNT1=(ITER-1)*N
            ICNT2=(II-1)*N
            DO JJ=1,N
              IF(Y(ICNT1+JJ).NE.Y(ICNT2+JJ))GO TO 4010
            ENDDO
            IFLAG=1
            NDUP=NDUP+1
            GO TO 4019
 4010     CONTINUE
 4019     CONTINUE
!
          IF(IFLAG.EQ.1)THEN
            NOUT=NOUT-N
          ENDIF
        ENDIF
!
 1000 CONTINUE
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'NPE3')THEN
        WRITE(ICOUT,9001)
 9001   FORMAT('AT THE END OF RANPE3')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9003)NOUT,NCUT,NDUP,IERROR
 9003   FORMAT('NOUT,NCUT,NDUP,IERROR = ',3I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        IF(NOUT.GE.1)THEN
          DO I=1,NOUT
            WRITE(ICOUT,9013)I,Y(I),TAG(I)
 9013       FORMAT('I,Y(I),TAG(I) = ',I8,2F15.1)
            CALL DPWRST('XXX','BUG ')
          ENDDO
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE RANPE3
      SUBROUTINE RANSUB(N,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SUBSET OF SIZE N
!              IN A RANDOM SUBSET OF SIZE N, THERE WILL BE N ELEMENTS
!              RETURNED, WHERE EACH IS EITHER A 0 (NOT INCLUDED) OR
!              1 (INCLUDED).
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF ITEMS IN THE PERMUTATION.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SUBSET WILL BE PLACED.
!     OUTPUT--A RANDOM SUBSET OF SIZE N
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCE: NIJENHUIS, ALBERT AND WILF, HERBERT S., 'COMBINATORIAL
!                ALGORITHMS', SECOND EDITION, ACADEMIC PRESS, 1978, CH. 2.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2008/5
!     ORIGINAL VERSION--MAY       2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DIMENSION X(*)
!
!-----COMMON---------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR--THE REQUESTED NUMBER OF ELEMENTS IN THE ',   &
             'RANDOM SUBSET IS NON-POSITIVE.')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
!
!     GENERATE A RANDOM SUBSET OF N ELEMENTS
!
      NPAR=1
      CALL DUNRAN(N,NPAR,ISEED,X)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE RANSUB
      SUBROUTINE RAYCDF(X,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE RAYLEIGH DISTRIBUTION.
!              THIS DISTRIBUTION IS DEFINED FOR NON-NEGATIVE X AND
!              HAS THE CUMULATIVE DISTRIBUTION FUNCTION
!                 F(X) = 1 - EXP(-0.5*X**2)       X > 0
!              NOTE THAT THE RAYLEIGH IS A SPECIAL CASE OF THE
!              FOLLOWING:
!              1) A CHI DISTRIBUTION WITH NU = 2
!              2) A WEIBULL DISTRIBUTION WITH GAMMA = 2 AND SCALE
!                 PARAMETER SQRT(2)
!     INPUT  ARGUMENTS--X     = THE SINGLE PRECISION VALUE AT
!                               WHICH THE CUMULATIVE DISTRIBUTION
!                               FUNCTION IS TO BE EVALUATED.
!                               X SHOULD BE NON-NEGATIVE.
!     OUTPUT ARGUMENTS--CDF   = THE SINGLE PRECISION PROBABILITY
!                               DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION FUNCTION
!             VALUE CDF FOR THE RAYLEIGH DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     REFERENCE--JOHNSON, KOTZ, AND BALAKRISHNAN (1994).
!                "CONTINUOUS UNIVARIATE DISTRIBUTIONS--VOLUME 1",
!                SECOND EDITION, WILEY, PP. 453, 686.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.6
!     ORIGINAL VERSION--JUNE      2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DCDF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!               ************************************
!               **  STEP 1--                      **
!               **  COMPUTE THE DENSITY FUNCTION  **
!               ************************************
!
      IF(X.LE.0.0)THEN
        CDF=0.0
      ELSE
        DX=DBLE(X)
        IF(DX.GE.DSQRT(D1MACH(2)))THEN
          CDF=1.0
          GO TO 9000
        ENDIF
!
        DCDF=1.0D0 - DEXP(-0.5D0*(DBLE(X)**2))
        CDF=REAL(DCDF)
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE RAYCDF
      DOUBLE PRECISION FUNCTION RAYFUN(UHAT,X)
!
!     PURPOSE--THIS ROUTINE IS USED IN FINDING THE MAXIMUM LIKELIHOOD
!              ESTIMATE OF THE LOCATION PARAMETER OF THE 2-PARAMETER
!              RAYLEIGH DISTRIBUTION.  THIS FUNCTION FINDS THE ROOT OF
!              THE EQUATION:
!
!              N*(XBAR - UHAT)/(SUM[i=1 to N][1/(X(i) - UHAT)] -
!              (1/(2*N))*SUM[i=1 to N][(X(i) - UHAT)**2] = 0
!
!              CALLED BY DFZER2 ROUTINE FOR FINDING THE ROOT OF A
!              FUNCTION.
!     EXAMPLE--RAYLEIGH MAXIMUM LIKELIHOOD Y
!     REFERENCE--COHEN AND WHITTEN (1988), "PARAMETER ESTIMATION IN
!                RELIABILITY AND LIFE SPAN MODELS", MARCEL DEKKER, INC.,
!                CHAPTER 10.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/7
!     ORIGINAL VERSION--JULY       2010.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION UHAT
      DOUBLE PRECISION X(*)
!
      INTEGER N
      DOUBLE PRECISION DXBAR
      COMMON/RAYCOM/DXBAR,N
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DX
      DOUBLE PRECISION DN
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      DN=DBLE(N)
      DTERM1=DN*(DXBAR - UHAT)
      DTERM2=1.0D0/(2.0D0*DN)
      DSUM1=0.0D0
      DSUM2=0.0D0
      DO 100 I=1,N
        DX=X(I) - UHAT
        DSUM1=DSUM1 + 1.0D0/DX
        DSUM2=DSUM1 + DX**2
  100 CONTINUE
!
      RAYFUN=(DTERM1/DSUM1) - DTERM2*DSUM2
!
      RETURN
      END FUNCTION RAYFUN
      SUBROUTINE RAYLI1(Y,N,ICASPL,   &
                        ALOC,SCALE,   &
                        ALIK,AIC,AICC,BIC,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE LIKELIHOOD FUNCTION FOR
!              THE RAYLEIGH DISTRIBUTION.  THIS IS FOR THE RAW DATA
!              CASE (I.E., NO GROUPING AND NO CENSORING).
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN ENGINEERING",
!                CAMBRIDGE UNIVERSITY PRESS, 1999, P. 187.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/7
!     ORIGINAL VERSION--JULY      2010.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DS
      DOUBLE PRECISION DU
      DOUBLE PRECISION DN
      DOUBLE PRECISION DNP
      DOUBLE PRECISION DLIK
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='RAYL'
      ISUBN2='I1  '
      IERROR='NO'
!
      ALIK=-99.0
      AIC=-99.0
      AICC=-99.0
      BIC=-99.0
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'YLI1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF RAYLI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO
   52   FORMAT('IBUGA3,ISUBRO = ',A4,2X,A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,55)N,ALOC,SCALE
   55   FORMAT('N,ALOC,SCALE = ',I8,2G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  COMPUTE LIKELIHOOD FUNCTION         **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'YLI1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IERFLG=0
      IERROR='NO'
      IWRITE='OFF'
      IF(ICASPL.EQ.'1RAY')ALOC=0.0
!
!     THE LOG-LIKELIHOOD FUNCTION IS
!
!     -2*N*LOG(S) + SUM[i=1][N][LOG(Y(i) - U) -
!     (1/(2*S**2)*SUM[i=1][N][Y(i) - U]
!
      DN=DBLE(N)
      DS=DBLE(SCALE)
      DU=DBLE(ALOC)
      DTERM1=-2.0D0*DN*DLOG(DS)
      DTERM2=1.0D0/(2.0D0*DS*DS)
      DSUM1=0.0D0
      DSUM2=0.0D0
      DO 1000 I=1,N
        DX=DBLE(Y(I))
        DSUM1=DSUM1 + DLOG(DX-DU)
        DSUM2=DSUM2 + (DX-DU)
 1000 CONTINUE
      DLIK=DTERM1 + DSUM1 - DTERM2*DSUM2
!
      ALIK=REAL(DLIK)
      DNP=2.0D0
      IF(ICASPL.EQ.'1RAY')DNP=1.0D0
      AIC=REAL(-2.0D0*DLIK + 2.0D0*DNP)
      DTERM3=(2.0D0*DNP*(DNP+1.0D0))/(DN-DNP-1.0D0)
      AICC=REAL(-2.0D0*DLIK + 2.0D0*DNP + DTERM3)
      BIC=REAL(-2.0D0*DLIK + DNP*LOG(DN))
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'YLI1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF RAYLI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)DSUM1,DSUM2,DTERM1,DTERM3
 9013   FORMAT('DSUM1,DSUM2,DTERM1,DTERM3 = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9014)ALIK,AIC,AICC,BIC
 9014   FORMAT('ALIK,AIC,AICC,BIC = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE RAYLI1
      SUBROUTINE RAYML1(Y,N,ICASPL,   &
                        DTEMP1,   &
                        XMEAN,XSD,XMIN,XMAX,   &
                        ALOCML,SCALML,SCALSE,   &
                        ALOCMM,SCALMM,SCA2SE,   &
                        ALOCMO,SCALMO,ALOCLM,SCALLM,ALOCPE,SCALPE,   &
                        ALOCSE,ALAMBA,ALAMSE,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD ESTIMATES
!              FOR THE RAYLEIGH DISTRIBUTION FOR THE RAW DATA CASE (I.E.,
!              NO CENSORING AND NO GROUPING).
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!              PUT THIS IN A SEPARATE ROUTINE AS IT MAY BE CALLED
!              FROM MULTIPLE PLACES (DPMLR1 WILL GENERATE THE OUTPUT
!              FOR THE RAYLEIGH MLE COMMAND).
!
!     REFERENCE--COHEN AND WHITTEN (1988), "PARAMETER ESTIMATION IN
!                RELIABILITY AND LIFE SPAN MODELS", MARCEL DEKKER, INC.,
!                CHAPTER 10.
!              --KARL BURY, "STATISTICAL DISTRIBUTIONS IN
!                ENGINEERING", CAMBRIDGE UNIVERSITY PRESS,
!                1999, PP. 331-332.
!              --DEY, DEY, AND KUNDU (xxxx), "TWO-PARAMETER RAYLEIGH
!                DISTRIBUTION: DIFFERENT METHODS OF ESTIMATION",
!                SUBMITTED.
!              --MAHDI (2006), "IMPROVED PARAMETER ESTIMATION IN
!                RAYLEIGH MODEL", METODOLOSKIZVEZKI, VOL. 3,
!                NO. 1, PP. 63-74.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/07
!     ORIGINAL VERSION--JULY      2010. EXTRACTED AS A SEPARATE
!                                       SUBROUTINE (FROM DPMLRA),
!                                       SUPPORT 2-PARAMETER CASE
!     UPDATED         --MAY       2014. ADDITIONAL METHODS FOR
!                                       2-PARAMETER CASE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*40 IDIST
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      DIMENSION Y(*)
      DOUBLE PRECISION DTEMP1(*)
!
      DOUBLE PRECISION DPI
      DOUBLE PRECISION DP
      DOUBLE PRECISION DX
      DOUBLE PRECISION DN
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DSUM3
      DOUBLE PRECISION DVAR
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
      DOUBLE PRECISION DTERM5
      DOUBLE PRECISION DEPS
      DOUBLE PRECISION DA
      DOUBLE PRECISION DB
      DOUBLE PRECISION DC
      DOUBLE PRECISION DL1
      DOUBLE PRECISION DL2
!
      DOUBLE PRECISION DAE
      DOUBLE PRECISION DRE
      DOUBLE PRECISION DXSTRT
      DOUBLE PRECISION DXLOW
      DOUBLE PRECISION DXUP
      DOUBLE PRECISION XLOWSV
      DOUBLE PRECISION XUPSV
!
      DOUBLE PRECISION DGAMMA
      EXTERNAL DGAMMA
      DOUBLE PRECISION DLNGAM
      EXTERNAL DLNGAM
!
      DOUBLE PRECISION RAYFUN
      EXTERNAL RAYFUN
!
      INTEGER IN
      DOUBLE PRECISION DXBAR
      COMMON/RAYCOM/DXBAR,IN
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA DPI/ 3.14159265358979D+00/
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='RAYM'
      ISUBN2='L1  '
      IWRITE='OFF'
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'YML1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF RAYML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N,MAXNXT
   52   FORMAT('IBUGA3,ISUBRO,N,MAXNXT = ',2(A4,2X),2I8)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CARRY OUT CALCULATIONS                **
!               **  FOR RAYLEIGH MLE ESTIMATE             **
!               ********************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'YML1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IDIST='RAYLEIGH'
      IFLAG=0
      IF(ICASPL.EQ.'1')IFLAG=1
      CALL SUMRAW(Y,N,IDIST,IFLAG,   &
                  XMEAN,XVAR,XSD,XMIN,XMAX,   &
                  ISUBRO,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
      CALL SORT(Y,N,Y)
!
      ALOCML=CPUMIN
      SCALML=CPUMIN
      ALOCMM=CPUMIN
      SCALMM=CPUMIN
      SCALSE=CPUMIN
      SCA2SE=CPUMIN
      DN=DBLE(N)
!
      IF(ICASPL.EQ.'1')THEN
!
!       ONE-PARAMETER MODEL
!
!       MAXIMUM LIKELIHOOD ESTIMATE OF SIGMA:
!
!       SIGMAHAT = SUM[i=1 to N][SQRT(X(i)**2/(2*N)]
!
!       FORMULA FOR STANDARD ERROR GIVEN ON PAGE 201 OF
!       COHEN AND WHITTEN.
!
        DP=2.0D0
        DSUM1=0.0D0
        DO 1010 I=1,N
          DX=DBLE(Y(I))
          DSUM1=DSUM1 + DX*DX/(DP*DN)
 1010   CONTINUE
        DSUM1=DSQRT(DSUM1)
        SCALML=REAL(DSUM1)
        DTERM1=DSUM1**2/(2.0D0*DN*DP)
        DTERM2=2.0D0*DN*DP
!
!       USE LOG GAMMA FUNCTION IN CASE N GETS LARGE
!
!CCCC   DTERM3=DGAMMA((DN*DP+1.0D0)/2.0D0)
!CCCC   DTERM4=DGAMMA(DN*DP/2.0D0)
        DTERM3=DLNGAM((DN*DP+1.0D0)/2.0D0)
        DTERM4=DLNGAM(DN*DP/2.0D0)
        DTERM5=2.0D0*(DLOG(2.0D0) + DTERM3 - DTERM4)
        DTERM5=DEXP(DTERM5)
!
        DVAR=DTERM1*(DTERM2 - DTERM5)
        SCALSE=REAL(DSQRT(DVAR))
      ELSE
!
!       MOMENT ESTIMATES ARE:
!
!       SIGMAHAT = S*SQRT(2/(4 - PI))
!       UHAT     = XBAR - SIGMAHAT*SQRT(PI/2)
!
        DTERM1=DBLE(XSD)*DSQRT(2.0D0/(4.0D0 - DPI))
        SCALMO=REAL(DTERM1)
        DTERM2=DBLE(XMEAN) - DTERM1*DSQRT(DPI/2.0D0)
        ALOCMO=REAL(DTERM2)
!
!       L-MOMENT ESTIMATES ARE:
!
!       UHAT      = L1 - (SQRT(2)/(SQRT(2) - 1))*L2
!       LAMBDAHAT = GAMMA(3/2)**2*(3 - 2*SQRT(2))/(2*L2**2)
!
!       WHERE L1 AND L2 ARE THE FIRST TWO SAMPLE MOMENTS
!
!       L1 = XBAR
!       L2 = (2/(N*(N-1)))*SUM[i=1 to N][(i-1)*X(i) - L1]
!
        DTERM1=DGAMMA(1.5D0)
        DL1=DBLE(XMEAN)
        DSUM1=0.0D0
        DO 1110 I=1,N
          DSUM1=DSUM1 + DBLE(I-1)*DBLE(Y(I))
 1110   CONTINUE
        DTERM3=2.0D0/(DN*(DN-1.0D0))
        DL2=(DTERM3*DSUM1) - DL1
        DTERM2=DL1 - (DSQRT(2.0D0)/(DSQRT(2.0D0) - 1.0D0))*DL2
        ALOCLM=REAL(DTERM2)
        DTERM2=DTERM1**2/DL2**2
        DTERM3=(3.0D0 - 2.0D0*DSQRT(2.0D0))/2.0D0
        DTERM4=DTERM2*DTERM3
        SCALLM=REAL(DTERM4)
        SCALLM=SQRT(1.0/(2.0*SCALLM))
!
!       PERCENTILE ESTIMATES ARE:
!
!       SIGMAHAT = (A - B**2)**2/(C - B*XBAR)**2
!       UHAT     = (A*XBAR - B*C)/(A - B**2)
!
!       WHERE
!
!       A = SUM[i=1 to N][-LOG(1 - P(i)]/N
!       B = SUM[i=1 to N][SQRT(-LOG(1 - P(i)))]/N
!       C = SUM[i=1 to N][X(i)*SQRT(-LOG(1 - P(i)))]
!       P(i) = i/(N+1)
!
        DSUM1=0.0D0
        DSUM2=0.0D0
        DSUM3=0.0D0
        DO 1120 I=1,N
          DTERM1=-DLOG(1.0D0 - DBLE(I)/(DN+1.0D0))
          DSUM1=DSUM1 + DTERM1
          DSUM2=DSUM2 + DSQRT(DTERM1)
          DSUM3=DSUM3 + DBLE(Y(I))*DSQRT(DTERM1)
 1120   CONTINUE
        DA=DSUM1/DN
        DB=DSUM2/DN
        DC=DSUM3/DN
        DTERM1=(DA*DBLE(XMEAN) - DB*DC)/(DA - DB**2)
        ALOCPE=REAL(DTERM1)
        DTERM1=(DA - DB*DB)**2/(DC - DB*DBLE(XMEAN))**2
        SCALPE=REAL(DTERM1)
        SCALPE=SQRT(1.0/(2.0*SCALPE))
!
!       MODIFIED MOMENT ESTIMATES ARE:
!
!       SIGMAHAT = (XBAR - XMEAN)/(SQRT(PI/2) - SQRT(PI/(2*N))
!       UHAT = XBAR - SIGMAHAT*SQRT(PI/2)
!
        DN=DBLE(N)
        DTERM1=DSQRT(DPI/2.0D0)
        DTERM2=DSQRT(DPI/(2.0D0*DN))
        SCALMM=(XMEAN - XMIN)/REAL(DTERM1 - DTERM2)
        ALOCMM=XMEAN - SCALMM*REAL(DTERM1)
!
!       MAXIMUM LIKELIHOOD ESTIMATES ARE:
!
!       TO ESTIMATE U, SOLVE THE FOLLOWING EQUATION:
!
!       N*(XBAR - UHAT)/(SUM[i=1 to N][1/(X(i) - UHAT)] -
!       (1/(2*N))*SUM[i=1 to N][(X(i) - UHAT)**2] = 0
!
!       THEN
!
!       SIGMAHAT = (1/(2*N))*SUM[i=1 to N][(X(i) - UHAT)**2]
!
        DXBAR=DBLE(XMEAN)
        IN=N
        DO 2010 I=1,N
          DTEMP1(I)=DBLE(Y(I))
 2010   CONTINUE
!
        DEPS=1.0D-12
        DXSTRT=DBLE(ALOCMM)
        DAE=2.0*0.000001D0*DXSTRT
        DRE=DAE
        IFLAG=0
        IF(DXSTRT.GE.0.0D0)THEN
          DXLOW=DXSTRT/3.0D0
        ELSE
          DXLOW=DXSTRT*3.0D0
        ENDIF
        DXUP=DBLE(XMIN) - DEPS
        ITBRAC=0
 4105   CONTINUE
        XLOWSV=DXLOW
        XUPSV=DXUP
        CALL DFZER2(RAYFUN,DXLOW,DXUP,DXSTRT,DRE,DAE,IFLAG,DTEMP1)
!
        IF(IFLAG.EQ.4 .AND. ITBRAC.LE.100)THEN
          IF(DXLOW.GE.0.0D0)THEN
            DXLOW=XLOWSV/2.0D0
          ELSE
            DXLOW=XLOWSV*2.0D0
          ENDIF
          ITBRAC=ITBRAC+1
          GO TO 4105
        ENDIF
!
        IF(IFLAG.EQ.2)THEN
!
!         NOTE: SUPPRESS THIS MESSAGE FOR NOW.
!CCCC     WRITE(ICOUT,999)
!CCCC     CALL DPWRST('XXX','BUG ')
!CCCC     WRITE(ICOUT,111)
!C111     FORMAT('***** WARNING FROM RAYLEIGH MAXIMUM ',
!CCCC1           'LIKELIHOOD--')
!CCCC     CALL DPWRST('XXX','BUG ')
!CCCC     WRITE(ICOUT,113)
!C113     FORMAT('      ESTIMATE OF MU MAY NOT BE COMPUTED TO ',
!CCCC1           'DESIRED TOLERANCE.')
!CCCC     CALL DPWRST('XXX','BUG ')
        ELSEIF(IFLAG.EQ.3)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,121)
  121     FORMAT('***** WARNING FROM RAYLEIGH MAXIMUM LIKELIHOOD--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,123)
  123     FORMAT('      ESTIMATE OF MU MAY BE NEAR A SINGULAR POINT.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(IFLAG.EQ.4)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,131)
  131     FORMAT('***** ERROR FROM RAYLEIGH MAXIMUM LIKELIHOOD--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,133)
  133     FORMAT('      APPROPRIATE BRACKETING INTERVAL NOT FOUND.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(IFLAG.EQ.5)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,121)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,143)
  143     FORMAT('      MAXIMUM ITERATIONS EXCEEDED.')
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        ALOCML=REAL(DXLOW)
        DSUM1=0.0D0
        DO 2030 I=1,N
          DX=DTEMP1(I) - DXLOW
          DSUM1=DSUM1 + DX**2
 2030   CONTINUE
        DTERM1=DSUM1/(2.0D0*DN)
        SCALML=REAL(DSQRT(DTERM1))
!
!       FORMULAS FOR STANDARD ERRORS ARE GIVEN IN KUNDU PAPER.
!       NOTE THAT HE IS OBTAINING THE VARIANCE FOR "LAMBDA"
!       RATHER THAN THE SCALE PARAMETER.
!
!          VAR(LAMBDA) = LAMBDA**2/N
!          VAR(U) = 1/{2*U + SUM[i=1 to N][Y(i) - U)**2/N}
!
!       THE MAHDI PAPER GIVES AN APPROXIMATE VARIANCE IN TERMS
!       OF THE SCALE PARAMETER:
!
!           VAR(SCALE) = SCALE**2/
!                        {4*[4 + 3*U**2/SCALE**2 + 6*U*SQRT(PI/2)/SCALE]}
!
        AN=REAL(N)
        ALAMBA=1.0/(2.0*SCALML**2)
        ALAMSE=ALAMBA/SQRT(AN)
        DSUM1=0.0D0
        DO 5010 I=1,N
          DX=DBLE(Y(I)) - DBLE(ALOCML)
          DSUM1=DSUM1 + 1.0D0/DX**2
 5010   CONTINUE
        DTERM1=DSQRT(1.0D0/(2.0D0*DBLE(ALOCML) + DSUM1/DN))
        ALOCSE=REAL(DTERM1)
        DTERM1=6.0D0*DBLE(ALOCML)*DSQRT(DPI/2.0D0)/DBLE(SCALML)
        DTERM2=4.0D0 + 3.0D0*DBLE(ALOCML)**2/DBLE(SCALML)**2
        DTERM3=DBLE(SCALML)**2/(DBLE(N)*(DTERM1+DTERM2))
        DTERM3=DSQRT(DTERM3)
        SCALSE=REAL(DTERM3)
!
      ENDIF
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'YML1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF RAYML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9055)N,XMEAN,XSD,XMIN,XMAX
 9055   FORMAT('N,XMEAN,XSD,XMIN,XMAX = ',I8,6G15.7)
        CALL DPWRST('XXX','WRIT')
        IF(ICASPL.EQ.'1')THEN
          WRITE(ICOUT,9056)SCALMM,SCALSE
 9056     FORMAT('SCALMM,SCALSE = ',2G15.7)
          CALL DPWRST('XXX','WRIT')
        ELSE
          WRITE(ICOUT,9057)ALOCMM,SCALMM
 9057     FORMAT('ALOCMM,SCALMM = ',2G15.7)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,9058)ALOCML,SCALML
 9058     FORMAT('ALOCML,SCALML = ',2G15.7)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,9060)ALAMBA,ALAMSE,ALOCSE
 9060     FORMAT('ALAMBA,ALAMSE,ALOCSE = ',3G15.7)
          CALL DPWRST('XXX','WRIT')
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE RAYML1
      SUBROUTINE RAYPDF(X,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE RAYLEIGH DISTRIBUTION.
!              THIS DISTRIBUTION IS DEFINED FOR NON-NEGATIVE X AND
!              HAS THE PROBABILITY DENSITY FUNCTION
!                 F(X) = X*EXP(-X**2/2)    X > 0
!              NOTE THAT THE RAYLEIGH IS A SPECIAL CASE OF THE
!              FOLLOWING:
!              1) A CHI DISTRIBUTION WITH NU = 2
!              2) A WEIBULL DISTRIBUTION WITH GAMMA = 2 AND SCALE
!                 PARAMETER = SQRT(2)
!     INPUT  ARGUMENTS--X     = THE SINGLE PRECISION VALUE AT
!                               WHICH THE PROBABILITY DENSITY
!                               FUNCTION IS TO BE EVALUATED.
!                               X SHOULD BE NON-NEGATIVE.
!     OUTPUT ARGUMENTS--PDF   = THE SINGLE PRECISION PROBABILITY
!                               DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY FUNCTION
!             VALUE PDF FOR THE RAYLEIGH DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP, LOG.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     REFERENCE--JOHNSON, KOTZ, AND BALAKRISHNAN (1994).
!                "CONTINUOUS UNIVARIATE DISTRIBUTIONS--VOLUME 1",
!                SECOND EDITION, WILEY, PP. 453, 686.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.6
!     ORIGINAL VERSION--JUNE      2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!               ************************************
!               **  STEP 1--                      **
!               **  COMPUTE THE DENSITY FUNCTION  **
!               ************************************
!
      IF(X.LT.0.0)THEN
        WRITE(ICOUT,8)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)X
        CALL DPWRST('XXX','WRIT')
        PDF=0.0
        GO TO 9000
      ENDIF
    8 FORMAT('***** ERROR: VALUE OF THE FIRST ARGUMENT TO RAYPDF ',   &
             'IS NEGATIVE.')
   48 FORMAT('      VALUE OF ARGUMENT IS: ',G15.7)
!
      IF(X.EQ.0.0)THEN
        PDF=0.0
      ELSE
        DX=DBLE(X)
        IF(DX.GE.DSQRT(D1MACH(2)))THEN
          PDF=0.0
          GO TO 9000
        ENDIF
!
        DTERM1=DLOG(DX)
        DTERM2=-DX*DX/2.0D0
        DPDF=DTERM1 + DTERM2
        DPDF=DEXP(DPDF)
        PDF=REAL(DPDF)
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE RAYPDF
      SUBROUTINE RAYPPF(P,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE RAYLEIGH DISTRIBUTION.
!              THIS DISTRIBUTION IS DEFINED FOR NON-NEGATIVE X AND
!              HAS THE PERCENT POINT FUNCTION
!                 G(P) = SQRT(2*LOG(1/(1-P)))    0 <= P < 1
!              NOTE THAT THE RAYLEIGH IS A SPECIAL CASE OF THE
!              FOLLOWING:
!              1) A CHI DISTRIBUTION WITH NU = 2
!              2) A WEIBULL DISTRIBUTION WITH GAMMA = 2 AND SCALE
!                 PARAMETER = SQRT(2)
!     INPUT  ARGUMENTS--P     = THE SINGLE PRECISION VALUE AT
!                               WHICH THE PERCENT POINT
!                               FUNCTION IS TO BE EVALUATED.
!                               0 <= P < 1.
!     OUTPUT ARGUMENTS--PPF   = THE SINGLE PRECISION PROBABILITY
!                               DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT FUNCTION
!             VALUE FOR THE RAYLEIGH DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     REFERENCE--JOHNSON, KOTZ, AND BALAKRISHNAN (1994).
!                "CONTINUOUS UNIVARIATE DISTRIBUTIONS--VOLUME 1",
!                SECOND EDITION, WILEY, PP. 453, 686.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.6
!     ORIGINAL VERSION--JUNE      2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DP
      DOUBLE PRECISION DPPF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!               ************************************
!               **  STEP 1--                      **
!               **  COMPUTE THE DENSITY FUNCTION  **
!               ************************************
!
      IF(P.LT.0.0 .OR. P.GE.1.0)THEN
        WRITE(ICOUT,8)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)P
        CALL DPWRST('XXX','WRIT')
        PPF=0.0
        GO TO 9000
      ENDIF
    8 FORMAT('***** ERROR: VALUE OF THE FIRST ARGUMENT TO RAYPPF ',   &
             'IS OUTSIDE THE [0,1) INTERVAL.')
   48 FORMAT('      VALUE OF ARGUMENT IS: ',G15.7)
      IF(P.EQ.0.0)THEN
        PPF=0.0
      ELSE
        DP=DBLE(P)
        DPPF=DSQRT(2.0D0*DLOG(1.0D0/(1.0D0-DP)))
        PPF=REAL(DPPF)
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE RAYPPF
      SUBROUTINE RAYRAN(N,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE RAYLEIGH DISTRIBUTION.
!              THIS DISTRIBUTION IS DEFINED FOR NON-NEGATIVE X AND HAS
!              THE PROBABILITY DENSITY FUNCTION
!                 F(X) = X*EXP(-X**2/2)
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE RAYLEIGH DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCE--JOHNSON, KOTZ, AND BALAKRISHNAN (1994).
!                "CONTINUOUS UNIVARIATE DISTRIBUTIONS--VOLUME 1",
!                SECOND EDITION, WILEY, P. 453.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRMAXMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.6
!     ORIGINAL VERSION--JUNE      2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DIMENSION X(*)
!
      DOUBLE PRECISION DP
      DOUBLE PRECISION DPPF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
    5 FORMAT('***** ERROR--FOR THE RAYLEIGH DISTRIBUTION, THE')
    6 FORMAT('      REQUESTED NUMBER OF RANDOM NUMBERS WAS ',   &
            'NON-POSITIVE.')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
!
!     USE PERCENT POINT TRANSFORMATION METHOD.
!
      CALL UNIRAN(N,ISEED,X)
      DO 100 I=1,N
        DP=DBLE(X(I))
        DPPF=DSQRT(2.0D0*DLOG(1.0D0/(1.0D0-DP)))
        X(I)=REAL(DPPF)
  100 CONTINUE
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE RAYRAN
      REAL FUNCTION RC (X, Y, IER)
!***BEGIN PROLOGUE  RC
!***PURPOSE  Calculate an approximation to
!             RC(X,Y) = Integral from zero to infinity of
!                              -1/2     -1
!                    (1/2)(t+X)    (t+Y)  dt,
!            where X is nonnegative and Y is positive.
!***LIBRARY   SLATEC
!***CATEGORY  C14
!***TYPE      SINGLE PRECISION (RC-S, DRC-D)
!***KEYWORDS  DUPLICATION THEOREM, ELEMENTARY FUNCTIONS,
!             ELLIPTIC INTEGRAL, TAYLOR SERIES
!***AUTHOR  Carlson, B. C.
!             Ames Laboratory-DOE
!             Iowa State University
!             Ames, IA  50011
!           Notis, E. M.
!             Ames Laboratory-DOE
!             Iowa State University
!             Ames, IA  50011
!           Pexton, R. L.
!             Lawrence Livermore National Laboratory
!             Livermore, CA  94550
!***DESCRIPTION
!
!   1.     RC
!          Standard FORTRAN function routine
!          Single precision version
!          The routine calculates an approximation to
!           RC(X,Y) = Integral from zero to infinity of
!
!                              -1/2     -1
!                    (1/2)(t+X)    (t+Y)  dt,
!
!          where X is nonnegative and Y is positive.  The duplication
!          theorem is iterated until the variables are nearly equal,
!          and the function is then expanded in Taylor series to fifth
!          order.  Logarithmic, inverse circular, and inverse hyper-
!          bolic functions can be expressed in terms of RC.
!
!
!   2.     Calling Sequence
!          RC( X, Y, IER )
!
!          Parameters on Entry
!          Values assigned by the calling routine
!
!          X      - Single precision, nonnegative variable
!
!          Y      - Single precision, positive variable
!
!
!
!          On Return  (values assigned by the RC routine)
!
!          RC     - Single precision approximation to the integral
!
!          IER    - Integer to indicate normal or abnormal termination.
!
!                     IER = 0 Normal and reliable termination of the
!                             routine.  It is assumed that the requested
!                             accuracy has been achieved.
!
!                     IER > 0 Abnormal termination of the routine
!
!          X and Y are unaltered.
!
!
!   3.    Error Messages
!
!         Value of IER assigned by the RC routine
!
!                  Value Assigned         Error Message Printed
!                  IER = 1                X.LT.0.0E0.OR.Y.LE.0.0E0
!                      = 2                X+Y.LT.LOLIM
!                      = 3                MAX(X,Y) .GT. UPLIM
!
!
!   4.     Control Parameters
!
!                  Values of LOLIM, UPLIM, and ERRTOL are set by the
!                  routine.
!
!          LOLIM and UPLIM determine the valid range of X and Y
!
!          LOLIM  - Lower limit of valid arguments
!
!                   Not less  than 5 * (machine minimum)  .
!
!          UPLIM  - Upper limit of valid arguments
!
!                   Not greater than (machine maximum) / 5 .
!
!
!                     Acceptable values for:   LOLIM       UPLIM
!                     IBM 360/370 SERIES   :   3.0E-78     1.0E+75
!                     CDC 6000/7000 SERIES :   1.0E-292    1.0E+321
!                     UNIVAC 1100 SERIES   :   1.0E-37     1.0E+37
!                     CRAY                 :   2.3E-2466   1.09E+2465
!                     VAX 11 SERIES        :   1.5E-38     3.0E+37
!
!          ERRTOL determines the accuracy of the answer
!
!                 The value assigned by the routine will result
!                 in solution precision within 1-2 decimals of
!                 "machine precision".
!
!
!          ERRTOL  - Relative error due to truncation is less than
!                    16 * ERRTOL ** 6 / (1 - 2 * ERRTOL).
!
!
!              The accuracy of the computed approximation to the inte-
!              gral can be controlled by choosing the value of ERRTOL.
!              Truncation of a Taylor series after terms of fifth order
!              introduces an error less than the amount shown in the
!              second column of the following table for each value of
!              ERRTOL in the first column.  In addition to the trunca-
!              tion error there will be round-off error, but in prac-
!              tice the total error from both sources is usually less
!              than the amount given in the table.
!
!
!
!          Sample Choices:  ERRTOL   Relative Truncation
!                                    error less than
!                           1.0E-3    2.0E-17
!                           3.0E-3    2.0E-14
!                           1.0E-2    2.0E-11
!                           3.0E-2    2.0E-8
!                           1.0E-1    2.0E-5
!
!
!                    Decreasing ERRTOL by a factor of 10 yields six more
!                    decimal digits of accuracy at the expense of one or
!                    two more iterations of the duplication theorem.
!
! *Long Description:
!
!   RC Special Comments
!
!
!
!
!                  Check: RC(X,X+Z) + RC(Y,Y+Z) = RC(0,Z)
!
!                  where X, Y, and Z are positive and X * Y = Z * Z
!
!
!          On Input:
!
!          X and Y are the variables in the integral RC(X,Y).
!
!          On Output:
!
!          X and Y are unaltered.
!
!
!
!                    RC(0,1/4)=RC(1/16,1/8)=PI=3.14159...
!
!                    RC(9/4,2)=LN(2)
!
!
!
!          ********************************************************
!
!          Warning: Changes in the program may improve speed at the
!                   expense of robustness.
!
!
!   --------------------------------------------------------------------
!
!   Special Functions via RC
!
!
!
!                  LN X                X .GT. 0
!
!                                            2
!                  LN(X) = (X-1) RC(((1+X)/2)  , X )
!
!
!   --------------------------------------------------------------------
!
!                  ARCSIN X            -1 .LE. X .LE. 1
!
!                                      2
!                  ARCSIN X = X RC (1-X  ,1 )
!
!   --------------------------------------------------------------------
!
!                  ARCCOS X            0 .LE. X .LE. 1
!
!
!                                     2      2
!                  ARCCOS X = SQRT(1-X ) RC(X  ,1 )
!
!   --------------------------------------------------------------------
!
!                  ARCTAN X            -INF .LT. X .LT. +INF
!
!                                       2
!                  ARCTAN X = X RC(1,1+X  )
!
!   --------------------------------------------------------------------
!
!                  ARCCOT X            0 .LE. X .LT. INF
!
!                                 2   2
!                  ARCCOT X = RC(X  ,X +1 )
!
!   --------------------------------------------------------------------
!
!                  ARCSINH X           -INF .LT. X .LT. +INF
!
!                                      2
!                  ARCSINH X = X RC(1+X  ,1 )
!
!   --------------------------------------------------------------------
!
!                  ARCCOSH X           X .GE. 1
!
!                                    2        2
!                  ARCCOSH X = SQRT(X -1) RC(X  ,1 )
!
!   --------------------------------------------------------------------
!
!                  ARCTANH X           -1 .LT. X .LT. 1
!
!                                        2
!                  ARCTANH X = X RC(1,1-X  )
!
!   --------------------------------------------------------------------
!
!                  ARCCOTH X           X .GT. 1
!
!                                  2   2
!                  ARCCOTH X = RC(X  ,X -1 )
!
!   --------------------------------------------------------------------
!
!***REFERENCES  B. C. Carlson and E. M. Notis, Algorithms for incomplete
!                 elliptic integrals, ACM Transactions on Mathematical
!                 Software 7, 3 (September 1981), pp. 398-403.
!               B. C. Carlson, Computing elliptic integrals by
!                 duplication, Numerische Mathematik 33, (1979),
!                 pp. 1-16.
!               B. C. Carlson, Elliptic integrals of the first kind,
!                 SIAM Journal of Mathematical Analysis 8, (1977),
!                 pp. 231-242.
!***ROUTINES CALLED  R1MACH, XERMSG
!***REVISION HISTORY  (YYMMDD)
!   790801  DATE WRITTEN
!   890531  Changed all specific intrinsics to generic.  (WRB)
!   891009  Removed unreferenced statement labels.  (WRB)
!   891009  REVISION DATE from Version 3.2
!   891214  Prologue converted to Version 4.0 format.  (BAB)
!   900315  CALLs to XERROR changed to CALLs to XERMSG.  (THJ)
!   900326  Removed duplicate information from DESCRIPTION section.
!           (WRB)
!   900510  Changed calls to XERMSG to standard form, and some
!           editorial changes.  (RWC))
!   920501  Reformatted the REFERENCES section.  (WRB)
!***END PROLOGUE  RC
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!CCCC CHARACTER*16 XERN3, XERN4, XERN5
      INTEGER IER
      REAL C1, C2, ERRTOL, LAMDA, LOLIM
      REAL MU, S, SN, UPLIM, X, XN, Y, YN
      LOGICAL FIRST
      SAVE ERRTOL,LOLIM,UPLIM,C1,C2,FIRST
      DATA FIRST /.TRUE./
!
!***FIRST EXECUTABLE STATEMENT  RC
      IF (FIRST) THEN
         ERRTOL = (R1MACH(3)/16.0E0)**(1.0E0/6.0E0)
         LOLIM  = 5.0E0 * R1MACH(1)
         UPLIM  = R1MACH(2) / 5.0E0
!
         C1 = 1.0E0/7.0E0
         C2 = 9.0E0/22.0E0
      ENDIF
      FIRST = .FALSE.
!
!         CALL ERROR HANDLER IF NECESSARY.
!
      RC = 0.0E0
      IF (X.LT.0.0E0.OR.Y.LE.0.0E0) THEN
         IER = 1
!CCCC    WRITE (XERN3, '(1PE15.6)') X
!CCCC    WRITE (XERN4, '(1PE15.6)') Y
         WRITE(ICOUT,1)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9)X
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,19)Y
         CALL DPWRST('XXX','BUG ')
         RETURN
      ENDIF
    1 FORMAT('***** ERORR FROM RC, EITHER THE FIRST ARGUMENT IS ',   &
             'NEGATIVE OR THE SECOND ARGUMENT IS NON-POSITIVE ***')
    9 FORMAT('***** THE VALUE OF THE FIRST ARGUMENT IS ',E15.8,' *****')
   19 FORMAT('***** THE VALUE OF THE SECOND ARGUMENT IS ',E15.8,' ***')
!
!CCCC IF (MAX(X,Y).GT.UPLIM) THEN
      IF (X.GT.UPLIM) THEN
         IER = 3
!CCCC    WRITE (XERN3, '(1PE15.6)') X
!CCCC    WRITE (XERN4, '(1PE15.6)') Y
!CCCC    WRITE (XERN5, '(1PE15.6)') UPLIM
         WRITE(ICOUT,2)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9)X
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,8)UPLIM
         CALL DPWRST('XXX','BUG ')
         RETURN
      ENDIF
    2 FORMAT('***** ERORR FROM RC, THE FIRST INPUT ARGUMENT IS LARGER',   &
             'THAN THE UPPER LIMIT. *****')
      IF (Y.GT.UPLIM) THEN
         IER = 3
         WRITE(ICOUT,3)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,19)Y
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,8)UPLIM
         CALL DPWRST('XXX','BUG ')
         RETURN
      ENDIF
    3 FORMAT('***** ERORR FROM RC, THE SECOND INPUT ARGUMENT IS ',   &
             'LARGER THAN THE UPPER LIMIT. *****')
    8 FORMAT('***** THE VALUE OF THE UPPER LIMIT IS ',E15.8,' *****')
!
      IF (X+Y.LT.LOLIM) THEN
         IER = 2
!CCCC    WRITE (XERN3, '(1PE15.6)') X
!CCCC    WRITE (XERN4, '(1PE15.6)') Y
!CCCC    WRITE (XERN5, '(1PE15.6)') LOLIM
         WRITE(ICOUT,4)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9)X
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9)Y
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,7)UPLIM
         CALL DPWRST('XXX','BUG ')
         RETURN
      ENDIF
    4 FORMAT('***** ERORR FROM RC, THE SUM OF THE TWO ARGUMENTS IS ',   &
             'LESS THAN THE LOWER LIMIT. *****')
    7 FORMAT('***** THE VALUE OF THE LOWER LIMIT IS ',E15.8,' *****')
!
      IER = 0
      XN = X
      YN = Y
!
   30 MU = (XN+YN+YN)/3.0E0
      SN = (YN+MU)/MU - 2.0E0
      IF (ABS(SN).LT.ERRTOL) GO TO 40
      LAMDA = 2.0E0*SQRT(XN)*SQRT(YN) + YN
      XN = (XN+LAMDA)*0.250E0
      YN = (YN+LAMDA)*0.250E0
      GO TO 30
!
   40 S = SN*SN*(0.30E0+SN*(C1+SN*(0.3750E0+SN*C2)))
      RC = (1.0E0+S)/SQRT(MU)
      RETURN
      END FUNCTION RC 
      SUBROUTINE RCRUDE(NDIM, MAXPTS, FUNCTN, ABSEST, FINEST, IR)
!
!     Crude Monte-Carlo Algorithm with simple antithetic variates
!      and weighted results on restart
!
      EXTERNAL FUNCTN
      INTEGER NDIM, MAXPTS, M, K, IR, NPTS
      DOUBLE PRECISION FINEST, ABSEST, X(100), FUN, FUNCTN, UNI,   &
           VARSQR, VAREST, VARPRD, FINDIF, FINVAL
      SAVE VAREST
      IF ( IR .LE. 0 ) THEN
         VAREST = 0.0D0
         FINEST = 0.0D0
      ENDIF
      FINVAL = 0.0D0
      VARSQR = 0.0D0
      NPTS = MAXPTS/2
      IRESET=0
      DO 100 M = 1,NPTS
         DO 200 K = 1,NDIM
            X(K) = UNI(IRESET)
  200    CONTINUE
         FUN = FUNCTN(NDIM, X)
         DO 300 K = 1,NDIM
            X(K) = 1.0D0 - X(K)
  300    CONTINUE
         FUN = ( FUNCTN(NDIM, X) + FUN )/2.0D0
         FINDIF = ( FUN - FINVAL )/DBLE(M)
         VARSQR = DBLE( M - 2 )*VARSQR/DBLE(M) + FINDIF**2
         FINVAL = FINVAL + FINDIF
  100 CONTINUE
      VARPRD = VAREST*VARSQR
      FINEST = FINEST + ( FINVAL - FINEST )/(1.0D0 + VARPRD)
      IF ( VARSQR .GT. 0.0D0 ) VAREST = (1.0D0 + VARPRD)/VARSQR
      ABSEST = 3.0D0*SQRT( VARSQR/( 1.0D0 + VARPRD ) )
!
      RETURN
      END SUBROUTINE RCRUDE
      SUBROUTINE RCSWAP(P, Q, A, B, INFIN, N, C)
!
!     Swaps rows and columns P and Q in situ.
!
      DOUBLE PRECISION A(*), B(*), C(*), T
      INTEGER INFIN(*), P, Q, N, I, J, II, JJ
      T = A(P)
      A(P) = A(Q)
      A(Q) = T
      T = B(P)
      B(P) = B(Q)
      B(Q) = T
      J = INFIN(P)
      INFIN(P) = INFIN(Q)
      INFIN(Q) = J
      JJ = (P*(P-1))/2
      II = (Q*(Q-1))/2
      T = C(JJ+P)
      C(JJ+P) = C(II+Q)
      C(II+Q) = T
      DO 100 J = 1, P-1
         T = C(JJ+J)
         C(JJ+J) = C(II+J)
         C(II+J) = T
  100 CONTINUE
      JJ = JJ + P
      DO 200 I = P+1, Q-1
         T = C(JJ+P)
         C(JJ+P) = C(II+I)
         C(II+I) = T
         JJ = JJ + I
  200 CONTINUE
      II = II + Q
      DO 300 I = Q+1, N
         T = C(II+P)
         C(II+P) = C(II+Q)
         C(II+Q) = T
         II = II + I
  300 CONTINUE
!
      RETURN
      END SUBROUTINE RCSWAP
      REAL FUNCTION RD (X, Y, Z, IER)
!***BEGIN PROLOGUE  RD
!***PURPOSE  Compute the incomplete or complete elliptic integral of the
!            2nd kind.  For X and Y nonnegative, X+Y and Z positive,
!             RD(X,Y,Z) = Integral from zero to infinity of
!                                -1/2     -1/2     -3/2
!                      (3/2)(t+X)    (t+Y)    (t+Z)    dt.
!            If X or Y is zero, the integral is complete.
!***LIBRARY   SLATEC
!***CATEGORY  C14
!***TYPE      SINGLE PRECISION (RD-S, DRD-D)
!***KEYWORDS  COMPLETE ELLIPTIC INTEGRAL, DUPLICATION THEOREM,
!             INCOMPLETE ELLIPTIC INTEGRAL, INTEGRAL OF THE SECOND KIND,
!             TAYLOR SERIES
!***AUTHOR  Carlson, B. C.
!             Ames Laboratory-DOE
!             Iowa State University
!             Ames, IA  50011
!           Notis, E. M.
!             Ames Laboratory-DOE
!             Iowa State University
!             Ames, IA  50011
!           Pexton, R. L.
!             Lawrence Livermore National Laboratory
!             Livermore, CA  94550
!***DESCRIPTION
!
!   1.     RD
!          Evaluate an INCOMPLETE (or COMPLETE) ELLIPTIC INTEGRAL
!          of the second kind
!          Standard FORTRAN function routine
!          Single precision version
!          The routine calculates an approximation result to
!          RD(X,Y,Z) = Integral from zero to infinity of
!                              -1/2     -1/2     -3/2
!                    (3/2)(t+X)    (t+Y)    (t+Z)    dt,
!          where X and Y are nonnegative, X + Y is positive, and Z is
!          positive.  If X or Y is zero, the integral is COMPLETE.
!          The duplication theorem is iterated until the variables are
!          nearly equal, and the function is then expanded in Taylor
!          series to fifth order.
!
!   2.     Calling Sequence
!
!          RD( X, Y, Z, IER )
!
!          Parameters on Entry
!          Values assigned by the calling routine
!
!          X      - Single precision, nonnegative variable
!
!          Y      - Single precision, nonnegative variable
!
!                   X + Y is positive
!
!          Z      - Real, positive variable
!
!
!
!          On Return     (values assigned by the RD routine)
!
!          RD     - Real approximation to the integral
!
!
!          IER    - Integer
!
!                   IER = 0 Normal and reliable termination of the
!                           routine.  It is assumed that the requested
!                           accuracy has been achieved.
!
!                   IER >  0 Abnormal termination of the routine
!
!
!          X, Y, Z are unaltered.
!
!   3.    Error Messages
!
!         Value of IER assigned by the RD routine
!
!                  Value Assigned         Error Message Printed
!                  IER = 1                MIN(X,Y) .LT. 0.0E0
!                      = 2                MIN(X + Y, Z ) .LT. LOLIM
!                      = 3                MAX(X,Y,Z) .GT. UPLIM
!
!
!   4.     Control Parameters
!
!                  Values of LOLIM, UPLIM, and ERRTOL are set by the
!                  routine.
!
!          LOLIM and UPLIM determine the valid range of X, Y, and Z
!
!          LOLIM  - Lower limit of valid arguments
!
!                    Not less  than 2 / (machine maximum) ** (2/3).
!
!          UPLIM  - Upper limit of valid arguments
!
!                    Not greater than (0.1E0 * ERRTOL / machine
!                    minimum) ** (2/3), where ERRTOL is described below.
!                    In the following table it is assumed that ERRTOL
!                    will never be chosen smaller than 1.0E-5.
!
!
!                    Acceptable Values For:   LOLIM      UPLIM
!                    IBM 360/370 SERIES   :   6.0E-51     1.0E+48
!                    CDC 6000/7000 SERIES :   5.0E-215    2.0E+191
!                    UNIVAC 1100 SERIES   :   1.0E-25     2.0E+21
!                    CRAY                 :   3.0E-1644   1.69E+1640
!                    VAX 11 SERIES        :   1.0E-25     4.5E+21
!
!
!          ERRTOL determines the accuracy of the answer
!
!                 The value assigned by the routine will result
!                 in solution precision within 1-2 decimals of
!                 "machine precision".
!
!          ERRTOL    Relative error due to truncation is less than
!                    3 * ERRTOL ** 6 / (1-ERRTOL) ** 3/2.
!
!
!
!              The accuracy of the computed approximation to the inte-
!              gral can be controlled by choosing the value of ERRTOL.
!              Truncation of a Taylor series after terms of fifth order
!              introduces an error less than the amount shown in the
!              second column of the following table for each value of
!              ERRTOL in the first column.  In addition to the trunca-
!              tion error there will be round-off error, but in prac-
!              tice the total error from both sources is usually less
!              than the amount given in the table.
!
!
!
!
!          Sample Choices:  ERRTOL   Relative Truncation
!                                    error less than
!                           1.0E-3    4.0E-18
!                           3.0E-3    3.0E-15
!                           1.0E-2    4.0E-12
!                           3.0E-2    3.0E-9
!                           1.0E-1    4.0E-6
!
!
!                    Decreasing ERRTOL by a factor of 10 yields six more
!                    decimal digits of accuracy at the expense of one or
!                    two more iterations of the duplication theorem.
!
! *Long Description:
!
!   RD Special Comments
!
!
!
!          Check: RD(X,Y,Z) + RD(Y,Z,X) + RD(Z,X,Y)
!          = 3 /  SQRT(X * Y * Z), where X, Y, and Z are positive.
!
!
!          On Input:
!
!          X, Y, and Z are the variables in the integral RD(X,Y,Z).
!
!
!          On Output:
!
!
!          X, Y, and Z are unaltered.
!
!
!
!          ********************************************************
!
!           WARNING: Changes in the program may improve speed at the
!                    expense of robustness.
!
!
!
!    -------------------------------------------------------------------
!
!
!   Special Functions via RD and RF
!
!
!                  Legendre form of ELLIPTIC INTEGRAL of 2nd kind
!                  ----------------------------------------------
!
!
!                                            2         2   2
!                  E(PHI,K) = SIN(PHI) RF(COS (PHI),1-K SIN (PHI),1) -
!
!                     2      3            2         2   2
!                  -(K/3) SIN (PHI) RD(COS (PHI),1-K SIN (PHI),1)
!
!
!                                 2        2           2
!                  E(K) = RF(0,1-K ,1) - (K/3) RD(3,1-K ,1)
!
!
!                         PI/2     2   2      1/2
!                       = INT  (1-K SIN (PHI) )  D PHI
!                          0
!
!
!
!                  Bulirsch form of ELLIPTIC INTEGRAL of 2nd kind
!                  ----------------------------------------------
!
!                                              2 2    2
!                  EL2(X,KC,A,B) = AX RF(1,1+KC X ,1+X ) +
!
!                                              3         2 2    2
!                                 +(1/3)(B-A) X RD(1,1+KC X ,1+X )
!
!
!
!                  Legendre form of alternative ELLIPTIC INTEGRAL of 2nd
!                  -----------------------------------------------------
!                        kind
!                        ----
!
!                            Q     2       2   2  -1/2
!                  D(Q,K) = INT SIN P  (1-K SIN P)     DP
!                            0
!
!
!
!                                   3          2     2   2
!                  D(Q,K) =(1/3)(SIN Q)  RD(COS Q,1-K SIN Q,1)
!
!
!
!
!
!                  Lemniscate constant B
!                  ---------------------
!
!
!
!                       1    2    4 -1/2
!                  B = INT  S (1-S )    DS
!                       0
!
!
!                  B =(1/3)RD (0,2,1)
!
!
!
!
!                  Heuman's LAMBDA function
!                  ------------------------
!
!
!
!                  (PI/2) LAMBDA0(A,B) =
!
!                                       2                2
!                     = SIN(B) (RF(0,COS (A),1)-(1/3) SIN (A) *
!
!                               2              2         2       2
!                      *RD(0,COS (A),1)) RF(COS (B),1-COS (A) SIN (B),1)
!
!                               2       3            2
!                     -(1/3) COS (A) SIN (B) RF(0,COS (A),1) *
!
!                             2         2       2
!                      *RD(COS (B),1-COS (A) SIN (B),1)
!
!
!
!                  Jacobi ZETA function
!                  --------------------
!
!
!                             2                2       2   2
!                  Z(B,K) = (K/3) SIN(B) RF(COS (B),1-K SIN (B),1)
!
!
!                                      2            2
!                             *RD(0,1-K ,1)/RF(0,1-K ,1)
!
!                               2       3          2       2   2
!                            -(K /3) SIN (B) RD(COS (B),1-K SIN (B),1)
!
!
!    -------------------------------------------------------------------
!
!***REFERENCES  B. C. Carlson and E. M. Notis, Algorithms for incomplete
!                 elliptic integrals, ACM Transactions on Mathematical
!                 Software 7, 3 (September 1981), pp. 398-403.
!               B. C. Carlson, Computing elliptic integrals by
!                 duplication, Numerische Mathematik 33, (1979),
!                 pp. 1-16.
!               B. C. Carlson, Elliptic integrals of the first kind,
!                 SIAM Journal of Mathematical Analysis 8, (1977),
!                 pp. 231-242.
!***ROUTINES CALLED  R1MACH, XERMSG
!***REVISION HISTORY  (YYMMDD)
!   790801  DATE WRITTEN
!   890531  Changed all specific intrinsics to generic.  (WRB)
!   890531  REVISION DATE from Version 3.2
!   891214  Prologue converted to Version 4.0 format.  (BAB)
!   900315  CALLs to XERROR changed to CALLs to XERMSG.  (THJ)
!   900326  Removed duplicate information from DESCRIPTION section.
!           (WRB)
!   900510  Modify calls to XERMSG to put in standard form.  (RWC)
!   920501  Reformatted the REFERENCES section.  (WRB)
!***END PROLOGUE  RD
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!CCCC CHARACTER*16 XERN3, XERN4, XERN5, XERN6
      INTEGER IER
      REAL LOLIM, UPLIM, EPSLON, ERRTOL
      REAL C1, C2, C3, C4, EA, EB, EC, ED, EF, LAMDA
      REAL MU, POWER4, SIGMA, S1, S2, X, XN, XNDEV
      REAL XNROOT, Y, YN, YNDEV, YNROOT, Z, ZN, ZNDEV, ZNROOT
      LOGICAL FIRST
      SAVE ERRTOL, LOLIM, UPLIM, C1, C2, C3, C4, FIRST
      DATA FIRST /.TRUE./
!
!***FIRST EXECUTABLE STATEMENT  RD
      IF (FIRST) THEN
         ERRTOL = (R1MACH(3)/3.0E0)**(1.0E0/6.0E0)
         LOLIM  = 2.0E0/(R1MACH(2))**(2.0E0/3.0E0)
         TUPLIM = R1MACH(1)**(1.0E0/3.0E0)
         TUPLIM = (0.10E0*ERRTOL)**(1.0E0/3.0E0)/TUPLIM
         UPLIM  = TUPLIM**2.0E0
!
         C1 = 3.0E0/14.0E0
         C2 = 1.0E0/6.0E0
         C3 = 9.0E0/22.0E0
         C4 = 3.0E0/26.0E0
      ENDIF
      FIRST = .FALSE.
!
!         CALL ERROR HANDLER IF NECESSARY.
!
      RD = 0.0E0
      IF( MIN(X,Y).LT.0.0E0) THEN
         IER = 1
!CCCC    WRITE (XERN3, '(1PE15.6)') X
!CCCC    WRITE (XERN4, '(1PE15.6)') Y
         WRITE(ICOUT,1)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9)X
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,8)Y
         CALL DPWRST('XXX','BUG ')
         RETURN
      ENDIF
    1 FORMAT('***** ERORR FROM RD, THE MINIMUM OF THE FIRST TWO ',   &
             'AGRUMENTS IS NEGATIVE. ***')
    9 FORMAT('***** THE VALUE OF THE FIRST ARGUMENT IS ',E15.8,' ***')
    8 FORMAT('***** THE VALUE OF THE SECOND ARGUMENT IS ',E15.8,' ***')
    7 FORMAT('***** THE VALUE OF THE THIRD ARGUMENT IS ',E15.8,' ***')
!
      IF (MAX(X,Y,Z).GT.UPLIM) THEN
         IER = 3
!CCCC    WRITE (XERN3, '(1PE15.6)') X
!CCCC    WRITE (XERN4, '(1PE15.6)') Y
!CCCC    WRITE (XERN5, '(1PE15.6)') Z
!CCCC    WRITE (XERN6, '(1PE15.6)') UPLIM
         WRITE(ICOUT,2)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9)X
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,8)Y
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,7)Z
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,6)UPLIM
         CALL DPWRST('XXX','BUG ')
         RETURN
      ENDIF
    2 FORMAT('***** ERORR FROM RD, ONE OF THE THREE ARGUMENTS EXCEEDS',   &
             ' THE LARGEST ALLOWABLE VALUE. ****')
    6 FORMAT('***** THE VALUE OF THE UPPER LIMIT IS ',E15.8,' *****')
!
      IF (MIN(X+Y,Z).LT.LOLIM) THEN
         IER = 2
!CCCC    WRITE (XERN3, '(1PE15.6)') X
!CCCC    WRITE (XERN4, '(1PE15.6)') Y
!CCCC    WRITE (XERN5, '(1PE15.6)') Z
!CCCC    WRITE (XERN6, '(1PE15.6)') LOLIM
         WRITE(ICOUT,3)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,4)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9)X
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,8)Y
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,7)Z
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,5)LOLIM
         CALL DPWRST('XXX','BUG ')
         RETURN
      ENDIF
    3 FORMAT('***** ERORR FROM RC, THE MINIMUM OF THE SUM OF THE ',   &
             'FIRST TWO ARGUMENTS ')
    4 FORMAT('AND THE THIRD ARGUMENT IS LESS THAN THE LOWER LIMIT. ')
    5 FORMAT('***** THE VALUE OF THE LOWER LIMIT IS ',E15.8,' *****')
!
      IER = 0
      XN = X
      YN = Y
      ZN = Z
      SIGMA = 0.0E0
      POWER4 = 1.0E0
!
   30 MU = (XN+YN+3.0E0*ZN)*0.20E0
      XNDEV = (MU-XN)/MU
      YNDEV = (MU-YN)/MU
      ZNDEV = (MU-ZN)/MU
      EPSLON = MAX(ABS(XNDEV), ABS(YNDEV), ABS(ZNDEV))
      IF (EPSLON.LT.ERRTOL) GO TO 40
      XNROOT = SQRT(XN)
      YNROOT = SQRT(YN)
      ZNROOT = SQRT(ZN)
      LAMDA = XNROOT*(YNROOT+ZNROOT) + YNROOT*ZNROOT
      SIGMA = SIGMA + POWER4/(ZNROOT*(ZN+LAMDA))
      POWER4 = POWER4*0.250E0
      XN = (XN+LAMDA)*0.250E0
      YN = (YN+LAMDA)*0.250E0
      ZN = (ZN+LAMDA)*0.250E0
      GO TO 30
!
   40 EA = XNDEV*YNDEV
      EB = ZNDEV*ZNDEV
      EC = EA - EB
      ED = EA - 6.0E0*EB
      EF = ED + EC + EC
      S1 = ED*(-C1+0.250E0*C3*ED-1.50E0*C4*ZNDEV*EF)
      S2 = ZNDEV*(C2*EF+ZNDEV*(-C3*EC+ZNDEV*C4*EA))
      RD = 3.0E0*SIGMA + POWER4*(1.0E0+S1+S2)/(MU* SQRT(MU))
!
      RETURN
      END FUNCTION RD 
      DOUBLE PRECISION FUNCTION rexp(x)
!-----------------------------------------------------------------------
!            EVALUATION OF THE FUNCTION EXP(X) - 1
!-----------------------------------------------------------------------
!     .. Scalar Arguments ..
      DOUBLE PRECISION x
!     ..
!     .. Local Scalars ..
      DOUBLE PRECISION p1,p2,q1,q2,q3,q4,w
!     ..
!     .. Intrinsic Functions ..
      INTRINSIC abs,exp
!     ..
!     .. Data statements ..
      DATA p1/.914041914819518D-09/,p2/.238082361044469D-01/,   &
           q1/-.499999999085958D+00/,q2/.107141568980644D+00/,   &
           q3/-.119041179760821D-01/,q4/.595130811860248D-03/
!     ..
!     .. Executable Statements ..
!-----------------------
      IF (abs(x).GT.0.15D0) GO TO 10
      rexp = x* (((p2*x+p1)*x+1.0D0)/ ((((q4*x+q3)*x+q2)*x+q1)*x+1.0D0))
      RETURN
!
   10 w = exp(x)
      IF (x.GT.0.0D0) GO TO 20
      rexp = (w-0.5D0) - 0.5D0
      RETURN
                                                                                                                                  
   20 rexp = w* (0.5D0+ (0.5D0-1.0D0/w))
      RETURN
                                                                                                                                  
      END FUNCTION rexp
      SUBROUTINE RGTCDF(X,ALPHA,BETA,A,B,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE
!              REFLECTED GENERALIZED TOPP AND LEONE DISTRIBUTION.
!              THE CUMULATIVE DISTRIBUTION FUNCTION IS:
!
!                  F(X;ALPHA,BETA,A,B) = 1 -
!                     ((B - X)/(B-A))**BETA*
!                     {ALPHA - (ALPHA-1)*((B-X)/(B-A))}**BETA
!                                    A <= X <= B, BETA > 0,
!                                    0 < ALPHA <= 2
!
!              WITH ALPHA AND BETA DENOTING THE SHAPE PARAMETERS.
!
!     INPUT  ARGUMENTS--X      = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                     --ALPHA  = THE DOUBLE PRECISION FIRST SHAPE
!                                PARAMETER
!                     --BETA   = THE DOUBLE PRECISION SECOND SHAPE
!                                PARAMETER
!     OUTPUT ARGUMENTS--CDF    = THE DOUBLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE BETWEEN 0 AND 1, INCLUSIVELY.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DLOG, DEXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--KOTZ AND VAN DORP (2004), "BEYOND BETA: OTHER
!                 CONTINUOUS FAMILIES OF DISTRIBUTIONS WITH BOUNDED
!                 SUPPORT AND APPLICATIONS", WORLD SCIENTFIC
!                 PUBLISHING COMPANY, CHAPTER 7.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--FEBRUARY  2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION X
      DOUBLE PRECISION ALPHA
      DOUBLE PRECISION BETA
      DOUBLE PRECISION A
      DOUBLE PRECISION B
      DOUBLE PRECISION CDF
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DX
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(B.LT.A)THEN
        TERM1=B
        B=A
        A=TERM1
      ENDIF
!
      IF(X.LT.A)THEN
!CCCC   WRITE(ICOUT,2)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,3)A,B
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,46)X
!CCCC   CALL DPWRST('XXX','BUG ')
        CDF=0.0D0
        GO TO 9000
      ELSEIF(X.GT.B)THEN
        CDF=1.0D0
        GO TO 9000
      ELSEIF(ALPHA.LE.0.0D0 .OR. ALPHA.GT.2.0)THEN
        WRITE(ICOUT,12)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        CDF=0.0D0
        GO TO 9000
      ELSEIF(BETA.LE.0.0D0)THEN
        WRITE(ICOUT,14)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        CDF=0.0D0
        GO TO 9000
      ELSEIF(B.EQ.A)THEN
        WRITE(ICOUT,16)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,48)A
        CALL DPWRST('XXX','BUG ')
        CDF=0.0D0
      ENDIF
!CCC2 FORMAT('***** ERROR--THE FIRST ARGUMENT TO RGTCDF IS OUTSIDE THE')
!CCC3 FORMAT('      (',G15.7,',',G15.7,') INTERVAL.')
   12 FORMAT('***** ERROR--THE SECOND ARGUMENT TO RGTCDF IS ',   &
             'OUTSIDE THE [0,2) INTERVAL')
   14 FORMAT('***** ERROR--THE THIRD ARGUMENT TO RGTCDF IS ',   &
             'IS NON-POSITIVE.')
   16 FORMAT('***** ERROR--THE LOWER AND UPPER LIMITS FOR RGTCDF ',   &
             'ARE EQUAL')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
   48 FORMAT('***** THE VALUE OF THE LIMIT IS ',G15.7)
!
!-----START POINT-----------------------------------------------------
!
      DX=(B-X)/(B-A)
      IF(X.LE.A)THEN
        CDF=0.0D0
      ELSEIF(X.GE.B)THEN
        CDF=1.0D0
      ELSE
        DTERM1=BETA*DLOG(DX)
        DTERM2=BETA*DLOG(ALPHA - (ALPHA-1.0D0)*DX)
        CDF=1.0D0 - DEXP(DTERM1 + DTERM2)
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE RGTCDF
      DOUBLE PRECISION FUNCTION RGTFUN(ALPHA,X)
!
!     PURPOSE--THIS ROUTINE IS USED IN FINDING THE ROOT OF THE
!              FOLLOWING EQUATION:
!
!              G(alpha) = {(N/SUM[i=1 to m]
!              [n(i)*LOG(1/(alpha*y(i)-(alpha-1)*y(i)**2))] - 1}*
!              SUM[i=1 to m][n(i)*(1 - y(i))/(alpha - (alpha-1)*y(i))]
!              + SUM[i=1 to m][n(i)*(1 - 2*y(i))/
!              (alpha - 2*(alpha-1)*y(i))]
!
!              WHERE
!
!              M       = NUMBER OF GROUPS
!              n(i)    = NUMBER OF OBSERVATIONS IN GROUP i
!              N       = TOTAL NUMBER OF OBSERVATIONS
!              y(i)    = 1 - XBAR(i)
!              XBAR(i) = MEAN OF THE iTH INTERVAL
!
!              THIS EQUATION IS USED TO PROVIDE AN APPROXIMATE
!              MAXIMUM LIKELIHOOD SOLUTION FOR THE
!              REFLECTED GENERALIZED TOPP AND LEONE DISTRIBUTION.
!
!              THIS ALGORITHM CAN IN FACT BE USED FOR RAW DATA,
!              GROUPS WITH EQUAL BIN SIZES, AND GROUPS WITH
!              UNEQUAL BIN SIZES.
!
!     EXAMPLE--REFLECTED GENERALIZED TOPP AND LEONE  MLE Y
!            --REFLECTED GENERALIZED TOPP AND LEONE  MLE Y X
!            --REFLECTED GENERALIZED TOPP AND LEONE  MLE Y XLOW XHIGH
!     REFERENCE--KOTZ AND VAN DORP (2004), "BEYOND BETA: OTHER
!                CONTINUOUS FAMILIES OF DISTRIBUTIONS WITH BOUNDED
!                SUPPORT AND APPLICATIONS", WORLD SCIENTIFIC,
!                PP. 211-213.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/7
!     ORIGINAL VERSION--JULY       2007.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION ALPHA
      DOUBLE PRECISION X(*)
!
      COMMON/RGTCOM/NTOT,NCLASS,MAXGRP
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DSUM3
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DXI
      DOUBLE PRECISION DNI
      DOUBLE PRECISION DYI
      DOUBLE PRECISION DN
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      DSUM1=0.0D0
      DSUM2=0.0D0
      DSUM3=0.0D0
!
      DN=DBLE(NTOT)
      DO 100 I=1,NCLASS
        DXI=X(I)
        DNI=X(I+MAXGRP)
!
        DYI=1.0D0 - DXI
        DTERM1=ALPHA*DYI - (ALPHA-1.0D0)*DYI**2
!
        DSUM1=DSUM1 + DNI*DLOG(1.0D0/DTERM1)
        DSUM2=DSUM2 + DNI*(1.0D0 - DYI)/(ALPHA-(ALPHA-1.0D0)*DYI)
        DSUM3=DSUM3 + DNI*(1.0D0 - 2.0D0*DYI)/   &
              (ALPHA-2.0D0*(ALPHA-1.0D0)*DYI)
!
  100 CONTINUE
!
      RGTFUN=((DN/DSUM1) - 1.0D0)*DSUM2 + DSUM3
!
      RETURN
      END FUNCTION RGTFUN
      SUBROUTINE RGTLI1(Y,N,   &
                        A,B,ALPHA,BETA,   &
                        ALIK,AIC,AICC,BIC,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE LOG-LIKIHOOD FUNCTION FOR
!              THE REFLECTED GENERALIZED TOPP AND LEONE DISTRIBUTION.
!              THIS IS FOR THE RAW DATA CASE (I.E., NO GROUPING AND NO
!              CENSORING).
!
!              NOTE THAT THE LOWER AND UPPER LIMITS MUST BE EXPLICITLY
!              GIVEN.
!
!     REFERENCE --KOTZ AND VAN DORP (2004), "BEYOND BETA: OTHER
!                 CONTINUOUS FAMILIES OF DISTRIBUTIONS WITH
!                 BOUNDED SUPPORT AND APPLICATIONS", WORLD
!                 SCIENTIFIC PUBLISHING CO., PP. 211-213.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2013/06
!     ORIGINAL VERSION--JUNE      2013.
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      DOUBLE PRECISION DA
      DOUBLE PRECISION DB
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DBETA
      DOUBLE PRECISION DN
      DOUBLE PRECISION DNP
      DOUBLE PRECISION DLIK
      DOUBLE PRECISION DPDF
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='RGTL'
      ISUBN2='I1  '
      IWRITE='OFF'
      IERROR='NO'
!
      ALIK=CPUMIN
      AIC=CPUMIN
      AICC=CPUMIN
      BIC=CPUMIN
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'TLI1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF RGTLI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N,A,B,ALPHA,BETA
   52   FORMAT('IBUGA3,ISUBRO,N,A,B,ALPHA,BETA = ',2(A4,2X),I8,4G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  COMPUTE LIKELIHOOD FUNCTION         **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'TLI1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL MINIM(Y,N,IWRITE,YMIN,IBUGA3,IERROR)
      CALL MAXIM(Y,N,IWRITE,YMAX,IBUGA3,IERROR)
      IF(A.GE.YMIN .OR. B.LE.YMAX)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
  101   FORMAT('**** ERROR IN REFLECTED GENERALIZED TOPP AND LEONE ',   &
               'LOG-LIKELIHOOD--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,103)
  103   FORMAT('     INVALID LIMITS:')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,105)A
  105   FORMAT('     LOWER LIMIT    = ',G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,106)YMIN
  106   FORMAT('     DATA MINIMUM   = ',G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,107)B
  107   FORMAT('     UPPER LIMIT    = ',G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,108)YMAX
  108   FORMAT('     DATA MAXIMUM   = ',G15.7)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!     COMPUTE THE LOG-LIKELIHOOD BY BRUTE FORCE (I.E., SUM  OF LOG OF
!     PDF VALUES.
!
      DALPHA=DBLE(ALPHA)
      DBETA=DBLE(BETA)
      DA=DBLE(A)
      DB=DBLE(B)
      DN=DBLE(N)
!
      DLIK=0.0D0
      DO 1010 I=1,N
        CALL RGTPDF(DBLE(Y(I)),DALPHA,DBETA,DA,DB,DPDF)
        IF(DPDF.GE.0.0D0)DLIK=DLIK + DLOG(DPDF)
 1010 CONTINUE
!
      ALIK=REAL(DLIK)
      DNP=2.0D0
      AIC=REAL(-2.0D0*DLIK + 2.0D0*DNP)
      DTERM3=(2.0D0*DNP*(DNP+1.0D0))/(DN-DNP-1.0D0)
      AICC=REAL(-2.0D0*DLIK + 2.0D0*DNP + DTERM3)
      BIC=REAL(-2.0D0*DLIK + DNP*LOG(DN))
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'TLI1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF RGTLI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9057)ALIK,AIC,AICC,BIC
 9057   FORMAT('ALIK,AIC,AICC,BIC = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE RGTLI1
      SUBROUTINE RGTML1(Y,XLOW,XHIGH,N,NUMV,MAXNXT,NTOT,   &
                        DTEMP1,TEMP1,TEMP2,TEMP3,TEMP4,   &
                        XMIN,XMAX,XMEAN,XSD,   &
                        ALPHSV,A,B,   &
                        ALPHML,BETAML,ALOWML,AUPPML,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD
!              ESTIMATES FOR THE REFLECTED GENERALIZED TOPP AND LEONE
!              DISTRIBUTION.
!
!              THE MAXIMUM LIKELIHOOD ESTIMATE OF BETA IS:
!
!                  BETAHAT = N/[SUM[i=1 to M]
!                  [n(i)*LOG(1/(ALPHA*Y(i) - (ALPHA - 1)Y(i)**2)]
!
!              WITH N(i) DENOTING THE SAMPLE SIZE OF GROUP i
!              AND Y(I) DENOTING 1 - XBAR(i) WHERE XBAR(i) IS
!              THE MEAN OF GROUP i.
!
!              ALPHA IS THE SOLUTION OF THE EQUATION
!
!              [N/[SUM[i=1 to M]
!              [n(i)*LOG(1/(ALPHA*Y(i) - (ALPHA - 1)Y(i)**2)]]*
!              SUM[i=1 to m][n(i)*(1 - y(i))/(ALPHA - (ALPHA - 1)*
!              Y(i)] +
!              SUM[i=1 to m][n(i)*(1 - 2*y(i))/(ALPHA -
!              2*(ALPHA - 1)*Y(i)]
!
!     EXAMPLE--REFLECTED GENERALIZED TOPP AND LEONE MAXIMUM LIKELIHOOD Y
!     REFERENCE --KOTZ AND VAN DORP (2004), "BEYOND BETA: OTHER
!                 CONTINUOUS FAMILIES OF DISTRIBUTIONS WITH
!                 BOUNDED SUPPORT AND APPLICATIONS", WORLD
!                 SCIENTIFIC PUBLISHING CO., PP. 211-213.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/07
!     ORIGINAL VERSION--JULY      2010. EXTRACTED AS A SEPARATE
!                                       SUBROUTINE (FROM DPMLRG)
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*40 IDIST
!
      DIMENSION Y(*)
      DIMENSION XLOW(*)
      DIMENSION XHIGH(*)
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
      DIMENSION TEMP3(*)
      DIMENSION TEMP4(*)
      DOUBLE PRECISION DTEMP1(*)
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      INTEGER IFLAG
!
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DTERM1
!
      DOUBLE PRECISION RGTFUN
      EXTERNAL RGTFUN
!
      COMMON/RGTCOM/NTOT2,NCLASS,MAXGRP
!
      DOUBLE PRECISION DA
      DOUBLE PRECISION DAE
      DOUBLE PRECISION DRE
      DOUBLE PRECISION DXSTRT
      DOUBLE PRECISION DXLOW
      DOUBLE PRECISION DXUP
!
      DOUBLE PRECISION DXI
      DOUBLE PRECISION DNI
      DOUBLE PRECISION DYI
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='RGTM'
      ISUBN2='L1  '
      IWRITE='OFF'
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'TML1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF RGTML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N,NUMV,MAXGRP
   52   FORMAT('IBUGA3,ISUBRO,N,NUMV,MAXGRP = ',A4,2X,A4,2X,3I8)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  CARRY OUT CALCULATIONS              **
!               **  FOR REFLECTED GENERALIZED TOPP AND  **
!               **  LEONE MLE ESTIMATE                  **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'TML1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IDIST='REFLECTED GENERALIZED TOPP AND LEONE'
      MAXGRP=MAXNXT/2
      IF(NUMV.EQ.1)THEN
        IFLAG=0
        CALL SUMRAW(Y,N,IDIST,IFLAG,   &
                    XMEAN,XVAR,XSD,XMIN,XMAX,   &
                    ISUBRO,IBUGA3,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
        CALL SORT(Y,N,Y)
        DO 180 I=1,N
          DTEMP1(I)=DBLE(Y(I))
          DTEMP1(I+MAXGRP)=1.0D0
  180   CONTINUE
        NTOT2=N
        NCLASS=N
!
      ELSEIF(NUMV.EQ.2)THEN
        IFLAG1=1
        IFLAG2=0
        CALL SUMGRP(Y,XLOW,N,IDIST,IFLAG1,IFLAG2,   &
                    TEMP1,TEMP2,TEMP3,MAXNXT,   &
                    XMEAN,XVAR,XSD,XMIN,XMAX,NTOT,   &
                    ISUBRO,IBUGA3,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
        CALL SORTC(XLOW,Y,N,TEMP1,TEMP2)
        DO 220 I=1,N
          XLOW(I)=TEMP1(I)
          Y(I)=TEMP2(I)
  220   CONTINUE
        DELTA=(XLOW(2) - XLOW(1))/2.0
!
        NCLASS=N
        NTOT2=NTOT
        DO 230 I=1,NCLASS
          DTEMP1(I)=DBLE(XLOW(I))
          DTEMP1(I+MAXGRP)=DBLE(Y(I))
  230   CONTINUE
!
      ELSEIF(NUMV.EQ.3)THEN
        IFLAG1=1
        IFLAG2=0
        CALL SUMGR2(Y,XLOW,XHIGH,N,IDIST,IFLAG1,IFLAG2,   &
                    TEMP1,TEMP2,TEMP3,MAXNXT,   &
                    XMEAN,XVAR,XSD,XMIN,XMAX,NTOT,   &
                    ISUBRO,IBUGA3,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
        CALL SORTC(XLOW,Y,N,TEMP1,TEMP2)
        CALL SORTC(XLOW,XHIGH,N,TEMP3,TEMP4)
        DO 320 I=1,N
          XLOW(I)=TEMP1(I)
          XHIGH(I)=TEMP4(I)
          Y(I)=TEMP2(I)
  320   CONTINUE
!
        DO 340 I=1,N
          DTEMP1(I)=DBLE((XHIGH(I) + XLOW(I))/2.0)
          DTEMP1(I+MAXGRP)=DBLE(Y(I))
  340   CONTINUE
!
        NCLASS=N
      ELSE
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!     NOW PERFORM THE MAXIMUM LIKELIHOOD ESTIMATION
!
!     STEP 1: NEED TO SCALE IF NOT WITHIN (0,1) INTERVAL.
!
!             IF USER SPECIFIES LIMITS, THEN USE THOSE.  IF NOT,
!             USE DATA MINIMUM/MAXIMUM.
!
      IFIX=1
!
      IF(A.NE.CPUMIN .AND. B.NE.CPUMIN .AND.   &
         A.LE.XMIN .AND. B.GE.XMAX) THEN
        IFIX=0
        ZLOC=A
        ZUPPLM=B
        ZSCALE=ZUPPLM - ZLOC
        DO 2110 I=1,NCLASS
          DTEMP1(I)=(DTEMP1(I) - DBLE(A))/DBLE(ZSCALE)
 2110   CONTINUE
      ELSEIF(XMIN.LT.0.0 .OR. XMAX.GT.1.0)THEN
        EPS=(XMAX-XMIN)*0.001
        ZLOC=XMIN - EPS
        ZUPPLM=XMAX+EPS
        ZSCALE=ZUPPLM - ZLOC
        DO 2120 I=1,NCLASS
          DTEMP1(I)=(DTEMP1(I) - DBLE(ZLOC))/DBLE(ZSCALE)
 2120   CONTINUE
      ELSE
        ZLOC=0.0
        ZUPPLM=1.0
        ZSCALE=1.0
      ENDIF
!
!     STEP 2: FIND ML ESTIMATE FOR ALPHA
!
      NTOT2=NTOT
      DXSTRT=1.5D0
      IF(ALPHSV.GE.0.0 .AND. ALPHSV.LE.2.0)DXSTRT=DBLE(ALPHSV)
      DXLOW=0.0D0
      DXUP=2.0D0
      DAE=2.0*0.000001D0*DXSTRT
      DRE=DAE
      IFLAG=0
      ITBRAC=0
      CALL DFZER2(RGTFUN,DXLOW,DXUP,DXSTRT,DRE,DAE,IFLAG,DTEMP1)
      ALPHML=REAL(DXLOW)
!
!     STEP 3: FIND ML ESTIMATE FOR BETA
!
      DSUM1=0.0D0
      DA=DBLE(ALPHML)
      DO 2210 I=1,NCLASS
        DXI=DTEMP1(I)
        DNI=DTEMP1(I+MAXGRP)
        DYI=1.0D0 - DXI
        DTERM1=1.0D0/(DA*DYI - (DA-1.0D0)*DYI**2)
        DSUM1=DSUM1 + DNI*DLOG(DTERM1)
 2210 CONTINUE
      BETAML=DBLE(NTOT2)/DSUM1
!
      ALOWML=ZLOC
      AUPPML=ZUPPLM
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'TML1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF RGTML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9055)N,XMEAN,XSD,XMIN,XMAX
 9055   FORMAT('N,XMEAN,XSD,XMIN,XMAX = ',I8,4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9057)ALPHML,BETAML,ALOWML,AUPPML
 9057   FORMAT('ALPHML,BETAML,ALOWML,AUPPML = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE RGTML1
      SUBROUTINE RGTPDF(X,ALPHA,BETA,A,B,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE
!              REFLECTED GENERALIZED TOPP AND LEONE DISTRIBUTION.
!              THE PROBABILITY DENSITY FUNCTION IS:
!
!                  f(X;ALPHA,BETA,A,B) = (BETA/(B-A))*
!                     ((B-X)/(B-A))**(BETA-1)*
!                     {ALPHA - (ALPHA-1)*((B-X)/(B-A))}**(BETA-1)*
!                     {ALPHA - 2*(ALPHA-1)*((B-X)/(B-A))}
!                     A <= X <= B, BETA > 0, 0 < ALPHA <= 2
!
!              WITH ALPHA AND BETA DENOTING THE SHAPE PARAMETERS.
!
!     INPUT  ARGUMENTS--X      = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                     --ALPHA  = THE DOUBLE PRECISION FIRST SHAPE
!                                PARAMETER
!                     --BETA   = THE DOUBLE PRECISION SECOND SHAPE
!                                PARAMETER
!     OUTPUT ARGUMENTS--PDF    = THE DOUBLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE BETWEEN 0 AND 1, INCLUSIVELY.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DLOG, DEXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--KOTZ AND VAN DORP (2004), "BEYOND BETA: OTHER
!                 CONTINUOUS FAMILIES OF DISTRIBUTIONS WITH BOUNDED
!                 SUPPORT AND APPLICATIONS", WORLD SCIENTFIC
!                 PUBLISHING COMPANY, CHAPTER 7.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--FEBRUARY  2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION X
      DOUBLE PRECISION ALPHA
      DOUBLE PRECISION BETA
      DOUBLE PRECISION A
      DOUBLE PRECISION B
      DOUBLE PRECISION PDF
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DX
      DOUBLE PRECISION DEPS
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(B.LT.A)THEN
        TERM1=B
        B=A
        A=TERM1
      ENDIF
!
      IF(X.LT.A .OR. X.GT.B)THEN
        WRITE(ICOUT,2)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3)A,B
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        PDF=0.0D0
        GO TO 9000
      ELSEIF(ALPHA.LE.0.0D0 .OR. ALPHA.GT.2.0)THEN
        WRITE(ICOUT,12)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        PDF=0.0D0
        GO TO 9000
      ELSEIF(BETA.LE.0.0D0)THEN
        WRITE(ICOUT,14)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        PDF=0.0D0
        GO TO 9000
      ELSEIF(B.EQ.A)THEN
        WRITE(ICOUT,16)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,48)A
        CALL DPWRST('XXX','BUG ')
        PDF=0.0D0
      ENDIF
    2 FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT TO RGTPDF IS ',   &
             'OUTSIDE THE')
    3 FORMAT('      (',G15.7,',',G15.7,') INTERVAL.')
   12 FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO RGTPDF IS ',   &
             'OUTSIDE THE [0,2) INTERVAL')
   14 FORMAT('***** ERROR--THE THIRD INPUT ARGUMENT TO RGTPDF IS ',   &
             'IS NON-POSITIVE.')
   16 FORMAT('***** ERROR--THE LOWER AND UPPER LIMITS FOR RGTPDF ',   &
             'ARE EQUAL')
   22 FORMAT('***** ERROR--FOR RGTPDF, WHEN BETA < 1, X SHOULD NOT',   &
             ' EQUAL THE UPPER LIMIT')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
   48 FORMAT('***** THE VALUE OF THE LIMIT IS ',G15.7)
   49 FORMAT('***** THE VALUE OF X IS ',G15.7)
   50 FORMAT('***** THE VALUE OF THE UPPER LIMIT IS ',G15.7)
!
!-----START POINT-----------------------------------------------------
!
      DX=(B-X)/(B-A)
      DEPS=1.0D-7
!
      IF(X.LE.A)THEN
        PDF=BETA*(2.0D0 - ALPHA)/(B-A)
      ELSEIF(X.GE.B)THEN
        IF(ABS(BETA-1.0D0).LE.DEPS)THEN
          PDF=BETA*ALPHA/(B-A)
        ELSEIF(BETA-1.0D0.GT.DEPS)THEN
          PDF=0.0D0
        ELSE
          WRITE(ICOUT,22)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,49)X
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,50)BETA
          CALL DPWRST('XXX','BUG ')
          PDF=0.0D0
          GO TO 9000
        ENDIF
      ELSE
        DTERM1=DLOG(BETA) - DLOG(B-A)
        DTERM2=(BETA-1.0D0)*DLOG(DX)
        DTERM3=(BETA-1.0D0)*DLOG(ALPHA - (ALPHA-1.0D0)*DX)
        DTERM4=DLOG(ALPHA - 2.0D0*(ALPHA-1.0D0)*DX)
        PDF=DEXP(DTERM1 + DTERM2 + DTERM3 + DTERM4)
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE RGTPDF
      SUBROUTINE RGTPPF(P,ALPHA,BETA,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE
!              REFLECTED GENERALIZED TOPP AND LEONE DISTRIBUTION.
!              THE PERCENT POINT FUNCTION IS:
!
!              G(P;ALPHA,BETA,A,B) =
!                  1-{ALPHA-SQRT(ALPHA**2-4*(ALPHA-1)*(1-P)**(1/BETA)}/
!                  {2*(ALPHA-1)}            FOR 1 < ALPHA <= 2
!                   1 - (1-P)**(1/BETA)     FOR ALPHA = 1
!                  1-{ALPHA+SQRT(ALPHA**2-4*(ALPHA-1)*(1-P)**(1/BETA)}/
!                  {2*(ALPHA-1)}            FOR 0 < ALPHA <= 2
!                  A <= X <= B, BETA > 0, 0 < ALPHA <= 2
!
!              WITH ALPHA AND BETA DENOTING THE SHAPE PARAMETERS.
!
!     INPUT  ARGUMENTS--X      = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --ALPHA  = THE DOUBLE PRECISION FIRST SHAPE
!                                PARAMETER
!                     --BETA   = THE DOUBLE PRECISION SECOND SHAPE
!                                PARAMETER
!     OUTPUT ARGUMENTS--PPF    = THE DOUBLE PRECISION PERCENT POINT
!                                FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PERCENT POINT FUNCTION VALUE PPF.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE BETWEEN 0 AND 1, INCLUSIVELY.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DLOG, DEXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--KOTZ AND VAN DORP (2004), "BEYOND BETA: OTHER
!                 CONTINUOUS FAMILIES OF DISTRIBUTIONS WITH BOUNDED
!                 SUPPORT AND APPLICATIONS", WORLD SCIENTFIC
!                 PUBLISHING COMPANY, CHAPTER 7.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--FEBRUARY  2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION P
      DOUBLE PRECISION ALPHA
      DOUBLE PRECISION BETA
      DOUBLE PRECISION PPF
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DEPS
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(P.LT.0.0D0 .OR. P.GT.1.0D0)THEN
        WRITE(ICOUT,2)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        PPF=0.0D0
        GO TO 9000
      ELSEIF(ALPHA.LE.0.0D0 .OR. ALPHA.GT.2.0)THEN
        WRITE(ICOUT,12)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        PPF=0.0D0
        GO TO 9000
      ELSEIF(BETA.LE.0.0D0)THEN
        WRITE(ICOUT,14)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        PPF=0.0D0
        GO TO 9000
      ENDIF
    2 FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT TO RGTPPF IS ',   &
             'OUTSIDE THE (0,1) INTERVAL.')
   12 FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO RGTPPF IS ',   &
             'OUTSIDE THE [0,2) INTERVAL')
   14 FORMAT('***** ERROR--THE THIRD INPUT ARGUMENT TO RGTPPF IS ',   &
             'IS NON-POSITIVE.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!-----START POINT-----------------------------------------------------
!
      DEPS=1.0D-7
      IF(P.LE.0.0D0)THEN
        PPF=0.0D0
      ELSEIF(P.GE.1.0D0)THEN
        PPF=1.0D0
      ELSE
        IF(DABS(ALPHA-1.0D0).LE.DEPS)THEN
          PPF=1.0D0 - (1.0D0 - P)**(1.0D0/BETA)
        ELSEIF(DABS(ALPHA-1.0D0).GT.DEPS)THEN
          DTERM1=ALPHA - DSQRT(ALPHA**2 - 4.0D0*(ALPHA - 1.0D0)*   &
                 (1.0D0 - P)**(1.0D0/BETA))
          DTERM2=2.0D0*(ALPHA - 1.0D0)
          PPF=1.0D0 - DTERM1/DTERM2
        ELSEIF(DABS(ALPHA-1.0D0).LT.DEPS)THEN
          DTERM1=ALPHA + DSQRT(ALPHA**2 - 4.0D0*(ALPHA - 1.0D0)*   &
                 (1.0D0 - P)**(1.0D0/BETA))
          DTERM2=2.0D0*(ALPHA - 1.0D0)
          PPF=1.0D0 - DTERM1/DTERM2
        ENDIF
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE RGTPPF
      SUBROUTINE RGTRAN(N,ALPHA,BETA,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE REFLECTED GENERALIZED TOPP AND LEONE
!              DISTRIBUTION WITH SHAPE PARAMETERS ALPHA AND BETA.
!
!              THE PROBABILITY DENSITY FUNCTION IS:
!
!                  f(X;ALPHA,BETA,A,B) = (BETA/(B-A))*
!                     ((B-X)/(B-A))**(BETA-1)*
!                     {ALPHA - (ALPHA-1)*((B-X)/(B-A))}**(BETA-1)*
!                     {ALPHA - 2*(ALPHA-1)*((B-X)/(B-A))}
!                     A <= X <= B, BETA > 0, 0 < ALPHA <= 2
!
!              WITH ALPHA AND BETA DENOTING THE SHAPE PARAMETERS.
!
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --ALPHA  = THE DOUBLE PRECISION FIRST SHAPE
!                                PARAMETER
!                     --BETA   = THE DOUBLE PRECISION VALUE OF THE
!                                SHAPE PARAMETER BETA.
!                                BETA SHOULD BE IN THE RANGE (0,1).
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE REFLECTED GENERALIZED TOPP AND LEONE
!             DISTRIBUTION WITH SHAPE PARAMETERS ALPHA AND BETA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, RGTPPF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--KOTZ AND VAN DORP (2004), "BEYOND BETA: OTHER
!                 CONTINUOUS FAMILIES OF DISTRIBUTIONS WITH BOUNDED
!                 SUPPORT AND APPLICATIONS", WORLD SCIENTFIC
!                 PUBLISHING COMPANY, CHAPTER 7.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHMOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007.2
!     ORIGINAL VERSION--FEBRUARY  2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION ALPHA
      DOUBLE PRECISION BETA
      DOUBLE PRECISION DTEMP
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR--THE REQUESTED NUMBER OF ',   &
      'REFLECTED GENERALIZED TOPP AND LEONE')
    6 FORMAT('      RANDOM NUMBERS IS NON-POSITIVE')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
!
      IF(BETA.LE.0.0D0)THEN
        WRITE(ICOUT,201)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,203)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
  201 FORMAT('***** ERROR--THE BETA SHAPE PARAMETER IS ',   &
             'NON-POSITIVE.')
  203 FORMAT('      THE VALUE OF BETA IS ',G15.7)
!
      IF(ALPHA.LE.0.0D0 .OR. ALPHA.GT.2.0D0)THEN
        WRITE(ICOUT,301)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,303)ALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
  301 FORMAT('***** ERROR--THE ALPHA SHAPE PARAMETER IS ',   &
             'OUTSIDE THE [0,2) INTERVAL.')
  303 FORMAT('      THE VALUE OF ALPHA IS ',G15.7)
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N REFLECTED GENERALIZED TOPP AND LEONE DISTRIBUTION
!     RANDOM NUMBERS USING THE PERCENT POINT FUNCTION TRANSFORMATION
!     METHOD.
!
      DO 300 I=1,N
        ZTEMP=X(I)
        CALL RGTPPF(DBLE(ZTEMP),ALPHA,BETA,DTEMP)
        X(I)=REAL(DTEMP)
  300 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE RGTRAN
      REAL FUNCTION RF (X, Y, Z, IER)
!***BEGIN PROLOGUE  RF
!***PURPOSE  Compute the incomplete or complete elliptic integral of the
!            1st kind.  For X, Y, and Z non-negative and at most one of
!            them zero, RF(X,Y,Z) = Integral from zero to infinity of
!                                -1/2     -1/2     -1/2
!                      (1/2)(t+X)    (t+Y)    (t+Z)    dt.
!            If X, Y or Z is zero, the integral is complete.
!***LIBRARY   SLATEC
!***CATEGORY  C14
!***TYPE      SINGLE PRECISION (RF-S, DRF-D)
!***KEYWORDS  COMPLETE ELLIPTIC INTEGRAL, DUPLICATION THEOREM,
!             INCOMPLETE ELLIPTIC INTEGRAL, INTEGRAL OF THE FIRST KIND,
!             TAYLOR SERIES
!***AUTHOR  Carlson, B. C.
!             Ames Laboratory-DOE
!             Iowa State University
!             Ames, IA  50011
!           Notis, E. M.
!             Ames Laboratory-DOE
!             Iowa State University
!             Ames, IA  50011
!           Pexton, R. L.
!             Lawrence Livermore National Laboratory
!             Livermore, CA  94550
!***DESCRIPTION
!
!   1.     RF
!          Evaluate an INCOMPLETE (or COMPLETE) ELLIPTIC INTEGRAL
!          of the first kind
!          Standard FORTRAN function routine
!          Single precision version
!          The routine calculates an approximation result to
!          RF(X,Y,Z) = Integral from zero to infinity of
!
!                               -1/2     -1/2     -1/2
!                     (1/2)(t+X)    (t+Y)    (t+Z)    dt,
!
!          where X, Y, and Z are nonnegative and at most one of them
!          is zero.  If one of them is zero, the integral is COMPLETE.
!          The duplication theorem is iterated until the variables are
!          nearly equal, and the function is then expanded in Taylor
!          series to fifth order.
!
!   2.     Calling Sequence
!          RF( X, Y, Z, IER )
!
!          Parameters on Entry
!          Values assigned by the calling routine
!
!          X      - Single precision, nonnegative variable
!
!          Y      - Single precision, nonnegative variable
!
!          Z      - Single precision, nonnegative variable
!
!
!
!          On Return     (values assigned by the RF routine)
!
!          RF     - Single precision approximation to the integral
!
!          IER    - Integer
!
!                   IER = 0 Normal and reliable termination of the
!                           routine.  It is assumed that the requested
!                           accuracy has been achieved.
!
!                   IER >  0 Abnormal termination of the routine
!
!          X, Y, Z are unaltered.
!
!
!   3.    Error Messages
!
!         Value of IER assigned by the RF routine
!
!                  Value assigned         Error Message Printed
!                  IER = 1                MIN(X,Y,Z) .LT. 0.0E0
!                      = 2                MIN(X+Y,X+Z,Y+Z) .LT. LOLIM
!                      = 3                MAX(X,Y,Z) .GT. UPLIM
!
!
!
!   4.     Control Parameters
!
!                  Values of LOLIM, UPLIM, and ERRTOL are set by the
!                  routine.
!
!          LOLIM and UPLIM determine the valid range of X, Y and Z
!
!          LOLIM  - Lower limit of valid arguments
!
!                   Not less than 5 * (machine minimum).
!
!          UPLIM  - Upper limit of valid arguments
!
!                   Not greater than (machine maximum) / 5.
!
!
!                     Acceptable Values For:   LOLIM      UPLIM
!                     IBM 360/370 SERIES   :   3.0E-78     1.0E+75
!                     CDC 6000/7000 SERIES :   1.0E-292    1.0E+321
!                     UNIVAC 1100 SERIES   :   1.0E-37     1.0E+37
!                     CRAY                 :   2.3E-2466   1.09E+2465
!                     VAX 11 SERIES        :   1.5E-38     3.0E+37
!
!
!
!          ERRTOL determines the accuracy of the answer
!
!                 The value assigned by the routine will result
!                 in solution precision within 1-2 decimals of
!                 "machine precision".
!
!
!
!          ERRTOL - Relative error due to truncation is less than
!                   ERRTOL ** 6 / (4 * (1-ERRTOL)  .
!
!
!
!              The accuracy of the computed approximation to the inte-
!              gral can be controlled by choosing the value of ERRTOL.
!              Truncation of a Taylor series after terms of fifth order
!              introduces an error less than the amount shown in the
!              second column of the following table for each value of
!              ERRTOL in the first column.  In addition to the trunca-
!              tion error there will be round-off error, but in prac-
!              tice the total error from both sources is usually less
!              than the amount given in the table.
!
!
!
!
!
!          Sample Choices:  ERRTOL   Relative Truncation
!                                    error less than
!                           1.0E-3    3.0E-19
!                           3.0E-3    2.0E-16
!                           1.0E-2    3.0E-13
!                           3.0E-2    2.0E-10
!                           1.0E-1    3.0E-7
!
!
!                    Decreasing ERRTOL by a factor of 10 yields six more
!                    decimal digits of accuracy at the expense of one or
!                    two more iterations of the duplication theorem.
!
! *Long Description:
!
!   RF Special Comments
!
!
!
!          Check by addition theorem: RF(X,X+Z,X+W) + RF(Y,Y+Z,Y+W)
!          = RF(0,Z,W), where X,Y,Z,W are positive and X * Y = Z * W.
!
!
!          On Input:
!
!          X, Y, and Z are the variables in the integral RF(X,Y,Z).
!
!
!          On Output:
!
!
!          X, Y, and Z are unaltered.
!
!
!
!          ********************************************************
!
!          Warning: Changes in the program may improve speed at the
!                   expense of robustness.
!
!
!
!   Special Functions via RF
!
!
!                  Legendre form of ELLIPTIC INTEGRAL of 1st kind
!                  ----------------------------------------------
!
!
!                                            2         2   2
!                  F(PHI,K) = SIN(PHI) RF(COS (PHI),1-K SIN (PHI),1)
!
!
!                                 2
!                  K(K) = RF(0,1-K ,1)
!
!                         PI/2     2   2      -1/2
!                       = INT  (1-K SIN (PHI) )   D PHI
!                          0
!
!
!
!
!
!                  Bulirsch form of ELLIPTIC INTEGRAL of 1st kind
!                  ----------------------------------------------
!
!
!                                         2 2    2
!                  EL1(X,KC) = X RF(1,1+KC X ,1+X )
!
!
!
!
!                  Lemniscate constant A
!                  ---------------------
!
!
!                       1      4 -1/2
!                  A = INT (1-S )    DS = RF(0,1,2) = RF(0,2,1)
!                       0
!
!
!    -------------------------------------------------------------------
!
!***REFERENCES  B. C. Carlson and E. M. Notis, Algorithms for incomplete
!                 elliptic integrals, ACM Transactions on Mathematical
!                 Software 7, 3 (September 1981), pp. 398-403.
!               B. C. Carlson, Computing elliptic integrals by
!                 duplication, Numerische Mathematik 33, (1979),
!                 pp. 1-16.
!               B. C. Carlson, Elliptic integrals of the first kind,
!                 SIAM Journal of Mathematical Analysis 8, (1977),
!                 pp. 231-242.
!***ROUTINES CALLED  R1MACH, XERMSG
!***REVISION HISTORY  (YYMMDD)
!   790801  DATE WRITTEN
!   890531  Changed all specific intrinsics to generic.  (WRB)
!   891009  Removed unreferenced statement labels.  (WRB)
!   891009  REVISION DATE from Version 3.2
!   891214  Prologue converted to Version 4.0 format.  (BAB)
!   900315  CALLs to XERROR changed to CALLs to XERMSG.  (THJ)
!   900326  Removed duplicate information from DESCRIPTION section.
!           (WRB)
!   900510  Changed calls to XERMSG to standard form, and some
!           editorial changes.  (RWC))
!   920501  Reformatted the REFERENCES section.  (WRB)
!***END PROLOGUE  RF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!CCCC CHARACTER*16 XERN3, XERN4, XERN5, XERN6
      INTEGER IER
      REAL LOLIM, UPLIM, EPSLON, ERRTOL
      REAL C1, C2, C3, E2, E3, LAMDA
      REAL MU, S, X, XN, XNDEV
      REAL XNROOT, Y, YN, YNDEV, YNROOT, Z, ZN, ZNDEV,   &
       ZNROOT
      LOGICAL FIRST
      SAVE ERRTOL,LOLIM,UPLIM,C1,C2,C3,FIRST
      DATA FIRST /.TRUE./
!
!***FIRST EXECUTABLE STATEMENT  RF
!
      IF (FIRST) THEN
         ERRTOL = (4.0E0*R1MACH(3))**(1.0E0/6.0E0)
         LOLIM  = 5.0E0 * R1MACH(1)
         UPLIM  = R1MACH(2)/5.0E0
!
         C1 = 1.0E0/24.0E0
         C2 = 3.0E0/44.0E0
         C3 = 1.0E0/14.0E0
      ENDIF
      FIRST = .FALSE.
!
!         CALL ERROR HANDLER IF NECESSARY.
!
      RF = 0.0E0
      IF (MIN(X,Y,Z).LT.0.0E0) THEN
         IER = 1
!CCCC    WRITE (XERN3, '(1PE15.6)') X
!CCCC    WRITE (XERN4, '(1PE15.6)') Y
!CCCC    WRITE (XERN5, '(1PE15.6)') Z
         WRITE(ICOUT,1)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9)X
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,8)Y
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,7)Z
         CALL DPWRST('XXX','BUG ')
         RETURN
      ENDIF
    1 FORMAT('***** ERORR FROM RF, ONE OF THE THREE ARGUMENTS IS',   &
             ' NEGATIVE. ***')
    9 FORMAT('***** THE VALUE OF THE FIRST ARGUMENT IS ',E15.8,' ***')
    8 FORMAT('***** THE VALUE OF THE SECOND ARGUMENT IS ',E15.8,' ***')
    7 FORMAT('***** THE VALUE OF THE THIRD ARGUMENT IS ',E15.8,' ***')
!
      IF (MAX(X,Y,Z).GT.UPLIM) THEN
         IER = 3
!CCCC    WRITE (XERN3, '(1PE15.6)') X
!CCCC    WRITE (XERN4, '(1PE15.6)') Y
!CCCC    WRITE (XERN5, '(1PE15.6)') Z
!CCCC    WRITE (XERN6, '(1PE15.6)') UPLIM
         WRITE(ICOUT,2)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9)X
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,8)Y
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,7)Z
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,6)UPLIM
         CALL DPWRST('XXX','BUG ')
         RETURN
      ENDIF
    2 FORMAT('***** ERORR FROM RF, ONE OF THE THREE ARGUMENTS EXCEEDS',   &
             ' THE LARGEST ALLOWABLE VALUE')
    6 FORMAT('***** THE VALUE OF THE UPPER LIMIT IS ',E15.8,' *****')
!
      IF (MIN(X+Y,X+Z,Y+Z).LT.LOLIM) THEN
         IER = 2
!CCCC    WRITE (XERN3, '(1PE15.6)') X
!CCCC    WRITE (XERN4, '(1PE15.6)') Y
!CCCC    WRITE (XERN5, '(1PE15.6)') Z
!CCCC    WRITE (XERN6, '(1PE15.6)') LOLIM
         WRITE(ICOUT,3)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9)X
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,8)Y
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,7)Z
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,5)LOLIM
         CALL DPWRST('XXX','BUG ')
         RETURN
      ENDIF
    3 FORMAT('***** ERORR FROM RF, THE MINIMUM OF THE PAIRWISE SUMS ',   &
             'OF THE ARGUMENTS IS LESS THAN THE LOWER LIMIT.')
    5 FORMAT('***** THE VALUE OF THE LOWER LIMIT IS ',E15.8,' *****')
!
      IER = 0
      XN = X
      YN = Y
      ZN = Z
!
   30 MU = (XN+YN+ZN)/3.0E0
      XNDEV = 2.0E0 - (MU+XN)/MU
      YNDEV = 2.0E0 - (MU+YN)/MU
      ZNDEV = 2.0E0 - (MU+ZN)/MU
      EPSLON = MAX(ABS(XNDEV), ABS(YNDEV), ABS(ZNDEV))
      IF (EPSLON.LT.ERRTOL) GO TO 40
      XNROOT =  SQRT(XN)
      YNROOT =  SQRT(YN)
      ZNROOT =  SQRT(ZN)
      LAMDA = XNROOT*(YNROOT+ZNROOT) + YNROOT*ZNROOT
      XN = (XN+LAMDA)*0.250E0
      YN = (YN+LAMDA)*0.250E0
      ZN = (ZN+LAMDA)*0.250E0
      GO TO 30
!
   40 E2 = XNDEV*YNDEV - ZNDEV*ZNDEV
      E3 = XNDEV*YNDEV*ZNDEV
      S  = 1.0E0 + (C1*E2-0.10E0-C2*E3)*E2 + C3*E3
      RF = S/SQRT(MU)
!
      RETURN
      END FUNCTION RF 
      REAL FUNCTION RJ (X, Y, Z, P, IER)
!***BEGIN PROLOGUE  RJ
!***PURPOSE  Compute the incomplete or complete (X or Y or Z is zero)
!            elliptic integral of the 3rd kind.  For X, Y, and Z non-
!            negative, at most one of them zero, and P positive,
!             RJ(X,Y,Z,P) = Integral from zero to infinity of
!                                  -1/2     -1/2     -1/2     -1
!                        (3/2)(t+X)    (t+Y)    (t+Z)    (t+P)  dt.
!***LIBRARY   SLATEC
!***CATEGORY  C14
!***TYPE      SINGLE PRECISION (RJ-S, DRJ-D)
!***KEYWORDS  COMPLETE ELLIPTIC INTEGRAL, DUPLICATION THEOREM,
!             INCOMPLETE ELLIPTIC INTEGRAL, INTEGRAL OF THE THIRD KIND,
!             TAYLOR SERIES
!***AUTHOR  Carlson, B. C.
!             Ames Laboratory-DOE
!             Iowa State University
!             Ames, IA  50011
!           Notis, E. M.
!             Ames Laboratory-DOE
!             Iowa State University
!             Ames, IA  50011
!           Pexton, R. L.
!             Lawrence Livermore National Laboratory
!             Livermore, CA  94550
!***DESCRIPTION
!
!   1.     RJ
!          Standard FORTRAN function routine
!          Single precision version
!          The routine calculates an approximation result to
!          RJ(X,Y,Z,P) = Integral from zero to infinity of
!
!                                -1/2     -1/2     -1/2     -1
!                      (3/2)(t+X)    (t+Y)    (t+Z)    (t+P)  dt,
!
!          where X, Y, and Z are nonnegative, at most one of them is
!          zero, and P is positive.  If X or Y or Z is zero, the
!          integral is COMPLETE.  The duplication theorem is iterated
!          until the variables are nearly equal, and the function is
!          then expanded in Taylor series to fifth order.
!
!
!   2.     Calling Sequence
!          RJ( X, Y, Z, P, IER )
!
!          Parameters On Entry
!          Values assigned by the calling routine
!
!          X      - Single precision, nonnegative variable
!
!          Y      - Single precision, nonnegative variable
!
!          Z      - Single precision, nonnegative variable
!
!          P      - Single precision, positive variable
!
!
!          On  Return     (values assigned by the RJ routine)
!
!          RJ     - Single precision approximation to the integral
!
!          IER    - Integer
!
!                   IER = 0 Normal and reliable termination of the
!                           routine.  It is assumed that the requested
!                           accuracy has been achieved.
!
!                   IER >  0 Abnormal termination of the routine
!
!
!          X, Y, Z, P are unaltered.
!
!
!   3.    Error Messages
!
!         Value of IER assigned by the RJ routine
!
!                  Value Assigned        Error Message Printed
!                  IER = 1               MIN(X,Y,Z) .LT. 0.0E0
!                      = 2               MIN(X+Y,X+Z,Y+Z,P) .LT. LOLIM
!                      = 3               MAX(X,Y,Z,P) .GT. UPLIM
!
!
!
!   4.     Control Parameters
!
!                  Values of LOLIM, UPLIM, and ERRTOL are set by the
!                  routine.
!
!
!          LOLIM and UPLIM determine the valid range of X Y, Z, and P
!
!          LOLIM is not less than the cube root of the value
!          of LOLIM used in the routine for RC.
!
!          UPLIM is not greater than 0.3 times the cube root of
!          the value of UPLIM used in the routine for RC.
!
!
!                     Acceptable Values For:   LOLIM      UPLIM
!                     IBM 360/370 SERIES   :   2.0E-26     3.0E+24
!                     CDC 6000/7000 SERIES :   5.0E-98     3.0E+106
!                     UNIVAC 1100 SERIES   :   5.0E-13     6.0E+11
!                     CRAY                 :   1.32E-822   1.4E+821
!                     VAX 11 SERIES        :   2.5E-13     9.0E+11
!
!
!
!          ERRTOL determines the accuracy of the answer
!
!                 The value assigned by the routine will result
!                 in solution precision within 1-2 decimals of
!                 "machine precision".
!
!
!
!
!          Relative error due to truncation of the series for RJ
!          is less than 3 * ERRTOL ** 6 / (1 - ERRTOL) ** 3/2.
!
!
!
!              The accuracy of the computed approximation to the inte-
!              gral can be controlled by choosing the value of ERRTOL.
!              Truncation of a Taylor series after terms of fifth order
!              Introduces an error less than the amount shown in the
!              second column of the following table for each value of
!              ERRTOL in the first column.  In addition to the trunca-
!              tion error there will be round-off error, but in prac-
!              tice the total error from both sources is usually less
!              than the amount given in the table.
!
!
!
!          Sample choices:  ERRTOL   Relative Truncation
!                                    error less than
!                           1.0E-3    4.0E-18
!                           3.0E-3    3.0E-15
!                           1.0E-2    4.0E-12
!                           3.0E-2    3.0E-9
!                           1.0E-1    4.0E-6
!
!                    Decreasing ERRTOL by a factor of 10 yields six more
!                    decimal digits of accuracy at the expense of one or
!                    two more iterations of the duplication theorem.
!
! *Long Description:
!
!   RJ Special Comments
!
!
!          Check by addition theorem: RJ(X,X+Z,X+W,X+P)
!          + RJ(Y,Y+Z,Y+W,Y+P) + (A-B) * RJ(A,B,B,A) + 3 / SQRT(A)
!          = RJ(0,Z,W,P), where X,Y,Z,W,P are positive and X * Y
!          = Z * W,  A = P * P * (X+Y+Z+W),  B = P * (P+X) * (P+Y),
!          and B - A = P * (P-Z) * (P-W).  The sum of the third and
!          fourth terms on the left side is 3 * RC(A,B).
!
!
!          On Input:
!
!          X, Y, Z, and P are the variables in the integral RJ(X,Y,Z,P).
!
!
!          On Output:
!
!
!          X, Y, Z, and P are unaltered.
!
!          ********************************************************
!
!          Warning: Changes in the program may improve speed at the
!                   expense of robustness.
!
! ------------------------------------------------------------
!
!
!   Special Functions via RJ and RF
!
!
!                  Legendre form of ELLIPTIC INTEGRAL of 3rd kind
!                  ----------------------------------------------
!
!
!                               PHI         2         -1
!                  P(PHI,K,N) = INT (1+N SIN (THETA) )   *
!                                0
!
!                                      2    2         -1/2
!                                 *(1-K  SIN (THETA) )     D THETA
!
!
!                                         2          2   2
!                       = SIN (PHI) RF(COS (PHI), 1-K SIN (PHI),1)
!
!                                  3            2         2   2
!                        -(N/3) SIN (PHI) RJ(COS (PHI),1-K SIN (PHI),
!
!                                 2
!                        1,1+N SIN (PHI))
!
!
!
!                  Bulirsch form of ELLIPTIC INTEGRAL of 3rd kind
!                  ----------------------------------------------
!
!
!                                           2 2    2
!                  EL3(X,KC,P) = X RF(1,1+KC X ,1+X ) +
!
!                                            3          2 2    2     2
!                               +(1/3)(1-P) X  RJ(1,1+KC X ,1+X ,1+PX )
!
!
!                                           2
!                  CEL(KC,P,A,B) = A RF(0,KC ,1) +
!
!                                                     2
!                                 +(1/3)(B-PA) RJ(0,KC ,1,P)
!
!
!
!
!                  Heuman's LAMBDA function
!                  ------------------------
!
!
!                                 2                     2      2    1/2
!                  L(A,B,P) = (COS(A)SIN(B)COS(B)/(1-COS (A)SIN (B))   )
!
!                                           2         2       2
!                            *(SIN(P) RF(COS (P),1-SIN (A) SIN (P),1)
!
!                                 2       3            2       2
!                            +(SIN (A) SIN (P)/(3(1-COS (A) SIN (B))))
!
!                                   2         2       2
!                            *RJ(COS (P),1-SIN (A) SIN (P),1,1-
!
!                                2       2          2       2
!                            -SIN (A) SIN (P)/(1-COS (A) SIN (B))))
!
!
!
!
!                  (PI/2) LAMBDA0(A,B) =L(A,B,PI/2) =
!
!
!                    2                         2       2    -1/2
!               = COS (A)  SIN(B) COS(B) (1-COS (A) SIN (B))
!
!                           2                  2       2
!                  *RF(0,COS (A),1) + (1/3) SIN (A) COS (A)
!
!                                       2       2    -3/2
!                  *SIN(B) COS(B) (1-COS (A) SIN (B))
!
!                           2         2       2          2       2
!                  *RJ(0,COS (A),1,COS (A) COS (B)/(1-COS (A) SIN (B)))
!
!
!
!                  Jacobi ZETA function
!                  --------------------
!
!
!                             2                     2   2    1/2
!                  Z(B,K) = (K/3) SIN(B) COS(B) (1-K SIN (B))
!
!
!                                      2      2   2                2
!                             *RJ(0,1-K ,1,1-K SIN (B)) / RF (0,1-K ,1)
!
!
!    -------------------------------------------------------------------
!
!***REFERENCES  B. C. Carlson and E. M. Notis, Algorithms for incomplete
!                 elliptic integrals, ACM Transactions on Mathematical
!                 Software 7, 3 (September 1981), pp. 398-403.
!               B. C. Carlson, Computing elliptic integrals by
!                 duplication, Numerische Mathematik 33, (1979),
!                 pp. 1-16.
!               B. C. Carlson, Elliptic integrals of the first kind,
!                 SIAM Journal of Mathematical Analysis 8, (1977),
!                 pp. 231-242.
!***ROUTINES CALLED  R1MACH, RC, XERMSG
!***REVISION HISTORY  (YYMMDD)
!   790801  DATE WRITTEN
!   890531  Changed all specific intrinsics to generic.  (WRB)
!   891009  Removed unreferenced statement labels.  (WRB)
!   891009  REVISION DATE from Version 3.2
!   891214  Prologue converted to Version 4.0 format.  (BAB)
!   900315  CALLs to XERROR changed to CALLs to XERMSG.  (THJ)
!   900326  Removed duplicate information from DESCRIPTION section.
!           (WRB)
!   900510  Changed calls to XERMSG to standard form, and some
!           editorial changes.  (RWC)).
!   920501  Reformatted the REFERENCES section.  (WRB)
!***END PROLOGUE  RJ
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!CCCC CHARACTER*16 XERN3, XERN4, XERN5, XERN6, XERN7
      INTEGER IER
      REAL ALFA, BETA, C1, C2, C3, C4, EA, EB, EC, E2, E3
      REAL LOLIM, UPLIM, EPSLON, ERRTOL
      REAL LAMDA, MU, P, PN, PNDEV
      REAL POWER4, RC, SIGMA, S1, S2, S3, X, XN, XNDEV
      REAL XNROOT, Y, YN, YNDEV, YNROOT, Z, ZN, ZNDEV,   &
       ZNROOT
      LOGICAL FIRST
      SAVE ERRTOL,LOLIM,UPLIM,C1,C2,C3,C4,FIRST
      DATA FIRST /.TRUE./
!
!***FIRST EXECUTABLE STATEMENT  RJ
      IF (FIRST) THEN
         ERRTOL = (R1MACH(3)/3.0E0)**(1.0E0/6.0E0)
         LOLIM  = (5.0E0 * R1MACH(1))**(1.0E0/3.0E0)
         UPLIM  = 0.30E0*( R1MACH(2) / 5.0E0)**(1.0E0/3.0E0)
!
         C1 = 3.0E0/14.0E0
         C2 = 1.0E0/3.0E0
         C3 = 3.0E0/22.0E0
         C4 = 3.0E0/26.0E0
      ENDIF
      FIRST = .FALSE.
!
!         CALL ERROR HANDLER IF NECESSARY.
!
      RJ = 0.0E0
      IF (MIN(X,Y,Z).LT.0.0E0) THEN
         IER = 1
!CCCC    WRITE (XERN3, '(1PE15.6)') X
!CCCC    WRITE (XERN4, '(1PE15.6)') Y
!CCCC    WRITE (XERN5, '(1PE15.6)') Z
         WRITE(ICOUT,1)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9)X
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,8)Y
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,7)Z
         CALL DPWRST('XXX','BUG ')
         RETURN
      ENDIF
    1 FORMAT('***** ERORR FROM RJ, ONE OF THE THREE ARGUMENTS IS',   &
             ' NEGATIVE. ***')
    9 FORMAT('***** THE VALUE OF THE FIRST ARGUMENT IS ',E15.8,' ***')
    8 FORMAT('***** THE VALUE OF THE SECOND ARGUMENT IS ',E15.8,' ***')
    7 FORMAT('***** THE VALUE OF THE THIRD ARGUMENT IS ',E15.8,' ***')
   11 FORMAT('***** THE VALUE OF THE FOURTH ARGUMENT IS ',E15.8,' ***')
!
      IF (MAX(X,Y,Z,P).GT.UPLIM) THEN
         IER = 3
!CCCC    WRITE (XERN3, '(1PE15.6)') X
!CCCC    WRITE (XERN4, '(1PE15.6)') Y
!CCCC    WRITE (XERN5, '(1PE15.6)') Z
!CCCC    WRITE (XERN6, '(1PE15.6)') P
!CCCC    WRITE (XERN7, '(1PE15.6)') UPLIM
         WRITE(ICOUT,2)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9)X
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,8)Y
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,7)Z
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,11)P
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,6)UPLIM
         CALL DPWRST('XXX','BUG ')
         RETURN
      ENDIF
    2 FORMAT('***** ERORR FROM RJ, ONE OF THE FOUR ARGUMENTS EXCEEDS',   &
             'THE LARGEST ALLOWABLE VALUE')
    6 FORMAT('***** THE VALUE OF THE UPPER LIMIT IS ',E15.8,' *****')
!
      IF (MIN(X+Y,X+Z,Y+Z,P).LT.LOLIM) THEN
         IER = 2
!CCCC    WRITE (XERN3, '(1PE15.6)') X
!CCCC    WRITE (XERN4, '(1PE15.6)') Y
!CCCC    WRITE (XERN5, '(1PE15.6)') Z
!CCCC    WRITE (XERN6, '(1PE15.6)') P
!CCCC    WRITE (XERN7, '(1PE15.6)') LOLIM
         WRITE(ICOUT,3)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,4)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9)X
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,8)Y
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,7)Z
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,11)P
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,5)LOLIM
         CALL DPWRST('XXX','BUG ')
         RETURN
      ENDIF
    3 FORMAT('***** ERORR FROM RJ, THE MINIMUM OF THE PAIRWISE SUMS ',   &
             'OF THE FIRST THREE ARGUMENTS ')
    4 FORMAT('      OR THE FOURTH ARGUMENT IS LESS THAN THE LOWER ',   &
             'LIMIT.')
    5 FORMAT('***** THE VALUE OF THE LOWER LIMIT IS ',E15.8,' *****')
!
      IER = 0
      XN = X
      YN = Y
      ZN = Z
      PN = P
      SIGMA = 0.0E0
      POWER4 = 1.0E0
!
   30 MU = (XN+YN+ZN+PN+PN)*0.20E0
      XNDEV = (MU-XN)/MU
      YNDEV = (MU-YN)/MU
      ZNDEV = (MU-ZN)/MU
      PNDEV = (MU-PN)/MU
      EPSLON = MAX(ABS(XNDEV), ABS(YNDEV), ABS(ZNDEV), ABS(PNDEV))
      IF (EPSLON.LT.ERRTOL) GO TO 40
      XNROOT =  SQRT(XN)
      YNROOT =  SQRT(YN)
      ZNROOT =  SQRT(ZN)
      LAMDA = XNROOT*(YNROOT+ZNROOT) + YNROOT*ZNROOT
      ALFA = PN*(XNROOT+YNROOT+ZNROOT) + XNROOT*YNROOT*ZNROOT
      ALFA = ALFA*ALFA
      BETA = PN*(PN+LAMDA)*(PN+LAMDA)
      SIGMA = SIGMA + POWER4*RC(ALFA,BETA,IER)
      POWER4 = POWER4*0.250E0
      XN = (XN+LAMDA)*0.250E0
      YN = (YN+LAMDA)*0.250E0
      ZN = (ZN+LAMDA)*0.250E0
      PN = (PN+LAMDA)*0.250E0
      GO TO 30
!
   40 EA = XNDEV*(YNDEV+ZNDEV) + YNDEV*ZNDEV
      EB = XNDEV*YNDEV*ZNDEV
      EC = PNDEV*PNDEV
      E2 = EA - 3.0E0*EC
      E3 = EB + 2.0E0*PNDEV*(EA-EC)
      S1 = 1.0E0 + E2*(-C1+0.750E0*C3*E2-1.50E0*C4*E3)
      S2 = EB*(0.50E0*C2+PNDEV*(-C3-C3+PNDEV*C4))
      S3 = PNDEV*EA*(C2-PNDEV*C3) - C2*PNDEV*EC
      RJ = 3.0E0*SIGMA + POWER4*(S1+S2+S3)/(MU* SQRT(MU))
      RETURN
      END FUNCTION RJ 
      SUBROUTINE RDMNOR(AMU,SIG,LDSIG,N,LTF,ZM,IFLAG,ISEED)
!
!-----------------------------------------------------------------------
!   RDMNOR   WRITTEN BY CHARLES P. REEVE, STATISTICAL ENGINEERING
!            DIVISION, NATION INSTITUTE OF STANDARDS AND TECHNOLOGY, GAITHERSBURG,
!            MARYLAND  20899
!
!   FOR: COMPUTING A VECTOR OF PSEUDO-RANDOM MULTIVARIATE NORMAL
!        DEVIATES WITH MEAN AMU AND VARIANCE SIG.  BEFORE THE FIRST
!        CALL WITH A GIVEN SIG, THE LOGICAL VARIABLE LTF MUST BE
!        ASSIGNED THE VALUE .TRUE. SO THAT A CHOLESKY FACTORIZATION
!        OF SIG IS PERFORMED AS IN THE REFERENCE.  THE RESULT IS A
!        LOWER TRIANGULAR MATRIX L, STORED IN THE LOWER TRIANGLE OF
!        SIG, SUCH THAT SIG=LL'.  FURTHER CALL TO RDMNOR USE ONLY THE
!        LOWER TRIANGLE OF SIG (L) IN COMPUTING THE DEVIATES UNTIL THE
!        VALUE OF LTF IS RESET TO .TRUE., EVEN IS SIG IS REDEFINED.
!
!   NOTE: BEFORE THE FIRST CALL TO THIS ROUTINE THE CALL
!
!                           Z = RDNOR(ISEED)
!
!         FOR DATAPLOT, PASS SEED AS AGRUMENT
!
!         SHOULD BE MADE IN ORDER TO INITIALIZE THE NORMAL RANDOM
!         NUMBER GENERATOR WHERE ISEED IS A POSITIVE INTEGER.  THIS
!         ALLOWS THE USER TO ESTABLISH A REPEATABLE SEQUENCE OF
!         DEVIATES.
!
!   SUBPROGRAMS CALLED: RDNOR (PSEUDO-RANDOM NORMAL GENERATOR)
!
!                       FOR DATAPLOT, REPLACE WITH NORRAN
!
!   CURRENT VERSION COMPLETED MAY 15, 1987
!
!   REFERENCE: STEWART, G.W., 'INTRODUCTION TO MATRIX COMPUTATIONS',
!              ACADEMIC PRESS, ALGORITHM 3.9, P 142.
!-----------------------------------------------------------------------
!   DEFINITION OF PASSED PARAMETERS:
!
!     * AMU = MEAN VECTOR (LENGTH N) OF THE MULTIVARIATE NORMAL
!             DEVIATES ZM (REAL)
!
!     * SIG = COVARIANCE MATRIX (SIZE NXN) OF THE MULTIVARIATE NORMAL
!             DEVIATES ZM (REAL)
!
!   * LDSIG = THE LEADING DIMENSION OF MATRIX SIG (>=N) (INTEGER)
!
!       * N = THE LENGTH OF THE VECTOR OF DEVIATES ZM (INTEGER)
!
!     * LTF = AN INDICATOR VARIABLE FOR PERFORMING A CHOLESKY
!             FACTORIZATION OF A NEW COVARIANCE MATRIX SIG (LOGICAL)
!
!        ZM = A PSEUDO-RANDOM MULTIVARIATE NORMAL VECTOR (LENGTH N)
!             WITH MEAN AMU AND VARIANCE SIG (REAL)
!
!     IFLAG = AN ERROR INDICATOR ON OUTPUT (INTEGER)   INTERPRETATION:
!             0 -> NO ERRORS DETECTED
!             1 -> THE MATRIX SIG IS NOT POSITIVE SEMIDEFINITE, THUS
!                  CANNOT BE A COVARIANCE MATRIX - NO DEVIATE GENERATED
!
!     ISEED = AN INTEGER THAT SPECIFIES THE SEED FOR THE DATAPLOT
!             RANDOM NUMBER GENERATOR.
!
!   * INDICATES VARIABLES REQUIRING INPUT VALUES
!-----------------------------------------------------------------------
      DIMENSION AMU(*),SIG(LDSIG,*),ZM(*)
      LOGICAL LTF
!
!--- IF NEW MATRIX SIG, PERFORM CHOLESKY FACTORIZATION.  SET ERROR
!--- FLAG IF SIG IS NOT POSITIVE DEFINITE
!
      IF (LTF) THEN
         DO 40 K = 1, N
            DO 20 I = 1, K-1
               S = 0.0
               DO 10 J = 1, I-1
                  S = S+SIG(I,J)*SIG(K,J)
   10          CONTINUE
               SIG(K,I) = (SIG(K,I)-S)/SIG(I,I)
   20       CONTINUE
            S = 0.0
            DO 30 J = 1, K-1
               S = S+SIG(K,J)**2
   30       CONTINUE
            Q = SIG(K,K)-S
            IF (Q.LT.0.0) THEN
               IFLAG = 1
               RETURN
            ELSE
               IF(Q.GT.0.0)THEN
                 SIG(K,K) = SQRT(Q)
               ELSE
                 SIG(K,K)=0.0
               ENDIF
            ENDIF
   40    CONTINUE
         LTF = .FALSE.
      ENDIF
      IFLAG = 0
!
!--- COMPUTE N INDEPENDENT N(0,1) PSEUDO-RANDOM DEVIATES IN ZM
!
!CCCC DO 50 I = 1, N
!CCCC    ZM(I) = RDNOR(0)
!CC50 CONTINUE
      CALL NORRAN(N,ISEED,ZM)
!
!--- COMPUTE THE PSEUDO-RANDOM MULTIVARIATE NORMAL DEVIATES IN ZM
!
      DO 70 I = N, 1, -1
         S = 0.0
         DO 60 J = 1, I
            S = S+SIG(I,J)*ZM(J)
   60    CONTINUE
         ZM(I) = AMU(I)+S
   70 CONTINUE
      RETURN
      END SUBROUTINE RDMNOR
      FUNCTION RDT (DF,ISEED)
!
!-----------------------------------------------------------------------
!   RDT   WRITTEN BY CHARLES P. REEVE, STATISTICAL ENGINEERING
!         DIVISION, NATIONAL BUREAU OF STANDARDS, GAITHERSBURG,
!
!   FOR: GENERATING A RANDOM DEVIATE FROM THE T(DF) DISTRIBUTION.
!        ONE OF THREE METHODS IS USED DEPENDING ON THE VALUE OF THE
!        PARAMETER DF (WHICH DOES NOT HAVE TO BE AN INTEGER):
!
!             VALUE OF DF             METHOD USED
!            -------------         ------------------
!              0 < DF < 1          NORMAL/SQRT(CHI-SQUARED/DF)
!                DF = 1            TANGENT TRANSFORMATION (CST)
!                DF > 1            KINDERMAN-MONAHAN-RAMAGE (TIR)
!
!        IF DF <= 0 AN ERROR MESSAGE IS PRINTED AND EXECUTION IS
!        TERMINATED.
!
!        DESCRIPTIONS OF EACH OF THESE ALGORITHMS CAN BE FOUND IN
!        THE REFERENCE GIVEN BELOW.
!
!   SUBPROGRAMS CALLED:  RDUNI (STSPAC) - UNIFORM(0,1) GENERATOR
!                        RDNOR (STSPAC) - NORMAL(0,1) GENERATOR
!                       RDCHI2 (STSPAC) - CHI-SQUARED GENERATOR
!
!   CURRENT VERSION COMPLETED FEBRUARY 28, 1986
!
!   REFERENCE: KINDERMAN, A.J., MONAHAN, J.F., AND RAMAGE, J.G.,
!              "COMPUTER METHODS FOR SAMPLING FROM STUDENT'S T
!              DISTRIBUTION", MATHEMATICS OF COMPUTATION, VOLUME 31,
!              NUMBER 140, OCTOBER 1977, PP. 1009-1018
!
!   ADAPTED FOR DATAPLOT.  USE THIS ALGORITHM FOR THE CASE OF
!   NON-INTEGER DEGREES OF FREEDOM.  CHANGE TO USE DATAPLOT UNIFORM
!   RANDOM NUMBER GENERATOR.
!
      REAL XTEMP(1)
!
!-----------------------------------------------------------------------
!
      F(X,A) = (1.0+X*X/A)**(-(A+1.0)/2.0)
!
      RDT=0.0
      IF (DF.GT.1.0) THEN
!
!
!   KINDERMAN-MONAHAN-RAMAGE ALGORITHM (TIR)
!
!--- STEP 1
!
   10    CONTINUE
!CCCC    U = RDUNI(0)
         CALL UNIRAN(1,ISEED,XTEMP)
         U=XTEMP(1)
         IF (U.GE.0.23079283) GO TO 20
         RDT = 4.0*U-0.46158566
!
!--- STEP 2
!
!CCCC    V = RDUNI(0)
         CALL UNIRAN(1,ISEED,XTEMP)
         V=XTEMP(1)
         IF (V.LE.1.0-0.5*ABS(RDT)) RETURN
         IF (V.LE.F(RDT,DF)) RETURN
         GO TO 10
!
!--- STEP 3
!
   20    IF (U.GE.0.5) GO TO 40
         S = 4.0*U-1.46158566
         RDT = SIGN(ABS(S)+0.46158566,S)
!CCCC    V = RDUNI(0)
         CALL UNIRAN(1,ISEED,XTEMP)
         V=XTEMP(1)
!
!--- STEP 4
!
   30    IF (V.LE.1.0-0.5*ABS(RDT)) RETURN
         IF (V.GE.1.2130613/(1.0+RDT*RDT)) GO TO 10
         IF (V.LE.F(RDT,DF)) RETURN
         GO TO 10
!
!--- STEP 5
!
   40    IF (U.GE.0.75) GO TO 50
         S = 8.0*U-5.0
         RDT = 2.0/SIGN(ABS(S)+1.0,S)
!CCCC    V = RDUNI(0)/(RDT*RDT)
         CALL UNIRAN(1,ISEED,XTEMP)
         V=XTEMP(1)
         GO TO 30
!
!--- STEP 6
!
   50    RDT = 2.0/(8.0*U-7.0)
!CCCC    V = RDUNI(0)
         CALL UNIRAN(1,ISEED,XTEMP)
         V=XTEMP(1)
         IF (V.LT.RDT*RDT*F(RDT,DF)) RETURN
         GO TO 10
!
      ELSEIF (DF.EQ.1.0) THEN
!
!
!   SYNTHETIC TANGENT ALGORITHM (CST)
!
!--- STEP 1
!
   60    CONTINUE
!CCCC    U = RDUNI(0)
         CALL UNIRAN(1,ISEED,XTEMP)
         U=XTEMP(1)
!CCCC    V = 2.0*RDUNI(0)-1.0
         CALL UNIRAN(1,ISEED,XTEMP)
         V=2.0*XTEMP(1)-1.0
!
!--- STEP 2
!
         IF (U*U+V*V.GT.1.0) GO TO 60
         RDT = V/U
         RETURN
!
      ELSEIF (DF.GT.0.0) THEN
!
!
!   RATIO OF STANDARD NORMAL AND SQUARE ROOT OF
!   CHI-SQUARED DIVIDED BY ITS DEGREES OF FREEDOM
!
!
!CCCC    D = SQRT(RDCHI2(DF)/DF)
         CALL CHSRAN(1,DF,ISEED,XTEMP)
         D = SQRT(XTEMP(1)/DF)
!CCCC    RDT = RDNOR(0)/D
         CALL NORRAN(1,ISEED,XTEMP)
         RDT = XTEMP(1)/D
      ELSE
!CCCC    PRINT *,' *** DEGREES OF FREEDOM MUST BE > 0'
!CCCC    PRINT *,' *** EXECUTION STOPPED IN FUNCTION RDT'
!CCCC    STOP
!
      ENDIF
      RETURN
      END FUNCTION RDT 
      SUBROUTINE RECCDF(X,B,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE RECIPROCAL
!              DISTRIBUTION WITH SINGLE PRECISION
!              TAIL LENGTH PARAMETER = B.
!              THE RECIPROCAL DISTRIBUTION USED
!              HEREIN IS DEFINED FOR 1/B <= x < 1.
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = 1/(X*LOG(B))
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE GREATER THAN
!                                OR EQUAL TO 1.
!                     --B      = THE SINGLE PRECISION VALUE
!                                OF THE TAIL LENGTH PARAMETER.
!                                B SHOULD BE > 1.
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE RECIPROCAL
!             DISTRIBUTION WITH TAIL LENGTH PARAMETER VALUE = B.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--B SHOULD BE > 1.
!                 --X SHOULD BE POSITIVE AND LESS THAN 1.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--R. W. HAMMING, NUMERICAL METHODS FOR SCIENTISTS
!                 AND ENGINEERS, 2ND. ED., 1973, PAGE 34.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--MAY       1996.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DB
      DOUBLE PRECISION DCDF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(B.LE.1.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)B
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
   15 FORMAT('***** FATAL DIAGNOSTIC--THE SECOND INPUT ARGUMENT ',   &
      'TO RECPDF IS LESS THAN OR EQUAL TO 1')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
      IF(X.LT.(1./B))THEN
        CDF=0.0
        GO TO 9999
      ENDIF
      IF(X.GE.1.0)THEN
        CDF=1.0
        GO TO 9999
      ENDIF
!
!-----START POINT-----------------------------------------------------
!
      DX=DBLE(X)
      DB=DBLE(B)
      DCDF=(DLOG(DX)+DLOG(DB))/DLOG(DB)
      CDF=SNGL(DCDF)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE RECCDF
      SUBROUTINE RECIPG(X,ODD,EVEN,RG)
! THIS ROUTINE IS A TRANSLATION INTO FORTRAN OF THE ALGOL PROCEDURE
! RECIPGAMMA GIVEN IN   N. M. TEMME, ON THE NUMERICAL EVALUATION OF THE
! MODIFIED BESSEL FUNCTION OF THE THIRD KIND, J. COMP. PHYSICS, VOLUME
! 19, PAGE 324 (1975).
      DIMENSION B(12)
!-----------------------------------------------------------------------
!
!  MACHINE DEPENDENT CONSTANTS.
!  ---------------------------
!
      DATA B(1), B(2), B(3), B(4), B(5), B(6), B(7), B(8), B(9), B(10),   &
           B(11), B(12)   &
            /-.28387654227602,-.076852840844786,.001706305071096,   &
        .001271927136655,.000076309597586,-.4971736704E-5,-.865920800E-6,   &
       -.33126120E-7,.1745136E-8,.242310E-9,.9161E-11,-.170E-12/
!
!-----------------------------------------------------------------------
      X2=8.*X*X
      ALFA=-1.E-15
      BETA=0.
      DO 1 N=1,11,2
        BETA=-(BETA+2.*ALFA)
        ITEMP = 13 - N
        ALFA = - X2 * BETA - ALFA + B(ITEMP)
    1 CONTINUE
      EVEN=(ALFA+.5*BETA)*X2-ALFA+.92187029365045
      ALFA=-.34E-13
      BETA=0.
      DO 2 N=2,12,2
        BETA=-(BETA+2.*ALFA)
        ITEMP = 13 - N
        ALFA = - X2 * BETA - ALFA + B(ITEMP)
    2 CONTINUE
      ODD=2.*(ALFA+BETA)
      RG=ODD*X+EVEN
      RETURN
      END SUBROUTINE RECIPG
      SUBROUTINE RECPDF(X,B,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE RECIPROCAL
!              DISTRIBUTION WITH SINGLE PRECISION
!              TAIL LENGTH PARAMETER = B.
!              THE RECIPROCAL DISTRIBUTION USED
!              HEREIN IS DEFINED FOR 1/B <= x < 1.
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = 1/(X*LOG(B))
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE GREATER THAN
!                                OR EQUAL TO 1.
!                     --B      = THE SINGLE PRECISION VALUE
!                                OF THE TAIL LENGTH PARAMETER.
!                                B SHOULD BE > 1.
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE RECIPROCAL
!             DISTRIBUTION WITH TAIL LENGTH PARAMETER VALUE = B.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--B SHOULD BE POSITIVE.
!                 --X SHOULD BE POSITIVE AND LESS THAN 1.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--R. W. HAMMING, NUMERICAL METHODS FOR SCIENTISTS
!                 AND ENGINEERS, 2ND. ED., 1973, PAGE 34.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--MAY       1996.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DB
      DOUBLE PRECISION DPDF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(B.LE.1.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)B
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
   15 FORMAT('***** FATAL DIAGNOSTIC--THE SECOND INPUT ARGUMENT ',   &
      'TO RECPDF IS LESS THAN OR EQUAL TO 1')
      IF(X.LT.(1./B).OR.X.GE.1.0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
    4 FORMAT('***** FATAL DIAGNOSTIC--THE FIRST  INPUT ARGUMENT ',   &
      'TO RECPDF IS OUTSIDE THE (1/B,1) INTERVAL')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
!
!-----START POINT-----------------------------------------------------
!
      DX=DBLE(X)
      DB=DBLE(B)
      DPDF=1.0D0/(DX*DLOG(DB))
      PDF=SNGL(DPDF)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE RECPDF
      SUBROUTINE RECPPF(P,B,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE RECIPROCAL
!              DISTRIBUTION WITH SINGLE PRECISION
!              TAIL LENGTH PARAMETER = B.
!              THE RECIPROCAL DISTRIBUTION USED
!              HEREIN IS DEFINED FOR 1/B <= X < 1.
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = 1/(X*LOG(B))
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                SPECIFYING THE PROBABILITY VALUE.
!                                P SHOULD BE GREATER THAN OR EQUAL TO 0
!                                AND LESS THAN OR EQUAL TO 1.
!                     --B      = THE SINGLE PRECISION VALUE
!                                OF THE TAIL LENGTH PARAMETER.
!                                B SHOULD BE > 1.
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT
!                                POINT FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT
!             FUNCTION VALUE PPF FOR THE RECIPROCAL
!             DISTRIBUTION WITH TAIL LENGTH PARAMETER VALUE = B.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--B SHOULD BE > 1.
!                 --P SHOULD BE >= 0 AND <= 1
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--R. W. HAMMING, NUMERICAL METHODS FOR SCIENTISTS
!                 AND ENGINEERS, 2ND. ED., 1973, PAGE 34.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--MAY       1996.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DP
      DOUBLE PRECISION DB
      DOUBLE PRECISION DPPF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(P.LT.0.0.OR.P.GT.1.0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
    4 FORMAT('***** FATAL DIAGNOSTIC--THE FIRST  INPUT ARGUMENT ',   &
      'TO RECPPF IS OUTSIDE THE (0,1) INTERVAL')
      IF(B.LE.1.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)B
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
   15 FORMAT('***** FATAL DIAGNOSTIC--THE SECOND INPUT ARGUMENT ',   &
      'TO RECPDF IS LESS THAN OR EQUAL TO 0')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
      IF(P.EQ.0.0)THEN
        PPF=1.0/B
        GO TO 9999
      ENDIF
      IF(P.EQ.1.0)THEN
        PPF=1.0
        GO TO 9999
      ENDIF
!
!-----START POINT-----------------------------------------------------
!
      DP=DBLE(P)
      DB=DBLE(B)
      DPPF=DEXP(DLOG(DB)*(DP-1.0D0))
      PPF=SNGL(DPPF)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE RECPPF
      SUBROUTINE RECRAN(N,B,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE RECIROCAL DISTRIBUTION
!              WITH SHAPE PARAMETER VALUE = B.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --B  = THE SINGLE PRECISION VALUE OF THE
!                                SHAPE PARAMETER.
!                                B SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE RECIROCAL DISTRIBUTION
!             WITH SHAPE PARAMETER VALUE = B.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --B SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--XX
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2001.10
!     ORIGINAL VERSION--OCTOBER   2001.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
      IF(B.LE.1.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)B
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT TO THE ',   &
      'RECRAN SUBROUTINE IS NON-POSITIVE *****')
   15 FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO THE ',   &
      'RECRAN SUBROUTINE IS <= 1 *****')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,' *****')
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N RECIROCAL DISTRIBUTION RANDOM NUMBERS
!     USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      DO 100 I=1,N
        CALL RECPPF(X(I),B,XTEMP)
        X(I)=XTEMP
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE RECRAN
      SUBROUTINE REGDAT (NPAR, NTOT, NBCH, NPTS, XPTS, Y, COEF,   &
                        SCRTCH, S1, V1, TLM0, TLM1, ETA0, ETA1,   &
                        WK1, XM, T, X, NLVL,   &
                        ICASRE, IFLAG, ISUBRO, IBUGA2, IERROR)
!
!         SUBROUTINE REGDAT PERFORMS ALL OF THE REGRESSION TOLERANCE LIMIT
!     CALCULATIONS WHICH INVOLVE THE RESPONSE (Y) DATA.  REGINI MUST BE
!     CALLED BEFORE REGDAT, BUT IF MULTIPLE SETS OF Y DATA ARE TO BE
!     ANALYZED (E.G., IN A SIMULATION), THEN REGINI NEED ONLY BE CALLED
!     ONCE.
!
      IMPLICIT DOUBLE PRECISION (A-H, O-Z)
      INCLUDE 'DPCOPA.INC'
!
      LOGICAL CONFND
      CHARACTER*4 ICASRE
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
      CHARACTER*4 IBUGA2
      CHARACTER*4 IBUGA3
      CHARACTER*4 IOP
      CHARACTER*4 IFLAG
!CCCC CHARACTER*80 IFILE
      CHARACTER (LEN=MAXFNC) :: IFILE
!
!CCCC DIMENSION U1(*),   S1(*),   V1(*),   U2(*),   Y(*),    COEF(*),
      DIMENSION SCRTCH(*),   S1(*),   V1(*),   Y(*),    COEF(*),   &
                XPTS(*), ETA0(*), ETA1(*), TLM0(*), TLM1(*), XM(*),   &
                T(*),    WK1(*), X(*)
!
      COMMON /RECIPA/ IRANK1, IRANK2, TR1, TR2, GNU0, GNU1, CONFND
      COMMON /RECIPB/ NUMXX, NUMU1, NUMU2, NUMH
      COMMON /RECSIM/ RSSA
!
      INCLUDE 'DPCOP2.INC'
!
      DATA ZERO /0.D0/
      DATA ONE/1.D0/
!
      IF(IBUGA2.EQ.'ON')THEN
        WRITE(ICOUT,12)NPAR,NTOT,NBCH,NPTS
   12   FORMAT('NPAR,NTOT,NBCH,NPTS = ',4I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IBUGA3='OFF'
!   -- OLS COEFFICIENTS
      IERROR='NO'
      CALL DSET (NTOT*NPAR, WK1, ZERO)
!
!   -- FOR DATAPLOT, READ U1 ARRAY BACK IN
      IOP='READ'
      IFILE='DPRE2F.DAT'
      CALL DPSWA2(IOP,IFILE,SCRTCH,NUMU1,IBUGA3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')RETURN
!
      DO 60 I=1, IRANK1
         CALL DGER (NPAR, NTOT, ONE/S1(I), V1((I-1)*NPAR+1), 1,   &
                    SCRTCH((I-1)*NTOT+1), 1, WK1, NPAR, IERROR)
         IF(IERROR.EQ.'YES')RETURN
 60   CONTINUE
      CALL DGEMV ('N', NPAR, NTOT, ONE, WK1, NPAR,   &
                   Y, 1, ZERO, COEF, 1, IERROR)
      IF(IERROR.EQ.'YES')RETURN
!
!    -- CALCULATE RESIDUAL SUMS OF SQUARES FOR BOTH MODELS
      SY = DDOT (NTOT, Y, 1, Y, 1)
!CCCC CALL DGEMV ('T', NTOT, IRANK1, ONE, U1, NTOT, Y, 1, ZERO, WK1, 1,
      CALL DGEMV ('T', NTOT, IRANK1, ONE, SCRTCH, NTOT, Y, 1, ZERO,   &
       WK1, 1, IERROR)
      IF(IERROR.EQ.'YES')RETURN
      RSSA = SY -DDOT (IRANK1, WK1, 1, WK1, 1)
!   -- FOR DATAPLOT, READ U2 ARRAY BACK IN
      IOP='READ'
      IFILE='DPRE3F.DAT'
      CALL DPSWA2(IOP,IFILE,SCRTCH,NUMU2,IBUGA3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')RETURN
!
!CCCC CALL DGEMV ('T', NTOT, IRANK2, ONE, U2, NTOT, Y, 1, ZERO, WK1, 1,
      CALL DGEMV ('T', NTOT, IRANK2, ONE, SCRTCH, NTOT, Y, 1, ZERO,   &
        WK1, 1, IERROR)
      IF(IERROR.EQ.'YES')RETURN
      RSSB = SY - DDOT (IRANK2, WK1, 1, WK1, 1)
!
!    -- VARIANCE COMPONENT ESTIMATES
      RMSA = RSSA /(NTOT -IRANK1)
      RMSB = RSSB /(NTOT -IRANK2)
      TMSA = RMSA
      IF (RMSA .LT. RMSB) TMSA = RMSB
      IF (CONFND) THEN
          S2B = ZERO
      ELSE
          S2B  = GNU0 /TR1 *(RMSA -RMSB)
      END IF
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'GDAT')THEN
        WRITE(ICOUT,2001)TR1
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2002)TR2
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2003)S2B
        CALL DPWRST('XXX','BUG ')
      END IF
 2001 FORMAT('TR1 = ',E15.7)
 2002 FORMAT('TR2 = ',E15.7)
 2003 FORMAT('S2B = ',E15.7)
      IF (S2B .LT. ZERO) S2B = ZERO
      S2W  = RMSB
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'GDAT')THEN
        WRITE(ICOUT,2004)S2W,NPTS
        CALL DPWRST('XXX','BUG ')
      END IF
 2004 FORMAT('S2W, NPTS = ',E15.7,I8)
      S    = SQRT(S2B +S2W)
!
!     -- TOLERANCE LIMIT FACTORS AND TOLERANCE LIMITS
      DO 10 I=1, NPTS
         SMEAN = SQRT(S2B/ETA1(I) +S2W/ETA0(I))
         TFCT  = (SQRT(ETA0(I)*ETA1(I)) *(TLM1(I) -TLM0(I))*SMEAN +   &
                 (TLM0(I)*SQRT(ETA0(I)) -TLM1(I)*SQRT(ETA1(I)))*S)/   &
                 (SQRT(TMSA) *(SQRT(ETA0(I)) -SQRT(ETA1(I))))
         XM(I) = DDOT (NPAR, XPTS(I), NPTS, COEF, 1)
         IF(IBUGA2.EQ.'ON')THEN
           WRITE(ICOUT,119)I,XM(I)
           CALL DPWRST('XXX','BUG ')
         ENDIF
         T (I) = XM(I) -TFCT*SQRT(RMSA)
 10   CONTINUE
!
!     -- FOR FIT CASE, CALCULATE PREDICTED VALUES AT
!     -- DESIGN POINTS
      IF(IBUGA2.EQ.'ON')THEN
        WRITE(ICOUT,118)ICASRE,NLVL,NPAR
 118    FORMAT('ICASRE,NLVL,NPAR=',A4,1X,2I8)
        CALL DPWRST('XXX','BUG ')
        DO 116 I=1,NPAR*NLVL
          WRITE(ICOUT,117)I,X(I)
 117      FORMAT('I,X(I)=',I8,E15.7)
          CALL DPWRST('XXX','BUG ')
 116    CONTINUE
        DO 115 I=1,NPAR*NPTS
          WRITE(ICOUT,114)I,XPTS(I)
 114      FORMAT('I,XPTS(I)=',I8,E15.7)
          CALL DPWRST('XXX','BUG ')
 115    CONTINUE
      ENDIF
      IF(ICASRE.EQ.'FREC')THEN
        DO 19 I=1, NLVL
          XM(I) = DDOT (NPAR, X(I), NLVL, COEF, 1)
          IF(IBUGA2.EQ.'ON')THEN
            WRITE(ICOUT,119)I,XM(I)
 119        FORMAT('I,XM(I)=',I8,E15.7)
            CALL DPWRST('XXX','BUG ')
          ENDIF
 19     CONTINUE
      ENDIF
!   -- FOR DATAPLOT, READ XX ARRAY BACK IN
!   -- FOR RECIPE, READ THIS MATRIX BACK IN, FOR SIMCOV DO NOT
!   -- (SIMCOV MAKES MULTIPLE CALLS TO REGDAT, WANT TO LEAVE
!   -- WK1 MATRIX AS THE SVDC MATRIX)
      IF(IFLAG.EQ.'RECI')THEN
        IOP='READ'
        IFILE='DPRE1F.DAT'
        NUMXX=NTOT*NPAR
        CALL DPSWA2(IOP,IFILE,WK1,NUMXX,IBUGA3,ISUBRO,IERROR)
        IF(IERROR.EQ.'YES')RETURN
      ENDIF
!
      RETURN
      END SUBROUTINE REGDAT 
      SUBROUTINE REGINI (   &
                   NLVL, NPAR, NTOT, NBCH, NPTS, X, XPTS, IP,   &
                   IQ, CONT, CONF, XX, XTX, XTXI, XN, SCRTCH,   &
                   S1, V1, S2, V2, TLM0, TLM1, ETA0, ETA1,   &
                   SATT, IN2, WK2, WK3,   &
                   CRT,ISEED, MAXREP,MAXLVL,   &
                   ICASRE,ISUBRO,IBUGA2, IERROR)
!
!        SUBROUTINE REGINI PERFORMS ALL OF THE CALCULATIONS FOR REGRESSION
!     TOLERANCE LIMITS WHICH DO NOT INVOLVE THE RESPONSE (Y) DATA.
!
!
      IMPLICIT DOUBLE PRECISION (A-H, O-Z)
      INCLUDE 'DPCOPA.INC'
      REAL AJUNK
      REAL XTMP(1)
!
      LOGICAL CONFND, SATT
!CCCC CHARACTER*10 DUMCHR
      DIMENSION X(*),    XPTS(*), IP(*),  IQ(*),   XX(*), XTX(*),   &
                XTXI(*), XN(*),   SCRTCH(*),   S1(*),   V1(*),   &
                S2(*),   V2(*),  TLM0(*), TLM1(*),   &
                ETA0(*), ETA1(*), WK2(*),  WK3(*), CRT(*)
!
      COMMON /RECIPA/ IRANK1, IRANK2, TR1, TR2, GNU0, GNU1, CONFND
      COMMON /RECIPB/ NUMXX, NUMU1, NUMU2, NUMH
!
      CHARACTER*4 IOP
      CHARACTER*4 IMATCH
!CCCC CHARACTER*80 IFILE
      CHARACTER (LEN=MAXFNC) :: IFILE
!
      CHARACTER*4 ICASRE
!
      CHARACTER*4 IERROR
      CHARACTER*4 IBUGA2
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
!
      INCLUDE 'DPCOP2.INC'
!
      DATA ONE /1.D0/
      DATA ZERO/0.D0/
      DATA EPS /1.D-7/
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,12)IN2
   12   FORMAT('IN2 = ',I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IBUGA3='OFF'
      IERROR='NO'
!      -- BUILD FULL DATA MATRIX FROM UNIQUE ROWS
!      -- NOTE: DATAPLOT PASSES IN FULL DESIGN MATRIX (MINUS
!               THE BATCH VARIABLE).  NEED TO RECONSTRUCT THE
!               X ARRAY.
!      -- NOTE: FOR EXAMPLE, THE 2-D ARRAY
!                   1 -3 -2
!                   1 -3 0
!                   1  1 -2
!                   1  1 0
!               IS STORED AS
!                   1 1 1 1 -3 -3 1 1 -2 0 -2 0
!               IN THE 1-D ARRAY
!
!      --       A DATAPLOT COMPLICATION IS THAT WE START WITH
!               THE FULL DESIGN MATRIX, BUT WE DON'T KNOW WHAT
!               NLVL IS IN ADVANCE (THAT IS BEING CACLUCATED
!               HERE).  THEREFORE, IN CREATING THE REDUCED DESIGN
!               MATRIX, X, WE NEED TO MAKE AN INITIAL PASS TO
!               DETERMINE THE VALUE OF "NLVL".  DO THIS BY LOOPING
!               THROUGH AND COMPARING EACH ROW OF XX WITH ALL PREVIOUS
!               ROWS OF XX.  INCREMENT NLVL IF NO MATCH FOUND.
!
!CCCC DO 10 I=1, NTOT
!CCCC    DO 20 J=1, NPAR
!CCCC       XX((J-1)*NTOT+I) = X((J-1)*NLVL+IP(I))
!20      CONTINUE
!10   CONTINUE
!
      NLVL=1
      DEPS=1.0D-10
      DO 110 I=2,NTOT
        IMATCH='NO'
        DO 120 J=1,I-1
          DO 125 KK=1,NPAR
            DTERM1=XX((KK-1)*NTOT+I)
            DTERM2=XX((KK-1)*NTOT+J)
!CCCC       IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'GINI')THEN
!CCCC         WRITE(ICOUT,126)I,J,KK,DTERM1,DTERM2
!C126         FORMAT('I,J,KK=',3I8,2D15.7)
!CCCC         CALL DPWRST('XXX','BUG ')
!CCCC       ENDIF
            IF(DABS(DTERM1-DTERM2).GT.DEPS)THEN
              GO TO 120
            ENDIF
  125    CONTINUE
         IMATCH='YES'
         GO TO 110
  120  CONTINUE
       IF(IMATCH.EQ.'NO')NLVL=NLVL+1
  110 CONTINUE
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'GINI')THEN
        WRITE(ICOUT,132)NLVL
        CALL DPWRST('XXX','BUG ')
      ENDIF
  132 FORMAT('NLVL=',I8)
!
      DO 5 J=1,NPAR
        X((J-1)*NLVL+1)=XX((J-1)*NTOT+1)
    5 CONTINUE
      ITEST=1
      IP(1)=ITEST
!
      DO 10 I=2,NTOT
        IMATCH='NO'
        DO 20 J=1,ITEST
          DO 25 K=1,NPAR
            DTERM1=XX((K-1)*NTOT+I)
            DTERM2=X((K-1)*NLVL+J)
!CCCC       IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'GINI')THEN
!CCCC         WRITE(ICOUT,136)I,J,K,DTERM1,DTERM2
!C136         FORMAT('I,J,KK=',3I8,2D15.7)
!CCCC         CALL DPWRST('XXX','BUG ')
!CCCC       ENDIF
            IF(DABS(DTERM1-DTERM2).GT.DEPS)THEN
              GO TO 20
            ENDIF
   25     CONTINUE
          IP(I)=J
          GO TO 10
   20   CONTINUE
        ITEST=ITEST+1
        DO 35 KK=1,NPAR
          X((KK-1)*NLVL+ITEST)=XX((KK-1)*NTOT+I)
   35   CONTINUE
        IP(I)=ITEST
   10 CONTINUE
!
      IF(ITEST.NE.NLVL)THEN
        WRITE(ICOUT,142)NLVL,ITEST
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        RETURN
      ENDIF
  142 FORMAT('***** INTERNAL ERROR FROM REGINI--NUMBER OF LEVELS ',   &
      'PASS 1 = ',I8,' NUMBER OF LEVELS PASS 2 = ',I8)
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'GINI')THEN
        DO 1001 I=1,NLVL*NPAR
        WRITE(ICOUT,1002)I,X(I)
        CALL DPWRST('XXX','BUG ')
 1001   CONTINUE
        DO 1006 I=1,NTOT
        WRITE(ICOUT,1007)I,IP(I)
        CALL DPWRST('XXX','BUG ')
 1006   CONTINUE
      ENDIF
 1002 FORMAT('I,X(I)=',I8,D15.7)
 1007 FORMAT('I,IP(I)=',2I8)
!
      IF(NLVL.GT.MAXLVL)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,101)NLVL
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)MAXLVL
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        RETURN
      ENDIF
  101 FORMAT('**** ERROR FROM REGINI:  THE NUMBER OF LEVELS IN THE ',   &
      'DESIGN MATRIX ',I8)
  102 FORMAT('     EXCEEDS THE MAXIMUM ALLOWABLE ',I8)
!
!   --FOR RECIPE FIT CASE, XPTS IS CREATED FROM USER SUPPLIED DATA.
!   --FOR RECIPE ANOVA CASE, XPTS IS EQUAL TO X MATRIX (THAT IS,
!   --WE WILL COMPUTE A TOLERANCE VALUE AT ALL UNIQUE DESIGN
!   --POINTS.
!   --FOR ANOVA CASE, XPTS SHOULD BE ALL ZERO'S.  FOR FIT CASE
!   --FIRST NTOT ROWS SHOULD BE 1 (CORRESPONDING TO THE CONSTANT).
!
      IF(ICASRE.EQ.'AREC'.OR.(ICASRE.EQ.'FREC'.AND.NPTS.EQ.0))THEN
        NPTS=NLVL
        DO 42 I=1,NPAR*NLVL
          XPTS(I)=X(I)
 42     CONTINUE
      ENDIF
!
!   -- NEED COPY OF XX, BECAUSE DSVDC DESTROYS INPUT MATRIX
!   -- FOR DATAPLOT, COPY XX FILE TO A SWAP FILE, USE XX IN SUBSEQUENT
!      CALCULATIONS.
      IOP='WRIT'
      IFILE='DPRE1F.DAT'
      NUMXX=NTOT*NPAR
      CALL DPSWA2(IOP,IFILE,XX,NUMXX,IBUGA3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')RETURN
!
!CCCC CALL DCOPY (NTOT*NPAR, XX, 1, WK1, 1)
!
!   --  XX^T *XX
      CALL DGEMM ('T', 'N', NPAR, NPAR, NTOT, ONE, XX, NTOT,   &
                   XX, NTOT, ZERO, XTX, NPAR,IERROR)
      IF(IERROR.EQ.'YES')RETURN
!
!    --  SVD OF DESIGN MATRIX XX (COPY IN WK1)
      IJOB = 21
      LDU  = NTOT
      LDV  = NPAR
      TOL  = 1.D-7
!CCCC CALL DSVDC (WK1 , NTOT, NTOT, NPAR, S1, WK2, U1, LDU, V1, LDV,
      CALL DSVDC (XX , NTOT, NTOT, NPAR, S1, WK2, SCRTCH, LDU, V1, LDV,   &
                  WK3, IJOB, INFO)
!   -- FOR DATAPLOT, COPY U1 (=SCRTCH) FILE TO A SWAP FILE
      IOP='WRIT'
      IFILE='DPRE2F.DAT'
      NUMU1=NTOT*NPAR
      CALL DPSWA2(IOP,IFILE,SCRTCH,NUMU1,IBUGA3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')RETURN
!
!    -- RANK (XX)
      IRANK1 = 0
      DO 30 I=1, NPAR
         IF (ABS(S1(I)) .LT. TOL) GO TO 40
         IRANK1 = IRANK1 +1
 30   CONTINUE
 40   CONTINUE
!
!     -- DO "SIMRAT" CODE HERE
      IF(.NOT.SATT)THEN
        IOP='WRIT'
        IFILE='DPRE3F.DAT'
        NUMXX=NTOT*NPAR
        CALL DPSWA2(IOP,IFILE,XX,NUMXX,IBUGA3,ISUBRO,IERROR)
        IF(IERROR.EQ.'YES')RETURN
!
        IOP='WRIT'
        IFILE='DPRE4F.DAT'
        NUMXPT=NPTS*NPAR
        CALL DPSWA2(IOP,IFILE,XPTS,NUMXPT,IBUGA3,ISUBRO,IERROR)
        IF(IERROR.EQ.'YES')RETURN
!
        CALL NODPPF(CONT,ZCONT)
        NREP=MAXREP
        NRAN=1
        DO 900 I=1, NPTS
!CCCC    Z = RNOR(ISEED)
         CALL NORRAN(NRAN,ISEED,XTMP)
         Z=DBLE(XTMP(1))
!CCCC    CALL DCOPY(NPAR,  XPTS(I), NPTS, W, 1)
         CALL SIMRAT   &
           (SCRTCH,S1,V1,IQ,XPTS,NBCH,NTOT,NPAR,NREP,IRK,ZCONT,CONF,   &
            WK2,WK3,XX,QUANT, IERROR)
           IF(IERROR.EQ.'YES')RETURN
           CRT(I)=QUANT
 900  CONTINUE
!
        IOP='READ'
        IFILE='DPRE2F.DAT'
        CALL DPSWA2(IOP,IFILE,SCRTCH,NUMU1,IBUGA3,ISUBRO,IERROR)
        IF(IERROR.EQ.'YES')RETURN
!
        IOP='READ'
        IFILE='DPRE3F.DAT'
        NUMXX=NTOT*NPAR
        CALL DPSWA2(IOP,IFILE,XX,NUMXX,IBUGA3,ISUBRO,IERROR)
        IF(IERROR.EQ.'YES')RETURN
!
        IOP='READ'
        IFILE='DPRE4F.DAT'
        NUMXPT=NPTS*NPAR
        CALL DPSWA2(IOP,IFILE,XPTS,NUMXPT,IBUGA3,ISUBRO,IERROR)
        IF(IERROR.EQ.'YES')RETURN
      ENDIF
!
!     -- INVERSE (XX^T XX)
      CALL DSET (NPAR*NPAR, XTXI, ZERO)
      DO 50 I=1, IRANK1
         CALL DGER (NPAR, NPAR, ONE/S1(I)**2, V1((I-1)*NPAR+1), 1,   &
                    V1((I-1)*NPAR+1), 1, XTXI, NPAR,IERROR)
         IF(IERROR.EQ.'YES')RETURN
 50   CONTINUE
!
!     -- H = X *INVERSE(XX^T XX) *X^T
      CALL DGEMM ('N', 'N', NLVL, NPAR, NPAR, ONE, X, NLVL,   &
                    XTXI, NPAR, ZERO, XX, NLVL,IERROR)
      IF(IERROR.EQ.'YES')RETURN
!CCCC CALL DGEMM ('N', 'T', NLVL, NLVL, NPAR, ONE, WK1, NLVL,
!CCCC$             X, NLVL, ZERO, H, NLVL,IERROR)
      CALL DGEMM ('N', 'T', NLVL, NLVL, NPAR, ONE, XX, NLVL,   &
                   X, NLVL, ZERO, SCRTCH, NLVL,IERROR)
!   -- FOR DATAPLOT, COPY H (=SCRTCH) FILE TO A SWAP FILE
      IOP='WRIT'
      IFILE='DPRE4F.DAT'
      NUMH=NLVL*NLVL
      CALL DPSWA2(IOP,IFILE,SCRTCH,NUMH,IBUGA3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')RETURN
!
      IF(IERROR.EQ.'YES')RETURN
!
!    -- AUGMENT THE XX MATRIX WITH BATCH INDICATORS
!    -- FOR DATAPLOT, READ ORIGINAL XX MATRIX BACK IN
      IOP='READ'
      IFILE='DPRE1F.DAT'
      NUMXX=NTOT*NPAR
      CALL DPSWA2(IOP,IFILE,XX,NUMXX,IBUGA3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')RETURN
!
      CALL DSET (NTOT*NBCH, XX(NTOT*NPAR+1), ZERO)
      DO 70 I=1, NTOT
        XX((IQ(I)+NPAR-1)*NTOT +I) = ONE
 70   CONTINUE
!
!     -- DO AN SVD ON THE AUGMENTED MATRIX
      IJOB = 21
      LDU  = NTOT
      NCOL = NPAR+NBCH
      LDV  = NCOL
      TOL  = 1.D-7
!CCCC CALL DCOPY (NTOT*NCOL, XX, 1, WK1, 1)
!CCCC CALL DSVDC (WK1, NTOT, NTOT, NCOL, S2, WK2, U2,
!CCCC$            LDU, V2, LDV,  WK3, IJOB, INFO)
      CALL DSVDC (XX, NTOT, NTOT, NCOL, S2, WK2, SCRTCH,   &
                  LDU, V2, LDV,  WK3, IJOB, INFO)
!   -- FOR DATAPLOT, COPY U2 (=SCRTCH) FILE TO A SWAP FILE
      IOP='WRIT'
      IFILE='DPRE3F.DAT'
!CCCC NUMU2=NTOT*(NPAR+NUMBCH)
      NUMU2=NTOT*(NPAR+NBCH)
      CALL DPSWA2(IOP,IFILE,SCRTCH,NUMU2,IBUGA3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')RETURN
!
!    -- GET RANK OF AUGMENTED DESIGN MATRIX
      IRANK2 = 0
      DO 80 I=1, NPAR+NBCH
         IF (ABS(S2(I)) .LT. TOL) GO TO 90
         IRANK2 = IRANK2 +1
 80   CONTINUE
 90   CONTINUE
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'GINI')THEN
        WRITE(ICOUT,91)IRANK2
        CALL DPWRST('XXX','BUG ')
      ENDIF
   91 FORMAT('FROM REGINI--IRANK2=',I8)
!
!     -- CALCULATE N, M, B =M-N^T*H*N, TR(B), AND TR(B^2)
      CALL DSET (NBCH*NLVL, XN, ZERO)
      DO 100 I=1, NTOT
        IDX = (IQ(I)-1)*NLVL +IP(I)
        XN(IDX) = XN(IDX) +1
 100  CONTINUE
!CCCC CALL DGEMM  ('T', 'N', NBCH, NLVL, NLVL, ONE, XN, NLVL,
!CCCC$             H, NLVL, ZERO, WK1, NBCH,IERROR)
!   -- FOR DATAPLOT, READ H (=SCRTCH) FROM SWAP FILE
      IOP='READ'
      IFILE='DPRE4F.DAT'
      NUMH=NLVL*NLVL
      CALL DPSWA2(IOP,IFILE,SCRTCH,NUMH,IBUGA3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')RETURN
!
      CALL DGEMM  ('T', 'N', NBCH, NLVL, NLVL, ONE, XN, NLVL,   &
                   SCRTCH, NLVL, ZERO, XX, NBCH,IERROR)
      IF(IERROR.EQ.'YES')RETURN
!CCCC CALL DGEMM  ('N', 'N', NBCH , NBCH, NLVL, ONE, WK1, NBCH,
      CALL DGEMM  ('N', 'N', NBCH , NBCH, NLVL, ONE, XX, NBCH,   &
                   XN, NLVL, ZERO, WK2, NBCH,IERROR)
      IF(IERROR.EQ.'YES')RETURN
!CCCC CALL DSET   (NLVL, WK1, ONE)
      CALL DSET   (NLVL, XX, ONE)
!CCCC CALL DGEMV  ('T', NLVL, NBCH, ONE, XN, NLVL, WK1, 1,ZERO,WK3,1,
      CALL DGEMV  ('T', NLVL, NBCH, ONE, XN, NLVL, XX, 1,ZERO,WK3,1,   &
                   IERROR)
      IF(IERROR.EQ.'YES')RETURN
      CALL DSCAL  (NBCH*NBCH, -ONE, WK2, 1)
      CALL DAXPY  (NBCH, ONE, WK3, 1, WK2, NBCH+1)
      TR1 = DSUM  (NBCH, WK2, NBCH+1)
      TR2 = DDOT  (NBCH*NBCH, WK2, 1, WK2, 1)
!
!    -- CHECK TO SEE IF BETWEEN-BATCH VARIANCE IS CONFOUNDED WITH FIXED PART
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'GINI')THEN
        WRITE(ICOUT,191)TR1,TR2,EPS
        CALL DPWRST('XXX','BUG ')
      ENDIF
  191 FORMAT('FROM REGINI--TR1,TR2,EPS=',3D15.7)
      IF (TR2 .LE. EPS) THEN
         IF(ICASRE.NE.'UREC')THEN
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,2001)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,2002)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,2003)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,2004)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         ENDIF
         CONFND = .TRUE.
      ELSE
         CONFND = .FALSE.
      END IF
  999 FORMAT(' ')
 2001 FORMAT(' REGINI : WARNING: BETWEEN-BATCH VARIANCE CANNOT')
 2002 FORMAT('          BE ESTIMATED FROM THESE DATA. RESULTS')
 2003 FORMAT('          WILL BE BASED ON THE ASSUMPTION THAT THE')
 2004 FORMAT('          BETWEEN-BATCH VARIABILITY IS NEGLIGIBLE.')
!
!    -- VARIANCE OF MEAN WHEN S2W = 0
      CALL DGEMM ('T', 'N', NBCH, NPAR, NLVL, ONE, XN, NLVL, X,   &
                   NLVL, ZERO, XX, NBCH, IERROR)
      IF(IERROR.EQ.'YES')RETURN
!CCCC CALL DGEMM ('T', 'N', NPAR, NPAR, NBCH, ONE, WK1, NBCH, WK1,
      CALL DGEMM ('T', 'N', NPAR, NPAR, NBCH, ONE, XX, NBCH, XX,   &
                   NBCH, ZERO, WK2, NPAR, IERROR)
      IF(IERROR.EQ.'YES')RETURN
      CALL DGEMM ('N', 'N', NPAR, NPAR, NPAR, ONE, XTXI, NPAR, WK2,   &
                   NPAR, ZERO, XX, NPAR, IERROR)
      IF(IERROR.EQ.'YES')RETURN
!CCCC CALL DGEMM ('N', 'N', NPAR, NPAR, NPAR, ONE, WK1, NPAR, XTXI,
      CALL DGEMM ('N', 'N', NPAR, NPAR, NPAR, ONE, XX, NPAR, XTXI,   &
                   NPAR, ZERO, WK2, NPAR, IERROR)
      IF(IERROR.EQ.'YES')RETURN
!
!     -- TOLERANCE LIMIT FACTORS
!     8/97.  REPLACE WITH DATAPLOT NODPPF ROUTINE.
!CCCC ZCONT = PPND16 (CONT, IFAULT)
      CALL NODPPF (CONT, ZCONT)
      IF (.NOT. CONFND) GNU1 = TR1**2 /TR2
      GNU0 = NTOT -IRANK1
      NDF  = IRANK2 -IRANK1
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'GINI')THEN
        WRITE(ICOUT,2011)CONT,ZCONT,GNU0, NDF
        CALL DPWRST('XXX','BUG ')
      ENDIF
 2011 FORMAT('CONT,ZCONT, GNU0, NDF = ',3D15.7,I8)
!
!     -- IF SIMULATED CRITICAL VALUES ARE TO BE USED, SKIP
!        THE HEADER LINE IN THE CRITICAL VALUE FILE
!CCCC NOTE: FOR DATAPLOT, NOT ACTUALLY READING FILE, SO SKIP
!CCCC       THIS STEP.
!CCCC IF (.NOT. SATT) THEN
!CCCC    READ (IN2,'(A)') DUMCHR
!CCCC END IF
      DO 130 I=1, NPTS
         CALL DGEMV ('N', NPAR, NPAR, ONE, XTXI, NPAR, XPTS(I), NPTS,   &
                     ZERO, XX, 1, IERROR)
         IF(IERROR.EQ.'YES')RETURN
!CCCC    ETA0(I) = ONE /DDOT (NPAR, WK1, 1, XPTS(I), NPTS)
         ETA0(I) = ONE /DDOT (NPAR, XX, 1, XPTS(I), NPTS)
         CALL DGEMV ('N', NPAR, NPAR, ONE, WK2, NPAR, XPTS(I),   &
                     NPTS, ZERO, XX, 1, IERROR)
         IF(IERROR.EQ.'YES')RETURN
!CCCC    ETA1(I) = ONE /DDOT (NPAR, WK1, 1, XPTS(I), NPTS)
         ETA1(I) = ONE /DDOT (NPAR, XX, 1, XPTS(I), NPTS)
         XNCP0 = ZCONT *SQRT(ETA0(I))
         XNCP1 = ZCONT *SQRT(ETA1(I))
         IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'GINI')THEN
           WRITE(ICOUT,2021)I,XNCP0,XNCP1
           CALL DPWRST('XXX','BUG ')
         ENDIF
 2021 FORMAT('I,XNCP0, XNCP1 = ',I8,D15.7,D15.7)
!
                                                                                                                                  
!CCCC 8/97.  REPLACE FOLLOWING NON-CENTRAL T PPF WITH DATAPLOT
!CCCC        VERSION NCTPPF.
!CCCC    CALL INVNCT (CONF, GNU0, XNCP0,  TLM0(I))
         CALL NCTPPF (SNGL(CONF), SNGL(GNU0), SNGL(XNCP0),  AJUNK)
         TLM0(I)=DBLE(AJUNK)
         IF (CONFND) THEN
             TLM1(I) = TLM0(I)
         ELSE
!CCCC 8/97.  REPLACE FOLLOWING NON-CENTRAL T PPF WITH DATAPLOT
!CCCC        VERSION DNTPPF.
!CCCC       CALL INVNCT (CONF, GNU1, XNCP1,  TLM1(I))
            CALL NCTPPF (SNGL(CONF), SNGL(GNU1), SNGL(XNCP1), AJUNK)
            TLM1(I)=DBLE(AJUNK)
            IF (.NOT. SATT) THEN
!CCCC         READ (IN2,*) CRT
              TLM1(I) = CRT(I) *SQRT(TR1 *ETA1(I)/GNU0)
            END IF
         END IF
         TLM0(I) = TLM0(I)/SQRT(ETA0(I))
         TLM1(I) = TLM1(I)/SQRT(ETA1(I))
         IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'GINI')THEN
           WRITE(ICOUT,2031)I,TLM0(I),TLM1(I),ETA0(I),ETA1(I)
           CALL DPWRST('XXX','BUG ')
         ENDIF
 2031 FORMAT('I,TLM0(I),TLM1(I),ETA0(I),ETA1(I) = ',I8,4D15.7)
 130  CONTINUE
      RETURN
      END SUBROUTINE REGINI 
      SUBROUTINE RELRSK(X,N1,Y,N2,PSTAMV,IWRITE,XIDTEM,STAT,   &
                        IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE RELATIVE RISK
!              (= P1/P2 WHERE P1 = PROBABILITY OF SUCCESS FOR
!              VARIABLE 1 AND P2 = PROBABILITY OF SUCCESS FOR
!              VARIABLE 2)
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED) OBSERVATIONS
!                                WHICH CONSTITUTE THE FIRST SET
!                                OF DATA.
!                     --N1     = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!                     --Y      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED) OBSERVATIONS
!                                WHICH CONSTITUTE THE SECOND SET
!                                OF DATA.
!                     --N2     = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR Y.
!                     --PSTAMV = THE MISSING VALUE CODE.
!     OUTPUT ARGUMENTS--STAT   = THE SINGLE PRECISION VALUE OF THE
!                                RELATIVE RISK BETWEEN THE 2 SETS
!                                OF DATA IN THE INPUT VECTORS
!                                X AND Y.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             RELATIVE RISK BETWEEN THE 2 SETS
!             OF DATA IN THE INPUT VECTORS X AND Y.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--ODDDIS.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTIUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/4
!     ORIGINAL VERSION--APRIL     2007.
!     UPDATED         --AUGUST    2007. IF 2X2 CASE, CHECK IF SUM
!                                       OF ENTRIES IS <= 4.  IN THIS
!                                       CASE, ASSUME WE HAVE RAW DATA
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISTEPN
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(*)
      DIMENSION XIDTEM(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='RELR'
      ISUBN2='SK  '
      IERROR='NO'
!
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF RELRSK--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3
   52   FORMAT('IBUGA3 = ',A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)N1,N2
   53   FORMAT('N1,N2 = ',2I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,MAX(N1,N2)
          WRITE(ICOUT,56)I,X(I),Y(I)
   56     FORMAT('I,X(I),Y(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 21--                             **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='21'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(N1.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1201)
 1201   FORMAT('***** ERROR IN THE RELATIVE RISK')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1203)
 1203   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE FIRST ',   &
               'RESPONSE VARIABLES IS LESS THAN TWO')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1205)N1
 1205   FORMAT('SAMPLE SIZE = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(N2.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1201)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1213)
 1213   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE SECOND ',   &
               'RESPONSE VARIABLES IS LESS THAN TWO')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1205)N2
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!     NOTE: CHECK FOR SPECIAL CASE N = 2.  IN THIS CASE,
!           ASSUME WE HAVE A 2X2 TABLE OF COUNTS INSTEAD
!           OF RAW DATA.
!
      IF(N1.EQ.2 .AND. N2.EQ.2)THEN
        N11=INT(X(1)+0.5)
        N21=INT(X(2)+0.5)
        N12=INT(Y(1)+0.5)
        N22=INT(Y(2)+0.5)
!
!       CHECK IF ALL ENTRIES 0 OR 1. IF SO, ASSUME
!       RAW DATA CASE.
!
        IF((N11.EQ.0 .OR. N11.EQ.1) .AND.   &
           (N12.EQ.0 .OR. N12.EQ.1) .AND.   &
           (N21.EQ.0 .OR. N21.EQ.1) .AND.   &
           (N22.EQ.0 .OR. N22.EQ.1)) GO TO 1349
!
        IF(N11.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1311)
 1311     FORMAT('      ROW 1 COLUMN 1 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(N21.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1321)
 1321     FORMAT('      ROW 2 COLUMN 1 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(N12.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1331)
 1331     FORMAT('      ROW 1 COLUMN 2 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(N22.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1341)
 1341     FORMAT('      ROW 2 COLUMN 2 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        AN11=REAL(N11)
        AN21=REAL(N21)
        AN12=REAL(N12)
        AN22=REAL(N22)
        GO TO 3000
      ENDIF
!
 1349 CONTINUE
!
      CALL ODDDIS(X,N1,PSTAMV,IWRITE,XIDTEM,N11,N21,NOUT,   &
                  IBUGA3,IERROR)
      IF(IERROR.EQ.'YES' .OR. IERROR.EQ.'ON')GO TO 9000
      CALL ODDDIS(Y,N2,PSTAMV,IWRITE,XIDTEM,N12,N22,NOUT,   &
                  IBUGA3,IERROR)
      IF(IERROR.EQ.'YES' .OR. IERROR.EQ.'ON')GO TO 9000
      AN11=REAL(N11)
      AN21=REAL(N21)
      AN12=REAL(N12)
      AN22=REAL(N22)
      GO TO 3000
!
!     COMPUTE THE BIAS CORRECTED LOG OF THE ODDS RATIO.
!
 3000 CONTINUE
      AN1=AN11+AN21
      AN2=AN12+AN22
      AN=AN1 + AN2
!
      P11=AN11/AN1
      P21=AN21/AN1
      P12=AN12/AN2
      P22=AN22/AN2
!
      IF(P12.GT.0.0)THEN
        STAT=(P11/AN)/(P12/AN)
      ELSE
        STAT=0.0
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1201)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2411)
 2411   FORMAT('      PROBABILITY OF SUCCESS FOR VARIABLE TWO')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2413)
 2413   FORMAT('      IS ZERO.  UNABLE TO COMPUTE RELATIVE RISK.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'OFF')GO TO 890
      IF(IWRITE.EQ.'OFF' .OR. IWRITE.EQ.'NO')GO TO 890
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,811)STAT
  811 FORMAT('THE RELATIVE RISK = ',G15.7)
      CALL DPWRST('XXX','BUG ')
  890 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END OF RELRSK--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA3,IERROR
 9012   FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)N,N11,N12,N21,N22
 9013   FORMAT('N,N11,N12,N21,N22 = ',5I10)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)P11,P12,P21,P22
 9014   FORMAT('P11,P12,P21,P22 = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)STAT
 9015   FORMAT('STAT = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE RELRSK
      SUBROUTINE RELSD(X,N,IWRITE,XRELSD,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE
!              SAMPLE RELATIVE STANDARD DEVIATION
!              OF THE DATA IN THE INPUT VECTOR X.
!              THE SAMPLE RELATIVE STANDARD DEVIATION = 100 * (THE SAMPLE
!              STANDARD DEVIATION)/(THE SAMPLE MEAN).
!              THE DENOMINATOR N-1 IS USED IN COMPUTING THE
!              SAMPLE STANDARD DEVIATION.
!              THE SAMPLE RELATIVE STANDARD DEVIATION IS ALTERNATIVELY
!              REFERRED TO AS THE SAMPLE COEFFICIENT OF VARIATION.
!              THE SAMPLE STANDARD DEVIATION = SQRT((THE SUM OF THE
!              SQUARED DEVIATIONS ABOUT THE SAMPLE MEAN)/(N-1)).
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XRELSD = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE RELATIVE STANDARD DEVIATION.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE RELATIVE STANDARD DEVIATION.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DSQRT.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--KENDALL AND STUART, THE ADVANCED THEORY OF
!                 STATISTICS, VOLUME 1, EDITION 2, 1963, PAGES 47, 233.
!               --SNEDECOR AND COCHRAN, STATISTICAL METHODS,
!                 EDITION 6, 1967, PAGES 62-65.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--JUNE      1972.
!     UPDATED         --SEPTEMBER 1975.
!     UPDATED         --NOVEMBER  1975.
!     UPDATED         --AUGUST    1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --FEBRUARY  1994. USE ABS OF MEAN
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DX
      DOUBLE PRECISION DSUM
      DOUBLE PRECISION DMEAN
      DOUBLE PRECISION DVAR
      DOUBLE PRECISION DSD
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='RELS'
      ISUBN2='D   '
      IERROR='NO'
!
      DMEAN=0.0D0
      DSD=0.0D0
!
      IF(IBUGA3.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF RELSD--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGA3
   52 FORMAT('IBUGA3 = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)N
   53 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 55 I=1,N
      WRITE(ICOUT,56)I,X(I)
   56 FORMAT('I,X(I) = ',I8,E15.7)
      CALL DPWRST('XXX','BUG ')
   55 CONTINUE
   90 CONTINUE
!
!               *******************************************
!               **  COMPUTE RELATIVE STANDARD DEVIATION  **
!               *******************************************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.GE.1)GO TO 119
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,111)
  111 FORMAT('***** ERROR IN RELSD--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,112)
  112 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,113)
  113 FORMAT('      IN THE VARIABLE FOR WHICH')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,114)
  114 FORMAT('      THE RELATIVE STANDARD DEVIATION IS TO BE ',   &
      'COMPUTED')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,115)
  115 FORMAT('      MUST BE 1 OR LARGER.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,116)
  116 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,117)N
  117 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS HERE = ',I8,   &
      '.')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
  119 CONTINUE
!
      IF(N.EQ.1)GO TO 120
      GO TO 129
  120 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,121)
  121 FORMAT('***** NON-FATAL DIAGNOSTIC IN RELSD--',   &
      'THE SECOND INPUT ARGUMENT (N) HAS THE VALUE 1')
      CALL DPWRST('XXX','BUG ')
      XRELSD=0.0
      GO TO 9000
  129 CONTINUE
!
      HOLD=X(1)
      DO 135 I=2,N
      IF(X(I).NE.HOLD)GO TO 139
  135 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,136)HOLD
  136 FORMAT('***** NON-FATAL DIAGNOSTIC IN RELSD--',   &
      'THE FIRST INPUT ARGUMENT (A VECTOR) HAS ALL ELEMENTS = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      XRELSD=0.0
      GO TO 9000
  139 CONTINUE
!
!               ************************************************
!               **  STEP 2--                                  **
!               **  COMPUTE THE RELATIVE STANDARD DEVIATION.  **
!               ************************************************
!
      DN=N
      DSUM=0.0D0
      DO 200 I=1,N
      DX=X(I)
      DSUM=DSUM+DX
  200 CONTINUE
      DMEAN=DSUM/DN
      XMEAN=DMEAN
!
      DSUM=0.0D0
      DO 300 I=1,N
      DX=X(I)
      DSUM=DSUM+(DX-DMEAN)**2
  300 CONTINUE
      DVAR=DSUM/(DN-1.0D0)
      DSD=0.0D0
      IF(DVAR.GT.0.0D0)DSD=DSQRT(DVAR)
!CCCC MODIFY FOLLOWING LINE.  FEBRUARY 1994.
!CCCC XRELSD=100.0D0*DSD/DMEAN
      XRELSD=100.0D0*DSD/ABS(DMEAN)
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'OFF')GO TO 890
      IF(IWRITE.EQ.'OFF')GO TO 890
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,811)N,XRELSD
  811 FORMAT('THE RELATIVE STANDARD DEVIATION OF THE ',I8,   &
      ' OBSERVATIONS = ',E15.7,' PERCENT')
      CALL DPWRST('XXX','BUG ')
  890 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF RELSD--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGA3,IERROR
 9012 FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)N
 9013 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9014)DMEAN,DSD
 9014 FORMAT('DMEAN,DSD = ',2D15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)XRELSD
 9015 FORMAT('XRELSD = ',E15.7)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE RELSD
      SUBROUTINE REMOVE(YORG,NORG,YSUB,NSUB,YOUT,NOUT,TEMP1,ITEMP1,    &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--GIVEN A SET OF OBSERVATIONS, YORG, LOOP THROUGHT
!              THE UNIQUE VALUES IN YSUB AND REMOVE ANY OBSERVATIONS
!              IN YORG THAT MATCH THAT VALUE.
!
!              IF ALL OBSERVATIONS IN YORG ARE REMOVED, THEN RETURN
!              A SINGLE VALUE SET TO CPUMIN.
!     INPUT  ARGUMENTS--YORG   = A SINGLE PRECISION VECTOR OF OBSERVATIONS
!                     --NORG   = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN YORG
!                     --YSUB   = A SINGLE PRECISION VECTOR OF OBSERVATIONS
!                                THAT WILL IDENTIFY OBSERVATIONS TO BE
!                                REMOVED FROM YORG
!                     --NSUB   = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN YSUB
!     OUTPUT ARGUMENTS--YOUT   = THE OUTPUT ARRAY THAT WILL CONTAIN
!                                THE OBSERVATIONS AFTER REMOVING THE
!                                SPECIFIED VALUES
!                     --NOUT   = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN YOUT
!     OUTPUT--THE COMPUTED SINGLE PRECISION ARRAY YOUT.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DISTIN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2025.12
!     ORIGINAL VERSION--DECEMBER  2025.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!
      INTEGER ITEMP1(*)
      INTEGER NORG
      INTEGER NSUB
      INTEGER NOUT
      REAL YORG(*)
      REAL YSUB(*)
      REAL YOUT(*)
      REAL TEMP1(*)
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
!
      INTEGER NDIST
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MOVE')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF REMOVE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,NORG,NSUB
   52   FORMAT('IBUGA3,ISUBRO,NORG,NSUB = ',2(A4,2X),2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NORG.GT.0)THEN
          DO I=1,N
            WRITE(ICOUT,56)I,YORG(I)
   56       FORMAT('I,YORG(I) = ',I8,2X,G15.7)
            CALL DPWRST('XXX','BUG ')
          ENDDO
        ENDIF
        IF(NSUB.GT.0)THEN
          DO I=1,NSUB
            WRITE(ICOUT,58)I,YSUB(I)
   58       FORMAT('I,YSUB(I) = ',I8,2X,G15.7)
            CALL DPWRST('XXX','BUG ')
          ENDDO
        ENDIF
      ENDIF
!
      IF(NORG.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1011)
 1011   FORMAT('***** ERROR IN REMOVE OPERATION--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1013)NORG
 1013   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE ORIGINAL ',  &
               'RESPONSE VARIABLE IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IWRITE='OFF'
      IF(NSUB.LT.1)THEN
        YOUT(1:NORG)=YORG(1:NORG)
        NOUT=NORG
      ELSE
        CALL DISTIN(YSUB,NSUB,IWRITE,TEMP1,NDIST,IBUGA3,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
        ITEMP1(1:NORG)=1
        DO I=1,NDIST
           AHOLD=TEMP1(I)
           DO J=1,NORG
              IF(YORG(J).EQ.AHOLD)ITEMP1(J)=0
           ENDDO
        ENDDO
        NOUT=0
        DO I=1,NORG
           IF(ITEMP1(I).EQ.1)THEN
             NOUT=NOUT+1
             YOUT(NOUT)=YORG(I)
           ENDIF
        ENDDO
        IF(NOUT.EQ.0)THEN
          NOUT=1
          YOUT(1)=CPUMIN
        ENDIF
      ENDIF
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MOVE')THEN
        WRITE(ICOUT,9051)
 9051   FORMAT('***** AT THE END OF REMOVE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9053)NOUT
 9053   FORMAT('NOUT = ',I8)
        CALL DPWRST('XXX','BUG ')
        IF(NOUT.GT.0)THEN
          DO I=1,NOUT
            WRITE(ICOUT,9056)I,YOUT(I)
 9056       FORMAT('I,YOUT(I) = ',I8,2X,G15.7)
            CALL DPWRST('XXX','BUG ')
          ENDDO
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE REMOVE
      SUBROUTINE REPEAZ(Y,X,XIDTEM,TEMP,N,IWRITE,XREP,   &
      ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE SAMPLE REPEATABILITY
!              STANDARD DEVIATION OF THE DATA IN THE INPUT VECTOR Y
!              WITH LAB ID VECTOR X.  THE REPEATABILITY STANDARD
!              DEVIATION IS DEFINED AS:
!
!                 Sr = SQRT(SUM[i=1 to p][s(i)**2/p]
!
!              WITH
!                 p      = NUMBER OF LABS
!                 s(i)   = STANDARD DEVIATION OF GROUP i.
!
!
!              FOR UNBALANCED DATA< THE FORMULA BECOMES:
!
!                 Sr = SQRT(SUM[i=1 to p][(n(i)-1)*s(i)**2/(N-p)]
!
!              WITH
!                 n(i)   = SAMPLE SIZE OF GROUP i
!
!     INPUT  ARGUMENTS--Y      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --X      = THE SINGLE PRECISION VECTOR OF
!                                GROUP ID's.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR Y.
!     OUTPUT ARGUMENTS--XREP   = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE REPEATABILITY SD.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE REPEATABILITY SD.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--SORT, DISTIN, SD.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--SQRT.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--"Standard Practice for Conducting an
!                 Interlaboratory Study to Determine the Precision
!                 of a Test Method", ASTM International,
!                 100 Barr Harbor Drive, PO BOX C700,
!                 West Conshohoceken, PA 19428-2959, USA.
!                 This document is in support of
!                 ASTM Standard E 691 - 99.
!                 SUPPORT FOR UNBALANCED DATA ADDED IN "E691 - 23".
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2005.2
!     ORIGINAL VERSION--FEBRUARY  2005.
!     UPDATED         --NOVEMBER  2009. MODIFY NAME TO AVOID CONFLICT
!                                       WITH INTRINSIC REPEAT FUNCTION
!                                       ON SOME FORTRAN 90 COMPILERS
!     UPDATED         --MARCH     2024. UPDATED TO ALLOW UNBALANCED DATA
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DSUM
!
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION XIDTEM(*)
      DIMENSION TEMP(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='REPE'
      ISUBN2='AT  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'PEAT')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF REPEAT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N
   52   FORMAT('IBUGA3,ISUBRO,N = ',A4,1X,A4,1X,I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,Y(I),X(I)
   56     FORMAT('I,Y(I),X(I) = ',I8,2E15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               **********************
!               **  COMPUTE REPEAT  **
!               ********************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.LE.1)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN COMPUTING REPEATABILITY SD--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS IN THE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,114)
  114   FORMAT('      VARIABLES FOR WHICH THE REPEATABILITY SD IS ')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,115)
  115   FORMAT('      TO BE COMPUTED MUST BE 2 OR LARGER.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,116)
  116   FORMAT('      SUCH WAS NOT THE CASE HERE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ****************************************************
!               **  STEP 2--                                      **
!               **  COMPUTE THE REPEATABILTY STANDARD DEVIATION.  **
!               ****************************************************
!
      IWRITE='OFF'
      CALL DISTIN(X,N,IWRITE,XIDTEM,NUMSET,IBUGA3,IERROR)
      CALL SORT(XIDTEM,NUMSET,XIDTEM)
!
      IF(NUMSET.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,192)
  192   FORMAT('      NUMBER OF LABS    NUMSET < 1')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      AN=N
      ANUMSE=NUMSET
!
      DSUM=0.0D0
      J=0
      DO 1110 ISET1=1,NUMSET
        K=0
        DO 1130 I=1,N
          IF(XIDTEM(ISET1).EQ.X(I))THEN
            K=K+1
            TEMP(K)=Y(I)
          ENDIF
 1130   CONTINUE
        NTEMP=K
        CALL SD(TEMP,NTEMP,IWRITE,XSD,IBUGA3,IERROR)
        DSUM=DSUM + DBLE(NTEMP-1)*DBLE(XSD)**2
!
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'PEAT')THEN
          WRITE(ICOUT,1131)ISET1,NTEMP,XSD,DSUM
 1131     FORMAT('***** GROUP ',I8,': N, SD, DSUM = ',I8,2X,2G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
 1110 CONTINUE
!
      XREP=REAL(DSQRT(DSUM/DBLE(N-NUMSET)))
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)XREP
  811   FORMAT('THE REPEATABILITY STANDARD DEVIATION = ',E15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'PEAT')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF REPEAT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR,NUMSET,XREP
 9012   FORMAT('IERROR,NUMSET,XREP = ',A4,2X,I6,G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE REPEAZ
      SUBROUTINE REPLAC(X,Z,NX,VAL,NVAL,IWRITE,Y,ICASE,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS COMMAND IS A VARIANT OF THE MATCH COMMAND.
!              THE SYNTAX
!                  LET Y2 = REPLACE GROUPID GROUP2 Y1
!              DOES THE FOLLOWING:
!              1) IT MATCHES THE VALUES IN GROUP2 AGAINST
!                 GROUPID AND RETURNS THE INDICES OF THE
!                 MATCHING ROWS FOR THE GROUPID ARRAY.
!              2) THE INDEX IS USED TO ACCESS THE CORRESPONDING
!                 VALUE IN THE Y1 ARRAY.
!              3) THE CORRESPONDING ROW OF Y2 IS REPLACED WITH
!                 THE Y1 VALUE.
!              NOTE THAT Y2, GROUPID, AND Y1 SHOULD HAVE THE
!              SAME LENGTH.  ALSO, IT IS ASSUMED THAT Y1
!              ALREADY EXISTS.  THIS SHOULD BE CHECKED FOR BEFORE
!              CALLING THIS ROUTINE.
!
!              THE SHORTHAND SYNTAX
!                  LET Y2 = REPLACE GROUPID GROUP
!              SIMPLY ASSIGNS A VALUE OF 1 IN THE CORRESPONDING
!              ROW OF Y2 (THIS IS A CONVENIENT SYNTAX FOR
!              CREATING A TAG VARIABLE).  THIS CASE IS IDENTIFIED
!              WITH THE "ICASE=INDE" OPTION.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/2
!     ORIGINAL VERSION--FEBRUARY  2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES----------------
!
      CHARACTER*4 ICASE
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!
!------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(*)
      DIMENSION Z(*)
      DIMENSION VAL(*)
!
!-----COMMOMN---------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT--------------------------------------------------
!
      ISUBN1='MATC'
      ISUBN2='H   '
      IERROR='NO'
!
      IF(ISUBRO.EQ.'PLAC' .OR. IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF REPLAC--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,IWRITE,NX,NVAL
   52   FORMAT('IBUGA3,IWRITE,NX,NVAL = ',2(A4,2X),2I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,NX
          WRITE(ICOUT,56)I,X(I),Z(I),Y(I)
   56     FORMAT('I,X(I),Z(I),Y(I) = ',I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
        DO 65 I=1,NVAL
          WRITE(ICOUT,66)I,VAL(I)
   66     FORMAT('I,VAL(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   65   CONTINUE
      ENDIF
!
!               ****************************************
!               **  COMPUTE INDICES OF MATCHING VALUES *
!               ****************************************
!
      DO 100 I=1,NVAL
        VALTMP=VAL(I)
        INDTMP=1
        YDIFF=CPUMAX
        DO 200 J=1,NX
          APROD=X(J)*VALTMP
          TERM1=MAX(X(J),VALTMP)
          TERM2=MIN(X(J),VALTMP)
          IF(APROD.GT.0.0)THEN
            ADIFF=ABS(ABS(TERM1) - ABS(TERM2))
          ELSEIF(APROD.LT.0.0)THEN
            ADIFF=TERM1+ABS(TERM2)
          ELSE
            ADIFF=ABS(TERM1-TERM2)
          ENDIF
          IF(ADIFF.LT.YDIFF)THEN
            INDTMP=J
            YDIFF=ADIFF
          ENDIF
  200   CONTINUE
        IF(ICASE.EQ.'INDE')THEN
          Y(INDTMP)=1.0
        ELSE
          Y(INDTMP)=Z(INDTMP)
        ENDIF
  100 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
      IF(ISUBRO.EQ.'PLAC' .OR. IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF REPLAC--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA3,IERROR,NX
 9012   FORMAT('IBUGA3,IERROR,NX = ',2(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        DO 9015 I=1,NX
          WRITE(ICOUT,9016)I,X(I),Z(I),Y(I)
 9016     FORMAT('I,X(I),Z(I),Y(I) = ',I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
 9015   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE REPLAC
      SUBROUTINE REPROD(Y,X,XIDTEM,TEMP,TEMP2,TEMP3,NCELL,N,   &
                        IWRITE,XREP,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE SAMPLE REPRODUCABILITY
!              STANDARD DEVIATION OF THE DATA IN THE INPUT VECTOR Y
!              WITH LAB ID VECTOR X.  THE REPRODUCABILITY STANDARD
!              DEVIATION IS DEFINED AS:
!
!                 SR = MAX(SR*,Sr)
!
!              WITH
!
!                 SR* = SQRT(s(x)**2 + (Sr**2*(n-1)/n)
!
!                 s(xbar)    = STANDARD DEVIATION OF THE CELL
!                              AVERAGES
!                 n          = CELL SAMPLE SIZE (CURRENTLY, EQUAL
!                              CELL SIZES EXPECTED)
!
!              AND Sr DENOTING THE REPEATABILITY STANDARD DEVIATION
!
!                 Sr = SQRT(SUM[i=1 to p][s(i)**2/p]
!
!              WITH
!                 p      = NUMBER OF LABS
!                 s(i)   = STANDARD DEVIATION OF GROUP i.
!
!
!              2024/04: THE 2023 VERSION OF THE E691 STANDARD UPDATED
!                       THE FORMULAS TO SUPPORT THE UNBALANCED CASE.
!                       SEE THE STANDARD FOR DETAILS.
!     INPUT  ARGUMENTS--Y      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --X      = THE SINGLE PRECISION VECTOR OF
!                                GROUP ID's.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR Y.
!     OUTPUT ARGUMENTS--XREP   = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE REPRODUCABILITY SD.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE REPRODUCABILITY SD.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--SORT, DISTIN, SD.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--SQRT.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--"Standard Practice for Conducting an
!                 Interlaboratory Study to Determine the Precision
!                 of a Test Method", ASTM International,
!                 100 Barr Harbor Drive, PO BOX C700,
!                 West Conshohoceken, PA 19428-2959, USA.
!                 This document is in support of
!                 ASTM Standard E 691 - 99.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2005.2
!     ORIGINAL VERSION--FEBRUARY  2005.
!     UPDATED         --APRIL     2024. SUPPORT FOR UNBALANCED DATA
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DSUM
      DOUBLE PRECISION DXREP
      DOUBLE PRECISION XREPRD
!
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION XIDTEM(*)
      DIMENSION TEMP(*)
      DIMENSION TEMP2(*)
      DIMENSION TEMP3(*)
      DIMENSION NCELL(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='REPR'
      ISUBN2='OD  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'PROD')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF REPROD--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N
   52   FORMAT('IBUGA3,ISUBRO,N = ',2(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,Y(I),X(I)
   56     FORMAT('I,Y(I),X(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               **********************
!               **  COMPUTE REPROD  **
!               **********************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.LE.1)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN COMPUTING REPRODUCABILITY SD--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS IN THE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,114)
  114   FORMAT('      VARIABLES FOR WHICH THE REPRODUCABILITY SD IS ')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,115)
  115   FORMAT('      TO BE COMPUTED MUST BE 2 OR LARGER.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,116)
  116   FORMAT('      SUCH WAS NOT THE CASE HERE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ****************************************************
!               **  STEP 2--                                      **
!               **  COMPUTE THE REPRODABILTY STANDARD DEVIATION.  **
!               ****************************************************
!
      IWRITE='OFF'
      CALL DISTIN(X,N,IWRITE,XIDTEM,NUMSET,IBUGA3,IERROR)
      CALL SORT(XIDTEM,NUMSET,XIDTEM)
!
      IF(NUMSET.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,192)
  192   FORMAT('      NUMBER OF LABS    NUMSET < 1')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      AN=N
      ANUMSE=NUMSET
!
!     2024/03: CHECK FOR UNBALANCED CASE AND PROCESS DIFFERENTLY IF
!              DETECTED
!
      DSUM=0.0D0
      J=0
      NIHOLD=-1
      DO 1110 ISET1=1,NUMSET
        K=0
        DO 1130 I=1,N
          IF(XIDTEM(ISET1).EQ.X(I))THEN
            K=K+1
            TEMP(K)=Y(I)
          ENDIF
 1130   CONTINUE
        NTEMP=K
!
        IF(ISET1.EQ.1)THEN
          NHOLD=NTEMP
        ELSE
          IF(NTEMP.NE.NHOLD)GO TO 2000
!CCCC     IF(NTEMP.NE.NHOLD)THEN
!CCCC       WRITE(ICOUT,999)
!CCCC       CALL DPWRST('XXX','BUG ')
!CCCC       WRITE(ICOUT,111)
!CCCC       CALL DPWRST('XXX','BUG ')
!CCCC       WRITE(ICOUT,1131)ISET1,NHOLD,NTEMP
!1131       FORMAT('      FOR GROUP ',I8,', ',I8,
!CCCC1             'ELEMENTS EXPECTED BUT ',I8,' ELEMENTS FOUND.')
!CCCC       CALL DPWRST('XXX','BUG ')
!CCCC       IERROR='YES'
!CCCC       GO TO 9000
!CCCC     ENDIF
        ENDIF
!
        CALL MEAN(TEMP,NTEMP,IWRITE,XMEAN,IBUGA3,IERROR)
        CALL SD(TEMP,NTEMP,IWRITE,XSD,IBUGA3,IERROR)
        DSUM=DSUM + DBLE(XSD)**2
        TEMP2(ISET1)=XMEAN
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'PROD')THEN
          WRITE(ICOUT,1151)NUMSET,XSD
 1151     FORMAT('***** GROUP ',I8,': MEAN, SD = ',2G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
 1110 CONTINUE
!
      DXREP=DSUM/DBLE(NUMSET)
      CALL SD(TEMP2,NUMSET,IWRITE,SXBAR,IBUGA3,IERROR)
      XREPRD=DSQRT(DBLE(SXBAR**2) + DXREP*DBLE(NHOLD-1)/DBLE(NHOLD))
      XREP=REAL(MAX(DSQRT(DXREP),XREPRD))
      GO TO 8000
!
!     2024/03: UNBALANCED CASE
!
 2000 CONTINUE
!
!     DETERMINE CELL SIZES
!
      SUM=0.0
      DO 2110 ISET1=1,NUMSET
        K=0
        DO 2130 I=1,N
          IF(XIDTEM(ISET1).EQ.X(I))THEN
            K=K+1
            TEMP(K)=Y(I)
          ENDIF
 2130   CONTINUE
        NCELL(ISET1)=K
        CALL MEAN(TEMP,K,IWRITE,XMEAN,IBUGA3,IERROR)
        CALL SD(TEMP,K,IWRITE,XSD,IBUGA3,IERROR)
        TEMP2(ISET1)=XMEAN
        TEMP3(ISET1)=XSD
        SUM=SUM + REAL(K)*XMEAN
 2110 CONTINUE
      GMEAN=SUM/REAL(N)
!
      SUM=0.0
      SUM2=0.0
      SUM3=0.0
      NTOTAL=N
      DO 2150 ISET1=1,NUMSET
        IINDX=ISET1
        AVAL=REAL(NCELL(IINDX))
        DXBARI=TEMP2(IINDX) - GMEAN
        SDI=TEMP3(IINDX)
        SUM=SUM + (AVAL**2/REAL(NTOTAL))
        SUM2=SUM2 + AVAL*DXBARI**2
        SUM3=SUM3 + (AVAL-1.0)*SDI**2
!
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'PROD')THEN
          WRITE(ICOUT,2153)ISET1,IINDX,AVAL,DXBARI,TEMP3(IINDX)
 2153     FORMAT('ISET1,IINDX,AVAL,DXBARI,TEMP3(IINDX) = ',2I6,3G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
 2150 CONTINUE
      ANSTAR=(REAL(N) - SUM)/REAL(NUMSET-1)
      DENOM=ANSTAR*REAL(NUMSET-1)
      SDXBRI=SQRT(SUM2/DENOM)
      SRPT=SQRT(SUM3/REAL(N-NUMSET))
      AVAL=SDXBRI**2 - (SRPT**2/ANSTAR)
      SL=0.0
      IF(AVAL.GT.0.0)SL=SQRT(AVAL)
      XREP=SQRT(SL**2 + SRPT**2)
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'PROD')THEN
        WRITE(ICOUT,2158)SUM,SUM2,SUM3,DENOM,ANSTAR,SDXBRI
 2158   FORMAT('SUM,SUM2,SUM3,DENOM,ANSTAR,SDXBRI = ',6G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2159)SRPT,SL,XREP
 2159   FORMAT('SRPT,SL,XREP = ',6G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      GO TO 8000
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
 8000 CONTINUE
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)XREP
  811   FORMAT('THE REPRODUCABILITY STANDARD DEVIATION = ',E15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'PROD')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF REPROD--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA3,ISUBRO,IERROR
 9012   FORMAT('IBUGA3,ISUBRO,IERROR = ',A4,2X,A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)N,NUMSET
 9013   FORMAT('N,NUMSET = ',I8,1X,I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)XREP,DXREP,XREPRD
 9015   FORMAT('XREP,DXREP,XREPRD = ',3G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE REPROD
      SUBROUTINE RESULT(NR,N,X,F,G,A,P,ITNCNT,IFLG)
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
! PURPOSE
! -------
! PRINT INFORMATION  (FOR OPTIMIZE COMMAND)
!
! PARAMETERS
! ----------
! NR           --> ROW DIMENSION OF MATRIX
! N            --> DIMENSION OF PROBLEM
! X(N)         --> ITERATE X[K]
! F            --> FUNCTION VALUE AT X[K]
! G(N)         --> GRADIENT AT X[K]
! A(N,N)       --> HESSIAN AT X[K]
! P(N)         --> STEP TAKEN
! ITNCNT       --> ITERATION NUMBER K
! IFLG         --> FLAG CONTROLLING INFO TO PRINT
! IPR          --> DEVICE TO WHICH TO SEND OUTPUT
!
      DIMENSION X(N),G(N),P(N),A(NR,1)
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
! PRINT ITERATION NUMBER
      WRITE(ICOUT,903) ITNCNT
      CALL DPWRST('XXX','BUG ')
      IF(IFLG.EQ.0) GO TO 120
!
! PRINT STEP
      WRITE(ICOUT,907)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,905) (P(I),I=1,MIN(5,N))
      CALL DPWRST('XXX','BUG ')
!
! PRINT CURRENT ITERATE
  120 CONTINUE
      WRITE(ICOUT,904)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,905) (X(I),I=1,MIN(5,N))
      CALL DPWRST('XXX','BUG ')
!
! PRINT FUNCTION VALUE
      WRITE(ICOUT,906)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,905) F
      CALL DPWRST('XXX','BUG ')
!
! PRINT GRADIENT
      WRITE(ICOUT,908)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,905) (G(I),I=1,MIN(5,N))
      CALL DPWRST('XXX','BUG ')
!
! PRINT HESSIAN FROM ITERATION K
      IF(IFLG.EQ.0) GO TO 140
      WRITE(ICOUT,901)
      CALL DPWRST('XXX','BUG ')
      DO 130 I=1,N
        WRITE(ICOUT,900) I
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,902) (A(I,J),J=1,I)
        CALL DPWRST('XXX','BUG ')
  130 CONTINUE
        WRITE(ICOUT,902) (A(I,J),J=1,I)
        CALL DPWRST('XXX','BUG ')
!
  900 FORMAT('****** FROM RESULT     ROW',I5)
  901 FORMAT('****** FROM RESULT       HESSIAN AT X(K)')
  902 FORMAT('****** FROM RESULT       ',5(2X,E20.13))
  903 FORMAT('****** FROM RESULT    ITERATE K=',I5)
  904 FORMAT('****** FROM RESULT       X(K)')
  905 FORMAT('****** FROM RESULT       ',5(2X,E20.13))
  906 FORMAT('****** FROM RESULT       FUNCTION AT X(K)')
  907 FORMAT('****** FROM RESULT       STEP')
  908 FORMAT('****** FROM RESULT       GRADIENT AT X(K)')
  140 RETURN
      END SUBROUTINE RESULT
      SUBROUTINE REVERS(X,NX,IWRITE,Y,YTEMP,IBUGA3,IERROR)
!
!     PURPOSE--REVERSE THE ORDER OF AN ARRAY.  THAT IS,
!              Y(1)=X(N), ..., Y(N)=X(1).
!     NOTE--IT IS PERMISSIBLE TO HAVE THE OUTPUT VECTOR Y(.)
!           BEING IDENTICAL TO THE INPUT VECTOR X(.).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--98/5
!     ORIGINAL VERSION--MAY       1998.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(*)
      DIMENSION YTEMP(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='REVE'
      ISUBN2='RS  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF REVERS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,IWRITE,NX
   52   FORMAT('IBUGA3,IWRITE,NX = ',2(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,NX
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               **************************************
!               **  FLIP ORDER OF ARRAY             **
!               **************************************
!
      DO 100 I=1,NX
        IREV=NX-I+1
        YTEMP(I)=X(IREV)
  100 CONTINUE
      DO 200 I=1,NX
        Y(I)=YTEMP(I)
  200 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF REVERS--')
        CALL DPWRST('XXX','BUG ')
        DO 9015 I=1,NX
          WRITE(ICOUT,9016)I,X(I),Y(I)
 9016     FORMAT('I,X(I),Y(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
 9015   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE REVERS
      SUBROUTINE REVRT(X, M)
!
!     ALGORITHM AS 97.1  APPL. STATIST. (1976) VOL.25, NO. 2
!
!     Inverse discrete Fourier transform in one dimension of real
!     data using complex transform subroutine FASTG.
!
!     X = array of Fourier components as output from subroutine FORRT,
!         type real, dimension M.
!     M = length of the inverse transform, must be a power of 2.
!     The minimum length is 8, maximum 2**21.
!
!     Auxiliary routines required: SCRAG & FASTG from AS 83, but
!     with SCRAG modified as described on page 168 of the paper for
!     this algorithm.
!
      IMPLICIT DOUBLE PRECISION (A-H, O-Z)
      DOUBLE PRECISION X(M)
      DATA ZERO/0.0D0/, HALF/0.5D0/, ONE/1.0D0/, ONE5/1.5D0/,   &
            TWO/2.0D0/, FOUR/4.0D0/
!
!     Check for valid transform size.
!
      II = 8
      DO 2 K = 3, 21
      IPOW = K
      IF (II .EQ. M) GO TO 3
      II = II * 2
    2 CONTINUE
!
!     If this point is reached, an illegal size was specified.
!
      RETURN
    3 PIE = FOUR * ATAN(ONE)
      N = M / 2
      NN = N / 2
!
!     Undo the spectrum into that of two interleaved series.
!     First, the special cases.
!
      Z = X(1) + X(N+1)
      X(N+1) = X(1) - X(N+1)
      X(1) = Z
      NN1 = NN + 1
      NN2 = NN1 + N
      X(NN1) = TWO * X(NN1)
      X(NN2) = -TWO * X(NN2)
      Z = PIE / N
      BCOS = -TWO * (SIN(Z / TWO) **2)
      BSIN = SIN(Z)
      UN = ONE
      VN = ZERO
      DO 4 K = 2, NN
      Z = UN * BCOS + VN * BSIN + UN
      VN = VN * BCOS - UN * BSIN + VN
      SAVE1 = ONE5 - HALF * (Z * Z + VN * VN)
      UN = Z * SAVE1
      VN = VN * SAVE1
      KI = N + K
      L = N + 2 - K
      LI = N + L
      AN = X(K) + X(L)
      BN = X(KI) - X(LI)
      PN = X(K) - X(L)
      QN = X(KI) + X(LI)
      CN = UN * PN + VN * QN
      DN = UN * QN - VN * PN
      X(K) = AN - DN
      X(KI) = BN + CN
      X(L) = AN + DN
      X(LI) = CN - BN
    4 CONTINUE
!
!     Now do the inverse transform
!
      CALL FASTG(X, X(N+1), N, -1)
!
!     Now undo the order - the half arrays are already bit reversed;
!     bit reverse the whole array.
!
      CALL SCRAG(X, M, IPOW)
      RETURN
      END SUBROUTINE REVRT
      SUBROUTINE RIGCDF(DX,DGAMMA,DMU,DCDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE RECIPROCAL INVERSE GAUSSIAN
!              DISTRIBUTION WITH SHAPE PARAMETERS GAMMA AND MU.
!              THE RECIPROCAL INVERSE GAUSSIAN DISTRIBUTION IS
!              THE DISTRIBUTION OF Y = 1/X WHEN X HAS AN INVERSE
!              GAUSSIAN DISTRIBUTION.
!              THE FORMULA FOR THE CDF OF THE RECIROCAL INVERSE
!              GAUSIAN DISTRIBUTION IS:
!              F(X,GAMMA,MU) = NORCDF{-[1/(MU*X) - 1]*SQRT(GAMMA*X)} -
!              EXP[2*GAMMA/MU]*NORCDF{-[1/(MU*X) - 1]*SQRT(GAMMA*X)} -
!              X, GAMMA, MU > 0
!     NOTE--THE RECIPROCAL INVERSE GAUSSIA DISTRIBUTION CAN BE
!           COMPUTED IN TERMS OF THE INVERSE GAUSSIAN CDF:
!              RIGCDF(X,GAMMA,MU) = 1 - IGCDF(1/X,GAMMA,MU)
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE POSITIVE.
!                     --GAMMA  = THE SHAPE PARAMETER
!                                GAMMA SHOULD BE POSITIVE.
!                     --AMU    = THE SHAPE PARAMETER
!                                MU SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE RECIPROCAL INVERSE
!             GAUSSIAN DISTRIBUTION
!             WITH SHAPE PARAMETERS GAMMA AND MU
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE POSITIVE.
!                 --GAMMA SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--IGCDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--SAM SAUNDERS TALK, MAY 1990
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--90.6
!     ORIGINAL VERSION--MAY       1990.
!     UPDATED         --DECEMBER  2003. SUPPORT FOR GENERAL MU
!     UPDATED         --APRIL     2014. CONVERT TO DOUBLE PRECISION
!     UPDATED         --APRIL     2014. SUPPORT FOR CHAN PARAMETERIZATION
!                                       (THIS ACTUALLY DONE IN IGCDF)
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DGAMMA
      DOUBLE PRECISION DMU
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DX2
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      DCDF=0.0D0
      IF(DGAMMA.LE.0.0D0)THEN
         WRITE(ICOUT,51)
   51    FORMAT('***** ERROR--THE FIRST SHAPE PARAMETER TO RIGCDF ',   &
                'IS NON-POSITIVE.')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,52)DGAMMA
   52    FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
         CALL DPWRST('XXX','BUG ')
         GO TO 9000
      ELSEIF(DMU.LE.0.0D0)THEN
         WRITE(ICOUT,71)
   71    FORMAT('***** ERROR--THE SECOND SHAPE PARAMETER TO RIGCDF ',   &
                'IS NON-POSITIVE.')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,52)DMU
         CALL DPWRST('XXX','BUG ')
         GO TO 9000
      ENDIF
!
      IF(DX.LE.0.0D0)GO TO 9000
!
      DX2=1.0D0/DX
      CALL IGCDF(DX2,DGAMMA,DMU,DCDF)
      DCDF=1.0D0 - DCDF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE RIGCDF
      SUBROUTINE RIGCHA(DX,DGAMMA,DMU,DHAZ)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE HAZARD
!              FUNCTION VALUE FOR THE RECIPROCAL INVERSE GAUSSIAN
!              DISTRIBUTION WITH SHAPE PARAMETERS GAMMA AND MU.
!              THE RECIPROCAL INVERSE GAUSSIAN DISTRIBUTION IS
!              THE DISTRIBUTION OF Y = 1/X WHEN X HAS AN INVERSE
!              GAUSSIAN DISTRIBUTION.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE POSITIVE.
!                     --GAMMA  = THE SHAPE PARAMETER
!                                GAMMA SHOULD BE POSITIVE.
!                     --AMU    = THE SHAPE PARAMETER
!                                MU SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--HAZ    = THE SINGLE PRECISION CUMULATIVE HAZARD
!                                FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE HAZARD
!             FUNCTION VALUE PDF FOR THE RECIPROCAL INVERSE GAUSSIAN
!             DISTRIBUTION WITH SHAPE PARAMETERS GAMMA AND MU
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE POSITIVE.
!                 --GAMMA AND MU SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--RIGDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--SAM SAUNDERS TALK, MAY 1990
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--98.6
!     ORIGINAL VERSION--APRIL     1998.
!     UPDATED         --DECEMBER  2003. SUPPORT FOR GENERAL MU
!     UPDATED         --APRIL     2014. CONVERT TO DOUBLE PRECISION
!     UPDATED         --APRIL     2014. SUPPORT FOR CHAN PARAMETERIZATION
!                                       (ACTUALLY DONE IN IGCDF ROUTINE)
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DGAMMA
      DOUBLE PRECISION DMU
      DOUBLE PRECISION DHAZ
      DOUBLE PRECISION DCDF
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      DHAZ=0.0D0
      IF(DGAMMA.LE.0.0D0)THEN
         WRITE(ICOUT,51)
   51    FORMAT('***** ERROR--THE FIRST SHAPE PARAMETER TO RIGCHA ',   &
                'IS NON-POSITIVE.')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,52)DGAMMA
   52    FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
         CALL DPWRST('XXX','BUG ')
         GO TO 9000
      ELSEIF(DMU.LE.0.0D0)THEN
         WRITE(ICOUT,71)
   71    FORMAT('***** ERROR--THE SECOND SHAPE PARAMETER TO RIGCHA ',   &
                'IS NON-POSITIVE.')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,52)DMU
         CALL DPWRST('XXX','BUG ')
         GO TO 9000
      ELSEIF(DX.LT.0.0D0)THEN
         WRITE(ICOUT,61)
   61    FORMAT('***** ERROR--THE FIRST  INPUT ARGUMENT TO RIGCHA ',   &
                'IS NON-POSITIVE.')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,52)X
         CALL DPWRST('XXX','BUG ')
         GO TO 9000
      ENDIF
!
      IF(DX.EQ.0.0D0)GO TO 9000
      CALL RIGCDF(DX,DGAMMA,DMU,DCDF)
      DCDF=1.0D0-DCDF
      IF(DCDF.GT.0.0D0)THEN
        DHAZ=-DLOG(DCDF)
      ELSE
        WRITE(ICOUT,162)X
  162   FORMAT('***** FOR THE VALUE OF THE ARGUMENT ',G15.7,   &
           ' THE CDF IS ESSENTIALLY 1, CUMULATIVE HAZARD SET TO 0.')
        CALL DPWRST('XXX','BUG ')
        DHAZ=0.0D0
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE RIGCHA
      SUBROUTINE RIGHAZ(DX,DGAMMA,DMU,DHAZ)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE HAZARD
!              FUNCTION VALUE FOR THE RECIPROCAL INVERSE GAUSSIAN
!              DISTRIBUTION WITH SHAPE PARAMETERS GAMMA AND MU.
!              THE RECIPROCAL INVERSE GAUSSIAN DISTRIBUTION IS
!              THE DISTRIBUTION OF Y = 1/X WHEN X HAS AN INVERSE
!              GAUSSIAN DISTRIBUTION.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE POSITIVE.
!                     --GAMMA  = THE SHAPE PARAMETER
!                                GAMMA SHOULD BE POSITIVE.
!                     --AMU    = THE SHAPE PARAMETER
!                                MU SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--HAZ    = THE SINGLE PRECISION HAZARD
!                                FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION HAZARD
!             FUNCTION VALUE HAZARD FOR THE RECIPROCAL INVERSE
!             GAUSSIAN DISTRIBUTION
!             WITH SHAPE PARAMETERS GAMMA AND MU
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE POSITIVE.
!                 --GAMMA AND MU SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--RIGCDF, RIGPDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--SAM SAUNDERS TALK, MAY 1990
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--98.6
!     ORIGINAL VERSION--APRIL     1998.
!     UPDATED         --DECEMBER  2003. USE GENERAL VALUE OF MU
!                                       INSTEAD OF ASSUMING MU=1
!     UPDATED         --APRIL     2014. CONVERT TO DOUBLE PRECISION
!     UPDATED         --APRIL     2014. SUPPORT FOR CHAN PARAMETERIZATION
!                                       (ACTUALLY DONE IN IGCDF AND
!                                       IGPDF ROUTINES)
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DGAMMA
      DOUBLE PRECISION DMU
      DOUBLE PRECISION DHAZ
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DPDF
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(DGAMMA.LE.0.0D0)THEN
         WRITE(ICOUT,51)
   51    FORMAT('***** ERROR--THE FIRST SHAPE PARAMETER TO RIGHAZ ',   &
                'IS NON-POSITIVE.')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,52)DGAMMA
   52    FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
         CALL DPWRST('XXX','BUG ')
         GO TO 9000
      ELSEIF(DMU.LE.0.0D0)THEN
         WRITE(ICOUT,71)
   71    FORMAT('***** ERROR--THE SECOND SHAPE PARAMETER TO RIGHAZ ',   &
                'IS NON-POSITIVE.')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,52)DMU
         CALL DPWRST('XXX','BUG ')
         GO TO 9000
      ELSEIF(DX.LT.0.0D0)THEN
         WRITE(ICOUT,61)
   61    FORMAT('***** ERROR--THE FIRST ARGUMENT TO RIGHAZ ',   &
                'IS NON-POSITIVE.')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,52)DX
         CALL DPWRST('XXX','BUG ')
         GO TO 9000
      ENDIF
!
      IF(DX.EQ.0.0D0)GO TO 9000
!
      CALL RIGCDF(DX,DGAMMA,DMU,DCDF)
      DCDF=1.0D0 - DCDF
      IF(DCDF.GT.0.0D0)THEN
        CALL RIGPDF(DX,DGAMMA,DMU,DPDF)
        DHAZ=DPDF/DCDF
      ELSE
        WRITE(ICOUT,162)DX
  162   FORMAT('***** FOR THE VALUE OF THE ARGUMENT ',   &
                  E15.8,' THE CDF IS ESSENTIALLY 1, HAZARD SET TO 0.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE RIGHAZ
      SUBROUTINE RIGPDF(DX,DGAMMA,DMU,DPDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE RECIPROCAL INVERSE GAUSSIAN
!              DISTRIBUTION WITH SHAPE PARAMETERS GAMMA AND MU.
!              THE RECIPROCAL INVERSE GAUSSIAN DISTRIBUTION IS
!              THE DISTRIBUTION OF Y = 1/X WHEN X HAS AN INVERSE
!              GAUSSIAN DISTRIBUTION.
!              THE FORMULA FOR THE RECIPROCAL INVERSE GAUSSIAN
!              PROBABILITY DENSITY FUNCTION IS:
!              f(X,GAMMA,MU)=SQRT(GAMMA/(2*PI*X)]*
!                            EXP[-GAMMA*(1-MU*X)**2/(2*MU**2*X)]
!                            X, GAMMA, MU > 0
!     NOTE--THE RECIPROCAL INVERSE GAUSSIA DISTRIBUTION CAN BE
!           COMPUTED IN TERMS OF THE INVERSE GAUSSIAN PDF:
!           RIGPDF(X,GAMMA,MU)=IGPDF(1/X,GAMMA,MU)/(X**2)
!     NOTE--THE RECIPROCAL INVERSE GAUSSIAN DISTRIBUTION--
!              GOES FROM 0 TO INFINITY
!              HAS MEAN = (GAMMA + MU)/(GAMMA*MU)
!              HAS STANDARD DEVIATION=SQRT((GAMMA+2*MU)/(GAMMA**2*MU))
!              IS NEAR-SYMMETRIC AND MODERATE-TAILED FOR SMALL GAMMA
!              IS HIGHLY-SKEWED AND LONG-TAILED FOR LARGE GAMMA
!              APPROACHES NORMALITY AS GAMMA APPROACHES 0
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE POSITIVE.
!                     --GAMMA  = THE SHAPE PARAMETER
!                                GAMMA SHOULD BE POSITIVE.
!                     --AMU    = THE SHAPE PARAMETER
!                                MU SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE RECIPROCAL INVERSE GAUSSIAN
!             DISTRIBUTION WITH SHAPE PARAMETERS GAMMA AND MU
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE POSITIVE.
!                 --GAMMA AND MU SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--IGPDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--SAM SAUNDERS TALK, MAY 1990
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--90.6
!     ORIGINAL VERSION--MAY       1990.
!     UPDATED         --DECEMBER  2003. USE GENERAL VALUE OF MU
!                                       INSTEAD OF ASSUMING MU=1
!     UPDATED         --APRIL     2014. CONVERT TO DOUBLE PRECISION
!     UPDATED         --APRIL     2014. SUPPORT FOR CHAN PARAMETERIZATION
!                                       (THIS ACTUALLY DONE IN IGCDF)
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DGAMMA
      DOUBLE PRECISION DMU
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DX2
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      DPDF=0.0D0
      IF(DGAMMA.LE.0.0D0)THEN
         WRITE(ICOUT,51)
   51    FORMAT('***** ERROR--THE FIRST SHAPE PARAMETER TO RIGPDF ',   &
                'IS NON-POSITIVE.')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,52)DGAMMA
   52    FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
         CALL DPWRST('XXX','BUG ')
         GO TO 9000
      ELSEIF(DMU.LE.0.0D0)THEN
         WRITE(ICOUT,71)
   71    FORMAT('***** ERROR--THE SECOND SHAPE PARAMETER TO RIGPDF ',   &
                'IS NON-POSITIVE.')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,52)DMU
         CALL DPWRST('XXX','BUG ')
         GO TO 9000
      ELSEIF(DX.LT.0.0D0)THEN
         WRITE(ICOUT,61)
   61    FORMAT('***** ERROR--THE FIRST ARGUMENT TO RIGPDF ',   &
                'IS NON-POSITIVE.')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,52)DX
         CALL DPWRST('XXX','BUG ')
         GO TO 9000
      ENDIF
!
      IF(DX.EQ.0.0D0)GO TO 9000
!
      DX2=1.0D0/DX
      CALL IGPDF(DX2,DGAMMA,DMU,DPDF)
      DPDF=DPDF/(DX**2)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE RIGPDF
      SUBROUTINE RIGPPF(DP,DGAMMA,DMU,DPPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE RECIPROCAL INVERSE GAUSSIAN
!              DISTRIBUTION WITH SHAPE PARAMETERS GAMMA AND MU.
!              THE RECIPROCAL INVERSE GAUSSIAN DISTRIBUTION IS
!              THE DISTRIBUTION OF Y = 1/X WHEN X HAS AN INVERSE
!              GAUSSIAN DISTRIBUTION.
!     NOTE--THE RECIPROCAL INVERSE GAUSSIAN PPF CAN BE
!           COMPUTED IN TERMS OF THE INVERSE GAUSSIAN PPF:
!              RIGPPF(P,GAMMA,MU) = 1/IGPPF(1-P,GAMMA,MU)
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                (BETWEEN 0.0 AND 1.0)
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --GAMMA  = THE SHAPE PARAMETER
!                                GAMMA SHOULD BE POSITIVE.
!                     --AMU    = THE SHAPE PARAMETER
!                                MU SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT POINT
!                                FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT
!             FUNCTION VALUE PPF FOR THE INVERSE GAUSSIAN DISRIBUTION
!             WITH SHAPE PARAMETERS GAMMA AND MU
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--P SHOULD BE BETWEEN
!                   0.0 (INCLUSIVELY) AND 1.0 (EXCLUSIVELY).
!                 --GAMMA AND MU SHOULD BE POSITIVE
!     OTHER DATAPAC   SUBROUTINES NEEDED--IGPPF
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--SAM SAUNDERS TALK, MAY 1990
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--90.6
!     ORIGINAL VERSION--MAY       1990.
!     UPDATED         --DECEMBER  2003. USE GENERAL VALUE OF MU
!                                       INSTEAD OF ASSUMING MU=1
!     UPDATED         --APRIL     2014. CONVERT TO DOUBLE PRECISION
!     UPDATED         --APRIL     2014. SUPPORT FOR CHAN PARAMETERIZATION
!                                       (THIS ACTUALLY DONE IN IGCDF)
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DP
      DOUBLE PRECISION DP2
      DOUBLE PRECISION DGAMMA
      DOUBLE PRECISION DMU
      DOUBLE PRECISION DPPF
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      DPPF=0.0D0
      IF(DGAMMA.LE.0.0D0)THEN
         WRITE(ICOUT,51)
   51    FORMAT('***** ERROR--THE FIRST SHAPE PARAMETER TO RIGPPF ',   &
                'IS NON-POSITIVE.')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,52)DGAMMA
   52    FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
         CALL DPWRST('XXX','BUG ')
         GO TO 9000
      ELSEIF(DMU.LE.0.0D0)THEN
         WRITE(ICOUT,71)
   71    FORMAT('***** ERROR--THE SECOND SHAPE PARAMETER TO RIGPPF ',   &
                'IS NON-POSITIVE.')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,52)DMU
         CALL DPWRST('XXX','BUG ')
         GO TO 9000
      ELSEIF(DP.LT.0.0D0 .OR. DP.GE.1.0D0)THEN
        WRITE(ICOUT,61)
   61   FORMAT('***** ERROR--THE FIRST ARGUMENT TO RIGPPF IS OUTSIDE ',   &
               'THE ALLOWABLE [0,1) INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)DP
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(DP.LE.0.0D0)GO TO 9000
!
      DP2=1.0D0 - DP
      CALL IGPPF(DP2,DGAMMA,DMU,DPPF)
      DPPF=1.0D0/DPPF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE RIGPPF
      SUBROUTINE RIGRAN(N,GAMMA,AMU,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE RECIPROCAL INVERSE GAUSSIAN DISTRIBUTION
!              WITH SHAPE PARAMETERS GAMMA AND MU.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --GAMMA  = THE SINGLE PRECISION VALUE OF THE
!                                TAIL LENGTH PARAMETER.
!                                GAMMA SHOULD BE POSITIVE.
!                     --AMU    = THE SHAPE PARAMETER
!                                MU SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE RECIPROCAL INVERSE GAUSSIAN DISTRIBUTION
!             WITH TAIL LENGTH PARAMETERS GAMMA AND MU.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --GAMMA AND MU SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, RIGPPF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON AND KOTZ
!               --SAM SAUNDERS
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--90.6
!     ORIGINAL VERSION--MAY       1990.
!     UPDATED         --DECEMBER  2003. USE GENERAL VALUE OF MU
!                                       INSTEAD OF ASSUMING MU=1
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
      DOUBLE PRECISION DPPF
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
         WRITE(ICOUT,51)
   51    FORMAT('***** ERROR--THE REQUESTED NUMBER OF ',   &
                'RECIPROCAL INVERSE GAUSSIAN RANDOM NUMBERS IS')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,52)N
   52    FORMAT('      NON-POSITIVE.  THE VALUE OF THE ARGUMENT IS ',   &
                I8,'.')
         CALL DPWRST('XXX','BUG ')
         GO TO 9000
      ELSEIF(GAMMA.LE.0.0)THEN
         WRITE(ICOUT,61)
   61    FORMAT('***** ERROR--THE GAMMA SHAPE PARAMETER FOR THE',   &
                ' RECIPROCAL INVERSE GAUSSIAN')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,62)
   62    FORMAT('      RANDOM NUMBERS IS NON-POSITIVE.')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,63)GAMMA
   63    FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
         CALL DPWRST('XXX','BUG ')
         GO TO 9000
      ELSEIF(AMU.LE.0.0)THEN
         WRITE(ICOUT,71)
   71    FORMAT('***** ERROR--THE MU SHAPE PARAMETER FOR THE',   &
                ' RECIPROCAL INVERSE GAUSSIAN')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,72)
   72    FORMAT('      RANDOM NUMBERS IS NON-POSITIVE.')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,63)AMU
         CALL DPWRST('XXX','BUG ')
         GO TO 9000
      ENDIF
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N RECIP. INV. GAUS. DISTRIBUTION RANDOM NUMBERS
!     USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      DO 100 I=1,N
        XTEMP=X(I)
        CALL RIGPPF(DBLE(XTEMP),DBLE(GAMMA),DBLE(AMU),DPPF)
        X(I)=REAL(DPPF)
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE RIGRAN
      DOUBLE PRECISION FUNCTION rlog1(x)
!-----------------------------------------------------------------------
!             EVALUATION OF THE FUNCTION X - LN(1 + X)
!-----------------------------------------------------------------------
!     .. Scalar Arguments ..
      DOUBLE PRECISION x
!     ..
!     .. Local Scalars ..
      DOUBLE PRECISION a,b,h,p0,p1,p2,q1,q2,r,t,w,w1
!     ..
!     .. Intrinsic Functions ..
      INTRINSIC dble,dlog
!     ..
!     .. Data statements ..
!------------------------
      DATA a/.566749439387324D-01/
      DATA b/.456512608815524D-01/
      DATA p0/.333333333333333D+00/,p1/-.224696413112536D+00/,   &
           p2/.620886815375787D-02/
      DATA q1/-.127408923933623D+01/,q2/.354508718369557D+00/
!     ..
!     .. Executable Statements ..
!------------------------
      IF (x.LT.-0.39D0 .OR. x.GT.0.57D0) GO TO 40
      IF (x.LT.-0.18D0) GO TO 10
      IF (x.GT.0.18D0) GO TO 20
!
!              ARGUMENT REDUCTION
!
      h = x
      w1 = 0.0D0
      GO TO 30
!
   10 h = dble(x) + 0.3D0
      h = h/0.7D0
      w1 = a - h*0.3D0
      GO TO 30
!
   20 h = 0.75D0*dble(x) - 0.25D0
      w1 = b + h/3.0D0
!
!               SERIES EXPANSION
!
   30 r = h/ (h+2.0D0)
      t = r*r
      w = ((p2*t+p1)*t+p0)/ ((q2*t+q1)*t+1.0D0)
      rlog1 = 2.0D0*t* (1.0D0/ (1.0D0-r)-r*w) + w1
      RETURN
!
!
   40 w = (x+0.5D0) + 0.5D0
      rlog1 = x - dlog(w)
      RETURN
                                                                                                                                  
      END FUNCTION rlog1
      SUBROUTINE RMS(X,N,IWRITE,XRMS,IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE SAMPLE ROOT MEANS SQUARE
!              ERROR
!
!                  RMS = SQRT(SUM[i=1 to n][X(i)**2]/N)
!
!              OF THE DATA IN THE INPUT VECTOR X.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XRMS    = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE ROOT MEAN SQUARE ERROR.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE ROOT MEAN SQUARE ERROR.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DSQRT.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010.1
!     ORIGINAL VERSION--JANUARY   2010.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DSUM
      DOUBLE PRECISION DRMS
!
      DIMENSION X(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='RMS '
      ISUBN2='    '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'RMS ')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF RMS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,N
   52   FORMAT('IBUGA3,N = ',A4,2X,I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               **************************************
!               **  COMPUTE ROOT MEAN SQUARE ERROR  **
!               **************************************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN ROOT MEAN SQUARE ERROR--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE RESPONSE ',   &
               'VARIABLE IS LESS THAN 1.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS = ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               *******************************************
!               **  STEP 2--                             **
!               **  COMPUTE THE ROOT MEAN SQUARE ERROR.  **
!               *******************************************
!
      DSUM=0.0D0
      DO 200 I=1,N
        DX=X(I)
        DSUM=DSUM + DX*DX
  200 CONTINUE
      DRMS=DSQRT(DSUM/DBLE(N))
      XRMS=REAL(DRMS)
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)N,XRMS
  811   FORMAT('THE ROOT MEAN SQUARE ERROR OF THE ',I8,   &
               ' OBSERVATIONS = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'RMS')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF SD--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR
 9012   FORMAT('IERROR = ',A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)N,DSUM,DRMS,XRMS
 9013   FORMAT('N,DSUM,DRMS,XRMS = ',I8,3G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE RMS
      REAL FUNCTION RND(X,IDIGIT)
!
!     PURPOSE--ROUND A REAL VALUE TO THE SPECIFIED NUMBER OF DIGITS
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2009/10
!     ORIGINAL VERSION--OCTOBER   2009.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      REAL X
!CCCC REAL ABSX
!CCCC REAL AMULT
      REAL SAVE1
!CCCC REAL TERM
!CCCC REAL TEMP1
!CCCC REAL TEMP2
!CCCC REAL TEMP3
!CCCC REAL TEMP4
      INTEGER IDIGIT
      INTEGER IPOWER
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      IF(IDIGIT.LT.-10)IDIGIT=-10
      IF(IDIGIT.GT.10)IDIGIT=10
!
!CCCC SAVE1=REAL(IDIGIT)
!CCCC ABSX=ABS(X)
!CCCC IPOWER=0
!CCCC IF(SAVE1.GT.0.0)IPOWER=AINT(SAVE1+0.5)
!CCCC AMULT=10.0**IPOWER
!CCCC TEMP2=ABSX*AMULT
!CCCC TEMP3=AINT(TEMP2+0.5)
!CCCC TEMP4=TEMP3/AMULT
!CCCC TERM=TEMP4
!CCCC IF(X.LT.0.0)TERM=(-TEMP4)
!CCCC RND=TERM
!
!     2014/12: ABOVE ALGORITHM DID NOT WORK AS EXPECTED FOR 64-BIT
!              INTEL FORTRAN COMPILER FOR WINDOWS.  USE DIFFERENT
!              ALGORITHM.
!
      SAVE1=REAL(IDIGIT)
      IF(SAVE1.LT.0.0)SAVE1=0.0
      IPOWER=INT(AINT(SAVE1+0.5))
      RND=REAL(INT(X*10**IPOWER + 0.5))/10**IPOWER
!
      RETURN
      END FUNCTION RND
      DOUBLE PRECISION FUNCTION RNOR()
!
!     RNOR generates normal random numbers with zero mean and unit
!     standard deviation, often denoted N(0,1),adapted from G. Marsaglia
!     and W. W. Tsang: "A Fast, Easily Implemented Method for Sampling
!     from Decreasing or Symmetric Unimodal Density Functions"
!      SIAM J. Sci. Stat. Comput. 5(1984), pp. 349-359.
!
      INTEGER J, N, TN
      DOUBLE PRECISION TWOPIS, AA, B, C, XDN
      PARAMETER ( N = 64, TN = 2*N, TWOPIS = TN/2.506628274631000D0 )
      PARAMETER ( XDN = 0.3601015713011893D0, B = 0.4878991777603940D0 )
      PARAMETER (  AA =  12.37586029917064D0, C =  12.67705807886560D0 )
      DOUBLE PRECISION XT, XX, Y, UNI
      DOUBLE PRECISION X(0:N)
      SAVE X
      DATA ( X(J), J = 0, 31 ) /   &
        0.3409450287039653D+00,  0.4573145918669259D+00,   &
        0.5397792816116612D+00,  0.6062426796530441D+00,   &
        0.6631690627645207D+00,  0.7136974590560222D+00,   &
        0.7596124749339174D+00,  0.8020356003555283D+00,   &
        0.8417226679789527D+00,  0.8792102232083114D+00,   &
        0.9148948043867484D+00,  0.9490791137530882D+00,   &
        0.9820004812398864D+00,  0.1013849238029940D+01,   &
        0.1044781036740172D+01,  0.1074925382028552D+01,   &
        0.1104391702268125D+01,  0.1133273776243940D+01,   &
        0.1161653030133931D+01,  0.1189601040838737D+01,   &
        0.1217181470700870D+01,  0.1244451587898246D+01,   &
        0.1271463480572119D+01,  0.1298265041883197D+01,   &
        0.1324900782180860D+01,  0.1351412509933371D+01,   &
        0.1377839912870011D+01,  0.1404221063559975D+01,   &
        0.1430592868502691D+01,  0.1456991476137671D+01,   &
        0.1483452656603219D+01,  0.1510012164318519D+01 /
      DATA ( X(J), J = 32, 64 ) /   &
        0.1536706093359520D+01,  0.1563571235037691D+01,   &
        0.1590645447014253D+01,  0.1617968043674446D+01,   &
        0.1645580218369081D+01,  0.1673525509567038D+01,   &
        0.1701850325062740D+01,  0.1730604541317782D+01,   &
        0.1759842199038300D+01,  0.1789622321566574D+01,   &
        0.1820009890130691D+01,  0.1851077020230275D+01,   &
        0.1882904397592872D+01,  0.1915583051943031D+01,   &
        0.1949216574916360D+01,  0.1983923928905685D+01,   &
        0.2019843052906235D+01,  0.2057135559990095D+01,   &
        0.2095992956249391D+01,  0.2136645022544389D+01,   &
        0.2179371340398135D+01,  0.2224517507216017D+01,   &
        0.2272518554850147D+01,  0.2323933820094302D+01,   &
        0.2379500774082828D+01,  0.2440221797979943D+01,   &
        0.2507511701865317D+01,  0.2583465835225429D+01,   &
        0.2671391590320836D+01,4*0.2776994269662875D+01 /
      IRESET=0
      Y = UNI(IRESET)
      J = MOD( INT( TN*UNI(IRESET) ), N )
      XT = X(J+1)
      RNOR = ( Y + Y - 1 )*XT
      IF ( ABS(RNOR) .GT. X(J) ) THEN
         XX = B*( XT - ABS(RNOR) )/( XT - X(J) )
         Y = UNI(IRESET)
         IF ( Y .GT. C - AA*EXP( -XX**2/2 ) ) THEN
            RNOR = SIGN( XX, RNOR )
         ELSE
            IF ( EXP(-XT**2/2)+Y/(TWOPIS*XT).GT.EXP(-RNOR**2/2) ) THEN
 10            XX = XDN*LOG( UNI(IRESET) )
               IF ( -2*LOG( UNI(IRESET) ) .LE. XX**2 ) GO TO 10
               RNOR = SIGN( X(N) - XX, RNOR )
            END IF
         END IF
      END IF
!
      RETURN
      END FUNCTION RNOR
      SUBROUTINE RNORM(U1, U2, ISEED)
!
!     ALGORITHM AS 53.1  APPL. STATIST. (1972) VOL.21, NO.3
!
!     Sets U1 and U2 to two independent standardized random normal
!     deviates.   This is a Fortran version of the method given in
!     Knuth(1969).
!
!     Function RAND must give a result randomly and rectangularly
!     distributed between the limits 0 and 1 exclusive.
!
      REAL U1, U2
      REAL XTEMP(1)
!
!     Local variables
!
      REAL X, Y, S, ONE, TWO
      DATA ONE /1.0/, TWO /2.0/
!
    1 CONTINUE
      N1 = 1
      CALL UNIRAN(N1,ISEED,XTEMP)
      X = XTEMP(1)
      CALL UNIRAN(N1,ISEED,XTEMP)
      Y = XTEMP(1)
!
      X = TWO * X - ONE
      Y = TWO * Y - ONE
      S = X * X + Y * Y
      IF (S .GT. ONE) GO TO 1
      S = SQRT(- TWO * LOG(S) / S)
      U1 = X * S
      U2 = Y * S
      RETURN
      END SUBROUTINE RNORM
      SUBROUTINE ROBPSD(X,N,NREPL,XTEMP1,ICASE,IWRITE,MAXNXT,   &
                        XSC,IERROR,ISUBRO,IBUGA3)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES A ROBUST POOLED STANDARD
!              DEVIATION.  THIS IS THE "ALGORITHM S" DESCRIBED IN
!              ISO STANDARD 1358 (IT WAS ORIGINALLY GIVEN IN ISO
!              STANDARD 5725-5).
!
!     REFERENCE--ISO 13528 (2005), "Statistical Methods for use in
!                proficiency testing by interlaboratory comparisons,"
!                Section C.2 Algorithm S.
!
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/12
!     ORIGINAL VERSION--DECEMBER  2010.
!
!     NOTE--THE X ARRAY MAY CONTAIN EITHER STANDARD DEVIATIONS OR
!           RANGES (ICASE SPECIFIES WHICH IS BEING USED).
!
      REAL    X(*)
      REAL    XTEMP1(*)
      REAL    XSC
      REAL    ANU
      REAL    EPS
      REAL    PHI
      REAL    WSTAR
      REAL    WSTARU
      REAL    DIFF
      REAL    XMED
!
      CHARACTER*4 ICASE
      CHARACTER*4 IWRITE
      CHARACTER*4 IERROR
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
!
      DOUBLE PRECISION DSUM
      DOUBLE PRECISION DTEMP1
!
      INTEGER N
      INTEGER MAXNXT
      INTEGER I
      INTEGER NU
      INTEGER ITER
!
      INCLUDE 'DPCOP2.INC'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'BPSD ')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF ROBPSD--')
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!     NEED AT LEAST 2 VALUES AND ALL VALUES SHOULD BE
!     NON-NEGATIVE.
!
      IF(N.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,101)
  101   FORMAT('***** ERROR IN ROBUST POOLED STANDARD DEVIATION--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,103)
  103   FORMAT('      THE NUMBER OF OBSERVATIONS IS LESS THAN TWO.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,105)N
  105   FORMAT('      THE NUMBER OF OBSERVATIONS = ',I6)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(ICASE.EQ.'SD' .AND. NREPL.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,107)
  107   FORMAT('      THE NUMBER OF REPLICATIONS FOR EACH SD IS ',   &
               'LESS THAN ONE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,109)NREPL
  109   FORMAT('      THE NUMBER OF REPLICATIONS = ',I6)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      DO 110 I=1,N
        IF(X(I).LT.0.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,101)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,113)I,X(I)
  113     FORMAT('      ROW ',I8,' CONTAINS A NEGATIVE VALUE (',   &
                 G15.7,').')
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
  110 CONTINUE
!
!     STEP 1: SORT THE STANDARD DEVIATIONS (RANGES)
!             AND COMPUTE THE MEDIAN
!
!CCCC CALL SORT(X,N,X)
      CALL MEDIAN(X,N,IWRITE,XTEMP1,MAXNXT,XMED,IBUGA3,IERROR)
      WSTAR=XMED
!
!     STEP 2: UPDATE WSTAR VIA:
!
!             1) CALCULATE PHI = NU*WSTAR
!             2) FOR EACH X(I), CALCULATE
!
!                XSTAR(I) = PHI     IF  X(I) > PHI
!                         = X(I)    OTHERWISE
!             3) UPDATED WSTAR = EPS*SQRT(SUM[i=1 to n][(XSTAR(I)**2)/N])
!
      NU=0
      IF(ICASE.EQ.'SD')THEN
        NU=NREPL-1
      ELSEIF(ICASE.EQ.'RANG')THEN
        NU=1
      ENDIF
!
      IF(NU.EQ.1)THEN
        ANU=1.645
        EPS=1.097
      ELSEIF(NU.EQ.2)THEN
        ANU=1.517
        EPS=1.054
      ELSEIF(NU.EQ.3)THEN
        ANU=1.444
        EPS=1.039
      ELSEIF(NU.EQ.4)THEN
        ANU=1.395
        EPS=1.032
      ELSEIF(NU.EQ.5)THEN
        ANU=1.359
        EPS=1.027
      ELSEIF(NU.EQ.6)THEN
        ANU=1.332
        EPS=1.024
      ELSEIF(NU.EQ.7)THEN
        ANU=1.310
        EPS=1.021
      ELSEIF(NU.EQ.8)THEN
        ANU=1.292
        EPS=1.019
      ELSEIF(NU.EQ.9)THEN
        ANU=1.277
        EPS=1.018
      ELSEIF(NU.EQ.10)THEN
        ANU=1.264
        EPS=1.017
      ELSE
        CALL CHSPPF(0.9,NU,APPF)
        ANU=SQRT(APPF/REAL(NU))
        IDF=NU+2
        TERM1=REAL(NU)*ANU*ANU
        CALL CHSCDF(TERM1,IDF,CDF)
        EPS=1.0/SQRT(CDF + 0.1*ANU*ANU)
      ENDIF
!
      ITER=1
 1000 CONTINUE
      PHI=ANU*WSTAR
      DSUM=0.0D0
      DO 1010 I=1,N
        IF(X(I).GT.PHI)THEN
          XTEMP1(I)=PHI
          DSUM=DSUM + DBLE(PHI)**2
        ELSE
          DSUM=DSUM + DBLE(X(I))**2
        ENDIF
 1010 CONTINUE
      DTEMP1=DBLE(EPS)*DSQRT(DSUM/DBLE(N))
      WSTARU=REAL(DTEMP1)
      DIFF=ABS(WSTAR - WSTARU)
      RATIO=WSTAR/WSTARU
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'BPSD ')THEN
        WRITE(ICOUT,1022)ITER,WSTAR,WSTARU,DIFF,RATIO
 1022   FORMAT('ITER,WSTAR,WSTARU,DIFF,RATIO =',I5,4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1024)ANU,EPS,PHI
 1024   FORMAT('ANU,EPS,PHI =',3G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      ITER=ITER+1
      IF(ITER.GT.50)GO TO 1099
      IF(ABS(RATIO - 1.0) .LT. 1.0E-4)GO TO 1099
      IF(DIFF.LT.0.0000001)GO TO 1099
      WSTAR=WSTARU
      GO TO 1000
!
 1099 CONTINUE
      WSTAR=WSTARU
      XSC=WSTAR
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'BPSD ')THEN
        WRITE(ICOUT,9010)
 9010   FORMAT('AT THE END OF ROBPSD')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)XSC
 9012   FORMAT('XSC=',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE ROBPSD
      SUBROUTINE RPOCDF(X,C,CDF)
!
!     NOTE--THE STANDARD REFLECTED POWER FUNCTION
!           CUMULATIVE DISTRIBUTION FUNCTION IS:
!
!           F(X,C) = 1 - (1-X)**C        0 <= X <= 1, C > 0
!
!           WITH C DENOTING THE SCALE PARAMETER.
!     REFERENCE --KOTZ AND VAN DORP (2004), "BEYOND BETA: OTHER
!                 CONTINUOUS FAMILIES OF DISTRIBUTIONS WITH BOUNDED
!                 SUPPORT AND APPLICATION", WORLD SCIENTIFIC, PP. 199-201.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/12
!     ORIGINAL VERSION--DECEMBER  2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DC
      DOUBLE PRECISION DCDF
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(X.LE.0.0)THEN
        CDF=0.0
        GO TO 9999
      ELSEIF(X.GE.1.0)THEN
        CDF=1.0
        GO TO 9999
      ENDIF
!
      IF(C.LE.0.0)THEN
        WRITE(ICOUT,311)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,302)C
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9999
      ENDIF
  311 FORMAT('***** ERROR IN RPOCDF--THE SECOND ARGUMENT IS ',   &
             'NON-POSITIVE.')
  302 FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      DX=DBLE(X)
      DC=DBLE(C)
      DCDF=1.0D0 - (1.0D0-DX)**DC
      CDF=REAL(DCDF)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE RPOCDF
      SUBROUTINE RPOCHA(X,C,HAZ)
!
!     NOTE--THE STANDARD REFLECTED POWER FUNCTION CUMULATIVE HAZARD
!           FUNCTION IS:
!
!              H(X;C) = -LOG((1 - X)**C)       0 <= X <= 1, C > 0
!
!           WHERE C IS THE SHAPE PARAMETER.
!     REFERENCE --KOTZ AND VAN DORP (2004), "BEYOND BETA: OTHER
!                 CONTINUOUS FAMILIES OF DISTRIBUTIONS WITH BOUNDED
!                 SUPPORT AND APPLICATION", WORLD SCIENTIFIC, PP. 199-201.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/12
!     ORIGINAL VERSION--DECEMBER  2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DX
      DOUBLE PRECISION DC
      DOUBLE PRECISION DHAZ
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      HAZ=0.0
      IF(X.LT.0.0 .OR. X.GT.1.0)THEN
        WRITE(ICOUT,301)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,302)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(C.LE.0.0)THEN
        WRITE(ICOUT,311)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,302)C
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
  301 FORMAT('***** ERROR IN RPOCHAZ--THE FIRST ARGUMENT IS NOT IN ',   &
             'THE INTERVAL (0,1).')
  311 FORMAT('***** ERROR IN RPOCHAZ--THE SECOND ARGUMENT IS ',   &
             'NON-POSITIVE.')
  302 FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      DX=DBLE(X)
      DC=DBLE(C)
      DTERM1=(1.0D0 - DX)**DC
      IF(DTERM1.GT.0.0D0)THEN
        DHAZ=-DLOG(DTERM1)
        HAZ=REAL(DHAZ)
      ELSE
        WRITE(ICOUT,401)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,402)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,302)X
        CALL DPWRST('XXX','BUG ')
      ENDIF
  401 FORMAT('***** ERROR IN RPOCHAZ')
  402 FORMAT('      THE COMPUTED VALUE OF THE HAZARD FUNCTION ',   &
             'OVERFLOWS.')
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE RPOCHA
      SUBROUTINE RPOHAZ(X,C,HAZ)
!
!     NOTE--THE STANDARD REFLECTED POWER FUNCTION HAZARD
!           FUNCTION IS:
!
!              h(X;C) = C/(1 - X)     0 <= X <= 1, C > 0
!
!           WHERE C IS THE SHAPE PARAMETER.
!     REFERENCE --KOTZ AND VAN DORP (2004), "BEYOND BETA: OTHER
!                 CONTINUOUS FAMILIES OF DISTRIBUTIONS WITH BOUNDED
!                 SUPPORT AND APPLICATION", WORLD SCIENTIFIC, PP. 199-201.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/12
!     ORIGINAL VERSION--DECEMBER  2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DC
      DOUBLE PRECISION DHAZ
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      HAZ=0.0
      IF(X.LT.0.0 .OR. X.GE.1.0)THEN
        WRITE(ICOUT,301)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,302)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(C.LE.0.0)THEN
        WRITE(ICOUT,311)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,302)C
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
  301 FORMAT('***** ERROR IN RPOHAZ--THE FIRST ARGUMENT IS NOT IN ',   &
             'THE INTERVAL (0,1).')
  311 FORMAT('***** ERROR IN RPOHAZ--THE SECOND ARGUMENT IS ',   &
             'NON-POSITIVE.')
  302 FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      DX=DBLE(X)
      DC=DBLE(C)
      DHAZ=DC/(1.0D0 - DX)
      HAZ=REAL(DHAZ)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE RPOHAZ
      SUBROUTINE RPOPDF(X,C,PDF)
!
!     NOTE--THE STANDARD REFLECTED POWER FUNCTION PROBABILITY DENSITY
!           FUNCTION IS:
!
!              f(X;C) = C*(1-X)**(C-1)    0 <= X <= 1, C > 0
!
!           WITH C DENOTING THE SHAPE PARAMETER.
!     REFERENCE --KOTZ AND VAN DORP (2004), "BEYOND BETA: OTHER
!                 CONTINUOUS FAMILIES OF DISTRIBUTIONS WITH BOUNDED
!                 SUPPORT AND APPLICATION", WORLD SCIENTIFIC, PP. 199-201.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/12
!     ORIGINAL VERSION--DECEMBER  2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DC
      DOUBLE PRECISION DPDF
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      PDF=0.0
      IF(X.LT.0.0 .OR. X.GT.1.0)THEN
        WRITE(ICOUT,301)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,302)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(C.LE.0.0)THEN
        WRITE(ICOUT,311)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,302)C
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(X.GE.1.0 .AND. C.LT.1.0)THEN
        WRITE(ICOUT,301)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,302)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
  301 FORMAT('***** ERROR IN RPOPDF--THE FIRST ARGUMENT IS NOT IN ',   &
             'THE INTERVAL (0,1).')
  311 FORMAT('***** ERROR IN RPOPDF--THE SECOND ARGUMENT IS ',   &
             'NON-POSITIVE.')
  302 FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      DX=DBLE(X)
      DC=DBLE(C)
      DPDF=DC*(1.0D0 - DX)**(DC-1.0D0)
      PDF=REAL(DPDF)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE RPOPDF
      SUBROUTINE RPOPPF(P,C,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT FUNCTION
!              VALUE FOR THE REFLECTED POWER FUNCTION DISTRIBUTION.
!              THE STANDARD REFLECTED POWER FUNCTION PPF IS:
!
!              G(P;C) = 1 - (1-P)**(1/C)    0 <= P <= 1, C > 0
!
!           WITH C DENOTING THE SHAPE PARAMETER.
!     REFERENCE --KOTZ AND VAN DORP (2004), "BEYOND BETA: OTHER
!                 CONTINUOUS FAMILIES OF DISTRIBUTIONS WITH BOUNDED
!                 SUPPORT AND APPLICATION", WORLD SCIENTIFIC, PP. 199-201.
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                (BETWEEN 0.0 AND 1.0)
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --C      = THE SINGLE PRECISION VALUE OF THE SHAPE
!                                PARAMETER.
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT
!                                POINT FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT
!             FUNCTION VALUE PPF.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--P SHOULD BE BETWEEN 0.0 AND 1.0, INCLUSIVELY.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-921-3651
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007.12
!     ORIGINAL VERSION--DECEMBER  2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DP
      DOUBLE PRECISION DC
      DOUBLE PRECISION DPPF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PPF=0.0
      IF(P.LT.0.0 .OR. P.GT.1.0)THEN
        WRITE(ICOUT,301)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,302)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(C.LE.0.0)THEN
        WRITE(ICOUT,311)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,302)C
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
  301 FORMAT('***** ERROR IN RPOPPF--THE FIRST ARGUMENT IS NOT IN ',   &
             'THE INTERVAL (0,1).')
  311 FORMAT('***** ERROR IN RPOPPF--THE SECOND ARGUMENT IS ',   &
             'NON-POSITIVE.')
  302 FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!-----START POINT-----------------------------------------------------
!
      IF(P.EQ.0.0)THEN
        PPF=0.0
      ELSEIF(P.EQ.1.0)THEN
        PPF=1.0
      ELSE
        DP=DBLE(P)
        DC=DBLE(C)
        DPPF=1.0D0 - (1.0D0-DP)**(1.0D0/DC)
        PPF=REAL(DPPF)
      ENDIF
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE RPOPPF
      SUBROUTINE RPORAN(N,C,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE THE REFLECTED POWER FUNCTION.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --C      = A SINGLE PRECISION VALUE THAT SPECIFIES
!                                THE VALUE OF THE SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE REFLECTED POWER DISTRIBUTION
!             WITH MEAN = 0 AND STANDARD DEVIATION = 1.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCE --KOTZ AND VAN DORP (2004), "BEYOND BETA: OTHER
!                 CONTINUOUS FAMILIES OF DISTRIBUTIONS WITH BOUNDED
!                 SUPPORT AND APPLICATION", WORLD SCIENTIFIC, PP. 199-201.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007.12
!     ORIGINAL VERSION--DECEMBER  2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DIMENSION X(*)
      DOUBLE PRECISION DX
      DOUBLE PRECISION DC
      DOUBLE PRECISION DTEMP
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(C.LE.0.0)THEN
        WRITE(ICOUT,311)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,312)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,302)C
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR--THE REQUESTED NUMBER OF REFLECTED POWER ',   &
             'FUNCTION RANDOM NUMBERS IS NON-POSITIVE.')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
  311 FORMAT('***** ERROR IN REFLECTED POWER FUNCTION RANDOM NUMBERS.')
  312 FORMAT('      THE VALUE OF THE SHAPE PARAMETER IS NON-POSITIVE.')
  302 FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     REFLECTED POWER FUNCTION RANDOM NUMBERS = (UNIFORM)**(1/C)
!
      DC=DBLE(C)
      DO 200 I=1,N
        DX=DBLE(X(I))
        DTEMP=1.0D0 - (1.0D0-DX)**(1.0D0/DC)
        X(I)=REAL(DTEMP)
  200 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE RPORAN
      SUBROUTINE RSCSUM(X,N,XCAP,IWRITE,XRSCSU,IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE RESCALED SUM OF SCORES
!
!                  RSCSUM = SUM[i=1 to n][X(i)]/SQRT(N)
!
!              OF THE DATA IN THE INPUT VECTOR X.
!
!              SOME AUTHORS RECOMMEND CAPPING THE VALUE OF
!              OUTLIERS TO LESSEN THE EFFECT OF SEVERE OUTLIERS
!              (THIS CAP IS TYPICALLY SET TO EITHER +/-3 OR
!              +/- 4).  SET XOUT TO CPUMIN IF CAPPING IS NOT
!              DESIRED.
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--RSCSUM = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED RESCALED SUM.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE RESCALED SUM.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2012.2
!     ORIGINAL VERSION--FEBRUARY  2012.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DX
      DOUBLE PRECISION DSUM
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='RSCS'
      ISUBN2='UM  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CSUM')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF RSCSUM--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,N,XCAP
   52   FORMAT('IBUGA3,N,XCAP = ',A4,2X,I8,2X,G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN RESCALED SUM ERROR--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE RESPONSE ',   &
               'VARIABLE IS LESS THAN 1.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS = ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ******************************************
!               **  STEP 2--                            **
!               **  COMPUTE THE SUM OF RESCALED SCORES. **
!               ******************************************
!
      DSUM=0.0D0
      IF(XCAP.EQ.CPUMIN)THEN
        DO 200 I=1,N
          DX=X(I)
          DSUM=DSUM + DX
  200   CONTINUE
      ELSE
        DO 300 I=1,N
          DX=X(I)
          IF(DABS(DX).GT.DBLE(XCAP))THEN
            IF(DX.GT.0.0D0)THEN
              DX=ABS(XCAP)
            ELSE
              DX=-ABS(XCAP)
            ENDIF
          ENDIF
          DSUM=DSUM + DX
  300   CONTINUE
      ENDIF
      DN=DBLE(N)
      XRSCSU=REAL(DSUM/DSQRT(DN))
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)N,XRSCSS
  811   FORMAT('THE RESCALED SUM OF THE ',I8,' OBSERVATIONS = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CSUM')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END OF RSCSUM--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)IERROR,N,DSUM,XRSCSU
 9013   FORMAT('IERROR,N,DSUM,XRSCSU = ',A4,2X,I8,2G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE RSCSUM
      SUBROUTINE RSURF(X,Y,NP,KOLR,FRM,   &
                       XTEMP,YTEMP,TATEMP,NTEMP,NTRACE,   &
                       IBUGG3,ISUBRO,IERROR)
!
!     PURPOSE--PAINT IN THE ENCLOSED REGION
!              DEFINED BY THE NP COORDINATES
!              IN X(.) AND Y(.).
!              USE FILL COLOR AS SPECIFIED BY THE INTEGER KOLR
!              (WHERE KOLR = 0 IMPLIES NO FILL).
!
!     WRITTEN BY--DAVID W. BEHRINGER NOAA/AOML (MIAMI).
!                 AS PART OF NOAA'S CONCX V.3   MARCH 1988.
!     ORIGINAL VERSION (IN DATAPLOT)--AUGUST    1988.
!
!---------------------------------------------------------------------
!
      CHARACTER*4 IBUGG3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      DIMENSION X(*)
      DIMENSION Y(*)
!
      DIMENSION XTEMP(*)
      DIMENSION YTEMP(*)
      DIMENSION TATEMP(*)
!
!---------------------------------------------------------------------
!
