!
!CCCC NTRACE=NTRACE+1
!CCCC DO1100I=1,NP
!CCCC NTEMP=NTEMP+1
!CCCC XTEMP(NTEMP)=X(I)
!CCCC YTEMP(NTEMP)=Y(I)
!CCCC TATEMP(NTEMP)=NTRACE
!1100 CONTINUE
!
      RETURN
      END SUBROUTINE RSURF
      SUBROUTINE RULNRM( LENRUL, NUMNUL, RULPTS, W, RULCON )
      INTEGER LENRUL, NUMNUL, I, J, K, RULPTS(*)
      DOUBLE PRECISION ALPHA, NORMCF, NORMNL, W(LENRUL, *), RULCON
!
!     Compute orthonormalized null rules.
!
      NORMCF = 0
      DO 100 I = 1,LENRUL
         NORMCF = NORMCF + RULPTS(I)*W(I,1)*W(I,1)
  100 CONTINUE
      DO 200 K = 2,NUMNUL
         DO 300 I = 1,LENRUL
            W(I,K) = W(I,K) - W(I,1)
  300    CONTINUE
         DO 400 J = 2,K-1
            ALPHA = 0
            DO 500 I = 1,LENRUL
               ALPHA = ALPHA + RULPTS(I)*W(I,J)*W(I,K)
  500       CONTINUE
            ALPHA = -ALPHA/NORMCF
            DO 600 I = 1,LENRUL
               W(I,K) = W(I,K) + ALPHA*W(I,J)
  600       CONTINUE
  400    CONTINUE
         NORMNL = 0
         DO 700 I = 1,LENRUL
            NORMNL = NORMNL + RULPTS(I)*W(I,K)*W(I,K)
  700    CONTINUE
         ALPHA = SQRT(NORMCF/NORMNL)
         DO 800 I = 1,LENRUL
            W(I,K) = ALPHA*W(I,K)
  800    CONTINUE
  200 CONTINUE
      DO 900 J = 2, NUMNUL
         DO 950 I = 1,LENRUL
            W(I,J) = W(I,J)/RULCON
  950    CONTINUE
  900 CONTINUE
!
      RETURN
      END SUBROUTINE RULNRM
      FUNCTION RUNIF(T,N)
!***BEGIN PROLOGUE  RUNIF
!***DATE WRITTEN   770401   (YYMMDD)
!***REVISION DATE  820801   (YYMMDD)
!***REVISION HISTORY  (YYMMDD)
!   000330  Modified array declarations.  (JEC)
!***CATEGORY NO.  L6A21
!***KEYWORDS  RANDOM NUMBER,SPECIAL FUNCTION,UNIFORM
!***AUTHOR  FULLERTON, W., (LANL)
!***PURPOSE  A portable random number genaerator.
!***DESCRIPTION
!
! This random number generator is portable among a wide variety of
! computers.  It generates a random number between 0.0 and 1.0 accord-
! ing to the algorithm presented by Bays and Durham (TOMS, 2, 59,
! 1976).  The motivation for using this scheme, which resembles the
! Maclaren-Marsaglia method, is to greatly increase the period of the
! random sequence.  If the period of the basic generator (RAND) is P,
! then the expected mean period of the sequence generated by RUNIF is
! given by   new mean P = SQRT (PI*FACTORIAL(N)/(8*P)),
! where FACTORIAL(N) must be much greater than P in this asymptotic
! formula.  Generally, N should be around 32 if P=4.E6 as for RAND.
!
!             Input Argument --
! N      IABS(N) is the number of random numbers in an auxiliary table.
!        Note though that IABS(N)+1 is the number of items in array T.
!        If N is positive and differs from its value in the previous
!        invocation, then the table is initialized for the new value of
!        N.  If N is negative, IABS(N) is the number of items in an
!        auxiliary table, but the tables are now assumed already to
!        be initialized.  This option enables the user to save the
!        table T at the end of a long computer run and to restart with
!        the same sequence.  Normally, RUNIF would be called at most
!        once with negative N.  Subsequent invocations would have N
!        positive and of the correct magnitude.
!
!             Input and Output Argument  --
! T      an array of IABS(N)+1 random numbers from a previous invocation
!        of RUNIF.  Whenever N is positive and differs from the old
!        N, the table is initialized.  The first IABS(N) numbers are the
!        table discussed in the reference, and the N+1 -st value is Y.
!        This array may be saved in order to restart a sequence.
!
!             Output Value --
! RUNIF  a random number between 0.0 and 1.0.
!***REFERENCES  (NONE)
!***ROUTINES CALLED  RAND
!***END PROLOGUE  RUNIF
      DIMENSION T(*)
      EXTERNAL RANDDP
      DATA NOLD /-1/
!***FIRST EXECUTABLE STATEMENT  RUNIF
!
      FLOATN=0.0
!
      IF (N.EQ.NOLD) GO TO 20
!
      NOLD = IABS(N)
      FLOATN = NOLD
      IF (N.LT.0) DUMMY = RANDDP (T(NOLD+1))
      IF (N.LT.0) GO TO 20
!
      DO 10 I=1,NOLD
        T(I) = RANDDP (0.)
 10   CONTINUE
      T(NOLD+1) = RANDDP (0.)
!
 20   J = INT(T(NOLD+1)*FLOATN + 1.)
      T(NOLD+1) = T(J)
      RUNIF = T(J)
      T(J) = RANDDP (0.)
!
      RETURN
      END FUNCTION RUNIF
      subroutine rwts(y,n,fit,rw)
!
!  This routine is part of the Bill Cleveland seasonal loess
!  program.
!
      integer mid(2), n
      real y(n), fit(n), rw(n), cmad, c9, c1, r
      do 23097 i = 1,n
      rw(i) = abs(y(i)-fit(i))
23097 continue
      mid(1) = n/2+1
      mid(2) = n-mid(1)+1
      call psort(rw,n,mid,2)
      cmad = 3.0*(rw(mid(1))+rw(mid(2)))
      c9 = .999*cmad
      c1 = .001*cmad
      do 23099 i = 1,n
      r = abs(y(i)-fit(i))
      if(.not.(r .le. c1))go to 23101
      rw(i) = 1.
      go to 23102
23101 continue
      if(.not.(r .le. c9))go to 23103
      rw(i) = (1.0-(r/cmad)**2)**2
      go to 23104
23103 continue
      rw(i) = 0.
23104 continue
23102 continue
23099 continue
      return
      end
      SUBROUTINE R9AIMP (X, AMPL, THETA)
!***BEGIN PROLOGUE  R9AIMP
!***SUBSIDIARY
!***PURPOSE  Evaluate the Airy modulus and phase.
!***LIBRARY   SLATEC (FNLIB)
!***CATEGORY  C10D
!***TYPE      SINGLE PRECISION (R9AIMP-S, D9AIMP-D)
!***KEYWORDS  AIRY FUNCTION, FNLIB, MODULUS, PHASE, SPECIAL FUNCTIONS
!***AUTHOR  Fullerton, W., (LANL)
!***DESCRIPTION
!
! Evaluate the Airy modulus and phase for X .LE. -1.0
!
! Series for AM21       on the interval -1.25000D-01 to  0.
!                                        with weighted error   2.89E-17
!                                         log weighted error  16.54
!                               significant figures required  14.15
!                                    decimal places required  17.34
!
! Series for ATH1       on the interval -1.25000D-01 to  0.
!                                        with weighted error   2.53E-17
!                                         log weighted error  16.60
!                               significant figures required  15.15
!                                    decimal places required  17.38
!
! Series for AM22       on the interval -1.00000D+00 to -1.25000D-01
!                                        with weighted error   2.99E-17
!                                         log weighted error  16.52
!                               significant figures required  14.57
!                                    decimal places required  17.28
!
! Series for ATH2       on the interval -1.00000D+00 to -1.25000D-01
!                                        with weighted error   2.57E-17
!                                         log weighted error  16.59
!                               significant figures required  15.07
!                                    decimal places required  17.34
!
!***REFERENCES  (NONE)
!***ROUTINES CALLED  CSEVL, INITS, R1MACH, XERMSG
!***REVISION HISTORY  (YYMMDD)
!   770701  DATE WRITTEN
!   890206  REVISION DATE from Version 3.2
!   891214  Prologue converted to Version 4.0 format.  (BAB)
!   900315  CALLs to XERROR changed to CALLs to XERMSG.  (THJ)
!   900720  Routine changed from user-callable to subsidiary.  (WRB)
!***END PROLOGUE  R9AIMP
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
      DIMENSION AM21CS(40), ATH1CS(36), AM22CS(33), ATH2CS(32)
