      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,811)N,XSD
  811 FORMAT('THE STANDARD DEVIATION OF THE ',I8,' OBSERVATIONS = ',   &
      E15.7)
      CALL DPWRST('XXX','BUG ')
  890 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF SDDP--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGA3,IERROR
 9012 FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)N
 9013 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9014)DMEAN
 9014 FORMAT('DMEAN = ',D15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)XSD
 9015 FORMAT('XSD = ',E15.7)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE SDDP
      SUBROUTINE SDECDF(X,ALMBDA,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE SKEW-LAPLACE DISTRIBUTION
!              (OR SKEW-DOUBLE EXPONENTIAL)
!              WITH SHAPE PARAMETER = LAMBDA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND HAS
!              THE CUMULATIVE DISTRIBUTION FUNCTION
!                 SDECDF(X,LAMBDA) = 0.5*EXP((1+LAMBDA)*X)/(1+LAMMBDA)
!                                                          X <= 0
!                                  = 1 + (1)*EXP(-X) -
!                                    0.5/(EXP((1+LAMBDA)*X)*(-1-LAMBDA))
!                                                          X > 0
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                     --ALMBDA = THE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE SKEWED-LAPLACE DISTRIBUTION
!             WITH SHAPE PARAMETER = LAMBDA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--KOTZ, KOZUBOWSKI, AND PODGORSKI, "THE LAPLACE
!                 DISTRIBUTION AND GENERALIZATIONS: A REVISIT WITH
!                 APPLICATIONS TO COMMUNICATIONS, ECONOMICS,
!                 ENGINEERING, AND FINANCE", BIRKHAUSR, 2001,
!                 PP. 134.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.6
!     ORIGINAL VERSION--JUNE      2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DLMBDA
      DOUBLE PRECISION DCDF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!               ************************************
!               **  STEP 1--                      **
!               **  COMPUTE THE DENSITY FUNCTION  **
!               ************************************
!
      IF(ALMBDA.LT.0.0)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)ALMBDA
        CALL DPWRST('XXX','WRIT')
        CDF=0.0
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR: VALUE OF SHAPE PARAMETER IN SDECDF ',   &
             'ROUTINE IS NEGATIVE.')
   48 FORMAT('      VALUE OF ARGUMENT IS: ',G15.7)
!
      DX=DBLE(X)
      DLMBDA=DBLE(ALMBDA)
!
      IF(ALMBDA.EQ.0)THEN
        CALL DEXCDF(X,CDF)
        GO TO 9000
      ELSE
        IF(X.LE.0.0)THEN
          DCDF=0.5D0*DEXP((1.0D0 + DLMBDA)*DX)/(1.0D0 + DLMBDA)
        ELSE
          DCDF=1.0D0 - DEXP(-DX) -   &
               0.5D0/(DEXP((1.0D0 + DLMBDA)*DX)*(-1.0D0-DLMBDA))
        ENDIF
        CDF=REAL(DCDF)
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE SDECDF
      REAL FUNCTION SDEFUN(X)
!
!     PURPOSE--SDEPPF CALLS FZERO TO FIND A ROOT FOR THE PERCENT
!              POINT FUNCTION.  SDEFUN IS THE FUNCTION FOR WHICH
!              THE ZERO IS FOUND.  IT IS:
!                 P - SDECDF(X,LAMBDA)
!              WHERE P IS THE DESIRED PERCENT POINT.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE SDEFUN.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--SDECDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.6
!     ORIGINAL VERSION--JUNE      2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      REAL P
      COMMON/SDECOM/P,ALAMB
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      CALL SDECDF(X,ALAMB,CDF)
      SDEFUN=P - CDF
!
      RETURN
      END FUNCTION SDEFUN
      SUBROUTINE SDEPDF(X,ALMBDA,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE SKEW-LAPLACE DISTRIBUTION
!              (OR SKEW-DOUBLE EXPONENTIAL)
!              WITH SHAPE PARAMETER = LAMBDA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND HAS
!              THE PROBABILITY DENSITY FUNCTION
!                 SDEPDF(X,LAMBDA) = 0.5*EXP((1+LAMBDA)*X)   X <= 0
!                                  = EXP(-X) - 0.5*EXP((1+LAMBDA)*X)
!                                                            X > 0
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                     --ALMBDA = THE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE SKEWED-LAPLACE DISTRIBUTION
!             WITH SHAPE PARAMETER = LAMBDA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--KOTZ, KOZUBOWSKI, AND PODGORSKI, "THE LAPLACE
!                 DISTRIBUTION AND GENERALIZATIONS: A REVISIT WITH
!                 APPLICATIONS TO COMMUNICATIONS, ECONOMICS,
!                 ENGINEERING, AND FINANCE", BIRKHAUSR, 2001,
!                 PP. 134.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.6
!     ORIGINAL VERSION--JUNE      2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DLMBDA
      DOUBLE PRECISION DPDF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!               ************************************
!               **  STEP 1--                      **
!               **  COMPUTE THE DENSITY FUNCTION  **
!               ************************************
!
      IF(ALMBDA.LT.0.0)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)ALMBDA
        CALL DPWRST('XXX','WRIT')
        PDF=0.0
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR: VALUE OF SHAPE PARAMETER IN SDEPDF ',   &
             'ROUTINE IS NEGATIVE.')
   48 FORMAT('      VALUE OF ARGUMENT IS: ',G15.7)
!
      DX=DBLE(X)
      DLMBDA=DBLE(ALMBDA)
!
      IF(ALMBDA.EQ.0.0)THEN
        CALL DEXPDF(X,PDF)
        GO TO 9000
      ELSE
        IF(X.LE.0.0)THEN
          DPDF=0.5D0*DEXP((1.0D0 + DLMBDA)*DX)
        ELSE
          DPDF=DEXP(-DX) - 0.5D0*DEXP(-(1.0D0 + DLMBDA)*DX)
        ENDIF
        PDF=REAL(DPDF)
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE SDEPDF
      SUBROUTINE SDEPPF(P,ALMBDA,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE SKEW DOUBLE EXPONENTIAL
!              DISTRIBUTION WITH SHAPE PARAMETER = LAMBDA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND THE
!              PERCENT POINT FUNCTION IS COMPUTED BY:
!              1) COMPUTE PCUT = SDECDF(0,LAMBDA)
!              2) IF P <= PCUT, USE CLOSED FORM FORMULA:
!                    PPF = LOG[2*P*(1+LAMBDA)]/(1+LAMBDA)
!
!              3) IF P > PCUT, NUMERICALLY INVERT THE CDF FUNCTION.
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --ALMBDA = THE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT
!             FUNCTION VALUE PPF.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--FZERO.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--KOTZ, KOZUBOWSKI, AND PODGORSKI, "THE LAPLACE
!                 DISTRIBUTION AND GENERALIZATIONS: A REVISIT WITH
!                 APPLICATIONS TO COMMUNICATIONS, ECONOMICS,
!                 ENGINEERING, AND FINANCE", BIRKHAUSR, 2001,
!                 PP. 134.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.6
!     ORIGINAL VERSION--JUNE      2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      REAL PPF
      DOUBLE PRECISION DP
      DOUBLE PRECISION DPPF
      DOUBLE PRECISION DLMBDA
!
      REAL SDEFUN
      EXTERNAL SDEFUN
!
      REAL P2,ALAMB
      COMMON/SDECOM/P2,ALAMB
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!
      IF(P.LE.0.0.OR.P.GE.1.0)THEN
         WRITE(ICOUT,61)
   61    FORMAT('***** ERROR--THE FIRST  INPUT ARGUMENT ',   &
                'TO THE SDEPPF SUBROUTINE ')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,62)
   62    FORMAT('      IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL.')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,63)P
   63    FORMAT('      VALUE OF ARGUMENT = ',G15.7)
         CALL DPWRST('XXX','BUG ')
         PPF=0.0
         GO TO 9000
      ENDIF
!
      IF(ALMBDA.LT.0.0)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)ALMBDA
        CALL DPWRST('XXX','WRIT')
        PDF=0.0
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR: VALUE OF SHAPE PARAMETER IN SDEPPF ',   &
             'ROUTINE IS NEGATIVE.')
   48 FORMAT('      VALUE OF ARGUMENT IS: ',G15.7)
!
      DP=DBLE(P)
      DLMBDA=DBLE(ALMBDA)
!
      IF(ALMBDA.EQ.0.0)THEN
        CALL DEXPPF(P,PPF)
        GO TO 9000
      ENDIF
!
!  STEP 1: COMPUTE SDECDF(0,LAMBDA).  CLOSED FORM FOR P < PCUT.
!
      CALL SDECDF(0.0,ALMBDA,PCUT)
      IF(P.LE.PCUT)THEN
        DPPF=DLOG(2.0D0*DP*(1.0D0+DLMBDA))/(1.0D0+DLMBDA)
        PPF=REAL(DPPF)
        GO TO 9000
      ENDIF
!
!  STEP 2: FIND BRACKETING INTERVAL.  PCUT IS LOWER BOUND, PPF OF
!          EXPONENTIAL DISTRIBUTION IS UPPER BOUND.
!
      XLOW=PCUT
      CALL EXPPPF(P,XUP)
      XLOW=XLOW - 1.0
      XUP=XUP + 10.0
!
      AE=1.E-6
      RE=1.E-6
      ALAMB=ALMBDA
      P2=P
      CALL FZERO(SDEFUN,XLOW,XUP,XUP,RE,AE,IFLAG)
!
      PPF=XLOW
      IF(IFLAG.EQ.2)THEN
!
!  NOTE: SUPPRESS THIS MESSAGE FOR NOW.
!CCCC   WRITE(ICOUT,999)
  999   FORMAT(1X)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,111)
!C111   FORMAT('***** WARNING FROM SDEPPF--')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,113)
!C113   FORMAT('      PPF VALUE MAY NOT BE COMPUTED TO DESIRED ',
!CCCC1         'TOLERANCE.')
!CCCC   CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.3)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,121)
  121   FORMAT('***** WARNING FROM SDEPPF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,123)
  123   FORMAT('      PPF VALUE MAY BE NEAR A SINGULAR POINT.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,131)
  131   FORMAT('***** ERROR FROM SDEPPF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,133)
  133   FORMAT('      APPROPRIATE BRACKETING INTERVAL NOT FOUND.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,141)
  141   FORMAT('***** WARNING FROM SDEPPF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,143)
  143   FORMAT('      MAXIMUM ITERATIONS EXCEEDED.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE SDEPPF
      SUBROUTINE SDERAN(N,ALMBDA,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE SKEWED DOUBLE EXPONENTIAL (LAPLACE)
!              DISTRIBUTION WITH SHAPE PARAMETER = ALMBDA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND HAS
!              THE PROBABILITY DENSITY FUNCTION
!                 SDEPDF(X,LAMBDA) = 0.5*EXP((1+LAMBDA)*X)   X <= 0
!                                  = EXP(-X) - 0.5*EXP((1+LAMBDA)*X)
!                                                            X > 0
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --ALMBDA = THE SHAPE (PARAMETER) FOR THE
!                                SKEWED DOUBLE EXPONENTIAL
!                                DISTRIBUTION.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE SKEWED DOUBLE EXPONENTIAL DISTRIBUTION
!             WITH SHAPE PARAMETER = ALMBDA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --ALMBDA CAN BE ANY REAL NUMBER.
!     OTHER DATAPAC   SUBROUTINES NEEDED--SDEPPF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--KOTZ, KOZUBOWSKI, AND PODGORSKI, "THE LAPLACE
!                 DISTRIBUTION AND GENERALIZATIONS: A REVISIT WITH
!                 APPLICATIONS TO COMMUNICATIONS, ECONOMICS,
!                 ENGINEERING, AND FINANCE", BIRKHAUSR, 2001,
!                 PP. 134.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.6
!     ORIGINAL VERSION--JUNE      2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
      IF(ALMBDA.LT.0.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)ALMBDA
        CALL DPWRST('XXX','WRIT')
        PDF=0.0
        GO TO 9999
      ENDIF
    5 FORMAT('***** ERROR--FOR THE SKEWED DOUBLE EXPONENTIAL ',   &
             'DISTRIBUTION,')
    6 FORMAT('       THE REQUESTED NUMBER OF RANDOM NUMBERS WAS ',   &
            'NON-POSITIVE.')
   15 FORMAT('***** ERROR: VALUE OF LAMBDA FOR SKEW DOUBLE ',   &
             'EXPONENTIAL RANDOM NUMBERS IS NEGATIVE.')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
   48 FORMAT('      VALUE OF ARGUMENT IS: ',G15.7)
!
!     USE PERCENT POINT TRANSFORMATION METHOD.
!
      CALL UNIRAN(N,ISEED,X)
!
      DO 100 I=1,N
        ATEMP=X(I)
        CALL SDEPPF(ATEMP,ALMBDA,APPF)
        X(I)=APPF
  100 CONTINUE
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE SDERAN
      SUBROUTINE SDMEAN(X,N,IWRITE,XSDM,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE
!              STANDARD DEVIATION OF THE MEAN (AVERAGE).
!              IT IS HERE COMPUTED AS THE RATIO OF THE
!              SAMPLE STANDARD DEVIATION (WITH DENOMINATOR N-1)
!              OF THE DATA IN THE INPUT VECTOR X,
!              DIVIDED BY THE SQUARE ROOT OF THE
!              NUMBER N OF OBSERVATIONS IN X.
!              THE SAMPLE STANDARD DEVIATION = SQRT((THE SUM OF THE
!              SQUARED DEVIATIONS ABOUT THE SAMPLE MEAN)/(N-1)).
!              THE STANDARD DEVIATION OF THE MEAN =
!              THE SAMPLE STANDARD DEVIATION / SQRT(N).
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XSDM   = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED STANDARD DEVIATION
!                                OF THE SAMPLE MEAN.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             STANDARD DEVIATION OF THE SAMPLE MEAN.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DSQRT.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--SNEDECOR AND COCHRAN, STATISTICAL METHODS,
!                 EDITION 6, 1967, PAGE 44.
!               --DIXON AND MASSEY, INTRODUCTION TO STATISTICAL
!                 ANALYSIS, EDITION 2, 1957, PAGES 19, 76.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--JANUARY   1978.
!     UPDATED         --JUNE      1979.
!     UPDATED         --JUNE      1979.
!     UPDATED         --AUGUST    1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DX
      DOUBLE PRECISION DSUM
      DOUBLE PRECISION DMEAN
      DOUBLE PRECISION DVAR
      DOUBLE PRECISION DSD
!
      DIMENSION X(*)
!
!-----COMMON---------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='SDME'
      ISUBN2='AN  '
      IERROR='NO'
!
      DMEAN=0.0D0
      DSD=0.0D0
!
      IF(IBUGA3.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF SDMEAN--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGA3
   52 FORMAT('IBUGA3 = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)N
   53 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 55 I=1,N
      WRITE(ICOUT,56)I,X(I)
   56 FORMAT('I,X(I) = ',I8,E15.7)
      CALL DPWRST('XXX','BUG ')
   55 CONTINUE
   90 CONTINUE
!
!               **********************************************
!               **  COMPUTE STANDARD DEVIATION OF THE MEAN  **
!               **********************************************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.GE.1)GO TO 119
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,111)
  111 FORMAT('***** ERROR IN SDMEAN--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,112)
  112 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,113)
  113 FORMAT('      IN THE VARIABLE FOR WHICH')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,114)
  114 FORMAT('      THE STANDARD DEVIATION OF THE MEAN IS TO BE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,115)
  115 FORMAT('      COMPUTED, MUST BE 1 OR LARGER.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,116)
  116 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,117)N
  117 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS HERE = ',I8,   &
      '.')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
  119 CONTINUE
!
      IF(N.EQ.1)GO TO 120
      GO TO 129
  120 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,121)
  121 FORMAT('***** NON-FATAL DIAGNOSTIC IN SDMEAN--',   &
      'THE 2ND INPUT ARGUMENT (N) HAS THE VALUE 1')
      CALL DPWRST('XXX','BUG ')
      XSDM=0.0
      GO TO 9000
  129 CONTINUE
!
      HOLD=X(1)
      DO 135 I=2,N
      IF(X(I).NE.HOLD)GO TO 139
  135 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,136)HOLD
  136 FORMAT('***** NON-FATAL DIAGNOSTIC IN SDMEAN--',   &
      'THE FIRST INPUT ARGUMENT (A VECTOR) HAS ALL ELEMENTS = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      XSDM=0.0
      GO TO 9000
  139 CONTINUE
!
!               ***************************************************
!               **  STEP 2--                                     **
!               **  COMPUTE THE STANDARD DEVIATION OF THE MEAN.  **
!               ***************************************************
!
      DN=N
      DSUM=0.0D0
      DO 200 I=1,N
      DX=X(I)
      DSUM=DSUM+DX
  200 CONTINUE
      DMEAN=DSUM/DN
!
      DSUM=0.0D0
      DO 300 I=1,N
      DX=X(I)
      DSUM=DSUM+(DX-DMEAN)**2
  300 CONTINUE
      DVAR=DSUM/(DN-1.0D0)
      DSD=0.0D0
      IF(DVAR.GT.0.0D0)DSD=DSQRT(DVAR)
      XSDM=DSD/DSQRT(DN)
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'OFF')GO TO 890
      IF(IWRITE.EQ.'OFF')GO TO 890
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,811)N,XSDM
  811 FORMAT('THE STANDARD DEVIATION OF THE MEAN BASED ON ',I8,   &
      ' OBSERVATIONS = ',E15.7)
      CALL DPWRST('XXX','BUG ')
  890 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF SDMEAN--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGA3,IERROR
 9012 FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)N
 9013 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9014)DMEAN,DSD
 9014 FORMAT('DMEAN,DSD = ',2D15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)XSDM
 9015 FORMAT('XSDM = ',E15.7)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE SDMEAN
      SUBROUTINE SDMLE(X,N,IWRITE,XSD,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE SAMPLE STANDARD DEVIATION
!              (WITH DENOMINATOR N) OF THE DATA IN THE INPUT VECTOR X.
!              THE SAMPLE STANDARD DEVIATION = SQRT((THE SUM OF THE
!              SQUARED DEVIATIONS ABOUT THE SAMPLE MEAN)/N).
!
!              NOTE THAT THIS IS SIMILAR TO SUBROUTINE SD.  THE
!              DISTINCTION IS THAT THIS ROUTINE USES N RATHER THAN
!              N-1 AS THE DIVISOR.  THIS IS THE MAXIMUM LIKELIHOOD
!              VERSION OF THE ESTIMATOR.  THIS WAS ADDED PRIMARILY
!              FOR INTERNAL USE (E.G., COEFFICIENT OF VARIATION
!              CONFIDENCE LIMITS MAY USE THIS).
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XSD    = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE STANDARD DEVIATION.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE STANDARD DEVIATION (WITH DENOMINATOR N-1).
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DSQRT.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2016.12
!     ORIGINAL VERSION--DECEMBER  2016.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DX
      DOUBLE PRECISION DSUM
      DOUBLE PRECISION DMEAN
      DOUBLE PRECISION DVAR
      DOUBLE PRECISION DSD
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='SDML'
      ISUBN2='E   '
      IERROR='NO'
!
      DMEAN=0.0D0
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF SDMLE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,N
   52   FORMAT('IBUGA3,N = ',A4,2X,I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               **********************************
!               **  COMPUTE STANDARD DEVIATION  **
!               **********************************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.LT.1)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN SD (MLE FORM)--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE RESPONSE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,115)
  115   FORMAT('      VARIABLE IS LESS THAN 1.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS HERE = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      XSD=0.0
      IF(N.EQ.1)GO TO 800
!
      HOLD=X(1)
      DO 135 I=2,N
        IF(X(I).NE.HOLD)GO TO 139
  135 CONTINUE
      GO TO 800
  139 CONTINUE
!
!               ***************************************
!               **  STEP 2--                         **
!               **  COMPUTE THE STANDARD DEVIATION.  **
!               ***************************************
!
      DN=N
      DSUM=0.0D0
      DO 200 I=1,N
        DX=X(I)
        DSUM=DSUM+DX
  200 CONTINUE
      DMEAN=DSUM/DN
!
      DSUM=0.0D0
      DO 300 I=1,N
        DX=X(I)
        DSUM=DSUM+(DX-DMEAN)**2
  300 CONTINUE
      DVAR=DSUM/DN
      DSD=0.0D0
      IF(DVAR.GT.0.0D0)DSD=DSQRT(DVAR)
      XSD=DSD
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
  800 CONTINUE
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)N,XSD
  811   FORMAT('THE STANDARD DEVIATION (MLE) OF THE ',I8,   &
               ' OBSERVATIONS = ',E15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF SD--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR,DMEAN,XSD
 9012   FORMAT('IERROR,DMEAN,XSD = ',A4,2X,2G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE SDMLE
      REAL FUNCTION SDOT(N,SX,INCX,SY,INCY)
!
!***BEGIN PROLOGUE  SDOT
!***DATE WRITTEN   791001   (YYMMDD)
!***REVISION DATE  820801   (YYMMDD)
!***CATEGORY NO.  D1A4
!***KEYWORDS  BLAS,INNER PRODUCT,LINEAR ALGEBRA,VECTOR
!***AUTHOR  LAWSON, C. L., (JPL)
!           HANSON, R. J., (SNLA)
!           KINCAID, D. R., (U. OF TEXAS)
!           KROGH, F. T., (JPL)
!***PURPOSE  S.P. inner product of s.p. vectors
!***DESCRIPTION
!
!                B L A S  Subprogram
!    Description of Parameters
!
!     --Input--
!        N  number of elements in input vector(s)
!       SX  single precision vector with N elements
!     INCX  storage spacing between elements of SX
!       SY  single precision vector with N elements
!     INCY  storage spacing between elements of SY
!
!     --Output--
!     SDOT  single precision dot product (zero if N .LE. 0)
!
!     where LX = 1 if INCX .GE. 0, else LX = (-INCX)*N, and LY is
!     defined in a similar way using INCY.
!***REFERENCES  LAWSON C.L., HANSON R.J., KINCAID D.R., KROGH F.T.,
!                 *BASIC LINEAR ALGEBRA SUBPROGRAMS FOR FORTRAN USAGE*,
!                 ALGORITHM NO. 539, TRANSACTIONS ON MATHEMATICAL
!                 SOFTWARE, VOLUME 5, NUMBER 3, SEPTEMBER 1979, 308-323
!***ROUTINES CALLED  (NONE)
!***END PROLOGUE  SDOT
!
      REAL SX(*),SY(*)
!***FIRST EXECUTABLE STATEMENT  SDOT
      SDOT = 0.0E0
      IF(N.LE.0)RETURN
!
!CCCC JUNE 2008: MODIFY FOLLOWING LINE SO THAT IT DOES NOT
!CCCC            GENERATE WARNING MESSAGE ON FORTRAN 95 COMPILERS.
!
!CCCC IF(INCX.EQ.INCY) IF(INCX-1)5,20,60
      IF(INCX.EQ.INCY) THEN
        IF(INCX-1.LT.0)THEN
          GO TO 5
        ELSEIF(INCX-1.EQ.0)THEN
          GO TO 20
        ELSE
          GO TO 60
        ENDIF
      ENDIF
    5 CONTINUE
!
!        CODE FOR UNEQUAL INCREMENTS OR NONPOSITIVE INCREMENTS.
!
      IX = 1
      IY = 1
      IF(INCX.LT.0)IX = (-N+1)*INCX + 1
      IF(INCY.LT.0)IY = (-N+1)*INCY + 1
      DO 10 I = 1,N
        SDOT = SDOT + SX(IX)*SY(IY)
        IX = IX + INCX
        IY = IY + INCY
   10 CONTINUE
      RETURN
!
!        CODE FOR BOTH INCREMENTS EQUAL TO 1
!
!
!        CLEAN-UP LOOP SO REMAINING VECTOR LENGTH IS A MULTIPLE OF 5.
!
   20 M = MOD(N,5)
      IF( M .EQ. 0 ) GO TO 40
      DO 30 I = 1,M
        SDOT = SDOT + SX(I)*SY(I)
   30 CONTINUE
      IF( N .LT. 5 ) RETURN
   40 MP1 = M + 1
      DO 50 I = MP1,N,5
        SDOT = SDOT + SX(I)*SY(I) + SX(I + 1)*SY(I + 1) +   &
         SX(I + 2)*SY(I + 2) + SX(I + 3)*SY(I + 3) + SX(I + 4)*SY(I + 4)
   50 CONTINUE
      RETURN
!
!        CODE FOR POSITIVE EQUAL INCREMENTS .NE.1.
!
   60 CONTINUE
      NS=N*INCX
      DO 70 I=1,NS,INCX
        SDOT = SDOT + SX(I)*SY(I)
   70   CONTINUE
      RETURN
      END FUNCTION SDOT
      REAL FUNCTION SDSDOT(N,X,INCX,Y,INCY,C)
!CCCC REAL FUNCTION SDSDOT(N,SB,SX,INCX,SY,INCY)
!CCCC OCTOBER 1993.  USE VERSION AS CODED IN LINPACK MANUAL
!***BEGIN PROLOGUE  SDSDOT
!***DATE WRITTEN   791001   (YYMMDD)
!***REVISION DATE  820801   (YYMMDD)
!***CATEGORY NO.  D1A4
!***KEYWORDS  BLAS,INNER PRODUCT,LINEAR ALGEBRA,VECTOR
!***AUTHOR  LAWSON, C. L., (JPL)
!           HANSON, R. J., (SNLA)
!           KINCAID, D. R., (U. OF TEXAS)
!           KROGH, F. T., (JPL)
!***PURPOSE  S.P. result with inner product accumulated in d.p.
!***DESCRIPTION
!
!                B L A S  Subprogram
!    Description of Parameters
!
!     --Input--
!        N  number of elements in input vector(s)
!        C  single precision scalar to be added to inner product
!        X  single precision vector with N elements
!     INCX  storage spacing between elements of SX
!        Y  single precision vector with N elements
!     INCY  storage spacing between elements of SY
!
!     --Output--
!   SDSDOT  single precision dot product (zero if N .LE. 0)
!
!     Returns S.P. result with dot product accumulated in D.P.
!     SDSDOT = SB + sum for I = 0 to N-1 of SX(LX+I*INCX)*SY(LY+I*INCY)
!     where LX = 1 if INCX .GE. 0, else LX = (-INCX)*N, and LY is
!     defined in a similar way using INCY.
!***REFERENCES  LAWSON C.L., HANSON R.J., KINCAID D.R., KROGH F.T.,
!                 *BASIC LINEAR ALGEBRA SUBPROGRAMS FOR FORTRAN USAGE*,
!                 ALGORITHM NO. 539, TRANSACTIONS ON MATHEMATICAL
!                 SOFTWARE, VOLUME 5, NUMBER 3, SEPTEMBER 1979, 308-323
!***ROUTINES CALLED  (NONE)
!***END PROLOGUE  SDSDOT
!
      REAL X(INCX,*),Y(INCY,*),C
      DOUBLE PRECISION SUM
!***FIRST EXECUTABLE STATEMENT  SDSDOT
      SUM = 0.0D0
      IF(N .LE. 0) GO TO 20
      DO 10 I = 1,N
        SUM = SUM + DBLE(X(1,I))*DBLE(Y(1,I))
   10 CONTINUE
   20 SUM = SUM + DBLE(C)
      SDSDOT = SNGL(SUM)
      RETURN
      END FUNCTION SDSDOT
      SUBROUTINE SECFAC(NR,N,X,G,A,XPLS,GPLS,EPSM,ITNCNT,RNF,   &
           IAGFLG,NOUPDT,S,Y,U,W)
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
! PURPOSE
! -------
! UPDATE HESSIAN BY THE BFGS FACTORED METHOD
!
! PARAMETERS
! ----------
! NR           --> ROW DIMENSION OF MATRIX
! N            --> DIMENSION OF PROBLEM
! X(N)         --> OLD ITERATE, X[K-1]
! G(N)         --> GRADIENT OR APPROXIMATE AT OLD ITERATE
! A(N,N)      <--> ON ENTRY: CHOLESKY DECOMPOSITION OF HESSIAN IN
!                    LOWER PART AND DIAGONAL.
!                  ON EXIT:  UPDATED CHOLESKY DECOMPOSITION OF HESSIAN
!                    IN LOWER TRIANGULAR PART AND DIAGONAL
! XPLS(N)      --> NEW ITERATE, X[K]
! GPLS(N)      --> GRADIENT OR APPROXIMATE AT NEW ITERATE
! EPSM         --> MACHINE EPSILON
! ITNCNT       --> ITERATION COUNT
! RNF          --> RELATIVE NOISE IN OPTIMIZATION FUNCTION FCN
! IAGFLG       --> =1 IF ANALYTIC GRADIENT SUPPLIED, =0 ITHERWISE
! NOUPDT      <--> BOOLEAN: NO UPDATE YET
!                  [RETAIN VALUE BETWEEN SUCCESSIVE CALLS]
! S(N)         --> WORKSPACE
! Y(N)         --> WORKSPACE
! U(N)         --> WORKSPACE
! W(N)         --> WORKSPACE
!
      DIMENSION X(*),XPLS(*),G(*),GPLS(*)
      DIMENSION A(NR,*)
      DIMENSION S(*),Y(*),U(*),W(*)
      LOGICAL NOUPDT,SKPUPD
!
      IF(ITNCNT.EQ.1) NOUPDT=.TRUE.
      DO 10 I=1,N
        S(I)=XPLS(I)-X(I)
        Y(I)=GPLS(I)-G(I)
   10 CONTINUE
      DEN1=DDOT(N,S,1,Y,1)
      SNORM2=DNRM2(N,S,1)
      YNRM2=DNRM2(N,Y,1)
      IF(DEN1.LT.SQRT(EPSM)*SNORM2*YNRM2) GO TO 110
!     IF(DEN1.GE.SQRT(EPSM)*SNORM2*YNRM2)
!     THEN
        CALL MVMLTU(NR,N,A,S,U)
        DEN2=DDOT(N,U,1,U,1)
!
!       L <-- SQRT(DEN1/DEN2)*L
!
        ALP=SQRT(DEN1/DEN2)
        IF(.NOT.NOUPDT) GO TO 50
!       IF(NOUPDT)
!       THEN
          DO 30 J=1,N
            U(J)=ALP*U(J)
            DO 20 I=J,N
              A(I,J)=ALP*A(I,J)
   20       CONTINUE
   30     CONTINUE
          NOUPDT=.FALSE.
          DEN2=DEN1
          ALP=1.0
!       ENDIF
   50   SKPUPD=.TRUE.
!
!       W = L(L+)S = HS
!
        CALL MVMLTL(NR,N,A,U,W)
        I=1
        IF(IAGFLG.NE.0) GO TO 55
!       IF(IAGFLG.EQ.0)
!       THEN
          RELTOL=SQRT(RNF)
          GO TO 60
!       ELSE
   55     RELTOL=RNF
!       ENDIF
   60   IF(I.GT.N .OR. .NOT.SKPUPD) GO TO 70
!       IF(I.LE.N .AND. SKPUPD)
!       THEN
          IF(ABS(Y(I)-W(I)) .LT. RELTOL*MAX(ABS(G(I)),ABS(GPLS(I))))   &
               GO TO 65
!         IF(ABS(Y(I)-W(I)) .GE. RELTOL*AMAX1(ABS(G(I)),ABS(GPLS(I))))
!         THEN
            SKPUPD=.FALSE.
            GO TO 60
!         ELSE
   65       I=I+1
            GO TO 60
!         ENDIF
!       ENDIF
   70   IF(SKPUPD) GO TO 110
!       IF(.NOT.SKPUPD)
!       THEN
!
!         W=Y-ALP*L(L+)S
!
          DO 75 I=1,N
            W(I)=Y(I)-ALP*W(I)
   75     CONTINUE
!
!         ALP=1/SQRT(DEN1*DEN2)
!
          ALP=ALP/DEN1
!
!         U=(L+)/SQRT(DEN1*DEN2) = (L+)S/SQRT((Y+)S * (S+)L(L+)S)
!
          DO 80 I=1,N
            U(I)=ALP*U(I)
   80     CONTINUE
!
!         COPY L INTO UPPER TRIANGULAR PART.  ZERO L.
!
          IF(N.EQ.1) GO TO 93
          DO 90 I=2,N
            IM1=I-1
            DO 85 J=1,IM1
              A(J,I)=A(I,J)
              A(I,J)=0.
   85       CONTINUE
   90     CONTINUE
!
!         FIND Q, (L+) SUCH THAT  Q(L+) = (L+) + U(W+)
!
   93     CALL QRUPDT(NR,N,A,U,W)
!
!         UPPER TRIANGULAR PART AND DIAGONAL OF A NOW CONTAIN UPDATED
!         CHOLESKY DECOMPOSITION OF HESSIAN.  COPY BACK TO LOWER
!         TRIANGULAR PART.
!
          IF(N.EQ.1) GO TO 110
          DO 100 I=2,N
            IM1=I-1
            DO 95 J=1,IM1
              A(I,J)=A(J,I)
   95       CONTINUE
  100     CONTINUE
!       ENDIF
!     ENDIF
  110 RETURN
      END SUBROUTINE SECFAC
      SUBROUTINE SECUNF(NR,N,X,G,A,UDIAG,XPLS,GPLS,EPSM,ITNCNT,   &
           RNF,IAGFLG,NOUPDT,S,Y,T)
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
! PURPOSE
! -------
! UPDATE HESSIAN BY THE BFGS UNFACTORED METHOD
!
! PARAMETERS
! ----------
! NR           --> ROW DIMENSION OF MATRIX
! N            --> DIMENSION OF PROBLEM
! X(N)         --> OLD ITERATE, X[K-1]
! G(N)         --> GRADIENT OR APPROXIMATE AT OLD ITERATE
! A(N,N)      <--> ON ENTRY: APPROXIMATE HESSIAN AT OLD ITERATE
!                    IN UPPER TRIANGULAR PART (AND UDIAG)
!                  ON EXIT:  UPDATED APPROX HESSIAN AT NEW ITERATE
!                    IN LOWER TRIANGULAR PART AND DIAGONAL
!                  [LOWER TRIANGULAR PART OF SYMMETRIC MATRIX]
! UDIAG        --> ON ENTRY: DIAGONAL OF HESSIAN
! XPLS(N)      --> NEW ITERATE, X[K]
! GPLS(N)      --> GRADIENT OR APPROXIMATE AT NEW ITERATE
! EPSM         --> MACHINE EPSILON
! ITNCNT       --> ITERATION COUNT
! RNF          --> RELATIVE NOISE IN OPTIMIZATION FUNCTION FCN
! IAGFLG       --> =1 IF ANALYTIC GRADIENT SUPPLIED, =0 OTHERWISE
! NOUPDT      <--> BOOLEAN: NO UPDATE YET
!                  [RETAIN VALUE BETWEEN SUCCESSIVE CALLS]
! S(N)         --> WORKSPACE
! Y(N)         --> WORKSPACE
! T(N)         --> WORKSPACE
!
      DIMENSION X(N),G(N),XPLS(N),GPLS(N)
      DIMENSION A(NR,1)
      DIMENSION UDIAG(N)
      DIMENSION S(N),Y(N),T(N)
      LOGICAL NOUPDT,SKPUPD
!
! COPY HESSIAN IN UPPER TRIANGULAR PART AND UDIAG TO
! LOWER TRIANGULAR PART AND DIAGONAL
!
      DO 5 J=1,N
        A(J,J)=UDIAG(J)
        IF(J.EQ.N) GO TO 5
        JP1=J+1
        DO 4 I=JP1,N
          A(I,J)=A(J,I)
    4   CONTINUE
    5 CONTINUE
!
      IF(ITNCNT.EQ.1) NOUPDT=.TRUE.
      DO 10 I=1,N
        S(I)=XPLS(I)-X(I)
        Y(I)=GPLS(I)-G(I)
   10 CONTINUE
      DEN1=DDOT(N,S,1,Y,1)
      SNORM2=DNRM2(N,S,1)
      YNRM2=DNRM2(N,Y,1)
      IF(DEN1.LT.SQRT(EPSM)*SNORM2*YNRM2) GO TO 100
!     IF(DEN1.GE.SQRT(EPSM)*SNORM2*YNRM2)
!     THEN
        CALL MVMLTS(NR,N,A,S,T)
        DEN2=DDOT(N,S,1,T,1)
        IF(.NOT. NOUPDT) GO TO 50
!       IF(NOUPDT)
!       THEN
!
!         H <-- [(S+)Y/(S+)HS]H
!
          GAM=DEN1/DEN2
          DEN2=GAM*DEN2
          DO 30 J=1,N
            T(J)=GAM*T(J)
            DO 20 I=J,N
              A(I,J)=GAM*A(I,J)
   20       CONTINUE
   30     CONTINUE
          NOUPDT=.FALSE.
!       ENDIF
   50   SKPUPD=.TRUE.
!
!       CHECK UPDATE CONDITION ON ROW I
!
        DO 60 I=1,N
          TOL=RNF*MAX(ABS(G(I)),ABS(GPLS(I)))
          IF(IAGFLG.EQ.0) TOL=TOL/SQRT(RNF)
          IF(ABS(Y(I)-T(I)).LT.TOL) GO TO 60
!         IF(ABS(Y(I)-T(I)).GE.TOL)
!         THEN
            SKPUPD=.FALSE.
            GO TO 70
!         ENDIF
   60   CONTINUE
   70   IF(SKPUPD) GO TO 100
!       IF(.NOT.SKPUPD)
!       THEN
!
!         BFGS UPDATE
!
          DO 90 J=1,N
            DO 80 I=J,N
              A(I,J)=A(I,J)+Y(I)*Y(J)/DEN1-T(I)*T(J)/DEN2
   80       CONTINUE
   90     CONTINUE
!       ENDIF
!     ENDIF
  100 RETURN
      END SUBROUTINE SECUNF
      SUBROUTINE SEMCDF(X,R,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE SEMI-CIRCULAR
!              DISTRIBUTION ON THE INTERVAL (-R,R).
!              THE CUMULATIVE DISTRIBUTION FUNCTION IS
!
!                  F(X;R) = 0.5 + X*SQRT(R**2-X**2)/(PI*R**2) +
!                           ARCSIN(X/R)/PI
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                     --R      = THE SINGLE PRECISION VALUE OF
!                                THE SHAPE PARAMETER (RADIUS)
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE BETWEEN -R AND R, INCLUSIVELY.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--SQRT, ATAN.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--XXXXX.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--NOVEMBER  1977.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --OCTOBER   2006. GENERALIZE TO CASE WHERE
!                                       RADIUS NOT EQUAL TO 1
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
      DATA PI/3.14159265359/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(R.LE.0.0)THEN
        WRITE(ICOUT,1)
    1   FORMAT('***** ERROR--THE SECOD INPUT ARGUMENT ',   &
               'TO SEMCDF IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)R
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9000
      ENDIF
      IF(X.LT.-R .OR. X.GT.R)THEN
        WRITE(ICOUT,2)
    2   FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT ',   &
               'TO SEMCDF IS OUTSIDE THE (-R,R) INTERVAL')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)R
   47   FORMAT('***** THE VALUE OF R            IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9000
      ENDIF
!
      IF(X.EQ.-R)THEN
        CDF=0.0
      ELSEIF(X.EQ.R)THEN
        CDF=1.0
      ELSE
        TERM1=0.5
        TERM2=X*SQRT(R**2 - X*X)/(PI*R**2)
        TERM3=ASIN(X/R)/PI
        CDF=TERM1 + TERM2 + TERM3
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE SEMCDF
      SUBROUTINE SEMPDF(X,R,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE SEMI-CIRCULAR
!              DISTRIBUTION ON THE INTERVAL (-R,R).
!              THIS DISTRIBUTION HAS MEAN = 0.0
!              AND STANDARD DEVIATION = SQRT(R**2/4)
!              THIS DISTRIBUTION HAS THE PROBABILITY
!              DENSITY FUNCTION
!
!                  F(X;R) = 2*SQRT(R**2-X**2)/(PI*R**2)
!
!              (A SEMI-CIRCLE FOR R=1, AN ELLIPSE OTHERWISE).
!              THIS DISTRIBUTION IS IMPORTANT IN THAT IT IS
!              THE DISTRIBUTION ONTO ONE AXIS
!              OF POINTS WHICH ARE UNIFORMLY
!              DISTRIBUTED WITHIN A CIRCLE OF UNIT RADIUS.
!              IT IS USEFUL IN TESTING FOR
!              2-DIMENSIONAL UNIFORMITY.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                     --R      = THE SINGLE PRECISION VALUE THAT
!                                DEFINES THE RADIUS
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE BETWEEN -R AND R, INCLUSIVELY.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--SQRT
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--XXXXX.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--94.4
!     ORIGINAL VERSION--APRIL     1994
!     UPDATED         --OCTOBER   2006. GENERALIZE TO CASES WHERE
!                                       R NOT EQUAL TO 1.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
      DATA PI/3.14159265359/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(R.LE.0.0)THEN
        WRITE(ICOUT,1)
    1   FORMAT('***** ERROR--THE SECOD INPUT ARGUMENT ',   &
               'TO SEMPDF IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)R
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9000
      ENDIF
      IF(X.LT.-R .OR. X.GT.R)THEN
        WRITE(ICOUT,2)
    2   FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT ',   &
               'TO SEMPDF IS OUTSIDE THE (-R,R) INTERVAL')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)R
   47   FORMAT('***** THE VALUE OF R            IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9000
      ENDIF
!
      IF(X.EQ.-R)THEN
        PDF=0.0
      ELSEIF(X.EQ.R)THEN
        PDF=0.0
      ELSE
        PDF=2.0*SQRT(R**2 - X*X)/(R**2*PI)
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE SEMPDF
      SUBROUTINE SEMPPF(P,R,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE SEMI-CIRCULAR
!              DISTRIBUTION ON THE INTERVAL (-R,R).
!              THIS DISTRIBUTION HAS MEAN = 0.0
!              AND STANDARD DEVIATION = SQRT(R**2/4)
!              THIS DISTRIBUTION HAS THE PROBABILITY
!              DENSITY FUNCTION
!
!                  F(X;R) = 2*SQRT(R**2-X**2)/(PI*R**2)
!
!              (A SEMI-CIRCLE FOR R=1, AN ELLIPSE OTHERWISE).
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                (BETWEEN 0.0 AND 1.0)
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --R      = THE SINGLE PRECISION VALUE THAT
!                                DEFINES THE RADIUS
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT
!                                POINT FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT
!             FUNCTION VALUE PPF.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--P SHOULD BE BETWEEN 0.0 AND 1.0, INCLUSIVELY.
!     OTHER DATAPAC   SUBROUTINES NEEDED--SEMCDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--ABS.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--FILLIBEN, SIMPLE AND ROBUST LINEAR ESTIMATION
!                 OF THE LOCATION PARAMETER OF A SYMMETRIC
!                 DISTRIBUTION (UNPUBLISHED PH.D. DISSERTATION,
!                 PRINCETON UNIVERSITY), 1969, PAGES 21-44, 229-231.
!               --FILLIBEN, 'THE PERCENT POINT FUNCTION',
!                 (UNPUBLISHED MANUSCRIPT), 1970, PAGES 28-31.
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 1970, PAGES 57-74.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--DECEMBER  1977.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --OCTOBER   2006. GENERALIZE TO THE CASE
!                                       WHERE R NOT EQUAL TO 1
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(P.LT.0.0 .OR. P.GT.1.0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    1 FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT TO ',   &
             'SEMPPF IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
      IF(R.LE.0.0)THEN
        WRITE(ICOUT,2)
    2   FORMAT('***** ERROR--THE SECOD INPUT ARGUMENT ',   &
               'TO SEMPDF IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)R
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9000
      ENDIF
!
      PHOLD=P
      IF(PHOLD.EQ.0.0)THEN
        PPF=-R
      ELSEIF(PHOLD.EQ.1.0)THEN
        PPF=R
      ELSE
        CONTINUE
        TOL=0.000001
        MAXIT=100
!
        XMIN=-R
        XMAX=R
!
        XMID=(XMIN+XMAX)/2.0
        XLOW=XMIN
        XUP=XMAX
        ICOUNT=0
!
  210   CONTINUE
        X=XMID
        CALL SEMCDF(X,R,PCALC)
        IF(PCALC.EQ.PHOLD)GO TO 240
        IF(PCALC.GT.PHOLD)GO TO 220
!
        XLOW=XMID
        XMID=(XMID+XUP)/2.0
        GO TO 230
!
  220   CONTINUE
        XUP=XMID
        XMID=(XMID+XLOW)/2.0
!
  230   CONTINUE
        XDEL=ABS(XMID-XLOW)
        ICOUNT=ICOUNT+1
        IF(XDEL.LT.TOL.OR.ICOUNT.GT.MAXIT)GO TO 240
        GO TO 210
!
  240   CONTINUE
        PPF=XMID
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE SEMPPF
      SUBROUTINE SEMRAN(N,R,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE SEMI-CIRCULAR DISTRIBUTION.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --R      = THE SINGLE PRECISION VALUE THAT
!                                DEFINES THE RADIUS
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE SEMI-CIRCULAR DISTRIBUTION
!             WITH MEAN = 0 AND STANDARD DEVIATION = ZZZ
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, SEMPPF
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--TOCHER, THE ART OF SIMULATION,
!                 1963, PAGES 14-15.
!               --HAMMERSLEY AND HANDSCOMB, MONTE CARLO METHODS,
!                 1964, PAGE 36.
!               --FILLIBEN, SIMPLE AND ROBUST LINEAR ESTIMATION
!                 OF THE LOCATION PARAMETER OF A SYMMETRIC
!                 DISTRIBUTION (UNPUBLISHED PH.D. DISSERTATION,
!                 PRINCETON UNIVERSITY), 1969, PAGE 230.
!               --FILLIBEN, 'THE PERCENT POINT FUNCTION',
!                 (UNPUBLISHED MANUSCRIPT), 1970, PAGES 28-31.
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 1970, PAGES ZZZ.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--JUNE      1978.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --OCTOBER   2006. GENERALIZE TO CASES WHERE
!                                       R NOT EQUAL TO 1.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR--THE REQUESTED NUMBER OF SEMI-CIRCULAR ',   &
             'RANDOM NUMBERS IS NON-POSITIVE')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
!
      IF(R.LE.0.0)THEN
        WRITE(ICOUT,8)
    8   FORMAT('***** ERROR--THE SHAPE PARAMETER, R, FOR THE ',   &
             'SEMI-CIRCULAR RANDOM NUMBERS IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)R
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N SEMI-CIRCULAR RANDOM NUMBERS
!     USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      DO 100 I=1,N
      CALL SEMPPF(X(I),R,ATEMP)
      X(I)=ATEMP
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE SEMRAN
      SUBROUTINE SENSIT(X,Y,N,IWRITE,XIDTEM,STAT,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE TEST SENSITIVITY
!              BETWEEN TWO VARIABLES.
!
!              THIS IS SPECIFICALLY FOR THE 2X2 CASE.  THAT IS,
!              EACH VARIABLE HAS TWO MUTUALLY EXCLUSIVE
!              CHOICES CODED AS 1 (FOR SUCCESS) OR 0 (FOR
!              FAILURE).  TEST SENSITIVITY IS DEFINED AS THE
!              CONDITIONAL PROBABILITY OF A POSITIVE TEST GiVEN
!              THAT THE DISEASE IS PRESENT.
!
!              A TYPICAL EXAMPLE WOULD BE WHERE VARIABLE ONE
!              DENOTES THE GROUND TRUTH AND A VALUE OF 1
!              INDICATES "PRESENT" AND A VALUE OF 0 INDICATES
!              "NOT PRESENT".  VARIABLE TWO REPRESENTS SOME TYPE
!              OF DETECTION DEVICE WHERE A VALUE OF 1 INDICATES
!              THE DEVICE DETECTED THE SPECIFIED OBJECT WHILE A
!              VALUE OF 0 INDICATES THAT THE OBJECT WAS NOT
!              DETECTED.  TEST SENSITIVITY IS THEN DEFINED AS
!              THE PROBABILITY OF DETECTING THE OBJECT GIVEN
!              THAT THE OBJECT IS ACTUALLY THERE.
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED) OBSERVATIONS
!                                WHICH CONSTITUTE THE FIRST SET
!                                OF DATA.
!                     --Y      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED) OBSERVATIONS
!                                WHICH CONSTITUTE THE SECOND SET
!                                OF DATA.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X, OR EQUIVALENTLY,
!                                THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR Y.
!     OUTPUT ARGUMENTS--STAT   = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED TEST SENSITIVITY
!                                BETWEEN THE 2 SETS OF DATA
!                                IN THE INPUT VECTORS X AND Y.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE TEST SENSITIVITY BETWEEN THE 2 SETS
!             OF DATA IN THE INPUT VECTORS X AND Y.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTIUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/3
!     ORIGINAL VERSION--MARCH     2007.
!     UPDATED         --AUGUST    2007. IF 2X2 CASE, CHECK IF SUM
!                                       OF ENTRIES IS <= 4.  IN THIS
!                                       CASE, ASSUME WE HAVE RAW DATA
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISTEPN
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(*)
      DIMENSION XIDTEM(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='SENS'
      ISUBN2='IT  '
      IERROR='NO'
!
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF SENSIT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3
   52   FORMAT('IBUGA3 = ',A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)N
   53   FORMAT('N = ',I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I),Y(I)
   56     FORMAT('I,X(I),Y(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 21--                             **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='21'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(N.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1201)
 1201   FORMAT('***** ERROR IN THE TEST SENSITIVITY')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1203)
 1203   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE RESPONSE ',   &
               'VARIABLES IS LESS THAN TWO')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1205)N
 1205   FORMAT('SAMPLE SIZE = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ********************************************
!               **  STEP 22--                             **
!               **  CHECK THAT THE VARIABLES HAVE AT MOST **
!               **  TWO DISTINCT VALUES (1 INDICATES A    **
!               **  SUCCESS, 0 INDICATES A FAILURE).      **
!               ********************************************
!
      ISTEPN='22'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     NOTE: CHECK FOR SPECIAL CASE N = 2.  IN THIS CASE,
!           ASSUME WE HAVE A 2X2 TABLE OF COUNTS INSTEAD
!           OF RAW DATA.
!
      IF(N.EQ.2)THEN
        N11=INT(X(1)+0.5)
        N21=INT(X(2)+0.5)
        N12=INT(Y(1)+0.5)
        N22=INT(Y(2)+0.5)
!
!       CHECK IF ALL ENTRIES 0 OR 1. IF SO, ASSUME
!       RAW DATA CASE.
!
        IF((N11.EQ.0 .OR. N11.EQ.1) .AND.   &
           (N12.EQ.0 .OR. N12.EQ.1) .AND.   &
           (N21.EQ.0 .OR. N21.EQ.1) .AND.   &
           (N22.EQ.0 .OR. N22.EQ.1)) GO TO 1349
!
        IF(N11.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1311)
 1311     FORMAT('      ROW 1 COLUMN 1 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(N21.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1321)
 1321     FORMAT('      ROW 2 COLUMN 1 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(N12.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1331)
 1331     FORMAT('      ROW 1 COLUMN 2 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(N22.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1341)
 1341     FORMAT('      ROW 2 COLUMN 2 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        AN11=REAL(N11)
        AN21=REAL(N21)
        AN12=REAL(N12)
        AN22=REAL(N22)
        STAT=AN11/(AN11+AN12)
        GO TO 3000
      ENDIF
!
 1349 CONTINUE
!
      CALL DISTIN(X,N,IWRITE,XIDTEM,NDIST,IBUGA3,IERROR)
      IF(NDIST.EQ.1)THEN
        AVAL=XIDTEM(1)
        IF(ABS(AVAL).LE.0.5)THEN
          AVAL=0.0
        ELSE
          AVAL=1.0
        ENDIF
        DO 2202 I=1,N
          X(I)=1.0
 2202   CONTINUE
      ELSEIF(NDIST.EQ.2)THEN
        IF(XIDTEM(1).EQ.1.0 .OR. XIDTEM(2).EQ.1.0)THEN
          DO 2203 I=1,N
            IF(X(I).NE.1.0)X(I)=0.0
 2203     CONTINUE
        ELSE
          ATEMP1=MIN(XIDTEM(1),XIDTEM(2))
          ATEMP2=MAX(XIDTEM(1),XIDTEM(2))
          DO 2208 I=1,N
            IF(X(I).EQ.ATEMP1)X(I)=0.0
            IF(X(I).EQ.ATEMP2)X(I)=1.0
 2208     CONTINUE
        ENDIF
      ELSE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1201)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2211)
 2211   FORMAT('      RESPONSE VARIABLE ONE SHOULD CONTAIN AT MOST')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2213)
 2213   FORMAT('      TWO DISTINCT VALUES.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2215)NDIST
 2215   FORMAT('      ',I8,' DISTINCT VALUES FOUND.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      CALL DISTIN(Y,N,IWRITE,XIDTEM,NDIST,IBUGA3,IERROR)
      IF(NDIST.EQ.1)THEN
        AVAL=XIDTEM(1)
        IF(ABS(AVAL).LE.0.5)THEN
          AVAL=0.0
        ELSE
          AVAL=1.0
        ENDIF
        DO 2302 I=1,N
          Y(I)=1.0
 2302   CONTINUE
      ELSEIF(NDIST.EQ.2)THEN
        IF(XIDTEM(1).EQ.1.0 .OR. XIDTEM(2).EQ.1.0)THEN
          DO 2303 I=1,N
            IF(Y(I).NE.1.0)Y(I)=0.0
 2303     CONTINUE
        ELSE
          ATEMP1=MIN(XIDTEM(1),XIDTEM(2))
          ATEMP2=MAX(XIDTEM(1),XIDTEM(2))
          DO 2308 I=1,N
            IF(Y(I).EQ.ATEMP1)Y(I)=0.0
            IF(Y(I).EQ.ATEMP2)Y(I)=1.0
 2308     CONTINUE
        ENDIF
      ELSE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1201)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2311)
 2311   FORMAT('      RESPONSE VARIABLE TWO SHOULD CONTAIN AT MOST')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2313)
 2313   FORMAT('      TWO DISTINCT VALUES.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2315)NDIST
 2315   FORMAT('      ',I8,' DISTINCT VALUES FOUND.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      N11=0
      N12=0
      N21=0
      N22=0
      DO 2410 I=1,N
        IF(X(I).EQ.1.0 .AND. Y(I).EQ.1.0)THEN
          N11=N11+1
        ELSEIF(X(I).EQ.0.0 .AND. Y(I).EQ.0.0)THEN
          N22=N22+1
        ELSEIF(X(I).EQ.1.0 .AND. Y(I).EQ.0.0)THEN
          N12=N12+1
        ELSEIF(X(I).EQ.0.0 .AND. Y(I).EQ.1.0)THEN
          N21=N21+1
        ENDIF
 2410 CONTINUE
!
      STAT=REAL(N11)/REAL(N11+N12)
!
 3000 CONTINUE
!
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'OFF')GO TO 890
      IF(IWRITE.EQ.'OFF' .OR. IWRITE.EQ.'NO')GO TO 890
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,811)STAT
  811 FORMAT('THE TEST SENSITIVITY PROPORTION = ',G15.7)
      CALL DPWRST('XXX','BUG ')
  890 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END OF SENSIT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA3,IERROR
 9012   FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)N,N11,N12,N21,N22
 9013   FORMAT('N,N11,N12,N21,N22 = ',5I10)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)STAT
 9015   FORMAT('STAT = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE SENSIT
      SUBROUTINE SEQDIF(X,NX,IWRITE,Y,NY,ISTAT,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--COMPUTE SEQUENTIAL DIFFERENCE OF A VARIABLE--
!              Y(1) = X(2)-X(1)
!              Y(2) = X(3)-X(2)
!              Y(3) = X(4)-X(3)
!              ETC.
!     NOTE--CODE UPDATED TO ALSO ALLOW
!              SEQUENTIAL MEAN
!              SEQUENTIAL SUM
!              SEQUENTIAL MINIMUM
!              SEQUENTIAL MAXIMUM
!              SEQUENTIAL PRODUCT
!              SEQUENTIAL LOWER
!              SEQUENTIAL UPPER
!     NOTE--IT IS PERMISSIBLE TO HAVE THE OUTPUT VECTOR Y(.)
!           BEING IDENTICAL TO THE INPUT VECTOR X(.).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--FEBRUARY  1979.
!     UPDATED         --APRIL     1979.
!     UPDATED         --JULY      1979.
!     UPDATED         --AUGUST    1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --FEBRUARY  2016. SUPPORT FOR MEAN, SUM, PRODUCT,
!                                       MIN, AND MAX CASES
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ISTAT
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='SEQD'
      ISUBN2='IF  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'QDIF')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF SEQDIF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,IWRITE,ISTAT,NX
   52   FORMAT('IBUGA3,IWRITE,ISTAT,NX = ',3(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,NX
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               **************************************
!               **  COMPUTE SEQUENTIAL DIFFERENCE.  **
!               **************************************
!
      NXM1=NX-1
      IF(NXM1.LT.1)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,151)
  151   FORMAT('***** ERROR IN SEQUENTIAL DIFFERENCE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,152)
  152   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE RESPONSE ',   &
               'VARIABLE IS LESS THAN 2.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,157)NX
  157   FORMAT('      THE NUMBER OF OBSERVATIONS = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
      ELSE
        IF(ISTAT.EQ.'MEAN')THEN
          DO 110 I=1,NXM1
            IP1=I+1
            Y(I)=(X(IP1)+X(I))/2.0
  110     CONTINUE
          NY=NXM1
        ELSEIF(ISTAT.EQ.'MINI')THEN
          DO 120 I=1,NXM1
            IP1=I+1
            Y(I)=MIN(X(IP1),X(I))
  120     CONTINUE
          NY=NXM1
        ELSEIF(ISTAT.EQ.'MAXI')THEN
          DO 130 I=1,NXM1
            IP1=I+1
            Y(I)=MAX(X(IP1),X(I))
  130     CONTINUE
          NY=NXM1
        ELSEIF(ISTAT.EQ.'SUM ')THEN
          DO 140 I=1,NXM1
            IP1=I+1
            Y(I)=X(IP1)+X(I)
  140     CONTINUE
          NY=NXM1
        ELSEIF(ISTAT.EQ.'PROD')THEN
          DO 150 I=1,NXM1
            IP1=I+1
            Y(I)=X(IP1)*X(I)
  150     CONTINUE
          NY=NXM1
        ELSEIF(ISTAT.EQ.'LOWE')THEN
          DO 160 I=1,NXM1
            Y(I)=X(I)
  160     CONTINUE
          NY=NXM1
        ELSEIF(ISTAT.EQ.'UPPE')THEN
          DO 170 I=1,NXM1
            IP1=I+1
            Y(I)=X(IP1)
  170     CONTINUE
          NY=NXM1
        ELSE
          DO 100 I=1,NXM1
            IP1=I+1
            Y(I)=X(IP1)-X(I)
  100     CONTINUE
          NY=NXM1
        ENDIF
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'QDIF')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF SEQDIF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)IERROR,NX,NY
 9013   FORMAT('IERROR,NX,NY = ',A4,2X,2I8)
        CALL DPWRST('XXX','BUG ')
        DO 9015 I=1,NX
          WRITE(ICOUT,9016)I,X(I),Y(I)
 9016     FORMAT('I,X(I),Y(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
 9015   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE SEQDIF
      SUBROUTINE SEQDI2(X,XGROUP,NX,IWRITE,Y,YGROUP,NY,ISTAT,   &
                        XDIST,XTEMP,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS IS A VARIANT OF THE SEQDIF (SEQUENTIAL DIFFERENCE)
!              ROUTINE.  THE DISTINCTION IS THAT THIS ROUTINE INCLUDES
!              A GROUP-ID VARIABLE.  THAT IS, THE SEQUENTIAL DIFFERENCE
!              WILL BE COMPUTED WITHIN EACH GROUP.  NOTE THAT ALTHOUGH
!              THE DATA DO NOT NEED TO BE PRE-SORTED BY GROUP, THE ORDER
!              WITHIN A GROUP WILL BE MAINTAINED.  THE COMMAND IS
!
!                  LET Y YGROUP = SEQUENTIAL DIFFERENCE X XGROUP
!
!     NOTE--CODE ALSO SUPPORTS THE FOLLOWING
!              SEQUENTIAL MEAN
!              SEQUENTIAL SUM
!              SEQUENTIAL MINIMUM
!              SEQUENTIAL MAXIMUM
!              SEQUENTIAL PRODUCT
!              SEQUENTIAL LOWER
!              SEQUENTIAL UPPER
!     NOTE--IT IS PERMISSIBLE TO HAVE THE OUTPUT VECTOR Y(.)
!           BEING IDENTICAL TO THE INPUT VECTOR X(.).
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2016.02
!     ORIGINAL VERSION--FEBRUARY  2016.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ISTAT
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION XGROUP(*)
      DIMENSION Y(*)
      DIMENSION YGROUP(*)
      DIMENSION XDIST(*)
      DIMENSION XTEMP(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='SEQD'
      ISUBN2='I2  '
      IERROR='NO'
!
      NY=0
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'QDI2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF SEQDI2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISTAT,NX
   52   FORMAT('IBUGA3,ISTAT,NX = ',2(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,NX
          WRITE(ICOUT,56)I,XGROUP(I),X(I)
   56     FORMAT('I,XGROUP(I),X(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               **************************************
!               **  COMPUTE SEQUENTIAL DIFFERENCE.  **
!               **************************************
!
      IF(NX.LT.2)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,151)
  151   FORMAT('***** ERROR IN GROUP SEQUENTIAL DIFFERENCE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,152)
  152   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE RESPONSE ',   &
               'VARIABLE IS LESS THAN 2.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,157)NX
  157   FORMAT('      THE NUMBER OF OBSERVATIONS = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
      ELSE
!
!       DETERMINE THE DISTINCT GROUPS
!
        CALL DISTIN(XGROUP,NX,IWRITE,XDIST,NXDIST,IBUGA3,IERROR)
        IF(NX.EQ.NXDIST)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,151)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,201)
  201     FORMAT('      THE NUMBER OF OBSERVATIONS IS EQUAL TO THE ',   &
                 'NUMBER OF GROUPS.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,203)
  203     FORMAT('      NOTHING DONE.')
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
!
        DO 300 K=1,NXDIST
          NTEMP=0
          HOLD=XDIST(K)
          DO 301 J=1,NX
            IF(XGROUP(J).EQ.HOLD)THEN
              NTEMP=NTEMP+1
              XTEMP(NTEMP)=X(J)
            ENDIF
  301     CONTINUE
!
          NXM1=NTEMP-1
          IF(NXM1.GE.1)THEN
            IF(ISTAT.EQ.'MEAN')THEN
              DO 410 I=1,NXM1
                IP1=I+1
                NY=NY+1
                Y(NY)=(XTEMP(IP1)+XTEMP(I))/2.0
                YGROUP(NY)=REAL(K)
  410         CONTINUE
            ELSEIF(ISTAT.EQ.'MINI')THEN
              DO 420 I=1,NXM1
                IP1=I+1
                NY=NY+1
                Y(NY)=MIN(XTEMP(IP1),XTEMP(I))
                YGROUP(NY)=REAL(K)
  420         CONTINUE
            ELSEIF(ISTAT.EQ.'MAXI')THEN
              DO 430 I=1,NXM1
                IP1=I+1
                NY=NY+1
                Y(NY)=MAX(XTEMP(IP1),XTEMP(I))
                YGROUP(NY)=REAL(K)
  430         CONTINUE
            ELSEIF(ISTAT.EQ.'SUM ')THEN
              DO 440 I=1,NXM1
                IP1=I+1
                NY=NY+1
                Y(NY)=XTEMP(IP1)+XTEMP(I)
                YGROUP(NY)=REAL(K)
  440         CONTINUE
            ELSEIF(ISTAT.EQ.'PROD')THEN
              DO 450 I=1,NXM1
                IP1=I+1
                NY=NY+1
                Y(NY)=XTEMP(IP1)*XTEMP(I)
                YGROUP(NY)=REAL(K)
  450         CONTINUE
            ELSEIF(ISTAT.EQ.'DIFF')THEN
              DO 460 I=1,NXM1
                IP1=I+1
                NY=NY+1
                Y(NY)=XTEMP(IP1)-XTEMP(I)
                YGROUP(NY)=REAL(K)
  460         CONTINUE
            ELSEIF(ISTAT.EQ.'LOWE')THEN
              DO 470 I=1,NXM1
                IP1=I+1
                NY=NY+1
                Y(NY)=XTEMP(I)
                YGROUP(NY)=REAL(K)
  470         CONTINUE
            ELSEIF(ISTAT.EQ.'UPPE')THEN
              DO 480 I=1,NXM1
                IP1=I+1
                NY=NY+1
                Y(NY)=XTEMP(IP1)
                YGROUP(NY)=REAL(K)
  480         CONTINUE
            ENDIF
          ENDIF
  300   CONTINUE
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'QDI2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF SEQDI2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)IERROR,NX,NY
 9013   FORMAT('IERROR,NX,NY = ',A4,2X,2I8)
        CALL DPWRST('XXX','BUG ')
        DO 9015 I=1,NY
          WRITE(ICOUT,9016)I,YGROUP(I),Y(I)
 9016     FORMAT('I,YGROUP(I),Y(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
 9015   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE SEQDI2
      SUBROUTINE SETARI(Y1,Y2,N1,N2,IACASE,IWRITE,   &
                        Y3,Y4,N3,SCAL3,ITYP3,   &
                        Y1HOLD,Y2HOLD,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--CARRY OUT SET        ARITHMETIC OPERATIONS
!              OF THE REAL DATA IN Y1 AND Y2.
!
!     OPERATIONS--UNION
!                 INTERSECTION
!                 COMPLEMENT
!                 CARDINALITY
!                 CARTESIAN PRODUCT
!                 ELEMENTS (DISTINCT)
!
!     INPUT  ARGUMENTS--Y1 (REAL)
!                     --Y2 (REAL)
!     OUTPUT ARGUMENTS--Y3 (REAL)
!                       SCAL3
!                       ITYP3
!                     --Y4 (REAL)
!
!     NOTE--IT IS NOT PERMISSIBLE TO HAVE THE OUTPUT SETS Y3(.) & Y4(.)
!           BEING IDENTICAL TO THE INPUT SETS   Y1(.) OR Y2(.).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--87/9
!     ORIGINAL VERSION--AUGUST   1987.
!     UPDATED         --JUNE      1990. TEMPORARY ARRAYS TO GARBAGE COMMON
!     UPDATED         --SEPTEMBER 1993. FIX CARTESIAN PRODUCT (ALAN)
!     UPDATED         --JULY      2019. MOVE CREATION OF SCRATCH
!                                       STORAGE TO CALLING ROUTINE
!                                       SOME RECODING FOR BETTER
!                                       READABILITY (BUT NO SUBSTANATIVE
!                                       CHANGE)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IACASE
      CHARACTER*4 IWRITE
      CHARACTER*4 ITYP3
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
!
      DIMENSION Y1(*)
      DIMENSION Y2(*)
      DIMENSION Y3(*)
      DIMENSION Y4(*)
      DIMENSION Y1HOLD(*)
      DIMENSION Y2HOLD(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='SETA'
      ISUBN2='RI  '
      IERROR='NO'
      SCAL3=(-999.0)
      ITYP3='VECT'
!
      TOL=0.00001
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'TARI')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF SETARI--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,IACASE,IWRITE,N1
   52   FORMAT('IBUGA3,ISUBRO,IACASE,IWRITE,N1 = ',4(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N1
          WRITE(ICOUT,56)I,Y1(I),Y2(I)
   56     FORMAT('I,Y1(I),Y2(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               **************************************************
!               **  CARRY OUT SET        ARITHMETIC OPERATIONS  **
!               **************************************************
!
!               ********************************************
!               **  STEP 11--                             **
!               **  CHECK NUMBER OF INPUT OBSERVATIONS.   **
!               ********************************************
!
      IF(N1.LT.1 .OR. N2.LT.1)THEN
        IF(N1.GT.1 .AND.   &
          (IACASE.EQ.'SECA' .OR. IACASE.EQ.'SEEL'))GO TO 1190
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1151)
 1151   FORMAT('***** ERROR IN SET ARITHMETIC (SETARI)--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1152)
 1152   FORMAT('      THE NUMBER OF OBSERVATIONS IN THE VARIABLE ',   &
               'FOR WHICH')
        CALL DPWRST('XXX','BUG ')
        IF(IACASE.EQ.'SEUN')THEN
          WRITE(ICOUT,1161)
 1161     FORMAT('      THE  SET UNION  IS TO BE COMPUTED')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(IACASE.EQ.'SEIN')THEN
          WRITE(ICOUT,1162)
 1162     FORMAT('      THE  SET INTERSECTION  IS TO BE COMPUTED')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(IACASE.EQ.'SECO')THEN
          WRITE(ICOUT,1163)
 1163     FORMAT('      THE  SET COMPLEMENT  IS TO BE COMPUTED')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(IACASE.EQ.'SECA')THEN
          WRITE(ICOUT,1164)
 1164     FORMAT('      THE  SET CARDINALITY  IS TO BE COMPUTED')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(IACASE.EQ.'SECP')THEN
          WRITE(ICOUT,1165)
 1165     FORMAT('      THE  SET CARTESIAN PRODUCT  IS TO BE COMPUTED')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(IACASE.EQ.'SEEL')THEN
          WRITE(ICOUT,1166)
 1166     FORMAT('      THE  SET ELEMENTS  IS TO BE COMPUTED')
          CALL DPWRST('XXX','BUG ')
        ENDIF
        WRITE(ICOUT,1181)
 1181   FORMAT('      MUST BE 1 OR LARGER.  SUCH WAS NOT THE ',   &
               'CASE HERE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1183)N1
 1183   FORMAT('      THE NUMBER OF OBSERVATIONS = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
 1190 CONTINUE
!
!               *********************************
!               **  STEP 12--                  **
!               **  BRANCH TO THE PROPER CASE  **
!               *********************************
!
      IF(IACASE.EQ.'SEUN')THEN
!
!               *********************************************
!               **  STEP 21--                              **
!               **  TREAT THE SET        UNION       CASE  **
!               *********************************************
!
        K=1
        Y3(K)=Y1(K)
!
        IF(N1.GT.1)THEN
          DO 2110 I=1,N1
            TARGET=Y1(I)
            DO 2120 J=1,K
              Y3JL=Y3(J)-TOL
              Y3JU=Y3(J)+TOL
              IF(Y3JL.LE.TARGET.AND.TARGET.LE.Y3JU)GO TO 2110
 2120       CONTINUE
            K=K+1
            Y3(K)=TARGET
 2110     CONTINUE
        ENDIF
!
        DO 2130 I=1,N2
          TARGET=Y2(I)
          DO 2140 J=1,K
            Y3JL=Y3(J)-TOL
            Y3JU=Y3(J)+TOL
            IF(Y3JL.LE.TARGET.AND.TARGET.LE.Y3JU)GO TO 2130
 2140     CONTINUE
          K=K+1
          Y3(K)=TARGET
 2130   CONTINUE
!
        ITYP3='VECT'
        N3=K
      ELSEIF(IACASE.EQ.'SEIN')THEN
!
!               *********************************************
!               **  STEP 22--                              **
!               **  TREAT THE SET        INTERSECTION CASE **
!               *********************************************
!
        K=0
!
        DO 2210 I=1,N1
          TARGET=Y1(I)
          DO 2220 J=1,N2
            Y2JL=Y2(J)-TOL
            Y2JU=Y2(J)+TOL
            IF(Y2JL.LE.TARGET.AND.TARGET.LE.Y2JU)GO TO 2215
 2220     CONTINUE
          GO TO 2210
 2215     CONTINUE
          K=K+1
          Y3(K)=TARGET
 2210   CONTINUE
!
        ITYP3='VECT'
        N3=K
      ELSEIF(IACASE.EQ.'SECO')THEN
!
!               ************************************************
!               **  STEP 23--                                 **
!               **  TREAT THE SET        COMPLEMENT     CASE  **
!               ************************************************
!
        K=0
!
        DO 2310 I=1,N2
          TARGET=Y2(I)
          DO 2320 J=1,N1
            Y1JL=Y1(J)-TOL
            Y1JU=Y1(J)+TOL
            IF(Y1JL.LE.TARGET.AND.TARGET.LE.Y1JU)GO TO 2310
 2320     CONTINUE
          K=K+1
          Y3(K)=TARGET
 2310   CONTINUE
!
        ITYP3='VECT'
        N3=K
      ELSEIF(IACASE.EQ.'SECA')THEN
!
!               ************************************************
!               **  STEP 24--                                 **
!               **  TREAT THE SET        CARDINALITY    CASE  **
!               ************************************************
!
        K=1
        Y3(K)=Y1(K)
!
        IF(N1.GT.1)THEN
          DO 2410 I=1,N1
            TARGET=Y1(I)
            DO 2420 J=1,K
              Y3JL=Y3(J)-TOL
              Y3JU=Y3(J)+TOL
              IF(Y3JL.LE.TARGET.AND.TARGET.LE.Y3JU)GO TO 2410
 2420       CONTINUE
            K=K+1
 2410     CONTINUE
        ENDIF
        SCAL3=K
!
        ITYP3='SCAL'
        N3=1
      ELSEIF(IACASE.EQ.'SECP')THEN
!
!               ***************************************************
!               **  STEP 25--                                    **
!               **  TREAT THE SET        CARTESIAN PRODUCT CASE  **
!               ***************************************************
!
        K1=1
        Y1HOLD(K1)=Y1(K1)
        IF(N1.GT.1)THEN
          DO 2510 I=1,N1
            TARGET=Y1(I)
            DO 2520 J=1,K1
              Y1JL=Y1HOLD(J)-TOL
              Y1JU=Y1HOLD(J)+TOL
              IF(Y1JL.LE.TARGET.AND.TARGET.LE.Y1JU)GO TO 2510
 2520       CONTINUE
            K1=K1+1
            Y1HOLD(K1)=TARGET
 2510     CONTINUE
        ENDIF
!
!CCCC   THE FOLLOWING SECTION WAS CORRECTED (ALAN) SEPTEMBER 1993
        K2=1
        Y2HOLD(K2)=Y2(K2)
        IF(N2.GT.1)THEN
          DO 2530 I=1,N2
            TARGET=Y2(I)
            DO 2540 J=1,K2
              Y2JL=Y2HOLD(J)-TOL
              Y2JU=Y2HOLD(J)+TOL
              IF(Y2JL.LE.TARGET.AND.TARGET.LE.Y2JU)GO TO 2530
 2540       CONTINUE
            K2=K2+1
            Y2HOLD(K2)=TARGET
 2530     CONTINUE
        ENDIF
!
!CCCC   THE FOLLOWING SECTION WAS CORRECTED   (ALAN) SEPTEMBER 1993
        K=0
        DO 2550 I=1,K1
          DO 2560 J=1,K2
            K=K+1
            Y3(K)=Y1HOLD(I)
            Y4(K)=Y2HOLD(J)
 2560     CONTINUE
 2550   CONTINUE
!
        ITYP3='VECT'
        N3=K
      ELSEIF(IACASE.EQ.'SEEL')THEN
!
!               *******************************************************
!               **  STEP 26--                                        **
!               **  TREAT THE SET        ELEMENTS (DISTINCT)   CASE  **
!               *******************************************************
!
        K=1
        Y3(K)=Y1(K)
!
        IF(N1.GT.1)THEN
          DO 2610 I=1,N1
            TARGET=Y1(I)
            DO 2620 J=1,K
              Y3JL=Y3(J)-TOL
              Y3JU=Y3(J)+TOL
              IF(Y3JL.LE.TARGET.AND.TARGET.LE.Y3JU)GO TO 2610
 2620       CONTINUE
            K=K+1
            Y3(K)=TARGET
 2610     CONTINUE
        ENDIF
!
        ITYP3='VECT'
        N3=K
      ELSE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1211)
 1211   FORMAT('***** INTERNAL ERROR IN SETARI--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1212)
 1212   FORMAT('      IACASE NOT EQUAL TO')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1213)
 1213   FORMAT('      SEUN, SEIN, SECO, SECA, SECP OR SEEL')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1215)
 1215   FORMAT('      IACASE = ',A4)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'TARI')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF SETARI--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9017)N1,N2,N3
 9017   FORMAT('N1,N2,N3 = ',3I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9018)SCAL3,ITYP3,IERROR
 9018   FORMAT('SCAL3,ITYP3,IERROR = ',G15.7,2(2X,A4))
        CALL DPWRST('XXX','BUG ')
        IF(ITYP3.NE.'SCAL')THEN
          DO 9021 I=1,N1
            WRITE(ICOUT,9022)I,Y1(I)
 9022       FORMAT('I,Y1(I) = ',I8,G15.7)
            CALL DPWRST('XXX','BUG ')
 9021     CONTINUE
          DO 9031 I=1,N2
            WRITE(ICOUT,9032)I,Y2(I)
 9032       FORMAT('I,Y2(I) = ',I8,G15.7)
            CALL DPWRST('XXX','BUG ')
 9031     CONTINUE
          DO 9041 I=1,N3
            WRITE(ICOUT,9042)I,Y3(I),Y4(I)
 9042       FORMAT('I,Y3(I),Y4(I) = ',I8,2G15.7)
            CALL DPWRST('XXX','BUG ')
 9041     CONTINUE
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE SETARI
      REAL FUNCTION SGAMMA(ISEED,A)
!CCCC REAL FUNCTION SGAMMA(IR,A)
!                                                                       SGA   10
!**********************************************************************CSGA   20
!**********************************************************************CSGA   30
!                                                                      CSGA   40
!                                                                      CSGA   50
!     (STANDARD-)  G A M M A  DISTRIBUTION                             CSGA   60
!                                                                      CSGA   70
!                                                                      CSGA   80
!**********************************************************************CSGA   90
!**********************************************************************CSGA  100
!                                                                      CSGA  110
!               PARAMETER  A >= 1.0  ]                                 CSGA  120
!                                                                      CSGA  130
!**********************************************************************CSGA  140
!                                                                      CSGA  150
!     FOR DETAILS SEE:                                                 CSGA  160
!                                                                      CSGA  170
!               AHRENS, J.H. AND DIETER, U.                            CSGA  180
!               GENERATING GAMMA VARIATES BY A                         CSGA  190
!               MODIFIED REJECTION TECHNIQUE.                          CSGA  200
!               COMM. ACM, 25,1 (JAN. 1982), 47 - 54.                  CSGA  210
!                                                                      CSGA  220
!     STEP NUMBERS CORRESPOND TO ALGORITHM 'GD' IN THE ABOVE PAPER     CSGA  230
!                                 (STRAIGHTFORWARD IMPLEMENTATION)     CSGA  240
!                                                                      CSGA  250
!**********************************************************************CSGA  260
!                                                                      CSGA  270
!               PARAMETER  0.0 < A < 1.0  ]                            CSGA  280
!                                                                      CSGA  290
!**********************************************************************CSGA  300
!                                                                      CSGA  310
!     FOR DETAILS SEE:                                                 CSGA  320
!                                                                      CSGA  330
!               AHRENS, J.H. AND DIETER, U.                            CSGA  340
!               COMPUTER METHODS FOR SAMPLING FROM GAMMA,              CSGA  350
!               BETA, POISSON AND BINOMIAL DISTRIBUTIONS.              CSGA  360
!               COMPUTING, 12 (1974), 223 - 246.                       CSGA  370
!                                                                      CSGA  380
!     (ADAPTED IMPLEMENTATION OF ALGORITHM 'GS' IN THE ABOVE PAPER)    CSGA  390
!                                                                      CSGA  400
!**********************************************************************CSGA  410
!                                                                       SGA  420
!
!     INPUT:  IR=CURRENT STATE OF BASIC RANDOM NUMBER GENERATOR
!             A =PARAMETER (MEAN) OF THE STANDARD GAMMA DISTRIBUTION
!     OUTPUT: SGAMMA = SAMPLE FROM THE GAMMA-(A)-DISTRIBUTION
!
!     COEFFICIENTS Q(K) - FOR Q0 = SUM(Q(K)*A**(-K))
!     COEFFICIENTS A(K) - FOR Q = Q0+(T*T/2)*SUM(A(K)*V**K)
!     COEFFICIENTS E(K) - FOR EXP(Q)-1 = SUM(E(K)*Q**K)
!
!  MAY, 2003: SOME MODIFICATIONS MADE IN ORDER TO INCORPORATE
!             INTO DATAPLOT.
!
!             1) REPLACE CALLS TO SUNIF WITH CALLS TO DATAPLOT
!                UNIFORM RANDOM NUMBER ROUTINE "UNIRAN".
!             2) REPLACE IR WITH ISEED
!             3) REPLACE CALLS TO "SNORM" WITH "NORRAN"
!
!  JANUARY, 2005: THERE WAS A BUG IF GAMMA RAND NUMBER ROUTINE
!                 CALLED MORE THAN ONCE.  NEED TO RESET VALUE OF
!                 AA AND AAA TO 0.  DO THIS BY STORING IN COMMON
!                 AND HAVING CALLING ROUTINE RESET.
!
      REAL XTEMP(1)
!
      COMMON/SGAMM/AA,AAA,S2,S,D,Q0,B,SI,C
!
      DATA Q1,Q2,Q3,Q4,Q5,Q6,Q7 /.04166669,.02083148,   &
      .00801191,.00144121,-.00007388,.00024511,.00024240/
      DATA A1,A2,A3,A4,A5,A6,A7 /.3333333,-.2500030,   &
      .2000062,-.1662921,.1423657,-.1367177,.1233795/
      DATA E1,E2,E3,E4,E5 /1.,.4999897,.1668290,.0407753,.0102930/
!
!     PREVIOUS A PRE-SET TO ZERO - AA IS A', AAA IS A"
!     SQRT32 IS THE SQUAREROOT OF 32 = 5.656854249492380
!
!CCCC DATA AA /0.0/, AAA /0.0/, SQRT32 /5.656854/
      DATA SQRT32 /5.656854/
!
      IF (A .EQ. AA) GO TO 1
      IF (A .LT. 1.0) GO TO 12
!
!     STEP  1:  RECALCULATIONS OF S2,S,D IF A HAS CHANGED
!
      AA=A
      S2=A-0.5
      S=SQRT(S2)
      D=SQRT32-12.0*S
!
!     STEP  2:  T=STANDARD NORMAL DEVIATE,
!               X=(S,1/2)-NORMAL DEVIATE.
!               IMMEDIATE ACCEPTANCE (I)
!
!CC1  T=SNORM(IR)
   1  CONTINUE
      NTEMP=1
      CALL NORRAN(NTEMP,ISEED,XTEMP)
      T=XTEMP(1)
      X=S+0.5*T
      SGAMMA=X*X
      IF (T .GE. 0.0) RETURN
!
!     STEP  3:  U= 0,1 -UNIFORM SAMPLE. SQUEEZE ACCEPTANCE (S)
!
!CCCC U=SUNIF(IR)
      NTEMP=1
      CALL UNIRAN(NTEMP,ISEED,XTEMP)
      U=XTEMP(1)
      IF (D*U .LE. T*T*T) RETURN
!
!     STEP  4:  RECALCULATIONS OF Q0,B,SI,C IF NECESSARY
!
      IF (A .EQ. AAA) GO TO 4
      AAA=A
      R=1.0/A
      Q0=((((((Q7*R+Q6)*R+Q5)*R+Q4)*R+Q3)*R+Q2)*R+Q1)*R
!
!               APPROXIMATION DEPENDING ON SIZE OF PARAMETER A
!               THE CONSTANTS IN THE EXPRESSIONS FOR B, SI AND
!               C WERE ESTABLISHED BY NUMERICAL EXPERIMENTS
!
      IF (A .LE. 3.686) GO TO 3
      IF (A .LE. 13.022) GO TO 2
!
!               CASE 3:  A .GT. 13.022
!
      B=1.77
      SI=.75
      C=.1515/S
      GO TO 4
!
!               CASE 2:  3.686 .LT. A .LE. 13.022
!
   2  B=1.654+.0076*S2
      SI=1.68/S+.275
      C=.062/S+.024
      GO TO 4
!
!               CASE 1:  A .LE. 3.686
!
   3  B=.463+S-.178*S2
      SI=1.235
      C=.195/S-.079+.016*S
!
!     STEP  5:  NO QUOTIENT TEST IF X NOT POSITIVE
!
   4  IF (X .LE. 0.0) GO TO 7
!
!     STEP  6:  CALCULATION OF V AND QUOTIENT Q
!
      V=T/(S+S)
      IF (ABS(V) .LE. 0.25) GO TO 5
      Q=Q0-S*T+0.25*T*T+(S2+S2)*LOG(1.0+V)
      GO TO 6
   5  Q=Q0+0.5*T*T*((((((A7*V+A6)*V+A5)*V+A4)*V+A3)*V+A2)*V+A1)*V
!
!     STEP  7:  QUOTIENT ACCEPTANCE (Q)
!
   6  IF (LOG(1.0-U) .LE. Q) RETURN
!
!     STEP  8:  E=STANDARD EXPONENTIAL DEVIATE
!               U= 0,1 -UNIFORM DEVIATE
!               T=(B,SI)-DOUBLE EXPONENTIAL (LAPLACE) SAMPLE
!
!CC7  E=SEXPO(IR)
   7  CONTINUE
      NTEMP=1
      CALL EXPRAN(NTEMP,ISEED,XTEMP)
      E=XTEMP(1)
      CALL UNIRAN(NTEMP,ISEED,XTEMP)
!CCCC U=SUNIF(IR)
      U=XTEMP(1)
      U=U+U-1.0
      T=B+SIGN(SI*E,U)
!
!     STEP  9:  REJECTION IF T .LT. TAU(1) = -.71874483771719
!
      IF (T .LT. (-.7187449)) GO TO 7
!
!     STEP 10:  CALCULATION OF V AND QUOTIENT Q
!
      V=T/(S+S)
      IF (ABS(V) .LE. 0.25) GO TO 8
      Q=Q0-S*T+0.25*T*T+(S2+S2)*LOG(1.0+V)
      GO TO 9
   8  Q=Q0+0.5*T*T*((((((A7*V+A6)*V+A5)*V+A4)*V+A3)*V+A2)*V+A1)*V
!
!     STEP 11:  HAT ACCEPTANCE (H) (IF Q NOT POSITIVE GO TO STEP 8)
!
   9  IF (Q .LE. 0.0) GO TO 7
      IF (Q .LE. 0.5) GO TO 10
      W=EXP(Q)-1.0
      GO TO 11
  10  W=((((E5*Q+E4)*Q+E3)*Q+E2)*Q+E1)*Q
!
!               IF T IS REJECTED, SAMPLE AGAIN AT STEP 8
!
  11  IF (C*ABS(U) .GT. W*EXP(E-0.5*T*T)) GO TO 7
      X=S+0.5*T
      SGAMMA=X*X
      RETURN
!
!     ALTERNATE METHOD FOR PARAMETERS A BELOW 1  (.3678794=EXP(-1.))
!
  12  AA=0.0
      B=1.0+.3678794*A
!C13  P=B*SUNIF(IR)
  13  CONTINUE
      NTEMP=1
      CALL UNIRAN(NTEMP,ISEED,XTEMP)
      P=B*XTEMP(1)
      IF (P .GE. 1.0) GO TO 14
      SGAMMA=EXP(LOG(P)/A)
!CCCC IF (SEXPO(IR) .LT. SGAMMA) GO TO 13
      NTEMP=1
      CALL EXPRAN(NTEMP,ISEED,XTEMP)
      IF (XTEMP(1) .LT. SGAMMA) GO TO 13
      RETURN
  14  SGAMMA=-LOG((B-P)/A)
!CCCC IF (SEXPO(IR) .LT. (1.0-A)*LOG(SGAMMA)) GO TO 13
      NTEMP=1
      CALL EXPRAN(NTEMP,ISEED,XTEMP)
      IF (XTEMP(1) .LT. (1.0-A)*LOG(SGAMMA)) GO TO 13
      RETURN
      END FUNCTION SGAMMA
      SUBROUTINE SGECO(A,LDA,N,IPVT,RCOND,Z)
!***BEGIN PROLOGUE  SGECO
!***DATE WRITTEN   780814   (YYMMDD)
!***REVISION DATE  820801   (YYMMDD)
!***CATEGORY NO.  D2A1
!***KEYWORDS  CONDITION,FACTOR,LINEAR ALGEBRA,LINPACK,MATRIX
!***AUTHOR  MOLER, C. B., (U. OF NEW MEXICO)
!***PURPOSE  Factors a real matrix by Gaussian elimination and estimates
!            the condition number of the matrix.
!***DESCRIPTION
!
!     SGECO factors a real matrix by Gaussian elimination
!     and estimates the condition of the matrix.
!
!     If  RCOND  is not needed, SGEFA is slightly faster.
!     To solve  A*X = B , follow SGECO by SGESL.
!     To compute  INVERSE(A)*C , follow SGECO by SGESL.
!     To compute  DETERMINANT(A) , follow SGECO by SGEDI.
!     To compute  INVERSE(A) , follow SGECO by SGEDI.
!
!     On Entry
!
!        A       REAL(LDA, N)
!                the matrix to be factored.
!
!        LDA     INTEGER
!                the leading dimension of the array  A .
!
!        N       INTEGER
!                the order of the matrix  A .
!
!     On Return
!
!        A       an upper triangular matrix and the multipliers
!                which were used to obtain it.
!                The factorization can be written  A = L*U , where
!                L  is a product of permutation and unit lower
!                triangular matrices and  U  is upper triangular.
!
!        IPVT    INTEGER(N)
!                an integer vector of pivot indices.
!
!        RCOND   REAL
!                an estimate of the reciprocal condition of  A .
!                For the system  A*X = B , relative perturbations
!                in  A  and  B  of size  EPSILON  may cause
!                relative perturbations in  X  of size  EPSILON/RCOND .
!                If  RCOND  is so small that the logical expression
!                           1.0 + RCOND .EQ. 1.0
!                is true, then  A  may be singular to working
!                precision.  In particular,  RCOND  is zero  if
!                exact singularity is detected or the estimate
!                underflows.
!
!        Z       REAL(N)
!                a work vector whose contents are usually unimportant.
!                If  A  is close to a singular matrix, then  Z  is
!                an approximate null vector in the sense that
!                NORM(A*Z) = RCOND*NORM(A)*NORM(Z) .
!
!     LINPACK.  This version dated 08/14/78 .
!     Cleve Moler, University of New Mexico, Argonne National Lab.
!
!     Subroutines and Functions
!
!     LINPACK SGEFA
!     BLAS SAXPY,SDOT,SSCAL,SASUM
!     Fortran ABS,AMAX1,SIGN
!***REFERENCES  DONGARRA J.J., BUNCH J.R., MOLER C.B., STEWART G.W.,
!                 *LINPACK USERS  GUIDE*, SIAM, 1979.
!***ROUTINES CALLED  SASUM,SAXPY,SDOT,SGEFA,SSCAL
!***END PROLOGUE  SGECO
      INTEGER LDA,N,IPVT(*)
      REAL A(LDA,*),Z(*)
      REAL RCOND
!
      REAL SDOT,EK,T,WK,WKM
      REAL ANORM,S,SASUM,SM,YNORM
      INTEGER INFO,J,K,KB,KP1,L
!
!     COMPUTE 1-NORM OF A
!
!***FIRST EXECUTABLE STATEMENT  SGECO
      ANORM = 0.0E0
      DO 10 J = 1, N
         ANORM = AMAX1(ANORM,SASUM(N,A(1,J),1))
   10 CONTINUE
!
!     FACTOR
!
      CALL SGEFA(A,LDA,N,IPVT,INFO)
!
!     RCOND = 1/(NORM(A)*(ESTIMATE OF NORM(INVERSE(A)))) .
!     ESTIMATE = NORM(Z)/NORM(Y) WHERE  A*Z = Y  AND  TRANS(A)*Y = E .
!     TRANS(A)  IS THE TRANSPOSE OF A .  THE COMPONENTS OF  E  ARE
!     CHOSEN TO CAUSE MAXIMUM LOCAL GROWTH IN THE ELEMENTS OF W  WHERE
!     TRANS(U)*W = E .  THE VECTORS ARE FREQUENTLY RESCALED TO AVOID
!     OVERFLOW.
!
!     SOLVE TRANS(U)*W = E
!
      EK = 1.0E0
      DO 20 J = 1, N
         Z(J) = 0.0E0
   20 CONTINUE
      DO 100 K = 1, N
         IF (Z(K) .NE. 0.0E0) EK = SIGN(EK,-Z(K))
         IF (ABS(EK-Z(K)) .LE. ABS(A(K,K))) GO TO 30
            S = ABS(A(K,K))/ABS(EK-Z(K))
            CALL SSCAL(N,S,Z,1)
            EK = S*EK
   30    CONTINUE
         WK = EK - Z(K)
         WKM = -EK - Z(K)
         S = ABS(WK)
         SM = ABS(WKM)
         IF (A(K,K) .EQ. 0.0E0) GO TO 40
            WK = WK/A(K,K)
            WKM = WKM/A(K,K)
         GO TO 50
   40    CONTINUE
            WK = 1.0E0
            WKM = 1.0E0
   50    CONTINUE
         KP1 = K + 1
         IF (KP1 .GT. N) GO TO 90
            DO 60 J = KP1, N
               SM = SM + ABS(Z(J)+WKM*A(K,J))
               Z(J) = Z(J) + WK*A(K,J)
               S = S + ABS(Z(J))
   60       CONTINUE
            IF (S .GE. SM) GO TO 80
               T = WKM - WK
               WK = WKM
               DO 70 J = KP1, N
                  Z(J) = Z(J) + T*A(K,J)
   70          CONTINUE
   80       CONTINUE
   90    CONTINUE
         Z(K) = WK
  100 CONTINUE
      S = 1.0E0/SASUM(N,Z,1)
      CALL SSCAL(N,S,Z,1)
!
!     SOLVE TRANS(L)*Y = W
!
      DO 120 KB = 1, N
         K = N + 1 - KB
         IF (K .LT. N) Z(K) = Z(K) + SDOT(N-K,A(K+1,K),1,Z(K+1),1)
         IF (ABS(Z(K)) .LE. 1.0E0) GO TO 110
            S = 1.0E0/ABS(Z(K))
            CALL SSCAL(N,S,Z,1)
  110    CONTINUE
         L = IPVT(K)
         T = Z(L)
         Z(L) = Z(K)
         Z(K) = T
  120 CONTINUE
      S = 1.0E0/SASUM(N,Z,1)
      CALL SSCAL(N,S,Z,1)
!
      YNORM = 1.0E0
!
!     SOLVE L*V = Y
!
      DO 140 K = 1, N
         L = IPVT(K)
         T = Z(L)
         Z(L) = Z(K)
         Z(K) = T
         IF (K .LT. N) CALL SAXPY(N-K,T,A(K+1,K),1,Z(K+1),1)
         IF (ABS(Z(K)) .LE. 1.0E0) GO TO 130
            S = 1.0E0/ABS(Z(K))
            CALL SSCAL(N,S,Z,1)
            YNORM = S*YNORM
  130    CONTINUE
  140 CONTINUE
      S = 1.0E0/SASUM(N,Z,1)
      CALL SSCAL(N,S,Z,1)
      YNORM = S*YNORM
!
!     SOLVE  U*Z = V
!
      DO 160 KB = 1, N
         K = N + 1 - KB
         IF (ABS(Z(K)) .LE. ABS(A(K,K))) GO TO 150
            S = ABS(A(K,K))/ABS(Z(K))
            CALL SSCAL(N,S,Z,1)
            YNORM = S*YNORM
  150    CONTINUE
         IF (A(K,K) .NE. 0.0E0) Z(K) = Z(K)/A(K,K)
         IF (A(K,K) .EQ. 0.0E0) Z(K) = 1.0E0
         T = -Z(K)
         CALL SAXPY(K-1,T,A(1,K),1,Z(1),1)
  160 CONTINUE
!     MAKE ZNORM = 1.0
      S = 1.0E0/SASUM(N,Z,1)
      CALL SSCAL(N,S,Z,1)
      YNORM = S*YNORM
!
      IF (ANORM .NE. 0.0E0) RCOND = YNORM/ANORM
      IF (ANORM .EQ. 0.0E0) RCOND = 0.0E0
      RETURN
      END SUBROUTINE SGECO
      SUBROUTINE SGEDI(A,LDA,N,IPVT,DET,WORK,JOB)
!***BEGIN PROLOGUE  SGEDI
!***DATE WRITTEN   780814   (YYMMDD)
!***REVISION DATE  820801   (YYMMDD)
!***CATEGORY NO.  D2A1,D3A1
!***KEYWORDS  DETERMINANT,FACTOR,INVERSE,LINEAR ALGEBRA,LINPACK,MATRIX
!***AUTHOR  MOLER, C. B., (U. OF NEW MEXICO)
!***PURPOSE  Computes the determinant and inverse of a matrix
!            using the factors computed by SGECO or SGEFA.
!***DESCRIPTION
!
!     SGEDI computes the determinant and inverse of a matrix
!     using the factors computed by SGECO or SGEFA.
!
!     On Entry
!
!        A       REAL(LDA, N)
!                the output from SGECO or SGEFA.
!
!        LDA     INTEGER
!                the leading dimension of the array  A .
!
!        N       INTEGER
!                the order of the matrix  A .
!
!        IPVT    INTEGER(N)
!                the pivot vector from SGECO or SGEFA.
!
!        WORK    REAL(N)
!                work vector.  Contents destroyed.
!
!        JOB     INTEGER
!                = 11   both determinant and inverse.
!                = 01   inverse only.
!                = 10   determinant only.
!
!     On Return
!
!        A       inverse of original matrix if requested.
!                Otherwise unchanged.
!
!        DET     REAL(2)
!                determinant of original matrix if requested.
!                Otherwise not referenced.
!                Determinant = DET(1) * 10.0**DET(2)
!                with  1.0 .LE. ABS(DET(1)) .LT. 10.0
!                or  DET(1) .EQ. 0.0 .
!
!     Error Condition
!
!        A division by zero will occur if the input factor contains
!        a zero on the diagonal and the inverse is requested.
!        It will not occur if the subroutines are called correctly
!        and if SGECO has set RCOND .GT. 0.0 or SGEFA has set
!        INFO .EQ. 0 .
!
!     LINPACK.  This version dated 08/14/78 .
!     Cleve Moler, University of New Mexico, Argonne National Lab.
!
!     Subroutines and Functions
!
!     BLAS SAXPY,SSCAL,SSWAP
!     Fortran ABS,MOD
!***REFERENCES  DONGARRA J.J., BUNCH J.R., MOLER C.B., STEWART G.W.,
!                 *LINPACK USERS  GUIDE*, SIAM, 1979.
!***ROUTINES CALLED  SAXPY,SSCAL,SSWAP
!***END PROLOGUE  SGEDI
      INTEGER LDA,N,IPVT(1),JOB
      REAL A(LDA,1),DET(2),WORK(1)
!
      REAL T
      REAL TEN
      INTEGER I,J,K,KB,KP1,L,NM1
!
!     COMPUTE DETERMINANT
!
!***FIRST EXECUTABLE STATEMENT  SGEDI
      IF (JOB/10 .EQ. 0) GO TO 70
         DET(1) = 1.0E0
         DET(2) = 0.0E0
         TEN = 10.0E0
         DO 50 I = 1, N
            IF (IPVT(I) .NE. I) DET(1) = -DET(1)
            DET(1) = A(I,I)*DET(1)
!        ...EXIT
            IF (DET(1) .EQ. 0.0E0) GO TO 60
   10       IF (ABS(DET(1)) .GE. 1.0E0) GO TO 20
               DET(1) = TEN*DET(1)
               DET(2) = DET(2) - 1.0E0
            GO TO 10
   20       CONTINUE
   30       IF (ABS(DET(1)) .LT. TEN) GO TO 40
               DET(1) = DET(1)/TEN
               DET(2) = DET(2) + 1.0E0
            GO TO 30
   40       CONTINUE
   50    CONTINUE
   60    CONTINUE
   70 CONTINUE
!
!     COMPUTE INVERSE(U)
!
      IF (MOD(JOB,10) .EQ. 0) GO TO 150
         DO 100 K = 1, N
            A(K,K) = 1.0E0/A(K,K)
            T = -A(K,K)
            CALL SSCAL(K-1,T,A(1,K),1)
            KP1 = K + 1
            IF (N .LT. KP1) GO TO 90
            DO 80 J = KP1, N
               T = A(K,J)
               A(K,J) = 0.0E0
               CALL SAXPY(K,T,A(1,K),1,A(1,J),1)
   80       CONTINUE
   90       CONTINUE
  100    CONTINUE
!
!        FORM INVERSE(U)*INVERSE(L)
!
         NM1 = N - 1
         IF (NM1 .LT. 1) GO TO 140
         DO 130 KB = 1, NM1
            K = N - KB
            KP1 = K + 1
            DO 110 I = KP1, N
               WORK(I) = A(I,K)
               A(I,K) = 0.0E0
  110       CONTINUE
            DO 120 J = KP1, N
               T = WORK(J)
               CALL SAXPY(N,T,A(1,J),1,A(1,K),1)
  120       CONTINUE
            L = IPVT(K)
            IF (L .NE. K) CALL SSWAP(N,A(1,K),1,A(1,L),1)
  130    CONTINUE
  140    CONTINUE
  150 CONTINUE
      RETURN
      END SUBROUTINE SGEDI
      SUBROUTINE SGEEV(A,LDA,N,E,V,LDV,WORK,JOB,INFO)
!***BEGIN PROLOGUE  SGEEV
!***DATE WRITTEN   800808   (YYMMDD)
!***REVISION DATE  820801   (YYMMDD)
!***CATEGORY NO.  D4A2
!***KEYWORDS  EIGENVALUE,EIGENVECTOR,GENERAL MATRIX,REAL
!***AUTHOR  KAHANER, D. K., (NBS)
!           MOLER, C. B., (U. OF NEW MEXICO)
!           STEWART, G. W., (U. OF MARYLAND)
!***PURPOSE  To compute the eigenvalues and, optionally, the eigen-
!            vectors of a GENERAL real matrix.
!***DESCRIPTION
!
!     LICEPACK.    This version dated 08/08/80.
!     David Kahaner, Cleve Moler, G. W. Stewart,
!       N.B.S.         U.N.M.      N.B.S./U.MD.
!
!     Abstract
!      SGEEV computes the eigenvalues and, optionally,
!      the eigenvectors of a general real matrix.
!
!     Call Sequence Parameters-
!       (The values of parameters marked with * (star) will be changed
!         by SGEEV.)
!
!        A*      REAL(LDA,N)
!                real nonsymmetric input matrix.
!
!        LDA     INTEGER
!                set by the user to
!                the leading dimension of the real array A.
!
!        N       INTEGER
!                set by the user to
!                the order of the matrices A and V, and
!                the number of elements in E.
!
!        E*      COMPLEX(N)
!                on return from SGEEV, E contains the eigenvalues of A.
!                See also INFO below.
!
!        V*      COMPLEX(LDV,N)
!                on return from SGEEV, if the user has set JOB
!                = 0        V is not referenced.
!                = nonzero  the N eigenvectors of A are stored in the
!                first N columns of V.  See also INFO below.
!                (Note that if the input matrix A is nearly degenerate,
!                 V may be badly conditioned, i.e., may have nearly
!                 dependent columns.)
!
!        LDV     INTEGER
!                set by the user to
!                the leading dimension of the array V if JOB is also
!                set nonzero.  In that case, N must be .LE. LDV.
!                If JOB is set to zero, LDV is not referenced.
!
!        WORK*   REAL(2N)
!                temporary storage vector.  Contents changed by SGEEV.
!
!        JOB     INTEGER
!                set by the user to
!                = 0        eigenvalues only to be calculated by SGEEV.
!                           Neither V nor LDV is referenced.
!                = nonzero  eigenvalues and vectors to be calculated.
!                           In this case, A & V must be distinct arrays.
!                           Also, if LDA .GT. LDV, SGEEV changes all the
!                           elements of A thru column N.  If LDA < LDV,
!                           SGEEV changes all the elements of V through
!                           column N. If LDA = LDV, only A(I,J) and V(I,
!                           J) for I,J = 1,...,N are changed by SGEEV.
!
!        INFO*   INTEGER
!                on return from SGEEV the value of INFO is
!                = 0  normal return, calculation successful.
!                = K  if the eigenvalue iteration fails to converge,
!                     eigenvalues K+1 through N are correct, but
!                     no eigenvectors were computed even if they were
!                     requested (JOB nonzero).
!
!      Error Messages
!           No. 1  recoverable  N is greater than LDA
!           No. 2  recoverable  N is less than one.
!           No. 3  recoverable  JOB is nonzero and N is greater than LDV
!           No. 4  warning      LDA > LDV, elements of A other than the
!                               N by N input elements have been changed.
!           No. 5  warning      LDA < LDV, elements of V other than the
!                               N x N output elements have been changed.
!
!
!     Subroutines used
!
!     EISPACK-  BALANC,BALBAK, ORTHES, ORTRAN, HQR, HQR2
!     BLAS-  SCOPY, SCOPYM
!     SLATEC- XERROR
!***REFERENCES  (NONE)
!***ROUTINES CALLED  BALANC,BALBAK,HQR,HQR2,ORTHES,ORTRAN,SCOPY,SCOPYM,
!                    XERROR
!***END PROLOGUE  SGEEV
!CCCC INTEGER I,IHI,ILO,INFO,J,JB,JOB,K,KM,KP,L,LDA,LDV,
      INTEGER IHI,ILO,INFO,J,JOB,K,L,LDA,LDV,   &
              MDIM,MIN0,N
      REAL A(*),E(*),WORK(*),V(*)
!***FIRST EXECUTABLE STATEMENT  SGEEV
      IF(N .GT. LDA)THEN
!CCCC   WRITE(*,*) 'FROM SGEEV: N > LDA'
        INFO = -1
        RETURN
      ENDIF
      IF(N .LT. 1) THEN
!CCCC   WRITE(*,*) 'FROM SGEEV: N < 1'
        INFO = -1
        RETURN
      END IF
      IF(N .EQ. 1 .AND. JOB .EQ. 0) GO TO 35
      MDIM = LDA
      IF(JOB .EQ. 0) GO TO 5
      IF(N .GT. LDV)THEN
!CCCC   WRITE(*,*) 'FROM SGEEV: JOB NON-ZERO AND N > LDV'
        INFO = -1
        RETURN
      ENDIF
      IF(N .EQ. 1) GO TO 35
!
!       REARRANGE A IF NECESSARY WHEN LDA.GT.LDV AND JOB .NE.0
!
      MDIM = MIN0(LDA,LDV)
      IF(LDA.LT.LDV) THEN
!CCCC  WRITE(*,*) 'FROM SGEEV: LDA < LDV, ELEMENTS OF V OTHER'
!CCCC  WRITE(*,*) 'THAN THE N BY N OUTPUT ELEMENTS HAVE BEEN CHANGED.'
      ENDIF
      IF(LDA.LE.LDV) GO TO 5
!CCCC WRITE(*,*) 'FROM SGEEV: LDA > LDV, ELEMENTS OF A OTHER THAN THE'
!CCCC WRITE(*,*) 'N BY N INPUT ELEMENTS HAVE BEEN CHANGED.'
      L = N - 1
      DO 4 J=1,L
         M = 1+J*LDV
         K = 1+J*LDA
         CALL SCOPY(N,A(K),1,A(M),1)
    4 CONTINUE
    5 CONTINUE
!
!     SCALE AND ORTHOGONAL REDUCTION TO HESSENBERG.
!
      CALL BALANC(MDIM,N,A,ILO,IHI,WORK(1))
      CALL ORTHES(MDIM,N,ILO,IHI,A,WORK(N+1))
      IF(JOB .NE. 0) GO TO 10
!
!     EIGENVALUES ONLY
!
      CALL HQR(LDA,N,ILO,IHI,A,E(1),E(N+1),INFO)
      GO TO 30
!
!     EIGENVALUES AND EIGENVECTORS.
!
   10 CALL ORTRAN(MDIM,N,ILO,IHI,A,WORK(N+1),V)
      CALL HQR2(MDIM,N,ILO,IHI,A,E(1),E(N+1),V,INFO)
      IF (INFO .NE. 0) GO TO 30
      CALL BALBAK(MDIM,N,ILO,IHI,WORK(1),N,V)
!
!     CONVERT EIGENVECTORS TO COMPLEX STORAGE.
!
!CCCC JULY 1993.  FOR DATAPLOT PURPOSES, DO NOT CONVERT TO COMPLEX
!CCCC FORMAT (I.E., ROWS 1 TO N CORRESPOND TO REAL PART, ROWS N+1
!CCCC TO 2*N CORRESPOND TO IMAGINARY PART).
!NIST DO 20 JB = 1,N
!NIST    J=N+1-JB
!NIST    I=N+J
!NIST    K=(J-1)*MDIM+1
!NIST    KP=K+MDIM
!NIST    KM=K-MDIM
!NIST    IF(E(I).GE.0.0E0) CALL SCOPY(N,V(K),1,WORK(1),2)
!NIST    IF(E(I).LT.0.0E0) CALL SCOPY(N,V(KM),1,WORK(1),2)
!NIST    IF(E(I).EQ.0.0E0) CALL SCOPY(N,0.0E0,0,WORK(2),2)
!NIST    IF(E(I).GT.0.0E0) CALL SCOPY(N,V(KP),1,WORK(2),2)
!NIST    IF(E(I).LT.0.0E0) CALL SCOPYM(N,V(K),1,WORK(2),2)
!NIST    L=2*(J-1)*LDV+1
!NIST    CALL SCOPY(2*N,WORK(1),1,V(L),1)
!CC20 CONTINUE
!
!     CONVERT EIGENVALUES TO COMPLEX STORAGE.
!
!CCCC JULY 1993.  FOR DATAPLOT PURPOSES, DO NOT CONVERT TO COMPLEX
!CCCC FORMAT (I.E., ROWS 1 TO N CORRESPOND TO REAL PART, ROWS N+1
!CCCC TO 2*N CORRESPOND TO IMAGINARY PART).
   30 CONTINUE
!NIST CALL SCOPY(N,E(1),1,WORK(1),1)
!NIST CALL SCOPY(N,E(N+1),1,E(2),2)
!NIST CALL SCOPY(N,WORK(1),1,E(1),2)
      RETURN
!
!     TAKE CARE OF N=1 CASE
!
   35 E(1) = A(1)
      E(2) = 0.E0
      INFO = 0
      IF(JOB .EQ. 0) RETURN
      V(1) = A(1)
      V(2) = 0.E0
      RETURN
      END SUBROUTINE SGEEV
      SUBROUTINE SGEFA(A,LDA,N,IPVT,INFO)
!***BEGIN PROLOGUE  SGEFA
!***DATE WRITTEN   780814   (YYMMDD)
!***REVISION DATE  820801   (YYMMDD)
!***CATEGORY NO.  D2A1
!***KEYWORDS  FACTOR,LINEAR ALGEBRA,LINPACK,MATRIX
!***AUTHOR  MOLER, C. B., (U. OF NEW MEXICO)
!***PURPOSE  Factors a real matrix by Gaussian elimination.
!***DESCRIPTION
!
!     SGEFA factors a real matrix by Gaussian elimination.
!
!     SGEFA is usually called by SGECO, but it can be called
!     directly with a saving in time if  RCOND  is not needed.
!     (Time for SGECO) = (1 + 9/N)*(Time for SGEFA) .
!
!     On Entry
!
!        A       REAL(LDA, N)
!                the matrix to be factored.
!
!        LDA     INTEGER
!                the leading dimension of the array  A .
!
!        N       INTEGER
!                the order of the matrix  A .
!
!     On Return
!
!        A       an upper triangular matrix and the multipliers
!                which were used to obtain it.
!                The factorization can be written  A = L*U , where
!                L  is a product of permutation and unit lower
!                triangular matrices and  U  is upper triangular.
!
!        IPVT    INTEGER(N)
!                an integer vector of pivot indices.
!
!        INFO    INTEGER
!                = 0  normal value.
!                = K  if  U(K,K) .EQ. 0.0 .  This is not an error
!                     condition for this subroutine, but it does
!                     indicate that SGESL or SGEDI will divide by zero
!                     if called.  Use  RCOND  in SGECO for a reliable
!                     indication of singularity.
!
!     LINPACK.  This version dated 08/14/78 .
!     Cleve Moler, University of New Mexico, Argonne National Lab.
!
!     Subroutines and Functions
!
!     BLAS SAXPY,SSCAL,ISAMAX
!***REFERENCES  DONGARRA J.J., BUNCH J.R., MOLER C.B., STEWART G.W.,
!                 *LINPACK USERS  GUIDE*, SIAM, 1979.
!***ROUTINES CALLED  ISAMAX,SAXPY,SSCAL
!***END PROLOGUE  SGEFA
      INTEGER LDA,N,IPVT(*),INFO
      REAL A(LDA,*)
!
      REAL T
      INTEGER ISAMAX,J,K,KP1,L,NM1
!
!     GAUSSIAN ELIMINATION WITH PARTIAL PIVOTING
!
!***FIRST EXECUTABLE STATEMENT  SGEFA
      INFO = 0
      NM1 = N - 1
      IF (NM1 .LT. 1) GO TO 70
      DO 60 K = 1, NM1
         KP1 = K + 1
!
!        FIND L = PIVOT INDEX
!
         L = ISAMAX(N-K+1,A(K,K),1) + K - 1
         IPVT(K) = L
!
!        ZERO PIVOT IMPLIES THIS COLUMN ALREADY TRIANGULARIZED
!
         IF (A(L,K) .EQ. 0.0E0) GO TO 40
!
!           INTERCHANGE IF NECESSARY
!
            IF (L .EQ. K) GO TO 10
               T = A(L,K)
               A(L,K) = A(K,K)
               A(K,K) = T
   10       CONTINUE
!
!           COMPUTE MULTIPLIERS
!
            T = -1.0E0/A(K,K)
            CALL SSCAL(N-K,T,A(K+1,K),1)
!
!           ROW ELIMINATION WITH COLUMN INDEXING
!
            DO 30 J = KP1, N
               T = A(L,J)
               IF (L .EQ. K) GO TO 20
                  A(L,J) = A(K,J)
                  A(K,J) = T
   20          CONTINUE
               CALL SAXPY(N-K,T,A(K+1,K),1,A(K+1,J),1)
   30       CONTINUE
         GO TO 50
   40    CONTINUE
            INFO = K
   50    CONTINUE
   60 CONTINUE
   70 CONTINUE
      IPVT(N) = N
      IF (A(N,N) .EQ. 0.0E0) INFO = N
      RETURN
      END SUBROUTINE SGEFA
      SUBROUTINE SGESL(A,LDA,N,IPVT,B,JOB)
!***BEGIN PROLOGUE  SGESL
!***DATE WRITTEN   780814   (YYMMDD)
!***REVISION DATE  820801   (YYMMDD)
!***CATEGORY NO.  D2A1
!***KEYWORDS  LINEAR ALGEBRA,LINPACK,MATRIX,SOLVE
!***AUTHOR  MOLER, C. B., (U. OF NEW MEXICO)
!***PURPOSE  Solves the real system A*X=B or TRANS(A)*X=B
!            using the factors of SGECO or SGEFA
!***DESCRIPTION
!
!     SGESL solves the real system
!     A * X = B  or  TRANS(A) * X = B
!     using the factors computed by SGECO or SGEFA.
!
!     On Entry
!
!        A       REAL(LDA, N)
!                the output from SGECO or SGEFA.
!
!        LDA     INTEGER
!                the leading dimension of the array  A .
!
!        N       INTEGER
!                the order of the matrix  A .
!
!        IPVT    INTEGER(N)
!                the pivot vector from SGECO or SGEFA.
!
!        B       REAL(N)
!                the right hand side vector.
!
!        JOB     INTEGER
!                = 0         to solve  A*X = B ,
!                = nonzero   to solve  TRANS(A)*X = B  where
!                            TRANS(A)  is the transpose.
!
!     On Return
!
!        B       the solution vector  X .
!
!     Error Condition
!
!        A division by zero will occur if the input factor contains a
!        zero on the diagonal.  Technically, this indicates singularity,
!        but it is often caused by improper arguments or improper
!        setting of LDA .  It will not occur if the subroutines are
!        called correctly and if SGECO has set RCOND .GT. 0.0
!        or SGEFA has set INFO .EQ. 0 .
!
!     To compute  INVERSE(A) * C  where  C  is a matrix
!     with  P  columns
!           CALL SGECO(A,LDA,N,IPVT,RCOND,Z)
!           IF (RCOND is too small) GO TO ...
!           DO 10 J = 1, P
!              CALL SGESL(A,LDA,N,IPVT,C(1,J),0)
!        10 CONTINUE
!
!     LINPACK.  This version dated 08/14/78 .
!     Cleve Moler, University of New Mexico, Argonne National Lab.
!
!     Subroutines and Functions
!
!     BLAS SAXPY,SDOT
!***REFERENCES  DONGARRA J.J., BUNCH J.R., MOLER C.B., STEWART G.W.,
!                 *LINPACK USERS  GUIDE*, SIAM, 1979.
!***ROUTINES CALLED  SAXPY,SDOT
!***END PROLOGUE  SGESL
      INTEGER LDA,N,IPVT(*),JOB
      REAL A(LDA,*),B(*)
!
      REAL SDOT,T
      INTEGER K,KB,L,NM1
!***FIRST EXECUTABLE STATEMENT  SGESL
      NM1 = N - 1
      IF (JOB .NE. 0) GO TO 50
!
!        JOB = 0 , SOLVE  A * X = B
!        FIRST SOLVE  L*Y = B
!
         IF (NM1 .LT. 1) GO TO 30
         DO 20 K = 1, NM1
            L = IPVT(K)
            T = B(L)
            IF (L .EQ. K) GO TO 10
               B(L) = B(K)
               B(K) = T
   10       CONTINUE
            CALL SAXPY(N-K,T,A(K+1,K),1,B(K+1),1)
   20    CONTINUE
   30    CONTINUE
!
!        NOW SOLVE  U*X = Y
!
         DO 40 KB = 1, N
            K = N + 1 - KB
            B(K) = B(K)/A(K,K)
            T = -B(K)
            CALL SAXPY(K-1,T,A(1,K),1,B(1),1)
   40    CONTINUE
      GO TO 100
   50 CONTINUE
!
!        JOB = NONZERO, SOLVE  TRANS(A) * X = B
!        FIRST SOLVE  TRANS(U)*Y = B
!
         DO 60 K = 1, N
            T = SDOT(K-1,A(1,K),1,B(1),1)
            B(K) = (B(K) - T)/A(K,K)
   60    CONTINUE
!
!        NOW SOLVE TRANS(L)*X = Y
!
         IF (NM1 .LT. 1) GO TO 90
         DO 80 KB = 1, NM1
            K = N - KB
            B(K) = B(K) + SDOT(N-K,A(K+1,K),1,B(K+1),1)
            L = IPVT(K)
            IF (L .EQ. K) GO TO 70
               T = B(L)
               B(L) = B(K)
               B(K) = T
   70       CONTINUE
   80    CONTINUE
   90    CONTINUE
  100 CONTINUE
      RETURN
      END SUBROUTINE SGESL
      SUBROUTINE SGEMM (TRANSA, TRANSB, M, N, K, ALPHA, A, LDA, B, LDB,   &
         BETA, C, LDC,   &
         IERROR)
!DECK SGEMM
!***BEGIN PROLOGUE  SGEMM
!***PURPOSE  Multiply a real general matrix by a real general matrix.
!***LIBRARY   SLATEC (BLAS)
!***CATEGORY  D1B6
!***TYPE      SINGLE PRECISION (SGEMM-S, DGEMM-D, CGEMM-C)
!***KEYWORDS  LEVEL 3 BLAS, LINEAR ALGEBRA
!***AUTHOR  Dongarra, J., (ANL)
!           Duff, I., (AERE)
!           Du Croz, J., (NAG)
!           Hammarling, S. (NAG)
!***DESCRIPTION
!
!  SGEMM  performs one of the matrix-matrix operations
!
!     C := alpha*op( A )*op( B ) + beta*C,
!
!  where  op( X ) is one of
!
!     op( X ) = X   or   op( X ) = X',
!
!  alpha and beta are scalars, and A, B and C are matrices, with op( A )
!  an m by k matrix,  op( B )  a  k by n matrix and  C an m by n matrix.
!
!  Parameters
!  ==========
!
!  TRANSA - CHARACTER*1.
!           On entry, TRANSA specifies the form of op( A ) to be used in
!           the matrix multiplication as follows:
!
!              TRANSA = 'N' or 'n',  op( A ) = A.
!
!              TRANSA = 'T' or 't',  op( A ) = A'.
!
!              TRANSA = 'C' or 'c',  op( A ) = A'.
!
!           Unchanged on exit.
!
!  TRANSB - CHARACTER*1.
!           On entry, TRANSB specifies the form of op( B ) to be used in
!           the matrix multiplication as follows:
!
!              TRANSB = 'N' or 'n',  op( B ) = B.
!
!              TRANSB = 'T' or 't',  op( B ) = B'.
!
!              TRANSB = 'C' or 'c',  op( B ) = B'.
!
!           Unchanged on exit.
!
!  M      - INTEGER.
!           On entry,  M  specifies  the number  of rows  of the  matrix
!           op( A )  and of the  matrix  C.  M  must  be at least  zero.
!           Unchanged on exit.
!
!  N      - INTEGER.
!           On entry,  N  specifies the number  of columns of the matrix
!           op( B ) and the number of columns of the matrix C. N must be
!           at least zero.
!           Unchanged on exit.
!
!  K      - INTEGER.
!           On entry,  K  specifies  the number of columns of the matrix
!           op( A ) and the number of rows of the matrix op( B ). K must
!           be at least  zero.
!           Unchanged on exit.
!
!  ALPHA  - REAL            .
!           On entry, ALPHA specifies the scalar alpha.
!           Unchanged on exit.
!
!  A      - REAL             array of DIMENSION ( LDA, ka ), where ka is
!           k  when  TRANSA = 'N' or 'n',  and is  m  otherwise.
!           Before entry with  TRANSA = 'N' or 'n',  the leading  m by k
!           part of the array  A  must contain the matrix  A,  otherwise
!           the leading  k by m  part of the array  A  must contain  the
!           matrix A.
!           Unchanged on exit.
!
!  LDA    - INTEGER.
!           On entry, LDA specifies the first dimension of A as declared
!           in the calling (sub) program. When  TRANSA = 'N' or 'n' then
!           LDA must be at least  max( 1, m ), otherwise  LDA must be at
!           least  max( 1, k ).
!           Unchanged on exit.
!
!  B      - REAL             array of DIMENSION ( LDB, kb ), where kb is
!           n  when  TRANSB = 'N' or 'n',  and is  k  otherwise.
!           Before entry with  TRANSB = 'N' or 'n',  the leading  k by n
!           part of the array  B  must contain the matrix  B,  otherwise
!           the leading  n by k  part of the array  B  must contain  the
!           matrix B.
!           Unchanged on exit.
!
!  LDB    - INTEGER.
!           On entry, LDB specifies the first dimension of B as declared
!           in the calling (sub) program. When  TRANSB = 'N' or 'n' then
!           LDB must be at least  max( 1, k ), otherwise  LDB must be at
!           least  max( 1, n ).
!           Unchanged on exit.
!
!  BETA   - REAL            .
!           On entry,  BETA  specifies the scalar  beta.  When  BETA  is
!           supplied as zero then C need not be set on input.
!           Unchanged on exit.
!
!  C      - REAL             array of DIMENSION ( LDC, n ).
!           Before entry, the leading  m by n  part of the array  C must
!           contain the matrix  C,  except when  beta  is zero, in which
!           case C need not be set on entry.
!           On exit, the array  C  is overwritten by the  m by n  matrix
!           ( alpha*op( A )*op( B ) + beta*C ).
!
!  LDC    - INTEGER.
!           On entry, LDC specifies the first dimension of C as declared
!           in  the  calling  (sub)  program.   LDC  must  be  at  least
!           max( 1, m ).
!           Unchanged on exit.
!
!***REFERENCES  Dongarra, J., Du Croz, J., Duff, I., and Hammarling, S.
!                 A set of level 3 basic linear algebra subprograms.
!                 ACM TOMS, Vol. 16, No. 1, pp. 1-17, March 1990.
!***ROUTINES CALLED  LSAME, XERBLA
!***REVISION HISTORY  (YYMMDD)
!   890208  DATE WRITTEN
!   910605  Modified to meet SLATEC prologue standards.  Only comment
!           lines were modified.  (BKS)
!***END PROLOGUE  SGEMM
!     .. Scalar Arguments ..
      CHARACTER*1        TRANSA, TRANSB
      INTEGER            M, N, K, LDA, LDB, LDC
      REAL               ALPHA, BETA
!     .. Array Arguments ..
      REAL               A( LDA, * ), B( LDB, * ), C( LDC, * )
!     .. External Functions ..
      LOGICAL            LSAME
      EXTERNAL           LSAME
!     .. External Subroutines ..
!CCCC EXTERNAL           XERBLA
!     .. Intrinsic Functions ..
      INTRINSIC          MAX
!     .. Local Scalars ..
      LOGICAL            NOTA, NOTB
      INTEGER            I, INFO, J, L, NCOLA, NROWA, NROWB
      REAL               TEMP
!     .. Parameters ..
      REAL               ONE         , ZERO
      PARAMETER        ( ONE = 1.0E+0, ZERO = 0.0E+0 )
!
      CHARACTER*4 IERROR
!
      INCLUDE 'DPCOP2.INC'
!
!***FIRST EXECUTABLE STATEMENT  SGEMM
!
!     Set  NOTA  and  NOTB  as  true if  A  and  B  respectively are not
!     transposed and set  NROWA, NCOLA and  NROWB  as the number of rows
!     and  columns of  A  and the  number of  rows  of  B  respectively.
!
      IERROR='NO'
!
      NOTA  = LSAME( TRANSA, 'N' )
      NOTB  = LSAME( TRANSB, 'N' )
      IF( NOTA )THEN
         NROWA = M
         NCOLA = K
      ELSE
         NROWA = K
         NCOLA = M
      END IF
      IF( NOTB )THEN
         NROWB = K
      ELSE
         NROWB = N
      END IF
!
!     Test the input parameters.
!
      INFO = 0
      IF(      ( .NOT.NOTA                 ).AND.   &
               ( .NOT.LSAME( TRANSA, 'C' ) ).AND.   &
               ( .NOT.LSAME( TRANSA, 'T' ) )      )THEN
         INFO = 1
      ELSE IF( ( .NOT.NOTB                 ).AND.   &
               ( .NOT.LSAME( TRANSB, 'C' ) ).AND.   &
               ( .NOT.LSAME( TRANSB, 'T' ) )      )THEN
         INFO = 2
      ELSE IF( M  .LT.0               )THEN
         INFO = 3
      ELSE IF( N  .LT.0               )THEN
         INFO = 4
      ELSE IF( K  .LT.0               )THEN
         INFO = 5
      ELSE IF( LDA.LT.MAX( 1, NROWA ) )THEN
         INFO = 8
      ELSE IF( LDB.LT.MAX( 1, NROWB ) )THEN
         INFO = 10
      ELSE IF( LDC.LT.MAX( 1, M     ) )THEN
         INFO = 13
      END IF
      IF( INFO.NE.0 )THEN
!CCCC    CALL XERBLA( 'SGEMM ', INFO )
         WRITE(ICOUT,1001)
         CALL DPWRST('XXX','BUG ')
         IERROR='YES'
 1001 FORMAT('***** INTERNAL ERROR FROM SGEMM, INVALID',   &
      ' ARGUMENTS.')
         RETURN
      END IF
!
!     Quick return if possible.
!
      IF( ( M.EQ.0 ).OR.( N.EQ.0 ).OR.   &
          ( ( ( ALPHA.EQ.ZERO ).OR.( K.EQ.0 ) ).AND.( BETA.EQ.ONE ) ) )   &
         RETURN
!
!     And if  alpha.eq.zero.
!
      IF( ALPHA.EQ.ZERO )THEN
         IF( BETA.EQ.ZERO )THEN
            DO 20, J = 1, N
               DO 10, I = 1, M
                  C( I, J ) = ZERO
   10          CONTINUE
   20       CONTINUE
         ELSE
            DO 40, J = 1, N
               DO 30, I = 1, M
                  C( I, J ) = BETA*C( I, J )
   30          CONTINUE
   40       CONTINUE
         END IF
         RETURN
      END IF
!
!     Start the operations.
!
      IF( NOTB )THEN
         IF( NOTA )THEN
!
!           Form  C := alpha*A*B + beta*C.
!
            DO 90, J = 1, N
               IF( BETA.EQ.ZERO )THEN
                  DO 50, I = 1, M
                     C( I, J ) = ZERO
   50             CONTINUE
               ELSE IF( BETA.NE.ONE )THEN
                  DO 60, I = 1, M
                     C( I, J ) = BETA*C( I, J )
   60             CONTINUE
               END IF
               DO 80, L = 1, K
                  IF( B( L, J ).NE.ZERO )THEN
                     TEMP = ALPHA*B( L, J )
                     DO 70, I = 1, M
                        C( I, J ) = C( I, J ) + TEMP*A( I, L )
   70                CONTINUE
                  END IF
   80          CONTINUE
   90       CONTINUE
         ELSE
!
!           Form  C := alpha*A'*B + beta*C
!
            DO 120, J = 1, N
               DO 110, I = 1, M
                  TEMP = ZERO
                  DO 100, L = 1, K
                     TEMP = TEMP + A( L, I )*B( L, J )
  100             CONTINUE
                  IF( BETA.EQ.ZERO )THEN
                     C( I, J ) = ALPHA*TEMP
                  ELSE
                     C( I, J ) = ALPHA*TEMP + BETA*C( I, J )
                  END IF
  110          CONTINUE
  120       CONTINUE
         END IF
      ELSE
         IF( NOTA )THEN
!
!           Form  C := alpha*A*B' + beta*C
!
            DO 170, J = 1, N
               IF( BETA.EQ.ZERO )THEN
                  DO 130, I = 1, M
                     C( I, J ) = ZERO
  130             CONTINUE
               ELSE IF( BETA.NE.ONE )THEN
                  DO 140, I = 1, M
                     C( I, J ) = BETA*C( I, J )
  140             CONTINUE
               END IF
               DO 160, L = 1, K
                  IF( B( J, L ).NE.ZERO )THEN
                     TEMP = ALPHA*B( J, L )
                     DO 150, I = 1, M
                        C( I, J ) = C( I, J ) + TEMP*A( I, L )
  150                CONTINUE
                  END IF
  160          CONTINUE
  170       CONTINUE
         ELSE
!
!           Form  C := alpha*A'*B' + beta*C
!
            DO 200, J = 1, N
               DO 190, I = 1, M
                  TEMP = ZERO
                  DO 180, L = 1, K
                     TEMP = TEMP + A( L, I )*B( J, L )
  180             CONTINUE
                  IF( BETA.EQ.ZERO )THEN
                     C( I, J ) = ALPHA*TEMP
                  ELSE
                     C( I, J ) = ALPHA*TEMP + BETA*C( I, J )
                  END IF
  190          CONTINUE
  200       CONTINUE
         END IF
      END IF
!
      RETURN
!
!     End of SGEMM .
!
      END SUBROUTINE SGEMM 
      SUBROUTINE SGTSL(N,C,D,E,B,INFO)
!***BEGIN PROLOGUE  SGTSL
!***DATE WRITTEN   780814   (YYMMDD)
!***REVISION DATE  820801   (YYMMDD)
!***CATEGORY NO.  D2A2A
!***KEYWORDS  LINEAR ALGEBRA,LINPACK,MATRIX,SOLVE,TRIDIAGONAL
!***AUTHOR  DONGARRA, J., (ANL)
!***PURPOSE  Solves the system A*X=B where a is TRIDIAGONAL
!***DESCRIPTION
!
!     SGTSL given a general tridiagonal matrix and a right hand
!     side will find the solution.
!
!     On Entry
!
!        N       INTEGER
!                is the order of the tridiagonal matrix.
!
!        C       REAL(N)
!                is the subdiagonal of the tridiagonal matrix.
!                C(2) through C(N) should contain the subdiagonal.
!                On output, C is destroyed.
!
!        D       REAL(N)
!                is the diagonal of the tridiagonal matrix.
!                On output, D is destroyed.
!
!        E       REAL(N)
!                is the superdiagonal of the tridiagonal matrix.
!                E(1) through E(N-1) should contain the superdiagonal.
!                On output, E is destroyed.
!
!        B       REAL(N)
!                is the right hand side vector.
!
!     On Return
!
!        B       is the solution vector.
!
!        INFO    INTEGER
!                = 0 normal value.
!                = K if the K-th element of the diagonal becomes
!                    exactly zero.  The subroutine returns when
!                    this is detected.
!
!     LINPACK.  This version dated 08/14/78 .
!     Jack Dongarra, Argonne National Laboratory.
!
!     No externals
!     Fortran ABS
!***REFERENCES  DONGARRA J.J., BUNCH J.R., MOLER C.B., STEWART G.W.,
!                 *LINPACK USERS  GUIDE*, SIAM, 1979.
!***ROUTINES CALLED  (NONE)
!***END PROLOGUE  SGTSL
      INTEGER N,INFO
      REAL C(1),D(1),E(1),B(1)
!
      INTEGER K,KB,KP1,NM1,NM2
      REAL T
!     BEGIN BLOCK PERMITTING ...EXITS TO 100
!
!***FIRST EXECUTABLE STATEMENT  SGTSL
         INFO = 0
         C(1) = D(1)
         NM1 = N - 1
         IF (NM1 .LT. 1) GO TO 40
            D(1) = E(1)
            E(1) = 0.0E0
            E(N) = 0.0E0
!
            DO 30 K = 1, NM1
               KP1 = K + 1
!
!              FIND THE LARGEST OF THE TWO ROWS
!
               IF (ABS(C(KP1)) .LT. ABS(C(K))) GO TO 10
!
!                 INTERCHANGE ROW
!
                  T = C(KP1)
                  C(KP1) = C(K)
                  C(K) = T
                  T = D(KP1)
                  D(KP1) = D(K)
                  D(K) = T
                  T = E(KP1)
                  E(KP1) = E(K)
                  E(K) = T
                  T = B(KP1)
                  B(KP1) = B(K)
                  B(K) = T
   10          CONTINUE
!
!              ZERO ELEMENTS
!
               IF (C(K) .NE. 0.0E0) GO TO 20
                  INFO = K
!     ............EXIT
                  GO TO 100
   20          CONTINUE
               T = -C(KP1)/C(K)
               C(KP1) = D(KP1) + T*D(K)
               D(KP1) = E(KP1) + T*E(K)
               E(KP1) = 0.0E0
               B(KP1) = B(KP1) + T*B(K)
   30       CONTINUE
   40    CONTINUE
         IF (C(N) .NE. 0.0E0) GO TO 50
            INFO = N
         GO TO 90
   50    CONTINUE
!
!           BACK SOLVE
!
            NM2 = N - 2
            B(N) = B(N)/C(N)
            IF (N .EQ. 1) GO TO 80
               B(NM1) = (B(NM1) - D(NM1)*B(N))/C(NM1)
               IF (NM2 .LT. 1) GO TO 70
               DO 60 KB = 1, NM2
                  K = NM2 - KB + 1
                  B(K) = (B(K) - D(K)*B(K+1) - E(K)*B(K+2))/C(K)
   60          CONTINUE
   70          CONTINUE
   80       CONTINUE
   90    CONTINUE
  100 CONTINUE
!
      RETURN
      END SUBROUTINE SGTSL
      SUBROUTINE SHANDI(Y,N,IWRITE,RIGHT,TEMP1,TEMP2,ICASE1,ICASE2,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE SHANNON DIVERSITY INDEX.
!
!              THE FOLLOWING CASES ARE SUPPORTED:
!
!              1) IF ICASE1 = 'RAW', THEN "Y" IS A GROUP-ID VARIABLE.
!                 DATAPLOT WILL GENERATE A FREQUENCY TABLE FOR THE
!                 GROUPS AND THEN COMPUTE THE SHANNON DIVERSITY INDEX AS
!
!                     H = {N*LOG(N) - SUM[i=1 to K][F(i)*LOG(F(i))]}/N
!
!                 WHERE N IS THE COUNT OVER ALL GROUPS, K IS THE NUMBER OF
!                 GROUPS, AND F(I) IS THE FREQUENCY OF THE I-TH GROUP.
!
!                 THIS STATISTIC IS THEN NORMALIZED BY DIVIDING BY LOG(K).
!
!             2) IF ICASE1 = 'SUMMARY', THEN
!
!                a) SUM THE VALUES IN Y.  IF THIS SUM EQUALS 1, THEN ASSUME
!                   THAT Y DENOTES THE PROPORTIONS FOR EACH GROUP AND
!                   COMPUTE THE STATISTIC AS
!
!                        H = -SUM[i=1 to K][P(i)*LOG(P(i))]
!
!                b) IF THE SUM IS NOT EQUAL TO 1, THEN ASSUME THAT Y DENOTES
!                   THE COUNTS FOR EACH GROUP AND COMPUTE THE STATISTIC AS
!                   FOR THE RAW CASE (I.E., JUST SKIP THE BINNING STEP).
!
!     INPUT  ARGUMENTS--Y      = THE SINGLE PRECISION VECTOR OF OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR Y.
!     OUTPUT ARGUMENTS--RIGHT  = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SHANNON DIVERSITY INDEX.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE SHANNON DIVERSITY INDEX.
!     REFERENCE--BRANI VIDAKOVIC (2011), "STATISTICS FOR
!                BIOENGINEERING SCIENCES: WITH MATLAB AND WINBUGS
!                SUPPORT", SPRINGER, P. 23.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--FREQUE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2011/12
!     ORIGINAL VERSION--DECEMBER  2011.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ICASE1
      CHARACTER*4 ICASE2
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
      DOUBLE PRECISION DSUM
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DYI
      DOUBLE PRECISION EPS
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA EPS /1.0D-12/
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='SHAN'
      ISUBN2='DI  '
      IERROR='NO'
      RIGHT=CPUMIN
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'ANDI')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF SHANDI--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N
   52   FORMAT('IBUGA3,ISUBRO,N = ',2(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,Y(I)
   56     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N.LT.1)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN SHANNON DIVERSITY INDEX--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE RESPONSE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      VARIABLES IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE NUMBER OF OBSERVATIONS      = ',I8)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(ICASE1.EQ.'RAW')THEN
        NUMVAR=1
        ND=0
        CALL FREQUE(Y,N,TEMP1,ND,NUMVAR,IWRITE,   &
                    TEMP2,K,IBUGA3,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
        DSUM=0.0D0
        DSUM2=0.0D0
        DO 1210 I=1,K
          ITEMP=INT(TEMP2(I)+0.5)
          IF(ITEMP.GT.0)THEN
            DYI=DBLE(ITEMP)
            DSUM=DSUM + DYI*DLOG(DYI)
            DSUM2=DSUM2 + DBLE(ITEMP)
          ENDIF
 1210   CONTINUE
        IF(DSUM2.LE.0.0D0)THEN
          IERROR='YES'
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,111)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1212)
 1212     FORMAT('      THE TOTAL FREQUENCY COUNT WAS NON-POSITIVE.')
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ELSE
          DTERM1=(DSUM2*DLOG(DSUM2) - DSUM)/DSUM2
          IF(ICASE2.EQ.'EQUI')THEN
            RIGHT=REAL(DTERM1)/DBLE(K)
          ELSE
            RIGHT=REAL(DTERM1)
          ENDIF
        ENDIF
      ELSE
        DSUM=0.0D0
        DO 2000 I=1,N
          IF(Y(I).LT.0.0)THEN
            IERROR='YES'
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,111)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,2012)
 2012       FORMAT('      A NEGATIVE PROPORTION OR COUNT WAS ',   &
                   'ENCOUNTERED.')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,2013)I,Y(I)
 2013       FORMAT('      ROW ',I8,' = ',G15.7)
            CALL DPWRST('XXX','BUG ')
            GO TO 9000
          ENDIF
          DSUM=DSUM + DBLE(Y(I))
 2000   CONTINUE
!
        IF(DABS(DSUM - 1.0D0).LE.EPS)THEN
          DSUM=0.0D0
          DO 2110 I=1,N
            IF(Y(I).GT.0.0)THEN
              DYI=DBLE(Y(I))
              DSUM=DSUM + DYI*DLOG(DYI)
            ENDIF
 2110     CONTINUE
          IF(ICASE2.EQ.'EQUI')THEN
            RIGHT=-REAL(DSUM)/LOG(REAL(N))
          ELSE
            RIGHT=-REAL(DSUM)
          ENDIF
        ELSE
          DSUM=0.0D0
          DSUM2=0.0D0
          DO 2210 I=1,N
            ITEMP=INT(Y(I)+0.5)
            IF(ITEMP.GT.0)THEN
              DYI=DBLE(ITEMP)
              DSUM=DSUM + DYI*DLOG(DYI)
              DSUM2=DSUM2 + DBLE(ITEMP)
            ENDIF
 2210     CONTINUE
          IF(DSUM2.LE.0.0D0)THEN
            IERROR='YES'
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,111)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,2212)
 2212       FORMAT('      THE TOTAL FREQUENCY COUNT WAS NON-POSITIVE.')
            CALL DPWRST('XXX','BUG ')
            GO TO 9000
          ELSE
            DTERM1=(DSUM2*DLOG(DSUM2) - DSUM)/DSUM2
            IF(ICASE2.EQ.'EQUI')THEN
              RIGHT=REAL(DTERM1)/LOG(REAL(N))
            ELSE
              RIGHT=REAL(DTERM1)
            ENDIF
          ENDIF
        ENDIF
      ENDIF
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)RIGHT
  811   FORMAT('THE SHANNON DIVERSITY INDEX = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'ANDI')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF SHANDI--')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE SHANDI
      SUBROUTINE SHMIDM(X,N,IWRITE,XTEMP,MAXNXT,XMIDM,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE SAMPLE SHORTEST HALF
!              MIDMEAN.  THE FORMULA FOR THIS STATISTIC IS
!
!                   M = SUM[i=k to k+m][X(i)]/m   FOR THE MINIMUM
!                                                 (X(k+m) - X(k))
!                       m = n/2              n ODD
!                       m = INT(n/2) + 1     n EVEN
!
!              THIS IS ESSENTIALLY AN ASYMETRIC VERSION OF THE MID-MEAN.
!              ALTHOUGH IT HAS RATHER LOW EFFICIENY (LOWER THAN THE
!              MEDIAN), IT IS LESS SENSITIVE TO ASYMMETRICALLY
!              DISTRIBUTED OUTLIERS.
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XMIDM  = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE SHORTEST HALF MIDMEAN.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE SAMPLE SHMIDMN.
!     OTHER DATAPAC   SUBROUTINES NEEDED--SORT.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--DAVID DUEWER (2008), "A COMPARISON OF LOCATION
!                 ESTIMATORS FOR INTERLABORATORY DATA CONTAMINATED
!                 WITH VALUE AND UNCERTAINTY OUTLIERS",
!                 ACCREDITED QUALITY ASSURANCE, VOL. 13, PP. 193-216.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2017.02
!     ORIGINAL VERSION--FEBRUARY  2017.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DK
      DOUBLE PRECISION DX
      DOUBLE PRECISION DSUM
!
      DIMENSION X(*)
      DIMENSION XTEMP(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='SHMI'
      ISUBN2='DM  '
      IERROR='NO'
      XMIDM=CPUMIN
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF SHMIDM--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)ISUBRO,IBUGA3,N
   52   FORMAT('ISUBRO,IBUGA3,N = ',2(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ***********************
!               **  COMPUTE SHMIDMN  **
!               ***********************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.LT.1 .OR. N.GT.MAXNXT)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN SHORTEST HALF MIDMEAN--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS IN THE RESPONSE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,115)MAXNXT
  115   FORMAT('      MUST BE BETWEEN 1 AND ',I8,' (INCLUSIVELY).')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,116)
  116   FORMAT('      SUCH WAS NOT THE CASE HERE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS HERE = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(N.EQ.1)THEN
        XMIDM=X(1)
        GO TO 800
      ELSEIF(N.EQ.2)THEN
        XMIDM=(X(1)+X(2))/2.0
        GO TO 800
      ELSEIF(N.EQ.3)THEN
        XMIDM=(X(1)+X(2)+X(3))/3.0
        GO TO 800
      ENDIF
!
      HOLD=X(1)
      DO 135 I=2,N
        IF(X(I).NE.HOLD)GO TO 139
  135 CONTINUE
      XMIDM=HOLD
      GO TO 800
  139 CONTINUE
!
!               ****************************
!               **  STEP 2--              **
!               **  COMPUTE THE SHMIDMN.  **
!               ****************************
!
      CALL SORT(X,N,XTEMP)
!
!     FIND K
!
      M=(N/2)
      IF(MOD(N,2).EQ.1)M=M+1
      NLAST=N-M
      DIFF=XTEMP(1+M)-XTEMP(1)
      K=1
      DO 200 I=2,NLAST
        HOLD=XTEMP(I+M) - XTEMP(I)
        IF(HOLD.LT.DIFF)THEN
          DIFF=HOLD
          K=I
        ENDIF
  200 CONTINUE
!
      DSUM=0.0
      DO 210 I=K,K+M
        DX=XTEMP(I)
        DSUM=DSUM+DX
  210 CONTINUE
      DK=DBLE(M+1)
      XMIDM=DSUM/DK
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
  800 CONTINUE
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,821)N,XMIDM
  821   FORMAT('THE SHORTEST HALF MIDMEAN OF THE ',I8,   &
               ' OBSERVATIONS = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF SHMIDM--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA3,IERROR,K,M,XMIIDM
 9012   FORMAT('IBUGA3,IERROR,K,M,XMIDM = ',2(A4,2X),2I8,G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE SHMIDM
      SUBROUTINE SHMIDR(X,N,IWRITE,XTEMP,MAXNXT,XMIDR,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE SAMPLE SHORTEST HALF
!              MIDRANGE.  THE FORMULA FOR THIS STATISTIC IS
!
!                   SHMIDRM = (X(k) + X(k+m))/2   FOR THE MINIMUM
!                                                 (X(k+m) - X(k))
!                       m = n/2              n ODD
!                       m = INT(n/2) + 1     n EVEN
!
!              THIS IS ESSENTIALLY AN ASYMETRIC VERSION OF THE MID-RANGE.
!              ALTHOUGH IT HAS RATHER LOW EFFICIENY (LOWER THAN THE
!              MEDIAN), IT IS LESS SENSITIVE TO ASYMMETRICALLY
!              DISTRIBUTED OUTLIERS.
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XMIDR  = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE SHORTEST HALF MIDRANGE.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE SAMPLE SHMIDR.
!     OTHER DATAPAC   SUBROUTINES NEEDED--SORT.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--DAVID DUEWER (2008), "A COMPARISON OF LOCATION
!                 ESTIMATORS FOR INTERLABORATORY DATA CONTAMINATED
!                 WITH VALUE AND UNCERTAINTY OUTLIERS",
!                 ACCREDITED QUALITY ASSURANCE, VOL. 13, PP. 193-216.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2017.02
!     ORIGINAL VERSION--FEBRUARY  2017.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION XTEMP(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='SHMI'
      ISUBN2='DR  '
      IERROR='NO'
      XMIDR=CPUMIN
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF SHMIDR--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)ISUBRO,IBUGA3,N
   52   FORMAT('ISUBRO,IBUGA3,N = ',2(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ***********************
!               **  COMPUTE SHMIDRN  **
!               ***********************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.LT.1 .OR. N.GT.MAXNXT)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN SHORTEST HALF MIDRANGE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS IN THE RESPONSE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,115)MAXNXT
  115   FORMAT('      MUST BE BETWEEN 1 AND ',I8,' (INCLUSIVELY).')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,116)
  116   FORMAT('      SUCH WAS NOT THE CASE HERE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS HERE = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(N.EQ.1)THEN
        XMIDR=X(1)
        GO TO 800
      ELSEIF(N.EQ.2)THEN
        XMIDR=(X(1)+X(2))/2.0
        GO TO 800
      ELSEIF(N.EQ.3)THEN
        XMIDR=(X(1)+X(2)+X(3))/3.0
        GO TO 800
      ENDIF
!
      HOLD=X(1)
      DO 135 I=2,N
        IF(X(I).NE.HOLD)GO TO 139
  135 CONTINUE
      XMIDR=HOLD
      GO TO 800
  139 CONTINUE
!
!               ****************************
!               **  STEP 2--              **
!               **  COMPUTE THE SHMIDRN.  **
!               ****************************
!
      CALL SORT(X,N,XTEMP)
!
!     FIND K
!
      M=(N/2)
      IF(MOD(N,2).EQ.1)M=M+1
      NLAST=N-M
      DIFF=XTEMP(1+M)-XTEMP(1)
      K=1
      DO 200 I=2,NLAST
        HOLD=XTEMP(I+M) - XTEMP(I)
        IF(HOLD.LT.DIFF)THEN
          DIFF=HOLD
          K=I
        ENDIF
  200 CONTINUE
!
      XMIDR=(XTEMP(K) + XTEMP(K+M))/2.0
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
  800 CONTINUE
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,821)N,XMIDR
  821   FORMAT('THE SHORTEST HALF MIDRANGE OF THE ',I8,   &
               ' OBSERVATIONS = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF SHMIDR--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA3,IERROR,K,M,XMIIDM
 9012   FORMAT('IBUGA3,IERROR,K,M,XMIDR = ',2(A4,2X),2I8,G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE SHMIDR
      SUBROUTINE SIMPDI(Y,N,IWRITE,RIGHT,TEMP1,TEMP2,ICASE1,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE SIMPSON DIVERSITY INDEX.
!
!              THE FOLLOWING CASES ARE SUPPORTED:
!
!              1) IF ICASE1 = 'RAW', THEN "Y" IS A GROUP-ID VARIABLE.
!                 DATAPLOT WILL GENERATE A FREQUENCY TABLE FOR THE
!                 GROUPS AND THEN COMPUTE THE SIMPSON DIVERSITY INDEX AS
!
!                     D = SUM[i=1 TO K][(F(i)/N)**2]
!
!                 WHERE N IS THE COUNT OVER ALL GROUPS, K IS THE NUMBER OF
!                 GROUPS, AND F(i) IS THE FREQUENCY OF THE i-TH GROUP.
!
!             2) IF ICASE1 = 'SUMMARY', THEN
!
!                a) SUM THE VALUES IN Y.  IF THIS SUM EQUALS 1, THEN ASSUME
!                   THAT Y DENOTES THE PROPORTIONS FOR EACH GROUP AND
!                   COMPUTE THE STATISTIC AS
!
!                        D = SUM[i=1 TO K][P(i)**2]
!
!                b) IF THE SUM IS NOT EQUAL TO 1, THEN ASSUME THAT Y
!                   DENOTES THE COUNTS FOR EACH GROUP AND COMPUTE THE
!                   STATISTIC AS FOR THE RAW CASE (I.E., JUST SKIP THE
!                   BINNING STEP).
!
!     INPUT  ARGUMENTS--Y      = THE SINGLE PRECISION VECTOR OF OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR Y.
!     OUTPUT ARGUMENTS--RIGHT  = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SIMPSON DIVERSITY INDEX.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE SIMPSON DIVERSITY INDEX.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--FREQUE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2011/12
!     ORIGINAL VERSION--DECEMBER  2011.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ICASE1
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
      DOUBLE PRECISION DSUM
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DYI
      DOUBLE PRECISION EPS
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA EPS /1.0D-12/
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='SIMP'
      ISUBN2='DI  '
      IERROR='NO'
      RIGHT=CPUMIN
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MPDI')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF SIMPDI--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N
   52   FORMAT('IBUGA3,ISUBRO,N = ',2(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,Y(I)
   56     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N.LT.1)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN SIMPSON DIVERSITY INDEX--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE RESPONSE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      VARIABLES IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE NUMBER OF OBSERVATIONS      = ',I8)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(ICASE1.EQ.'RAW')THEN
        NUMVAR=1
        ND=0
        CALL FREQUE(Y,N,TEMP1,ND,NUMVAR,IWRITE,   &
                    TEMP2,K,IBUGA3,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
        DSUM=0.0D0
        DSUM2=0.0D0
        DO 1210 I=1,K
          ITEMP=INT(TEMP2(I)+0.5)
          IF(ITEMP.GT.0)THEN
            DYI=DBLE(ITEMP)
            DSUM=DSUM + DYI**2
            DSUM2=DSUM2 + DBLE(ITEMP)
          ENDIF
 1210   CONTINUE
        IF(DSUM2.LE.0.0D0)THEN
          IERROR='YES'
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,111)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1212)
 1212     FORMAT('      THE TOTAL FREQUENCY COUNT WAS NON-POSITIVE.')
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ELSE
          DTERM1=DSUM/DSUM2**2
          RIGHT=REAL(DTERM1)
        ENDIF
      ELSE
        DSUM=0.0D0
        DO 2000 I=1,N
          IF(Y(I).LT.0.0)THEN
            IERROR='YES'
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,111)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,2012)
 2012       FORMAT('      A NEGATIVE PROPORTION OR COUNT WAS ',   &
                   'ENCOUNTERED.')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,2013)I,Y(I)
 2013       FORMAT('      ROW ',I8,' = ',G15.7)
            CALL DPWRST('XXX','BUG ')
            GO TO 9000
          ENDIF
          DSUM=DSUM + DBLE(Y(I))
 2000   CONTINUE
!
        IF(DABS(DSUM - 1.0D0).LE.EPS)THEN
          DSUM=0.0D0
          DO 2110 I=1,N
            IF(Y(I).GT.0.0)THEN
              DYI=DBLE(Y(I))
              DSUM=DSUM + DYI**2
            ENDIF
 2110     CONTINUE
          RIGHT=REAL(DSUM)
        ELSE
          DSUM=0.0D0
          DSUM2=0.0D0
          DO 2210 I=1,N
            ITEMP=INT(Y(I)+0.5)
            IF(ITEMP.GT.0)THEN
              DYI=DBLE(ITEMP)
              DSUM=DSUM + DYI**2
              DSUM2=DSUM2 + DBLE(ITEMP)
            ENDIF
 2210     CONTINUE
          IF(DSUM2.LE.0.0D0)THEN
            IERROR='YES'
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,111)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,2212)
 2212       FORMAT('      THE TOTAL FREQUENCY COUNT WAS NON-POSITIVE.')
            CALL DPWRST('XXX','BUG ')
            GO TO 9000
          ELSE
            DTERM1=DSUM/DSUM2**2
            RIGHT=REAL(DTERM1)
          ENDIF
        ENDIF
      ENDIF
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)RIGHT
  811   FORMAT('THE SIMPSON DIVERSITY INDEX = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MPDI')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF SIMPDI--')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE SIMPDI
      SUBROUTINE SHIFTC(X,N1,NSHIFT,MAXOBV,Y,N2,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE SETS THE VECTOR Y EQUAL TO THE
!              VECTOR Y AND THEN CIRCULAR SHIFTS THE ELEMENTS IN Y
!              EITHER TO THE LEFT (IF NSHIFT < 0) OR TO THE RIGHT
!              (IF NSHIFT > 0).
!     INPUT  ARGUMENTS--X      = A SINGLE PRECISION VECTOR CONTAINING
!                                THE DATA TO BE SHIFTED.
!                     --N1     = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE INPUT VECTOR.
!                     --NSHIFT = THE INTEGER NUMBER THAT SPECIFIES
!                                THE NUMBER OF ELEMENTS TO SHIFT
!     OUTPUT ARGUMENTS--Y      = THE OUTPUT ARRAY THAT WILL CONTAIN
!                                SHIFTED ELEMENTS.
!                     --N2     = THE NUMBER OF ELEMENTS IN THE OUTPUT
!                                ARRAY.
!     OUTPUT--THE COMPUTED SINGLE PRECISION ARRAY Y.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2009.6
!     ORIGINAL VERSION--JUNE      2009.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!
      INTEGER N1
      INTEGER N2
      INTEGER NSHIFT
      REAL X(*)
      REAL Y(*)
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'IFTC')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF SHIFTC--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N1,MAXOBV
   52   FORMAT('IBUGA3,ISUBRO,N1,MAXOBV = ',2(A4,2X),2I8)
        CALL DPWRST('XXX','BUG ')
        IF(N1.GT.0)THEN
          DO 55 I=1,N1
            WRITE(ICOUT,56)I,X(I)
   56       FORMAT('I,X(I) = ',I8,2X,G15.7)
            CALL DPWRST('XXX','BUG ')
   55     CONTINUE
        ENDIF
      ENDIF
!
      NTEMP=0
!
      IF(N1.LT.1)THEN
        WRITE(ICOUT,1011)
 1011   FORMAT('***** ERROR IN CIRCULAR SHIFT OPERATION--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1013)N1
 1013   FORMAT('      THE NUMBER OF ELEMENTS IN THE INPUT VARIABLE ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      DO 2000 I=1,N1
        Y(I)=X(I)
 2000 CONTINUE
!
      IF(NSHIFT.GT.0)THEN
        DO 2100 I=1,N1
          IINDX=MOD(I+NSHIFT-1,N1)+1
          Y(IINDX)=X(I)
!
          IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'IFTC')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,2101)I,NSHIFT,IINDX
 2101       FORMAT('I,NSHIFT,IINDX=',3I8)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
 2100   CONTINUE
      ELSEIF(NSHIFT.LT.0)THEN
!
        IF(ABS(NTEMP).LE.N1)THEN
          NTEMP=NSHIFT
        ELSE
          NTEMP=MOD(ABS(NSHIFT),N1)
        ENDIF
!
        DO 2200 I=1,N1
          IINDX=MOD(I-NTEMP-1,N1)+1
          Y(I)=X(IINDX)
!
          IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'IFTC')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,2201)I,NSHIFT,IINDX
 2201       FORMAT('I,NSHIFT,IINDX=',3I8)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
2200    CONTINUE
      ENDIF
!
      N2=N1
!
 9000 CONTINUE
