 9051   FORMAT('***** AT THE END OF SHIFTC--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9052)N2
 9052   FORMAT('N2 = ',I8)
        CALL DPWRST('XXX','BUG ')
