      SUBROUTINE SHIFTR(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                        IBUGO2,IERROR)
!
!     PURPOSE--SHIFT TO THE RIGHT (ONLY)
!              THE IHARG,IHARG2,IARG,ARG, AND IARGT VECTORS
!              AND ADJUST THE VALUE OF NUMARG ACCORDINGLY.
!              THE ADJUSTMENT RESULTS IN
!              ALL ELEMENTS BEING SHIFTED
