      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF SHIFTR--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)ISHIFT,NUMARG
 9012 FORMAT('ISHIFT,NUMARG = ',2I8)
      CALL DPWRST('XXX','BUG ')
      DO 9015 I=1,NUMARG
      WRITE(ICOUT,9016)I,IHARG(I),IHARG2(I),IARG(I),ARG(I),IARGT(I)
 9016 FORMAT('I,IHARG(I),IHARG2(I),IARG(I),ARG(I),IARGT(I) = ',   &
      I8,2X,A4,A4,I8,E15.7,2X,A4)
      CALL DPWRST('XXX','BUG ')
 9015 CONTINUE
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE SHIFTR
      SUBROUTINE SHIFTZ(X,N1,NSHIFT,MAXOBV,Y,N2,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE SETS THE VECTOR Y EQUAL TO THE
!              VECTOR Y AND THEN SHIFTS THE ELEMENTS IN Y EITHER
!              TO THE LEFT (IF NSHIFT < 0) OR TO THE RIGHT
!              (IF NSHIFT > 0).
!     INPUT  ARGUMENTS--X      = A SINGLE PRECISION VECTOR CONTAINING
!                                THE DATA TO BE SHIFTED.
!                     --N1     = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE INPUT VECTOR.
!                     --NSHIFT = THE INTEGER NUMBER THAT SPECIFIES
!                                THE NUMBER OF ELEMENTS TO SHIFT
!     OUTPUT ARGUMENTS--Y      = THE OUTPUT ARRAY THAT WILL CONTAIN
!                                SHIFTED ELEMENTS.
!                     --N2     = THE NUMBER OF ELEMENTS IN THE OUTPUT
!                                ARRAY.
!     OUTPUT--THE COMPUTED SINGLE PRECISION ARRAY Y.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2009.2
!     ORIGINAL VERSION--FEBRUARY  2009.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!
      INTEGER N1
      INTEGER N2
      INTEGER NSHIFT
      REAL X(*)
      REAL Y(*)
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'IFTZ')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF SHIFTZ--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N1
   52   FORMAT('IBUGA3,ISUBRO,N1 = ',A4,2X,A4,2X,I8)
        CALL DPWRST('XXX','BUG ')
        IF(N1.GT.0)THEN
          DO 55 I=1,N1
            WRITE(ICOUT,56)I,X(I)
   56       FORMAT('I,X(I) = ',I8,2X,G15.7)
            CALL DPWRST('XXX','BUG ')
   55     CONTINUE
        ENDIF
      ENDIF
!
      IF(N1.LT.1)THEN
        WRITE(ICOUT,1011)
 1011   FORMAT('***** ERROR IN SHIFT OPERATION--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1013)N1
 1013   FORMAT('      THE NUMBER OF ELEMENTS IN THE INPUT VARIABLE ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      DO 2000 I=1,N1
        Y(I)=X(I)
 2000 CONTINUE
!
      IF(NSHIFT.GT.0)THEN
        N2=NSHIFT
        DO 2100 I=1,N1
          N2=N2+1
!
          IF(N2.GT.MAXOBV)THEN
            WRITE(ICOUT,1011)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,2113)
 2113       FORMAT('      THE MAXIMUM NUMBER OF ROWS FOR THE OUTPUT')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,2115)
 2115       FORMAT('      VARIABLE HAS BEEN EXCEEDED.')
            CALL DPWRST('XXX','BUG ')
            IERROR='YES'
            GO TO 9000
          ENDIF
!
          Y(N2)=X(I)
2100    CONTINUE
      ELSEIF(NSHIFT.LT.0)THEN
        ICNT=0
        NSTRT=ABS(NSHIFT)+1
        DO 2200 I=NSTRT,N1
          ICNT=ICNT+1
          Y(ICNT)=X(I)
2200    CONTINUE
        N2=N1
      ENDIF
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'IFTZ')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9051)
 9051   FORMAT('***** AT THE END OF SHIFTZ--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9052)N2
 9052   FORMAT('N2 = ',I8)
        CALL DPWRST('XXX','BUG ')
        IF(N2.GT.0)THEN
          DO 9055 I=1,N1
            WRITE(ICOUT,9056)I,Y(I)
 9056       FORMAT('I,Y(I) = ',I8,2X,G15.7)
            CALL DPWRST('XXX','BUG ')
 9055     CONTINUE
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE SHIFTZ
      SUBROUTINE SICIEI(IC,X,SI,CI,CII,EI,EXNEI,SHI,CHI,CHII,IERR)
!
!                         APPENDIX
!
!                   IMPLEMENTING PROGRAM
! LANGUAGE. AMERICAN NATIONAL STANDARD FORTRAN
! DEFINITIONS. X, A REAL VARIABLE
!     SI(X) =INTEGRAL(SIN T/T)DT FROM 0 TO X
!     SI(-X)=-SI(X)
!     CI(X) =GAMMA+LN X+INTEGRAL((COS T-1)/T)DT FROM 0 TO X
!     CI(-X)=CI(X)-I PI
!     EI(X) =-P.V.INTEGRAL(EXP(-T)/T)DT FROM -X TO INFINITY
!     EXNEI(X)=EXP(-X)*EI(X)                      (X .GT. 0)
!         INTEGRAL(EXP(-T)/T) DT FROM X TO INFINITY, OFTEN
!         DENOTED BY -EI(-X)=E1(X). (SEE AUTOMATIC COMPUTING
!         METHODS FOR SPECIAL FUNCTIONS, PART II. THE EXPO-
!         NENTIAL INTEGRAL EN(X), J. OF RESEARCH NBS, 78B,
!         OCTOBER-DECEMBER 1974, PP. 199-216.)
!     SHI(X) =INTEGRAL(SINH T/T)DT FROM 0 TO X
!     SHI(-X)=-SHI(X)
!     CHI(X)=GAMMA+LN X+INTEGRAL((COSH T-1)/T)DT FROM 0 TO X
!     CHI(-X)=CHI(X)-I PI
!                 GAMMA(EULER'S CONSTANT)=.5772156649...
!   SPECIAL CASES
!     X=0
!       SI(0)=SHI(0)=0
!       CI(0)=EI(0)=EXNEI(0)=CHI(0)=-INFINITY
!                                  =-MAX. MACH. VALUE (RINF)
!     LIMITING VALUES - X APPROACHES INFINITY
!       SI(X)=PI/2
!       CI(X)=0
!       EI(X)=SHI(X)=CHI(X)=INFINITY (RINF)
!       EXNEI(X)=0
! USAGE. CALL SICIEI (IC,X,SI,CI,CII,EI,EXNEI,SHI,CHI,CHII,
!                                                      IERR)
!     FORMAL PARAMETERS
!         IC      INTEGER TYPE                        INPUT
!                     IC  FUNCTIONS TO BE COMPUTED
!                      1    SI,CI
!                      2    EI,EXNEI
!                      3    EI,EXNEI,SHI,CHI
!                      4    SI,CI,EI,EXNEI,SHI,CHI
!         X       REAL OR DOUBLE PRECISION TYPE       INPUT
!         SI=SI(X)             (SAME TYPE AS X)       OUTPUT
!         CI+I CII=CI(X)              ''              OUTPUT
!         EI=EI(X)                    ''              OUTPUT
!         EXNEI=EXP(-X)*EI(X)         ''              OUTPUT
!         SHI=SHI(X)                  ''              OUTPUT
!         CHI+I CHII=CHI(X)           ''              OUTPUT
!         IERR    INTEGER TYPE                        OUTPUT
!                     IERR=0   X .GE. 0, NORMAL RETURN
!                     IERR=1   X .LT. 0, ERROR RETURN IF
!                                           IC=2
! MODIFICATIONS.
!     THE CODE IS SET UP FOR DOUBLE PRECISION COMPUTATION
!     WITH DOUBLE PRECISION TYPE STATEMENTS
!          DOUBLE PRECISION FUNCTION REFERENCES AND,PARTICU-
!     LARLY,FOR THE UNIVAC 1108 WITH (SEE DEFINITIONS BELOW)
!          RINF APPROX. 2**1023,ULSC=2**56,NBM=60 AND OTHER
!     CONSTANTS IN DOUBLE PRECISION FORMAT TO 19 SIGNIFICANT
!     FIGURES. ALL ABOVE ITEMS MUST BE CHANGED FOR SINGLE
!     PRECISION COMPUTATIONS WITH DATA ADJUSTMENTS FOR OTHER
!     COMPUTERS.
!   AUXILIARY FUNCTIONS
!       VARIOUS FUNCTIONS ARE AVAILABLE TO GREATER ACCURACY
!       AT INTERMEDIATE POINTS IN THE SUBROUTINE,NAMELY,
!           SI-(PI/2)=IMAG. PART OF THE CONTINUED FRACTION
!           CI(EI AND CHI)-GAMMA-LN X=SUM OF SERIES
!   CAUTION - THE SUBROUTINE CANNOT READILY BE ADAPTED TO
!             COMPUTE THE FUNCTIONS FOR COMPLEX ARGUMENTS.
! METHOD.   T=ABS(X)
!     POWER SERIES   T .LE. PSLSC(=2) FOR SI,CI
!                    T .LE. AELL(=-LN(TOLER)) FOR EI,SHI,CHI
!         SI=SUMS(SGN(RK)*TM(RK))  IP=-1  RK=1,3,...,RKO
!         CI=SUMC(SGN(RK)*TM(RK))  IP=+1  RK=2,4,...,RKE
!                +EULER+XLOG
!         SHI=SUMOT(TM(RK))        IP=-1  RK=1,3,...,RKO
!         CHI=SUMET(TM(RK))        IP=+1  RK=2,4,...,RKE
!                +EULER+XLOG
!         EI=SUMOT+SUMET+EULER+XLOG               (X .GT. 0)
!               SGN(1)=1
!               SGN(RK+1)=-SGN(RK)        RK=1,3,...
!               SGN(RK+1)=+SGN(RK)        RK=2,4,...
!               TM(RK)=((T**RK)/(1*2...RK))/RK
!                     =PTM(RK)/RK
!                   PTM(1)=T
!                   PTM(RK+1)=PTM(RK)*(T/(RK+1))   RK .GE. 1
!               IF TM(RK)/SUM .LT. TOLER
!                 RKE=RK WHERE SUM=ABS(SUMC)       IC=1 OR 4
!                              SUM=SUMET           IC=2 OR 3
!                                          IC=4,X .GT. PSLSC
!                 RKO=RK WHERE SUM=ABS(SUMS)       IC=1 OR 4
!                              SUM=SUMOT           IC=2 OR 3
!                                          IC=4,X .GT. PSLSC
!         EXNEI= EI/EXP(T/2)/EXP(T/2)
!              =(EI/EXPHT)/EXPHT
!     CONTINUED FRACTION    T .GT. PSLSC
!         -CI+I(SI-PI/2)=E1(IT)
!                       =EXP(-IT)*(1 I/I (1+IT)-
!                               1**2 I/I (3+IT)-
!                               2**2 I/I (5+IT)-...)
!                       =EXP(-IT)*II(AM(RM) I/I BM(RM))
!                                             RM=1,2,...,RMF
!                            AM(1)=1
!                            AM(RM)=-(RM-1)**2     RM .GT. 1
!                            BM(RM)=2*RM-1+IT=BMR+I BMI
!                       =EXP(-IT)*(FM/GM)
!                       =EXP(-IT)*(FMR+I FMI)/(GMR+I GMI)
!                       =EXP(-IT)*F(RM)
!                       =(COST-I SINT)*(FR+I FI)
!         -CI+I(SI-PI/2)=(FR*COST+FI*SINT)+
!                                         I(FI*COST-FR*SINT)
!                         IF RESQ(RM) .LE. TOLSQ(=TOLER**2)
!                             OR RESQ(RM) .GE. RESQ(RM-1)
!                               (RESQ .GE. RESQP)
!                         RMF=RM  WHERE
!                             RESQ=(MOD(1-F(RM-1)/F(RM)))**2
!     ASYMPTOTIC EXPANSION    T .GT. AELL
!         EI=(EXNEI*EXPHT)*EXPHT
!         EXNEI=(1+SUME(TM(RK)))/T            RK=1,2,...,RKF
!         SHI=CHI=EI/2
!             TM(RK)=(1*2...RK)/(T**RK)
!             TM(0)=1
!             TM(RK)=(RK/T)*TM(RK-1)               RK .GE. 1
!               IF TM(RK) .LT. TOLER (CONVERGENCE) RKF=RK OR
!                  TM(RK) .GE. TM(RK-1)(DIVERGENCE) RKF=RK-1
! RANGE.
!     FOR SI(X),CI(X), ABS(X) .LT. ULSC(UPPER LIMIT FOR
!                                           SIN,COS ROUTINE)
!         X=APPROXIMATELY 2**21, NBM=27
!                         2**56, NBM=60
!     FOR EXP(-X)*EI(X), X .LE. RINF
!     FOR EI(X), X .LT. XMAXEI (APPROXIMATELY 92.5,  NBC=8,
!                                            715.6,  NBC=11)
!                 NBC=NUMBER OF BINARY DIGITS IN THE BIASED
!                 CHARACTERISTIC OF A FLOATING POINT NUMBER
!     FOR SHI(X),CHI(X), ABS(X) .LT. XMAXHF
!         X=APPROXIMATELY 93.2,   NBC=8
!                        716.3,   NBC=11
! ACCURACY. THE MAXIMUM RELATIVE ERROR, EXCEPT FOR REGIONS
!           IN THE IMMEDIATE NEIGHBORHOOD OF ZEROS,ON THE
!           UNIVAC 1108 IS 4.5(-7) FOR SINGLE PRECISION COM-
!           PUTATION AND 7.5(-17) FOR DOUBLE PRECISION COM-
!           PUTATION.
! PRECISION. VARIABLE - BY SETTING THE DESIRED VALUE OF NBM
!                       OR A PREDETERMINED VALUE OF TOLER
! MAXIMUM     UNIVAC 1108 TIME/SHARING EXECUTIVE SYSTEM
! TIMING.      NBM=27   NBM=60
! (SECONDS)     .0093    .070
! STORAGE. 954 WORDS REQUIRED BY THE UNIVAC 1108 COMPILER
!
!
!          MACHINE DEPENDENT STATEMENTS
!               TYPE STATEMENTS
!
      INCLUDE 'DPCOMC.INC'
!
      DOUBLE PRECISION X,SI,CI,CII,EI,EXNEI,SHI,CHI,CHII
      DOUBLE PRECISION A,AELL,AM,AMIN,ASUMSC,   &
             BMI,BMR,COST,EXPL,EXPHT,   &
             FI,FIP,FMI,FMM1I,FMM1R,FMM2I,FMM2R,FMR,FR,FRP,   &
             GMI,GMM1I,GMM1R,GMM2I,GMM2R,GMR,   &
             PSLL,PSLSC,PTM,RE,RESQ,RESQP,RK,RM,   &
             SCC,SFMI,SFMR,SGMI,SGMR,SGN,   &
             SINT,SUMC,SUME,SUMEO,SUMET,SUMOT,SUMS,SUMSC,   &
             T,TEMP,TEMPA,TEMPB,TM,TMAX,TMM1,TOLER,TOLSQ,   &
             XLOG,XMAXEI,XMAXHF
      DOUBLE PRECISION RINF,ULSC,EULER,HALFPI,PI,ALOG2,   &
                       ZERO,ONE,TWO,FOUR
      DIMENSION A(4)
      EQUIVALENCE (FMR,A(1)), (FMI,A(2)), (GMR,A(3)),   &
                  (GMI,A(4))
!               CONSTANTS
      DATA EULER/.5772156649015328606D0/
      DATA HALFPI/1.570796326794896619D0/
      DATA PI/3.141592653589793238D0/
      DATA ALOG2/.6931471805599453094D0/
      DATA ZERO,ONE,TWO,FOUR /   &
           0.0D0,1.D0,2.D0,4.D0/
!                 RINF=MAXIMUM MACHINE VALUE
!                 ULSC=MAXIMUM ARGUMENT FOR SIN,COS ROUTINE
!                        APPROX. 2**(NBM-6) OR 10**(S-2)
!                                   (S=SIGNIFICANT FIGURES)
!                 NBM=ACCURACY DESIRED OR THE
!                     MAXIMUM NUMBER OF BINARY DIGITS IN THE
!                       MANTISSA OF A FLOATING POINT NUMBER
!                 TOLER=UPPER LIMIT FOR RELATIVE ERRORS
!                      =2**(-NBM)=APPROX. 10**(-S)
! TOLER PRECOMPUTED MAY BE INSERTED IN A DATA STATEMENT AND
! THE NBM DATA STATEMENT ELIMINATED
!CCCC DATA RINF/.8988465674311579538D308 /
!CCCC DATA ULSC/.72057594037927936D17/
!CCCC DATA NBM / 60 /
!
      RINF=D1MACH(2)
      NBM=I1MACH(14)
      ULSC=TWO**(NBM-6)
      TOLER=TWO**(-NBM)
!
! NOTE - ARGUMENT CHECKS PRECEDING FUNCTION REFERENCES
!        NECESSITATE ADDITIONAL MACHINE DEPENDENT STATEMENTS           0
!        IN THE STATEMENT NUMBER RANGE 140-150
!          INITIALIZATION OF OUTPUT FUNCTIONS
      SI=RINF
      CI=RINF
      CII=RINF
      EI=ZERO
      EXNEI=RINF
      SHI=ZERO
      CHI=ZERO
      CHII=RINF
!          VALIDITY CHECK ON INPUT PARAMETERS
!               INDICATOR CHECK
!                 SET IND=IC
!                   CHANGE IND=4 IF IC .LT. 1 OR .GT. 4
      IND=IC
      IF (IND .LT. 1) GO TO 10
      IF (IND .GT. 4) GO TO 10
      GO TO 20
  10  IND=4
!               ARGUMENT CHECK
!                 X .GE. 0    IERR=0
!                 X .LT. 0    IERR=1
!                             (ERROR RETURN IF IC=2)
  20  IERR=0
      T=X
  30  CONTINUE
!
!CCCC JUNE 2008: MODIFY FOLLOWING LINE SO THAT IT DOES NOT
!CCCC            GENERATE WARNING MESSAGES WITH FORTRAN 95 COMPILERS.
!
!CCCC IF (T) 40,50,90
      IF (T.LT.0) THEN
        GO TO 40
      ELSEIF (T.EQ.0) THEN
        GO TO 50
      ELSE
        GO TO 90
      ENDIF
  40  T=-T
      IF (IND .EQ. 1) GO TO 30
      IERR=1
      IF (IND .NE. 2) GO TO 30
      IF (X .LT. ZERO) RETURN
!          SPECIAL CASES
!               X=0
  50  CONTINUE
!CCCC IF (IND-2) 80,70,60
      IF (IND-2.LT.0) THEN
         GO TO 80
      ELSEIF (IND-2.EQ.0) THEN
         GO TO 70
      ELSE
         GO TO 60
      ENDIF
  60  SHI=ZERO
      CHI=-RINF
      CHII=ZERO
  70  EI=-RINF
      EXNEI=-RINF
      IF (IND .NE. 4) RETURN
  80  SI=ZERO
      CI=-RINF
      CII=ZERO
      RETURN
  90  IF (T .LT. ULSC) GO TO 140
!               ABS(X) .GE. ULSC
!CCCC IF (IND-2) 130,110,100
      IF (IND-2.LT.0) THEN
         GO TO 130
      ELSEIF (IND-2.EQ.0) THEN
         GO TO 110
      ELSE
         GO TO 100
      ENDIF
 100  SHI=RINF
      CHI=RINF
      CHII=ZERO
      IF (IERR .EQ. 1) GO TO 120
 110  EI=RINF
      EXNEI=(ONE+(ONE/T))/T
 120  IF (IND .NE. 4) GO TO 1000
 130  SI=HALFPI
      CI=ZERO
      CII=ZERO
      GO TO 1000
!          EVALUATIONS FOR ABS(X)(=T) .GT. 0 AND .LT. ULSC
!               ADDITIONAL MACHINE DEPENDENT STATEMENTS
!                    FUNCTION REFERENCES
!                    CONTROL VARIABLES
 140  XLOG=DLOG(T)
      SINT=DSIN(T)
      COST=DCOS(T)
      EXPL =DLOG(RINF)
      XMAXEI=EXPL+DLOG(EXPL+DLOG(EXPL)) -ONE/EXPL
      XMAXHF=XMAXEI+ALOG2
      AELL=-DLOG(TOLER)
      AMIN=ONE/RINF
      PSLL=TWO*DSQRT(AMIN)
      PSLSC=TWO
!               EXPONENTIAL FUNCTION DETERMINATION
      IF (T .LE. TOLER) GO TO 150
      IF (T .GE. XMAXHF) GO TO 160
      EXPHT=DEXP(T/TWO)
      GO TO 170
 150  EXPHT=ONE
      GO TO 170
 160  EXPHT=RINF
!               METHOD SELECTION
 170  IF (T .LE. PSLSC) GO TO 200
      IF (IND .EQ. 1) GO TO 500
      IF (IND .EQ. 4) GO TO 500
 180  IF (T .GT. AELL) GO TO 800
      GO TO 230
!                    INDICATOR TO COMPUTE EI,SHI,CHI
 190  IF (IND .EQ. 1) GO TO 1000
      IND=3
      GO TO 180
!                    METHOD --- POWER SERIES
!                      SI(X),CI(X),           T .LE. PSLSC
!                      EI(X),SHI(X),CHI(X),   T .LE. AELL
!                         LIMITING VALUES, T NEAR ZERO
 200  IF (T .GT. PSLL) GO TO 210
      SUMC=ZERO
      SUMET=ZERO
      SUMS=T
      SUMOT=T
      GO TO 360
!                         INITIALIZATION FOR SI,CI
 210  IF (IND .NE. 1) GO TO 230
 220  SUMS=ZERO
      SUMC=ZERO
      SUMSC=ZERO
      SGN=ONE
      GO TO 240
!                         INITIALIZATION FOR SHI,CHI(AND EI)
 230  SUMOT=ZERO
      SUMET=ZERO
      SUMEO=ZERO
      IF (IND .EQ. 4) GO TO 220
!                              IP -  INDICATOR FOR ODD OR
!                                      EVEN TERMS
 240  IP=-1
      RK=ONE
      PTM=T
!                         COMPUTATION OF (T**K)/(1*2...K)/K
 250  TM=PTM/RK
!                         SUMMATION FOR SI(CI)
        IF (IND .NE. 1) GO TO 310
 260    SUMSC=SGN*TM+SUMSC
!                         RELATIVE ERROR FOR SI(CI)
! PARTIAL SUM OF ALTERNATING ODD(EVEN) TERMS MAY EQUAL ZERO
        ASUMSC=SUMSC
 270    CONTINUE
!CCCC   IF (ASUMSC) 280,300,290
        IF (ASUMSC.LT.0) THEN
           GO TO 280
        ELSEIF (ASUMSC.EQ.0) THEN
           GO TO 300
        ELSE
           GO TO 290
        ENDIF
 280    ASUMSC=-ASUMSC
        GO TO 270
 290    RE=TM/ASUMSC
        GO TO 320
 300    RE=RINF
        GO TO 320
!                         SUMMATION FOR SHI(CHI)(AND EI)
 310    SUMEO=TM+SUMEO
        IF (IND .EQ. 4) GO TO 260
!                         RELATIVE ERROR FOR SHI(CHI)
        RE=TM/SUMEO
!                         SIGN CHANGE AND SELECTION
!                         OF SUMS OF ODD(EVEN) TERMS
 320    IF (IP .EQ. 1) GO TO 330
        SGN=-SGN
        SUMS=SUMSC
        SUMSC=SUMC
        SUMOT=SUMEO
        SUMEO=SUMET
        GO TO 340
 330    SUMC=SUMSC
        SUMSC=SUMS
        SUMET=SUMEO
        SUMEO=SUMOT
!                         RELATIVE ERROR CHECK
 340    IF (RE .LT. TOLER) GO TO 360
!                         ADDITIONAL TERMS
        RK=RK+ONE
!                              UNDERFLOW TEST
! UNDERFLOWS AFFECTING ACCURACY ARE AVOIDED. ALL OTHER
! UNDERFLOWS ARE ASSUMED TO BE SET EQUAL TO ZERO
        IF (T .GT. PSLSC) GO TO 350
        IF (PTM .LE. (AMIN*RK*RK)/T ) GO TO 360
 350    PTM=(T/RK)*PTM
        IP=-IP
        GO TO 250
!                         SI,CI EVALUATION
 360  IF (IND .NE. 1) GO TO 380
 370  SI=SUMS
      CI=(SUMC+XLOG)+EULER
      CII=ZERO
      GO TO 1000
!                         EI EVALUATION
 380  IF (X .LE. ZERO) GO TO 390
      EI=(SUMET+SUMOT+XLOG)+EULER
      EXNEI=(EI/EXPHT)/EXPHT
      IF (IND .EQ. 2) RETURN
!                         SHI,CHI EVALUATION
 390  SHI=SUMOT
      CHI=(EULER+SUMET)+XLOG
      CHII=ZERO
      IF (IND .NE. 4) GO TO 1000
      GO TO 370
!                    METHOD --- CONTINUED FRACTION
!                      SI(X),CI(X),       T .GT. PSLSC
!                      -CI(T) + I (SI(T)-HALFPI)=E1(IT)
!                         INITIALIZATION
 500  SCC=RINF/FOUR
      TOLSQ=TOLER*TOLER
      RM=ONE
      AM=ONE
      BMR=ONE
      BMI=T
      FMM2R=ONE
      FMM2I=ZERO
      GMM2R=ZERO
      GMM2I=ZERO
      FMM1R=ZERO
      FMM1I=ZERO
      GMM1R=ONE
      GMM1I=ZERO
      RESQP=RINF
      FRP=ZERO
      FIP=ZERO
!                         RECURRENCE RELATION
!                           FM=BM*FMM1 + AM*FMM2
!                           GM=BM*GMM1 + AM*GMM2
 510  FMR=BMR*FMM1R-BMI*FMM1I+AM*FMM2R
        FMI=BMI*FMM1R+BMR*FMM1I+AM*FMM2I
        GMR=BMR*GMM1R-BMI*GMM1I+AM*GMM2R
        GMI=BMI*GMM1R+BMR*GMM1I+AM*GMM2I
!                         CONVERGENT F=FM/GM
!                           TESTS TO AVOID INCORRECT RESULTS
!                               DUE TO OVERFLOWS(UNDERFLOWS)
!                             FINDING MAXIMUM(=TMAX) OF
!                               ABSOLUTE OF FMR,GMR,FMI,GMI
!                               FOR SCALING PURPOSES
        TMAX=ZERO
        I=1
 520    TEMP=A(I)
 530      CONTINUE
!CCCC     IF (TEMP) 540,560,550
          IF (TEMP.LT.0) THEN
             GO TO 540
          ELSEIF (TEMP.EQ.0) THEN
             GO TO 560
          ELSE
             GO TO 550
          ENDIF
 540      TEMP=-TEMP
          GO TO 530
 550      IF (TEMP .LE. TMAX) GO TO 560
          TMAX=TEMP
 560      IF (I .GE. 4) GO TO 570
          I=I+1
          GO TO 520
 570    SFMR=FMR/TMAX
        SFMI=FMI/TMAX
        SGMR=GMR/TMAX
        SGMI=GMI/TMAX
        TEMP=SGMR*SGMR + SGMI*SGMI
        FR=(SFMR*SGMR+SFMI*SGMI)/TEMP
        FI=(SFMI*SGMR-SFMR*SGMI)/TEMP
!                         RELATIVE ERROR CHECK
        TEMP=FR*FR+FI*FI
        TEMPA=(FRP*FR+FIP*FI)/TEMP
        TEMPB=(FIP*FR-FRP*FI)/TEMP
        TEMP=ONE-TEMPA
        RESQ =TEMP*TEMP+TEMPB*TEMPB
        IF (RESQ  .LE. TOLSQ) GO TO 590
        IF (RESQ .GE. RESQP) GO TO 580
!                         ADDITIONAL CONVERGENTS
        AM=-RM*RM
        RM=RM+ONE
        BMR=BMR+TWO
        FMM2R=FMM1R
        FMM2I=FMM1I
        GMM2R=GMM1R
        GMM2I=GMM1I
        FMM1R=FMR
        FMM1I=FMI
        GMM1R=GMR
        GMM1I=GMI
        FRP=FR
        FIP=FI
        RESQP=RESQ
!                         SCALING
! SCALING SHOULD NOT BE DELETED AS THE VALUES OF FMR,FMI AND
! GMR,GMI MAY OVERFLOW FOR SMALL VALUES OF T
        IF (TMAX .LT. SCC/(BMR-AM ) ) GO TO 510
        FMM2R=FMM2R/TMAX
        FMM2I=FMM2I/TMAX
        GMM2R=GMM2R/TMAX
        GMM2I=GMM2I/TMAX
        FMM1R=FMM1R/TMAX
        FMM1I=FMM1I/TMAX
        GMM1R=GMM1R/TMAX
        GMM1I=GMM1I/TMAX
        GO TO 510
!                         DIVERGENCE OF RELATIVE ERROR
!                           ACCEPT PRIOR CONVERGENT
 580  FR=FRP
      FI=FIP
!                         SI,CI EVALUATION
 590  SI=FI*COST-FR*SINT+HALFPI
      CI=-(FR*COST+FI*SINT)
      CII=ZERO
      GO TO 190
!                    METHOD --- ASYMPTOTIC EXPANSION
!                      EI(X),EXNEI(X)         X .GT. AELL
!                      SHI(T)=CHI(T)=EI(T)/2  T .GT. AELL
!                         INITIALIZATION
 800  IF (IND .NE. 2) GO TO 880
 810  SUME=ZERO
      RK=ZERO
      TM=ONE
!                         ADDITIONAL TERMS
 820  TMM1=TM
        RK=RK+ONE
        TM=(RK/T)*TM
!                         TOLERANCE CHECK
        IF (TM .LT. TOLER) GO TO 840
        IF (TM .GE. TMM1) GO TO 830
        SUME=SUME+TM
        GO TO 820
!                         DIVERGENT PATH
 830  SUME=SUME-TMM1
!                         EXNEI EVALUATION
 840  IF (X .LT. ZERO) GO TO 870
      EXNEI=(ONE+SUME)/T
!                         EI EVALUATION - X .LT. XMAXEI
      IF (T .GE. XMAXEI) GO TO 850
      EI=(EXNEI*EXPHT)*EXPHT
      GO TO 860
!                         EI - LIMITING VALUE, X .GE. XMAXEI
 850  EI=RINF
!                         SHI,CHI EVALUATION - T .LT. XMAXHF
 860  IF (IND .EQ. 2) RETURN
 870  IF (T .GE. XMAXHF) GO TO 1000
      SHI=(((( ONE+SUME)/T)/TWO)*EXPHT)*EXPHT
      CHI=SHI
      CHII=ZERO
      GO TO 1000
!                         SHI,CHI - LIMITING VALUE
!                                              T .GE. XMAXHF
 880  IF ( T .LT. XMAXHF) GO TO 810
      SHI=RINF
      CHI=RINF
      CHII=ZERO
      IF ( X .GT. ZERO) GO TO 810
      GO TO 1010
!          ADJUSTMENTS FOR X .LT. 0
1000  IF (X .GT. ZERO) RETURN
1010  IF (IC .EQ. 3) GO TO 1020
      SI=-SI
      CII=-PI
      IF (IC .EQ. 1) RETURN
1020  SHI=-SHI
      CHII=-PI
      RETURN
      END SUBROUTINE SICIEI
      SUBROUTINE SIDEDI(XC,YC,NS,D,IB,JB,X,Y,   &
                        IBUGG3,ISUBRO,IERROR)
!
!     PURPOSE--XX
!
!     WRITTEN BY--DAVID W. BEHRINGER NOAA/AOML (MIAMI).
!                 AS PART OF NOAA'S CONCX V.3   MARCH 1988.
!     ORIGINAL VERSION (IN DATAPLOT)--AUGUST    1988.
!     UPDATED         --JANUARY   1989.  MORE CHANGES TO STANDARD FORTRAN 77--
!                                        CHANGED DO WHILE/END DO (ALAN HECKERT).
!
!---------------------------------------------------------------------
!
      CHARACTER*4 IBUGG3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      DIMENSION IB(*)
      DIMENSION JB(*)
      DIMENSION X(*)
      DIMENSION Y(*)
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'DEDI')THEN
        WRITE(ICOUT,101)NBX,NS,XC,YC,D
  101   FORMAT('FROM SIDEDI: NS,XC,YC,D = ',I8,3G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,103)X(1),X(2),Y(1),Y(2)
  103   FORMAT('X(1),X(2),Y(1),Y(2) = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IERROR='NO'
      EPS=0.001*AMIN1(ABS(X(2)-X(1)),ABS(Y(2)-Y(1)))
      NS=0
      D=0.
      NB=1
!CCCC DO WHILE (NS.EQ.0)                 JANUARY 1989
  100 CONTINUE
      IF(NS.NE.0)GO TO 199
        IF (IB(NB).EQ.IB(NB+1)) THEN
          I=IB(NB)
          J1=JB(NB)
          J2=JB(NB+1)
!
          IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'DEDI')THEN
             WRITE(ICOUT,141)NB,I,J1,J2
  141        FORMAT('IB(NB) = IB(NB+1) CASE: NB,I,J1,J2 = ',4I6)
             CALL DPWRST('XXX','BUG ')
             WRITE(ICOUT,142)XC,X(I),YC,Y(J1),Y(J2)
  142        FORMAT('XC,X(I),YC,Y(J1),Y(J2) = ',5G15.7)
             CALL DPWRST('XXX','BUG ')
             TERM1=ABS(XC-X(I))
             TERM2=ABS(YC-Y(J1))
             TERM3=ABS(Y(J2)-Y(J1))
             WRITE(ICOUT,143)TERM1,TERM2,TERM3
  143        FORMAT('TERM1,TERM2,TERM3 = ',3G15.7)
             CALL DPWRST('XXX','BUG ')
          ENDIF
!
          IF (ABS(XC-X(I)).LE.EPS.AND.   &
               ABS(YC-Y(J1)).LT.ABS(Y(J2)-Y(J1))) THEN
            D=D+ABS(YC-Y(J1))
            NS=NB
          ELSE
            D=D+ABS(Y(J2)-Y(J1))
          END IF
        ELSE
          J=JB(NB)
          I1=IB(NB)
          I2=IB(NB+1)
!
          IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'DEDI')THEN
             WRITE(ICOUT,151)NB,J,I1,I2
  151        FORMAT('IB(NB) <> IB(NB+1) CASE: NB,J,I1,I2 = ',4I6)
             CALL DPWRST('XXX','BUG ')
             WRITE(ICOUT,152)XC,X(I1),X(I2),YC,Y(J)
  152        FORMAT('XC,X(I1),X(I2),YC,Y(J) = ',5G15.7)
             CALL DPWRST('XXX','BUG ')
             TERM1=ABS(YC-Y(J))
             TERM2=ABS(XC-X(I1))
             TERM3=ABS(X(I2)-X(I1))
             WRITE(ICOUT,153)TERM1,TERM2,TERM3
  153        FORMAT('TERM1,TERM2,TERM3 = ',3G15.7)
             CALL DPWRST('XXX','BUG ')
          ENDIF
!
          IF (ABS(YC-Y(J)).LE.EPS.AND.   &
               ABS(XC-X(I1)).LT.ABS(X(I2)-X(I1))) THEN
            D=D+ABS(XC-X(I1))
            NS=NB
          ELSE
            D=D+ABS(X(I2)-X(I1))
          END IF
        END IF
        NB=NB+1
!CCCC END DO                             JANUARY 1989
!
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'DEDI')THEN
        WRITE(ICOUT,191)NB,D
  191   FORMAT('FROM SIDEDI END OF LOOP: NB,D = ',I6,G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      GO TO 100
  199 CONTINUE
      RETURN
      END SUBROUTINE SIDEDI
      SUBROUTINE SIMCOV(ISEED,IBUGA2,IBUGA3,IBUGCO,IBUGEV,IBUGQ,   &
                        ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--CARRY OUT MARK VANGEL'S SIMCOV PROGRAM
!              FOR LINEAR MODELS.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--97/9
!     ORIGINAL VERSION--SEPTEMBER   1997.
!     UPDATED         --JULY        2019. TWEAK SCRATCH SPACE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IBUGA2
      CHARACTER*4 IBUGA3
      CHARACTER*4 IBUGCO
      CHARACTER*4 IBUGEV
      CHARACTER*4 IBUGQ
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 ICASRE
      CHARACTER*4 ICASDG
      CHARACTER*4 ICASEQ
      CHARACTER*4 IKEY
      CHARACTER*4 IHRIGH
      CHARACTER*4 IHRIG2
      CHARACTER*4 IFLAG
!
      CHARACTER*4 IHWUSE
      CHARACTER*4 MESSAG
      CHARACTER*4 IHLEFT
      CHARACTER*4 IHLEF2
!
      CHARACTER*4 IVARN1
      CHARACTER*4 IVARN2
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!CCCC CHARACTER*20 IMODEL
!
      LOGICAL SATT
!
      DOUBLE PRECISION PCT
      DOUBLE PRECISION ERR
      DOUBLE PRECISION SDW
      DOUBLE PRECISION SDB
      DOUBLE PRECISION RHO
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOZZ.INC'
      INCLUDE 'DPCOZI.INC'
      INCLUDE 'DPCOZD.INC'
!
      DIMENSION ILIS(100)
      DIMENSION ICOLR(100)
!
      REAL XTMP(1)
      DOUBLE PRECISION XDESGN(MAXOBV)
      DOUBLE PRECISION XPTS(MAXOBV)
      DOUBLE PRECISION V2(MAXOBV)
      DOUBLE PRECISION TLM0(MAXOBV)
      DOUBLE PRECISION TLM1(MAXOBV)
      DOUBLE PRECISION ETA0(MAXOBV)
      DOUBLE PRECISION ETA1(MAXOBV)
      DOUBLE PRECISION XM(MAXOBV)
      DOUBLE PRECISION WK2(MAXOBV)
      DOUBLE PRECISION WK3(MAXOBV)
      DOUBLE PRECISION XN(MAXOBV)
      DOUBLE PRECISION T(MAXOBV)
      DOUBLE PRECISION CRT(MAXOBV)
      DOUBLE PRECISION Y2(MAXOBV)
      DOUBLE PRECISION COV(MAXOBV)
!
      DIMENSION IP(MAXOBV)
      DIMENSION IQ(MAXOBV)
!
      DIMENSION PRED2(MAXOBV)
      DIMENSION RES2(MAXOBV)
!
      DOUBLE PRECISION XMAT(5*MAXOBV)
      DOUBLE PRECISION SCRTCH(10*MAXOBV)
!
      DOUBLE PRECISION XTX(100)
      DOUBLE PRECISION XTXI(100)
      DOUBLE PRECISION S1(100)
      DOUBLE PRECISION S2(100)
      DOUBLE PRECISION V1(100)
      DOUBLE PRECISION COEF(100)
!
!CCCC DIMENSION ICH(10)
!
      DIMENSION IVARN1(100)
      DIMENSION IVARN2(100)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOSU.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOHO.INC'
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      EQUIVALENCE (COV(1),X(1))
      EQUIVALENCE (Y2(1),X3D(1))
      EQUIVALENCE (PRED2(1),D(1))
      EQUIVALENCE (RES2(1),D(MAXOBV+1))
      EQUIVALENCE (CRT(1),DSIZE(1))
      EQUIVALENCE (XN(1),DSYMB(1))
      EQUIVALENCE (T(1),DFILL(1))
      EQUIVALENCE (XTX(1),DCOLOR(1))
      EQUIVALENCE (XTXI(1),DCOLOR(1001))
      EQUIVALENCE (S1(1),DCOLOR(2001))
      EQUIVALENCE (S2(1),DCOLOR(3001))
      EQUIVALENCE (V1(1),DCOLOR(4001))
!
      EQUIVALENCE (GARBAG(IGARB1),XMAT(1))
      EQUIVALENCE (GARBAG(IGAR11),SCRTCH(1))
!
      EQUIVALENCE (DGARBG(IDGAR1),XDESGN(1))
      EQUIVALENCE (DGARBG(IDGAR2),XPTS(1))
      EQUIVALENCE (DGARBG(IDGAR3),V2(1))
      EQUIVALENCE (DGARBG(IDGAR4),TLM0(1))
      EQUIVALENCE (DGARBG(IDGAR5),TLM1(1))
      EQUIVALENCE (DGARBG(IDGAR6),ETA0(1))
      EQUIVALENCE (DGARBG(IDGAR7),ETA1(1))
      EQUIVALENCE (DGARBG(IDGAR8),XM(1))
      EQUIVALENCE (DGARBG(IDGAR9),WK2(1))
      EQUIVALENCE (DGARBG(IDGA10),WK3(1))
!
      EQUIVALENCE (IGARBG(IIGAR1),IQ(1))
      EQUIVALENCE (IGARBG(IIGAR2),IP(1))
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='SIMC'
      ISUBN2='OV  '
      IERROR='NO'
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
!CCCC IPAROC(1)='NONE'
!
      MAXV2=35
      MINN2=2
      ILOCXP=0
      ILOCB=0
      JMAX=0
      NUMVAR=0
!
      CPUEPS=R1MACH(3)
!
      MAXN2=MAXCHF
      MAXN3=MAXCHF
      MAXN4=MAXCHF
!
      MAXLVL=INT(SQRT(REAL(IGARB0)))
      MAXPT1=20*MAXOBV
      MAXPT2=10*MAXOBV
!
      NPAR=0
      NTOT=0
      NBCH=0
      NLEFT=0
!
!               *****************************
!               **  TREAT THE RECIPE CASE  **
!               *****************************
!
      IF(IBUGA2.EQ.'OFF'.AND.ISUBRO.NE.'MCOV')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF SIMCOV--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)IBUGA2,IBUGA3
   53 FORMAT('IBUGA2,IBUGA3 = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,54)IBUGCO,IBUGEV,IBUGQ
   54 FORMAT('IBUGCO,IBUGEV,IBUGQ = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,56)NUMNAM
   56 FORMAT('NUMNAM = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 57 I=1,NUMNAM
      WRITE(ICOUT,58)I,IHNAME(I),IHNAM2(I),IUSE(I),IN(I),IVALUE(I),   &
      VALUE(I)
   58 FORMAT('I,IHNAME(I),IHNAM2(I),IUSE(I),IN(I),IVALUE(I)',   &
      'VALUE(I) = ',I8,2X,A4,A4,2X,A4,I8,I8,E15.7)
      CALL DPWRST('XXX','BUG ')
   57 CONTINUE
      WRITE(ICOUT,61)IRECSA,RECIDG,RECIPC,RECICO
   61 FORMAT('IRECSA,RECIDG,RECIPC,RECICO=',A4,1X,3(E15.7))
      CALL DPWRST('XXX','BUG ')
   90 CONTINUE
!
!               **********************************
!               **  STEP 1--                    **
!               **  EXTRACT THE COMMAND         **
!               **    SIMCOV FIT                **
!               **    SIMCOV ANOVA              **
!               **    SIMCOV Y <UNIVARIATE CASE **
!               **********************************
!
      ISTEPN='1'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MCOV')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(ICOM.EQ.'SIMC'.AND.NUMARG.GE.1.AND.IHARG(1).EQ.'FIT')THEN
        IFOUND='YES'
        ICASRE='FREC'
        IJUNK=INT(RECIDG+0.5)
        ICASDG='1'
        IF(IJUNK.EQ.0)ICASDG='0'
        IF(IJUNK.EQ.1)ICASDG='1'
        IF(IJUNK.EQ.2)ICASDG='2'
        IF(IJUNK.EQ.3)ICASDG='3'
        IF(IJUNK.EQ.4)ICASDG='4'
        IF(IJUNK.EQ.5)ICASDG='5'
        IF(IJUNK.EQ.6)ICASDG='6'
        IF(IJUNK.EQ.7)ICASDG='7'
        IF(IJUNK.EQ.8)ICASDG='8'
        IF(IJUNK.EQ.9)ICASDG='9'
        IF(IJUNK.EQ.10)ICASDG='10'
      ELSEIF(ICOM.EQ.'SIMC'.AND.NUMARG.GE.1.AND.IHARG(1).EQ.'ANOV')THEN
        IFOUND='YES'
        ICASRE='AREC'
      ELSEIF(ICOM.EQ.'SIMC'.AND.NUMARG.GE.1)THEN
        IFOUND='YES'
        ICASRE='UREC'
      ENDIF
      IF(IBUGA2.EQ.'ON')THEN
        WRITE(ICOUT,66)ICASRE
   66   FORMAT('ICASRE=',A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      IF(ICASRE.EQ.'    ')GO TO 9000
!
!               *******************************************************
!               **  STEP 2--                                         **
!               **  CHECK FOR THE PROPER NUMBER OF INPUT ARGUMENTS.  **
!               *******************************************************
!
      ISTEPN='2'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MCOV')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      MINNA=0
      MAXNA=100
      CALL CHECKA(NUMARG,MINNA,MAXNA,IANS,IWIDTH,ISUBN1,ISUBN2,   &
      IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
!               ******************************************************
!               **  STEP 3--                                        **
!               **  IN PARTICULAR, CHECK THAT THE NUMBER OF ARGUMENTS*
!               **  IS AT LEAST 1,                                  **
!               *******************************************************
!
      ISTEPN='3'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MCOV')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMARG.GE.1)GO TO 2090
      WRITE(ICOUT,2001)
 2001 FORMAT('***** ERROR IN SIMCOV--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2002)
 2002 FORMAT('      NUMBER OF ARGUMENTS DETECTED')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2003)NUMARG
 2003 FORMAT('      IN RECIPE COMMAND = 0.  NUMARG = ',I6)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2007)IWIDTH
 2007 FORMAT('      NUMBER OF CHARACTERS IN COMMAND LINE = ',I8)
      CALL DPWRST('XXX','BUG ')
      IF(IWIDTH.GE.1)WRITE(ICOUT,2008)(IANS(J),J=1,MIN(IWIDTH,100))
 2008 FORMAT('      COMMAND LINE--',100A1)
      IF(IWIDTH.GE.1)CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
 2090 CONTINUE
!
      DO 2100 J=1,NUMARG
      J1=J
      IF(IHARG(J).EQ.'SUBS'.AND.IHARG2(J).EQ.'ET  ')GO TO 2110
      IF(IHARG(J).EQ.'EXCE'.AND.IHARG2(J).EQ.'PT  ')GO TO 2110
      IF(IHARG(J).EQ.'FOR '.AND.IHARG2(J).EQ.'    ')GO TO 2110
 2100 CONTINUE
      ILOCQ=NUMARG+1
      GO TO 2120
 2110 CONTINUE
      ILOCQ=J1
      GO TO 2120
 2120 CONTINUE
!
!               *******************************************************
!               **  STEP 4--                                         **
!               **  FOR RECIPE FIT AND RECIPE ANOVA,                 **
!               **  THE SECOND WORD AFTER  RECIPE SHOULD BE THE      **
!               **  RESPONSE VARIABLE (= THE DEPENDENT VARIABLE).    **
!               **  FOR RECIPE <Y>, RESPONSE VARIABLE IS FIRST WORD. **
!               **  EXTRACT THE RESPONSE VARIABLE AND DETERMINE      **
!               **  IF IT IS ALREADY IN THE NAME LIST AND IS, IN FACT,*
!               **  A VARIABLE (AS OPPOSED TO A PARAMETER).          **
!               *******************************************************
!
      ISTEPN='4'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MCOV')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ILOCY=2
      IF(ICASRE.EQ.'UREC')ILOCY=1
      IHLEFT=IHARG(ILOCY)
      IHLEF2=IHARG2(ILOCY)
      DO 2350 I=1,NUMNAM
      I2=I
      IF(IHLEFT.EQ.IHNAME(I2).AND.IHLEF2.EQ.IHNAM2(I2).AND.   &
      IUSE(I2).EQ.'V')GO TO 2379
 2350 CONTINUE
      WRITE(ICOUT,2361)
 2361 FORMAT('***** ERROR IN SIMCOV--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2362)
 2362 FORMAT('      THE NAME FOLLOWING THE WORD RECIPE FIT ',   &
      '(OR RECIPE ANOVA')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2363)
 2363 FORMAT('      (WHICH SHOULD BE THE RESPONSE VARIABLE)')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2364)
 2364 FORMAT('      EITHER DOES NOT EXIST,')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2365)
 2365 FORMAT('      OR IS A PARAMETER (AS OPPOSED')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2366)
 2366 FORMAT('      TO A VARIABLE) IN THE CURRENT')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2367)
 2367 FORMAT('      LIST OF AVAILABLE VARIABLE AND PARAMETER')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2368)
 2368 FORMAT('      NAMES.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2369)IHLEFT,IHLEF2
 2369 FORMAT('      NAME AFTER THE WORD RECIPE FIT/ANOVA = ',A4,A4)
      CALL DPWRST('XXX','BUG ')
      IF(IWIDTH.GE.1)WRITE(ICOUT,2378)(IANS(J),J=1,MIN(IWIDTH,100))
 2378 FORMAT('      COMMAND LINE--',100A1)
      IF(IWIDTH.GE.1)CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
 2379 CONTINUE
      ILOCV=I2
      ICOLL=IVALUE(ILOCV)
      NLEFT=IN(ILOCV)
!
!               *******************************************************
!               **  STEP 5--                                         **
!               **  FOR ALL VARIATIONS OF THE SIMCOV COMMAND,        **
!               **  CHECK THAT THE INPUT NUMBER OF OBSERVATIONS (NLEFT)
!               **  FOR THE RESPONSE VARIABLE IS 2 OR LARGER.        **
!               *******************************************************
!
      ISTEPN='5'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MCOV')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NLEFT.GE.MINN2)GO TO 390
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,311)
  311 FORMAT('***** ERROR IN SIMCOV--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,312)IHLEFT,IHLEF2
  312 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS ',   &
      'IN VARIABLE ',A4,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,313)
  313 FORMAT('      (FOR WHICH A RECIPE ANALYSIS ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,314)
  314 FORMAT('      WAS TO HAVE BEEN PERFORMED)')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,315)MINN2
  315 FORMAT('      MUST BE ',I8,' OR LARGER;')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,316)
  316 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,317)NLEFT
  317 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS NLEFT = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,318)
  318 FORMAT('      THE ENTERED COMMAND LINE WAS AS FOLLOWS--')
      CALL DPWRST('XXX','BUG ')
      IF(IWIDTH.GE.1)WRITE(ICOUT,319)(IANS(I),I=1,IWIDTH)
  319 FORMAT(80A1)
      IF(IWIDTH.GE.1)CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
!
  390 CONTINUE
!
!               **************************************************
!               **  STEP 12--                                   **
!               **  EXTRACT THE INDEPENDENT VARIABLES           **
!               **  FOR SIMCOV FIT:                             **
!               **      Y X <BATCH> <XPRED>                     **
!               **  FOR SIMCOV ANOVA:                           **
!               **      Y X1 ... XK <BATCH>                     **
!               **  FOR SIMCOV :                                **
!               **      Y <BATCH>                               **
!               **  IF THE   TO   FEATURE IS USED IN THE        **
!               **  ARGUMENT LIST, TRANSLATE THE   TO   TO      **
!               **  EXPLICIT VARIABLE NAMES             INTO    **
!               **************************************************
!
      ISTEPN='12'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MCOV')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(ICASRE.EQ.'FREC')THEN
        MAXREC=3
        JMIN=ILOCY+1
        JMAX=ILOCQ-1
        CALL EXTVAR(IHARG,IHARG2,NUMARG,JMIN,JMAX,MAXREC,   &
        IHNAME,IHNAM2,IUSE,NUMNAM,   &
        IVARN1,IVARN2,NUMVAR,IBUGA2,ISUBRO,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
        IF(NUMVAR.EQ.1)THEN
          ILOCX=ILOCY+1
          ILOCB=-1
          ILOCXP=-1
        ELSEIF(NUMVAR.EQ.2)THEN
          ILOCX=ILOCY+1
          ILOCB=ILOCX+1
          ILOCXP=-1
        ELSEIF(NUMVAR.EQ.3)THEN
          ILOCX=ILOCY+1
          ILOCB=ILOCX+1
          ILOCXP=ILOCB+1
        ELSE
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,411)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,412)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,413)NUMVAR
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
  411 FORMAT('***** ERROR IN SIMCOV (SIMCOV FIT)--')
  412 FORMAT('      BETWEEN 2 AND 4 VARIABLE NAMES CAN BE SPECIFIED '   &
            ,'FOR THIS COMMAND')
  413 FORMAT('      ',I8,' VARIABLES WERE GIVEN.')
      ELSEIF(ICASRE.EQ.'UREC')THEN
        MAXREC=1
        JMIN=ILOCY+1
        JMAX=ILOCQ-1
        CALL EXTVAR(IHARG,IHARG2,NUMARG,JMIN,JMAX,MAXREC,   &
        IHNAME,IHNAM2,IUSE,NUMNAM,   &
        IVARN1,IVARN2,NUMVAR,IBUGA2,ISUBRO,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
        ILOCX=-1
        ILOCXP=-1
        IF(NUMVAR.EQ.1)THEN
          ILOCB=ILOCX+1
        ELSEIF(NUMVAR.EQ.0)THEN
          ILOCB=-1
        ELSE
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,421)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,422)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,423)NUMVAR
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
  421 FORMAT('***** ERROR IN SIMCOV (SIMCOV)--')
  422 FORMAT('      BETWEEN 0 AND 1 VARIABLE NAMES CAN BE SPECIFIED '   &
            ,'FOR THIS COMMAND')
  423 FORMAT('      ',I8,' VARIABLES WERE GIVEN.')
      ELSEIF(ICASRE.EQ.'AREC')THEN
        NUMFAC=INT(RECIFA+0.5)
!CCCC   IF(NUMFAC.GT.MAXPAR)THEN
!CCCC     WRITE(ICOUT,999)
!CCCC     CALL DPWRST('XXX','BUG ')
!CCCC     WRITE(ICOUT,511)
!CCCC     CALL DPWRST('XXX','BUG ')
!CCCC     WRITE(ICOUT,512)NUMFAC,MAXPAR
!CCCC     CALL DPWRST('XXX','BUG ')
!CCCC     IERROR='YES'
!CCCC     GO TO 9000
!CCCC   ENDIF
!C511   FORMAT('***** ERROR IN SIMCOV (RECIPE ANOVA)--')
!C512   FORMAT('      THE REQUESTED NUMBER OF FACTORS ',I8,
!CCCC1        ' IS GREATER THAN THE ALLOWED MAXIMUM OF ',I8)
        MAXREC=NUMFAC+1
        JMIN=ILOCY+1
        JMAX=ILOCQ-1
        CALL EXTVAR(IHARG,IHARG2,NUMARG,JMIN,JMAX,MAXREC,   &
        IHNAME,IHNAM2,IUSE,NUMNAM,   &
        IVARN1,IVARN2,NUMVAR,IBUGA2,ISUBRO,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
        IF(NUMVAR.EQ.NUMFAC)THEN
          ILOCX=ILOCY+1
          ILOCB=-1
          ILOCXP=-1
        ELSEIF(NUMVAR.EQ.NUMFAC+1)THEN
          ILOCX=ILOCY+1
          ILOCB=ILOCX+NUMFAC
          ILOCXP=-1
        ELSE
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,611)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,612)NUMFAC,NUMVAR
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
  611 FORMAT('***** ERROR IN SIMCOV (SIMCOV ANOVA)--')
  612 FORMAT('      ',I8,' FACTORS WERE SPECIFIED, BUT ONLY ',I8,   &
             ' VARIABLES WERE GIVEN ON THE COMMAND LINE.')
      ENDIF
!
      IF(IBUGA2.EQ.'ON')THEN
        WRITE(ICOUT,71)NUMVAR,NUMFAC
   71   FORMAT('NUMVAR,NUMFAC=',2I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ***************************************
!               **  STEP 13--                        **
!               **  CHECK THE VALIDITY OF EACH       **
!               **  OF THE VARIABLES.                **
!               **  THE DESIGN MATRIX (X) AND BATCH  **
!               **  IDENTIFIER VARIABLE MUST HAVE THE**
!               **  SAME NUMER OF OBSERVATIONS AS THE**
!               **  Y VARIABLE.  THE XPRED VARIABLE  **
!               **  MUST HAVE AT LEAST 2 OBSERVATIONS**
!               ***************************************
!
      ISTEPN='13'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MCOV')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(ICASRE.EQ.'UREC'.AND.NUMVAR.EQ.0)GO TO 1399
      DO 1300 I=1,NUMVAR
!
      IHRIGH=IVARN1(I)
      IHRIG2=IVARN2(I)
      IHWUSE='V'
      MESSAG='YES'
      CALL CHECKN(IHRIGH,IHRIG2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCV,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      NRIGHT=IN(ILOCV)
      ILIS(I)=ILOCV
      ICOLR(I)=IVALUE(ILOCV)
!
      IF(ILOCXP.GT.0 .AND. I.EQ.NUMVAR)NPRED=NRIGHT
      IF(NRIGHT.EQ.NLEFT)GO TO 1390
      IF(ILOCXP.GT.0 .AND. I.EQ.NUMVAR .AND. NRIGHT.GT.2)GO TO 1390
!
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1311)
 1311 FORMAT('***** ERROR IN SIMCOV--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1312)
 1312 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1321)
 1321 FORMAT('      FOR THE INDEPENDENT VARIABLES')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1322)
 1322 FORMAT('      MUST BE THE SAME AS THE DEPENDENT VARIABLE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1323)
 1323 FORMAT('      IN ADDITION, THE VARIABLE CONTAINING THE X ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1324)
 1324 FORMAT('      VALUES FOR THE TOLERANCE LIMITS MUST HAVE AT ',   &
      'LEAST 2 ELEMENTS.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1327)
 1327 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1328)
 1328 FORMAT('      THE ENTERED COMMAND LINE WAS AS FOLLOWS--')
      CALL DPWRST('XXX','BUG ')
      IF(IWIDTH.GE.1)WRITE(ICOUT,1329)(IANS(J),J=1,MIN(80,IWIDTH))
 1329 FORMAT('      ',80A1)
      IF(IWIDTH.GE.1)CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
 1390 CONTINUE
!
 1300 CONTINUE
 1399 CONTINUE
!
!               **********************************************
!               **  STEP 6.3--                              **
!               **  FOR ALL VARIATIONS OF THE SIMCOV COMMAND,*
!               **  CHECK TO SEE THE TYPE CASE--            **
!               **    1) UNQUALIFIED (THAT IS, FULL);       **
!               **    2) SUBSET/EXCEPT; OR                  **
!               **    3) FOR.                               **
!               **********************************************
!
      ISTEPN='6.3'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MCOV')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ICASEQ='FULL'
      ILOCQ=NUMARG+1
      IF(NUMARG.LT.1)GO TO 490
      DO 400 J=1,NUMARG
      J1=J
      IF(IHARG(J).EQ.'SUBS'.AND.IHARG2(J).EQ.'ET  ')GO TO 410
      IF(IHARG(J).EQ.'EXCE'.AND.IHARG2(J).EQ.'PT  ')GO TO 410
      IF(IHARG(J).EQ.'FOR '.AND.IHARG2(J).EQ.'    ')GO TO 420
  400 CONTINUE
      GO TO 490
  410 CONTINUE
      ICASEQ='SUBS'
      IKEY='SUBS'
      IF(IHARG(J1).EQ.'EXCE')IKEY='EXCE'
      ILOCQ=J1
      GO TO 490
  420 CONTINUE
      ICASEQ='FOR'
      ILOCQ=J1
      GO TO 490
  490 CONTINUE
      IF(IBUGA2.EQ.'OFF'.AND.ISUBRO.NE.'MCOV')GO TO 495
      WRITE(ICOUT,491)NUMARG,ILOCQ
  491 FORMAT('NUMARG,ILOCQ = ',2I8)
      CALL DPWRST('XXX','BUG ')
  495 CONTINUE
!
!               *******************************************************
!               **  STEP 12--                                        **
!               **  BRANCH TO THE APPROPRIATE SUBCASE; THEN          **
!               **  COPY OVER THE RESPONSE VECTOR TO BE USED IN THE  **
!               **  MODEL INTO THE VECTOR Y2; AND                    **
!               **  COPY OVER THE VECTORS THAT WERE USED IN THE MODEL**
!               **  INTO THE FULL DESIGN MATRIX                      **
!               *******************************************************
!
      ISTEPN='12'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MCOV')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MCOV')WRITE(ICOUT,601)NLEFT,NUMVAR
  601 FORMAT('NLEFT,NUMVAR = ',2I8)
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MCOV')CALL DPWRST('XXX','BUG ')
!
      IF(ICASEQ.EQ.'FULL')GO TO 610
      IF(ICASEQ.EQ.'SUBS')GO TO 620
      IF(ICASEQ.EQ.'FOR')GO TO 630
!
  610 CONTINUE
      DO 615 I=1,NLEFT
      ISUB(I)=1
  615 CONTINUE
      NQ=NLEFT
      GO TO 650
!
  620 CONTINUE
      NIOLD=NLEFT
!CCCC CALL DPSUB2(NIOLD,ILOCS,NS,IBUGQ,IERROR)
      CALL DPSUBS(NIOLD,ILOCS,NS,IBUGQ,IERROR)
      NQ=NIOLD
      GO TO 650
!
  630 CONTINUE
      NIOLD=NLEFT
      CALL DPFOR(NIOLD,NFOR,IROW1,IROWN,   &
      NLOCAL,ILOCS,NS,IBUGQ,IERROR)
      NQ=NFOR
      GO TO 650
!
  650 CONTINUE
      NTOT=NQ
      K=ICOLL
      J=0
      DO 4500 I=1,NLEFT
      IF(ISUB(I).EQ.0)GO TO 4500
      J=J+1
      IJ=MAXN*(K-1)+I
      IF(K.LE.MAXCOL)Y2(J)=DBLE(V(IJ))
      IF(K.EQ.MAXCP1)Y2(J)=DBLE(PRED(I))
      IF(K.EQ.MAXCP2)Y2(J)=DBLE(RES(I))
      IF(K.EQ.MAXCP3)Y2(J)=DBLE(YPLOT(I))
      IF(K.EQ.MAXCP4)Y2(J)=DBLE(XPLOT(I))
      IF(K.EQ.MAXCP5)Y2(J)=DBLE(X2PLOT(I))
      IF(K.EQ.MAXCP6)Y2(J)=DBLE(TAGPLO(I))
 4500 CONTINUE
      IF(IBUGA2.EQ.'ON')THEN
        DO 4503 I=1,NTOT
        WRITE(ICOUT,4504)I,Y2(I)
 4504   FORMAT('I,Y2(I)=',I8,2X,D15.7)
        CALL DPWRST('XXX','BUG ')
 4503   CONTINUE
      ENDIF
!
!     ********************************************************
!     ** DEFINE A VECTOR OF ALL 1'S (FOR THE CONSTANT TERM) **
!     ** IN THE DESIGN MATRIX.                              **
!     ********************************************************
!
      J=0
      DO 380 I=1,NLEFT
      IF(ISUB(I).EQ.0)GO TO 380
      J=J+1
      XMAT(J)=1.0D0
  380 CONTINUE
!
!     ********************************************************
!     ** DETERMINE IF THERE IS A BATCH VARIABLE.  IF NOT,   **
!     ** CREATE ONE EQUAL TO ALL 1'S.  IF YES, DETERMINE    **
!     ** HOW MANY UNIQUE VALUES.                            **
!     ********************************************************
!
      IF(ILOCB.LE.0)THEN
        J=0
        DO 4610 I=1,NLEFT
          IF(ISUB(I).EQ.0)GO TO 4610
          J=J+1
          IQ(J)=1
 4610   CONTINUE
        NBCH=1
        GO TO 4699
      ENDIF
!
      IF(ICASRE.EQ.'FREC')THEN
        K=ICOLR(NUMVAR)
        IF(ILOCXP.GT.0)K=ICOLR(NUMVAR-1)
      ELSE
        K=ICOLR(NUMVAR)
      ENDIF
!
      J=0
      DO 4600 I=1,NLEFT
      IF(ISUB(I).EQ.0)GO TO 4600
      J=J+1
      IJ=MAXN*(K-1)+I
      IF(K.LE.MAXCOL)RES2(J)=V(IJ)
      IF(K.EQ.MAXCP1)RES2(J)=PRED(I)
      IF(K.EQ.MAXCP2)RES2(J)=RES(I)
      IF(K.EQ.MAXCP3)RES2(J)=YPLOT(I)
      IF(K.EQ.MAXCP4)RES2(J)=XPLOT(I)
      IF(K.EQ.MAXCP5)RES2(J)=X2PLOT(I)
      IF(K.EQ.MAXCP6)RES2(J)=TAGPLO(I)
 4600 CONTINUE
!
      CALL SORT(RES2,NQ,PRED2)
      IWRITE='NO'
      CALL DISTIN(PRED2,NQ,IWRITE,PRED2,NBCH,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
      DO 4650 I=1,NQ
        IQ(I)=0
        DO 4660 J=1,NBCH
          IF(RES2(I).EQ.PRED2(J))THEN
            IQ(I)=J
            GO TO 4650
          ENDIF
 4660   CONTINUE
 4650 CONTINUE
!
 4699 CONTINUE
!
      IF(IBUGA2.EQ.'ON')THEN
        DO 4603 I=1,NTOT
        WRITE(ICOUT,4604)I,IQ(I)
 4604   FORMAT('I,IQ(I)=',I8,2X,I8)
        CALL DPWRST('XXX','BUG ')
 4603   CONTINUE
      ENDIF
!
!     ********************************************************
!     ** DETERMINE IF THERE IS A PREDICTED VARIABLE (FIT    **
!     ** CASE ONLY).  IF SO, EXTRACT AND PUT IN XPTS.       **
!     ********************************************************
!
      IF(ICASRE.EQ.'UREC')THEN
        XPTS(1)=1.D0
        NPRED=1
        NPAR=1
        GO TO 4799
      ELSEIF(ILOCXP.LT.0.OR.ICASRE.EQ.'AREC')THEN
        XPTS(1:MAXOBV/2)=0.D0
        NPRED=0
        GO TO 4799
      ENDIF
!
      K=ICOLR(NUMVAR)
      DO 4703 I=1,NPRED
        XPTS(I)=1.D0
 4703 CONTINUE
      J=NPRED
      DO 4700 I=1,NPRED
      IF(ISUB(I).EQ.0)GO TO 4700
      J=J+1
      IJ=MAXN*(K-1)+I
      IF(K.LE.MAXCOL)XPTS(J)=DBLE(V(IJ))
      IF(K.EQ.MAXCP1)XPTS(J)=DBLE(PRED(I))
      IF(K.EQ.MAXCP2)XPTS(J)=DBLE(RES(I))
      IF(K.EQ.MAXCP3)XPTS(J)=DBLE(YPLOT(I))
      IF(K.EQ.MAXCP4)XPTS(J)=DBLE(XPLOT(I))
      IF(K.EQ.MAXCP5)XPTS(J)=DBLE(X2PLOT(I))
      IF(K.EQ.MAXCP6)XPTS(J)=DBLE(TAGPLO(I))
 4700 CONTINUE
!
 4799 CONTINUE
!
      IF(IBUGA2.EQ.'ON')THEN
        DO 4713 I=1,2*NPRED
        WRITE(ICOUT,4714)I,XPTS(I)
 4714   FORMAT('I,XPTS(I)=',I8,2X,D15.7)
        CALL DPWRST('XXX','BUG ')
 4713   CONTINUE
      ENDIF
!
!     ********************************************************
!     ** COPY OVER THE FULL DESIGN MATRIX.                  **
!     ********************************************************
!
      IF(ICASRE.EQ.'FREC')THEN
        NPAR=1
        IF(ICASDG.EQ.'0')GO TO 379
        IF(ICASDG.EQ.'1')NLOOP=1
        IF(ICASDG.EQ.'2')NLOOP=2
        IF(ICASDG.EQ.'3')NLOOP=3
        IF(ICASDG.EQ.'4')NLOOP=4
        IF(ICASDG.EQ.'5')NLOOP=5
        IF(ICASDG.EQ.'6')NLOOP=6
        IF(ICASDG.EQ.'7')NLOOP=7
        IF(ICASDG.EQ.'8')NLOOP=8
        IF(ICASDG.EQ.'9')NLOOP=9
        IF(ICASDG.EQ.'10')NLOOP=10
        K=ICOLR(1)
        DO 376 IVAR=1,NLOOP
          J=IVAR*NTOT
          DO 371 I=1,NLEFT
            IF(ISUB(I).EQ.0)GO TO 371
            J=J+1
            IJ=MAXN*(K-1)+I
            IF(K.LE.MAXCOL)XMAT(J)=DBLE(V(IJ)**NLOOP)
            IF(K.EQ.MAXCP1)XMAT(J)=DBLE(PRED(I)**NLOOP)
            IF(K.EQ.MAXCP2)XMAT(J)=DBLE(RES(I)**NLOOP)
            IF(K.EQ.MAXCP3)XMAT(J)=DBLE(YPLOT(I)**NLOOP)
            IF(K.EQ.MAXCP4)XMAT(J)=DBLE(XPLOT(I)**NLOOP)
            IF(K.EQ.MAXCP5)XMAT(J)=DBLE(X2PLOT(I)**NLOOP)
            IF(K.EQ.MAXCP6)XMAT(J)=DBLE(TAGPLO(I)**NLOOP)
  371     CONTINUE
  376   CONTINUE
        NPAR=NLOOP+1
  379   CONTINUE
!
      ELSEIF(ICASRE.EQ.'UREC')THEN
        NPAR=1
        J=NTOT
!CCCC   DO372I=1,NLEFT
!CCCC     IF(ISUB(I).EQ.0)GO TO 372
!CCCC     J=J+1
!CCCC     XMAT(J)=1.D0
!372    CONTINUE
      ELSEIF(ICASRE.EQ.'AREC')THEN
        NLOOP=NUMVAR
        IF(ILOCB.GT.0)NLOOP=NUMVAR-1
        DO 389 IVAR=1,NLOOP
          K=ICOLR(IVAR)
          J=IVAR*NTOT
          DO 381 I=1,NLEFT
            IF(ISUB(I).EQ.0)GO TO 381
            J=J+1
            IJ=MAXN*(K-1)+I
            IF(K.LE.MAXCOL)XMAT(J)=DBLE(V(IJ))
            IF(K.EQ.MAXCP1)XMAT(J)=DBLE(PRED(I))
            IF(K.EQ.MAXCP2)XMAT(J)=DBLE(RES(I))
            IF(K.EQ.MAXCP3)XMAT(J)=DBLE(YPLOT(I))
            IF(K.EQ.MAXCP4)XMAT(J)=DBLE(XPLOT(I))
            IF(K.EQ.MAXCP5)XMAT(J)=DBLE(X2PLOT(I))
            IF(K.EQ.MAXCP6)XMAT(J)=DBLE(TAGPLO(I))
  381     CONTINUE
  389   CONTINUE
        NPAR=NLOOP+1
      ENDIF
!
      IF(IBUGA2.EQ.'ON')THEN
        DO 4803 I=1,NTOT*NPAR
        WRITE(ICOUT,4804)I,XMAT(I)
 4804   FORMAT('I,XMAT(I)=',I8,2X,D15.7)
        CALL DPWRST('XXX','BUG ')
 4803   CONTINUE
      ENDIF
!
!               ******************************************************
!               **  STEP 14--                                       **
!               **  CARRY OUT THE ACTUAL FIT                        **
!               **  VIA CALLING                                     **
!               **  REGINI AND REGDAT                               **
!               ******************************************************
!
      NSTOR=NTOT*(NPAR+NBCH)
      IF(NSTOR.GT.MAXPT1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,6071)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,6072)NSTOR
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,6073)MAXPT1
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
 6071 FORMAT('***** ERROR FROM SIMCOV--THE AMOUNT OF SCRATCH STORAGE ',   &
      'REQUIRED')
 6072 FORMAT('     NUMBER OF POINTS*(NUMBER OF PARAMETERS + NUMBER OF',   &
      ' BATCHES) = ',I8)
 6073 FORMAT('     EXCEEDS THE MAXIMIM ALLOWABLE OF ',I8)
      ISTEPN='14'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MCOV')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IBUGA2.EQ.'OFF'.AND.ISUBRO.NE.'MCOV')GO TO 6099
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,6081)
 6081 FORMAT('***** FROM SIMCOV, AS ABOUT TO CALL REGINI--')
      CALL DPWRST('XXX','BUG ')
 6099 CONTINUE
!
      SATT=.FALSE.
      IF(IRECSA.EQ.'YES'.OR.IRECSA.EQ.'TRUE'.OR.IRECSA.EQ.'ON')   &
      SATT=.TRUE.
      NREPS=IRECR2
      MAXREP=10*MAXOBV
      IF(NREPS.GT.MAXREP)THEN
        NREPS=MAXREP
        WRITE(ICOUT,998)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,6531)NREPS,MAXREP
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,6532)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,998)
        CALL DPWRST('XXX','WRIT')
      ENDIF
  998 FORMAT(1X)
 6531 FORMAT('THE REQUESTED NUMBER OF SIMULATION REPLICATIONS ',I8,   &
      ' IS GREATER THAN THE ALLOWED MAXIMUM OF ',I8)
 6532 FORMAT('THE MAXIMUM ALLOWED NUMBER OF REPLICATIONS WILL BE ',   &
      'USED.')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,1032)
 1032 FORMAT(20X,'RECIPE SIMCOV ANALYSIS')
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,1132)
 1132 FORMAT(22X,'(MARK VANGEL, NIST)')
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,998)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,1033)NTOT
 1033 FORMAT('NUMBER OF OBSERVATIONS         = ',I8)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,1035)NBCH
 1035 FORMAT('NUMBER OF BATCHES              = ',I8)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,1036)IRECR1
 1036 FORMAT('NUMBER OF SIMCOV SIMULATIONS   = ',I8)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,1037)RECIPC
 1037 FORMAT('PROBABILITY CONTENT            = ',G15.7)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,1039)
 1039 FORMAT('NOTE: PLEASE BE PATIENT.  THE SIMULATION CAN TAKE ',   &
      'SOME TIME.')
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,998)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,1041)
 1041 FORMAT('  CORRELATION      PROBABILITY')
      CALL DPWRST('XXX','WRIT')
!
      CALL REGINI(NLVL,NPAR,NTOT,NBCH,NPRED,XDESGN,XPTS,IP,IQ,   &
                  DBLE(RECIPC),DBLE(RECICO),XMAT,XTX,XTXI,XN,SCRTCH,   &
                  S1,V1,S2,V2,TLM0,TLM1,ETA0,ETA1,   &
                  SATT,IN2,WK2,WK3,   &
                  CRT,ISEED,MAXREP,MAXLVL,   &
                  ICASRE,ISUBRO,IBUGA2,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
      IF(IBUGA2.EQ.'OFF'.AND.ISUBRO.NE.'MCOV')GO TO 6199
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,6181)
 6181 FORMAT('***** FROM SIMCOV, AS ABOUT TO PERFORM SIMULATION--')
      CALL DPWRST('XXX','BUG ')
 6199 CONTINUE
!
      NSIM=IRECR1
      NRHO=IRECC1
      NRAN=1
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MCOV')THEN
        WRITE(ICOUT,6185)NSIM,NRHO,NRAN,NPRED
 6185   FORMAT('NSIM,NRHO,NRAN,NPRED=',4I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!  LOOP OVER INTRACLASS CORRELATION VALUES
!
      DO 7000  IRHO=1,NRHO
        RHO=DBLE(IRHO-1)/DBLE(NRHO-1)
        IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MCOV')THEN
          WRITE(ICOUT,7005)IRHO,RHO
 7005     FORMAT('IRHO,RHO=',I8,E15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
        CALL NODPPF(DBLE(RECIPC),PCT)
        PCT=-PCT
        SDB=DSQRT(RHO)
        SDW=DSQRT(1.0D0-RHO)
        IF(NBCH.EQ.1)THEN
          SDB=0.0D0
          SDW=1.0D0
        ENDIF
        DO 7049  IDX=1,NPRED
          COV(IDX)=0.D0
!CCCC     XMU(IDX)=0.D0
 7049   CONTINUE
        DO 5000  IDX=1,NSIM
          CALL NORRAN(NBCH,ISEED,RES2)
          DO 5021 I=1,NTOT
            CALL NORRAN(NRAN,ISEED,XTMP)
            ERR=DBLE(XTMP(1))
            Y2(I)=DBLE(RES2(IQ(I)))*SDB + ERR*SDW
 5021     CONTINUE
!
        IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MCOV')THEN
          WRITE(ICOUT,7009)
 7009     FORMAT('BEFORE CALL TO REGDAT')
          CALL DPWRST('XXX','BUG ')
        ENDIF
        IFLAG='SIMC'
        CALL REGDAT(NPAR,NTOT,NBCH,NPRED,XPTS,Y2,COEF,   &
                  SCRTCH,S1,V1,TLM0,TLM1,ETA0,ETA1,   &
                  XMAT,XM,T,XDESGN,NLVL,   &
                  ICASRE,IFLAG,ISUBRO,IBUGA2,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MCOV')THEN
        WRITE(ICOUT,7019)
 7019   FORMAT('NPRED = ',I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      DO 4000 I=1,NPRED
        IF(T(I).LT.PCT) COV(I) = COV(I)+1.0D0
 4000 CONTINUE
 5000 CONTINUE
!
      WRITE(ICOUT,998)
      CALL DPWRST('XXX','WRIT')
      DO 6000 I=1,NPRED
        WRITE(ICOUT,2000)RHO,COV(I)/DBLE(NSIM)
 2000   FORMAT(2F12.4)
        CALL DPWRST('XXX','WRIT')
 6000 CONTINUE
!
 7000 CONTINUE
!
!               ***************************************
!               **  STEP 16--                        **
!               **  STORE THE TOLERANCE VALUES       **
!               ***************************************
!7640 CONTINUE
!CCCC IH=IRECTN(1:4)
!CCCC IH2=IRECTN(5:8)
!
!CCCC NEWNAM='NO'
!CCCC DO7650I=1,NUMNAM
!CCCC I2=I
!CCCC IF(IH.EQ.IHNAME(I).AND.IH2.EQ.IHNAM2(I).AND.
!CCCC1IUSE(I).EQ.'V')THEN
!CCCC   ICOLL1=IVALUE(I2)
!CCCC   GO TO 7680
!CCCC ENDIF
!CCCC IF(IH.EQ.IHNAME(I).AND.IH2.EQ.IHNAM2(I).AND.
!CCCC1IUSE(I).NE.'V')THEN
!CCCC   WRITE(ICOUT,7646)
!7646   FORMAT('***** ERROR IN SIMCOV--')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,7647)IRECTN
!7647   FORMAT('      THE REQUESTED NAME FOR THE TOLERANCE ',
!CCCC1         'VARIABLE, ',A8,', WAS FOUND IN THE')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,7648)
!7648   FORMAT('      CURRENT NAME LIST, BUT NOT AS A VARIABLE.')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,7649)
!7649   FORMAT('      THEREFORE THE TOLERANCE VARIABLE WAS NOT ',
!CCCC1         'UPDATED.')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   GO TO 7699
!CCCC ENDIF
!7650 CONTINUE
!CCCC NEWNAM='YES'
!
!  NEW VARIABLE, CHECK TO ENSURE MAXIMUM NAMES AND MAXIMUM
!  COLUMNS NOT EXCEEDED.
!
!CCCC IF(NUMNAM.GE.MAXNAM)THEN
!CCCC   WRITE(ICOUT,7651)
!7651   FORMAT('***** ERROR IN SIMCOV--')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,7652)
!7652   FORMAT('      THE TOTAL NUMBER OF (VARIABLE + PARAMETER)')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,7653)MAXNAM
!7653   FORMAT('      NAMES MUST BE AT MOST ',I8)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,7654)
!7654   FORMAT('      SUCH WAS NOT THE CASE HERE--')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,7655)
!7655   FORMAT('      THE MAXIMUM ALLOWABLE NUMBER OF NAMES')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,7656)
!7656   FORMAT('      WAS JUST EXCEEDED.')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,7657)
!7657   FORMAT('      SUGGESTED ACTION--ENTER     STAT')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,7658)
!7658   FORMAT('      TO DETERMINE THE IMPORTANT')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,7659)
!7659   FORMAT('      (VERSUS UNIMPORTANT) VARIABLES')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,7660)
!7660   FORMAT('      AND PARAMETERS, AND THEN REUSE SOME')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,7661)
!7661   FORMAT('      OF THE NAMES.')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,7662)
!7662   FORMAT('      THE TOLERANCE VARIABLE WAS NOT UPDATED--')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   GO TO 7699
!CCCC ENDIF
!
!CCCC IF(NUMCOL.GE.MAXCOL)THEN
!CCCC   WRITE(ICOUT,7665)
!7665   FORMAT('***** ERROR IN SIMCOV--')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,7666)
!7666   FORMAT('      THE NUMBER OF DATA COLUMNS')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,7667)MAXCOL
!7667   FORMAT('      HAS JUST EXCEEDED THE MAX ALLOWABLE ',I8,'  .')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,7668)
!7668   FORMAT('      SUGGESTED ACTION--')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,7669)
!7669   FORMAT('      ENTER      STATUS VARIABLES')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,7670)
!7670   FORMAT('      TO FIND OUT THE FULL LIST OF USED COLUMNS')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,7671)
!7671   FORMAT('      AND THEN DELETE SOME COLUMNS.')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,7672)
!7672   FORMAT('      THE TOLERANCE VARIABLE WAS NOT UPDATED--')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   GO TO 7699
!CCCC ENDIF
!
!7680 CONTINUE
!CCCC IF(NEWNAM.EQ.'YES')THEN
!CCCC   NUMCOL=NUMCOL+1
!CCCC   ICOLL1=NUMCOL
!CCCC   NUMNAM=NUMNAM+1
!CCCC   IHNAME(NUMNAM)=IH
!CCCC   IHNAM2(NUMNAM)=IH2
!CCCC   IUSE(NUMNAM)='V'
!CCCC   VALUE(NUMNAM)=ICOLL1
!CCCC   IVALUE(NUMNAM)=ICOLL1
!CCCC   NTEMP=NTOT
!CCCC   IF(ICASRE.EQ.'FREC'.AND.ILOCXP.GT.0)NTEMP=NPRED
!CCCC   IN(NUMNAM)=NTEMP
!CCCC   IF(IBUGA2.EQ.'ON')THEN
!CCCC     WRITE(ICOUT,7683)IN(NUMNAM)
!7683     FORMAT('IN(NUMNAM)=',I8)
!CCCC     CALL DPWRST('XXX','BUG ')
!CCCC   ENDIF
!CCCC ELSE
!CCCC   NTEMP=NTOT
!CCCC   IF(ICASRE.EQ.'FREC'.AND.ILOCXP.GT.0)NTEMP=NPRED
!CCCC   IF(ICASRE.EQ.'UREC')NTEMP=1
!CCCC   IN(ICOLL1)=NTEMP
!CCCC   IF(IBUGA2.EQ.'ON')THEN
!CCCC     WRITE(ICOUT,7686)IN(ICOLL1)
!7686     FORMAT('IN(ICOLL1)=',I8)
!CCCC     CALL DPWRST('XXX','BUG ')
!CCCC   ENDIF
!CCCC ENDIF
!CCCC IF(IBUGA2.EQ.'ON')THEN
!CCCC   WRITE(ICOUT,7681)NEWNAM,ICOLL1,NUMCOL,NUMNAM,NPRED,NTEMP
!CCCC   CALL DPWRST('XXX','BUG ')
!7681   FORMAT('NEWNAM,ICOLL1,NUMCOL,NUMNAM,NPRED,NTEMP =',
!CCCC1         A4,1X,5I8)
!CCCC ENDIF
!CCCC K=ICOLL1
!CCCC DO7682I=1,NTEMP
!CCCC   IJ=MAXN*(K-1)+I
!CCCC   IF(K.LE.MAXCOL)V(IJ)=T(I)
!CCCC   IF(K.EQ.MAXCP1)PRED(I)=T(I)
!CCCC   IF(K.EQ.MAXCP1)RES(I)=T(I)
!CCCC   IF(K.EQ.MAXCP1)YPLOT(I)=T(I)
!CCCC   IF(K.EQ.MAXCP1)XPLOT(I)=T(I)
!CCCC   IF(K.EQ.MAXCP1)X2PLOT(I)=T(I)
!CCCC   IF(K.EQ.MAXCP1)TAGPLO(I)=T(I)
!7682 CONTINUE
!
!7699 CONTINUE
!
!8000 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA2.EQ.'OFF'.AND.ISUBRO.NE.'MCOV')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF SIMCOV--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGA2,IBUGA3
 9012 FORMAT('IBUGA2,IBUGA3 = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)IBUGCO,IBUGEV,IBUGQ
 9013 FORMAT('IBUGCO,IBUGEV,IBUGQ = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)NPAR,NTOT,NBCH,NLVL,ICASRE
 9015 FORMAT('NPAR,NTOT,NBCH,NLEVL,ICASRE = ',4(I8,1X),2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9052)ICASEQ
 9052 FORMAT('ICASEQ = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9061)IWIDTH
 9061 FORMAT('IWIDTH = ',I8)
      CALL DPWRST('XXX','BUG ')
      IF(IWIDTH.GE.1)WRITE(ICOUT,9062)(IANS(I),I=1,MIN(100,IWIDTH))
 9062 FORMAT('(IANS(I),I=1,IWIDTH) = ',100A1)
      IF(IWIDTH.GE.1)CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9069)IFOUND,IERROR
 9069 FORMAT('IFOUND,IERROR = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE SIMCOV
      SUBROUTINE SIMPLX(A,M,N,MP,NP,M1,M2,M3,   &
      ICASE,IZROV,IPOSV,IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--CARRY OUT SIMPLEX LINEAR PROGRAMMING SOLUTION
!
!     INPUT  ARGUMENTS--
!
!     SOURCE--NUMERICAL RECIPES,
!             PRESS, FLANNERY, TEUKOLSKY, AND VETTERLING,
!             CAMBRIDGE UNIVERSITY PRESS, 1986.
!
!---------------------------------------------------------------------
!
!CCCC PARAMETER(MMAX=100,EPS=1.E-6)
!CCCC PARAMETER(MMAX=100,EPS=1.E-3)
      PARAMETER(MMAX=100)
!
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      DIMENSION A(MP,NP),IZROV(N),IPOSV(M),L1(MMAX),L2(MMAX),L3(MMAX)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IERROR='NO'
!
      JMAX=0
      MP1=M+1
      NP1=N+1
!
      MP2=M+2
!
      IF(IBUGA3.EQ.'OFF'.AND.ISUBRO.NE.'MPLX')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF SIMPLX--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGA3,ISUBRO
   52 FORMAT('IBUGA3,ISUBRO = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,61)M,N,MP,NP,M1,M2,M3
   61 FORMAT('M,N,MP,NP,M1,M2,M3 = ',7I8)
      CALL DPWRST('XXX','BUG ')
      IF(M.LE.0)GO TO 69
      IF(N.LE.0)GO TO 69
      JMAX=NP1
      IF(JMAX.GT.10)JMAX=10
      DO 62 I=1,MP2
      WRITE(ICOUT,63)I,(A(I,J),J=1,JMAX)
   63 FORMAT('I,A(I,.) = ',I8,10F10.2)
      CALL DPWRST('XXX','BUG ')
   62 CONTINUE
   69 CONTINUE
   90 CONTINUE
!
!     MAKE A CORRECTION (THANKS TO CHRIS WITZGEL, NBS)
!     ON THE VALUE OF EPSILON
!     TO CIRCUMVENT A BUG ARISING FROM
!     A TEST PROBLEM DRAWN FROM
!     BRONSON/SCHAUM OP. RES. (PROBLEM 1.7).
!     (SEPT, 1987)
!
      AM=M
      SUM=0.0
      DO 1000 I=1,M
      MP1=M+1
      SUM=SUM+A(MP1,1)
 1000 CONTINUE
      XBAR=SUM/AM
      EPSEXP=6.0
      IF(XBAR.GT.0.0)EPSEXP=6.0-AINT(LOG10(XBAR)+0.5)
      IF(EPSEXP.LT.1.0)EPSEXP=1.0
      EPS=10.0**(-EPSEXP)
!
!CCCC IF(M.NE.M1+M2+M3)PAUSE 'Bad input constraint counts.'
      IF(M.NE.M1+M2+M3)GO TO 110
      GO TO 119
  110 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,111)
  111 FORMAT('***** ERROR IN SIMPLX--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,112)
  112 FORMAT('      BAD INPUT CONSTRAINT COUNTS.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,113)M
  113 FORMAT('      M = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,114)M1,M2,M3
  114 FORMAT('      M1,M2,M3 = ',3I8)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
  119 CONTINUE
!
      NL1=N
      DO 11 K=1,N
        L1(K)=K
        IZROV(K)=K
11    CONTINUE
      NL2=M
      DO 12 I=1,M
!
!CCCC   IF(A(I+1,1).LT.0.)PAUSE 'Bad input tableau.'
      IF(A(I+1,1).LT.0.)GO TO 120
      GO TO 129
  120 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,121)
  121 FORMAT('***** ERROR IN SIMPLX--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,122)
  122 FORMAT('      BAD INPUT TABLEAU.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,123)
  123 FORMAT('      POSSIBLE CAUSE--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,124)
  124 FORMAT('      SOME CONSTRAINT LIMIT IS NEGATIVE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,125)
  125 FORMAT('      (FORBIDDEN IN SIMPLEX METHOD)')
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
  129 CONTINUE
!
        L2(I)=I
        IPOSV(I)=N+I
12    CONTINUE
!
      DO 13 I=1,M2
        L3(I)=1
13    CONTINUE
!
      IR=0
      IF(M2+M3.EQ.0)GO TO 30
      IR=1
!
      DO 15 K=1,N+1
        Q1=0.
        DO 14 I=M1+1,M
          Q1=Q1+A(I+1,K)
14      CONTINUE
        A(M+2,K)=-Q1
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MPLX')   &
      WRITE(ICOUT,777)K,A(M+2,K)
  777 FORMAT('K,A(M+2,K) = ',I8,F10.2)
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MPLX')   &
      CALL DPWRST('XXX','BUG ')
15    CONTINUE
!
10    CONTINUE
      CALL SIMP1(A,MP,NP,M+1,L1,NL1,0,KP,BMAX)
      IF(IBUGA3.EQ.'OFF'.AND.ISUBRO.NE.'MPLX')GO TO 790
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      DO 782 I=1,MP2
      WRITE(ICOUT,783)I,(A(I,J),J=1,JMAX)
  783 FORMAT('I,A(I,.) = ',I8,10F10.2)
      CALL DPWRST('XXX','BUG ')
  782 CONTINUE
      WRITE(ICOUT,784)IR,BMAX,A(M+2,1),EPS,XBAR
  784 FORMAT('IR,BMAX,A(M+2,1),EPS,XBAR = ',I8,4E15.7)
      CALL DPWRST('XXX','BUG ')
  790 CONTINUE
!
      IF(BMAX.LE.EPS.AND.A(M+2,1).LT.-EPS)THEN
        ICASE=-1
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,211)
  211 FORMAT('***** ERROR IN SIMPLX (FROM CODE POINT 211)--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,212)
  212 FORMAT('      NO SOLUTION SATISFIES ALL CONSTRAINTS.')
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
!CCCC   RETURN
        GO TO 9000
!
      ELSE IF(BMAX.LE.EPS.AND.A(M+2,1).LE.EPS)THEN
        M12=M1+M2+1
        IF(M12.LE.M)THEN
          DO 16 IP=M12,M
            IF(IPOSV(IP).EQ.IP+N)THEN
              CALL SIMP1(A,MP,NP,IP,L1,NL1,1,KP,BMAX)
              IF(BMAX.GT.0.)GO TO 1
            ENDIF
16        CONTINUE
        ENDIF
        IR=0
        M12=M12-1
        IF(M1+1.GT.M12)GO TO 30
!
        DO 18 I=M1+1,M12
          IF(L3(I-M1).EQ.1)THEN
            DO 17 K=1,N+1
              A(I+1,K)=-A(I+1,K)
17          CONTINUE
          ENDIF
18      CONTINUE
!
        GO TO 30
      ENDIF
      CALL SIMP2(A,M,N,MP,NP,L2,NL2,IP,KP,Q1)
      IF(IP.EQ.0)THEN
        ICASE=-1
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,221)
  221 FORMAT('***** ERROR IN SIMPLX (FROM CODE POINT 221)--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,222)
  222 FORMAT('      NO SOLUTION SATISFIES ALL CONSTRAINTS.')
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
!CCCC   RETURN
        GO TO 9000
      ENDIF
!
1     CONTINUE
      CALL SIMP3(A,MP,NP,M+1,N,IP,KP)
      IF(IPOSV(IP).GE.N+M1+M2+1)THEN
        DO 19 K=1,NL1
          IF(L1(K).EQ.KP)GO TO 2
19      CONTINUE
2       CONTINUE
        NL1=NL1-1
        DO 21 IS=K,NL1
          L1(IS)=L1(IS+1)
21      CONTINUE
      ELSE
        IF(IPOSV(IP).LT.N+M1+1)GO TO 20
        KH=IPOSV(IP)-M1-N
        IF(L3(KH).EQ.0)GO TO 20
        L3(KH)=0
      ENDIF
      A(M+2,KP+1)=A(M+2,KP+1)+1.
      DO 22 I=1,M+2
        A(I,KP+1)=-A(I,KP+1)
22    CONTINUE
20    CONTINUE
      IS=IZROV(KP)
      IZROV(KP)=IPOSV(IP)
      IPOSV(IP)=IS
      IF(IR.NE.0)GO TO 10
30    CONTINUE
      CALL SIMP1(A,MP,NP,0,L1,NL1,0,KP,BMAX)
      IF(BMAX.LE.0.)THEN
        ICASE=0
!CCCC   RETURN
        GO TO 9000
      ENDIF
      CALL SIMP2(A,M,N,MP,NP,L2,NL2,IP,KP,Q1)
      IF(IP.EQ.0)THEN
        ICASE=1
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,231)
  231 FORMAT('***** ERROR IN SIMPLX--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,232)
  232 FORMAT('      OBJECTIVE FUNCTION UNBOUNDED IN THIS REGION.')
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
!CCCC   RETURN
        GO TO 9000
      ENDIF
      CALL SIMP3(A,MP,NP,M,N,IP,KP)
      GO TO 20
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'OFF'.AND.ISUBRO.NE.'MPLX')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF SIMPLX--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGA3,ISUBRO
 9012 FORMAT('IBUGA3,ISUBRO = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9021)M,N,MP,NP,M1,M2,M3,MP1,NP1
 9021 FORMAT('M,N,MP,NP,M1,M2,M3,MP1,NP1 = ',9I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9022)ICASE
 9022 FORMAT('ICASE = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9023)XBAR,EPS
 9023 FORMAT('XBAR,EPS = ',2E15.7)
      CALL DPWRST('XXX','BUG ')
      IF(M.LE.0)GO TO 9039
      IF(N.LE.0)GO TO 9039
      JMAX=NP1
      IF(JMAX.GT.10)JMAX=10
      DO 9032 I=1,MP1
      WRITE(ICOUT,9033)I,(A(I,J),J=1,JMAX)
 9033 FORMAT('I,A(I,.) = ',I8,10F10.2)
      CALL DPWRST('XXX','BUG ')
 9032 CONTINUE
 9039 CONTINUE
      DO 9041 I=1,M
      WRITE(ICOUT,9042)I,IPOSV(I)
 9042 FORMAT('I,IPOSV(I) = ',2I8)
      CALL DPWRST('XXX','BUG ')
 9041 CONTINUE
      DO 9051 I=1,N
      WRITE(ICOUT,9052)I,IZROV(I)
 9052 FORMAT('I,IZROV(I) = ',2I8)
      CALL DPWRST('XXX','BUG ')
 9051 CONTINUE
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE SIMPLX
      SUBROUTINE SIMP1(A,MP,NP,MM,LL,NLL,IABF,KP,BMAX)
!
!     PURPOSE--
!
!     SOURCE--NUMERICAL RECIPES,
!             PRESS, FLANNERY, TEUKOLSKY, AND VETTERLING,
!             CAMBRIDGE UNIVERSITY PRESS, 1986.
!
!
!---------------------------------------------------------------------
!
      DIMENSION A(MP,NP),LL(NP)
!
!-----START POINT-----------------------------------------------------
!
      KP=LL(1)
      BMAX=A(MM+1,KP+1)
      IF(NLL.LT.2)RETURN
      DO 11 K=2,NLL
        IF(IABF.EQ.0)THEN
          TEST=A(MM+1,LL(K)+1)-BMAX
        ELSE
          TEST=ABS(A(MM+1,LL(K)+1))-ABS(BMAX)
        ENDIF
        IF(TEST.GT.0.)THEN
          BMAX=A(MM+1,LL(K)+1)
          KP=LL(K)
        ENDIF
11    CONTINUE
!
      RETURN
      END SUBROUTINE SIMP1
      SUBROUTINE SIMP2(A,M,N,MP,NP,L2,NL2,IP,KP,Q1)
!
!     PURPOSE--
!
!     SOURCE--NUMERICAL RECIPES,
!             PRESS, FLANNERY, TEUKOLSKY, AND VETTERLING,
!             CAMBRIDGE UNIVERSITY PRESS, 1986.
!
!---------------------------------------------------------------------
!
      PARAMETER (EPS=1.E-6)
      DIMENSION A(MP,NP),L2(MP)
!
      INCLUDE 'DPCOBE.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(ISUBG4.EQ.'IMP2')THEN
        WRITE(ICOUT,1)M,N,MP,NP
    1   FORMAT('M,N,MP,NP = ',4I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      Q0=0.0
      QP=0.0
!
      IP=0
      IF(NL2.LT.1)RETURN
      DO 11 I=1,NL2
        IF(A(L2(I)+1,KP+1).LT.-EPS)GO TO 2
11    CONTINUE
      RETURN
2     Q1=-A(L2(I)+1,1)/A(L2(I)+1,KP+1)
      IP=L2(I)
      IF(I+1.GT.NL2)RETURN
      DO 13 I=I+1,NL2
        II=L2(I)
        IF(A(II+1,KP+1).LT.-EPS)THEN
          Q=-A(II+1,1)/A(II+1,KP+1)
          IF(Q.LT.Q1)THEN
            IP=II
            Q1=Q
          ELSE IF (Q.EQ.Q1) THEN
            DO 12 K=1,N
              QP=-A(IP+1,K+1)/A(IP+1,KP+1)
              Q0=-A(II+1,K+1)/A(II+1,KP+1)
              IF(Q0.NE.QP)GO TO 6
12          CONTINUE
6           IF(Q0.LT.QP)IP=II
          ENDIF
        ENDIF
13    CONTINUE
!
      RETURN
      END SUBROUTINE SIMP2
      SUBROUTINE SIMP3(A,MP,NP,I1,K1,IP,KP)
!
!     PURPOSE--
!
!     SOURCE--NUMERICAL RECIPES,
!             PRESS, FLANNERY, TEUKOLSKY, AND VETTERLING,
!             CAMBRIDGE UNIVERSITY PRESS, 1986.
!
!---------------------------------------------------------------------
!
      DIMENSION A(MP,NP)
!
!-----START POINT-----------------------------------------------------
!
      PIV=1./A(IP+1,KP+1)
      IF(I1.GE.0)THEN
        DO 12 II=1,I1+1
          IF(II-1.NE.IP)THEN
            A(II,KP+1)=A(II,KP+1)*PIV
            DO 11 KK=1,K1+1
              IF(KK-1.NE.KP)THEN
                A(II,KK)=A(II,KK)-A(IP+1,KK)*A(II,KP+1)
              ENDIF
11          CONTINUE
          ENDIF
12      CONTINUE
      ENDIF
      DO 13 KK=1,K1+1
        IF(KK-1.NE.KP)A(IP+1,KK)=-A(IP+1,KK)*PIV
13    CONTINUE
      A(IP+1,KP+1)=PIV
!
      RETURN
      END SUBROUTINE SIMP3
      SUBROUTINE SIMRAT   &
       (U1, S1, V1, IQ, W, NBCH, NTOT, NPAR, NREP, IRK,   &
       XNCP, CONF, WK1, WK2, VALS, QUANT,IERROR)
!
!      MARK VANGEL, APRIL 1995
!
!        SIMULATE THE PIVOTAL RATIO IN THE LIMIT OF ZERO
!     WITHIN-GROUP VARIANCE.
!
!     SINGULAR VALUE DECOMPOSITION OF THE DEISGN MATRIX:
!     U1, S1, V1  ---  (INPUT, D.P.)
!     IQ    ---   BATCH INDICATOR (INPUT, INT., LENGTH `NBCH')
!     W     ---   VECTOR OF COEFFICIENTS OF POINT AT WHICH TOL.
!             LIM. IS TO BE CALCULATED (INPUT, D.P., LENGTH `NREP')
!     NBCH  ---   NUMBER OF BATCHES (INPUT, INT.)
!     NTOT  ---   TOTAL NUMBER OF DATA VALUES (INPUT, INT.)
!     NPAR  ---   NUMBER OF REGRESSION COEFFICIENTS (INPUT, INT.)
!     NREP  ---   NUMBER OF SIMULATION REPLICATES (INPUT, INT.)
!     IRK   ---   RANK OF DESIGN MATRIX (INPUT, INT.)
!     XNCP  ---   NONCENTRALITY PARAMETER (Z_{\BETA}) (INPUT,D.P.)
!     CONF  ---   CONFIDENCE LEVEL (INPUT, D.P.)
!     WK1   ---   WORK ARRAY (OUTPUT, D.P., LENGTH MAX(NBCH, IRK))
!     WK2   ---   WORK ARRAY (OUTPUT, D.P., LENGTH NTOT)
!     VALS  ---   ARRAY OF SIM. VALUES (OUTPUT, D.P., LENGTH NREP)
!     QUANT ---   ESTIMATED QUANTILE (OUPUT, D.P.)
!
      IMPLICIT DOUBLE PRECISION (A-H, O-Z)
!CCCC REAL RNOR
      REAL XTMP(1)
      DOUBLE PRECISION DUM(1)
      CHARACTER*4 IERROR
      DIMENSION U1(1), S1(1), V1(1), IQ(1), W(1), WK1(1),   &
                WK2(1), VALS(1)
      DATA ZERO, ONE /0.D0, 1.D0/
!
!     -- LOOP OVER `NREP' REPLICATES
      NRAN=1
      DO 100 ISIM=1, NREP
!
!     -- GENERATE ONE N(0,1) R.V. FOR EACH LEVEL OF RANDOM
!        EFFECT.
         DO 10 I=1, NBCH
!CCCC      WK1(I) = RNOR(0)
           CALL NORRAN(NRAN,ISEED,XTMP)
           WK1(I)=DBLE(XTMP(1))
 10      CONTINUE
!
!     --  CREATE PSEUDO-RANDOM DATA FOR \SIGMA_{E}^2 = 0 CASE
         DO 20 I=1, NTOT
            WK2(I) = WK1(IQ(I))
 20      CONTINUE
         Y2 = DDOT (NTOT, WK2, 1, WK2, 1)
!
!     -- FORM VECTOR Q = (U^T)Y
         CALL DGEMV ('T', NTOT, IRK, ONE, U1, NTOT,   &
                  WK2, 1, ZERO, WK1, 1, IERROR)
         IF(IERROR.EQ.'YES')RETURN
         Q2 = DDOT (IRK, WK1, 1, WK1, 1)
!
!     -- FORM VECTOR W = (V^T)W
         CALL DGEMV ('T', NPAR, NTOT, ONE, V1, NPAR,   &
                  W,   1, ZERO, WK2,   1, IERROR)
         IF(IERROR.EQ.'YES')RETURN
!
!     -- CALCULATE W^T(L^(-))Q, WHERE L IS MATRIX OF SVS
         XNUM = 0
         DO 30 I=1, IRK
            XNUM = XNUM +WK2(I) *WK1(I) /S1(I)
 30      CONTINUE
!
!     -- CALCULATE RESIDUAL SUM OF SQUARES
         RSS = Y2 -Q2
!
!     -- FINALLY, FORM RATIO AND RETURN
         VALS (ISIM) = (XNUM+XNCP) /SQRT(RSS/(NTOT -IRK))
 100  CONTINUE
!
!     -- SORT THE SIMULATED PIVOT VALUES
      KFLAG=1
      CALL DSORT (VALS, DUM, NREP, KFLAG, IERROR)
!
!     -- RETURN THE DESIRED QUANTILE
      IDX   = INT(CONF*NREP)
      QUANT = VALS(IDX)
      RETURN
      END SUBROUTINE SIMRAT                 
      SUBROUTINE SINCDF(X,CDF)
!
!     NOTE--SINE CDF IS:
!              SINCDF(X) = SIN((X/2) + (PI/4))**2
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGYS
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2899
!     REFERENCE--PETER BURROWS, "EXTREME STATISTICS FROM THE SINE
!                DISTRIBUTION", THE AMERICAN STATISTICIAN, AUGUST 1986,
!                VOL. 40, NO. 3, PP. 216-218.
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGYS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2013/3
!     ORIGINAL VERSION--MARCH     2013.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA PI/3.1415926535898E0/
!
!-----START POINT-----------------------------------------------------
!
      CDF=0.0
      PI2=PI/2.0
      PI4=PI/4.0
      IF(X.LE.-PI2)THEN
        CDF=0.0
      ELSEIF(X.GE.PI2)THEN
        CDF=1.0
      ELSE
        CDF=SIN((X/2.0) + PI4)**2
      ENDIF
!
      RETURN
      END SUBROUTINE SINCDF
      SUBROUTINE SINFIT(X,TEMP,N,IWRITE,XSINFR,XSINAM,XRESSD,   &
      ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE
!              SINUSOIDAL FREQUENCY ESTIMATE
!              AND THE SINUSOIDAL AMPLITUDE ESTIMATE
!              OF THE DATA IN THE INPUT VECTOR X.
!              THE FREQUENCY AND AMPLITUDE ESTIMATE =
!              THAT APPROXIMATE LEAST SQUARES FIT FREQUENCY AND AMP.
!              WHICH BEST FITS THE DATA IN A 1-FREQUENCY SIN MODEL.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XSINFR = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE AUTOCOVARIANCE
!                                COEFFICIENT.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SINUSOIDAL FREQUENCY ESTIMATE AND AMPLITUDE ESTIMATE.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCE--BLOOMFIELD, PETER, FOURIER ANALYSIS OF TIME SERIES:
!                AN INTRODUCTION, WILEY, 1976, PAGES 14 AND 18.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     VERSION NUMBER--88/1
!     ORIGINAL VERSION--JANUARY   1988.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DX
!CCCC DOUBLE PRECISION DX1
!CCCC DOUBLE PRECISION DX2
      DOUBLE PRECISION DSUM
      DOUBLE PRECISION DMEAN
!
      DIMENSION X(*)
      DIMENSION TEMP(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='SINF'
      ISUBN2='IT  '
      IERROR='NO'
!
      PI=3.1415926
!
      DN=0.0D0
      DMEAN=0.0D0
!
      IF(IBUGA3.EQ.'OFF'.AND.ISUBRO.NE.'NFIT')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF SINFIT--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)ISUBRO,IBUGA3,N
   52 FORMAT('ISUBRO,IBUGA3,N = ',2(A4,2X),I8)
      CALL DPWRST('XXX','BUG ')
      DO 55 I=1,N
      WRITE(ICOUT,56)I,X(I)
   56 FORMAT('I,X(I) = ',I8,G15.7)
      CALL DPWRST('XXX','BUG ')
   55 CONTINUE
   90 CONTINUE
!
!               *******************************************
!               **  COMPUTE  APPROX. LEAST SQUARES FIT   **
!               **  ESTIMATE OF UENCY                    **
!               **  IN A 1-TERM SINUSOIDAL MODEL.        **
!               *******************************************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.LT.1)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN SINFIT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS MUST BE 1 OR ',   &
               'LARGER.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,116)
  116   FORMAT('      SUCH WAS NOT THE CASE HERE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(N.EQ.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,121)
  121   FORMAT('***** WARNING IN SINFIT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,123)
  123   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS IS EXACTLY ',   &
               'EQUAL TO ONE.')
        CALL DPWRST('XXX','BUG ')
        XSINFR=0.0
        GO TO 9000
      ENDIF
!
      HOLD=X(1)
      DO 135 I=2,N
      IF(X(I).NE.HOLD)GO TO 139
  135 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,121)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,136)HOLD
  136 FORMAT('      THE RESPONSE VARIABLE HAS ALL ELEMENTS = ',G15.7)
      CALL DPWRST('XXX','BUG ')
      XSINFR=0.0
      GO TO 9000
  139 CONTINUE
!
!               ************************************************
!               **  STEP 2--                                  **
!               **  COMPUTE THE  APPROXIMATE LEAST SQUARES    **
!               **  SINUSOIDAL FREQUENCY ESTIMATE             **
!               ************************************************
!
      DN=N
      DSUM=0.0D0
      DO 200 I=1,N
      DX=X(I)
      DSUM=DSUM+DX
  200 CONTINUE
      DMEAN=DSUM/DN
      XMEAN=DMEAN
!
      DO 300 I=1,N
      TEMP(I)=X(I)-XMEAN
  300 CONTINUE
!
      SSQHOL=CPUMAX
      NLOOP=100
      ANLOOP=NLOOP
      DO 500 IANGLE=1,NLOOP
      AANGLE=IANGLE
      THETA=AANGLE/(2.0*ANLOOP)
      OMEGA=2.0*PI*THETA
!
      SUM1=0.0
      SUM2=0.0
      DO 550 I=1,N
      AI=I
      SUM1=SUM1+X(I)*COS(OMEGA*AI)
      SUM2=SUM2+X(I)*SIN(OMEGA*AI)
  550 CONTINUE
      A=(2.0/AN)*SUM1
      B=(2.0/AN)*SUM2
      AMP=A*A+B*B
      IF(AMP.GT.0.0)AMP=SQRT(AMP)
!
      SSQZ=0.0
      DO 560 I=1,N
      AI=I
      PREDI=A*COS(OMEGA*AI)+B*SIN(OMEGA*AI)
      RESI=TEMP(I)-PREDI
      SSQZ=SSQZ+RESI**2
  560 CONTINUE
!
      IF(IANGLE.LE.1)GO TO 561
      GO TO 562
  561 CONTINUE
      FREHOL=THETA
      AMPHOL=AMP
      SSQHOL=SSQZ
      GO TO 569
  562 CONTINUE
      IF(SSQZ.LT.SSQHOL)FREHOL=THETA
      IF(SSQZ.LT.SSQHOL)AMPHOL=AMP
      IF(SSQZ.LT.SSQHOL)SSQHOL=SSQZ
      GO TO 569
  569 CONTINUE
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'NFIT')THEN
        WRITE(ICOUT,563)AANGLE,THETA,SSQZ,SSQHOL,A,B,AMP
  563   FORMAT('AANGLE,THETA,SSQZ,SSQHOL,A,B,AMP = ',7E12.4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
  500 CONTINUE
      XSINFR=FREHOL
      XSINAM=AMPHOL
      RESSD=SSQHOL/(AN-2.0)
      IF(RESSD.GT.0.0)RESSD=SQRT(RESSD)
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'NFIT')THEN
        WRITE(ICOUT,591)XSINFR,XSINAM,XRESSD
  591   FORMAT('XSINFR,XSINAM,XRESSD = ',3E15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'OFF')GO TO 890
      IF(IWRITE.EQ.'OFF')GO TO 890
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,811)N,XSINFR
  811 FORMAT('THE SINUSOIDAL FREQUENCY ESTIMATE FOR THE ',I8,   &
      ' OBSERVATIONS = ',G15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,812)N,XSINAM
  812 FORMAT('THE SINUSOIDAL AMPLITUDE ESTIMATE FOR THE ',I8,   &
      ' OBSERVATIONS = ',G15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,813)XRESSD
  813 FORMAT('THE RESIDUAL STANDARD DEVIATION = ',G15.7)
      CALL DPWRST('XXX','BUG ')
  890 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'OFF'.AND.ISUBRO.NE.'NFIT')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF SINFIT--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)ISUBRO,IBUGA3,IERROR
 9012 FORMAT('ISUBRO,IBUGA3,IERROR = ',2(A4,2X),A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9014)N,DN,DMEAN
 9014 FORMAT('N,DN,DMEAN = ',I8,2G15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)XSINFR,XSINAM,XRESSD
 9015 FORMAT('XSINFR,XSINAM,XRESSD = ',3G15.7)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE SINFIT
      SUBROUTINE SINPDF(X,PDF)
!
!     NOTE--SINE PDF IS:
!              SINPDF(X) = 0.5*COS(X)
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGYS
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2899
!     REFERENCE--PETER BURROWS, "EXTREME STATISTICS FROM THE SINE
!                DISTRIBUTION", THE AMERICAN STATISTICIAN, AUGUST 1986,
!                VOL. 40, NO. 3, PP. 216-218.
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGYS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2013/3
!     ORIGINAL VERSION--MARCH     2013.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA PI/3.1415926535898E0/
!
!-----START POINT-----------------------------------------------------
!
      PDF=0.0
      PI2=PI/2.0
      IF(X.LT.-PI2 .OR. X.GT.PI2)THEN
        WRITE(ICOUT,301)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,302)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
  301 FORMAT('***** ERROR--THE INPUT ARGUMENT TO SINPDF IS NOT IN THE ',   &
             'INTERVAL (-PI/2,PI/2).')
  302 FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      PDF=0.5*COS(X)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE SINPDF
      SUBROUTINE SINPPF(P,PPF)
!
!     NOTE--THE SINE PPF IS:
!
!               G(P) = 2*(ARCSIN(SQRT(P)) - (PI/4))
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGYS
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGYS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2013/3
!     ORIGINAL VERSION--MARCH     2013.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA PI/3.1415926535898E0/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(P.LT.0.0.OR.P.GT.1.0)THEN
        WRITE(ICOUT,1)
    1   FORMAT('***** ERROR--THE FIRST ARGUMENT TO SINPPF IS OUTSIDE',   &
               ' THE ALLOWABLE (0,1) INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9000
      ENDIF
!
      IF(P.LE.0.0)THEN
        PPF=-PI/2.0
      ELSEIF(P.GE.1.0)THEN
        PPF=PI/2.0
      ELSE
        ARG=SQRT(P)
        ARG2=ARG/SQRT(1.0 - ARG*ARG)
        TERM1=ATAN(ARG2)
        PPF=2.0*(TERM1 - (PI/4.0))
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE SINPPF
      SUBROUTINE SINRAN(N,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE SINE DISTRIBUTION
!              F(X) = 0.5*EXP(-ABS(X)).
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N FROM THE SINE DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--ALAN HECKER
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGYS
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGYS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2013/3
!     ORIGINAL VERSION--MARCH     2013.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
    5   FORMAT('***** ERROR--THE FIRST ARGUMENT TO SINRAN IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
   47   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
        CALL DPWRST('XXX','BUG ')
        RETURN
      ENDIF
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N COSINE RANDOM NUMBERS
!     USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      DO 100 I=1,N
        CALL SINPPF(X(I),XTEMP)
        X(I)=XTEMP
  100 CONTINUE
!
      RETURN
      END SUBROUTINE SINRAN
      SUBROUTINE SINTRA(Y1,N1,IWRITE,Y2,N2,IBUGA3,IERROR)
!
!     PURPOSE--COMPUTE SINE TRANSFORM OF A VARIABLE--
!            = THE COEFFICIENTS OF THE SINE TERM
!              IN THE FINITE FOURIER RESPRESENTATION OF THE DATA IN Y1.
!              Y2(1) = B0 = 0
!              Y2(2) = B1
!              Y2(3) = B2
!              ETC.
!     NOTE--IT IS NOT PERMISSIBLE TO HAVE THE OUTPUT VECTOR Y2(.)
!           BEING IDENTICAL TO THE INPUT VECTOR Y1(.).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--85/1
!     ORIGINAL VERSION--DECEMBER  1984.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!-----DOUBLE PRECISION STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DPI
      DOUBLE PRECISION DN1
      DOUBLE PRECISION DDEL
      DOUBLE PRECISION DI
      DOUBLE PRECISION DSUM
      DOUBLE PRECISION DK
      DOUBLE PRECISION DOMEGA
      DOUBLE PRECISION DY1K
!
!---------------------------------------------------------------------
!
      DIMENSION Y1(*)
      DIMENSION Y2(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='SINT'
      ISUBN2='RA  '
      IERROR='NO'
!
      N1HALF=(-999)
      IMAX=(-999)
      IEVODD=(-999)
      DDEL=(-999.0D0)
!
      DN1=N1
!
      DPI=3.14159265358979D0
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF SINTRA--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,IWRITE,N1,MAXOBV
   52   FORMAT('IBUGA3,IWRITE,N1,MAXOBV = ',2(A4,2X),2I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N1
          WRITE(ICOUT,56)I,Y1(I)
   56     FORMAT('I,Y1(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ***********************************
!               **  COMPUTE SINE TRANSFORM.      **
!               ***********************************
!
      IF(N1.LT.1)GO TO 1100
      GO TO 1190
!
 1100 CONTINUE
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1151)
 1151 FORMAT('***** ERROR IN SINTRA--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1152)
 1152 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1153)
 1153 FORMAT('      IN THE VARIABLE FOR WHICH')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1154)
 1154 FORMAT('      THE SINE TRANSFORM IS TO BE COMPUTED')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1155)
 1155 FORMAT('      MUST BE 1 OR LARGER.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1156)
 1156 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1157)N1
 1157 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS HERE = ',I8,   &
      '.')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
!
 1190 CONTINUE
!
      N1HALF=N1/2
      N1HALP=N1HALF+1
      IMAX=N1HALP
      IEVODD=N1-2*(N1/2)
      DDEL=(DN1+1.0D0)/2.0D0
      IF(IEVODD.EQ.0)DDEL=(DN1+2.0D0)/2.0D0
!
      J=0
      J=J+1
      Y2(J)=0.0
!
      DO 1210 IP1=2,IMAX
      J=J+1
      I=IP1-1
      DI=I
!CCCC FREQI=DI/DN1
      DSUM=0.0D0
!
      DO 1220 K=1,N1
      DK=K
      DOMEGA=2.0*DPI*(DI/DN1)
      DY1K=Y1(K)
      DSUM=DSUM+DY1K*DSIN(DOMEGA*(DK-DDEL))
 1220 CONTINUE
      COEF=DSUM/DN1
      IF(IBUGA3.EQ.'ON')WRITE(ICOUT,1221)J,I,DN1,DI,COEF
 1221 FORMAT('J,I,DN1,DI,COEF = ',I8,I8,2D15.7,E15.7)
      IF(IBUGA3.EQ.'ON')CALL DPWRST('XXX','BUG ')
!
      Y2(J)=COEF
!
 1210 CONTINUE
!
      N2=J
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF SINTRA--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR
 9012   FORMAT('IERROR = ',A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)N1,N2,N1HALF,IMAX,IEVODD,DDEL
 9013   FORMAT('N1,N2,N1HALF,IMAX,IEVODD,DDEL = ',5I8,D15.7)
        CALL DPWRST('XXX','BUG ')
        DO 9015 I=1,N1
          WRITE(ICOUT,9016)I,Y1(I),Y2(I)
 9016     FORMAT('I,Y1(I),Y2(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
 9015   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE SINTRA
      SUBROUTINE SIZE(X,N,IWRITE,XSIZE,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE    COMPUTES    THE
!              SAMPLE SIZE
!              OF THE DATA IN THE INPUT VECTOR X.
!              THE SAMPLE SIZE IS IDENTICALLY = THE INPUT ARGUMENT N
!              EXCEPT N IS AN INTEGER VARIABLE
!              WHEREAS THE OUTPUTTED XSIZE IS A SINGLE PRECISION VARIABLE.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XSIZE  = THE SINGLE PRECISION VALUE OF THE
!                                   COMPUTED    SAMPLE SIZE.
!     OUTPUT--THE    COMPUTED    SINGLE PRECISION VALUE OF THE
!             SAMPLE SIZE; THAT IS, A SINGLE PRECISION REPRESENTATION
!             OF THE INTEGER INPUT VARIABLE N.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--NONE.
!     NOTE--ALTHOUGH THIS SUBROUTINE DOES    NOTHING
!           EXCEPT FORM THE SINGLE PRECISION VARIABLE XSIZE
!           WHICH IS EQUAL TO THE INTEGER INPUT VARIABLE N,
!           IT EXISTS AND HAS THE ARGUMENT STRUCTURE
!           THAT IT DOES SO AS TO HAVE AN IDENTICAL
!           CALLING SEQUENCE WITH MOST OF THE OTHER
!           SUBROUTINES IN THE INDIVIDUAL STATISTICS
!           CATEGORY OF THE DATAPAC LIBRARY.
!           THIS IS DESIRABLE FOR THE USE OF THE
!           SUBSET STATISTICS SUBROUTINES SSTAT1, SSTAT2, SSTAT3, ...
!           WHICH CARRY AN INDIVIDUAL STATISTICS CATEGORY SUBROUTINE
!           NAME (E. G., MEAN, MEDIAN, SD, RANGE, SIZE, ETC.)
!           AS ITS FIRST INPUT ARGUMENT SO AS TO SPECIFY
!           WHAT STATISTIC IS TO BE COMPUTED FOR THE SUBSETS OF
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--JUNE      1977.
!     UPDATED         --JUNE      1979.
!     UPDATED         --AUGUST    1981.
!     UPDATED         --MARCH     1982.
!     UPDATED         --MAY       1982.
!     UPDATED         --OCTOBER   2012. DON'T SET ERROR FLAG
!                                       FOR EMPTY SUBSET, JUST
!                                       SET SIZE TO 0.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='SIZE'
      ISUBN2='    '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF SIZE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,N
   52   FORMAT('IBUGA3,N = ',A4,2X,I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************
!               **  COMPUTE SIZE  **
!               ********************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
!CCCC AN=N
!
!CCCC IF(N.GE.1)GO TO 119
!CCCC IERROR='YES'
!CCCC WRITE(ICOUT,999)
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,111)
!C111 FORMAT('***** ERROR IN SIZE--')
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,112)
!C112 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS')
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,113)
!C113 FORMAT('      IN THE VARIABLE FOR WHICH')
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,114)
!C114 FORMAT('      THE SAMPLE SIZE IS TO BE COMPUTED')
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,115)
!C115 FORMAT('      MUST BE 1 OR LARGER.')
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,116)
!C116 FORMAT('      SUCH WAS NOT THE CASE HERE.')
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,117)N
!C117 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS HERE = ',I8,
!CCCC1'.')
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC GO TO 9000
!C119 CONTINUE
!
!CCCC IF(N.LE.1)GO TO 120
!CCCC GO TO 129
!C120 CONTINUE
!CCCC WRITE(ICOUT,999)
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,121)N
!C121 FORMAT('***** NON-FATAL DIAGNOSTIC IN SIZE--',
!CCCC1'THE SECOND INPUT ARGUMENT (N) HAS THE VALUE ',I8)
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC XSIZE=N
!CCCC GO TO 9000
!C129 CONTINUE
!
!CCCC HOLD=X(1)
!CCCC DO135I=2,N
!CCCC IF(X(I).NE.HOLD)GO TO 139
!C135 CONTINUE
!CCCC WRITE(ICOUT,999)
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,136)HOLD
!C136 FORMAT('***** NON-FATAL DIAGNOSTIC IN SIZE--',
!CCCC1'THE FIRST INPUT ARGUMENT (A VECTOR) HAS ALL ELEMENTS = ',E15.7)
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC XSIZE=N
!CCCC GO TO 9000
!C139 CONTINUE
!
!C190 CONTINUE
!
!               ********************************
!               **  STEP 2--                  **
!               **  COMPUTE THE SAMPLE SIZE.  **
!               ********************************
!
      XSIZE=N
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)N,XSIZE
  811   FORMAT('THE SAMPLE SIZE OF THE ',I8,' OBSERVATIONS = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF SIZE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA3,IERROR,N,XSIZE
 9012   FORMAT('IBUGA3,IERROR,N,XSIZE = ',2(A4,2X),I8,G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE SIZE
      SUBROUTINE SLACDF(X,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION FROM THE THE SLASH DISTIBUTION WITH
!              LOCATION = 0 AND SCALE = 1.  THIS DISTRIBUTION IS
!              DEFINED FOR ALL X AND HAS THE PROBABILITY DENSITY
!              FUNCTION
!              F(X) = NORPDF(0) - NORPDF(X))/[X**2]     X <> 0
!                     0.5*NORPDF(0)                     X = 0
!              WHERE NORPDF IS THE PDF OF THE STANDARD NORMAL
!              DISTRIBUTION.  THE CUMULATIVE DISTRIBUTION IS
!              COMPUTED BY CALLING THE QAGI (FROM QUADPACK)
!              INTEGRATION ROUTINE.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DQAGI.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, BALKRISHNAN, "CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS, VOLUME 1", WILEY, 1994 (PAGE 63).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2003.12
!     ORIGINAL VERSION--DECEMBER  2003.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      INTEGER LIMIT
      INTEGER LENW
      PARAMETER(LIMIT=100)
      PARAMETER(LENW=4*LIMIT)
      INTEGER INF
      INTEGER NEVAL
      INTEGER IER
      INTEGER LAST
      INTEGER IWORK(LIMIT)
      REAL X
      REAL CDF
      DOUBLE PRECISION EPSABS
      DOUBLE PRECISION EPSREL
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DX
      DOUBLE PRECISION ABSERR
      DOUBLE PRECISION WORK(LENW)
!
      DOUBLE PRECISION SLAFUN
      EXTERNAL SLAFUN
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!
      INF=-1
      EPSABS=0.0D0
      EPSREL=1.0D-7
      IER=0
      DCDF=0.0D0
!
!  NOTE: FOR X > 0, COMPUTE 1 - SLACDF(-X) FOR EFFICIENCY (INTEGRATING
!        OVER A SMALLER RANGE) AND GREATER ACCURACY.
!
      IFLAG=0
      DX=DBLE(X)
      IF(DX.GT.0.0D0)THEN
        IFLAG=1
        DX=-DX
      ENDIF
!
      CALL DQAGI(SLAFUN,DX,INF,EPSABS,EPSREL,DCDF,ABSERR,NEVAL,   &
                IER,LIMIT,LENW,LAST,IWORK,WORK)
!
      IF(IFLAG.EQ.0)THEN
        CDF=REAL(DCDF)
      ELSE
        DCDF=1.0D0 - DCDF
        CDF=REAL(DCDF)
      ENDIF
!
      IF(IER.EQ.1)THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR FROM SLACDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      MAXIMUM NUMBER OF SUBDIVISIONS EXCEEDED.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,121)
  121   FORMAT('***** ERROR FROM SLACDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,123)
  123   FORMAT('      ROUNDOFF ERROR PREVENTS REQUESTED TOLERANCE ',   &
               'FROM BEING ACHIEVED.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.3)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,131)
  131   FORMAT('***** ERROR FROM SLACDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,133)
  133   FORMAT('      BAD INTEGRAND BEHAVIOUR DETECTED.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,141)
  141   FORMAT('***** ERROR FROM SLACDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,143)
  143   FORMAT('      INTEGRATION DID NOT CONVERGE.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,151)
  151   FORMAT('***** ERROR FROM SLACDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,153)
  153   FORMAT('      THE INTEGRATION IS PROBABLY DIVERGENT.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.6)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,161)
  161   FORMAT('***** ERROR FROM SLACDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,163)
  163   FORMAT('      INVALID INPUT TO THE INTEGRATION ROUTINE.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE SLACDF
      DOUBLE PRECISION FUNCTION SLAFUN(DX)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION FROM THE THE SLASH DISTIBUTION WITH
!              LOCATION = 0 AND SCALE = 1.  IDENTICAL TO SLAPDF,
!              BUT DEFINE AS FUNCTION TO BE USED FOR INTEGRATION
!              CODE CALLED BY SLACDF.
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE SLAFUN.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NODPDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, BALKRISHNAN, "CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS, VOLUME 1", WILEY, 1994 (PAGE 63).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2003.12
!     ORIGINAL VERSION--DECEMBER  2003.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DX
      DOUBLE PRECISION DPDF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!
!     TRANSFORM THE NORMAL PDF
!
      CALL NODPDF(DX,DTERM3)
!
      IF(DX.EQ.0.0D0)THEN
        DPDF=0.5D0*DTERM3
      ELSE
        CALL NODPDF(0.0D0,DTERM2)
        DPDF=(DTERM2 - DTERM3)/(DX*DX)
      ENDIF
!
      SLAFUN=DPDF
!
      RETURN
      END FUNCTION SLAFUN
      REAL FUNCTION SLAFU2(X)
!
!     PURPOSE--SLAPPF CALLS FZERO TO FIND A ROOT FOR THE PERCENT
!              POINT FUNCTION.  SLAFU2 IS THE FUNCTION FOR WHICH
!              THE ZERO IS FOUND.  IT IS:
!                 P - SLACDF(X)
!              WHERE P IS THE DESIRED PERCENT POINT.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE SLAFU2.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--SLACDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, BALKRISHNAN, "CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS, VOLUME 1", WILEY, 1994 (PAGE 63).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2003.12
!     ORIGINAL VERSION--DECEMBER  2003.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      REAL P
      COMMON/SLACOM/P
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      CALL SLACDF(X,CDF)
      SLAFU2=P - CDF
!
      RETURN
      END FUNCTION SLAFU2
      DOUBLE PRECISION FUNCTION SLAFU3(SIGMA,X)
!
!     PURPOSE--THIS ROUTINE IS USED IN FINDING THE MAXIMUM LIKELIHOOD
!              ESTIMATE OF THE SCALE PARAMETER OF THE SLASH
!              DISTRIBUTION.  THIS FUNCTION FINDS THE ROOT OF
!              THE EQUATION:
!
!              (SIGMA**2/N)*SUM[i=1 to n][X(I)**2*W(X(I))] - 1 = 0
!
!              WHERE
!
!              X(I) = (Y(I) - MU)/SIGMA
!              W(X(I)) = (2/X**2) - 1/(EXP(X**2/2) - 1)
!
!              CALLED BY DFZER2 ROUTINE FOR FINDING THE ROOT OF A
!              FUNCTION.
!     EXAMPLE--SLASH MAXIMUM LIKELIHOOD Y
!     REFERENCE--KAREN KAFADAR, (1982), "A BIWEIGHT APPROACH TO
!                THE ONE-SAMPLE PROBLEM", JOURNAL OF THE
!                AMERICAN STATISTICAL ASSOCIATION, VOL. 77,
!                NO. 378, PP. 416-424.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/6
!     ORIGINAL VERSION--JUNE       2007.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION SIGMA
      DOUBLE PRECISION X(*)
!
      INTEGER N
      DOUBLE PRECISION DMU
      COMMON/SL3COM/DMU,N
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DX
      DOUBLE PRECISION DWI
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      DSUM1=0.0D0
      DO 100 I=1,N
        DX=(X(I) - DMU)/SIGMA
        DWI=(2.0D0/DX**2) - 1.0D0/(DEXP(DX**2/2.0D0) - 1.0D0)
        DSUM1=DSUM1 + DX*DX*DWI
  100 CONTINUE
!
      SLAFU3=(SIGMA**2/DBLE(N))*DSUM1 - SIGMA**2
!
      RETURN
      END FUNCTION SLAFU3
      SUBROUTINE SLALI1(Y,TEMP1,N,ALOC,SCALE,   &
                        ALIK,AIC,AICC,BIC,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE LIKELIHOOD FUNCTION FOR
!              THE SLASH DISTRIBUTION.  THIS IS FOR THE RAW DATA
!              CASE (I.E., NO GROUPING AND NO CENSORING).
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2009/10
!     ORIGINAL VERSION--OCTOBER   2009.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ICASPL
      CHARACTER*4 IADEDF
      CHARACTER*4 IGEPDF
      CHARACTER*4 IMAKDF
      CHARACTER*4 IBEIDF
      CHARACTER*4 ILGADF
      CHARACTER*4 ISKNDF
      CHARACTER*4 IGLDDF
      CHARACTER*4 IBGEDF
      CHARACTER*4 IGETDF
      CHARACTER*4 ICONDF
      CHARACTER*4 IGOMDF
      CHARACTER*4 IKATDF
      CHARACTER*4 IGIGDF
      CHARACTER*4 IGEODF
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 ICAPTY
      CHARACTER*4 ICAPSW
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DNP
      DOUBLE PRECISION DLIK
      DOUBLE PRECISION DTERM3
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION TEMP1(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='SLAL'
      ISUBN2='I1  '
      IERROR='NO'
!
      ALIK=-99.0
      AIC=-99.0
      AICC=-99.0
      BIC=-99.0
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'ALI1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF SLALI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO
   52   FORMAT('IBUGA3,ISUBRO = ',A4,2X,A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,55)N,ALOC,SCALE
   55   FORMAT('N,ALOC,SCALE = ',I8,2G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  COMPUTE LIKELIHOOD FUNCTION         **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'ALI1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IERFLG=0
      IERROR='NO'
      IWRITE='OFF'
      ICASPL='SLAS'
      MINMAX=0
!
!     COMPUTE THE LOG-LIKELIHOOD FUNCTION FROM:
!
!         LOG-LIKE = SUM[i=1 to n][LOG(f(x(i);theta))]
!
!     WITH theta DENOTING THE PARAMETERS OF THE
!     DISTRIBUTION.  CALL DPPDF1 AND SUM TO COMPUTE THIS SUM.
!
      SHAPE1=CPUMIN
      SHAPE2=CPUMIN
      SHAPE3=CPUMIN
      SHAPE4=CPUMIN
      SHAPE5=CPUMIN
      SHAPE6=CPUMIN
      SHAPE7=CPUMIN
      IADEDF='NULL'
      IGEPDF='NULL'
      IMAKDF='NULL'
      IBEIDF='NULL'
      ILGADF='NULL'
      ISKNDF='NULL'
      IGLDDF='NULL'
      IBGEDF='NULL'
      IGETDF='NULL'
      ICONDF='NULL'
      IGOMDF='NULL'
      IKATDF='NULL'
      IGIGDF='NULL'
      IGEODF='NULL'
      ICAPSW='NULL'
      ICAPTY='NULL'
      CALL DPPDF1(Y,TEMP1,N,ICASPL,   &
                  SHAPE1,SHAPE2,SHAPE3,SHAPE4,   &
                  SHAPE5,SHAPE6,SHAPE7,   &
                  YLOWLM,YUPPLM,A,B,MINMAX,   &
                  ICAPSW,ICAPTY,   &
                  IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                  ILGADF,ISKNDF,IGLDDF,IBGEDF,   &
                  IGETDF,ICONDF,IGOMDF,IKATDF,   &
                  IGIGDF,IGEODF,   &
                  ALOC,SCALE,   &
                  IBUGA3,ISUBRO,IERROR)
      DO 1000 I=1,N
        TEMP1(I)=LOG(TEMP1(I))
 1000 CONTINUE
      CALL SUMDP(TEMP1,N,IWRITE,ALIK,IBUGA3,IERROR)
!
      DN=DBLE(N)
      DLIK=DBLE(ALIK)
      DNP=2.0D0
      AIC=REAL(-2.0D0*DLIK + 2.0D0*DNP)
      DTERM3=(2.0D0*DNP*(DNP+1.0D0))/(DN-DNP-1.0D0)
      AICC=REAL(-2.0D0*DLIK + 2.0D0*DNP + DTERM3)
      BIC=REAL(-2.0D0*DLIK + DNP*LOG(DN))
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'ALI1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF SLALI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)DSUM1,DTERM1,DTERM3
 9013   FORMAT('DSUM1,DTERM1,DTERM3 = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9014)ALIK,AIC,AICC,BIC
 9014   FORMAT('ALIK,AIC,AICC,BIC = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE SLALI1
      SUBROUTINE SLAML1(Y,N,MAXNXT,   &
                        TEMP1,TEMP2,TEMP3,DTEMP1,   &
                        XMEAN,XSD,XMIN,XMAX,XMED,XMAD,   &
                        ALOC,ASCALE,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD ESTIMATES
!              FOR THE SLASH DISTRIBUTION FOR THE RAW DATA CASE (I.E.,
!              NO CENSORING AND NO GROUPING).
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!              PUT THIS IN A SEPARATE ROUTINE AS IT MAY BE CALLED
!              FROM MULTIPLE PLACES (DPMGU1 WILL GENERATE THE OUTPUT
!              FOR THE SLASH MLE COMMAND).
!
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2009/10
!     ORIGINAL VERSION--OCTOBER   2009. EXTRACTED AS A SEPARATE
!                                       SUBROUTINE (FROM DPMLSL)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*40 IDIST
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      INTEGER IFLAG
!
      DIMENSION Y(*)
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
      DIMENSION TEMP3(*)
      DOUBLE PRECISION DTEMP1(*)
!
      DOUBLE PRECISION DAE
      DOUBLE PRECISION DRE
      DOUBLE PRECISION DXSTRT
      DOUBLE PRECISION DXLOW
      DOUBLE PRECISION DXUP
      DOUBLE PRECISION XLOWSV
      DOUBLE PRECISION XUPSV
!
!
      DOUBLE PRECISION SLAFU3
      EXTERNAL SLAFU3
!
      INTEGER IN
      DOUBLE PRECISION DMU
      COMMON/SL3COM/DMU,IN
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='SLAM'
      ISUBN2='L1  '
      IWRITE='OFF'
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'AML1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF SLAML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N,MAXNXT
   52   FORMAT('IBUGA3,ISUBRO,N,MAXNXT = ',2(A4,2X),2I8)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CARRY OUT CALCULATIONS                **
!               **  FOR SLASH MLE ESTIMATE                **
!               ********************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'AML1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IDIST='SLASH'
      IFLAG=0
      CALL SUMRAW(Y,N,IDIST,IFLAG,   &
                  XMEAN,XVAR,XSD,XMIN,XMAX,   &
                  ISUBRO,IBUGA3,IERROR)
      CALL MEDIAN(Y,N,IWRITE,TEMP1,MAXNXT,XMED,IBUGA3,IERROR)
!
      CALL MAD(Y,N,IWRITE,TEMP1,TEMP2,MAXNXT,XMAD,IBUGA3,IERROR)
      CALL SORT(Y,N,Y)
!
!     IF THE DATA ARE IN Y, THE ML ESTIMATE FOR THE LOCATION
!     PARAMETER IS THE SOLUTION TO THE EQUATION
!
!        MUHAT = SUM[i=1 to n][X(I)*W(X(I))]/
!                SUM[i=1 to n][W(X(I))]
!
!     WHERE
!
!        X(I) = (Y(I) - MU)/SIGMA
!        W(X(I)) = (2/X**2) - 1/(EXP(X**2/2) - 1)
!
!     THIS IS THE BIWEIGHT ESTIMATE OF LOCATION.
!
      DO 1107 I=1,N
        TEMP1(I)=Y(I)
 1107 CONTINUE
      CALL BIWLOC(TEMP1,N,IWRITE,TEMP2,TEMP3,MAXNXT,XBW,   &
                  IBUGA3,IERROR)
      ALOC=XBW
!
!     THE ESTIMATE FOR THE SCALE PARAMETER IS THE SOLUTION
!     OF THE FOLLOWING EQUATION:
!
!        (1/N)*SUM[i=1 to n][X(I)**2*W(X(I))] - 1 = 0
!
      DO 4101 I=1,N
        DTEMP1(I)=DBLE(Y(I))
 4101 CONTINUE
!
      DMU=DBLE(ALOC)
      IN=N
!
      DXSTRT=DBLE(XMAD)
      DAE=2.0*0.000001D0*DXSTRT
      DRE=DAE
      IFLAG=0
      DXLOW=DXSTRT/2.0D0
      DXUP=2.0D0*DXSTRT
      ITBRAC=0
 4105 CONTINUE
      XLOWSV=DXLOW
      XUPSV=DXUP
      CALL DFZER2(SLAFU3,DXLOW,DXUP,DXSTRT,DRE,DAE,IFLAG,DTEMP1)
!
      IF(IFLAG.EQ.4 .AND. ITBRAC.LE.100)THEN
        DXLOW=XLOWSV/2.0D0
        DXUP=2.0D0*XUPSV
        ITBRAC=ITBRAC+1
        GO TO 4105
      ENDIF
!
      IF(IFLAG.EQ.2)THEN
!
!  NOTE: SUPPRESS THIS MESSAGE FOR NOW.
!CCCC   WRITE(ICOUT,999)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,111)
!C111   FORMAT('***** WARNING FROM SLASH MAXIMUM ',
!CCCC1         'LIKELIHOOD--')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,113)
!C113   FORMAT('      ESTIMATE OF SIGMA MAY NOT BE COMPUTED TO ',
!CCCC1         'DESIRED TOLERANCE.')
!CCCC   CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.3)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,121)
  121   FORMAT('***** WARNING FROM SLASH MAXIMUM LIKELIHOOD--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,123)
  123   FORMAT('      ESTIMATE OF SIGMA MAY BE NEAR A SINGULAR POINT.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,131)
  131   FORMAT('***** ERROR FROM SLASH MAXIMUM LIKELIHOOD--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,133)
  133   FORMAT('      APPROPRIATE BRACKETING INTERVAL NOT FOUND.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,141)
  141   FORMAT('***** WARNING FROM SLASH MAXIMUM LIKELIHOOD--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,143)
  143   FORMAT('      MAXIMUM ITERATIONS EXCEEDED.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      ASCALE=REAL(DXLOW)
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'AML1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF SLAML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9055)N,XMEAN,XSD,XMIN,XMAX
 9055   FORMAT('N,XMEAN,XSD,XMIN,XMAX = ',I8,4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9056)ALOC,ASCALE,XMED,XMAD
 9056   FORMAT('ALOC,ASCALE,XMED,XMAD = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE SLAML1
      SUBROUTINE SLAPDF(X,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION FROM THE THE SLASH DISTIBUTION WITH
!              LOCATION = 0 AND SCALE = 1.  THIS DISTRIBUTION IS
!              DEFINED FOR ALL X AND HAS THE PROBABILITY DENSITY
!              FUNCTION
!              F(X) = NORPDF(0) - NORPDF(X))/[X**2]     X <> 0
!                     0.5*NORPDF(0)                     X = 0
!              WHERE NORPDF IS THE PDF OF THE STANDARD NORMAL
!              DISTRIBUTION.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NODPDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, BALKRISHNAN, "CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS, VOLUME 1", WILEY, 1994 (PAGE 63).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2003.1
!     ORIGINAL VERSION--JANUARY   2003.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DX
      DOUBLE PRECISION DPDF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!
!     TRANSFORM THE NORMAL PDF
!
      DX=DBLE(X)
      CALL NODPDF(DX,DTERM3)
!
      IF(X.EQ.0.0)THEN
        DPDF=0.5D0*DTERM3
        PDF=REAL(DPDF)
      ELSE
        CALL NODPDF(0.0D0,DTERM2)
        DPDF=(DTERM2 - DTERM3)/(DX*DX)
        PDF=REAL(DPDF)
      ENDIF
!
      RETURN
      END SUBROUTINE SLAPDF
      SUBROUTINE SLAPPF(P,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION OF THE THE SLASH DISTIBUTION WITH
!              LOCATION = 0 AND SCALE = 1.  THIS DISTRIBUTION IS
!              DEFINED FOR ALL X AND HAS THE PROBABILITY DENSITY
!              FUNCTION
!              F(X) = NORPDF(0) - NORPDF(X))/[X**2]     X <> 0
!                     0.5*NORPDF(0)                     X = 0
!              WHERE NORPDF IS THE PDF OF THE STANDARD NORMAL
!              DISTRIBUTION.  THE PERCENT POINT FUNCTION IS
!              COMPUTED BY CALLING THE FZERO ROUTINE TO FIND THE
!              ROOT OF P - SLACDF(X) WHERE SLACDF IS THE CUMULATIVE
!              DISTRIBUTION FUNCTION OF THE SLASH DISTRIBUTION.
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT
!             FUNCTION VALUE PPF.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--FZERO.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, BALKRISHNAN, "CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS, VOLUME 1", WILEY, 1994 (PAGE 63).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2003.12
!     ORIGINAL VERSION--DECEMBER  2003.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      REAL PPF
!
      REAL SLAFU2
      EXTERNAL SLAFU2
!
      REAL P2
      COMMON/SLACOM/P2
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!
      IF(P.LE.0.0.OR.P.GE.1.0)THEN
         WRITE(ICOUT,61)
   61    FORMAT('***** ERROR--THE FIRST  INPUT ARGUMENT ',   &
                'TO THE SLAPPF SUBROUTINE ')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,62)
   62    FORMAT('      IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL ***')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,63)P
   63    FORMAT('      VALUE OF ARGUMENT = ',G15.7)
         CALL DPWRST('XXX','BUG ')
         PPF=0.0
         GO TO 9000
      ELSE
         XTEMP=675000.
         CALL SLACDF(-XTEMP,PLOW)
         CALL SLACDF(XTEMP,PUPP)
         IF(P.LT.PLOW .OR. P.GT.PUPP)THEN
           WRITE(ICOUT,71)
   71      FORMAT('***** ERROR--THE FIRST  INPUT ARGUMENT ',   &
                  'TO THE SLAPPF SUBROUTINE ')
           CALL DPWRST('XXX','BUG ')
           WRITE(ICOUT,72)
   72      FORMAT('      IS OUTSIDE THE INTERVAL (',G15.7,',',G15.7,   &
                  ') INTERVAL, UNABLE TO COMPUTE PPF')
           CALL DPWRST('XXX','BUG ')
           WRITE(ICOUT,63)P
           CALL DPWRST('XXX','BUG ')
           PPF=0.0
           GO TO 9000
         ENDIF
      ENDIF
!
!  STEP 1: FIND BRACKETING INTERVAL.  START WITH FACT THAT SLASH
!          DISTRIBUTION IS SYMMETRIC ABOUT X = 0.
!
      IF(P.EQ.0.5)THEN
        PPF=0.0
        GO TO 9000
      ELSEIF(P.GT.0.5)THEN
        XLOW=0.0
        IF(P.LE.0.95)THEN
          XUP=9.0
        ELSEIF(P.LT.0.995)THEN
          XUP=100.
        ELSEIF(P.LT.0.9995)THEN
          XUP=1000.
        ELSEIF(P.LT.0.99995)THEN
          XUP=10000.
        ELSE
          XUP=675000.
        ENDIF
      ELSE
        XUP=0.0
        IF(P.GT.0.05)THEN
          XLOW=-9.0
        ELSEIF(P.GT.0.005)THEN
          XLOW=-100.0
        ELSEIF(P.GT.0.0005)THEN
          XLOW=-1000.
        ELSEIF(P.GT.0.00005)THEN
          XLOW=-10000.
        ELSE
          XLOW=-675000.
        ENDIF
      ENDIF
!
      P2=P
      AE=1.E-6
      RE=1.E-6
      IFLAG=0
      CALL FZERO(SLAFU2,XLOW,XUP,XUP,RE,AE,IFLAG)
!
      PPF=XLOW
!
      IF(IFLAG.EQ.2)THEN
!
!  NOTE: SUPPRESS THIS MESSAGE FOR NOW.
!CCCC   WRITE(ICOUT,999)
  999   FORMAT(1X)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,111)
!C111   FORMAT('***** WARNING FROM SLAPPF--')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,113)
!C113   FORMAT('      PPF VALUE MAY NOT BE COMPUTED TO DESIRED ',
!CCCC1         'TOLERANCE.')
!CCCC   CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.3)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,121)
  121   FORMAT('***** WARNING FROM SLAPPF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,123)
  123   FORMAT('      PPF VALUE MAY BE NEAR A SINGULAR POINT.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,131)
  131   FORMAT('***** ERROR FROM SLAPPF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,133)
  133   FORMAT('      APPROPRIATE BRACKETING INTERVAL NOT FOUND.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,141)
  141   FORMAT('***** WARNING FROM SLAPPF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,143)
  143   FORMAT('      MAXIMUM ITERATIONS EXCEEDED.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE SLAPPF
      SUBROUTINE SLARAN(N,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE THE SLASH DISTIBUTION WITH LOCATION = 0
!              AND SCALE = 1.  THIS DISTRIBUTION IS DEFINED FOR ALL
!              X AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = NORPDF(0) - NORPDF(X))/[X**2]     X <> 0
!                     0.5*NORPDF(0)                     X = 0
!              WHERE NORPDF IS THE PDF OF THE STANDARD NORMAL
!              DISTRIBUTION.  NOTE THAT THE SLASH DISTRIBUTION IS
!              THE RATIO OF AN INDEPENDENT STANDARD NORMAL AND
!              UNIFORM DISTRIBUTIONS.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N FROM THE SLASH DISTRIBUTION
!             WITH LOCATION = 0 AND SCALE = 1.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG, SQRT, SIN, COS.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     METHOD--TRANSFORM NORMAL RANDOM NUMBERS
!     REFERENCES--JOHNSON, KOTZ, BALKRISHNAN, "CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS, VOLUME 1", WILEY, 1994 (PAGE 63).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2003.1
!     ORIGINAL VERSION--JANUARY   2003.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(1)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
!     GENERATE N NORMAL (0,1) RANDOM NUMBERS;
!
!
!     TRANSFORM THE NORMAL RANDOM NUMBERS
!
      NTEMP=1
      DO 300 I=1,N
        CALL NORRAN(NTEMP,ISEED,Y)
        TERM1=Y(1)
        CALL UNIRAN(NTEMP,ISEED,Y)
        TERM2=Y(1)
        IF(TERM2.EQ.0.0)THEN
          CALL UNIRAN(NTEMP,ISEED,Y)
          TERM2=Y(1)
        ENDIF
        X(I)=TERM1/TERM2
  300 CONTINUE
!
      RETURN
      END SUBROUTINE SLARAN
      SUBROUTINE SLOCDF(X,ALPHA,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE SLOPE DISTRIBUTION.
!              THE CUMULATIVE DISTRIBUTION FUNCTION IS:
!
!                  F(X;ALPHA) = ALPHA*X + (1-ALPHA)*X**2
!                              0 <= X <= 1, 0 <= ALPHA <= 2
!
!              WITH ALPHA DENOTING THE SHAPE PARAMETER.
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                     --ALPHA   = THE SINGLE PRECISION SHAPE PARAMETER
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE BETWEEN 0 AND 1, INCLUSIVELY.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--KOTZ AND VAN DORP (2004), "BEYOND ALPHA: OTHER
!                 CONTINUOUS FAMILIES OF DISTRIBUTIONS WITH BOUNDED
!                 SUPPORT AND APPLICATIONS", WORLD SCIENTFIC
!                 PUBLISHING COMPANY, CHAPTER 8.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--SEPTEMBER   2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(X.LT.0.0 .OR. X.GT.1.0)THEN
        WRITE(ICOUT,2)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9000
      ELSEIF(ALPHA.LT.0.0 .OR. ALPHA.GT.2.0)THEN
        WRITE(ICOUT,12)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9000
      ENDIF
    2 FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT TO SLOCDF IS ',   &
             'OUTSIDE THE (0,1) INTERVAL.')
   12 FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO SLOCDF IS ',   &
             'OUTSIDE THE (0,2) INTERVAL.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!-----START POINT-----------------------------------------------------
!
      CDF=ALPHA*X + (1.0-ALPHA)*X**2
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE SLOCDF
      SUBROUTINE SLOPDF(X,ALPHA,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE SLOPE DISTRIBUTION.
!              THE PROBABILITY DENSITY FUNCTION IS:
!
!                  f(X;ALPHA) = ALPHA + 2*(1-ALPHA)*X
!                              0 <= X <= 1, 0 <= ALPHA <= 2
!
!              WITH ALPHA DENOTING THE SHAPE PARAMETER.
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                     --ALPHA   = THE SINGLE PRECISION SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE BETWEEN 0 AND 1, INCLUSIVELY.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DLOG, DEXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--KOTZ AND VAN DORP (2004), "BEYOND ALPHA: OTHER
!                 CONTINUOUS FAMILIES OF DISTRIBUTIONS WITH BOUNDED
!                 SUPPORT AND APPLICATIONS", WORLD SCIENTFIC
!                 PUBLISHING COMPANY, CHAPTER 8.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--SEPTEMBER   2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(X.LT.0.0 .OR. X.GT.1.0)THEN
        WRITE(ICOUT,2)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9000
      ELSEIF(ALPHA.LT.0.0 .OR. ALPHA.GT.2.0)THEN
        WRITE(ICOUT,12)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9000
      ENDIF
    2 FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT TO SLOPDF IS ',   &
             'OUTSIDE THE (0,1) INTERVAL.')
   12 FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO SLOPDF IS ',   &
             'OUTSIDE THE (0,2) INTERVAL.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!-----START POINT-----------------------------------------------------
!
      PDF=ALPHA + 2.0*(1.0-ALPHA)*X
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE SLOPDF
      SUBROUTINE SLOPPF(P,ALPHA,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE SLOPE DISTRIBUTION.
!              THE PERCENT POINT FUNCTION IS:
!
!              F(P;ALPHA) = P                ALPHA = 1
!                         = {-ALPHA +
!                           SQRT(ALPHA**2 + 4*P*(1-ALPHA))}/
!                           (2*(1-ALPHA))    ALPHA <> 1
!                           0 <= P <= 1, 0 <= ALPHA <= 2
!
!              WITH ALPHA DENOTING THE SHAPE PARAMETER.
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --ALPHA   = THE SINGLE PRECISION SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT POINT
!                                FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT
!             FUNCTION VALUE PPF.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--P SHOULD BE BETWEEN 0 AND 1, INCLUSIVELY.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--KOTZ AND VAN DORP (2004), "BEYOND ALPHA: OTHER
!                 CONTINUOUS FAMILIES OF DISTRIBUTIONS WITH BOUNDED
!                 SUPPORT AND APPLICATIONS", WORLD SCIENTFIC
!                 PUBLISHING COMPANY, CHAPTER 8.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--SEPTEMBER   2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(P.LT.0.0 .OR. P.GT.1.0)THEN
        WRITE(ICOUT,2)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9000
      ELSEIF(ALPHA.LT.0.0 .OR. ALPHA.GT.2.0)THEN
        WRITE(ICOUT,12)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9000
      ENDIF
    2 FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT TO SLOPPF IS ',   &
             'OUTSIDE THE (0,1) INTERVAL.')
   12 FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO SLOPPF IS ',   &
             'OUTSIDE THE (0,2) INTERVAL.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!-----START POINT-----------------------------------------------------
!
      IF(ALPHA.EQ.1.0)THEN
        PPF=P
      ELSE
        TERM1=ALPHA**2 + 4.0*P*(1.0-ALPHA)
        TERM2=2.0*(1.0 - ALPHA)
        PPF=(-ALPHA + SQRT(TERM1))/TERM2
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE SLOPPF
      SUBROUTINE SLORAN(N,ALPHA,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE SLOPE DISTRIBUTION WITH
!              SHAPE PARAMETER ALPHA.
!
!              THE PROBABILITY DENSITY FUNCTION IS:
!
!                  f(X;ALPHA) = ALPHA + 2*(1-ALPHA)*X
!                              0 <= X <= 1, 0 <= ALPHA <= 2
!
!              WITH ALPHA DENOTING THE SHAPE PARAMETER.
!
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --ALPHA  = THE SINGLE PRECISION VALUE OF THE
!                                SHAPE PARAMETER ALPHA.
!                                ALPHA SHOULD BE IN THE RANGE (0,1).
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE SLOPE DISTRIBUTION
!             WITH SHAPE PARAMETER ALPHA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, SLOPPF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--KOTZ AND VAN DORP (2004), "BEYOND ALPHA: OTHER
!                 CONTINUOUS FAMILIES OF DISTRIBUTIONS WITH BOUNDED
!                 SUPPORT AND APPLICATIONS", WORLD SCIENTFIC
!                 PUBLISHING COMPANY, CHAPTER 8.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHMOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007.9
!     ORIGINAL VERSION--SEPTEMBER 2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR--THE REQUESTED NUMBER OF ',   &
      'SLOPE RANDOM NUMBERS IS NON-POSITIVE')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
!
      IF(ALPHA.LT.0.0 .OR. ALPHA.GT.2.0)THEN
        WRITE(ICOUT,201)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,203)ALPHA
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9000
      ENDIF
  201 FORMAT('***** ERROR--THE ALPHA SHAPE PARAMETER IS ',   &
             'OUTSIDE THE (0,2) INTERVAL.')
  203 FORMAT('      THE VALUE OF ALPHA IS ',G15.7)
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N SLOPE DISTRIBUTION RANDOM
!     NUMBERS USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      DO 300 I=1,N
        CALL SLOPPF(X(I),ALPHA,XTEMP)
        X(I)=XTEMP
  300 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE SLORAN
      function Sn(x,n,y,a2,scrtch)
!
!c#####################################################################
!c######################  file Sn.for :  ##############################
!c#####################################################################
!c
!c   This file contains a Fortran function for a new robust estimator
!c   of scale denoted as Sn, proposed in Rousseeuw and Croux (1993).
!c   The estimator has a high breakdown point and a bounded influence
!c   function. The algorithm given here is very fast (running in
!c   O(nlogn) time) and needs only O(n) storage space.
!c
!c   Rousseeuw, P.J. and Croux, C. (1993), "Alternatives to the
!c      Median Absolute Deviation," Journal of the American
!c      Statistical Association, Vol. 88, 1273-1283.
!c
!c   A Fortran function for the estimator Qn, described in the same
!c   paper, is attached below. For both estimators, implementations
!c   in the Pascal language can be obtained from the authors.
!c
!c   This software may be used and copied freely, provided
!c   reference is made to the abovementioned paper.
!c
!c   For questions, problems or comments contact:
!c
!c              Peter Rousseeuw (rousse@wins.uia.ac.be)
!c              Christophe Croux (croux@wins.uia.ac.be)
!c              Department of Mathematics and Computing
!c              Universitaire Instelling Antwerpen
!c              Universiteitsplein 1
!c              B-2610 Wilrijk (Antwerp)
!c              Belgium
!c
!c--------------------------------------------------------------------
!c
!c   Efficient algorithm for the scale estimator:
!c
!c       Sn = cn * 1.1926 * LOMED_{i} HIMED_{i} |x_i-x_j|
!c
!c   which can equivalently be written as
!c
!c       Sn = cn * 1.1926 * LOMED_{i} LOMED_{j<>i} |x_i-x_j|
!c
!c   Parameters of the function Sn :
!c       x  : real array containing the observations
!c       n  : number of observations (n>=2)
!c
!c   The function Sn uses the procedures:
!c       sort(x,n,y) : sorts an array x of length n, and stores the
!c                     result in an array y (of size at least n)
!c       pull(a,n,k) : finds the k-th order statistic of an
!c                     array a of length n
!c
!c   The function Sn also creates an auxiliary array a2
!c       (of size at least n) in which it stores the values
!c       LOMED_{j<>i} |x_i-x_j|   for i=1,...,n
!c
!cccc dimension x(n),y(1000),a2(1000)
      dimension x(*),y(*),a2(*),scrtch(*)
      integer rightA,rightB,tryA,tryB,diff,Amin,Amax,even,half
      real medA, medB
      call sort(x,n,y)
      a2(1)=y(n/2+1)-y(1)
      do 10 i=2,(n+1)/2
          nA=i-1
          nB=n-i
          diff=nB-nA
          leftA=1
          leftB=1
          rightA=nB
          rightB=nB
          Amin=diff/2+1
          Amax=diff/2+nA
15        continue
          if (leftA.lt.rightA) then
              length=rightA-leftA+1
              even=1-mod(length,2)
              half=(length-1)/2
              tryA=leftA+half
              tryB=leftB+half
              if (tryA.lt.Amin) then
                  rightB=tryB
                  leftA=tryA+even
              else
                  if (tryA.gt.Amax) then
                      rightA=tryA
                      leftB=tryB+even
                  else
                      medA=y(i)-y(i-tryA+Amin-1)
                      medB=y(tryB+i)-y(i)
                      if (medA.ge.medB) then
                          rightA=tryA
                          leftB=tryB+even
                      else
                          rightB=tryB
                          leftA=tryA+even
                      endif
                  endif
              endif
          go to 15
          endif
          if (leftA.gt.Amax) then
              a2(i)=y(leftB+i)-y(i)
          else
              medA=y(i)-y(i-leftA+Amin-1)
              medB=y(leftB+i)-y(i)
              a2(i)=min(medA,medB)
          endif
10    continue
      do 20 i=(n+1)/2+1,n-1
          nA=n-i
          nB=i-1
          diff=nB-nA
          leftA=1
          leftB=1
          rightA=nB
          rightB=nB
          Amin=diff/2+1
          Amax=diff/2+nA
25        continue
          if (leftA.lt.rightA) then
              length=rightA-leftA+1
              even=1-mod(length,2)
              half=(length-1)/2
              tryA=leftA+half
              tryB=leftB+half
              if (tryA.lt.Amin) then
                  rightB=tryB
                  leftA=tryA+even
              else
                  if (tryA.gt.Amax) then
                      rightA=tryA
                      leftB=tryB+even
                  else
                      medA=y(i+tryA-Amin+1)-y(i)
                      medB=y(i)-y(i-tryB)
                      if (medA.ge.medB) then
                          rightA=tryA
                          leftB=tryB+even
                      else
                          rightB=tryB
                          leftA=tryA+even
                      endif
                  endif
              endif
          go to 25
          endif
          if (leftA.gt.Amax) then
              a2(i)=y(i)-y(i-leftB)
          else
              medA=y(i+leftA-Amin+1)-y(i)
              medB=y(i)-y(i-leftB)
              a2(i)=min(medA,medB)
          endif
20    continue
      a2(n)=y(n)-y((n+1)/2)
      cn=1
      if (n.le.9) then
          if (n.eq.2) cn=0.743
          if (n.eq.3) cn=1.851
          if (n.eq.4) cn=0.954
          if (n.eq.5) cn=1.351
          if (n.eq.6) cn=0.993
          if (n.eq.7) cn=1.198
          if (n.eq.8) cn=1.005
          if (n.eq.9) cn=1.131
      else
          if (mod(n,2).eq.1) cn=n/(n-0.9)
      endif
      Sn=cn*1.1926*pull(a2,n,(n+1)/2,scrtch)
      return
      end
      SUBROUTINE SNCDF(X,ALMBDA,ISKNDF,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE SKEW-NORMAL DISTRIBUTION
!              WITH SHAPE PARAMETER = LAMBDA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND
!              THE CUMULATIVE DISTRIBUTION IS COMPUTED BY
!              NUMERICALLY INTEGRATING THE PDF FUNCTION.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                     --ALMBDA = THE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE SKEWED-NORMAL DISTRIBUTION
!             WITH SHAPE PARAMETER = LAMBDA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DQAGI.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PAGE 454.
!               --"Log-Skew-Normal and Log-Skew-t Distributions as
!                 Models for Family Income Data", Azzalini, Cappello,
!                 and Kotz, paper downloaded from Azzalini's web
!                 site.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2003.11
!     ORIGINAL VERSION--NOVEMBER  2003.
!     UPDATED         --JULY      2005. SUPPORT FOR RE-PARAMETERIZED
!                                       DEFINITION THAT IS USEFUL FOR
!                                       FITTING
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      CHARACTER*4 ISKNDF
!
      INTEGER LIMIT
      INTEGER LENW
      PARAMETER(LIMIT=100)
      PARAMETER(LENW=4*LIMIT)
      INTEGER INF
      INTEGER NEVAL
      INTEGER IER
      INTEGER LAST
      INTEGER IWORK(LIMIT)
      REAL X
      REAL CDF
      DOUBLE PRECISION EPSABS
      DOUBLE PRECISION EPSREL
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DX
      DOUBLE PRECISION ABSERR
      DOUBLE PRECISION WORK(LENW)
!
      DOUBLE PRECISION SNFUN
      EXTERNAL SNFUN
!
      DOUBLE PRECISION DLMBDA
      COMMON/SNCOM/DLMBDA
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!               ************************************
!               **  STEP 1--                      **
!               **  COMPUTE THE DENSITY FUNCTION  **
!               ************************************
!
      IF(ISKNDF.EQ.'DEFA')THEN
        INF=-1
        EPSABS=0.0D0
        EPSREL=1.0D-7
        IER=0
        CDF=0.0D0
!
        DX=DBLE(X)
        DLMBDA=DBLE(ALMBDA)
!
        CALL DQAGI(SNFUN,DX,INF,EPSABS,EPSREL,DCDF,ABSERR,NEVAL,   &
                   IER,LIMIT,LENW,LAST,IWORK,WORK)
!
        CDF=REAL(DCDF)
!
        IF(IER.EQ.1)THEN
          WRITE(ICOUT,999)
  999     FORMAT(1X)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,111)
