          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,113)
  113     FORMAT('      MAXIMUM NUMBER OF SUBDIVISIONS EXCEEDED.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(IER.EQ.2)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,121)
  121     FORMAT('***** ERROR FROM SNCDF--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,123)
  123     FORMAT('      ROUNDOFF ERROR PREVENTS REQUESTED TOLERANCE ',   &
                 'FROM BEING ACHIEVED.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(IER.EQ.3)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,131)
  131     FORMAT('***** ERROR FROM SNCDF--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,133)
  133     FORMAT('      BAD INTEGRAND BEHAVIOUR DETECTED.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(IER.EQ.4)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,141)
  141     FORMAT('***** ERROR FROM SNCDF--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,143)
  143     FORMAT('      INTEGRATION DID NOT CONVERGE.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(IER.EQ.5)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,151)
  151     FORMAT('***** ERROR FROM SNCDF--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,153)
  153     FORMAT('      THE INTEGRATION IS PROBABLY DIVERGENT.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(IER.EQ.6)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,161)
  161     FORMAT('***** ERROR FROM SNCDF--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,163)
  163     FORMAT('      INVALID INPUT TO THE INTEGRATION ROUTINE.')
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
      ENDIF
!
      RETURN
      END SUBROUTINE SNCDF
      DOUBLE PRECISION FUNCTION SNFUN(DX)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE SKEW-NORMAL DISTRIBUTION
!              WITH SHAPE PARAMETER = LAMBDA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND HAS
!              THE PROBABILITY DENSITY FUNCTION.  IDENTICAL TO SLAPDF,
!              BUT DEFINE AS FUNCTION TO BE USED FOR INTEGRATION
!              CODE CALLED BY SLACDF.  ALSO, THIS ROUTINE USES
!              DOUBLE PRECISION ARITHMETIC.
!                 SNPDF(X,LAMBDA) = 2*NORCDF(LAMDDA*X)*NORPDF(X)
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--SNFUN  = THE DOUBLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE SKEWED-NORMAL DISTRIBUTION
!             WITH SHAPE PARAMETER = LAMBDA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NODPDF, NODCDF..
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PAGE 454.
!               --AZZALINI HAS AUTHORED A NUMBER OF PAPERS ON THIS
!                 DISTRIBUTION.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2003.12
!     ORIGINAL VERSION--DECEMBER  2003.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DPDF
!
      DOUBLE PRECISION DLMBDA
      COMMON/SNCOM/DLMBDA
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!               ************************************
!               **  STEP 1--                      **
!               **  COMPUTE THE DENSITY FUNCTION  **
!               ************************************
!
      CALL NODCDF(DX*DLMBDA,DTERM1)
      CALL NODPDF(DX,DTERM2)
      DPDF=2.0D0*DTERM1*DTERM2
      SNFUN=DPDF
!
      RETURN
      END FUNCTION SNFUN
      REAL FUNCTION SNFU2(X)
!
!     PURPOSE--SNPPF CALLS FZERO TO FIND A ROOT FOR THE PERCENT
!              POINT FUNCTION.  SNFU2 IS THE FUNCTION FOR WHICH
!              THE ZERO IS FOUND.  IT IS:
!                 P - SNCDF(X,LAMBDA)
!              WHERE P IS THE DESIRED PERCENT POINT.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE SNFU2.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--SNCDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PAGE 454.
!               --AZZALINI HAS AUTHORED A NUMBER OF PAPERS ON THIS
!                 DISTRIBUTION.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2003.12
!     ORIGINAL VERSION--DECEMBER  2003.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      REAL P
      CHARACTER*4 ISKNDF
      COMMON/SN2COM/P,ISKNDF
!
      DOUBLE PRECISION DLMBDA
      COMMON/SNCOM/DLMBDA
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      CALL SNCDF(X,REAL(DLMBDA),ISKNDF,CDF)
      SNFU2=P - CDF
!
      RETURN
      END FUNCTION SNFU2
      SUBROUTINE SNPDF(X,ALMBDA,ISKNDF,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE SKEW-NORMAL DISTRIBUTION
!              WITH SHAPE PARAMETER = LAMBDA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND HAS
!              THE PROBABILITY DENSITY FUNCTION
!                 SNPDF(X,LAMBDA) = 2*NORCDF(LAMDDA*X)*NORPDF(X)
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!                     --ALMBDA = THE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE SKEWED-NORMAL DISTRIBUTION
!             WITH SHAPE PARAMETER = LAMBDA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NODPDF, NODCDF..
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PAGE 454.
!               --"Log-Skew-Normal and Log-Skew-t Distributions as
!                 Models for Family Income Data", Azzalini, Cappello,
!                 and Kotz, paper downloaded from Azzalini's web
!                 site.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2003.11
!     ORIGINAL VERSION--NOVEMBER  2003.
!     UPDATED         --JULY      2005. SUPPORT FOR RE-PARAMETERIZED
!                                       DEFINITION THAT IS USEFUL FOR
!                                       FITTING
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      CHARACTER*4 ISKNDF
!
      DOUBLE PRECISION DX,DLMBDA
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DPDF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!               ************************************
!               **  STEP 1--                      **
!               **  COMPUTE THE DENSITY FUNCTION  **
!               ************************************
!
      DX=DBLE(X)
      DLMBDA=DBLE(ALMBDA)
      IF(ISKNDF.EQ.'DEFA')THEN
        CALL NODCDF(DX*DLMBDA,DTERM1)
        CALL NODPDF(DX,DTERM2)
        DPDF=2.0D0*DTERM1*DTERM2
        PDF=REAL(DPDF)
        GO TO 9000
      ELSE
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE SNPDF
      SUBROUTINE SNPPF(P,ALMBDA,ISKNDF,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE SKEW-NORMAL DISTRIBUTION
!              WITH SHAPE PARAMETER = LAMBDA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND THE
!              PERCENT POINT FUNCTION IS COMPUTED BY
!              NUMERICALLY INVERTING THE CDF FUNCTION.
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --ALMBDA = THE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT
!             FUNCTION VALUE PPF.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--FZERO.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PAGE 454.
!               --"Log-Skew-Normal and Log-Skew-t Distributions as
!                 Models for Family Income Data", Azzalini, Cappello,
!                 and Kotz, paper downloaded from Azzalini's web
!                 site.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2003.12
!     ORIGINAL VERSION--DECEMBER  2003.
!     UPDATED         --JULY      2005. SUPPORT FOR RE-PARAMETERIZED
!                                       DEFINITION THAT IS USEFUL FOR
!                                       FITTING
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      CHARACTER*4 ISKNDF
!
      REAL PPF
!
      REAL SNFU2
      EXTERNAL SNFU2
!
      REAL P2
      CHARACTER*4 ISNDF2
      COMMON/SN2COM/P2,ISNDF2
!
      DOUBLE PRECISION DLMBDA
      COMMON/SNCOM/DLMBDA
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!
      IF(P.LE.0.0.OR.P.GE.1.0)THEN
         WRITE(ICOUT,61)
   61    FORMAT('***** ERROR--THE FIRST  INPUT ARGUMENT ',   &
                'TO THE SNPPF SUBROUTINE ')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,62)
   62    FORMAT('      IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL ***')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,63)P
   63    FORMAT('      VALUE OF ARGUMENT = ',G15.7)
         CALL DPWRST('XXX','BUG ')
         PPF=0.0
         GO TO 9000
      ENDIF
!
!  STEP 1: FIND BRACKETING INTERVAL.  START WITH FACT THAT LAMBDA = 0
!          IS THE NORMAL DISTRIBUTION AND THE HALF-NORMAL IS THE
!          LIMITING DISTRIBUTION AS LAMBDA GOES TO INFINITY.
!
      IF(ALMBDA.EQ.0.0)THEN
        CALL NORPPF(P,PPF)
        GO TO 9000
      ELSE
        IFLAG2=0
        IF(ALMBDA.LT.0.0)IFLAG2=1
        P2=P
        IF(IFLAG2.EQ.1)P2=1.0 - P
        CALL NORPPF(P2,XLOW)
        CALL HFNPPF(P2,XUP)
      ENDIF
      XLOW=XLOW - 0.2
      XUP=XUP + 0.2
!
      ISNDF2=ISKNDF
      AE=1.E-6
      RE=1.E-6
      DLMBDA=DBLE(ALMBDA)
      IF(IFLAG2.EQ.1)DLMBDA=-DLMBDA
      IFLAG=0
      CALL FZERO(SNFU2,XLOW,XUP,XUP,RE,AE,IFLAG)
!
      PPF=XLOW
      IF(IFLAG2.EQ.1)PPF=-PPF
!
      IF(IFLAG.EQ.2)THEN
!
!  NOTE: SUPPRESS THIS MESSAGE FOR NOW.
!CCCC   WRITE(ICOUT,999)
  999   FORMAT(1X)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,111)
!C111   FORMAT('***** WARNING FROM SNPPF--')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,113)
!C113   FORMAT('      PPF VALUE MAY NOT BE COMPUTED TO DESIRED ',
!CCCC1         'TOLERANCE.')
!CCCC   CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.3)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,121)
  121   FORMAT('***** WARNING FROM SNPPF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,123)
  123   FORMAT('      PPF VALUE MAY BE NEAR A SINGULAR POINT.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,131)
  131   FORMAT('***** ERROR FROM SNPPF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,133)
  133   FORMAT('      APPROPRIATE BRACKETING INTERVAL NOT FOUND.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,141)
  141   FORMAT('***** WARNING FROM SNPPF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,143)
  143   FORMAT('      MAXIMUM ITERATIONS EXCEEDED.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE SNPPF
      SUBROUTINE SNRAN(N,ALMBDA,ISKNDF,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE SKEWED NORMAL DISTRIBUTION
!              WITH SHAPE PARAMETER = ALMBDA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND HAS
!              THE PROBABILITY DENSITY FUNCTION
!                 SNPDF(X,LAMBDA) = 2*NORCDF(LAMDDA*X)*NORPDF(X)
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --ALMBDA = THE SHAPE (PARAMETER) FOR THE
!                                SKEWED NORMAL DISTRIBUTION.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE SKEWED NORMAL DISTRIBUTION
!             WITH SHAPE PARAMETER = ALMBDA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --ALMBDA CAN BE ANY REAL NUMBER.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NORRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PAGE 454.
!               --"Log-Skew-Normal and Log-Skew-t Distributions as
!                 Models for Family Income Data", Azzalini, Cappello,
!                 and Kotz, paper downloaded from Azzalini's web
!                 site.
!               --ALGORITHM FOR RANDOM NUMBERS ADAPTED FROM
!                 AZZALINI'S R FUNCTIONS FOR SKEW NORMAL.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2003.11
!     ORIGINAL VERSION--NOVEMBER  2003.
!     UPDATED         --JULY      2005. SUPPORT FOR RE-PARAMETERIZED
!                                       DEFINITION THAT IS USEFUL FOR
!                                       FITTING
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(2)
!
      CHARACTER*4 ISKNDF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
    5 FORMAT('***** FATAL ERROR--FOR THE SKEWED NORMAL DISTRIBUTION,')
    6 FORMAT('       THE REQUESTED NUMBER OF RANDOM NUMBERS WAS ',   &
            'NON-POSITIVE.')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,' *****')
!
!     ALGORITHM ADAPTED FROM AZZALINI'S R FUNCTION LIBRARY.
!
      IF(ISKNDF.EQ.'DEFA')THEN
        DO 100 I=1,N
          CALL NORRAN(2,ISEED,Y)
          U1=Y(1)
          U2=Y(2)
          ATEMP=ALMBDA*U1
          IF(U2.GT.ATEMP)U1=-U1
          X(I)=U1
  100   CONTINUE
      ELSE
      ENDIF
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE SNRAN
      SUBROUTINE STCDF(X,NU,ALMBDA,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE SKEW-T DISTRIBUTION
!              WITH SHAPE PARAMETERS NU AND LAMBDA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND HAS
!              THE PROBABILITY DENSITY FUNCTION
!                 STPDF(X,NU,LAMBDA) = 2*
!                       TCDF(LAMBDA*X*SQRT((NU+1)/(X**2+NU)),NU+1)*
!                       TPDF(X,NU)
!              THE CUMULATIVE DISTRIBUTION IS COMPUTED BY
!              NUMERICALLY INTEGRATING THE PDF FUNCTION.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                     --NU     = THE DEGREES OF FREEDOM PARAMETER
!                     --ALMBDA = THE SKEWNESS PARAMETER
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE SKEW-T DISTRIBUTION
!             WITH SHAPE PARAMETERS NU AND LAMBDA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DQAGI.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PAGE 454.
!               --"Log-Skew-Normal and Log-Skew-t Distributions as
!                 Models for Family Income Data", Azzalini, Cappello,
!                 and Kotz, paper downloaded from Azzalini's web
!                 site.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2003.12
!     ORIGINAL VERSION--DECEMBER  2003.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      INTEGER LIMIT
      INTEGER LENW
      PARAMETER(LIMIT=100)
      PARAMETER(LENW=4*LIMIT)
      INTEGER INF
      INTEGER NEVAL
      INTEGER IER
      INTEGER LAST
      INTEGER IWORK(LIMIT)
      INTEGER NU
      REAL X
      REAL CDF
      DOUBLE PRECISION EPSABS
      DOUBLE PRECISION EPSREL
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DX
      DOUBLE PRECISION ABSERR
      DOUBLE PRECISION WORK(LENW)
!
      DOUBLE PRECISION STFUN
      EXTERNAL STFUN
!
      DOUBLE PRECISION DNU
      DOUBLE PRECISION DLMBDA
      COMMON/STCOM/DNU,DLMBDA
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(NU.LE.0)THEN
        WRITE(ICOUT,115)
  115   FORMAT('***** ERROR--THE DEGREES OF FREEDOM SHAPE ',   &
              'PARAMETER FOR THE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,116)
  116   FORMAT('     SKEWED-T DISTRIBUTION IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)NU
  147   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9000
      ENDIF
!
!               ************************************
!               **  STEP 1--                      **
!               **  COMPUTE THE DENSITY FUNCTION  **
!               ************************************
!
      INF=-1
      EPSABS=0.0D0
      EPSREL=1.0D-7
      IER=0
      CDF=0.0D0
!
      DX=DBLE(X)
      DLMBDA=DBLE(ALMBDA)
      DNU=DBLE(NU)
!
      CALL DQAGI(STFUN,DX,INF,EPSABS,EPSREL,DCDF,ABSERR,NEVAL,   &
                IER,LIMIT,LENW,LAST,IWORK,WORK)
!
      CDF=REAL(DCDF)
!
      IF(IER.EQ.1)THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR FROM STCDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      MAXIMUM NUMBER OF SUBDIVISIONS EXCEEDED.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,121)
  121   FORMAT('***** ERROR FROM STCDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,123)
  123   FORMAT('      ROUNDOFF ERROR PREVENTS REQUESTED TOLERANCE ',   &
               'FROM BEING ACHIEVED.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.3)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,131)
  131   FORMAT('***** ERROR FROM STCDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,133)
  133   FORMAT('      BAD INTEGRAND BEHAVIOUR DETECTED.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,141)
  141   FORMAT('***** ERROR FROM STCDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,143)
  143   FORMAT('      INTEGRATION DID NOT CONVERGE.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,151)
  151   FORMAT('***** ERROR FROM STCDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,153)
  153   FORMAT('      THE INTEGRATION IS PROBABLY DIVERGENT.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.6)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,161)
  161   FORMAT('***** ERROR FROM STCDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,163)
  163   FORMAT('      INVALID INPUT TO THE INTEGRATION ROUTINE.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE STCDF
      DOUBLE PRECISION FUNCTION STFUN(DX)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE SKEW-T DISTRIBUTION
!              WITH SHAPE PARAMETERS NU AND LAMBDA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND HAS
!              THE PROBABILITY DENSITY FUNCTION
!                 STPDF(X,NU,LAMBDA) = 2*
!                       TCDF(LAMBDA*X*SQRT((NU+1)/(X**2+NU)),NU+1)*
!                       TPDF(X,NU)
!              IDENTICAL TO TNPDF,
!              BUT DEFINE AS FUNCTION TO BE USED FOR INTEGRATION
!              CODE CALLED BY TNCDF.  ALSO, THIS ROUTINE USES
!              DOUBLE PRECISION ARITHMETIC.
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--STFUN  = THE DOUBLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE SKEW-T DISTRIBUTION
!             WITH SHAPE PARAMETERS NU AND LAMBDA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NODPDF, NODCDF..
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PAGE 454.
!               --AZZALINI HAS AUTHORED A NUMBER OF PAPERS ON THIS
!                 DISTRIBUTION.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2003.12
!     ORIGINAL VERSION--DECEMBER  2003.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DZ
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DNU2
!
      DOUBLE PRECISION DNU
      DOUBLE PRECISION DLMBDA
      COMMON/STCOM/DNU,DLMBDA
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!               ************************************
!               **  STEP 1--                      **
!               **  COMPUTE THE DENSITY FUNCTION  **
!               ************************************
!
      NU=INT(DNU+0.5)
      DZ=DLMBDA*DX*DSQRT((DNU+1.0D0)/(DX**2+DNU))
      DNU2=DBLE(NU+1)
      CALL TDCDF(DZ,DNU2,DTERM1)
      CALL TDPDF(DX,NU,DTERM2)
      STFUN=2.0D0*DTERM1*DTERM2
!
      RETURN
      END FUNCTION STFUN
      REAL FUNCTION STFU2(X)
!
!     PURPOSE--STPPF CALLS FZERO TO FIND A ROOT FOR THE PERCENT
!              POINT FUNCTION.  STFU2 IS THE FUNCTION FOR WHICH
!              THE ZERO IS FOUND.  IT IS:
!                 P - STCDF(X,LAMBDA)
!              WHERE P IS THE DESIRED PERCENT POINT.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE STFU2.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--STCDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PAGE 454.
!               --AZZALINI HAS AUTHORED A NUMBER OF PAPERS ON THIS
!                 DISTRIBUTION.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2003.12
!     ORIGINAL VERSION--DECEMBER  2003.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      REAL P
      COMMON/ST2COM/P
!
      DOUBLE PRECISION DNU
      DOUBLE PRECISION DLMBDA
      COMMON/STCOM/DNU,DLMBDA
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      NU=INT(DNU+0.01D0)
      CALL STCDF(X,NU,REAL(DLMBDA),CDF)
      STFU2=P - CDF
!
      RETURN
      END FUNCTION STFU2
      SUBROUTINE STPDF(X,NU,ALMBDA,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE SKEW-T DISTRIBUTION
!              WITH SHAPE PARAMETERS NU AND LAMBDA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND HAS
!              THE PROBABILITY DENSITY FUNCTION
!                 STPDF(X,NU,LAMBDA) = 2*
!                       TCDF(LAMBDA*X*SQRT((NU+1)/(X**2+NU)),NU+1)*
!                       TPDF(X,NU)
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!                     --NU     = THE FIRST SHAPE PARAMETER
!                     --ALMBDA = THE SECOND SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE SKEWED-T DISTRIBUTION
!             WITH SHAPE PARAMETERS NU AND LAMBDA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--TPDF, TCDF
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--"Log-Skew-Normal and Log-Skew-t Distributions as
!                 Models for Family Income Data", Azzalini, Cappello,
!                 and Kotz, paper downloaded from Azzalini's web
!                 site.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2003.11
!     ORIGINAL VERSION--NOVEMBER  2003.
!     UPDATED         --OCTOBER   2006. CALL LIST TO TCDF/TPDF
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(NU.LE.0)THEN
        WRITE(ICOUT,115)
  115   FORMAT('***** ERROR--THE DEGREES OF FREEDOM SHAPE ',   &
              'PARAMETER FOR THE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,116)
  116   FORMAT('     SKEWED-T DISTRIBUTION IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)NU
  147   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9000
      ENDIF
!
!               ************************************
!               **  STEP 1--                      **
!               **  COMPUTE THE DENSITY FUNCTION  **
!               ************************************
!
      ANU=REAL(NU)
      Z=ALMBDA*X*SQRT((ANU+1.0)/(X**2+ANU))
      CALL TCDF(Z,REAL(NU+1),TERM1)
      CALL TPDF(X,REAL(NU),TERM2)
      PDF=2.0D0*TERM1*TERM2
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE STPDF
      SUBROUTINE STPPF(P,NU,ALMBDA,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE SKEW-NORMAL DISTRIBUTION
!              WITH SHAPE PARAMETER = LAMBDA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND THE
!              PERCENT POINT FUNCTION IS COMPUTED BY
!              NUMERICALLY INVERTING THE CDF FUNCTION.
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --NU     = THE DEGREES OF FREEDOM PARAMETER
!                     --ALMBDA = THE SKEWNESS PARAMETER
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT
!             FUNCTION VALUE PPF.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--FZERO.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PAGE 454.
!               --"Log-Skew-Normal and Log-Skew-t Distributions as
!                 Models for Family Income Data", Azzalini, Cappello,
!                 and Kotz, paper downloaded from Azzalini's web
!                 site.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2003.12
!     ORIGINAL VERSION--DECEMBER  2003.
!     UPDATED         --OCTOBER   2006. CALL LIST TO TPPF
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      REAL PPF
!
      REAL STFU2
      EXTERNAL STFU2
!
      REAL P2
      COMMON/ST2COM/P2
!
      DOUBLE PRECISION DNU
      DOUBLE PRECISION DLMBDA
      COMMON/STCOM/DNU,DLMBDA
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      PPF=0.0
      IF(NU.LE.0)THEN
        WRITE(ICOUT,115)
  115   FORMAT('***** ERROR--THE DEGREES OF FREEDOM SHAPE ',   &
              'PARAMETER FOR THE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,116)
  116   FORMAT('     SKEWED-T DISTRIBUTION IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)NU
  147   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(P.LE.0.0.OR.P.GE.1.0)THEN
         WRITE(ICOUT,61)
   61    FORMAT('***** ERROR--THE FIRST  ARGUMENT TO STPPF')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,62)
   62    FORMAT('      IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL.')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,63)P
   63    FORMAT('      VALUE OF ARGUMENT = ',G15.7)
         CALL DPWRST('XXX','BUG ')
         GO TO 9000
      ENDIF
!
!  STEP 1: FIND BRACKETING INTERVAL.  START WITH FACT THAT LAMBDA = 0
!          IS THE T DISTRIBUTION AND THE FOLDED-T IS THE
!          LIMITING DISTRIBUTION AS LAMBDA GOES TO INFINITY.
!
      IF(ALMBDA.EQ.0.0)THEN
        CALL TPPF(P,REAL(NU),PPF)
        GO TO 9000
      ELSE
        IFLAG2=0
        IF(ALMBDA.LT.0.0)IFLAG2=1
        P2=P
        IF(IFLAG2.EQ.1)P2=1.0 - P
        CALL TPPF(P2,REAL(NU),XLOW)
        CALL FTPPF(P2,NU,XUP)
      ENDIF
      XLOW=XLOW - 0.2
      XUP=XUP + 0.2
!
      AE=1.E-6
      RE=1.E-6
      DLMBDA=DBLE(ALMBDA)
      DNU=DBLE(NU)
      IF(IFLAG2.EQ.1)DLMBDA=-DLMBDA
      IFLAG=0
      CALL FZERO(STFU2,XLOW,XUP,XUP,RE,AE,IFLAG)
!
      PPF=XLOW
      IF(IFLAG2.EQ.1)PPF=-PPF
!
      IF(IFLAG.EQ.2)THEN
!
!  NOTE: SUPPRESS THIS MESSAGE FOR NOW.
!CCCC   WRITE(ICOUT,999)
  999   FORMAT(1X)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,111)
!C111   FORMAT('***** WARNING FROM STPPF--')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,113)
!C113   FORMAT('      PPF VALUE MAY NOT BE COMPUTED TO DESIRED ',
!CCCC1         'TOLERANCE.')
!CCCC   CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.3)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,121)
  121   FORMAT('***** WARNING FROM STPPF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,123)
  123   FORMAT('      PPF VALUE MAY BE NEAR A SINGULAR POINT.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,131)
  131   FORMAT('***** ERROR FROM STPPF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,133)
  133   FORMAT('      APPROPRIATE BRACKETING INTERVAL NOT FOUND.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,141)
  141   FORMAT('***** WARNING FROM STPPF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,143)
  143   FORMAT('      MAXIMUM ITERATIONS EXCEEDED.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE STPPF
      SUBROUTINE STRAN(N,NU,ALMBDA,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE SKEWED T DISTRIBUTION
!              WITH SHAPE PARAMETERS NU AND ALMBDA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND HAS
!              THE PROBABILITY DENSITY FUNCTION
!                 STPDF(X,NU,LAMBDA) = 2*
!                       TCDF(LAMBDA*X*SQRT((NU+1)/(X**2+NU)),NU+1)*
!                       TPDF(X,NU)
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --NU     = THE FIRST SHAPE PARAMETER
!                     --ALMBDA = THE SECOND SHAPE PARAMETER
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE SKEWED T DISTRIBUTION
!             WITH SHAPE PARAMETERS NU AND ALMBDA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --NU SHOULD BE A POSITIVE INTEGER.
!                 --ALMBDA CAN BE ANY REAL NUMBER.
!     OTHER DATAPAC   SUBROUTINES NEEDED--CHSRAN, SNRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!               --"Log-Skew-Normal and Log-Skew-t Distributions as
!                 Models for Family Income Data", Azzalini, Cappello,
!                 and Kotz, paper downloaded from Azzalini's web
!                 site.
!     REFERENCES--ALGORITHM FOR RANDOM NUMBERS ADAPTED FROM
!                 AZZALINI'S R FUNCTIONS FOR SKEW T.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2003.11
!     ORIGINAL VERSION--NOVEMBER  2003.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(1)
!
      CHARACTER*4 ISKNDF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,5)
    5   FORMAT('***** ERROR--FOR THE SKEWED T DISTRIBUTION,')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,6)
    6   FORMAT('       THE REQUESTED NUMBER OF RANDOM NUMBERS WAS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
   47   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(NU.LE.0)THEN
        WRITE(ICOUT,115)
  115   FORMAT('***** ERROR--THE DEGREES OF FREEDOM SHAPE ',   &
               'PARAMETER FOR THE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,116)
  116   FORMAT('     SKEWED-T RANDOM NUMBERS IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)NU
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
!     ALGORITM ADAPTED FROM AZZALINI'S R FUNCTION LIBRARY.
!
      ISKNDF='DEFA'
      NTEMP=1
      ANU=REAL(NU)
      DO 100 I=1,N
!
        CALL SNRAN(1,ALMBDA,ISKNDF,ISEED,Y)
        Z=Y(1)
        CALL CHSRAN(1,ANU,ISEED,Y)
        V=Y(1)/ANU
        X(I)=Z/SQRT(V)
!
  100 CONTINUE
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE STRAN
      REAL FUNCTION SNRM2(N,SX,INCX)
!***BEGIN PROLOGUE  SNRM2
!***DATE WRITTEN   791001   (YYMMDD)
!***REVISION DATE  820801   (YYMMDD)
!***CATEGORY NO.  D1A3B
!***KEYWORDS  BLAS,EUCLIDEAN,L2,LENGTH,LINEAR ALGEBRA,NORM,VECTOR
!***AUTHOR  LAWSON, C. L., (JPL)
!           HANSON, R. J., (SNLA)
!           KINCAID, D. R., (U. OF TEXAS)
!           KROGH, F. T., (JPL)
!***PURPOSE  Euclidean length (L2 norm) of s.p. vector
!***DESCRIPTION
!
!                B L A S  Subprogram
!    Description of Parameters
!
!     --Input--
!        N  number of elements in input vector(s)
!       SX  single precision vector with N elements
!     INCX  storage spacing between elements of SX
!
!     --Output--
!    SNRM2  single precision result (zero if N .LE. 0)
!
!     Euclidean norm of the N-vector stored in SX() with storage
!     increment INCX .
!     If N .LE. 0, return with result = 0.
!     If N .GE. 1, then INCX must be .GE. 1
!
!           C. L. Lawson, 1978 Jan 08
!
!     Four Phase Method     using two built-in constants that are
!     hopefully applicable to all machines.
!         CUTLO = maximum of  SQRT(U/EPS)  over all known machines.
!         CUTHI = minimum of  SQRT(V)      over all known machines.
!     where
!         EPS = smallest no. such that EPS + 1. .GT. 1.
!         U   = smallest positive no.   (underflow limit)
!         V   = largest  no.            (overflow  limit)
!
!     Brief Outline of Algorithm..
!
!     Phase 1 scans zero components.
!     Move to phase 2 when a component is nonzero and .LE. CUTLO
!     Move to phase 3 when a component is .GT. CUTLO
!     Move to phase 4 when a component is .GE. CUTHI/M
!     where M = N for X() real and M = 2*N for complex.
!
!     Values for CUTLO and CUTHI..
!     From the environmental parameters listed in the IMSL converter
!     document the limiting values are as follows..
!     CUTLO, S.P.   U/EPS = 2**(-102) for  Honeywell.  Close seconds are
!                   Univac and DEC at 2**(-103)
!                   Thus CUTLO = 2**(-51) = 4.44089E-16
!     CUTHI, S.P.   V = 2**127 for Univac, Honeywell, and DEC.
!                   Thus CUTHI = 2**(63.5) = 1.30438E19
!     CUTLO, D.P.   U/EPS = 2**(-67) for Honeywell and DEC.
!                   Thus CUTLO = 2**(-33.5) = 8.23181D-11
!     CUTHI, D.P.   same as S.P.  CUTHI = 1.30438D19
!     DATA CUTLO, CUTHI / 8.232D-11,  1.304D19 /
!     DATA CUTLO, CUTHI / 4.441E-16,  1.304E19 /
!***REFERENCES  LAWSON C.L., HANSON R.J., KINCAID D.R., KROGH F.T.,
!                 *BASIC LINEAR ALGEBRA SUBPROGRAMS FOR FORTRAN USAGE*,
!                 ALGORITHM NO. 539, TRANSACTIONS ON MATHEMATICAL
!                 SOFTWARE, VOLUME 5, NUMBER 3, SEPTEMBER 1979, 308-323
!***ROUTINES CALLED  (NONE)
!***END PROLOGUE  SNRM2
      INTEGER          NEXT
      REAL   SX(*),  CUTLO, CUTHI, HITEST, SUM, XMAX, ZERO, ONE
      DATA   ZERO, ONE /0.0E0, 1.0E0/
!
      DATA CUTLO, CUTHI / 4.441E-16,  1.304E19 /
!***FIRST EXECUTABLE STATEMENT  SNRM2
      IF(N .GT. 0) GO TO 10
         SNRM2  = ZERO
         GO TO 300
!
!CC10 ASSIGN 30 TO NEXT
   10 CONTINUE
      NEXT=30
      SUM = ZERO
      NN = N * INCX
!                                                 BEGIN MAIN LOOP
      I = 1
!CC20    GO TO NEXT,(30, 50, 70, 110)
   20 CONTINUE
      IF(NEXT.EQ.30)THEN
        GO TO 30
      ELSEIF(NEXT.EQ.50)THEN
        GO TO 50
      ELSEIF(NEXT.EQ.70)THEN
        GO TO 70
      ELSEIF(NEXT.EQ.110)THEN
        GO TO 110
      ENDIF
   30 CONTINUE
      IF( ABS(SX(I)) .GT. CUTLO) GO TO 85
!CCCC ASSIGN 50 TO NEXT
      NEXT=50
      XMAX = ZERO
!
!                        PHASE 1.  SUM IS ZERO
!
   50 CONTINUE
      IF( SX(I) .EQ. ZERO) GO TO 200
      IF( ABS(SX(I)) .GT. CUTLO) GO TO 85
!
!                                PREPARE FOR PHASE 2.
!CCCC ASSIGN 70 TO NEXT
      NEXT=70
      GO TO 105
!
!                                PREPARE FOR PHASE 4.
!
  100 CONTINUE
      I = J
!CCCC ASSIGN 110 TO NEXT
      NEXT=110
      SUM = (SUM / SX(I)) / SX(I)
  105 CONTINUE
      XMAX = ABS(SX(I))
      GO TO 115
!
!                   PHASE 2.  SUM IS SMALL.
!                             SCALE TO AVOID DESTRUCTIVE UNDERFLOW.
!
   70 CONTINUE
      IF( ABS(SX(I)) .GT. CUTLO ) GO TO 75
!
!                     COMMON CODE FOR PHASES 2 AND 4.
!                     IN PHASE 4 SUM IS LARGE.  SCALE TO AVOID OVERFLOW.
!
  110 CONTINUE
      IF( ABS(SX(I)) .LE. XMAX ) GO TO 115
         SUM = ONE + SUM * (XMAX / SX(I))**2
         XMAX = ABS(SX(I))
         GO TO 200
!
  115 CONTINUE
      SUM = SUM + (SX(I)/XMAX)**2
      GO TO 200
!
!
!                  PREPARE FOR PHASE 3.
!
   75 CONTINUE
      SUM = (SUM * XMAX) * XMAX
!
!
!     FOR REAL OR D.P. SET HITEST = CUTHI/N
!     FOR COMPLEX      SET HITEST = CUTHI/(2*N)
!
   85 CONTINUE
      HITEST = CUTHI/FLOAT( N )
!
!                   PHASE 3.  SUM IS MID-RANGE.  NO SCALING.
!
      DO 95 J =I,NN,INCX
         IF(ABS(SX(J)) .GE. HITEST) GO TO 100
         SUM = SUM + SX(J)**2
   95 CONTINUE
      SNRM2 = SQRT( SUM )
      GO TO 300
!
  200 CONTINUE
      I = I + INCX
      IF ( I .LE. NN ) GO TO 20
!
!              END OF MAIN LOOP.
!
!              COMPUTE SQUARE ROOT AND ADJUST FOR SCALING.
!
      SNRM2 = XMAX * SQRT(SUM)
  300 CONTINUE
      RETURN
      END FUNCTION SNRM2
      SUBROUTINE SNDOFD(NR,N,XPLS,FPLS,A,SX,RNOISE,STEPSZ,ANBR)
!DPLT SUBROUTINE SNDOFD(NR,N,XPLS,OPTFCN,FPLS,A,SX,RNOISE,STEPSZ,ANBR)
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
! PURPOSE
! -------
! FIND SECOND ORDER FORWARD FINITE DIFFERENCE APPROXIMATION "A"
! TO THE SECOND DERIVATIVE (HESSIAN) OF THE FUNCTION DEFINED BY THE SUBP
! "OPTFCN" EVALUATED AT THE NEW ITERATE "XPLS"
!
! FOR OPTIMIZATION USE THIS ROUTINE TO ESTIMATE
! 1) THE SECOND DERIVATIVE (HESSIAN) OF THE OPTIMIZATION FUNCTION
!    IF NO ANALYTICAL USER FUNCTION HAS BEEN SUPPLIED FOR EITHER
!    THE GRADIENT OR THE HESSIAN AND IF THE OPTIMIZATION FUNCTION
!    "OPTFCN" IS INEXPENSIVE TO EVALUATE.
!
! PARAMETERS
! ----------
! NR           --> ROW DIMENSION OF MATRIX
! N            --> DIMENSION OF PROBLEM
! XPLS(N)      --> NEW ITERATE:   X[K]
! OPTFCN       --> NAME OF SUBROUTINE TO EVALUATE FUNCTION
! FPLS         --> FUNCTION VALUE AT NEW ITERATE, F(XPLS)
! A(N,N)      <--  FINITE DIFFERENCE APPROXIMATION TO HESSIAN
!                  ONLY LOWER TRIANGULAR MATRIX AND DIAGONAL
!                  ARE RETURNED
! SX(N)        --> DIAGONAL SCALING MATRIX FOR X
! RNOISE       --> RELATIVE NOISE IN FNAME [F(X)]
! STEPSZ(N)    --> WORKSPACE (STEPSIZE IN I-TH COMPONENT DIRECTION)
! ANBR(N)      --> WORKSPACE (NEIGHBOR IN I-TH DIRECTION)
!
!
      DIMENSION XPLS(N)
      DIMENSION SX(N)
      DIMENSION STEPSZ(N),ANBR(N)
      DIMENSION A(NR,1)
      DIMENSION FHAT2(1)
!
! FIND I-TH STEPSIZE AND EVALUATE NEIGHBOR IN DIRECTION
! OF I-TH UNIT VECTOR.
!
      OV3 = 1.0D0/3.0D0
      DO 10 I=1,N
        STEPSZ(I)=RNOISE**OV3 * MAX(ABS(XPLS(I)),1.D0/SX(I))
        XTMPI=XPLS(I)
        XPLS(I)=XTMPI+STEPSZ(I)
        CALL OPTFCN(N,XPLS,ANBR(I))
        XPLS(I)=XTMPI
   10 CONTINUE
!
! CALCULATE COLUMN I OF A
!
      DO 30 I=1,N
        XTMPI=XPLS(I)
        XPLS(I)=XTMPI+2.0*STEPSZ(I)
        CALL OPTFCN(N,XPLS,FHAT2)
        FHAT=FHAT2(1)
        A(I,I)=((FPLS-ANBR(I))+(FHAT-ANBR(I)))/(STEPSZ(I)*STEPSZ(I))
!
! CALCULATE SUB-DIAGONAL ELEMENTS OF COLUMN
        IF(I.EQ.N) GO TO 25
        XPLS(I)=XTMPI+STEPSZ(I)
        IP1=I+1
        DO 20 J=IP1,N
          XTMPJ=XPLS(J)
          XPLS(J)=XTMPJ+STEPSZ(J)
          CALL OPTFCN(N,XPLS,FHAT2)
          FHAT=FHAT2(1)
          A(J,I)=((FPLS-ANBR(I))+(FHAT-ANBR(J)))/(STEPSZ(I)*STEPSZ(J))
          XPLS(J)=XTMPJ
   20   CONTINUE
   25   XPLS(I)=XTMPI
   30 CONTINUE
      RETURN
      END SUBROUTINE SNDOFD
      REAL FUNCTION SNV(AJV, ITYPE, GAMMA, DELTA, XLAM, XI, IFAULT)
!
!        ALGORITHM AS 100.2  APPL. STATIST. (1976) VOL.25, P.190
!
!        CONVERTS A JOHNSON VARIATE (AJV) TO A
!        STANDARD NORMAL VARIATE (SNV)
!
      REAL AJV, GAMMA, DELTA, XLAM, XI, V, W, C, ZERO, HALF, ONE,   &
        ZLOG, ZSQRT
!
      DATA ZERO, HALF, ONE, C /0.0, 0.5, 1.0, -63.0/
!
      ZLOG(W) = LOG(W)
      ZSQRT(W) = SQRT(W)
!
      SNV = ZERO
      IFAULT = 1
      IF (ITYPE .LT. 1 .OR. ITYPE .GT. 4) RETURN
      IFAULT = 0
      GO TO  (10, 20, 30, 40), ITYPE
!
!        SL DISTRIBUTION
!
   10 W = XLAM * (AJV - XI)
      IF (W .LE. ZERO) GO TO  15
      SNV = XLAM * (ZLOG(W) * DELTA + GAMMA)
      RETURN
   15 IFAULT = 2
      RETURN
!
!        SU DISTRIBUTION
!
   20 W = (AJV - XI) / XLAM
      IF (W .GT. C) GO TO  23
      W = -HALF / W
      GO TO  27
   23 W = ZSQRT(W * W + ONE) + W
   27 SNV = ZLOG(W) * DELTA + GAMMA
      RETURN
!
!        SB DISTRIBUTION
!
   30 W = AJV - XI
      V = XLAM - W
      IF (W .LE. ZERO .OR. V .LE. ZERO) GO TO  35
      SNV = ZLOG(W / V) * DELTA + GAMMA
      RETURN
   35 IFAULT = 2
      RETURN
!
!        NORMAL DISTRIBUTION
!
   40 SNV = DELTA * AJV + GAMMA
      RETURN
      END FUNCTION SNV
      SUBROUTINE SORT(X,N,Y)
!
!     PURPOSE--THIS SUBROUTINE SORTS (IN ASCENDING ORDER)
!              THE N ELEMENTS OF THE SINGLE PRECISION VECTOR X
!              AND PUTS THE RESULTING N SORTED VALUES INTO THE
!              SINGLE PRECISION VECTOR Y.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                OBSERVATIONS TO BE SORTED.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--Y      = THE SINGLE PRECISION VECTOR
!                                INTO WHICH THE SORTED DATA VALUES
!                                FROM X WILL BE PLACED.
!     OUTPUT--THE SINGLE PRECISION VECTOR Y
!             CONTAINING THE SORTED
!             (IN ASCENDING ORDER) VALUES
!             OF THE SINGLE PRECISION VECTOR X.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THE DIMENSIONS OF THE VECTORS IL AND IU
!                   (DEFINED AND USED INTERNALLY WITHIN
!                   THIS SUBROUTINE) DICTATE THE MAXIMUM
!                   ALLOWABLE VALUE OF N FOR THIS SUBROUTINE.
!                   IF IL AND IU EACH HAVE DIMENSION K,
!                   THEN N MAY NOT EXCEED 2**(K+1) - 1.
!                   FOR THIS SUBROUTINE AS WRITTEN, THE DIMENSIONS
!                   OF IL AND IU HAVE BEEN SET TO 36,
!                   THUS THE MAXIMUM ALLOWABLE VALUE OF N IS
!                   APPROXIMATELY 137 BILLION.
!                   SINCE THIS EXCEEDS THE MAXIMUM ALLOWABLE
!                   VALUE FOR AN INTEGER VARIABLE IN MANY COMPUTERS,
!                   AND SINCE A SORT OF 137 BILLION ELEMENTS
!                   IS PRESENTLY IMPRACTICAL AND UNLIKELY,
!                   THEN THERE IS NO PRACTICAL RESTRICTION
!                   ON THE MAXIMUM VALUE OF N FOR THIS SUBROUTINE.
!                   (IN LIGHT OF THE ABOVE, NO CHECK OF THE
!                   UPPER LIMIT OF N HAS BEEN INCORPORATED
!                   INTO THIS SUBROUTINE.)
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     COMMENT--THE SMALLEST ELEMENT OF THE VECTOR X
!              WILL BE PLACED IN THE FIRST POSITION
!              OF THE VECTOR Y,
!              THE SECOND SMALLEST ELEMENT IN THE VECTOR X
!              WILL BE PLACED IN THE SECOND POSITION
!              OF THE VECTOR Y, ETC.
!     COMMENT--THE INPUT VECTOR X REMAINS UNALTERED.
!     COMMENT--IF THE ANALYST DESIRES A SORT 'IN PLACE',
!              THIS IS DONE BY HAVING THE SAME
!              OUTPUT VECTOR AS INPUT VECTOR IN THE CALLING SEQUENCE.
!              THUS, FOR EXAMPLE, THE CALLING SEQUENCE
!              CALL SORT(X,N,X)
!              IS ALLOWABLE AND WILL RESULT IN
!              THE DESIRED 'IN-PLACE' SORT.
!     COMMENT--THE SORTING ALGORTHM USED HEREIN
!              IS THE  QUICKSORT.
!              THIS ALGORTHIM IS EXTREMELY FAST AS THE
!              FOLLOWING TIME TRIALS INDICATE.
!              THESE TIME TRIALS WERE CARRIED OUT ON THE
!              UNIVAC 1108 EXEC 8 SYSTEM AT NBS
!              IN AUGUST OF 1974.
!              BY WAY OF COMPARISON, THE TIME TRIAL VALUES
!              FOR THE EASY-TO-PROGRAM BUT EXTREMELY
!              INEFFICIENT BUBBLE SORT ALGORITHM HAVE
!              ALSO BEEN INCLUDED--
!              NUMBER OF RANDOM         QUICKSORT       BUBBLE SORT
!               NUMBERS SORTED
!                N = 10                 .002 SEC          .002 SEC
!                N = 100                .011 SEC          .045 SEC
!                N = 1000               .141 SEC         4.332 SEC
!                N = 3000               .476 SEC        37.683 SEC
!                N = 10000             1.887 SEC      NOT COMPUTED
!     REFERENCES--CACM MARCH 1969, PAGE 186 ( QUICKSORT ALGORITHM
!                 BY RICHARD C. SINGLETON).
!               --CACM JANUARY 1970, PAGE 54.
!               --CACM OCTOBER 1970, PAGE 624.
!               --JACM JANUARY 1961, PAGE 41.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--JUNE      1972.
!     UPDATED         --NOVEMBER  1975.
!     UPDATED         --JUNE      1981.
!     UPDATED         --AUGUST    1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(*)
!
      DIMENSION IU(36)
      DIMENSION IL(36)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='SORT'
      ISUBN2='    '
      IERROR='NO'
      IBUGA3='OFF'
!
      IF(IBUGA3.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF SORT--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGA3
   52 FORMAT('IBUGA3 = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)N
   53 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 55 I=1,N
      WRITE(ICOUT,56)I,X(I)
   56 FORMAT('I,X(I) = ',I8,E15.7)
      CALL DPWRST('XXX','BUG ')
   55 CONTINUE
   90 CONTINUE
!
!               ************************
!               **  SORT THE VALUES.  **
!               ************************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N.GE.1)GO TO 119
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,111)
  111 FORMAT('***** ERROR IN SORT--',   &
      'THE SECOND INPUT ARGUMENT (N) IS SMALLER THAN 1')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,118)N
  118 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
  119 CONTINUE
!
      IF(N.EQ.1)GO TO 120
      GO TO 129
  120 CONTINUE
!CCCC WRITE(ICOUT,999)
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,121)
!C121 FORMAT('***** NON-FATAL DIAGNOSTIC IN SORT--',
!CCCC1'THE SECOND INPUT ARGUMENT (N) HAS THE VALUE 1')
!CCCC CALL DPWRST('XXX','BUG ')
      Y(1)=X(1)
      GO TO 9000
  129 CONTINUE
!
      HOLD=X(1)
      DO 135 I=2,N
      IF(X(I).NE.HOLD)GO TO 139
  135 CONTINUE
!CCCC WRITE(ICOUT,999)
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,136)HOLD
!C136 FORMAT('***** NON-FATAL DIAGNOSTIC IN SORT--',
!CCCC1'THE FIRST INPUT ARGUMENT (A VECTOR) HAS ALL ELEMENTS = ',E15.7)
!CCCC CALL DPWRST('XXX','BUG ')
      DO 137 I=1,N
        Y(I)=X(I)
  137 CONTINUE
      GO TO 9000
  139 CONTINUE
!
!               *******************************************
!               **  STEP 2--                             **
!               **  COPY THE VECTOR X INTO THE VECTOR Y  **
!               *******************************************
!
      DO 200 I=1,N
        Y(I)=X(I)
  200 CONTINUE
!
!               **********************************************************
!               **  STEP 3--                                            **
!               **  CHECK TO SEE IF THE INPUT VECTOR IS ALREADY SORTED  **
!               **********************************************************
!
      NM1=N-1
      DO 250 I=1,NM1
      IP1=I+1
      IF(Y(I).LE.Y(IP1))GO TO 250
      GO TO 290
  250 CONTINUE
      GO TO 9000
  290 CONTINUE
!
!               ***************************
!               **  STEP 4--             **
!               **  CARRY OUT THE SORT.  **
!               ***************************
!
      M=1
      I=1
      J=N
  305 IF(I.GE.J)GO TO 370
  310 K=I
      MID=(I+J)/2
      AMED=Y(MID)
      IF(Y(I).LE.AMED)GO TO 320
      Y(MID)=Y(I)
      Y(I)=AMED
      AMED=Y(MID)
  320 L=J
      IF(Y(J).GE.AMED)GO TO 340
      Y(MID)=Y(J)
      Y(J)=AMED
      AMED=Y(MID)
      IF(Y(I).LE.AMED)GO TO 340
      Y(MID)=Y(I)
      Y(I)=AMED
      AMED=Y(MID)
      GO TO 340
  330 Y(L)=Y(K)
      Y(K)=TT
  340 L=L-1
      IF(Y(L).GT.AMED)GO TO 340
      TT=Y(L)
  350 K=K+1
      IF(Y(K).LT.AMED)GO TO 350
      IF(K.LE.L)GO TO 330
      LMI=L-I
      JMK=J-K
      IF(LMI.LE.JMK)GO TO 360
      IL(M)=I
      IU(M)=L
      I=K
      M=M+1
      GO TO 380
  360 IL(M)=K
      IU(M)=J
      J=L
      M=M+1
      GO TO 380
  370 M=M-1
      IF(M.EQ.0)GO TO 9000
      I=IL(M)
      J=IU(M)
  380 JMI=J-I
      IF(JMI.GE.11)GO TO 310
      IF(I.EQ.1)GO TO 305
      I=I-1
  390 I=I+1
      IF(I.EQ.J)GO TO 370
      AMED=Y(I+1)
      IF(Y(I).LE.AMED)GO TO 390
      K=I
  395 Y(K+1)=Y(K)
      K=K-1
      IF(AMED.LT.Y(K))GO TO 395
      Y(K+1)=AMED
      GO TO 390
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF SORT--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGA3,IERROR
 9012 FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)N
 9013 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 9015 I=1,N
      WRITE(ICOUT,9016)I,X(I),Y(I)
 9016 FORMAT('I,X(I),Y(I) = ',I8,2E15.7)
      CALL DPWRST('XXX','BUG ')
 9015 CONTINUE
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE SORT
      SUBROUTINE SORT2(X1,X2,N,IWRITE,Y1,Y2,TEMP1,XIDTEM,   &
                       ISORDI,ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE SORTS BASED ON TWO VARIABLES
!     INPUT  ARGUMENTS--X1     = THE SINGLE PRECISION VECTOR CONTAINING
!                                THE FIRST RESPONSE VARIABLE TO BE
!                                SORTED.
!                     --X2     = THE SINGLE PRECISION VECTOR CONTAINING
!                                THE SECOND RESPONSE VARIABLE TO BE
!                                SORTED.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!                     --ISORDI = CHARACTER VARIABLE THAT SPECIFIES
!                                WHETHER SORT IS ASCENDING OR
!                                DESCENDING.
!     OUTPUT ARGUMENTS--Y1     = THE SINGLE PRECISION VECTOR
!                                CONTAINING THE SORTED VALUES OF
!                                THE FIRST RESPONSE VARIABLE.
!     OUTPUT ARGUMENTS--Y2     = THE SINGLE PRECISION VECTOR
!                                CONTAINING THE SORTED VALUES OF
!                                THE SECOND RESPONSE VARIABLE.
!     OUTPUT--THE SINGLE PRECISION VECTORS Y1 AND Y2 CONTAINING
!             THE SORTED VECTORS.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     OTHER DATAPAC   SUBROUTINES NEEDED--SORT, SORTI.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2008.10
!     ORIGINAL VERSION--OCTOBER   2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISORDI
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION Y1(*)
      DIMENSION Y2(*)
      DIMENSION X1(*)
      DIMENSION X2(*)
      DIMENSION TEMP1(*)
      DIMENSION XIDTEM(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='SORT'
      ISUBN2='2   '
      IERROR='NO'
!
      ISTRT=0
      IFRST=0
      ILAST=0
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'ORT2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF SORT2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISORDI
   52   FORMAT('IBUGA3,ISORDI = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)N
   53   FORMAT('N = ',2I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X1(I),X2(I)
   56     FORMAT('I,X1(I),X2(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!    ********************************************
!    **  STEP 1--                              **
!    **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!    ********************************************
!
      AN=N
!
      IF(N.LT.1)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN SORT2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      THE NUMBER OF RESPONSE VALUES IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,115)N
  115   FORMAT('      THE NUMBER OF RESPONSE VALUES IS ',I8)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(N.EQ.1)THEN
        Y1(1)=X1(1)
        Y2(1)=X2(1)
        GO TO 9000
      ENDIF
!
!     ***************************************************
!     **  STEP 2--                                     **
!     **  SORT FIRST VARIABLE AND CARRY THE SECOND     **
!     **  VARIABLE.                                    **
!     ***************************************************
!
      CALL SORTI(X1,N,Y1,TEMP1)
!
      IF(ISORDI.EQ.'DESC')THEN
        DO 1010 I=1,N
          Y2(I)=Y1(I)
 1010   CONTINUE
        DO 1020 I=1,N
          II=N-I+1
          Y1(I)=Y2(II)
 1020   CONTINUE
      ENDIF
!
      DO 1030 I=1,N
        J=INT(TEMP1(I)+0.5)
        Y2(I)=X2(J)
 1030 CONTINUE
      IF(ISORDI.EQ.'DESC')THEN
        DO 1040 I=1,N
          TEMP1(I)=Y2(I)
 1040   CONTINUE
        DO 1050 I=1,N
          II=N-I+1
          Y2(I)=TEMP1(II)
 1050   CONTINUE
      ENDIF
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'ORT2')THEN
        WRITE(ICOUT,1091)
 1091   FORMAT('AFTER SORT FIRST RESPONSE VARIABLE')
        CALL DPWRST('XXX','BUG ')
        DO 1099 I=1,N
        WRITE(ICOUT,1093)I,X1(I),X2(I),Y1(I),Y2(I)
 1093   FORMAT('I,X1(I),X2(I),Y1(I),Y2(I) = ',I8,4G15.7)
        CALL DPWRST('XXX','BUG ')
 1099   CONTINUE
      ENDIF
!
!     ****************************************************
!     **  STEP 3--                                      **
!     **  NOW SORT THE SECOND VARIABLE FOR COMMON       **
!     **  VALUES OF FIRST VARIABLE.                     **
!     ****************************************************
!
      CALL DISTIN(Y1,N,IWRITE,XIDTEM,NDIST,IBUGA3,IERROR)
      IF(N.EQ.NDIST)GO TO 9000
      IF(NDIST.EQ.1)THEN
        CALL SORTI(X2,N,Y2,TEMP1)
        IF(ISORDI.EQ.'DESC')THEN
          DO 2010 I=1,N
            TEMP1(I)=Y2(I)
 2010     CONTINUE
          DO 2020 I=1,N
            II=N-I+1
            Y2(I)=TEMP1(I)
 2020     CONTINUE
        ENDIF
        GO TO 9000
      ENDIF
!
      CALL SORT(XIDTEM,NDIST,XIDTEM)
      IF(ISORDI.EQ.'DESC')THEN
        DO 2030 I=1,NDIST
          TEMP1(I)=XIDTEM(I)
 2030   CONTINUE
        DO 2040 I=1,NDIST
          II=NDIST-I+1
          XIDTEM(I)=TEMP1(II)
 2040   CONTINUE
      ENDIF
!
      ISTRT=1
      DO 2110 ISET=1,NDIST
        HOLD=XIDTEM(ISET)
!
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'ORT2')THEN
          WRITE(ICOUT,2111)ISET,ISTRT,HOLD
 2111     FORMAT('AT 2110: ISET,ISTRT,HOLD = ',2I8,G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        ICNT=0
        IFLAG1=0
        DO 2120 I=ISTRT,N
          IF(Y1(I).EQ.HOLD)THEN
            IF(IFLAG1.EQ.0)THEN
              IFRST=I
              IFLAG1=1
            ENDIF
            ILAST=I
            ICNT=ICNT+1
            TEMP1(ICNT)=Y2(I)
          ENDIF
 2120   CONTINUE
        ISTRT=ILAST+1
        CALL SORT(TEMP1,ICNT,TEMP1)
        IF(ISORDI.EQ.'DESC')THEN
          ICNT2=0
          DO 2130 J=ICNT,1,-1
            ICNT2=ICNT2+1
            Y2(IFRST+J-1)=TEMP1(ICNT2)
 2130     CONTINUE
        ELSE
          DO 2160 J=1,ICNT
            Y2(IFRST+J-1)=TEMP1(J)
 2160     CONTINUE
        ENDIF
 2110 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'ORT2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF SORT2--')
        CALL DPWRST('XXX','BUG ')
        DO 9015 I=1,N
          WRITE(ICOUT,9016)I,X1(I),X2(I),Y1(I),Y2(I)
 9016     FORMAT('I,X1(I),X2(I),Y1(I),Y2(I) = ',I8,4G15.7)
          CALL DPWRST('XXX','BUG ')
 9015   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE SORT2
      SUBROUTINE SORT3(X1,X2,X3,N,IWRITE,Y1,Y2,Y3,   &
                       TEMP1,TEMP2,TEMP3,TEMP4,TEMP5,XIDTEM,XIDTE2,   &
                       ISORDI,ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE SORTS BASED ON THREE VARIABLES
!     INPUT  ARGUMENTS--X1     = THE SINGLE PRECISION VECTOR CONTAINING
!                                THE FIRST RESPONSE VARIABLE TO BE
!                                SORTED.
!                     --X2     = THE SINGLE PRECISION VECTOR CONTAINING
!                                THE SECOND RESPONSE VARIABLE TO BE
!                                SORTED.
!                     --X3     = THE SINGLE PRECISION VECTOR CONTAINING
!                                THE THIRD RESPONSE VARIABLE TO BE
!                                SORTED.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!                     --ISORDI = CHARACTER VARIABLE THAT SPECIFIES
!                                WHETHER SORT IS ASCENDING OR
!                                DESCENDING.
!     OUTPUT ARGUMENTS--Y1     = THE SINGLE PRECISION VECTOR
!                                CONTAINING THE SORTED VALUES OF
!                                THE FIRST RESPONSE VARIABLE.
!                     --Y2     = THE SINGLE PRECISION VECTOR
!                                CONTAINING THE SORTED VALUES OF
!                                THE SECOND RESPONSE VARIABLE.
!                     --Y3     = THE SINGLE PRECISION VECTOR
!                                CONTAINING THE SORTED VALUES OF
!                                THE THIRD RESPONSE VARIABLE.
!     OUTPUT--THE SINGLE PRECISION VECTORS Y1, Y2 AND Y3 CONTAINING
!             THE SORTED VECTORS.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     OTHER DATAPAC   SUBROUTINES NEEDED--SORT, SORTI.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2008.10
!     ORIGINAL VERSION--OCTOBER   2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISORDI
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION Y1(*)
      DIMENSION Y2(*)
      DIMENSION Y3(*)
      DIMENSION X1(*)
      DIMENSION X2(*)
      DIMENSION X3(*)
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
      DIMENSION TEMP3(*)
      DIMENSION TEMP4(*)
      DIMENSION TEMP5(*)
      DIMENSION XIDTEM(*)
      DIMENSION XIDTE2(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='SORT'
      ISUBN2='3   '
      IERROR='NO'
!
      ISTRT=0
      IFRST=0
      ILAST=0
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'ORT3')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF SORT3--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISORDI
   52   FORMAT('IBUGA3,ISORDI = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)N
   53   FORMAT('N = ',2I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X1(I),X2(I),X3(I)
   56     FORMAT('I,X1(I),X2(I),X3(I) = ',I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!    ********************************************
!    **  STEP 1--                              **
!    **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!    ********************************************
!
      AN=N
!
      IF(N.LT.1)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN SORT3--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      THE NUMBER OF RESPONSE VALUES IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,115)N
  115   FORMAT('      THE NUMBER OF RESPONSE VALUES IS ',I8)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(N.EQ.1)THEN
        Y1(1)=X1(1)
        Y2(1)=X2(1)
        Y3(1)=X3(1)
        GO TO 9000
      ENDIF
!
!     ***************************************************
!     **  STEP 2--                                     **
!     **  SORT FIRST VARIABLE AND CARRY THE SECOND     **
!     **  AND THIRD VARIABLES.                         **
!     ***************************************************
!
      CALL SORTI(X1,N,Y1,TEMP1)
!
      IF(ISORDI.EQ.'DESC')THEN
        DO 1010 I=1,N
          Y2(I)=Y1(I)
 1010   CONTINUE
        DO 1020 I=1,N
          II=N-I+1
          Y1(I)=Y2(II)
 1020   CONTINUE
      ENDIF
!
      DO 1030 I=1,N
        J=INT(TEMP1(I)+0.5)
        Y2(I)=X2(J)
        Y3(I)=X3(J)
 1030 CONTINUE
      IF(ISORDI.EQ.'DESC')THEN
        DO 1040 I=1,N
          TEMP1(I)=Y2(I)
 1040   CONTINUE
        DO 1050 I=1,N
          II=N-I+1
          Y2(I)=TEMP1(II)
 1050   CONTINUE
        DO 1060 I=1,N
          TEMP1(I)=Y3(I)
 1060   CONTINUE
        DO 1070 I=1,N
          II=N-I+1
          Y3(I)=TEMP1(II)
 1070   CONTINUE
      ENDIF
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'ORT3')THEN
        WRITE(ICOUT,1091)
 1091   FORMAT('AFTER SORT FIRST RESPONSE VARIABLE')
        CALL DPWRST('XXX','BUG ')
        DO 1099 I=1,N
        WRITE(ICOUT,1093)I,X1(I),X2(I),X3(I),Y1(I),Y2(I),Y3(I)
 1093   FORMAT('I,X1(I),X2(I),X3(I),Y1(I),Y2(I),Y3(I) = ',   &
               I8,6G15.7)
        CALL DPWRST('XXX','BUG ')
 1099   CONTINUE
      ENDIF
!
!     **********************************************************
!     **  STEP 3--                                            **
!     **  NOW SORT THE SECOND AND THIRD VARIABLES FOR COMMON  **
!     **  VALUES OF FIRST VARIABLE.                           **
!     **********************************************************
!
      CALL DISTIN(Y1,N,IWRITE,XIDTEM,NDIST,IBUGA3,IERROR)
      IF(N.EQ.NDIST)GO TO 9000
      IF(NDIST.EQ.1)THEN
        CALL SORTI(X2,N,Y2,TEMP1)
        IF(ISORDI.EQ.'DESC')THEN
          DO 2010 I=1,N
            TEMP1(I)=Y2(I)
 2010     CONTINUE
          DO 2015 I=1,N
            II=N-I+1
            Y2(I)=TEMP1(I)
 2015     CONTINUE
          DO 2020 I=1,N
            TEMP1(I)=Y3(I)
 2020     CONTINUE
          DO 2025 I=1,N
            II=N-I+1
            Y3(I)=TEMP1(I)
 2025     CONTINUE
        ENDIF
        GO TO 9000
      ENDIF
!
      CALL SORT(XIDTEM,NDIST,XIDTEM)
      IF(ISORDI.EQ.'DESC')THEN
        DO 2030 I=1,NDIST
          TEMP1(I)=XIDTEM(I)
 2030   CONTINUE
        DO 2040 I=1,NDIST
          II=NDIST-I+1
          XIDTEM(I)=TEMP1(II)
 2040   CONTINUE
      ENDIF
!
      ISTRT=1
      DO 2110 ISET=1,NDIST
        HOLD=XIDTEM(ISET)
!
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'ORT3')THEN
          WRITE(ICOUT,2111)ISET,ISTRT,HOLD
 2111     FORMAT('AT 2110: ISET,ISTRT,HOLD = ',2I8,G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        ICNT=0
        IFLAG1=0
        DO 2120 I=ISTRT,N
          IF(Y1(I).EQ.HOLD)THEN
            IF(IFLAG1.EQ.0)THEN
              IFRST=I
              IFLAG1=1
            ENDIF
            ILAST=I
            ICNT=ICNT+1
            TEMP1(ICNT)=Y2(I)
            TEMP2(ICNT)=Y3(I)
          ENDIF
 2120   CONTINUE
        ISTRT=ILAST+1
        CALL SORT2(TEMP1,TEMP2,ICNT,IWRITE,TEMP3,TEMP4,TEMP5,XIDTE2,   &
                   ISORDI,ISUBRO,IBUGA3,IERROR)
        IF(ISORDI.EQ.'DESC')THEN
          ICNT2=0
          DO 2130 J=ICNT,1,-1
            ICNT2=ICNT2+1
            Y2(IFRST+J-1)=TEMP3(ICNT2)
            Y3(IFRST+J-1)=TEMP4(ICNT2)
 2130     CONTINUE
        ELSE
          DO 2160 J=1,ICNT
            Y2(IFRST+J-1)=TEMP3(J)
            Y3(IFRST+J-1)=TEMP4(J)
 2160     CONTINUE
        ENDIF
 2110 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'ORT3')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF SORT3--')
        CALL DPWRST('XXX','BUG ')
        DO 9015 I=1,N
          WRITE(ICOUT,9016)I,X1(I),X2(I),X3(I),Y1(I),Y2(I),Y3(I)
 9016     FORMAT('I,X1(I),X2(I),X3(I),Y1(I),Y2(I),Y3(I) = ',   &
                 I8,6G15.7)
          CALL DPWRST('XXX','BUG ')
 9015   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE SORT3
      SUBROUTINE SORT4(X1,X2,X3,X4,N,IWRITE,Y1,Y2,Y3,Y4,   &
                       TEMP1,TEMP2,TEMP3,TEMP4,TEMP5,TEMP6,   &
                       XTEMP1,XTEMP2,XTEMP3,XTEMP4,XTEMP5,   &
                       XIDTEM,XIDTE2,XIDTE3,   &
                       ISORDI,ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE SORTS BASED ON THREE VARIABLES
!     INPUT  ARGUMENTS--X1     = THE SINGLE PRECISION VECTOR CONTAINING
!                                THE FIRST RESPONSE VARIABLE TO BE
!                                SORTED.
!                     --X2     = THE SINGLE PRECISION VECTOR CONTAINING
!                                THE SECOND RESPONSE VARIABLE TO BE
!                                SORTED.
!                     --X3     = THE SINGLE PRECISION VECTOR CONTAINING
!                                THE THIRD RESPONSE VARIABLE TO BE
!                                SORTED.
!                     --X4     = THE SINGLE PRECISION VECTOR CONTAINING
!                                THE FOURTH RESPONSE VARIABLE TO BE
!                                SORTED.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!                     --ISORDI = CHARACTER VARIABLE THAT SPECIFIES
!                                WHETHER SORT IS ASCENDING OR
!                                DESCENDING.
!     OUTPUT ARGUMENTS--Y1     = THE SINGLE PRECISION VECTOR
!                                CONTAINING THE SORTED VALUES OF
!                                THE FIRST RESPONSE VARIABLE.
!                     --Y2     = THE SINGLE PRECISION VECTOR
!                                CONTAINING THE SORTED VALUES OF
!                                THE SECOND RESPONSE VARIABLE.
!                     --Y3     = THE SINGLE PRECISION VECTOR
!                                CONTAINING THE SORTED VALUES OF
!                                THE THIRD RESPONSE VARIABLE.
!                     --Y4     = THE SINGLE PRECISION VECTOR
!                                CONTAINING THE SORTED VALUES OF
!                                THE FOURTH RESPONSE VARIABLE.
!     OUTPUT--THE SINGLE PRECISION VECTORS Y1, Y2, Y3 AND Y4
!             CONTAINING THE SORTED VECTORS.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     OTHER DATAPAC   SUBROUTINES NEEDED--SORT, SORTI.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2008.10
!     ORIGINAL VERSION--OCTOBER   2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISORDI
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION Y1(*)
      DIMENSION Y2(*)
      DIMENSION Y3(*)
      DIMENSION Y4(*)
      DIMENSION X1(*)
      DIMENSION X2(*)
      DIMENSION X3(*)
      DIMENSION X4(*)
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
      DIMENSION TEMP3(*)
      DIMENSION TEMP4(*)
      DIMENSION TEMP5(*)
      DIMENSION TEMP6(*)
      DIMENSION XTEMP1(*)
      DIMENSION XTEMP2(*)
      DIMENSION XTEMP3(*)
      DIMENSION XTEMP4(*)
      DIMENSION XTEMP5(*)
      DIMENSION XIDTEM(*)
      DIMENSION XIDTE2(*)
      DIMENSION XIDTE3(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='SORT'
      ISUBN2='4   '
      IERROR='NO'
!
      IFRST=0
      ISTRT=0
      ILAST=0
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'ORT4')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF SORT3--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISORDI,N
   52   FORMAT('IBUGA3,ISORDI,N = ',2(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X1(I),X2(I),X3(I),X4(I)
   56     FORMAT('I,X1(I),X2(I),X3(I),X4(I) = ',I8,4G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!    ********************************************
!    **  STEP 1--                              **
!    **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!    ********************************************
!
      AN=N
!
      IF(N.LT.1)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN SORT3--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      THE NUMBER OF RESPONSE VALUES IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,115)N
  115   FORMAT('      THE NUMBER OF RESPONSE VALUES IS ',I8)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(N.EQ.1)THEN
        Y1(1)=X1(1)
        Y2(1)=X2(1)
        Y3(1)=X3(1)
        Y4(1)=X4(1)
        GO TO 9000
      ENDIF
!
!     ***************************************************
!     **  STEP 2--                                     **
!     **  SORT FIRST VARIABLE AND CARRY THE SECOND     **
!     **  AND THIRD VARIABLES.                         **
!     ***************************************************
!
      CALL SORTI(X1,N,Y1,TEMP1)
!
      IF(ISORDI.EQ.'DESC')THEN
        DO 1010 I=1,N
          Y2(I)=Y1(I)
 1010   CONTINUE
        DO 1020 I=1,N
          II=N-I+1
          Y1(I)=Y2(II)
 1020   CONTINUE
      ENDIF
!
      DO 1030 I=1,N
        J=INT(TEMP1(I)+0.5)
        Y2(I)=X2(J)
        Y3(I)=X3(J)
        Y4(I)=X4(J)
 1030 CONTINUE
      IF(ISORDI.EQ.'DESC')THEN
        DO 1040 I=1,N
          TEMP1(I)=Y2(I)
 1040   CONTINUE
        DO 1050 I=1,N
          II=N-I+1
          Y2(I)=TEMP1(II)
 1050   CONTINUE
        DO 1060 I=1,N
          TEMP1(I)=Y3(I)
 1060   CONTINUE
        DO 1070 I=1,N
          II=N-I+1
          Y3(I)=TEMP1(II)
 1070   CONTINUE
        DO 1080 I=1,N
          TEMP1(I)=Y4(I)
 1080   CONTINUE
        DO 1090 I=1,N
          II=N-I+1
          Y4(I)=TEMP1(II)
 1090   CONTINUE
      ENDIF
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'ORT3')THEN
        WRITE(ICOUT,1091)
 1091   FORMAT('AFTER SORT FIRST RESPONSE VARIABLE')
        CALL DPWRST('XXX','BUG ')
        DO 1099 I=1,N
        WRITE(ICOUT,1093)I,X1(I),X2(I),X3(I),X4(I),   &
                         Y1(I),Y2(I),Y3(I)
 1093   FORMAT('I,X1(I),X2(I),X3(I),X4(I),',   &
               'Y1(I),Y2(I),Y3(I),Y4(I) = ',   &
               I8,8G15.7)
        CALL DPWRST('XXX','BUG ')
 1099   CONTINUE
      ENDIF
!
!     **********************************************************
!     **  STEP 3--                                            **
!     **  NOW SORT THE SECOND AND THIRD VARIABLES FOR COMMON  **
!     **  VALUES OF FIRST VARIABLE.                           **
!     **********************************************************
!
      CALL DISTIN(Y1,N,IWRITE,XIDTEM,NDIST,IBUGA3,IERROR)
      IF(N.EQ.NDIST)GO TO 9000
      IF(NDIST.EQ.1)THEN
        CALL SORTI(X2,N,Y2,TEMP1)
        IF(ISORDI.EQ.'DESC')THEN
          DO 2010 I=1,N
            TEMP1(I)=Y2(I)
 2010     CONTINUE
          DO 2011 I=1,N
            II=N-I+1
            Y2(I)=TEMP1(I)
 2011     CONTINUE
          DO 2020 I=1,N
            TEMP1(I)=Y3(I)
 2020     CONTINUE
          DO 2021 I=1,N
            II=N-I+1
            Y3(I)=TEMP1(I)
 2021     CONTINUE
          DO 2025 I=1,N
            TEMP1(I)=Y4(I)
 2025     CONTINUE
          DO 2026 I=1,N
            II=N-I+1
            Y4(I)=TEMP1(I)
 2026     CONTINUE
        ENDIF
        GO TO 9000
      ENDIF
!
      CALL SORT(XIDTEM,NDIST,XIDTEM)
      IF(ISORDI.EQ.'DESC')THEN
        DO 2030 I=1,NDIST
          TEMP1(I)=XIDTEM(I)
 2030   CONTINUE
        DO 2040 I=1,NDIST
          II=NDIST-I+1
          XIDTEM(I)=TEMP1(II)
 2040   CONTINUE
      ENDIF
!
      ISTRT=1
      DO 2110 ISET=1,NDIST
        HOLD=XIDTEM(ISET)
!
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'ORT3')THEN
          WRITE(ICOUT,2111)ISET,ISTRT,HOLD
 2111     FORMAT('AT 2110: ISET,ISTRT,HOLD = ',2I8,G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        ICNT=0
        IFLAG1=0
        DO 2120 I=ISTRT,N
          IF(Y1(I).EQ.HOLD)THEN
            IF(IFLAG1.EQ.0)THEN
              IFRST=I
              IFLAG1=1
            ENDIF
            ILAST=I
            ICNT=ICNT+1
            TEMP1(ICNT)=Y2(I)
            TEMP2(ICNT)=Y3(I)
            TEMP3(ICNT)=Y4(I)
          ENDIF
 2120   CONTINUE
        ISTRT=ILAST+1
        CALL SORT3(TEMP1,TEMP2,TEMP3,ICNT,IWRITE,TEMP4,TEMP5,TEMP6,   &
                   XTEMP1,XTEMP2,XTEMP3,XTEMP4,XTEMP5,   &
                   XIDTE2,XIDTE3,   &
                   ISORDI,ISUBRO,IBUGA3,IERROR)
        IF(ISORDI.EQ.'DESC')THEN
          ICNT2=0
          DO 2130 J=ICNT,1,-1
            ICNT2=ICNT2+1
            Y2(IFRST+J-1)=TEMP4(ICNT2)
            Y3(IFRST+J-1)=TEMP5(ICNT2)
            Y4(IFRST+J-1)=TEMP6(ICNT2)
 2130     CONTINUE
        ELSE
          DO 2160 J=1,ICNT
            Y2(IFRST+J-1)=TEMP4(J)
            Y3(IFRST+J-1)=TEMP5(J)
            Y4(IFRST+J-1)=TEMP6(J)
 2160     CONTINUE
        ENDIF
 2110 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'ORT3')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF SORT3--')
        CALL DPWRST('XXX','BUG ')
        DO 9015 I=1,N
          WRITE(ICOUT,9016)I,X1(I),X2(I),X3(I),X4(I),   &
                           Y1(I),Y2(I),Y3(I),Y4(I)
 9016     FORMAT('I,X1(I),X2(I),X3(I),X4(I),',   &
                 'Y1(I),Y2(I),Y3(I),Y4(I) = ',   &
                 I8,8G15.7)
          CALL DPWRST('XXX','BUG ')
 9015   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE SORT4
      SUBROUTINE SORTC(X,Y,N,XS,YC)
!
!     PURPOSE--THIS SUBROUTINE SORTS (IN ASCENDING ORDER)
!              THE N ELEMENTS OF THE SINGLE PRECISION VECTOR X,
!              PUTS THE RESULTING N SORTED VALUES INTO THE
!              SINGLE PRECISION VECTOR XS,
!              REARRANGES THE ELEMENTS OF THE VECTOR Y
!              (ACCORDING TO THE SORT ON X),
!              AND PUTS THE REARRANGED Y VALUES
!              INTO THE SINGLE PRECISION VECTOR YC.
!              THIS SUBROUTINE GIVES THE DATA ANALYST
!              THE ABILITY TO SORT ONE DATA VECTOR
!              WHILE 'CARRYING ALONG' THE ELEMENTS
!              OF A SECOND DATA VECTOR.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                OBSERVATIONS TO BE SORTED.
!                     --Y      = THE SINGLE PRECISION VECTOR OF
!                                OBSERVATIONS TO BE 'CARRIED ALONG',
!                                THAT IS, TO BE REARRANGED ACCORDING
!                                TO THE SORT ON X.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XS     = THE SINGLE PRECISION VECTOR
!                                INTO WHICH THE SORTED DATA VALUES
!                                FROM X WILL BE PLACED.
!                     --YC     = THE SINGLE PRECISION VECTOR
!                                INTO WHICH THE REARRANGED
!                                (ACCORDING TO THE SORT OF THE
!                                VECTOR X) VALUES OF THE VECTOR Y
!                                WILL BE PLACED.
!     OUTPUT--THE SINGLE PRECISION VECTOR XS
!             CONTAINING THE SORTED
!             (IN ASCENDING ORDER) VALUES
!             OF THE SINGLE PRECISION VECTOR X, AND
!             THE SINGLE PRECISION VECTOR YC
!             CONTAINING THE REARRANGED
!             (ACCORDING TO THE SORT ON X)
!             VALUES OF THE VECTOR Y.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THE DIMENSIONS OF THE VECTORS IL AND IU
!                   (DEFINED AND USED INTERNALLY WITHIN
!                   THIS SUBROUTINE) DICTATE THE MAXIMUM
!                   ALLOWABLE VALUE OF N FOR THIS SUBROUTINE.
!                   IF IL AND IU EACH HAVE DIMENSION K,
!                   THEN N MAY NOT EXCEED 2**(K+1) - 1.
!                   FOR THIS SUBROUTINE AS WRITTEN, THE DIMENSIONS
!                   OF IL AND IU HAVE BEEN SET TO 36,
!                   THUS THE MAXIMUM ALLOWABLE VALUE OF N IS
!                   APPROXIMATELY 137 BILLION.
!                   SINCE THIS EXCEEDS THE MAXIMUM ALLOWABLE
!                   VALUE FOR AN INTEGER VARIABLE IN MANY COMPUTERS,
!                   AND SINCE A SORT OF 137 BILLION ELEMENTS
!                   IS PRESENTLY IMPRACTICAL AND UNLIKELY,
!                   THEN THERE IS NO PRACTICAL RESTRICTION
!                   ON THE MAXIMUM VALUE OF N FOR THIS SUBROUTINE.
!                   (IN LIGHT OF THE ABOVE, NO CHECK OF THE
!                   UPPER LIMIT OF N HAS BEEN INCORPORATED
!                   INTO THIS SUBROUTINE.)
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     COMMENT--THE SMALLEST ELEMENT OF THE VECTOR X
!              WILL BE PLACED IN THE FIRST POSITION
!              OF THE VECTOR XS,
!              THE SECOND SMALLEST ELEMENT IN THE VECTOR X
!              WILL BE PLACED IN THE SECOND POSITION
!              OF THE VECTOR XS,
!              ETC.
!     COMMENT--THE ELEMENT IN THE VECTOR Y CORRESPONDING
!              TO THE SMALLEST ELEMENT IN X
!              WILL BE PLACED IN THE FIRST POSITION
!              OF THE VECTOR YC,
!              THE ELEMENT IN THE VECTOR Y CORRESPONDING
!              TO THE SECOND SMALLEST ELEMENT IN X
!              WILL BE PLACED IN THE SECOND POSITION
!              OF THE VECTOR YC,
!              ETC.
!     COMMENT--THE INPUT VECTOR X REMAINS UNALTERED.
!     COMMENT--IF THE ANALYST DESIRES A SORT 'IN PLACE',
!              THIS IS DONE BY HAVING THE SAME
!              OUTPUT VECTOR AS INPUT VECTOR IN THE CALLING SEQUENCE.
!              THUS, FOR EXAMPLE, THE CALLING SEQUENCE
!              CALL SORTC(X,Y,N,X,YC)
!              IS ALLOWABLE AND WILL RESULT IN
!              THE DESIRED 'IN-PLACE' SORT.
!     COMMENT--THE SORTING ALGORTHM USED HEREIN
!              IS THE BINARY SORT.
!              THIS ALGORTHIM IS EXTREMELY FAST AS THE
!              FOLLOWING TIME TRIALS INDICATE.
!              THESE TIME TRIALS WERE CARRIED OUT ON THE
!              UNIVAC 1108 EXEC 8 SYSTEM AT NBS
!              IN AUGUST OF 1974.
!              BY WAY OF COMPARISON, THE TIME TRIAL VALUES
!              FOR THE EASY-TO-PROGRAM BUT EXTREMELY
!              INEFFICIENT BUBBLE SORT ALGORITHM HAVE
!              ALSO BEEN INCLUDED--
!              NUMBER OF RANDOM        BINARY SORT       BUBBLE SORT
!               NUMBERS SORTED
!                N = 10                 .002 SEC          .002 SEC
!                N = 100                .011 SEC          .045 SEC
!                N = 1000               .141 SEC         4.332 SEC
!                N = 3000               .476 SEC        37.683 SEC
!                N = 10000             1.887 SEC      NOT COMPUTED
!     REFERENCES--CACM MARCH 1969, PAGE 186 (BINARY SORT ALGORITHM
!                 BY RICHARD C. SINGLETON).
!               --CACM JANUARY 1970, PAGE 54.
!               --CACM OCTOBER 1970, PAGE 624.
!               --JACM JANUARY 1961, PAGE 41.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--JUNE      1972.
!     UPDATED         --NOVEMBER  1975.
!     UPDATED         --JUNE      1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*),Y(*),XS(*),YC(*)
      DIMENSION IU(36),IL(36)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO SORTC ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
   47   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(N.EQ.1)THEN
        XS(1)=X(1)
        YC(1)=Y(1)
        GO TO 9000
      ENDIF
!
!     COPY THE VECTOR X INTO THE VECTOR XS AND THE VECTOR Y INTO YC
!
      DO 100 I=1,N
        XS(I)=X(I)
        YC(I)=Y(I)
  100 CONTINUE
!
!     CHECK TO SEE IF THE INPUT VECTOR IS ALREADY SORTED
!
      NM1=N-1
      DO 200 I=1,NM1
      IP1=I+1
      IF(XS(I).LE.XS(IP1))GO TO 200
      GO TO 250
  200 CONTINUE
      GO TO 9000
  250 M=1
      I=1
      J=N
  305 IF(I.GE.J)GO TO 370
  310 K=I
      MID=(I+J)/2
      AMED=XS(MID)
      BMED=YC(MID)
      IF(XS(I).LE.AMED)GO TO 320
      XS(MID)=XS(I)
      YC(MID)=YC(I)
      XS(I)=AMED
      YC(I)=BMED
      AMED=XS(MID)
      BMED=YC(MID)
  320 L=J
      IF(XS(J).GE.AMED)GO TO 340
      XS(MID)=XS(J)
      YC(MID)=YC(J)
      XS(J)=AMED
      YC(J)=BMED
      AMED=XS(MID)
      BMED=YC(MID)
      IF(XS(I).LE.AMED)GO TO 340
      XS(MID)=XS(I)
      YC(MID)=YC(I)
      XS(I)=AMED
      YC(I)=BMED
      AMED=XS(MID)
      BMED=YC(MID)
      GO TO 340
  330 XS(L)=XS(K)
      YC(L)=YC(K)
      XS(K)=TX
      YC(K)=TY
  340 L=L-1
      IF(XS(L).GT.AMED)GO TO 340
      TX=XS(L)
      TY=YC(L)
  350 K=K+1
      IF(XS(K).LT.AMED)GO TO 350
      IF(K.LE.L)GO TO 330
      LMI=L-I
      JMK=J-K
      IF(LMI.LE.JMK)GO TO 360
      IL(M)=I
      IU(M)=L
      I=K
      M=M+1
      GO TO 380
  360 IL(M)=K
      IU(M)=J
      J=L
      M=M+1
      GO TO 380
  370 M=M-1
      IF(M.EQ.0)GO TO 9000
      I=IL(M)
      J=IU(M)
  380 JMI=J-I
      IF(JMI.GE.11)GO TO 310
      IF(I.EQ.1)GO TO 305
      I=I-1
  390 I=I+1
      IF(I.EQ.J)GO TO 370
      AMED=XS(I+1)
      BMED=YC(I+1)
      IF(XS(I).LE.AMED)GO TO 390
      K=I
  395 XS(K+1)=XS(K)
      YC(K+1)=YC(K)
      K=K-1
      IF(AMED.LT.XS(K))GO TO 395
      XS(K+1)=AMED
      YC(K+1)=BMED
      GO TO 390
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE SORTC
      SUBROUTINE SORTC3(X,Y,N,XS,YC)
!
!     PURPOSE--THIS SUBROUTINE SORTS (IN ASCENDING ORDER)
!              THE N ELEMENTS OF THE SINGLE PRECISION VECTOR X,
!              PUTS THE RESULTING N SORTED VALUES INTO THE
!              SINGLE PRECISION VECTOR XS,
!              REARRANGES THE ELEMENTS OF THE VECTOR Y
!              (ACCORDING TO THE SORT ON X),
!              AND PUTS THE REARRANGED Y VALUES
!              INTO THE SINGLE PRECISION VECTOR YC.
!              THIS SUBROUTINE GIVES THE DATA ANALYST
!              THE ABILITY TO SORT ONE DATA VECTOR
!              WHILE 'CARRYING ALONG' THE ELEMENTS
!              OF A SECOND DATA VECTOR.
!
!              NOTE: THIS IS A COPY OF SORTC WHERE THE Y AND
!                    YC ARRAYS ARE INTEGER RATHER THAN REAL.
!                    USE THIS TO AVOID WARNING MESSAGES ON THE
!                    COMPILE.
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                OBSERVATIONS TO BE SORTED.
!                     --Y      = THE SINGLE PRECISION VECTOR OF
!                                OBSERVATIONS TO BE 'CARRIED ALONG',
!                                THAT IS, TO BE REARRANGED ACCORDING
!                                TO THE SORT ON X.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XS     = THE SINGLE PRECISION VECTOR
!                                INTO WHICH THE SORTED DATA VALUES
!                                FROM X WILL BE PLACED.
!                     --YC     = THE SINGLE PRECISION VECTOR
!                                INTO WHICH THE REARRANGED
!                                (ACCORDING TO THE SORT OF THE
!                                VECTOR X) VALUES OF THE VECTOR Y
!                                WILL BE PLACED.
!     OUTPUT--THE SINGLE PRECISION VECTOR XS
!             CONTAINING THE SORTED
!             (IN ASCENDING ORDER) VALUES
!             OF THE SINGLE PRECISION VECTOR X, AND
!             THE SINGLE PRECISION VECTOR YC
!             CONTAINING THE REARRANGED
!             (ACCORDING TO THE SORT ON X)
!             VALUES OF THE VECTOR Y.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THE DIMENSIONS OF THE VECTORS IL AND IU
!                   (DEFINED AND USED INTERNALLY WITHIN
!                   THIS SUBROUTINE) DICTATE THE MAXIMUM
!                   ALLOWABLE VALUE OF N FOR THIS SUBROUTINE.
!                   IF IL AND IU EACH HAVE DIMENSION K,
!                   THEN N MAY NOT EXCEED 2**(K+1) - 1.
!                   FOR THIS SUBROUTINE AS WRITTEN, THE DIMENSIONS
!                   OF IL AND IU HAVE BEEN SET TO 36,
!                   THUS THE MAXIMUM ALLOWABLE VALUE OF N IS
!                   APPROXIMATELY 137 BILLION.
!                   SINCE THIS EXCEEDS THE MAXIMUM ALLOWABLE
!                   VALUE FOR AN INTEGER VARIABLE IN MANY COMPUTERS,
!                   AND SINCE A SORT OF 137 BILLION ELEMENTS
!                   IS PRESENTLY IMPRACTICAL AND UNLIKELY,
!                   THEN THERE IS NO PRACTICAL RESTRICTION
!                   ON THE MAXIMUM VALUE OF N FOR THIS SUBROUTINE.
!                   (IN LIGHT OF THE ABOVE, NO CHECK OF THE
!                   UPPER LIMIT OF N HAS BEEN INCORPORATED
!                   INTO THIS SUBROUTINE.)
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     COMMENT--THE SMALLEST ELEMENT OF THE VECTOR X
!              WILL BE PLACED IN THE FIRST POSITION
!              OF THE VECTOR XS,
!              THE SECOND SMALLEST ELEMENT IN THE VECTOR X
!              WILL BE PLACED IN THE SECOND POSITION
!              OF THE VECTOR XS,
!              ETC.
!     COMMENT--THE ELEMENT IN THE VECTOR Y CORRESPONDING
!              TO THE SMALLEST ELEMENT IN X
!              WILL BE PLACED IN THE FIRST POSITION
!              OF THE VECTOR YC,
!              THE ELEMENT IN THE VECTOR Y CORRESPONDING
!              TO THE SECOND SMALLEST ELEMENT IN X
!              WILL BE PLACED IN THE SECOND POSITION
!              OF THE VECTOR YC,
!              ETC.
!     COMMENT--THE INPUT VECTOR X REMAINS UNALTERED.
!     COMMENT--IF THE ANALYST DESIRES A SORT 'IN PLACE',
!              THIS IS DONE BY HAVING THE SAME
!              OUTPUT VECTOR AS INPUT VECTOR IN THE CALLING SEQUENCE.
!              THUS, FOR EXAMPLE, THE CALLING SEQUENCE
!              CALL SORTC(X,Y,N,X,YC)
!              IS ALLOWABLE AND WILL RESULT IN
!              THE DESIRED 'IN-PLACE' SORT.
!     COMMENT--THE SORTING ALGORTHM USED HEREIN
!              IS THE BINARY SORT.
!              THIS ALGORTHIM IS EXTREMELY FAST AS THE
!              FOLLOWING TIME TRIALS INDICATE.
!              THESE TIME TRIALS WERE CARRIED OUT ON THE
!              UNIVAC 1108 EXEC 8 SYSTEM AT NBS
!              IN AUGUST OF 1974.
!              BY WAY OF COMPARISON, THE TIME TRIAL VALUES
!              FOR THE EASY-TO-PROGRAM BUT EXTREMELY
!              INEFFICIENT BUBBLE SORT ALGORITHM HAVE
!              ALSO BEEN INCLUDED--
!              NUMBER OF RANDOM        BINARY SORT       BUBBLE SORT
!               NUMBERS SORTED
!                N = 10                 .002 SEC          .002 SEC
!                N = 100                .011 SEC          .045 SEC
!                N = 1000               .141 SEC         4.332 SEC
!                N = 3000               .476 SEC        37.683 SEC
!                N = 10000             1.887 SEC      NOT COMPUTED
!     REFERENCES--CACM MARCH 1969, PAGE 186 (BINARY SORT ALGORITHM
!                 BY RICHARD C. SINGLETON).
!               --CACM JANUARY 1970, PAGE 54.
!               --CACM OCTOBER 1970, PAGE 624.
!               --JACM JANUARY 1961, PAGE 41.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--JUNE      1972.
!     UPDATED         --NOVEMBER  1975.
!     UPDATED         --JUNE      1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      REAL X(*),XS(*)
      INTEGER Y(*),YC(*)
      INTEGER BMED
      INTEGER TY
      DIMENSION IU(36),IL(36)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO SORTC ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
   47   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(N.EQ.1)THEN
        XS(1)=X(1)
        YC(1)=Y(1)
        GO TO 9000
      ENDIF
!
      HOLD=X(1)
      DO 60 I=2,N
        IF(X(I).NE.HOLD)GO TO 90
   60 CONTINUE
      DO 61 I=1,N
        XS(I)=X(I)
        YC(I)=Y(I)
   61 CONTINUE
      GO TO 9000
!
   90 CONTINUE
!
!     COPY THE VECTOR X INTO THE VECTOR XS AND THE VECTOR Y INTO YS
!
      DO 100 I=1,N
        XS(I)=X(I)
        YC(I)=Y(I)
  100 CONTINUE
!
!     CHECK TO SEE IF THE INPUT VECTOR IS ALREADY SORTED
!
      NM1=N-1
      DO 200 I=1,NM1
      IP1=I+1
      IF(XS(I).LE.XS(IP1))GO TO 200
      GO TO 250
  200 CONTINUE
      GO TO 9000
  250 M=1
      I=1
      J=N
  305 IF(I.GE.J)GO TO 370
  310 K=I
      MID=(I+J)/2
      AMED=XS(MID)
      BMED=YC(MID)
      IF(XS(I).LE.AMED)GO TO 320
      XS(MID)=XS(I)
      YC(MID)=YC(I)
      XS(I)=AMED
      YC(I)=BMED
      AMED=XS(MID)
      BMED=YC(MID)
  320 L=J
      IF(XS(J).GE.AMED)GO TO 340
      XS(MID)=XS(J)
      YC(MID)=YC(J)
      XS(J)=AMED
      YC(J)=BMED
      AMED=XS(MID)
      BMED=YC(MID)
      IF(XS(I).LE.AMED)GO TO 340
      XS(MID)=XS(I)
      YC(MID)=YC(I)
      XS(I)=AMED
      YC(I)=BMED
      AMED=XS(MID)
      BMED=YC(MID)
      GO TO 340
  330 XS(L)=XS(K)
      YC(L)=YC(K)
      XS(K)=TX
      YC(K)=TY
  340 L=L-1
      IF(XS(L).GT.AMED)GO TO 340
      TX=XS(L)
      TY=YC(L)
  350 K=K+1
      IF(XS(K).LT.AMED)GO TO 350
      IF(K.LE.L)GO TO 330
      LMI=L-I
      JMK=J-K
      IF(LMI.LE.JMK)GO TO 360
      IL(M)=I
      IU(M)=L
      I=K
      M=M+1
      GO TO 380
  360 IL(M)=K
      IU(M)=J
      J=L
      M=M+1
      GO TO 380
  370 M=M-1
      IF(M.EQ.0)GO TO 9000
      I=IL(M)
      J=IU(M)
  380 JMI=J-I
      IF(JMI.GE.11)GO TO 310
      IF(I.EQ.1)GO TO 305
      I=I-1
  390 I=I+1
      IF(I.EQ.J)GO TO 370
      AMED=XS(I+1)
      BMED=YC(I+1)
      IF(XS(I).LE.AMED)GO TO 390
      K=I
  395 XS(K+1)=XS(K)
      YC(K+1)=YC(K)
      K=K-1
      IF(AMED.LT.XS(K))GO TO 395
      XS(K+1)=AMED
      YC(K+1)=BMED
      GO TO 390
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE SORTC3
      SUBROUTINE SORTC4(X,Y,N,XS,YC)
!
!     PURPOSE--THIS SUBROUTINE SORTS (IN ASCENDING ORDER)
!              THE N ELEMENTS OF THE SINGLE PRECISION VECTOR X,
!              PUTS THE RESULTING N SORTED VALUES INTO THE
!              SINGLE PRECISION VECTOR XS,
!              REARRANGES THE ELEMENTS OF THE VECTOR Y
!              (ACCORDING TO THE SORT ON X),
!              AND PUTS THE REARRANGED Y VALUES
!              INTO THE SINGLE PRECISION VECTOR YC.
!              THIS SUBROUTINE GIVES THE DATA ANALYST
!              THE ABILITY TO SORT ONE DATA VECTOR
!              WHILE 'CARRYING ALONG' THE ELEMENTS
!              OF A SECOND DATA VECTOR.
!
!              NOTE: THIS IS A COPY OF SORTC WHERE THE X, Y, XS, AND
!                    YC ARRAYS ARE INTEGER RATHER THAN REAL.
!                    USE THIS TO AVOID WARNING MESSAGES ON THE
!                    COMPILE.
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                OBSERVATIONS TO BE SORTED.
!                     --Y      = THE SINGLE PRECISION VECTOR OF
!                                OBSERVATIONS TO BE 'CARRIED ALONG',
!                                THAT IS, TO BE REARRANGED ACCORDING
!                                TO THE SORT ON X.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XS     = THE SINGLE PRECISION VECTOR
!                                INTO WHICH THE SORTED DATA VALUES
!                                FROM X WILL BE PLACED.
!                     --YC     = THE SINGLE PRECISION VECTOR
!                                INTO WHICH THE REARRANGED
!                                (ACCORDING TO THE SORT OF THE
!                                VECTOR X) VALUES OF THE VECTOR Y
!                                WILL BE PLACED.
!     OUTPUT--THE SINGLE PRECISION VECTOR XS
!             CONTAINING THE SORTED
!             (IN ASCENDING ORDER) VALUES
!             OF THE SINGLE PRECISION VECTOR X, AND
!             THE SINGLE PRECISION VECTOR YC
!             CONTAINING THE REARRANGED
!             (ACCORDING TO THE SORT ON X)
!             VALUES OF THE VECTOR Y.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THE DIMENSIONS OF THE VECTORS IL AND IU
!                   (DEFINED AND USED INTERNALLY WITHIN
!                   THIS SUBROUTINE) DICTATE THE MAXIMUM
!                   ALLOWABLE VALUE OF N FOR THIS SUBROUTINE.
!                   IF IL AND IU EACH HAVE DIMENSION K,
!                   THEN N MAY NOT EXCEED 2**(K+1) - 1.
!                   FOR THIS SUBROUTINE AS WRITTEN, THE DIMENSIONS
!                   OF IL AND IU HAVE BEEN SET TO 36,
!                   THUS THE MAXIMUM ALLOWABLE VALUE OF N IS
!                   APPROXIMATELY 137 BILLION.
!                   SINCE THIS EXCEEDS THE MAXIMUM ALLOWABLE
!                   VALUE FOR AN INTEGER VARIABLE IN MANY COMPUTERS,
!                   AND SINCE A SORT OF 137 BILLION ELEMENTS
!                   IS PRESENTLY IMPRACTICAL AND UNLIKELY,
!                   THEN THERE IS NO PRACTICAL RESTRICTION
!                   ON THE MAXIMUM VALUE OF N FOR THIS SUBROUTINE.
!                   (IN LIGHT OF THE ABOVE, NO CHECK OF THE
!                   UPPER LIMIT OF N HAS BEEN INCORPORATED
!                   INTO THIS SUBROUTINE.)
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     COMMENT--THE SMALLEST ELEMENT OF THE VECTOR X
!              WILL BE PLACED IN THE FIRST POSITION
!              OF THE VECTOR XS,
!              THE SECOND SMALLEST ELEMENT IN THE VECTOR X
!              WILL BE PLACED IN THE SECOND POSITION
!              OF THE VECTOR XS,
!              ETC.
!     COMMENT--THE ELEMENT IN THE VECTOR Y CORRESPONDING
!              TO THE SMALLEST ELEMENT IN X
!              WILL BE PLACED IN THE FIRST POSITION
!              OF THE VECTOR YC,
!              THE ELEMENT IN THE VECTOR Y CORRESPONDING
!              TO THE SECOND SMALLEST ELEMENT IN X
!              WILL BE PLACED IN THE SECOND POSITION
!              OF THE VECTOR YC,
!              ETC.
!     COMMENT--THE INPUT VECTOR X REMAINS UNALTERED.
!     COMMENT--IF THE ANALYST DESIRES A SORT 'IN PLACE',
!              THIS IS DONE BY HAVING THE SAME
!              OUTPUT VECTOR AS INPUT VECTOR IN THE CALLING SEQUENCE.
!              THUS, FOR EXAMPLE, THE CALLING SEQUENCE
!              CALL SORTC(X,Y,N,X,YC)
!              IS ALLOWABLE AND WILL RESULT IN
!              THE DESIRED 'IN-PLACE' SORT.
!     COMMENT--THE SORTING ALGORTHM USED HEREIN
!              IS THE BINARY SORT.
!              THIS ALGORTHIM IS EXTREMELY FAST AS THE
!              FOLLOWING TIME TRIALS INDICATE.
!              THESE TIME TRIALS WERE CARRIED OUT ON THE
!              UNIVAC 1108 EXEC 8 SYSTEM AT NBS
!              IN AUGUST OF 1974.
!              BY WAY OF COMPARISON, THE TIME TRIAL VALUES
!              FOR THE EASY-TO-PROGRAM BUT EXTREMELY
!              INEFFICIENT BUBBLE SORT ALGORITHM HAVE
!              ALSO BEEN INCLUDED--
!              NUMBER OF RANDOM        BINARY SORT       BUBBLE SORT
!               NUMBERS SORTED
!                N = 10                 .002 SEC          .002 SEC
!                N = 100                .011 SEC          .045 SEC
!                N = 1000               .141 SEC         4.332 SEC
!                N = 3000               .476 SEC        37.683 SEC
!                N = 10000             1.887 SEC      NOT COMPUTED
!     REFERENCES--CACM MARCH 1969, PAGE 186 (BINARY SORT ALGORITHM
!                 BY RICHARD C. SINGLETON).
!               --CACM JANUARY 1970, PAGE 54.
!               --CACM OCTOBER 1970, PAGE 624.
!               --JACM JANUARY 1961, PAGE 41.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--JUNE      1972.
!     UPDATED         --NOVEMBER  1975.
!     UPDATED         --JUNE      1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      INTEGER X(*),XS(*)
      INTEGER Y(*),YC(*)
      INTEGER BMED
      INTEGER AMED
      INTEGER HOLD
      INTEGER TX
      INTEGER TY
      DIMENSION IU(36),IL(36)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO ',   &
               'SORTC IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
   47   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        RETURN
      ELSEIF(N.EQ.1)THEN
!CCCC   WRITE(ICOUT,18)
!CC18   FORMAT('***** WARNING--THE THIRD ARGUMENT ',
!CCCC1         'TO SORTC HAS THE VALUE 1')
!CCCC   CALL DPWRST('XXX','BUG ')
        XS(1)=X(1)
        YC(1)=Y(1)
        RETURN
      ENDIF
!
      HOLD=X(1)
      DO 60 I=2,N
        IF(X(I).NE.HOLD)GO TO 90
   60 CONTINUE
!CCCC WRITE(ICOUT, 9)HOLD
!CCC9 FORMAT('***** WARNING--THE FIRST ARGUMENT ',
!CCCC1       '(A VECTOR) TO SORTC HAS ALL ELEMENTS = ',G15.7)
!CCCC CALL DPWRST('XXX','BUG ')
      DO 61 I=1,N
        XS(I)=X(I)
        YC(I)=Y(I)
   61 CONTINUE
      RETURN
!
   90 CONTINUE
!     COPY THE VECTOR X INTO THE VECTOR XS
      DO 100 I=1,N
      XS(I)=X(I)
  100 CONTINUE
!
!     COPY THE VECTOR Y INTO THE VECTOR YS
!
      DO 150 I=1,N
      YC(I)=Y(I)
  150 CONTINUE
!
!     CHECK TO SEE IF THE INPUT VECTOR IS ALREADY SORTED
!
      NM1=N-1
      DO 200 I=1,NM1
      IP1=I+1
      IF(XS(I).LE.XS(IP1))GO TO 200
      GO TO 250
  200 CONTINUE
      RETURN
  250 M=1
      I=1
      J=N
  305 IF(I.GE.J)GO TO 370
  310 K=I
      MID=(I+J)/2
      AMED=XS(MID)
      BMED=YC(MID)
      IF(XS(I).LE.AMED)GO TO 320
      XS(MID)=XS(I)
      YC(MID)=YC(I)
      XS(I)=AMED
      YC(I)=BMED
      AMED=XS(MID)
      BMED=YC(MID)
  320 L=J
      IF(XS(J).GE.AMED)GO TO 340
      XS(MID)=XS(J)
      YC(MID)=YC(J)
      XS(J)=AMED
      YC(J)=BMED
      AMED=XS(MID)
      BMED=YC(MID)
      IF(XS(I).LE.AMED)GO TO 340
      XS(MID)=XS(I)
      YC(MID)=YC(I)
      XS(I)=AMED
      YC(I)=BMED
      AMED=XS(MID)
      BMED=YC(MID)
      GO TO 340
  330 XS(L)=XS(K)
      YC(L)=YC(K)
      XS(K)=TX
      YC(K)=TY
  340 L=L-1
      IF(XS(L).GT.AMED)GO TO 340
      TX=XS(L)
      TY=YC(L)
  350 K=K+1
      IF(XS(K).LT.AMED)GO TO 350
      IF(K.LE.L)GO TO 330
      LMI=L-I
      JMK=J-K
      IF(LMI.LE.JMK)GO TO 360
      IL(M)=I
      IU(M)=L
      I=K
      M=M+1
      GO TO 380
  360 IL(M)=K
      IU(M)=J
      J=L
      M=M+1
      GO TO 380
  370 M=M-1
      IF(M.EQ.0)RETURN
      I=IL(M)
      J=IU(M)
  380 JMI=J-I
      IF(JMI.GE.11)GO TO 310
      IF(I.EQ.1)GO TO 305
      I=I-1
  390 I=I+1
      IF(I.EQ.J)GO TO 370
      AMED=XS(I+1)
      BMED=YC(I+1)
      IF(XS(I).LE.AMED)GO TO 390
      K=I
  395 XS(K+1)=XS(K)
      YC(K+1)=YC(K)
      K=K-1
      IF(AMED.LT.XS(K))GO TO 395
      XS(K+1)=AMED
      YC(K+1)=BMED
      GO TO 390
      END SUBROUTINE SORTC4
      SUBROUTINE SORTC5(X,Y,N,XS,YC)
!
!     PURPOSE--THIS SUBROUTINE SORTS (IN ASCENDING ORDER)
!              THE N ELEMENTS OF THE SINGLE PRECISION VECTOR X,
!              PUTS THE RESULTING N SORTED VALUES INTO THE
!              SINGLE PRECISION VECTOR XS,
!              REARRANGES THE ELEMENTS OF THE VECTOR Y
!              (ACCORDING TO THE SORT ON X),
!              AND PUTS THE REARRANGED Y VALUES
!              INTO THE SINGLE PRECISION VECTOR YC.
!              THIS SUBROUTINE GIVES THE DATA ANALYST
!              THE ABILITY TO SORT ONE DATA VECTOR
!              WHILE 'CARRYING ALONG' THE ELEMENTS
!              OF A SECOND DATA VECTOR.
!
!              NOTE: THIS IS A COPY OF SORTC WHERE THE X AND
!                    XS ARRAYS ARE INTEGER RATHER THAN REAL.
!                    USE THIS TO AVOID WARNING MESSAGES ON THE
!                    COMPILE.
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                OBSERVATIONS TO BE SORTED.
!                     --Y      = THE SINGLE PRECISION VECTOR OF
!                                OBSERVATIONS TO BE 'CARRIED ALONG',
!                                THAT IS, TO BE REARRANGED ACCORDING
!                                TO THE SORT ON X.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XS     = THE SINGLE PRECISION VECTOR
!                                INTO WHICH THE SORTED DATA VALUES
!                                FROM X WILL BE PLACED.
!                     --YC     = THE SINGLE PRECISION VECTOR
!                                INTO WHICH THE REARRANGED
!                                (ACCORDING TO THE SORT OF THE
!                                VECTOR X) VALUES OF THE VECTOR Y
!                                WILL BE PLACED.
!     OUTPUT--THE SINGLE PRECISION VECTOR XS
!             CONTAINING THE SORTED
!             (IN ASCENDING ORDER) VALUES
!             OF THE SINGLE PRECISION VECTOR X, AND
!             THE SINGLE PRECISION VECTOR YC
!             CONTAINING THE REARRANGED
!             (ACCORDING TO THE SORT ON X)
!             VALUES OF THE VECTOR Y.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THE DIMENSIONS OF THE VECTORS IL AND IU
!                   (DEFINED AND USED INTERNALLY WITHIN
!                   THIS SUBROUTINE) DICTATE THE MAXIMUM
!                   ALLOWABLE VALUE OF N FOR THIS SUBROUTINE.
!                   IF IL AND IU EACH HAVE DIMENSION K,
!                   THEN N MAY NOT EXCEED 2**(K+1) - 1.
!                   FOR THIS SUBROUTINE AS WRITTEN, THE DIMENSIONS
!                   OF IL AND IU HAVE BEEN SET TO 36,
!                   THUS THE MAXIMUM ALLOWABLE VALUE OF N IS
!                   APPROXIMATELY 137 BILLION.
!                   SINCE THIS EXCEEDS THE MAXIMUM ALLOWABLE
!                   VALUE FOR AN INTEGER VARIABLE IN MANY COMPUTERS,
!                   AND SINCE A SORT OF 137 BILLION ELEMENTS
!                   IS PRESENTLY IMPRACTICAL AND UNLIKELY,
!                   THEN THERE IS NO PRACTICAL RESTRICTION
!                   ON THE MAXIMUM VALUE OF N FOR THIS SUBROUTINE.
!                   (IN LIGHT OF THE ABOVE, NO CHECK OF THE
!                   UPPER LIMIT OF N HAS BEEN INCORPORATED
!                   INTO THIS SUBROUTINE.)
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     COMMENT--THE SMALLEST ELEMENT OF THE VECTOR X
!              WILL BE PLACED IN THE FIRST POSITION
!              OF THE VECTOR XS,
!              THE SECOND SMALLEST ELEMENT IN THE VECTOR X
!              WILL BE PLACED IN THE SECOND POSITION
!              OF THE VECTOR XS,
!              ETC.
!     COMMENT--THE ELEMENT IN THE VECTOR Y CORRESPONDING
!              TO THE SMALLEST ELEMENT IN X
!              WILL BE PLACED IN THE FIRST POSITION
!              OF THE VECTOR YC,
!              THE ELEMENT IN THE VECTOR Y CORRESPONDING
!              TO THE SECOND SMALLEST ELEMENT IN X
!              WILL BE PLACED IN THE SECOND POSITION
!              OF THE VECTOR YC,
!              ETC.
!     COMMENT--THE INPUT VECTOR X REMAINS UNALTERED.
!     COMMENT--IF THE ANALYST DESIRES A SORT 'IN PLACE',
!              THIS IS DONE BY HAVING THE SAME
!              OUTPUT VECTOR AS INPUT VECTOR IN THE CALLING SEQUENCE.
!              THUS, FOR EXAMPLE, THE CALLING SEQUENCE
!              CALL SORTC(X,Y,N,X,YC)
!              IS ALLOWABLE AND WILL RESULT IN
!              THE DESIRED 'IN-PLACE' SORT.
!     COMMENT--THE SORTING ALGORTHM USED HEREIN
!              IS THE BINARY SORT.
!              THIS ALGORTHIM IS EXTREMELY FAST AS THE
!              FOLLOWING TIME TRIALS INDICATE.
!              THESE TIME TRIALS WERE CARRIED OUT ON THE
!              UNIVAC 1108 EXEC 8 SYSTEM AT NBS
!              IN AUGUST OF 1974.
!              BY WAY OF COMPARISON, THE TIME TRIAL VALUES
!              FOR THE EASY-TO-PROGRAM BUT EXTREMELY
!              INEFFICIENT BUBBLE SORT ALGORITHM HAVE
!              ALSO BEEN INCLUDED--
!              NUMBER OF RANDOM        BINARY SORT       BUBBLE SORT
!               NUMBERS SORTED
!                N = 10                 .002 SEC          .002 SEC
!                N = 100                .011 SEC          .045 SEC
!                N = 1000               .141 SEC         4.332 SEC
!                N = 3000               .476 SEC        37.683 SEC
!                N = 10000             1.887 SEC      NOT COMPUTED
!     REFERENCES--CACM MARCH 1969, PAGE 186 (BINARY SORT ALGORITHM
!                 BY RICHARD C. SINGLETON).
!               --CACM JANUARY 1970, PAGE 54.
!               --CACM OCTOBER 1970, PAGE 624.
!               --JACM JANUARY 1961, PAGE 41.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--JUNE      1972.
!     UPDATED         --NOVEMBER  1975.
!     UPDATED         --JUNE      1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      INTEGER X(*),XS(*)
      REAL Y(*),YC(*)
!CCCC INTEGER BMED
      DIMENSION IU(36),IL(36)
!
      INTEGER HOLD
      INTEGER AMED
      INTEGER TX
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO SORTC5 ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
   47   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        RETURN
      ELSEIF(N.EQ.1)THEN
!CCCC   WRITE(ICOUT,18)
!CC18 FORMAT('***** WARNING--THE SECOND ARGUMENT ',
!CCCC1       'TO SORTC5 HAS THE VALUE 1.')
!CCCC   CALL DPWRST('XXX','BUG ')
        XS(1)=X(1)
        YC(1)=Y(1)
        RETURN
      ENDIF
!
      HOLD=X(1)
      DO 60 I=2,N
        IF(X(I).NE.HOLD)GO TO 90
   60 CONTINUE
!CCCC WRITE(ICOUT, 9)HOLD
!CCC9 FORMAT('***** NON-FATAL DIAGNOSTIC--THE 1ST INPUT ARGUMENT ',
!CCCC1'(A VECTOR) TO THE SORTC  SUBROUTINE HAS ALL ELEMENTS = ',E15.8)
!CCCC CALL DPWRST('XXX','BUG ')
      DO 61 I=1,N
        XS(I)=X(I)
        YC(I)=Y(I)
   61 CONTINUE
      RETURN
!
   90 CONTINUE
!     COPY THE VECTOR X INTO THE VECTOR XS
      DO 100 I=1,N
      XS(I)=X(I)
  100 CONTINUE
!
!     COPY THE VECTOR Y INTO THE VECTOR YS
!
      DO 150 I=1,N
      YC(I)=Y(I)
  150 CONTINUE
!
!     CHECK TO SEE IF THE INPUT VECTOR IS ALREADY SORTED
!
      NM1=N-1
      DO 200 I=1,NM1
      IP1=I+1
      IF(XS(I).LE.XS(IP1))GO TO 200
      GO TO 250
  200 CONTINUE
      RETURN
  250 M=1
      I=1
      J=N
  305 IF(I.GE.J)GO TO 370
  310 K=I
      MID=(I+J)/2
      AMED=XS(MID)
      BMED=YC(MID)
      IF(XS(I).LE.AMED)GO TO 320
      XS(MID)=XS(I)
      YC(MID)=YC(I)
      XS(I)=AMED
      YC(I)=BMED
      AMED=XS(MID)
      BMED=YC(MID)
  320 L=J
      IF(XS(J).GE.AMED)GO TO 340
      XS(MID)=XS(J)
      YC(MID)=YC(J)
      XS(J)=AMED
      YC(J)=BMED
      AMED=XS(MID)
      BMED=YC(MID)
      IF(XS(I).LE.AMED)GO TO 340
      XS(MID)=XS(I)
      YC(MID)=YC(I)
      XS(I)=AMED
      YC(I)=BMED
      AMED=XS(MID)
      BMED=YC(MID)
      GO TO 340
  330 XS(L)=XS(K)
      YC(L)=YC(K)
      XS(K)=TX
      YC(K)=TY
  340 L=L-1
      IF(XS(L).GT.AMED)GO TO 340
      TX=XS(L)
      TY=YC(L)
  350 K=K+1
      IF(XS(K).LT.AMED)GO TO 350
      IF(K.LE.L)GO TO 330
      LMI=L-I
      JMK=J-K
      IF(LMI.LE.JMK)GO TO 360
      IL(M)=I
      IU(M)=L
      I=K
      M=M+1
      GO TO 380
  360 IL(M)=K
      IU(M)=J
      J=L
      M=M+1
      GO TO 380
  370 M=M-1
      IF(M.EQ.0)RETURN
      I=IL(M)
      J=IU(M)
  380 JMI=J-I
      IF(JMI.GE.11)GO TO 310
      IF(I.EQ.1)GO TO 305
      I=I-1
  390 I=I+1
      IF(I.EQ.J)GO TO 370
      AMED=XS(I+1)
      BMED=YC(I+1)
      IF(XS(I).LE.AMED)GO TO 390
      K=I
  395 XS(K+1)=XS(K)
      YC(K+1)=YC(K)
      K=K-1
      IF(AMED.LT.XS(K))GO TO 395
      XS(K+1)=AMED
      YC(K+1)=BMED
      GO TO 390
      END SUBROUTINE SORTC5
      SUBROUTINE SORTDE(X,N,Y)
!
!     PURPOSE--THIS SUBROUTINE SORTS (IN DESCENDING ORDER)
!              THE N ELEMENTS OF THE SINGLE PRECISION VECTOR X
!              AND PUTS THE RESULTING N SORTED VALUES INTO THE
!              SINGLE PRECISION VECTOR Y.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                OBSERVATIONS TO BE SORTED.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--Y      = THE SINGLE PRECISION VECTOR
!                                INTO WHICH THE SORTED DATA VALUES
!                                FROM X WILL BE PLACED.
!     OUTPUT--THE SINGLE PRECISION VECTOR Y
!             CONTAINING THE SORTED
!             (IN ASCENDING ORDER) VALUES
!             OF THE SINGLE PRECISION VECTOR X.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THE DIMENSIONS OF THE VECTORS IL AND IU
!                   (DEFINED AND USED INTERNALLY WITHIN
!                   THIS SUBROUTINE) DICTATE THE MAXIMUM
!                   ALLOWABLE VALUE OF N FOR THIS SUBROUTINE.
!                   IF IL AND IU EACH HAVE DIMENSION K,
!                   THEN N MAY NOT EXCEED 2**(K+1) - 1.
!                   FOR THIS SUBROUTINE AS WRITTEN, THE DIMENSIONS
!                   OF IL AND IU HAVE BEEN SET TO 36,
!                   THUS THE MAXIMUM ALLOWABLE VALUE OF N IS
!                   APPROXIMATELY 137 BILLION.
!                   SINCE THIS EXCEEDS THE MAXIMUM ALLOWABLE
!                   VALUE FOR AN INTEGER VARIABLE IN MANY COMPUTERS,
!                   AND SINCE A SORT OF 137 BILLION ELEMENTS
!                   IS PRESENTLY IMPRACTICAL AND UNLIKELY,
!                   THEN THERE IS NO PRACTICAL RESTRICTION
!                   ON THE MAXIMUM VALUE OF N FOR THIS SUBROUTINE.
!                   (IN LIGHT OF THE ABOVE, NO CHECK OF THE
!                   UPPER LIMIT OF N HAS BEEN INCORPORATED
!                   INTO THIS SUBROUTINE.)
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     COMMENT--THE SMALLEST ELEMENT OF THE VECTOR X
!              WILL BE PLACED IN THE FIRST POSITION
!              OF THE VECTOR Y,
!              THE SECOND SMALLEST ELEMENT IN THE VECTOR X
!              WILL BE PLACED IN THE SECOND POSITION
!              OF THE VECTOR Y, ETC.
!     COMMENT--THE INPUT VECTOR X REMAINS UNALTERED.
!     COMMENT--IF THE ANALYST DESIRES A SORT 'IN PLACE',
!              THIS IS DONE BY HAVING THE SAME
!              OUTPUT VECTOR AS INPUT VECTOR IN THE CALLING SEQUENCE.
!              THUS, FOR EXAMPLE, THE CALLING SEQUENCE
!              CALL SORT(X,N,X)
!              IS ALLOWABLE AND WILL RESULT IN
!              THE DESIRED 'IN-PLACE' SORT.
!     COMMENT--THE SORTING ALGORTHM USED HEREIN
!              IS THE  QUICKSORT.
!              THIS ALGORTHIM IS EXTREMELY FAST AS THE
!              FOLLOWING TIME TRIALS INDICATE.
!              THESE TIME TRIALS WERE CARRIED OUT ON THE
!              UNIVAC 1108 EXEC 8 SYSTEM AT NBS
!              IN AUGUST OF 1974.
!              BY WAY OF COMPARISON, THE TIME TRIAL VALUES
!              FOR THE EASY-TO-PROGRAM BUT EXTREMELY
!              INEFFICIENT BUBBLE SORT ALGORITHM HAVE
!              ALSO BEEN INCLUDED--
!              NUMBER OF RANDOM         QUICKSORT       BUBBLE SORT
!               NUMBERS SORTED
!                N = 10                 .002 SEC          .002 SEC
!                N = 100                .011 SEC          .045 SEC
!                N = 1000               .141 SEC         4.332 SEC
!                N = 3000               .476 SEC        37.683 SEC
!                N = 10000             1.887 SEC      NOT COMPUTED
!     REFERENCES--CACM MARCH 1969, PAGE 186 ( QUICKSORT ALGORITHM
!                 BY RICHARD C. SINGLETON).
!               --CACM JANUARY 1970, PAGE 54.
!               --CACM OCTOBER 1970, PAGE 624.
!               --JACM JANUARY 1961, PAGE 41.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--88.9
!     ORIGINAL VERSION--AUGUST    1988.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(*)
!
      DIMENSION IU(36)
      DIMENSION IL(36)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='SORT'
      ISUBN2='DE  '
      IERROR='NO'
      IBUGA3='OFF'
!
      IF(IBUGA3.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF SORT--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGA3
   52 FORMAT('IBUGA3 = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)N
   53 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 55 I=1,N
      WRITE(ICOUT,56)I,X(I)
   56 FORMAT('I,X(I) = ',I8,E15.7)
      CALL DPWRST('XXX','BUG ')
   55 CONTINUE
   90 CONTINUE
!
!               ************************
!               **  SORT THE VALUES.  **
!               ************************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N.GE.1)GO TO 119
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,111)
  111 FORMAT('***** ERROR IN SORT--',   &
      'THE 2ND INPUT ARGUMENT (N) IS SMALLER THAN 1')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,118)N
  118 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
  119 CONTINUE
!
      IF(N.EQ.1)GO TO 120
      GO TO 129
  120 CONTINUE
!CCCC WRITE(ICOUT,999)
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,121)
!C121 FORMAT('***** WARNING IN SORT--THE SECOND ',
!CCCC1       'ARGUMENT (N) HAS THE VALUE 1.')
!CCCC CALL DPWRST('XXX','BUG ')
      Y(1)=X(1)
      GO TO 9000
  129 CONTINUE
!
      HOLD=X(1)
      DO 135 I=2,N
      IF(X(I).NE.HOLD)GO TO 139
  135 CONTINUE
!CCCC WRITE(ICOUT,999)
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,136)HOLD
!C136 FORMAT('***** WARNING IN SORT--THE FIRST ARGUMENT ',
!CCCC1       '(A VECTOR) HAS ALL ELEMENTS = ',G15.7)
!CCCC CALL DPWRST('XXX','BUG ')
      DO 137 I=1,N
      Y(I)=X(I)
  137 CONTINUE
      GO TO 9000
  139 CONTINUE
!
!               *******************************************
!               **  STEP 2--                             **
!               **  COPY THE VECTOR X INTO THE VECTOR Y  **
!               *******************************************
!
      DO 200 I=1,N
      Y(I)=X(I)
  200 CONTINUE
!
      DO 210 I=1,N
      Y(I)=(-Y(I))
  210 CONTINUE
!
!               **********************************************************
!               **  STEP 3--                                            **
!               **  CHECK TO SEE IF THE INPUT VECTOR IS ALREADY SORTED  **
!               **********************************************************
!
      NM1=N-1
      DO 250 I=1,NM1
      IP1=I+1
      IF(Y(I).LE.Y(IP1))GO TO 250
      GO TO 290
  250 CONTINUE
      GO TO 8000
  290 CONTINUE
!
!               ***************************
!               **  STEP 4--             **
!               **  CARRY OUT THE SORT.  **
!               ***************************
!
      M=1
      I=1
      J=N
  305 IF(I.GE.J)GO TO 370
  310 K=I
      MID=(I+J)/2
      AMED=Y(MID)
      IF(Y(I).LE.AMED)GO TO 320
      Y(MID)=Y(I)
      Y(I)=AMED
      AMED=Y(MID)
  320 L=J
      IF(Y(J).GE.AMED)GO TO 340
      Y(MID)=Y(J)
      Y(J)=AMED
      AMED=Y(MID)
      IF(Y(I).LE.AMED)GO TO 340
      Y(MID)=Y(I)
      Y(I)=AMED
      AMED=Y(MID)
      GO TO 340
  330 Y(L)=Y(K)
      Y(K)=TT
  340 L=L-1
      IF(Y(L).GT.AMED)GO TO 340
      TT=Y(L)
  350 K=K+1
      IF(Y(K).LT.AMED)GO TO 350
      IF(K.LE.L)GO TO 330
      LMI=L-I
      JMK=J-K
      IF(LMI.LE.JMK)GO TO 360
      IL(M)=I
      IU(M)=L
      I=K
      M=M+1
      GO TO 380
  360 IL(M)=K
      IU(M)=J
      J=L
      M=M+1
      GO TO 380
  370 M=M-1
      IF(M.EQ.0)GO TO 8000
      I=IL(M)
      J=IU(M)
  380 JMI=J-I
      IF(JMI.GE.11)GO TO 310
      IF(I.EQ.1)GO TO 305
      I=I-1
  390 I=I+1
      IF(I.EQ.J)GO TO 370
      AMED=Y(I+1)
      IF(Y(I).LE.AMED)GO TO 390
      K=I
  395 Y(K+1)=Y(K)
      K=K-1
      IF(AMED.LT.Y(K))GO TO 395
      Y(K+1)=AMED
      GO TO 390
!
 8000 CONTINUE
      DO 8100 I=1,N
      Y(I)=(-Y(I))
 8100 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF SORT--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGA3,IERROR
 9012 FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)N
 9013 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 9015 I=1,N
      WRITE(ICOUT,9016)I,X(I),Y(I)
 9016 FORMAT('I,X(I),Y(I) = ',I8,2E15.7)
      CALL DPWRST('XXX','BUG ')
 9015 CONTINUE
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE SORTDE
      SUBROUTINE SORTI(X,N,XS,AINDEX)
!
!     PURPOSE--THIS SUBROUTINE SORTS (IN ASCENDING ORDER)
!              THE N ELEMENTS OF THE SINGLE PRECISION VECTOR X,
!              PUTS THE RESULTING N SORTED VALUES INTO THE
!              SINGLE PRECISION VECTOR XS, AND
!              REARRANGES THE ELEMENTS 1, 2, ..., N OF VECTOR AINDEX
!              (ACCORDING TO THE SORT ON X).
!              THIS SUBROUTINE GIVES THE DATA ANALYST
!              THE ABILITY TO SORT ONE DATA VECTOR
!              WHILE DETERMINING THE POSITION INDEX
!              AFTER-THE-FACT, SO AS TO SUBSEQUENTLY
!              'CARRY ALONG' THE ELEMENTS
!              OF MANY OTHER DATA VECTORS (DONE ELSEWHERE).
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                OBSERVATIONS TO BE SORTED.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XS     = THE SINGLE PRECISION VECTOR
!                                INTO WHICH THE SORTED DATA VALUES
!                                FROM X WILL BE PLACED.
!                     --AINDEX = THE SINGLE PRECISION VECTOR
!                                INTO WHICH THE REARRANGED
!                                (ACCORDING TO THE SORT OF THE
!                                VECTOR X) VALUES OF 1, 2, ..., N
!                                WILL BE PLACED.
!     OUTPUT--THE SINGLE PRECISION VECTOR XS
!             CONTAINING THE SORTED
!             (IN ASCENDING ORDER) VALUES
!             OF THE SINGLE PRECISION VECTOR X, AND
!             THE SINGLE PRECISION VECTOR AINDEX
!             CONTAINING THE REARRANGED
!             (ACCORDING TO THE SORT ON X)
!             VALUES OF 1, 2, ..., N.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THE DIMENSIONS OF THE VECTORS IL AND IU
!                   (DEFINED AND USED INTERNALLY WITHIN
!                   THIS SUBROUTINE) DICTATE THE MAXIMUM
!                   ALLOWABLE VALUE OF N FOR THIS SUBROUTINE.
!                   IF IL AND IU EACH HAVE DIMENSION K,
!                   THEN N MAY NOT EXCEED 2**(K+1) - 1.
!                   FOR THIS SUBROUTINE AS WRITTEN, THE DIMENSIONS
!                   OF IL AND IU HAVE BEEN SET TO 36,
!                   THUS THE MAXIMUM ALLOWABLE VALUE OF N IS
!                   APPROXIMATELY 137 BILLION.
!                   SINCE THIS EXCEEDS THE MAXIMUM ALLOWABLE
!                   VALUE FOR AN INTEGER VARIABLE IN MANY COMPUTERS,
!                   AND SINCE A SORT OF 137 BILLION ELEMENTS
!                   IS PRESENTLY IMPRACTICAL AND UNLIKELY,
!                   THEN THERE IS NO PRACTICAL RESTRICTION
!                   ON THE MAXIMUM VALUE OF N FOR THIS SUBROUTINE.
!                   (IN LIGHT OF THE ABOVE, NO CHECK OF THE
!                   UPPER LIMIT OF N HAS BEEN INCORPORATED
!                   INTO THIS SUBROUTINE.)
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     COMMENT--THE SMALLEST ELEMENT OF THE VECTOR X
!              WILL BE PLACED IN THE FIRST POSITION
!              OF THE VECTOR XS,
!              THE SECOND SMALLEST ELEMENT IN THE VECTOR X
!              WILL BE PLACED IN THE SECOND POSITION
!              OF THE VECTOR XS,
!              ETC.
!     COMMENT--AT THE END, AINDEX(1) WILL CONTAIN TBE ORIGINAL
!              POSITION NUMBER WHERE THE SMALLEST VALUE OF X DID RESIDE.
!          AINDEX(2) WILL CONTAIN THE ORIGINAL
!          POSITION NUMBER WHERE THE SECOND SMALLEST VALUE OF X DID RESIDE.
!          AINDEX(N) WILL CONTAIN THE ORIGINAL
!          POSITION NUMBER WHERE THE LARGEST VALUE OF X DID RESIDE.
!     COMMENT--THE INPUT VECTOR X REMAINS UNALTERED.
!     COMMENT--IF THE ANALYST DESIRES A SORT 'IN PLACE',
!              THIS IS DONE BY HAVING THE SAME
!              OUTPUT VECTOR AS INPUT VECTOR IN THE CALLING SEQUENCE.
!              THUS, FOR EXAMPLE, THE CALLING SEQUENCE
!              CALL SORTI(X,N,X,AINDEX)
!              IS ALLOWABLE AND WILL RESULT IN
!              THE DESIRED 'IN-PLACE' SORT.
!     COMMENT--THE SORTING ALGORTHM USED HEREIN
!              IS THE BINARY SORT.
!              THIS ALGORTHIM IS EXTREMELY FAST AS THE
!              FOLLOWING TIME TRIALS INDICATE.
!              THESE TIME TRIALS WERE CARRIED OUT ON THE
!              UNIVAC 1108 EXEC 8 SYSTEM AT NBS
!              IN AUGUST OF 1974.
!              BY WAY OF COMPARISON, THE TIME TRIAL VALUES
!              FOR THE EASY-TO-PROGRAM BUT EXTREMELY
!              INEFFICIENT BUBBLE SORT ALGORITHM HAVE
!              ALSO BEEN INCLUDED--
!              NUMBER OF RANDOM        BINARY SORT       BUBBLE SORT
!               NUMBERS SORTED
!                N = 10                 .002 SEC          .002 SEC
!                N = 100                .011 SEC          .045 SEC
!                N = 1000               .141 SEC         4.332 SEC
!                N = 3000               .476 SEC        37.683 SEC
!                N = 10000             1.887 SEC      NOT COMPUTED
!     REFERENCES--CACM MARCH 1969, PAGE 186 (BINARY SORT ALGORITHM
!                 BY RICHARD C. SINGLETON).
!               --CACM JANUARY 1970, PAGE 54.
!               --CACM OCTOBER 1970, PAGE 624.
!               --JACM JANUARY 1961, PAGE 41.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--JUNE      1972.
!     UPDATED         --NOVEMBER  1975.
!     UPDATED         --JUNE      1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*),XS(*),AINDEX(*)
      DIMENSION IU(36),IL(36)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO SORTI ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
   47   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        RETURN
      ELSEIF(N.EQ.1)THEN
        XS(1)=X(1)
        AINDEX(1)=1
        RETURN
      ENDIF
!
      HOLD=X(1)
      DO 60 I=2,N
        IF(X(I).NE.HOLD)GO TO 90
   60 CONTINUE
      DO 61 I=1,N
        XS(I)=X(I)
        AINDEX(I)=I
   61 CONTINUE
      RETURN
!
   90 CONTINUE
!CCC9 FORMAT('***** WARNING--THE FIRST ARGUMENT (A VECTOR) TO ',
!CCCC1       'THE SORTI  SUBROUTINE HAS ALL ELEMENTS = ',G15.7)
!
      NTEMP=0
!
!     COPY THE VECTOR X INTO THE VECTOR XS
!
      DO 100 I=1,N
        XS(I)=X(I)
  100 CONTINUE
!
!     COPY THE VECTOR INDEX INTO THE VECTOR INDEXS
!
      DO 150 I=1,N
        AINDEX(I)=I
  150 CONTINUE
!
!     CHECK TO SEE IF THE INPUT VECTOR IS ALREADY SORTED
!
      NM1=N-1
      DO 200 I=1,NM1
      IP1=I+1
      IF(XS(I).LE.XS(IP1))GO TO 200
      GO TO 250
  200 CONTINUE
      RETURN
  250 M=1
      I=1
      J=N
  305 IF(I.GE.J)GO TO 370
  310 K=I
      MID=(I+J)/2
      AMED=XS(MID)
      BMED=AINDEX(MID)
      IF(XS(I).LE.AMED)GO TO 320
      XS(MID)=XS(I)
      AINDEX(MID)=AINDEX(I)
      XS(I)=AMED
      AINDEX(I)=BMED
      AMED=XS(MID)
      BMED=AINDEX(MID)
  320 L=J
      IF(XS(J).GE.AMED)GO TO 340
      XS(MID)=XS(J)
      AINDEX(MID)=AINDEX(J)
      XS(J)=AMED
      AINDEX(J)=BMED
      AMED=XS(MID)
      BMED=AINDEX(MID)
      IF(XS(I).LE.AMED)GO TO 340
      XS(MID)=XS(I)
      AINDEX(MID)=AINDEX(I)
      XS(I)=AMED
      AINDEX(I)=BMED
      AMED=XS(MID)
      BMED=AINDEX(MID)
      GO TO 340
  330 XS(L)=XS(K)
      AINDEX(L)=AINDEX(K)
      XS(K)=TX
      AINDEX(K)=TY
  340 L=L-1
      IF(XS(L).GT.AMED)GO TO 340
      TX=XS(L)
      TY=AINDEX(L)
  350 K=K+1
      IF(XS(K).LT.AMED)GO TO 350
      IF(K.LE.L)GO TO 330
      LMI=L-I
      JMK=J-K
      IF(LMI.LE.JMK)GO TO 360
      IL(M)=I
      IU(M)=L
      I=K
      M=M+1
      GO TO 380
  360 IL(M)=K
      IU(M)=J
      J=L
      M=M+1
      GO TO 380
  370 M=M-1
      IF(M.EQ.0)RETURN
      I=IL(M)
      J=IU(M)
  380 JMI=J-I
      IF(JMI.GE.11)GO TO 310
      IF(I.EQ.1)GO TO 305
      I=I-1
  390 I=I+1
      IF(I.EQ.J)GO TO 370
      AMED=XS(I+1)
      BMED=AINDEX(I+1)
      IF(XS(I).LE.AMED)GO TO 390
      K=I
  395 XS(K+1)=XS(K)
      AINDEX(K+1)=AINDEX(K)
      K=K-1
      IF(AMED.LT.XS(K))GO TO 395
      XS(K+1)=AMED
      AINDEX(K+1)=BMED
      GO TO 390
      END SUBROUTINE SORTI
      SUBROUTINE SORTII(X,N,XS,AINDEX)
!
!     PURPOSE--THIS SUBROUTINE SORTS (IN ASCENDING ORDER)
!              THE N ELEMENTS OF THE SINGLE PRECISION VECTOR X,
!              PUTS THE RESULTING N SORTED VALUES INTO THE
!              SINGLE PRECISION VECTOR XS, AND
!              REARRANGES THE ELEMENTS 1, 2, ..., N OF VECTOR AINDEX
!              (ACCORDING TO THE SORT ON X).
!              THIS SUBROUTINE GIVES THE DATA ANALYST
!              THE ABILITY TO SORT ONE DATA VECTOR
!              WHILE DETERMINING THE POSITION INDEX
!              AFTER-THE-FACT, SO AS TO SUBSEQUENTLY
!              'CARRY ALONG' THE ELEMENTS
!              OF MANY OTHER DATA VECTORS (DONE ELSEWHERE).
!
!              THIS ROUTINE IS IDENTICAL TO SORTII WITH THE
!              DIFFERENCE THAT THIS ROUTINE ASSUMES X, XS, AND
!              AINDEX ARE INTEGER RATHER THAN REAL.
!
!     INPUT  ARGUMENTS--X      = THE INTEGER VECTOR OF
!                                OBSERVATIONS TO BE SORTED.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XS     = THE INTEGER VECTOR
!                                INTO WHICH THE SORTED DATA VALUES
!                                FROM X WILL BE PLACED.
!                     --AINDEX = THE INTEGER VECTOR
!                                INTO WHICH THE REARRANGED
!                                (ACCORDING TO THE SORT OF THE
!                                VECTOR X) VALUES OF 1, 2, ..., N
!                                WILL BE PLACED.
!     OUTPUT--THE SINGLE PRECISION VECTOR XS
!             CONTAINING THE SORTED
!             (IN ASCENDING ORDER) VALUES
!             OF THE SINGLE PRECISION VECTOR X, AND
!             THE SINGLE PRECISION VECTOR AINDEX
!             CONTAINING THE REARRANGED
!             (ACCORDING TO THE SORT ON X)
!             VALUES OF 1, 2, ..., N.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THE DIMENSIONS OF THE VECTORS IL AND IU
!                   (DEFINED AND USED INTERNALLY WITHIN
!                   THIS SUBROUTINE) DICTATE THE MAXIMUM
!                   ALLOWABLE VALUE OF N FOR THIS SUBROUTINE.
!                   IF IL AND IU EACH HAVE DIMENSION K,
!                   THEN N MAY NOT EXCEED 2**(K+1) - 1.
!                   FOR THIS SUBROUTINE AS WRITTEN, THE DIMENSIONS
!                   OF IL AND IU HAVE BEEN SET TO 36,
!                   THUS THE MAXIMUM ALLOWABLE VALUE OF N IS
!                   APPROXIMATELY 137 BILLION.
!                   SINCE THIS EXCEEDS THE MAXIMUM ALLOWABLE
!                   VALUE FOR AN INTEGER VARIABLE IN MANY COMPUTERS,
!                   AND SINCE A SORT OF 137 BILLION ELEMENTS
!                   IS PRESENTLY IMPRACTICAL AND UNLIKELY,
!                   THEN THERE IS NO PRACTICAL RESTRICTION
!                   ON THE MAXIMUM VALUE OF N FOR THIS SUBROUTINE.
!                   (IN LIGHT OF THE ABOVE, NO CHECK OF THE
!                   UPPER LIMIT OF N HAS BEEN INCORPORATED
!                   INTO THIS SUBROUTINE.)
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     COMMENT--THE SMALLEST ELEMENT OF THE VECTOR X
!              WILL BE PLACED IN THE FIRST POSITION
!              OF THE VECTOR XS,
!              THE SECOND SMALLEST ELEMENT IN THE VECTOR X
!              WILL BE PLACED IN THE SECOND POSITION
!              OF THE VECTOR XS,
!              ETC.
!     COMMENT--AT THE END, AINDEX(1) WILL CONTAIN TBE ORIGINAL
!              POSITION NUMBER WHERE THE SMALLEST VALUE OF X DID RESIDE.
!          AINDEX(2) WILL CONTAIN THE ORIGINAL
!          POSITION NUMBER WHERE THE SECOND SMALLEST VALUE OF X DID RESIDE.
!          AINDEX(N) WILL CONTAIN THE ORIGINAL
!          POSITION NUMBER WHERE THE LARGEST VALUE OF X DID RESIDE.
!     COMMENT--THE INPUT VECTOR X REMAINS UNALTERED.
!     COMMENT--IF THE ANALYST DESIRES A SORT 'IN PLACE',
!              THIS IS DONE BY HAVING THE SAME
!              OUTPUT VECTOR AS INPUT VECTOR IN THE CALLING SEQUENCE.
!              THUS, FOR EXAMPLE, THE CALLING SEQUENCE
!              CALL SORTI(X,N,X,AINDEX)
!              IS ALLOWABLE AND WILL RESULT IN
!              THE DESIRED 'IN-PLACE' SORT.
!     COMMENT--THE SORTING ALGORTHM USED HEREIN
!              IS THE BINARY SORT.
!              THIS ALGORTHIM IS EXTREMELY FAST AS THE
!              FOLLOWING TIME TRIALS INDICATE.
!              THESE TIME TRIALS WERE CARRIED OUT ON THE
!              UNIVAC 1108 EXEC 8 SYSTEM AT NBS
!              IN AUGUST OF 1974.
!              BY WAY OF COMPARISON, THE TIME TRIAL VALUES
!              FOR THE EASY-TO-PROGRAM BUT EXTREMELY
!              INEFFICIENT BUBBLE SORT ALGORITHM HAVE
!              ALSO BEEN INCLUDED--
!              NUMBER OF RANDOM        BINARY SORT       BUBBLE SORT
!               NUMBERS SORTED
!                N = 10                 .002 SEC          .002 SEC
!                N = 100                .011 SEC          .045 SEC
!                N = 1000               .141 SEC         4.332 SEC
!                N = 3000               .476 SEC        37.683 SEC
!                N = 10000             1.887 SEC      NOT COMPUTED
!     REFERENCES--CACM MARCH 1969, PAGE 186 (BINARY SORT ALGORITHM
!                 BY RICHARD C. SINGLETON).
!               --CACM JANUARY 1970, PAGE 54.
!               --CACM OCTOBER 1970, PAGE 624.
!               --JACM JANUARY 1961, PAGE 41.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--JUNE      1972.
!     UPDATED         --NOVEMBER  1975.
!     UPDATED         --JUNE      1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      INTEGER X(*),XS(*),AINDEX(*)
      DIMENSION IU(36),IL(36)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO SORTII ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
   47   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        RETURN
      ELSEIF(N.EQ.1)THEN
!CCCC   WRITE(ICOUT,18)
!CC18   FORMAT('***** WARNING--THE SECOND ARGUMENT TO SORTII ',
!CCCC1         'HAS THE VALUE 1.')
!CCCC   CALL DPWRST('XXX','BUG ')
        XS(1)=X(1)
        AINDEX(1)=1
        RETURN
      ENDIF
!
      IHOLD=X(1)
      DO 60 I=2,N
        IF(X(I).NE.IHOLD)GO TO 90
   60 CONTINUE
      DO 61 I=1,N
        XS(I)=X(I)
        AINDEX(I)=I
   61 CONTINUE
      RETURN
   90 CONTINUE
!
!     COPY THE VECTOR X INTO THE VECTOR XS
      DO 100 I=1,N
        XS(I)=X(I)
  100 CONTINUE
!
!     COPY THE VECTOR INDEX INTO THE VECTOR INDEXS
!
      DO 150 I=1,N
        AINDEX(I)=I
  150 CONTINUE
!
!     CHECK TO SEE IF THE INPUT VECTOR IS ALREADY SORTED
!
      NM1=N-1
      DO 200 I=1,NM1
        IP1=I+1
        IF(XS(I).LE.XS(IP1))GO TO 200
        GO TO 250
  200 CONTINUE
      RETURN
  250 CONTINUE
      M=1
      I=1
      J=N
  305 CONTINUE
      IF(I.GE.J)GO TO 370
  310 CONTINUE
      K=I
      MID=(I+J)/2
      AMED=REAL(XS(MID))
      BMED=REAL(AINDEX(MID))
      IF(XS(I).LE.INT(AMED+0.1))GO TO 320
      XS(MID)=XS(I)
      AINDEX(MID)=AINDEX(I)
      XS(I)=INT(AMED+0.1)
      AINDEX(I)=INT(BMED+0.1)
      AMED=REAL(XS(MID))
      BMED=REAL(AINDEX(MID))
  320 L=J
      IF(XS(J).GE.INT(AMED+0.1))GO TO 340
      XS(MID)=XS(J)
      AINDEX(MID)=AINDEX(J)
      XS(J)=INT(AMED+0.1)
      AINDEX(J)=INT(BMED+0.1)
      AMED=REAL(XS(MID))
      BMED=REAL(AINDEX(MID))
      IF(XS(I).LE.INT(AMED+0.1))GO TO 340
      XS(MID)=XS(I)
      AINDEX(MID)=AINDEX(I)
      XS(I)=INT(AMED+0.1)
      AINDEX(I)=INT(BMED+0.1)
      AMED=REAL(XS(MID))
      BMED=REAL(AINDEX(MID))
      GO TO 340
  330 CONTINUE
      XS(L)=XS(K)
      AINDEX(L)=AINDEX(K)
      XS(K)=INT(TX+0.1)
      AINDEX(K)=INT(TY+0.1)
  340 CONTINUE
      L=L-1
      IF(XS(L).GT.INT(AMED+0.1))GO TO 340
      TX=REAL(XS(L))
      TY=REAL(AINDEX(L))
  350 CONTINUE
      K=K+1
      IF(XS(K).LT.INT(AMED+0.1))GO TO 350
      IF(K.LE.L)GO TO 330
      LMI=L-I
      JMK=J-K
      IF(LMI.LE.JMK)GO TO 360
      IL(M)=I
      IU(M)=L
      I=K
      M=M+1
      GO TO 380
  360 CONTINUE
      IL(M)=K
      IU(M)=J
      J=L
      M=M+1
      GO TO 380
  370 CONTINUE
      M=M-1
      IF(M.EQ.0)RETURN
      I=IL(M)
      J=IU(M)
  380 CONTINUE
      JMI=J-I
      IF(JMI.GE.11)GO TO 310
      IF(I.EQ.1)GO TO 305
      I=I-1
  390 CONTINUE
      I=I+1
      IF(I.EQ.J)GO TO 370
      AMED=REAL(XS(I+1))
      BMED=REAL(AINDEX(I+1))
      IF(XS(I).LE.INT(AMED+0.1))GO TO 390
      K=I
  395 CONTINUE
      XS(K+1)=XS(K)
      AINDEX(K+1)=AINDEX(K)
      K=K-1
      IF(INT(AMED+0.1).LT.XS(K))GO TO 395
      XS(K+1)=INT(AMED+0.1)
      AINDEX(K+1)=INT(BMED+0.1)
      GO TO 390
      END SUBROUTINE SORTII
      SUBROUTINE SORTSH(X, N)
!
!        ALGORITHM AS 304.8 APPL.STATIST. (1996), VOL.45, NO.3
!
!        Sorts the N values stored in array X in ascending order
!
!        DATAPLOT NOTE: THIS IS A UTILITY ROUTINE USED BY
!                       FISHER TWO SAMPLE RANDOMIZATION TEST
!
      INTEGER N
      REAL X(N)
!
      INTEGER I, J, INCR
      REAL TEMP
!
      INCR = 1
!
!        Loop : calculate the increment
!
   10 INCR = 3 * INCR + 1
      IF (INCR .LE. N) GO TO  10
                                                                                                                                  
!
!        Loop : Shell-Metzner sort
!
   20 INCR = INCR / 3
      I = INCR + 1
   30 IF (I .GT. N) GO TO  60
      TEMP = X(I)
      J = I
   40 IF (X(J - INCR) .LT. TEMP) GO TO  50
      X(J) = X(J - INCR)
      J = J - INCR
      IF (J .GT. INCR) GO TO  40
   50 X(J) = TEMP
      I = I + 1
      GO TO  30
   60 IF (INCR .GT. 1) GO TO  20
!
      RETURN
      END SUBROUTINE SORTSH
      SUBROUTINE SPANF1(EDGE1,EDGE2,NEDGE,Y,X,NVERT,IWRITE,   &
      Y2,X2,TAG,NOUT,   &
      IEDGE,IX,NV,IWORK1,   &
      IBUGA3,IERROR)
!
!     PURPOSE--IMPLEMENTS THE COMMAND
!
!                 LET Y1 Y2 TAG = SPANNING FOREST EDGE1 EDGE2 Y X
!
!              WHERE EDGE1 AND EDGE2 DEFINE A LIST OF EDGES
!              AND Y AND X ARE THE COORDINATES FOR THE VERTICES.
!
!              NOTE THAT THIS FORM OF THE COMMAND IS MOST USEFUL
!              WHEN THE PRIMARY GOAL IS TO GENERATE A PLOT OF
!              THE SPANNING FOREST (I.E., THE CONNECTED COMPONENTS
!              OF THE GRAPH).
!
!     EXAMPLES--LET Y2 X2 TAG = SPANNING FOREST E1 E2 Y X
!     INPUT  ARGUMENTS--EDGE1  VECTOR IDENTIFYING FIRST VERTEX IN EDGE
!                       EDGE2  VECTOR IDENTIFYING SECOND VERTEX IN EDGE
!                       NEDGE  NUMBER OF EDGES
!                       Y      VECTOR CONTAINING Y-COORDINATE OF
!                              VERTICES
!                       X      VECTOR CONTAINING X-COORDINATE OF
!                              VERTICES
!                       X      X-AXIS VECTOR
!                       NVERT  NUMBER OF VERTICES
!     REFERENCE--NIJENHUIS, ALBERT AND WILF, HERBERT S., 'COMBINATORIAL
!                ALGORITHMS', ACADEMIC PRESS, 1975, PP. 106-108.
!     OUTPUT ARGUMENTS--Y2     Y-AXIS VECTOR OF THE NEW VERTICES
!                       X2     X-AXIS VECTOR OF THE NEW VERTICES
!                       TAG    VECTOR IDENTIFYING PAIRS OF VERTICES
!                       NOUT   NUMBER OF VERTICES IN OUTPUT MATRIX
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2008/8
!     ORIGINAL VERSION--JUNE     2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
      DIMENSION EDGE1(*)
      DIMENSION EDGE2(*)
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION Y2(*)
      DIMENSION X2(*)
      DIMENSION TAG(*)
!
      INTEGER IEDGE(*)
      INTEGER IX(*)
      INTEGER NV(*)
      INTEGER IWORK1(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='SPAN'
      ISUBN2='F1  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF SPANF1--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,IWRITE,NEDGE,NVERT
   52   FORMAT('IBUGA3,IWRITE,NEDGE,NVERT = ',A4,2X,A4,2X,2I10)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,NEDGE
          WRITE(ICOUT,56)I,EDGE1(I),EDGE2(I)
   56     FORMAT('I,EDGE1(I),EDGE2(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
        DO 65 I=1,NVERT
          WRITE(ICOUT,66)I,Y(I),X(I)
   66     FORMAT('I,Y(I),X(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   65   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1: CHECK THAT VERTICES ARE IN  **
!               **          THE RANGE (1,NVERT)         **
!               ******************************************
!
      DO 100 I=1,NEDGE
        ITEMP1=INT(EDGE1(I)+0.01)
        IF(ITEMP1.LT.1 .OR. ITEMP1.GT.NVERT)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,101)
  101     FORMAT('***** ERROR FROM SPANNING FOREST--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,103)I
  103     FORMAT('      THE FIRST VERTEX FOR EDGE ',I8,' IS LESS ',   &
                 'THAN ONE')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,105)NVERT
  105     FORMAT('      OR GREATER THAN THE NUMBER OF VERTICES (',I8,   &
                 ').')
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
!
        ITEMP2=INT(EDGE2(I)+0.01)
        IF(ITEMP2.LT.1 .OR. ITEMP2.GT.NVERT)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,101)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,113)I
  113     FORMAT('      THE SECOND VERTEX FOR EDGE ',I8,' IS LESS THAN')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,105)NVERT
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
!
  100 CONTINUE
!
!               ******************************************
!               **  STEP 2: PREPARE INPUT FOR SPANFO    **
!               **          ROUTINE                     **
!               ******************************************
!
      DO 200 I=1,NEDGE
        IT1=(I-1)*2 + 1
        IT2=I*2
        IEDGE(IT1)=INT(EDGE1(I)+0.1)
        IEDGE(IT2)=INT(EDGE2(I)+0.1)
  200 CONTINUE
!
      CALL SPANFO(NVERT,NEDGE,IEDGE,K,IX,NV,IWORK1)
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,223)K
  223   FORMAT('AFTER CALL TO SPANFO: K = ',I8)
        CALL DPWRST('XXX','BUG ')
        DO 230 I=1,NEDGE
          IT1=(I-1)*2 + 1
          IT2=I*2
          WRITE(ICOUT,231)I,IEDGE(IT1),IEDGE(IT2)
  231     FORMAT('I,IEDGE(1,I),IEDGE(2,I) = ',3I8)
          CALL DPWRST('XXX','BUG ')
  230   CONTINUE
        DO 240 I=1,NVERT
          WRITE(ICOUT,241)I,IX(I)
  241     FORMAT('I,IX(I) = ',2I8)
          CALL DPWRST('XXX','BUG ')
  240   CONTINUE
        DO 250 I=1,K
          WRITE(ICOUT,251)I,NV(I)
  251     FORMAT('I,NV(I) = ',2I8)
          CALL DPWRST('XXX','BUG ')
  250   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 3: CONVERT SPANFO OUTPOUT TO   **
!               **          FORM WE WANT                **
!               ******************************************
!
      ICNT1=0
      ICNT2=0
!
      DO 300 IK=1,K
        ATAG=REAL(IK)
        IPTS=NV(IK)-1
!
        IF(IBUGA3.EQ.'ON')THEN
          WRITE(ICOUT,301)IK,IPTS,ATAG
  301     FORMAT('IK,IPTS,ATAG = ',2I8,G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        IF(IPTS.GE.1)THEN
          DO 310 I=1,IPTS
            ICNT2=ICNT2+1
            IT1=(ICNT2-1)*2 + 1
            IT2=ICNT2*2
            ITEMP1=IEDGE(IT1)
            ITEMP2=IEDGE(IT2)
!
            IF(IBUGA3.EQ.'ON')THEN
              WRITE(ICOUT,311)I,IT1,IT2,ITEMP1,ITEMP2
  311         FORMAT('I,IT1,IT2,ITEMP1,ITEMP2 = ',5I8)
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,313)Y(ITEMP1),X(ITEMP1)
  313         FORMAT('Y(ITEMP1),X(ITEMP1) = ',2G15.7)
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,314)Y(ITEMP2),X(ITEMP2)
  314         FORMAT('Y(ITEMP2),X(ITEMP2) = ',2G15.7)
              CALL DPWRST('XXX','BUG ')
            ENDIF
!
            ICNT1=ICNT1+1
            Y2(ICNT1)=Y(ITEMP1)
            X2(ICNT1)=X(ITEMP1)
            TAG(ICNT1)=ATAG
!
            IF(IBUGA3.EQ.'ON')THEN
              WRITE(ICOUT,315)ICNT1,Y2(ICNT1),X2(ICNT1)
  315         FORMAT('ICNT1,Y2(ICNT1),X2(ICNT1) = ',I8,2G15.7)
              CALL DPWRST('XXX','BUG ')
            ENDIF
!
            ICNT1=ICNT1+1
            Y2(ICNT1)=Y(ITEMP2)
            X2(ICNT1)=X(ITEMP2)
            TAG(ICNT1)=ATAG
!
            IF(IBUGA3.EQ.'ON')THEN
              WRITE(ICOUT,315)ICNT1,Y2(ICNT1),X2(ICNT1)
              CALL DPWRST('XXX','BUG ')
            ENDIF
!
  310     CONTINUE
        ELSE
          DO 320 I=1,NVERT
            IF(IK.EQ.IX(I))THEN
              ICNT1=ICNT1+1
              Y2(ICNT1)=Y(IX(I))
              X2(ICNT1)=X(IX(I))
              TAG(ICNT1)=ATAG
              GO TO 329
            ENDIF
  320     CONTINUE
  329     CONTINUE
        ENDIF
  300 CONTINUE
!
      NOUT=ICNT1
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END OF SPANF1--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)NOUT
 9014   FORMAT('NOUT = ',I8)
        CALL DPWRST('XXX','BUG ')
        DO 9015 I=1,NOUT
          WRITE(ICOUT,9016)I,Y2(I),X2(I),TAG(I)
 9016     FORMAT('I,Y2(I),X2(I),TAG(I) = ',I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
 9015   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE SPANF1
      SUBROUTINE SPANF2(EDGE1,EDGE2,NEDGE,NVERT,IWRITE,   &
      IEDGE,IX,NV,K,IWORK1,   &
      IBUGA3,IERROR)
!
!     PURPOSE--IMPLEMENTS THE COMMAND
!
!              LET EDGE1 EDGE2 TAG NV = SPANNING FOREST EDGE1 EDGE2 NVERT
!
!              WHERE EDGE1 AND EDGE2 DEFINE A LIST OF EDGES
!              AND NVERT IS THE NUMBER OF VERTICES.
!
!              NOTE THAT THIS FORM OF THE COMMAND RETURNS THE
!              OUTPUT AS GIVEN BY THE SPANFO ROUTINE.
!              THE SPANNING FOREST (I.E., THE CONNECTED COMPONENTS
!              OF THE GRAPH).
!
!     EXAMPLES--LET Y2 X2 TAG = SPANNING FOREST E1 E2 Y X
!     INPUT  ARGUMENTS--EDGE1  VECTOR IDENTIFYING FIRST VERTEX IN EDGE
!                       EDGE2  VECTOR IDENTIFYING SECOND VERTEX IN EDGE
!                       NEDGE  NUMBER OF EDGES
!                       NVERT  NUMBER OF VERTICES
!     OUTPUT ARGUMENTS--EDGE1  RE-ARRANGED FIRST VERTEX IN EDGE
!                       EDGE2  RE-ARRANGED SECOND VERTEX IN EDGE
!                       IX     INTEGER VECTOR THAT IDENTIFIES WHICH
!                              COMPONENT THE I-TH VERTEX BELONGS TO
!                       NV     INTEGER VECTOR THAT IDENTIFIES THEES
!                              NUMBER OF EDGES IN EACH COMPONENT
!                       K      AN INTEGER SCALAR THAT IDENTIFIES THE
!                              THE NUMBER OF COMPONENTS
!     REFERENCE--NIJENHUIS, ALBERT AND WILF, HERBERT S., 'COMBINATORIAL
!                ALGORITHMS', ACADEMIC PRESS, 1975, PP. 106-108.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2008/8
!     ORIGINAL VERSION--JUNE     2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
      DIMENSION EDGE1(*)
      DIMENSION EDGE2(*)
!
      INTEGER IEDGE(*)
      INTEGER IX(*)
      INTEGER NV(*)
      INTEGER IWORK1(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='SPAN'
      ISUBN2='F2  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF SPANF2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,IWRITE,NEDGE,NVERT
   52   FORMAT('IBUGA3,IWRITE,NEDGE,NVERT = ',A4,2X,A4,2X,2I10)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,NEDGE
          WRITE(ICOUT,56)I,EDGE1(I),EDGE2(I)
   56     FORMAT('I,EDGE1(I),EDGE2(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1: CHECK THAT VERTICES ARE IN  **
!               **          THE RANGE (1,NVERT)         **
!               ******************************************
!
      DO 100 I=1,NEDGE
        ITEMP1=INT(EDGE1(I)+0.01)
        IF(ITEMP1.LT.1 .OR. ITEMP1.GT.NVERT)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,101)
  101     FORMAT('***** ERROR FROM SPANNING FOREST--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,103)I
  103     FORMAT('      THE FIRST VERTEX FOR EDGE ',I8,' IS LESS ',   &
                 'THAN ONE')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,105)NVERT
  105     FORMAT('      OR GREATER THAN THE NUMBER OF VERTICES (',I8,   &
                 ').')
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
!
        ITEMP2=INT(EDGE2(I)+0.01)
        IF(ITEMP2.LT.1 .OR. ITEMP2.GT.NVERT)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,101)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,113)I
  113     FORMAT('      THE SECOND VERTEX FOR EDGE ',I8,' IS LESS THAN')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,105)NVERT
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
!
  100 CONTINUE
!
!               ******************************************
!               **  STEP 2: PREPARE INPUT FOR SPANFO    **
!               **          ROUTINE                     **
!               ******************************************
!
      DO 200 I=1,NEDGE
        IT1=(I-1)*2 + 1
        IT2=I*2
        IEDGE(IT1)=INT(EDGE1(I)+0.1)
        IEDGE(IT2)=INT(EDGE2(I)+0.1)
  200 CONTINUE
!
      CALL SPANFO(NVERT,NEDGE,IEDGE,K,IX,NV,IWORK1)
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,223)K
  223   FORMAT('AFTER CALL TO SPANFO: K = ',I8)
        CALL DPWRST('XXX','BUG ')
        DO 230 I=1,NEDGE
          IT1=(I-1)*2 + 1
          IT2=I*2
          WRITE(ICOUT,231)I,IEDGE(IT1),IEDGE(IT2)
  231     FORMAT('I,IEDGE(1,I),IEDGE(2,I) = ',3I8)
          CALL DPWRST('XXX','BUG ')
  230   CONTINUE
        DO 240 I=1,NVERT
          WRITE(ICOUT,241)I,IX(I)
  241     FORMAT('I,IX(I) = ',2I8)
          CALL DPWRST('XXX','BUG ')
  240   CONTINUE
        DO 250 I=1,K
          WRITE(ICOUT,251)I,NV(I)
  251     FORMAT('I,NV(I) = ',2I8)
          CALL DPWRST('XXX','BUG ')
  250   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 3: CONVERT SPANFO OUTPOUT TO   **
!               **          FORM WE WANT.  FOR THIS     **
!               **          ROUTINE, THAT JUST MEANS    **
!               **          COPY THE EDGE ARRAYS.       **
!               ******************************************
!
      DO 330 I=1,NEDGE
          IT1=(I-1)*2 + 1
          IT2=I*2
          EDGE1(I)=REAL(IEDGE(IT1))
          EDGE2(I)=REAL(IEDGE(IT2))
  330 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END OF SPANF2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)NEDGE,NVERT,K
 9014   FORMAT('NEDGE,NVERT,K = ',3I8)
        CALL DPWRST('XXX','BUG ')
        DO 9015 I=1,NEDGE
          WRITE(ICOUT,9016)I,EDGE1(I),EDGE2(I)
 9016     FORMAT('I,EDGE1(I),EDGE2(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
 9015   CONTINUE
        DO 9025 I=1,NVERT
          WRITE(ICOUT,9026)I,IX(I)
 9026     FORMAT('I,IX(I) = ',2I8)
          CALL DPWRST('XXX','BUG ')
 9025   CONTINUE
        DO 9035 I=1,K
          WRITE(ICOUT,9036)I,NV(I)
 9036     FORMAT('I,NV(I) = ',2I8)
          CALL DPWRST('XXX','BUG ')
 9035   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE SPANF2
      SUBROUTINE SPECIF(X,Y,N,IWRITE,XIDTEM,STAT,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE TEST SPECIFICITY
!              BETWEEN TWO VARIABLES.
!
!              THIS IS SPECIFICALLY FOR THE 2X2 CASE.  THAT IS,
!              EACH VARIABLE HAS TWO MUTUALLY EXCLUSIVE
!              CHOICES CODED AS 1 (FOR SUCCESS) OR 0 (FOR
!              FAILURE).  TEST SPECIFICITY IS DEFINED AS THE
!              CONDITIONAL PROBABILITY OF A POSITIVE TEST GiVEN
!              THAT THE DISEASE IS NOT PRESENT.
!
!              A TYPICAL EXAMPLE WOULD BE WHERE VARIABLE ONE
!              DENOTES THE GROUND TRUTH AND A VALUE OF 1
!              INDICATES "PRESENT" AND A VALUE OF 0 INDICATES
!              "NOT PRESENT".  VARIABLE TWO REPRESENTS SOME TYPE
!              OF DETECTION DEVICE WHERE A VALUE OF 1 INDICATES
!              THE DEVICE DETECTED THE SPECIFIED OBJECT WHILE A
!              VALUE OF 0 INDICATES THAT THE OBJECT WAS NOT
!              DETECTED.  TEST SPECIFICITY IS THEN DEFINED AS
!              THE PROBABILITY OF NOT DETECTING THE OBJECT GIVEN
!              THAT THE OBJECT IS NOT ACTUALLY THERE.
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED) OBSERVATIONS
!                                WHICH CONSTITUTE THE FIRST SET
!                                OF DATA.
!                     --Y      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED) OBSERVATIONS
!                                WHICH CONSTITUTE THE SECOND SET
!                                OF DATA.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X, OR EQUIVALENTLY,
!                                THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR Y.
!     OUTPUT ARGUMENTS--STAT   = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED TEST SPECIFICITY
!                                BETWEEN THE 2 SETS OF DATA
!                                IN THE INPUT VECTORS X AND Y.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE TEST SPECIFICITY BETWEEN THE 2 SETS
!             OF DATA IN THE INPUT VECTORS X AND Y.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTIUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/3
!     ORIGINAL VERSION--MARCH     2007.
!     UPDATED         --AUGUST    2007. IF 2X2 CASE, CHECK IF SUM
!                                       OF ENTRIES IS <= 4.  IN THIS
!                                       CASE, ASSUME WE HAVE RAW DATA
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISTEPN
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(*)
      DIMENSION XIDTEM(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='SPEC'
      ISUBN2='IF  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF SPECIF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,N
   52   FORMAT('IBUGA3,N = ',A4,2X,I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I),Y(I)
   56     FORMAT('I,X(I),Y(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 21--                             **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='21'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(N.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1201)
 1201   FORMAT('***** ERROR IN THE TEST SPECIFICITY')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1203)
 1203   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE RESPONSE ',   &
               'VARIABLES IS LESS THAN TWO')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1205)N
 1205   FORMAT('SAMPLE SIZE = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ********************************************
!               **  STEP 22--                             **
!               **  CHECK THAT THE VARIABLES HAVE AT MOST **
!               **  TWO DISTINCT VALUES (1 INDICATES A    **
!               **  SUCCESS, 0 INDICATES A FAILURE).      **
!               ********************************************
!
      ISTEPN='22'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     NOTE: CHECK FOR SPECIAL CASE N = 2.  IN THIS CASE,
!           ASSUME WE HAVE A 2X2 TABLE OF COUNTS INSTEAD
!           OF RAW DATA.
!
      IF(N.EQ.2)THEN
        N11=INT(X(1)+0.5)
        N21=INT(X(2)+0.5)
        N12=INT(Y(1)+0.5)
        N22=INT(Y(2)+0.5)
!
!       CHECK IF ALL ENTRIES 0 OR 1. IF SO, ASSUME
!       RAW DATA CASE.
!
        IF((N11.EQ.0 .OR. N11.EQ.1) .AND.   &
           (N12.EQ.0 .OR. N12.EQ.1) .AND.   &
           (N21.EQ.0 .OR. N21.EQ.1) .AND.   &
           (N22.EQ.0 .OR. N22.EQ.1)) GO TO 1349
!
        IF(N11.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1311)
 1311     FORMAT('      ROW 1 COLUMN 1 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(N21.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1321)
 1321     FORMAT('      ROW 2 COLUMN 1 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(N12.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1331)
 1331     FORMAT('      ROW 1 COLUMN 2 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(N22.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1341)
 1341     FORMAT('      ROW 2 COLUMN 2 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        AN11=REAL(N11)
        AN21=REAL(N21)
        AN12=REAL(N12)
        AN22=REAL(N22)
        STAT=AN22/(AN21+AN22)
        GO TO 3000
      ENDIF
!
      CALL DISTIN(X,N,IWRITE,XIDTEM,NDIST,IBUGA3,IERROR)
      IF(NDIST.EQ.1)THEN
        AVAL=XIDTEM(1)
        IF(ABS(AVAL).LE.0.5)THEN
          AVAL=0.0
        ELSE
          AVAL=1.0
        ENDIF
        DO 2202 I=1,N
          X(I)=1.0
 2202   CONTINUE
      ELSEIF(NDIST.EQ.2)THEN
        IF(XIDTEM(1).EQ.1.0 .OR. XIDTEM(2).EQ.1.0)THEN
          DO 2203 I=1,N
            IF(X(I).NE.1.0)X(I)=0.0
 2203     CONTINUE
        ELSE
          ATEMP1=MIN(XIDTEM(1),XIDTEM(2))
          ATEMP2=MAX(XIDTEM(1),XIDTEM(2))
          DO 2208 I=1,N
            IF(X(I).EQ.ATEMP1)X(I)=0.0
            IF(X(I).EQ.ATEMP2)X(I)=1.0
 2208     CONTINUE
        ENDIF
      ELSE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1201)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2211)
 2211   FORMAT('      RESPONSE VARIABLE ONE SHOULD CONTAIN AT MOST')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2213)
 2213   FORMAT('      TWO DISTINCT VALUES.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2215)NDIST
 2215   FORMAT('      ',I8,' DISTINCT VALUES FOUND.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
 1349 CONTINUE
!
      CALL DISTIN(Y,N,IWRITE,XIDTEM,NDIST,IBUGA3,IERROR)
      IF(NDIST.EQ.1)THEN
        AVAL=XIDTEM(1)
        IF(ABS(AVAL).LE.0.5)THEN
          AVAL=0.0
        ELSE
          AVAL=1.0
        ENDIF
        DO 2302 I=1,N
          Y(I)=1.0
 2302   CONTINUE
      ELSEIF(NDIST.EQ.2)THEN
        IF(XIDTEM(1).EQ.1.0 .OR. XIDTEM(2).EQ.1.0)THEN
          DO 2303 I=1,N
            IF(Y(I).NE.1.0)Y(I)=0.0
 2303     CONTINUE
        ELSE
          ATEMP1=MIN(XIDTEM(1),XIDTEM(2))
          ATEMP2=MAX(XIDTEM(1),XIDTEM(2))
          DO 2308 I=1,N
            IF(Y(I).EQ.ATEMP1)Y(I)=0.0
            IF(Y(I).EQ.ATEMP2)Y(I)=1.0
 2308     CONTINUE
        ENDIF
      ELSE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1201)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2311)
 2311   FORMAT('      RESPONSE VARIABLE TWO SHOULD CONTAIN AT MOST')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2313)
 2313   FORMAT('      TWO DISTINCT VALUES.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2315)NDIST
 2315   FORMAT('      ',I8,' DISTINCT VALUES FOUND.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      N11=0
      N12=0
      N21=0
      N22=0
      DO 2410 I=1,N
        IF(X(I).EQ.1.0 .AND. Y(I).EQ.1.0)THEN
          N11=N11+1
        ELSEIF(X(I).EQ.0.0 .AND. Y(I).EQ.0.0)THEN
          N22=N22+1
        ELSEIF(X(I).EQ.1.0 .AND. Y(I).EQ.0.0)THEN
          N12=N12+1
        ELSEIF(X(I).EQ.0.0 .AND. Y(I).EQ.1.0)THEN
          N21=N21+1
        ENDIF
 2410 CONTINUE
!
      STAT=REAL(N22)/REAL(N21+N22)
!
 3000 CONTINUE
!
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'OFF')GO TO 890
      IF(IWRITE.EQ.'OFF' .OR. IWRITE.EQ.'NO')GO TO 890
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,811)STAT
  811 FORMAT('THE TEST SPECIFICITY PROPORTION = ',G15.7)
      CALL DPWRST('XXX','BUG ')
  890 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END OF SPECIF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA3,IERROR
 9012   FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)N,N11,N12,N21,N22
 9013   FORMAT('N,N11,N12,N21,N22 = ',5I10)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)STAT
 9015   FORMAT('STAT = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE SPECIF
      DOUBLE PRECISION FUNCTION SPHINC( N, R )
!
!                   R
!     SPHINC =  K  I  exp(-t*t/2) t**(N-1) dt, for N > 1.
!                N  0
!
      INTEGER I, N
      DOUBLE PRECISION R, RR, RP, PF, ET, PHI
      PARAMETER ( RP = 2.5066282746310004D0 )
      IF ( R .GT. 0 ) THEN
         RR = R*R
         PF = 1.0D0
         DO 100 I = N-2, 2, -2
            PF = 1.0D0 + RR*PF/DBLE(I)
  100    CONTINUE
         IF ( MOD( N, 2 ) .EQ. 0 ) THEN
            ET = LOG(PF) - RR/2.0D0
            IF ( ET .GT. -40.0D0 ) THEN
               SPHINC = 1.0D0 - EXP( ET )
            ELSE
               SPHINC = 1.0D0
            END IF
         ELSE
            SPHINC = 1  - 2*PHI(-R)
            ET = LOG(R*PF) - RR/2
            IF ( ET .GT. -40 ) SPHINC = SPHINC - 2.0D0*EXP( ET )/RP
         ENDIF
      ELSE
         SPHINC = 0.0D0
      ENDIF
!
      RETURN
      END FUNCTION SPHINC
      DOUBLE PRECISION FUNCTION SPHLIM( N, A, B, INFI, Y )
      DOUBLE PRECISION A(*), B(*), Y(*), CMN, CMX, SPHINC
      INTEGER INFI(*), I, N
      CMN = -10*N
      CMX =  10*N
      DO 100 I = 1,N
         IF ( Y(I) .GT. 0.0D0 ) THEN
            IF ( INFI(I) .NE. 1 ) CMX = MIN( CMX, B(I)/Y(I) )
            IF ( INFI(I) .NE. 0 ) CMN = MAX( CMN, A(I)/Y(I) )
         ELSE
            IF ( INFI(I) .NE. 1 ) CMN = MAX( CMN, B(I)/Y(I) )
            IF ( INFI(I) .NE. 0 ) CMX = MIN( CMX, A(I)/Y(I) )
         ENDIF
  100 CONTINUE
      IF ( CMN .LT. CMX ) THEN
         IF ( CMN .GE. 0.0D0 .AND. CMX .GE. 0.0D0 ) THEN
            SPHLIM = SPHINC( N,  CMX ) - SPHINC( N,  CMN )
         ELSEIF ( CMN .LT. 0.0D0 .AND. CMX .GE. 0.0D0 ) THEN
            SPHLIM = SPHINC( N, -CMN ) + SPHINC( N,  CMX )
         ELSE
            SPHLIM = SPHINC( N, -CMN ) - SPHINC( N, -CMX )
         ENDIF
      ELSE
         SPHLIM = 0.0D0
      ENDIF
!
      RETURN
      END FUNCTION SPHLIM
      SUBROUTINE SPHMVN(N, LOWER, UPPER, INFIN, CORREL, MAXPTS,   &
           ABSEPS, RELEPS, ERROR, VALUE, INFORM)
!
!     A subroutine for computing multivariate normal probabilities.
!     This subroutine uses a Mont-Carlo algorithm given in the paper
!       "Three Digit Accurate Multiple Normal Probabilities",
!          pp. 369-380, Numer. Math. 35(1980), by I. Deak
!
!
!  Parameters
!
!     N      INTEGER, the number of variables.
!     LOWER  REAL, array of lower integration limits.
!     UPPER  REAL, array of upper integration limits.
!     INFIN  INTEGER, array of integration limits flags:
!            if INFIN(I) < 0, Ith limits are (-infinity, infinity);
!            if INFIN(I) = 0, Ith limits are (-infinity, UPPER(I)];
!            if INFIN(I) = 1, Ith limits are [LOWER(I), infinity);
!            if INFIN(I) = 2, Ith limits are [LOWER(I), UPPER(I)].
!     CORREL REAL, array of correlation coefficients; the correlation
!            coefficient in row I column J of the correlation matrix
!            should be stored in CORREL( J + ((I-2)*(I-1))/2 ), for J < I.
!     MAXPTS INTEGER, maximum number of function values allowed. This
!            parameter can be used to limit the time. A sensible
!            strategy is to start with MAXPTS = 1000*N, and then
!            increase MAXPTS if ERROR is too large.
!     ABSEPS REAL absolute error tolerance.
!     RELEPS REAL relative error tolerance.
!     ERROR  REAL, estimated absolute error, with 99% confidence level.
!     VALUE  REAL, estimated value for the integral
!     INFORM INTEGER, termination status parameter:
!            if INFORM = 0, normal completion with ERROR < EPS;
!            if INFORM = 1, completion with ERROR > EPS and MAXPTS
!                           function vaules used; increase MAXPTS to
!                           decrease ERROR;
!            if INFORM = 2, N > 100.
!
      EXTERNAL SPNRML
      INTEGER N, INFIS, INFIN(*), MAXPTS, MPT, INFORM, NS, IVLS
      DOUBLE PRECISION CORREL(*), LOWER(*), UPPER(*),   &
           ABSEPS, RELEPS, ERROR, VALUE, D, E, EPS, SPNRNT
      IF ( N .GT. 100 ) THEN
         INFORM = 2
         VALUE = 0.0D0
         ERROR = 1.0D0
         RETURN
      ENDIF
      INFORM = INT(SPNRNT(N,CORREL,LOWER,UPPER,INFIN,INFIS,D,E,NS))
      IF ( N-INFIS .EQ. 0 ) THEN
         VALUE = 1.0D0
         ERROR = 0.0D0
      ELSE IF ( N-INFIS .EQ. 1 ) THEN
         VALUE = E - D
         ERROR = 2E-16
      ELSE
!
!        Call then Monte-Carlo integration subroutine
!
         MPT = 25 + NS/N**3
         CALL SCRUDE( N-INFIS, MPT, ERROR, VALUE, 0 )
         IVLS = MPT*NS
 10      EPS = MAX( ABSEPS, RELEPS*ABS(VALUE) )
         IF ( ERROR .GT. EPS .AND. IVLS .LT. MAXPTS ) THEN
            MPT = MAX( MIN( INT(MPT*(ERROR/(EPS))**2),   &
                            ( MAXPTS - IVLS )/NS ), 10 )
            CALL SCRUDE( N-INFIS, MPT, ERROR, VALUE, 1 )
            IVLS = IVLS + MPT*NS
            GO TO 10
         ENDIF
         IF ( ERROR .GT. EPS .AND. IVLS .GE. MAXPTS ) INFORM = 1
      ENDIF
!
      RETURN
      END SUBROUTINE SPHMVN
      SUBROUTINE SPHMVT( N, NU, LOWER, UPPER, INFIN, CORREL, MAXPTS,   &
                         ABSEPS, RELEPS, ERROR, VALUE, INFORM )
!
!     A subroutine for computing multivariate t probabilities.
!     This subroutine uses a modified version of the Mont-Carlo
!     algorithm for multivariatie Normal probabilities in the paper
!       "Three Digit Accurate Multiple Normal Probabilities",
!          pp. 369-380, Numer. Math. 35(1980), by I. Deak
!
!
!  Parameters
!
!     N      INTEGER, the number of variables.
!     NU     INTEGER, the number of degrees of freedom.
!     LOWER  REAL, array of lower integration limits.
!     UPPER  REAL, array of upper integration limits.
!     INFIN  INTEGER, array of integration limits flags:
!            if INFIN(I) < 0, Ith limits are (-infinity, infinity);
!            if INFIN(I) = 0, Ith limits are (-infinity, UPPER(I)];
!            if INFIN(I) = 1, Ith limits are [LOWER(I), infinity);
!            if INFIN(I) = 2, Ith limits are [LOWER(I), UPPER(I)].
!     CORREL REAL, array of correlation coefficients; the correlation
!            coefficient in row I column J of the correlation matrix
!            should be stored in CORREL( J + ((I-2)*(I-1))/2 ), for J < I.
!     MAXPTS INTEGER, maximum number of function values allowed. This
!            parameter can be used to limit the time. A sensible
!            strategy is to start with MAXPTS = 1000*N, and then
!            increase MAXPTS if ERROR is too large.
!     ABSEPS REAL absolute error tolerance.
!     RELEPS REAL relative error tolerance.
!     ERROR  REAL, estimated absolute error, with 99% confidence level.
!     VALUE  REAL, estimated value for the integral
!     INFORM INTEGER, termination status parameter:
!            if INFORM = 0, normal completion with ERROR < EPS;
!            if INFORM = 1, completion with ERROR > EPS and MAXPTS
!                           function vaules used; increase MAXPTS to
!                           decrease ERROR;
!            if INFORM = 2, N > 50.
!
      EXTERNAL SPMVTI
      INTEGER N, NU, INFIS, INFIN(*), MAXPTS, MPT, INFORM, NS, IVLS
      DOUBLE PRECISION CORREL(*), LOWER(*), UPPER(*),   &
           ABSEPS, RELEPS, ERROR, VALUE, D, E, EPS, SPMVTI
      IF ( N .GT. 50 ) THEN
         INFORM = 2
         VALUE = 0.0D0
         ERROR = 1.0D0
         RETURN
      ENDIF
      INFORM = INT(SPMVTI(N,NU,CORREL,LOWER,UPPER,INFIN,INFIS,D,E,NS))
      IF ( N-INFIS .EQ. 0 ) THEN
         VALUE = 1.0D0
         ERROR = 0.0D0
      ELSE IF ( N-INFIS .EQ. 1 ) THEN
         VALUE = E - D
         ERROR = 2E-16
      ELSE
!
!        Call the Monte-Carlo integration subroutine
!
         MPT = 25 + NS/N**3
         CALL TCRUDE( N-INFIS, MPT, ERROR, VALUE, 0 )
         IVLS = MPT*NS
 10      EPS = MAX( ABSEPS, RELEPS*ABS(VALUE) )
         IF ( ERROR .GT. EPS .AND. IVLS .LT. MAXPTS ) THEN
            MPT = MAX( MIN( INT( MPT*( ERROR/EPS )**2 ),   &
                            ( MAXPTS - IVLS )/NS ), 10 )
            CALL TCRUDE( N-INFIS, MPT, ERROR, VALUE, 1 )
            IVLS = IVLS + MPT*NS
            GO TO 10
         ENDIF
         IF ( ERROR .GT. EPS .AND. IVLS .GE. MAXPTS ) INFORM = 1
      ENDIF
!
      RETURN
      END SUBROUTINE SPHMVT
      DOUBLE PRECISION FUNCTION SPHLMT( N, NU, A, B, INFI, Y )
      DOUBLE PRECISION A(*), B(*), Y(*), CMN, CMX, SPHNCT
      INTEGER INFI(*), I, N, NU
      CMN = -10.0D0*N
      CMX =  10.0D0*N
      DO 100 I = 1,N
         IF ( Y(I) .GT. 0.0D0 ) THEN
            IF ( INFI(I) .NE. 1 ) CMX = MIN( CMX, B(I)/Y(I) )
            IF ( INFI(I) .NE. 0 ) CMN = MAX( CMN, A(I)/Y(I) )
         ELSE
            IF ( INFI(I) .NE. 1 ) CMN = MAX( CMN, B(I)/Y(I) )
            IF ( INFI(I) .NE. 0 ) CMX = MIN( CMX, A(I)/Y(I) )
         ENDIF
  100 CONTINUE
      IF ( CMN .LT. CMX ) THEN
         IF ( CMN .GE. 0.0D0 .AND. CMX .GE. 0.0D0 ) THEN
            SPHLMT = SPHNCT( N, NU,  CMX ) - SPHNCT( N, NU,  CMN )
         ELSEIF ( CMN .LT. 0.0D0 .AND. CMX .GE. 00D0 ) THEN
            SPHLMT = SPHNCT( N, NU, -CMN ) + SPHNCT( N, NU,  CMX )
         ELSE
            SPHLMT = SPHNCT( N, NU, -CMN ) - SPHNCT( N, NU, -CMX )
         ENDIF
      ELSE
         SPHLMT = 0.0D0
      ENDIF
!
      RETURN
      END FUNCTION SPHLMT
      DOUBLE PRECISION FUNCTION SPHNCT( M, NU, R )
!
!                   R
!     SPHNCT =  K  I  ( 1 + t**2/NU )**(-(NU+M)/2 ) t**(M-1) dt, for M > 0.
!                M  0
!
      INTEGER I, M, NU, NUOLD
      DOUBLE PRECISION R, RR, RT, PI, PF, STUDNT, TCON
      PARAMETER ( PI = 3.141592653589793D0 )
      SAVE NUOLD, TCON
      DATA NUOLD / 0 /
      IF ( R .GT. 0.0D0 ) THEN
         IF ( M .LE. 1 ) THEN
            SPHNCT = 2.0D0*STUDNT( NU, R ) - 1.0D0
         ELSE IF ( M .EQ. 2 ) THEN
            SPHNCT = 1.0D0 - 1.0D0/SQRT( 1.0D0 + R*R/NU )**NU
         ELSE
            RR = R*R/NU
            RT = RR/( 1.0D0 + RR )
            PF = 1.0D0
            DO 100 I = M - 2, 2, -2
               PF = 1 + PF*RT*DBLE( NU + I - 2 )/DBLE(I)
  100       CONTINUE
            PF = PF*SQRT( RT/RR )**NU
            IF ( MOD( M, 2 ) .EQ. 0 ) THEN
               SPHNCT = 1.0D0 - PF
            ELSE
               IF ( NU .NE. NUOLD ) THEN
                  NUOLD = NU
                  TCON = 1.0D0
                  IF ( MOD( NU, 2 ) .EQ. 0 ) THEN
                     TCON = TCON/2.0D0
                  ELSE
                     TCON = TCON/PI
                  END IF
                  DO 200 I = NU-2, 1, -2
                     TCON = ( I + 1 )*TCON/I
  200             CONTINUE
               END IF
               SPHNCT = 2.0D0*   &
                        ( STUDNT( NU, R ) - TCON*SQRT(RT)*PF ) - 1.0D0
            ENDIF
         ENDIF
      ELSE
         SPHNCT = 0.0D0
      ENDIF
!
      RETURN
      END FUNCTION SPHNCT
      DOUBLE PRECISION FUNCTION spmpar(i)
!-----------------------------------------------------------------------
!
!     SPMPAR PROVIDES THE SINGLE PRECISION MACHINE CONSTANTS FOR
!     THE COMPUTER BEING USED. IT IS ASSUMED THAT THE ARGUMENT
!     I IS AN INTEGER HAVING ONE OF THE VALUES 1, 2, OR 3. IF THE
!     SINGLE PRECISION ARITHMETIC BEING USED HAS M BASE B DIGITS AND
!     ITS SMALLEST AND LARGEST EXPONENTS ARE EMIN AND EMAX, THEN
!
!        SPMPAR(1) = B**(1 - M), THE MACHINE PRECISION,
!
!        SPMPAR(2) = B**(EMIN - 1), THE SMALLEST MAGNITUDE,
!
!        SPMPAR(3) = B**EMAX*(1 - B**(-M)), THE LARGEST MAGNITUDE.
!
!-----------------------------------------------------------------------
!     WRITTEN BY
!        ALFRED H. MORRIS, JR.
!        NAVAL SURFACE WARFARE CENTER
!        DAHLGREN VIRGINIA
!-----------------------------------------------------------------------
!-----------------------------------------------------------------------
!     MODIFIED BY BARRY W. BROWN TO RETURN DOUBLE PRECISION MACHINE
!     CONSTANTS FOR THE COMPUTER BEING USED.  THIS MODIFICATION WAS
!     MADE AS PART OF CONVERTING BRATIO TO DOUBLE PRECISION
!-----------------------------------------------------------------------
!     .. Scalar Arguments ..
      INTEGER i
!     ..
!     .. Local Scalars ..
      DOUBLE PRECISION b,binv,bm1,one,w,z
      INTEGER emax,emin,ibeta,m
!     ..
!     .. External Functions ..
      INTEGER ipmpar
      EXTERNAL ipmpar
!     ..
!     .. Intrinsic Functions ..
      INTRINSIC dble
!
      INCLUDE 'DPCOMC.INC'
!     ..
!     .. Executable Statements ..
!
      IF (i.GT.1) GO TO 10
      b = i1mach(10)
      m = i1mach(11)
!CCCC b = ipmpar(4)
!CCCC m = ipmpar(8)
      spmpar = b** (1-m)
      RETURN
!
   10 IF (i.GT.2) GO TO 20
      b = i1mach(10)
!CCCC b = ipmpar(4)
      emin = i1mach(12)
!CCCC emin = ipmpar(9)
      one = dble(1)
      binv = one/b
      w = b** (emin+2)
      spmpar = ((w*binv)*binv)*binv
      RETURN
!
   20 continue
      ibeta = i1mach(10)
!CCCC ibeta = ipmpar(4)
      m = i1mach(11)
!CCCC m = ipmpar(8)
      emax = i1mach(13)
!CCCC emax = ipmpar(10)
!
      b = ibeta
      bm1 = ibeta - 1
      one = dble(1)
      z = b** (m-1)
      w = ((z-one)*b+bm1)/ (b*z)
!
      z = b** (emax-2)
      spmpar = ((w*z)*b)*b
      RETURN
                                                                                                                                  
      END FUNCTION spmpar
      DOUBLE PRECISION FUNCTION SPMVT(N)
!
!     Integrand subroutine
!
      DOUBLE PRECISION LOWER(*), UPPER(*), CORREL(*), D, E, ZERO
      INTEGER N, INFIN(*), INFIS
      INTEGER NL, IJ, I, II, J, K, NS, NSO, ND, NU, NUIN
      PARAMETER ( NL = 50, ND = 2, ZERO = 0 )
      DOUBLE PRECISION A(NL), B(NL), U(NL,NL), Y(NL), COV(NL*(NL+1)/2)
      INTEGER INFI(NL), IS(NL), IC(NL)
      DOUBLE PRECISION RS, TMP, BT, RNOR, SPHLMT, SPMVTI
      SAVE NU, A, B, INFI, U
!
!    First generate U = COV*(random orthogonal matrix)
!
      DO 100 K = N-1, 1, -1
         TMP = 0
         DO 200 J = K, N
            Y(J) = RNOR()
            TMP = TMP + Y(J)**2
  200    CONTINUE
         TMP = -SQRT(TMP)
         BT = 1/( TMP*( Y(K) + TMP ) )
         Y(K) = Y(K) + TMP
         DO 300 I = 1, N
            TMP = 0
            DO 350 J = K, N
               TMP = TMP + U(I,J)*Y(J)
  350       CONTINUE
            TMP = BT*TMP
            DO 380 J = K, N
               U(I,J) = U(I,J) - TMP*Y(J)
  380       CONTINUE
  300    CONTINUE
  100 CONTINUE
!
!     Compute integrand average
!
      RS = SQRT( DBLE(ND) )
      DO 400 I = 1,ND
         IC(I) = I
  400 CONTINUE
      IC(ND+1) = N+1
      SPMVT = 0.0D0
      NS = 0
 10   CONTINUE
      DO 410 I = 1,ND
         IS(I) = -1
  410 CONTINUE
 20   CONTINUE
      DO 420 I = 1, N
         TMP = 0
         DO 430 J = 1,ND
            TMP = TMP + IS(J)*U( I, IC(J) )
  430    CONTINUE
         Y(I) = TMP/RS
  420 CONTINUE
      NS = NS + 1
      SPMVT = SPMVT + ( SPHLMT( N, NU, A, B, INFI, Y ) - SPMVT )/NS
      DO 440 I = 1, ND
         IS(I) = IS(I) + 2
         IF ( IS(I) .LT. 2 ) GO TO 20
         IS(I) = -1
  440 CONTINUE
      DO 450 I = 1, ND
         IC(I) = IC(I) + 1
         IF ( IC(I) .LT. IC(I+1)  ) GO TO 10
         IC(I) = I
  450 CONTINUE
      SPMVT = SPMVT/2.0D0
      RETURN
!
      ENTRY SPMVTI( N,NUIN, CORREL, LOWER,UPPER,INFIN, INFIS, D,E, NSO )
      SPMVTI = 0.0D0
      NU = NUIN
!
!     Initialisation
!
      II = 0
      IJ = 0
      INFIS = 0
      DO 500 I = 1, N
         INFI(I) = INFIN(I)
         IF ( INFI(I) .LT. 0 ) THEN
            INFIS = INFIS + 1
         ELSE
            A(I) = 0.0D0
            B(I) = 0.0D0
            IF ( INFI(I) .NE. 0 ) A(I) = LOWER(I)
            IF ( INFI(I) .NE. 1 ) B(I) = UPPER(I)
         ENDIF
         DO 550 J = 1, I-1
            II = II + 1
            IJ = IJ + 1
            COV(IJ) = CORREL(II)
  550    CONTINUE
         IJ = IJ + 1
         COV(IJ) = 1
  500 CONTINUE
      NSO = 1
      DO 600 I = 1,ND
         NSO = 2*NSO*( N - INFIS - I + 1 )/I
  600 CONTINUE
!
!     First move any doubly infinite limits to innermost positions
!
      IF ( INFIS .LT. N ) THEN
         DO 700 I = N, N-INFIS+1, -1
            IF ( INFI(I) .GE. 0 ) THEN
               DO 750 J = 1,I-1
                  IF ( INFI(J) .LT. 0 ) THEN
                     CALL RCSWAP( J, I, A, B, INFI, N, COV )
                     GO TO 700
                  ENDIF
  750          CONTINUE
            ENDIF
  700    CONTINUE
      ENDIF
      II = 0
      DO 800 I = 1, N-INFIS
         DO 810 J = 1, I
            U(J,I) = 0
            II = II + 1
            U(I,J) = COV(II)
  810    CONTINUE
  800 CONTINUE
!
!     Determine Cholesky decomposition
!
      DO 900 J = 1, N-INFIS
         DO 910 I = J, N-INFIS
            TMP = U(I,J)
            DO 920 K = 1, J-1
               TMP = TMP - U(I,K)*U(J,K)
  920       CONTINUE
            IF ( I .EQ. J ) THEN
               U(J,J) = SQRT( MAX( TMP, ZERO ) )
            ELSE IF ( U(I,I) .GT. 0 ) THEN
               U(I,J) = TMP/U(J,J)
            ELSE
               U(I,J) = 0.0D0
            END IF
  910    CONTINUE
  900 CONTINUE
      DO 950 I = 1, N-INFIS
         IF ( U(I,I) .GT. 0 ) THEN
            IF ( INFI(I) .NE. 0 ) A(I) = A(I)/U(I,I)
            IF ( INFI(I) .NE. 1 ) B(I) = B(I)/U(I,I)
            DO 960 J = 1,I
               U(I,J) = U(I,J)/U(I,I)
  960       CONTINUE
         ENDIF
  950 CONTINUE
      CALL MVTLMS( NU, A(1), B(1), INFI(1), D, E )
!
      RETURN
      END FUNCTION SPMVT
      DOUBLE PRECISION FUNCTION SPNRML(N)
!
!     Integrand subroutine
!
      DOUBLE PRECISION LOWER(*), UPPER(*), CORREL(*), D, E, ZERO
      INTEGER N, INFIN(*), INFIS
      INTEGER NL, IJ, I, J, K, NS, NSO, ND
      PARAMETER ( NL = 100, ND = 3, ZERO = 0 )
      DOUBLE PRECISION A(NL), B(NL), U(NL,NL), Y(NL)
      INTEGER INFI(NL), IS(NL), IC(NL)
      DOUBLE PRECISION RS, TMP, BT, RNOR, SPHLIM, SPNRNT
!
!CCCC INCLUDE 'DPCOPA.INC'
!CCCC INCLUDE 'DPCOZD.INC'
!CCCC EQUIVALENCE (DGARBG(IDGA10),U(1,1))
!
      SAVE A, B, INFI, U
!
!    First generate U = COV*(random orthogonal matrix)
!
      DO 100 K = N-1, 1, -1
         TMP = 0
         DO 200 J = K, N
            Y(J) = RNOR()
            TMP = TMP + Y(J)**2
  200    CONTINUE
         TMP = -SQRT(TMP)
         BT = 1/( TMP*( Y(K) + TMP ) )
         Y(K) = Y(K) + TMP
         DO 300 I = 1, N
            TMP = 0
            DO 400 J = K, N
               TMP = TMP + U(I,J)*Y(J)
  400       CONTINUE
            TMP = BT*TMP
            DO 500 J = K, N
               U(I,J) = U(I,J) - TMP*Y(J)
  500       CONTINUE
  300    CONTINUE
  100 CONTINUE
!
!     Compute integrand average
!
      RS = SQRT( DBLE(ND) )
      DO 600 I = 1,ND
         IC(I) = I
 600  CONTINUE
      IC(ND+1) = N+1
      SPNRML = 0.0D0
      NS = 0
 10   DO 650 I = 1,ND
         IS(I) = -1
 650  CONTINUE
 20   DO 700 I = 1, N
         TMP = 0
         DO 750 J = 1,ND
            TMP = TMP + IS(J)*U(I,IC(J))
 750     CONTINUE
         Y(I) = TMP/RS
 700  CONTINUE
      NS = NS + 1
      SPNRML = SPNRML + ( SPHLIM( N, A, B, INFI, Y ) - SPNRML )/NS
      DO 800 I = 1, ND
         IS(I) = IS(I) + 2
         IF ( IS(I) .LT. 2 ) GO TO 20
         IS(I) = -1
 800  CONTINUE
      DO 850 I = 1, ND
         IC(I) = IC(I) + 1
         IF ( IC(I) .LT. IC(I+1)  ) GO TO 10
         IC(I) = I
 850  CONTINUE
      SPNRML = SPNRML/2.0D0
      RETURN
      ENTRY SPNRNT( N, CORREL, LOWER, UPPER, INFIN, INFIS, D, E, NSO )
      SPNRNT = 0
!
!     Initialisation
!
      IJ = 0
      INFIS = 0
      DO 900 I = 1, N
         INFI(I) = INFIN(I)
         IF ( INFI(I) .LT. 0 ) THEN
            INFIS = INFIS + 1
         ELSE
            A(I) = 0.0D0
            B(I) = 0.0D0
            IF ( INFI(I) .NE. 0 ) A(I) = LOWER(I)
            IF ( INFI(I) .NE. 1 ) B(I) = UPPER(I)
         ENDIF
         DO 910 J = 1, I-1
            IJ = IJ + 1
            U(I,J) = CORREL(IJ)
            U(J,I) = 0.0D0
  910    CONTINUE
         U(I,I) = 1.D0
  900 CONTINUE
      NSO = 1
      DO 920 I = 1,ND
         NSO = 2*NSO*( N - INFIS - I + 1 )/I
  920 CONTINUE
!
!     First move any doubly infinite limits to innermost positions
!
      IF ( INFIS .LT. N ) THEN
         DO 930 I = N, N-INFIS+1, -1
            IF ( INFI(I) .GE. 0 ) THEN
               DO 940 J = 1,I-1
                  IF ( INFI(J) .LT. 0 ) THEN
                     DO 950 K = 1, J-1
                        TMP = U(J,K)
                        U(J,K) = U(I,K)
                        U(I,K) = TMP
  950                CONTINUE
                     DO 960 K = J+1, I-1
                        TMP = U(I,K)
                        U(I,K) = U(K,J)
                        U(K,J) = TMP
 960                 CONTINUE
                     DO 970 K = I+1, N
                        TMP = U(K,J)
                        U(K,J) = U(K,I)
                        U(K,I) = TMP
 970                 CONTINUE
                     TMP = A(J)
                     A(J) = A(I)
                     A(I) = TMP
                     TMP = B(J)
                     B(J) = B(I)
                     B(I) = TMP
                     TMP = INFI(J)
                     INFI(J) = INFI(I)
                     INFI(I) = INT(TMP)
                     GO TO 930
                  ENDIF
 940           CONTINUE
            ENDIF
 930     CONTINUE
      ENDIF
!
!     Determine Cholesky decomposition
!
      DO 980 J = 1, N-INFIS
         DO 982 I = J, N-INFIS
            TMP = U(I,J)
            DO 984 K = 1, J-1
               TMP = TMP - U(I,K)*U(J,K)
  984       CONTINUE
            IF ( I .EQ. J ) THEN
               U(J,J) = SQRT( MAX( TMP, ZERO ) )
            ELSE IF ( U(I,I) .GT. 0 ) THEN
               U(I,J) = TMP/U(J,J)
            ELSE
               U(I,J) = 0.0D0
            END IF
 982     CONTINUE
 980  CONTINUE
      DO 990 I = 1, N-INFIS
         IF ( U(I,I) .GT. 0 ) THEN
            IF ( INFI(I) .NE. 0 ) A(I) = A(I)/U(I,I)
            IF ( INFI(I) .NE. 1 ) B(I) = B(I)/U(I,I)
            DO 995 J = 1,I
               U(I,J) = U(I,J)/U(I,I)
 995        CONTINUE
         ENDIF
 990  CONTINUE
      CALL LIMITS( A(1), B(1), INFI(1), D, E )
!
      RETURN
      END FUNCTION SPNRML
      SUBROUTINE SPOCO(A,LDA,N,RCOND,Z,INFO)
!***BEGIN PROLOGUE  SPOCO
!***DATE WRITTEN   780814   (YYMMDD)
!***REVISION DATE  820801   (YYMMDD)
!***CATEGORY NO.  D2B1B
!***KEYWORDS  CONDITION,FACTOR,LINEAR ALGEBRA,LINPACK,MATRIX,
!             POSITIVE DEFINITE
!***AUTHOR  MOLER, C. B., (U. OF NEW MEXICO)
!***PURPOSE  Factors a real SYMMETRIC POSITIVE DEFINITE MATRIX
!            and estimates the condition number of the matrix.
!***DESCRIPTION
!
!     SPOCO factors a real symmetric positive definite matrix
!     and estimates the condition of the matrix.
!
!     If  RCOND  is not needed, SPOFA is slightly faster.
!     To solve  A*X = B , follow SPOCO by SPOSL.
!     To compute  INVERSE(A)*C , follow SPOCO by SPOSL.
!     To compute  DETERMINANT(A) , follow SPOCO by SPODI.
!     To compute  INVERSE(A) , follow SPOCO by SPODI.
!
!     On Entry
!
!        A       REAL(LDA, N)
!                the symmetric matrix to be factored.  Only the
!                diagonal and upper triangle are used.
!
!        LDA     INTEGER
!                the leading dimension of the array  A .
!
!        N       INTEGER
!                the order of the matrix  A .
!
!     On Return
!
!        A       an upper triangular matrix  R  so that  A = TRANS(R)*R
!                where  TRANS(R)  is the transpose.
!                The strict lower triangle is unaltered.
!                If  INFO .NE. 0 , the factorization is not complete.
!
!        RCOND   REAL
!                an estimate of the reciprocal condition of  A .
!                For the system  A*X = B , relative perturbations
!                in  A  and  B  of size  EPSILON  may cause
!                relative perturbations in  X  of size  EPSILON/RCOND .
!                If  RCOND  is so small that the logical expression
!                           1.0 + RCOND .EQ. 1.0
!                is true, then  A  may be singular to working
!                precision.  In particular,  RCOND  is zero  if
!                exact singularity is detected or the estimate
!                underflows.  If INFO .NE. 0 , RCOND is unchanged.
!
!        Z       REAL(N)
!                a work vector whose contents are usually unimportant.
!                If  A  is close to a singular matrix, then  Z  is
!                an approximate null vector in the sense that
!                NORM(A*Z) = RCOND*NORM(A)*NORM(Z) .
!                If  INFO .NE. 0 , Z  is unchanged.
!
!        INFO    INTEGER
!                = 0  for normal return.
!                = K  signals an error condition.  The leading minor
!                     of order  K  is not positive definite.
!
!     LINPACK.  This version dated 08/14/78 .
!     Cleve Moler, University of New Mexico, Argonne National Lab.
!
!     Subroutines and Functions
!
!     LINPACK SPOFA
!     BLAS SAXPY,SDOT,SSCAL,SASUM
!     Fortran ABS,AMAX1,REAL,SIGN
!***REFERENCES  DONGARRA J.J., BUNCH J.R., MOLER C.B., STEWART G.W.,
!                 *LINPACK USERS  GUIDE*, SIAM, 1979.
!***ROUTINES CALLED  SASUM,SAXPY,SDOT,SPOFA,SSCAL
!***END PROLOGUE  SPOCO
      INTEGER LDA,N,INFO
      REAL A(LDA,1),Z(1)
      REAL RCOND
!
      REAL SDOT,EK,T,WK,WKM
      REAL ANORM,S,SASUM,SM,YNORM
      INTEGER I,J,JM1,K,KB,KP1
!
!     FIND NORM OF A USING ONLY UPPER HALF
!
!***FIRST EXECUTABLE STATEMENT  SPOCO
      DO 30 J = 1, N
         Z(J) = SASUM(J,A(1,J),1)
         JM1 = J - 1
         IF (JM1 .LT. 1) GO TO 20
         DO 10 I = 1, JM1
            Z(I) = Z(I) + ABS(A(I,J))
   10    CONTINUE
   20    CONTINUE
   30 CONTINUE
      ANORM = 0.0E0
      DO 40 J = 1, N
         ANORM = AMAX1(ANORM,Z(J))
   40 CONTINUE
!
!     FACTOR
!
      CALL SPOFA(A,LDA,N,INFO)
      IF (INFO .NE. 0) GO TO 180
!
!        RCOND = 1/(NORM(A)*(ESTIMATE OF NORM(INVERSE(A)))) .
!        ESTIMATE = NORM(Z)/NORM(Y) WHERE  A*Z = Y  AND  A*Y = E .
!        THE COMPONENTS OF  E  ARE CHOSEN TO CAUSE MAXIMUM LOCAL
!        GROWTH IN THE ELEMENTS OF W  WHERE  TRANS(R)*W = E .
!        THE VECTORS ARE FREQUENTLY RESCALED TO AVOID OVERFLOW.
!
!        SOLVE TRANS(R)*W = E
!
         EK = 1.0E0
         DO 50 J = 1, N
            Z(J) = 0.0E0
   50    CONTINUE
         DO 110 K = 1, N
            IF (Z(K) .NE. 0.0E0) EK = SIGN(EK,-Z(K))
            IF (ABS(EK-Z(K)) .LE. A(K,K)) GO TO 60
               S = A(K,K)/ABS(EK-Z(K))
               CALL SSCAL(N,S,Z,1)
               EK = S*EK
   60       CONTINUE
            WK = EK - Z(K)
            WKM = -EK - Z(K)
            S = ABS(WK)
            SM = ABS(WKM)
            WK = WK/A(K,K)
            WKM = WKM/A(K,K)
            KP1 = K + 1
            IF (KP1 .GT. N) GO TO 100
               DO 70 J = KP1, N
                  SM = SM + ABS(Z(J)+WKM*A(K,J))
                  Z(J) = Z(J) + WK*A(K,J)
                  S = S + ABS(Z(J))
   70          CONTINUE
               IF (S .GE. SM) GO TO 90
                  T = WKM - WK
                  WK = WKM
                  DO 80 J = KP1, N
                     Z(J) = Z(J) + T*A(K,J)
   80             CONTINUE
   90          CONTINUE
  100       CONTINUE
            Z(K) = WK
  110    CONTINUE
         S = 1.0E0/SASUM(N,Z,1)
         CALL SSCAL(N,S,Z,1)
!
!        SOLVE R*Y = W
!
         DO 130 KB = 1, N
            K = N + 1 - KB
            IF (ABS(Z(K)) .LE. A(K,K)) GO TO 120
               S = A(K,K)/ABS(Z(K))
               CALL SSCAL(N,S,Z,1)
  120       CONTINUE
            Z(K) = Z(K)/A(K,K)
            T = -Z(K)
            CALL SAXPY(K-1,T,A(1,K),1,Z(1),1)
  130    CONTINUE
         S = 1.0E0/SASUM(N,Z,1)
         CALL SSCAL(N,S,Z,1)
!
         YNORM = 1.0E0
!
!        SOLVE TRANS(R)*V = Y
!
         DO 150 K = 1, N
            Z(K) = Z(K) - SDOT(K-1,A(1,K),1,Z(1),1)
            IF (ABS(Z(K)) .LE. A(K,K)) GO TO 140
               S = A(K,K)/ABS(Z(K))
               CALL SSCAL(N,S,Z,1)
               YNORM = S*YNORM
  140       CONTINUE
            Z(K) = Z(K)/A(K,K)
  150    CONTINUE
         S = 1.0E0/SASUM(N,Z,1)
         CALL SSCAL(N,S,Z,1)
         YNORM = S*YNORM
!
!        SOLVE R*Z = V
!
         DO 170 KB = 1, N
            K = N + 1 - KB
            IF (ABS(Z(K)) .LE. A(K,K)) GO TO 160
               S = A(K,K)/ABS(Z(K))
               CALL SSCAL(N,S,Z,1)
               YNORM = S*YNORM
  160       CONTINUE
            Z(K) = Z(K)/A(K,K)
            T = -Z(K)
            CALL SAXPY(K-1,T,A(1,K),1,Z(1),1)
  170    CONTINUE
!        MAKE ZNORM = 1.0
         S = 1.0E0/SASUM(N,Z,1)
         CALL SSCAL(N,S,Z,1)
         YNORM = S*YNORM
!
         IF (ANORM .NE. 0.0E0) RCOND = YNORM/ANORM
         IF (ANORM .EQ. 0.0E0) RCOND = 0.0E0
  180 CONTINUE
      RETURN
      END SUBROUTINE SPOCO
      SUBROUTINE SPOFA(A,LDA,N,INFO)
!***BEGIN PROLOGUE  SPOFA
!***DATE WRITTEN   780814   (YYMMDD)
!***REVISION DATE  820801   (YYMMDD)
!***CATEGORY NO.  D2B1B
!***KEYWORDS  FACTOR,LINEAR ALGEBRA,LINPACK,MATRIX,POSITIVE DEFINITE
!***AUTHOR  MOLER, C. B., (U. OF NEW MEXICO)
!***PURPOSE  Factors a real SYMMETRIC POSITIVE DEFINITE matrix.
!***DESCRIPTION
!
!     SPOFA factors a real symmetric positive definite matrix.
!
!     SPOFA is usually called by SPOCO, but it can be called
!     directly with a saving in time if  RCOND  is not needed.
!     (Time for SPOCO) = (1 + 18/N)*(Time for SPOFA) .
!
!     On Entry
!
!        A       REAL(LDA, N)
!                the symmetric matrix to be factored.  Only the
!                diagonal and upper triangle are used.
!
!        LDA     INTEGER
!                the leading dimension of the array  A .
!
!        N       INTEGER
!                the order of the matrix  A .
!
!     On Return
!
!        A       an upper triangular matrix  R  so that  A = TRANS(R)*R
!                where  TRANS(R)  is the transpose.
!                The strict lower triangle is unaltered.
!                If  INFO .NE. 0 , the factorization is not complete.
!
!        INFO    INTEGER
!                = 0  for normal return.
!                = K  signals an error condition.  The leading minor
!                     of order  K  is not positive definite.
!
!     LINPACK.  This version dated 08/14/78 .
!     Cleve Moler, University of New Mexico, Argonne National Lab.
!
!     Subroutines and Functions
!
!     BLAS SDOT
!     Fortran SQRT
!***REFERENCES  DONGARRA J.J., BUNCH J.R., MOLER C.B., STEWART G.W.,
!                 *LINPACK USERS  GUIDE*, SIAM, 1979.
!***ROUTINES CALLED  SDOT
!***END PROLOGUE  SPOFA
      INTEGER LDA,N,INFO
      REAL A(LDA,1)
!
      REAL SDOT,T
      REAL S
      INTEGER J,JM1,K
!     BEGIN BLOCK WITH ...EXITS TO 40
!
!
!***FIRST EXECUTABLE STATEMENT  SPOFA
         DO 30 J = 1, N
            INFO = J
            S = 0.0E0
            JM1 = J - 1
            IF (JM1 .LT. 1) GO TO 20
            DO 10 K = 1, JM1
               T = A(K,J) - SDOT(K-1,A(1,K),1,A(1,J),1)
               T = T/A(K,K)
               A(K,J) = T
               S = S + T*T
   10       CONTINUE
   20       CONTINUE
            S = A(J,J) - S
!     ......EXIT
            IF (S .LE. 0.0E0) GO TO 40
            A(J,J) = SQRT(S)
   30    CONTINUE
         INFO = 0
   40 CONTINUE
      RETURN
      END SUBROUTINE SPOFA
      SUBROUTINE SQRDC(X,LDX,N,P,QRAUX,JPVT,WORK,JOB)
!***BEGIN PROLOGUE  SQRDC
!***DATE WRITTEN   780814   (YYMMDD)
!***REVISION DATE  820801   (YYMMDD)
!***CATEGORY NO.  D5
!***KEYWORDS  DECOMPOSITION,LINEAR ALGEBRA,LINPACK,MATRIX,
!             ORTHOGONAL TRIANGULAR
!***AUTHOR  STEWART, G. W., (U. OF MARYLAND)
!***PURPOSE  Uses Householder transformations to compute the QR
!            factorization of an N by P matrix X.  Column pivoting is
!            a users option.
!***DESCRIPTION
!
!     SQRDC uses Householder transformations to compute the QR
!     factorization of an N by P matrix X.  Column pivoting
!     based on the 2-norms of the reduced columns may be
!     performed at the user's option.
!
!     On Entry
!
!        X       REAL(LDX,P), where LDX .GE. N.
!                X contains the matrix whose decomposition is to be
!                computed.
!
!        LDX     INTEGER.
!                LDX is the leading dimension of the array X.
!
!        N       INTEGER.
!                N is the number of rows of the matrix X.
!
!        P       INTEGER.
!                P is the number of columns of the matrix X.
!
!        JPVT    INTEGER(P).
!                JPVT contains integers that control the selection
!                of the pivot columns.  The K-th column X(K) of X
!                is placed in one of three classes according to the
!                value of JPVT(K).
!
!                   If JPVT(K) .GT. 0, then X(K) is an initial
!                                      column.
!
!                   If JPVT(K) .EQ. 0, then X(K) is a free column.
!
!                   If JPVT(K) .LT. 0, then X(K) is a final column.
!
!                Before the decomposition is computed, initial columns
!                are moved to the beginning of the array X and final
!                columns to the end.  Both initial and final columns
!                are frozen in place during the computation and only
!                free columns are moved.  At the K-th stage of the
!                reduction, if X(K) is occupied by a free column,
!                it is interchanged with the free column of largest
!                reduced norm.  JPVT is not referenced if
!                JOB .EQ. 0.
!
!        WORK    REAL(P).
!                WORK is a work array.  WORK is not referenced if
!                JOB .EQ. 0.
!
!        JOB     INTEGER.
!                JOB is an integer that initiates column pivoting.
!                If JOB .EQ. 0, no pivoting is done.
!                If JOB .NE. 0, pivoting is done.
!
!     On Return
!
!        X       X contains in its upper triangle the upper
!                triangular matrix R of the QR factorization.
!                Below its diagonal X contains information from
!                which the orthogonal part of the decomposition
!                can be recovered.  Note that if pivoting has
!                been requested, the decomposition is not that
!                of the original matrix X but that of X
!                with its columns permuted as described by JPVT.
!
!        QRAUX   REAL(P).
!                QRAUX contains further information required to recover
!                the orthogonal part of the decomposition.
!
!        JPVT    JPVT(K) contains the index of the column of the
!                original matrix that has been interchanged into
!                the K-th column, if pivoting was requested.
!
!     LINPACK.  This version dated 08/14/78 .
!     G. W. Stewart, University of Maryland, Argonne National Lab.
!
!     SQRDC uses the following functions and subprograms.
!
!     BLAS SAXPY,SDOT,SSCAL,SSWAP,SNRM2
!     Fortran ABS,AMAX1,MIN0,SQRT
!***REFERENCES  DONGARRA J.J., BUNCH J.R., MOLER C.B., STEWART G.W.,
!                 *LINPACK USERS  GUIDE*, SIAM, 1979.
!***ROUTINES CALLED  SAXPY,SDOT,SNRM2,SSCAL,SSWAP
!***END PROLOGUE  SQRDC
      INTEGER LDX,N,P,JOB
      INTEGER JPVT(1)
      REAL X(LDX,1),QRAUX(1),WORK(1)
!
      INTEGER J,JP,L,LP1,LUP,MAXJ,PL,PU
      REAL MAXNRM,SNRM2,TT
      REAL SDOT,NRMXL,T
      LOGICAL NEGJ,SWAPJ
!
!***FIRST EXECUTABLE STATEMENT  SQRDC
      PL = 1
      PU = 0
      IF (JOB .EQ. 0) GO TO 60
!
!        PIVOTING HAS BEEN REQUESTED.  REARRANGE THE COLUMNS
!        ACCORDING TO JPVT.
!
         DO 20 J = 1, P
            SWAPJ = JPVT(J) .GT. 0
            NEGJ = JPVT(J) .LT. 0
            JPVT(J) = J
            IF (NEGJ) JPVT(J) = -J
            IF (.NOT.SWAPJ) GO TO 10
               IF (J .NE. PL) CALL SSWAP(N,X(1,PL),1,X(1,J),1)
               JPVT(J) = JPVT(PL)
               JPVT(PL) = J
               PL = PL + 1
   10       CONTINUE
   20    CONTINUE
         PU = P
         DO 50 JJ = 1, P
            J = P - JJ + 1
            IF (JPVT(J) .GE. 0) GO TO 40
               JPVT(J) = -JPVT(J)
               IF (J .EQ. PU) GO TO 30
                  CALL SSWAP(N,X(1,PU),1,X(1,J),1)
                  JP = JPVT(PU)
                  JPVT(PU) = JPVT(J)
                  JPVT(J) = JP
   30          CONTINUE
               PU = PU - 1
   40       CONTINUE
   50    CONTINUE
   60 CONTINUE
!
!     COMPUTE THE NORMS OF THE FREE COLUMNS.
!
      IF (PU .LT. PL) GO TO 80
      DO 70 J = PL, PU
         QRAUX(J) = SNRM2(N,X(1,J),1)
         WORK(J) = QRAUX(J)
   70 CONTINUE
   80 CONTINUE
!
!     PERFORM THE HOUSEHOLDER REDUCTION OF X.
!
      LUP = MIN0(N,P)
      DO 200 L = 1, LUP
         IF (L .LT. PL .OR. L .GE. PU) GO TO 120
!
!           LOCATE THE COLUMN OF LARGEST NORM AND BRING IT
!           INTO THE PIVOT POSITION.
!
            MAXNRM = 0.0E0
            MAXJ = L
            DO 100 J = L, PU
               IF (QRAUX(J) .LE. MAXNRM) GO TO 90
                  MAXNRM = QRAUX(J)
                  MAXJ = J
   90          CONTINUE
  100       CONTINUE
            IF (MAXJ .EQ. L) GO TO 110
               CALL SSWAP(N,X(1,L),1,X(1,MAXJ),1)
               QRAUX(MAXJ) = QRAUX(L)
               WORK(MAXJ) = WORK(L)
               JP = JPVT(MAXJ)
               JPVT(MAXJ) = JPVT(L)
               JPVT(L) = JP
  110       CONTINUE
  120    CONTINUE
         QRAUX(L) = 0.0E0
         IF (L .EQ. N) GO TO 190
!
!           COMPUTE THE HOUSEHOLDER TRANSFORMATION FOR COLUMN L.
!
            NRMXL = SNRM2(N-L+1,X(L,L),1)
            IF (NRMXL .EQ. 0.0E0) GO TO 180
               IF (X(L,L) .NE. 0.0E0) NRMXL = SIGN(NRMXL,X(L,L))
               CALL SSCAL(N-L+1,1.0E0/NRMXL,X(L,L),1)
               X(L,L) = 1.0E0 + X(L,L)
!
!              APPLY THE TRANSFORMATION TO THE REMAINING COLUMNS,
!              UPDATING THE NORMS.
!
               LP1 = L + 1
               IF (P .LT. LP1) GO TO 170
               DO 160 J = LP1, P
                  T = -SDOT(N-L+1,X(L,L),1,X(L,J),1)/X(L,L)
                  CALL SAXPY(N-L+1,T,X(L,L),1,X(L,J),1)
                  IF (J .LT. PL .OR. J .GT. PU) GO TO 150
                  IF (QRAUX(J) .EQ. 0.0E0) GO TO 150
                     TT = 1.0E0 - (ABS(X(L,J))/QRAUX(J))**2
                     TT = AMAX1(TT,0.0E0)
                     T = TT
                     TT = 1.0E0 + 0.05E0*TT*(QRAUX(J)/WORK(J))**2
                     IF (TT .EQ. 1.0E0) GO TO 130
                        QRAUX(J) = QRAUX(J)*SQRT(T)
                     GO TO 140
  130                CONTINUE
                        QRAUX(J) = SNRM2(N-L,X(L+1,J),1)
                        WORK(J) = QRAUX(J)
  140                CONTINUE
  150             CONTINUE
  160          CONTINUE
  170          CONTINUE
!
!              SAVE THE TRANSFORMATION.
!
               QRAUX(L) = X(L,L)
               X(L,L) = -NRMXL
  180       CONTINUE
  190    CONTINUE
  200 CONTINUE
      RETURN
      END SUBROUTINE SQRDC
      SUBROUTINE SQRSL(X,LDX,N,K,QRAUX,Y,QY,QTY,B,RSD,XB,JOB,INFO)
!***BEGIN PROLOGUE  SQRSL
!***DATE WRITTEN   780814   (YYMMDD)
!***REVISION DATE  820801   (YYMMDD)
!***CATEGORY NO.  D9,D2A1
!***KEYWORDS  LINEAR ALGEBRA,LINPACK,MATRIX,ORTHOGONAL TRIANGULAR,SOLVE
!***AUTHOR  STEWART, G. W., (U. OF MARYLAND)
!***PURPOSE  Applies the output of SQRDC to compute coordinate trans-
!            formations projections, and least squares solutions.
!***DESCRIPTION
!
!     SQRSL applies the output of SQRDC to compute coordinate
!     transformations, projections, and least squares solutions.
!     For K .LE. MIN(N,P), let XK be the matrix
!
!            XK = (X(JPVT(1)),X(JPVT(2)), ... ,X(JPVT(K)))
!
!     formed from columnns JPVT(1), ... ,JPVT(K) of the original
!     N x P matrix X that was input to SQRDC (if no pivoting was
!     done, XK consists of the first K columns of X in their
!     original order).  SQRDC produces a factored orthogonal matrix Q
!     and an upper triangular matrix R such that
!
!              XK = Q * (R)
!                       (0)
!
!     This information is contained in coded form in the arrays
!     X and QRAUX.
!
!     On Entry
!
!        X      REAL(LDX,P)
!               X contains the output of SQRDC.
!
!        LDX    INTEGER
!               LDX is the leading dimension of the array X.
!
!        N      INTEGER
!               N is the number of rows of the matrix XK.  It must
!               have the same value as N in SQRDC.
!
!        K      INTEGER
!               K is the number of columns of the matrix XK.  K
!               must not be greater than MIN(N,P), where P is the
!               same as in the calling sequence to SQRDC.
!
!        QRAUX  REAL(P)
!               QRAUX contains the auxiliary output from SQRDC.
!
!        Y      REAL(N)
!               Y contains an N-vector that is to be manipulated
!               by SQRSL.
!
!        JOB    INTEGER
!               JOB specifies what is to be computed.  JOB has
!               the decimal expansion ABCDE, with the following
!               meaning.
!
!                    If A .NE. 0, compute QY.
!                    If B,C,D, or E .NE. 0, compute QTY.
!                    If C .NE. 0, compute B.
!                    If D .NE. 0, compute RSD.
!                    If E .NE. 0, compute XB.
!
!               Note that a request to compute B, RSD, or XB
!               automatically triggers the computation of QTY, for
!               which an array must be provided in the calling
!               sequence.
!
!     On Return
!
!        QY     REAL(N).
!               QY contains Q*Y, if its computation has been
!               requested.
!
!        QTY    REAL(N).
!               QTY contains TRANS(Q)*Y, if its computation has
!               been requested.  Here TRANS(Q) is the
!               transpose of the matrix Q.
!
!        B      REAL(K)
!               B contains the solution of the least squares problem
!
!                    minimize norm2(Y - XK*B),
!
!               if its computation has been requested.  (Note that
!               if pivoting was requested in SQRDC, the J-th
!               component of B will be associated with column JPVT(J)
!               of the original matrix X that was input into SQRDC.)
!
!        RSD    REAL(N).
!               RSD contains the least squares residual Y - XK*B,
!               if its computation has been requested.  RSD is
!               also the orthogonal projection of Y onto the
!               orthogonal complement of the column space of XK.
!
!        XB     REAL(N).
!               XB contains the least squares approximation XK*B,
!               if its computation has been requested.  XB is also
!               the orthogonal projection of Y onto the column space
!               of X.
!
!        INFO   INTEGER.
!               INFO is zero unless the computation of B has
!               been requested and R is exactly singular.  In
!               this case, INFO is the index of the first zero
!               diagonal element of R and B is left unaltered.
!
!     The parameters QY, QTY, B, RSD, and XB are not referenced
!     if their computation is not requested and in this case
!     can be replaced by dummy variables in the calling program.
!     To save storage, the user may in some cases use the same
!     array for different parameters in the calling sequence.  A
!     frequently occuring example is when one wishes to compute
!     any of B, RSD, or XB and does not need Y or QTY.  In this
!     case one may identify Y, QTY, and one of B, RSD, or XB, while
!     providing separate arrays for anything else that is to be
!     computed.  Thus the calling sequence
!
!          CALL SQRSL(X,LDX,N,K,QRAUX,Y,DUM,Y,B,Y,DUM,110,INFO)
!
!     will result in the computation of B and RSD, with RSD
!     overwriting Y.  More generally, each item in the following
!     list contains groups of permissible identifications for
!     a single callinng sequence.
!
!          1. (Y,QTY,B) (RSD) (XB) (QY)
!
!          2. (Y,QTY,RSD) (B) (XB) (QY)
!
!          3. (Y,QTY,XB) (B) (RSD) (QY)
!
!          4. (Y,QY) (QTY,B) (RSD) (XB)
!
!          5. (Y,QY) (QTY,RSD) (B) (XB)
!
!          6. (Y,QY) (QTY,XB) (B) (RSD)
!
!     In any group the value returned in the array allocated to
!     the group corresponds to the last member of the group.
!
!     LINPACK.  This version dated 08/14/78 .
!     G. W. Stewart, University of Maryland, Argonne National Lab.
!
!     SQRSL uses the following functions and subprograms.
!
!     BLAS SAXPY,SCOPY,SDOT
!     Fortran ABS,MIN0,MOD
!***REFERENCES  DONGARRA J.J., BUNCH J.R., MOLER C.B., STEWART G.W.,
!                 *LINPACK USERS  GUIDE*, SIAM, 1979.
!***ROUTINES CALLED  SAXPY,SCOPY,SDOT
!***END PROLOGUE  SQRSL
      INTEGER LDX,N,K,JOB,INFO
      REAL X(LDX,1),QRAUX(1),Y(1),QY(1),QTY(1),B(1),RSD(1),XB(1)
!
      INTEGER I,J,JJ,JU,KP1
      REAL SDOT,T,TEMP
      LOGICAL CB,CQY,CQTY,CR,CXB
!
!     SET INFO FLAG.
!
!***FIRST EXECUTABLE STATEMENT  SQRSL
      INFO = 0
!
!     DETERMINE WHAT IS TO BE COMPUTED.
!
      CQY = JOB/10000 .NE. 0
      CQTY = MOD(JOB,10000) .NE. 0
      CB = MOD(JOB,1000)/100 .NE. 0
      CR = MOD(JOB,100)/10 .NE. 0
      CXB = MOD(JOB,10) .NE. 0
      JU = MIN0(K,N-1)
!
!     SPECIAL ACTION WHEN N=1.
!
      IF (JU .NE. 0) GO TO 40
         IF (CQY) QY(1) = Y(1)
         IF (CQTY) QTY(1) = Y(1)
         IF (CXB) XB(1) = Y(1)
         IF (.NOT.CB) GO TO 30
            IF (X(1,1) .NE. 0.0E0) GO TO 10
               INFO = 1
            GO TO 20
   10       CONTINUE
               B(1) = Y(1)/X(1,1)
   20       CONTINUE
   30    CONTINUE
         IF (CR) RSD(1) = 0.0E0
      GO TO 250
   40 CONTINUE
!
!        SET UP TO COMPUTE QY OR QTY.
!
         IF (CQY) CALL SCOPY(N,Y,1,QY,1)
         IF (CQTY) CALL SCOPY(N,Y,1,QTY,1)
         IF (.NOT.CQY) GO TO 70
!
!           COMPUTE QY.
!
            DO 60 JJ = 1, JU
               J = JU - JJ + 1
               IF (QRAUX(J) .EQ. 0.0E0) GO TO 50
                  TEMP = X(J,J)
                  X(J,J) = QRAUX(J)
                  T = -SDOT(N-J+1,X(J,J),1,QY(J),1)/X(J,J)
                  CALL SAXPY(N-J+1,T,X(J,J),1,QY(J),1)
                  X(J,J) = TEMP
   50          CONTINUE
   60       CONTINUE
   70    CONTINUE
         IF (.NOT.CQTY) GO TO 100
!
!           COMPUTE TRANS(Q)*Y.
!
            DO 90 J = 1, JU
               IF (QRAUX(J) .EQ. 0.0E0) GO TO 80
                  TEMP = X(J,J)
                  X(J,J) = QRAUX(J)
                  T = -SDOT(N-J+1,X(J,J),1,QTY(J),1)/X(J,J)
                  CALL SAXPY(N-J+1,T,X(J,J),1,QTY(J),1)
                  X(J,J) = TEMP
   80          CONTINUE
   90       CONTINUE
  100    CONTINUE
!
!        SET UP TO COMPUTE B, RSD, OR XB.
!
         IF (CB) CALL SCOPY(K,QTY,1,B,1)
         KP1 = K + 1
         IF (CXB) CALL SCOPY(K,QTY,1,XB,1)
         IF (CR .AND. K .LT. N) CALL SCOPY(N-K,QTY(KP1),1,RSD(KP1),1)
         IF (.NOT.CXB .OR. KP1 .GT. N) GO TO 120
            DO 110 I = KP1, N
               XB(I) = 0.0E0
  110       CONTINUE
  120    CONTINUE
         IF (.NOT.CR) GO TO 140
            DO 130 I = 1, K
               RSD(I) = 0.0E0
  130       CONTINUE
  140    CONTINUE
         IF (.NOT.CB) GO TO 190
!
!           COMPUTE B.
!
            DO 170 JJ = 1, K
               J = K - JJ + 1
               IF (X(J,J) .NE. 0.0E0) GO TO 150
                  INFO = J
!           ......EXIT
                  GO TO 180
  150          CONTINUE
               B(J) = B(J)/X(J,J)
               IF (J .EQ. 1) GO TO 160
                  T = -B(J)
                  CALL SAXPY(J-1,T,X(1,J),1,B,1)
  160          CONTINUE
  170       CONTINUE
  180       CONTINUE
  190    CONTINUE
         IF (.NOT.CR .AND. .NOT.CXB) GO TO 240
!
!           COMPUTE RSD OR XB AS REQUIRED.
!
            DO 230 JJ = 1, JU
               J = JU - JJ + 1
               IF (QRAUX(J) .EQ. 0.0E0) GO TO 220
                  TEMP = X(J,J)
                  X(J,J) = QRAUX(J)
                  IF (.NOT.CR) GO TO 200
                     T = -SDOT(N-J+1,X(J,J),1,RSD(J),1)/X(J,J)
                     CALL SAXPY(N-J+1,T,X(J,J),1,RSD(J),1)
  200             CONTINUE
                  IF (.NOT.CXB) GO TO 210
                     T = -SDOT(N-J+1,X(J,J),1,XB(J),1)/X(J,J)
                     CALL SAXPY(N-J+1,T,X(J,J),1,XB(J),1)
  210             CONTINUE
                  X(J,J) = TEMP
  220          CONTINUE
  230       CONTINUE
  240    CONTINUE
  250 CONTINUE
      RETURN
      END SUBROUTINE SQRSL
      SUBROUTINE SROT(N,SX,INCX,SY,INCY,SC,SS)
!***BEGIN PROLOGUE  SROT
!***DATE WRITTEN   791001   (YYMMDD)
!***REVISION DATE  820801   (YYMMDD)
!***CATEGORY NO.  D1A8
!***KEYWORDS  BLAS,GIVENS ROTATION,LINEAR ALGEBRA,VECTOR
!***AUTHOR  LAWSON, C. L., (JPL)
!           HANSON, R. J., (SNLA)
!           KINCAID, D. R., (U. OF TEXAS)
!           KROGH, F. T., (JPL)
!***PURPOSE  Apply s.p. Givens rotation
!***DESCRIPTION
!
!                B L A S  Subprogram
!    Description of Parameters
!
!     --Input--
!        N  number of elements in input vector(s)
!       SX  single precision vector with N elements
!     INCX  storage spacing between elements of SX
!       SY  single precision vector with N elements
!     INCY  storage spacing between elements of SY
!       SC  element of rotation matrix
!       SS  element of rotation matrix
!
!     --Output--
!       SX  rotated vector SX (unchanged if N .LE. 0)
!       SY  rotated vector SY (unchanged if N .LE. 0)
!
!     Multiply the 2 x 2 matrix  ( SC SS) times the 2 x N matrix (SX**T)
!                                (-SS SC)                        (SY**T)
!     where **T indicates transpose.  The elements of SX are in
!     SX(LX+I*INCX), I = 0 to N-1, where LX = 1 if INCX .GE. 0, else
!     LX = (-INCX)*N, and similarly for SY using LY and INCY.
!***REFERENCES  LAWSON C.L., HANSON R.J., KINCAID D.R., KROGH F.T.,
!                 *BASIC LINEAR ALGEBRA SUBPROGRAMS FOR FORTRAN USAGE*,
!                 ALGORITHM NO. 539, TRANSACTIONS ON MATHEMATICAL
!                 SOFTWARE, VOLUME 5, NUMBER 3, SEPTEMBER 1979, 308-323
!***ROUTINES CALLED  (NONE)
!***END PROLOGUE  SROT
!
      REAL             SX,SY,SC,SS,ZERO,ONE,W,Z
      DIMENSION SX(*),SY(*)
      DATA ZERO,ONE/0.E0,1.E0/
!***FIRST EXECUTABLE STATEMENT  SROT
      IF(N .LE. 0 .OR. (SS .EQ. ZERO .AND. SC .EQ. ONE)) GO TO 40
      IF(.NOT. (INCX .EQ. INCY .AND. INCX .GT. 0)) GO TO 20
!
           NSTEPS=INCX*N
           DO 10 I=1,NSTEPS,INCX
                W=SX(I)
                Z=SY(I)
                SX(I)=SC*W+SS*Z
                SY(I)=-SS*W+SC*Z
   10           CONTINUE
           GO TO 40
!
   20 CONTINUE
           KX=1
           KY=1
!
           IF(INCX .LT. 0) KX=1-(N-1)*INCX
           IF(INCY .LT. 0) KY=1-(N-1)*INCY
!
           DO 30 I=1,N
                W=SX(KX)
                Z=SY(KY)
                SX(KX)=SC*W+SS*Z
                SY(KY)=-SS*W+SC*Z
                KX=KX+INCX
                KY=KY+INCY
   30           CONTINUE
   40 CONTINUE
!
      RETURN
      END SUBROUTINE SROT
      SUBROUTINE SROTG(SA,SB,SC,SS)
!***BEGIN PROLOGUE  SROTG
!***DATE WRITTEN   791001   (YYMMDD)
!***REVISION DATE  820801   (YYMMDD)
!***CATEGORY NO.  D1B10
!***KEYWORDS  BLAS,GIVENS ROTATION,LINEAR ALGEBRA,VECTOR
!***AUTHOR  LAWSON, C. L., (JPL)
!           HANSON, R. J., (SNLA)
!           KINCAID, D. R., (U. OF TEXAS)
!           KROGH, F. T., (JPL)
!***PURPOSE  Construct s.p. plane Givens rotation
!***DESCRIPTION
!
!                B L A S  Subprogram
!    Description of Parameters
!
!     --Input--
!       SA  single precision scalar
!       SB  single precision scalar
!
!     --Output--
!       SA  single precision result R
!       SB  single precision result Z
!       SC  single precision result
!       SS  single precision result
!
!     Designed by C. L. Lawson, JPL, 1977 Sept 08
!
!
!     Construct the Givens transformation
!
!         ( SC  SS )
!     G = (        ) ,    SC**2 + SS**2 = 1 ,
!         (-SS  SC )
!
!     which zeros the second entry of the 2-vector  (SA,SB)**T.
!
!     The quantity R = (+/-)SQRT(SA**2 + SB**2) overwrites SA in
!     storage.  The value of SB is overwritten by a value Z which
!     allows SC and SS to be recovered by the following algorithm:
!
!           If Z=1  set  SC=0.  and  SS=1.
!           If ABS(Z) .LT. 1  set  SC=SQRT(1-Z**2)  and  SS=Z
!           If ABS(Z) .GT. 1  set  SC=1/Z  and  SS=SQRT(1-SC**2)
!
!     Normally, the subprogram SROT(N,SX,INCX,SY,INCY,SC,SS) will
!     next be called to apply the transformation to a 2 by N matrix.
!***REFERENCES  LAWSON C.L., HANSON R.J., KINCAID D.R., KROGH F.T.,
!                 *BASIC LINEAR ALGEBRA SUBPROGRAMS FOR FORTRAN USAGE*,
!                 ALGORITHM NO. 539, TRANSACTIONS ON MATHEMATICAL
!                 SOFTWARE, VOLUME 5, NUMBER 3, SEPTEMBER 1979, 308-323
!***ROUTINES CALLED  (NONE)
!***END PROLOGUE  SROTG
!
!***FIRST EXECUTABLE STATEMENT  SROTG
      IF (ABS(SA) .LE. ABS(SB)) GO TO 10
!
! *** HERE ABS(SA) .GT. ABS(SB) ***
!
      U = SA + SA
      V = SB / U
!
!     NOTE THAT U AND R HAVE THE SIGN OF SA
!
      R = SQRT(.25 + V**2) * U
!
!     NOTE THAT SC IS POSITIVE
!
      SC = SA / R
      SS = V * (SC + SC)
      SB = SS
      SA = R
      RETURN
!
! *** HERE ABS(SA) .LE. ABS(SB) ***
!
   10 IF (SB .EQ. 0.) GO TO 20
      U = SB + SB
      V = SA / U
!
!     NOTE THAT U AND R HAVE THE SIGN OF SB
!     (R IS IMMEDIATELY STORED IN SA)
!
      SA = SQRT(.25 + V**2) * U
!
!     NOTE THAT SS IS POSITIVE
!
      SS = SB / SA
      SC = V * (SS + SS)
      IF (SC .EQ. 0.) GO TO 15
      SB = 1. / SC
      RETURN
   15 SB = 1.
      RETURN
!
! *** HERE SA = SB = 0. ***
!
   20 SC = 1.
      SS = 0.
      RETURN
!
      END SUBROUTINE SROTG
      SUBROUTINE SRTMEA(Y,XH1,N,ICASE,ISTARA,   &
                        MAXNXT,   &
                        XH1DIS,STTEMP,TEMP,TEMP2,TEMP3,TEMP4,TEMP5,   &
                        TEMP6,TEMP7,   &
                        X2,AINDX,NUMSE1,   &
                        ISEED,ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                        DTEMP1,DTEMP2,DTEMP3,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--SORT BY MEAN (OR SOME OTHER LOCATION STATISTIC).
!              THAT IS,
!
!                 LET X2 INDEX = SORT BY MEAN Y X
!
!               WILL SORT X (HERE X IS A GROUP-ID VARIABLE AND
!               Y IS A RESPONSE VARIABLE) BASED ON THE MEAN
!               (OR SOME OTHER APPROPRIATE STATISTIC).
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2005/12
!     ORIGINAL VERSION--DECEMBER  2005.
!     UPDATED         --JANUARY   2007.  CALL LIST TO CODE
!     UPDATED         --JUNE      2010.  CALL LIST TO CMPSTA
!     UPDATED         --JULY      2016.  FIX ISSUE WHEN X IS NOT
!                                        PRE-SORTED
!     UPDATED         --AUGUST    2023.  CALL LIST TO CMPSTA
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASE
      CHARACTER*4 ISTARA
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION XH1(*)
      DIMENSION X2(*)
      DIMENSION AINDX(*)
!
      DIMENSION XH1DIS(*)
      DIMENSION STTEMP(*)
      DIMENSION TEMP(*)
      DIMENSION TEMP2(*)
      DIMENSION TEMP3(*)
      DIMENSION TEMP4(*)
      DIMENSION TEMP5(*)
      DIMENSION TEMP6(*)
      DIMENSION TEMP7(*)
      INTEGER ITEMP1(*)
      INTEGER ITEMP2(*)
      INTEGER ITEMP3(*)
      INTEGER ITEMP4(*)
      INTEGER ITEMP5(*)
      INTEGER ITEMP6(*)
      DOUBLE PRECISION DTEMP1(*)
      DOUBLE PRECISION DTEMP2(*)
      DOUBLE PRECISION DTEMP3(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='SRTM'
      ISUBN2='EA  '
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LE.1)THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,31)
   31   FORMAT('***** ERROR IN SORT BY <STATISTIC>--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,32)
   32   FORMAT('      THE NUMBER OF OBSERVATIONS MUST BE AT LEAST 2.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,34)N
   34   FORMAT('      THE ENTERED NUMBER OF OBSERVATIONS HERE = ',I6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'TMEA')THEN
        WRITE(ICOUT,70)
   70   FORMAT('AT THE BEGINNING OF SRTMEA--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,71)N,ICASE
   71   FORMAT('N,ICASE = ',I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        DO 72 I=1,N
          WRITE(ICOUT,73)I,Y(I),XH1(I)
   73     FORMAT('I, Y(I), XH1(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   72   CONTINUE
      ENDIF
!
!               ******************************************************
!               **  STEP 2--                                        **
!               **  DETERMINE THE NUMBER OF DISTINCT VALUES         **
!               **  FOR VARIABLE 2 (ONE OF THE GROUP VARIABLES).    **
!               ******************************************************
!
      ISTEPN='2'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'TMEA')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!  THE DISTINCT VALUES WILL BE CODED INTO 1, 2, ... , NDIST.
!  NOTE THAT TRYING TO MAINTAIN ORIGINAL SCALE IS PROBLEMATIC
!  IF THE DATA HAS GAPS (E.G., 101, 102, 105) SINCE WE HAVE
!  NO EASY WAY TO AUTOMATICALLY PLACE THE TIC MARK LABELS.
!
      IWRITE='OFF'
      CALL CODE(XH1,N,IWRITE,TEMP3,TEMP5,MAXNXT,IBUGA3,IERROR)
      DO 110 I=1,N
        XH1(I)=TEMP3(I)
  110 CONTINUE
      CALL DISTIN(XH1,N,IWRITE,XH1DIS,NUMSE1,IBUGA3,IERROR)
!
!     JULY 2016: FOLLOWING LINE NEEDED FOR CASE WHERE X VARIABLE
!                NOT PRE-SORTED.
!
      CALL SORT(XH1DIS,NUMSE1,XH1DIS)
!
      AN=N
      ANUMS1=NUMSE1
!
      DO 310 I=1,NUMSE1
        NTEMP=0
        DO 320 J=1,N
          IF(XH1(J).EQ.XH1DIS(I))THEN
            NTEMP=NTEMP+1
            TEMP2(NTEMP)=Y(J)
          ENDIF
  320   CONTINUE
        IWRITE='OFF'
        IF(NTEMP.GT.0)THEN
          NUMV=1
          CALL CMPSTA(TEMP2,TEMP,TEMP,TEMP3,TEMP4,TEMP5,   &
                      TEMP6,TEMP7,   &
                      MAXNXT,NTEMP,NTEMP,NTEMP,NUMV,ICASE,ISTARA,   &
                      ISEED,ITEMP1,ITEMP2,ITEMP3,   &
                      ITEMP4,ITEMP5,ITEMP6,   &
                      DTEMP1,DTEMP2,DTEMP3,   &
                      STAT1,   &
                      ISUBRO,IBUGA3,IERROR)
          IF(IERROR.EQ.'YES')GO TO 9000
          STTEMP(I)=STAT1
!CCCC     AINDX(I)=REAL(I)
          AINDX(I)=XH1DIS(I)
        ELSE
          IERROR='YES'
          GO TO 9000
        ENDIF
  310 CONTINUE
!
      CALL SORTC(STTEMP,AINDX,NUMSE1,STTEMP,TEMP3)
!
      DO 390 I=1,NUMSE1
        AINDX(I)=TEMP3(I)
  390 CONTINUE
!
      DO 410 I=1,NUMSE1
        AVALUE=0.0
        DO 415 J=1,NUMSE1
          IF(XH1DIS(I).EQ.AINDX(J))THEN
!CCCC       AVALUE=REAL(J)
            AVALUE=XH1DIS(J)
            GO TO 419
          ENDIF
  415   CONTINUE
  419   CONTINUE
        DO 420 J=1,N
          IF(XH1(J).EQ.XH1DIS(I))THEN
            X2(J)=AVALUE
          ENDIF
  420   CONTINUE
  410 CONTINUE
!
!               ******************
!               **   STEP 90--  **
!               **   EXIT       **
!               ******************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'TMEA')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF SRTMEA--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)NUMSE1
 9015   FORMAT('NUMSE1 = ',I8)
        CALL DPWRST('XXX','BUG ')
        DO 9020 I=1,NUMSE1
          WRITE(ICOUT,9021)I,XH1DIS(I),AINDX(I)
 9021     FORMAT('I,XH1DIS(I),AINDX(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
 9020   CONTINUE
        DO 9030 I=1,N
          WRITE(ICOUT,9031)I,Y(I),XH1(I),X2(I)
 9031     FORMAT('I,Y(I),XH1(I),X2(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
 9030   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE SRTMEA
      subroutine ss(y,n,np,ns,isdeg,nsjump,userw,rw,season,work1,work2,   &
      work3,work4)
!
!  This routine is part of the Bill Cleveland seasonal loess
!  program.
!
      integer n, np, ns, isdeg, nsjump, nright, nleft, i, j, k
      real y(n), rw(n), season(n+2*np), work1(n), work2(n), work3(n),   &
      work4(n), xs
      logical userw,ok
      j=1
23105 if(.not.(j .le. np))go to 23107
      k = (n-j)/np+1
      do 23108 i = 1,k
      work1(i) = y((i-1)*np+j)
23108 continue
      if(.not.(userw))go to 23110
      do 23112 i = 1,k
      work3(i) = rw((i-1)*np+j)
23112 continue
23110 continue
      call ess(work1,k,ns,isdeg,nsjump,userw,work3,work2(2),work4)
      xs = 0
      nright = min0(ns,k)
      call est(work1,k,ns,isdeg,xs,work2(1),1,nright,work4,userw,work3,   &
      ok)
      if(.not.( .not. ok))go to 23114
      work2(1) = work2(2)
23114 continue
      xs = k+1
      nleft = max0(1,k-ns+1)
      call est(work1,k,ns,isdeg,xs,work2(k+2),nleft,k,work4,userw,work3,   &
      ok)
      if(.not.( .not. ok))go to 23116
      work2(k+2) = work2(k+1)
23116 continue
      do 23118 m = 1,k+2
      season((m-1)*np+j) = work2(m)
23118 continue
       j=j+1
      go to 23105
23107 continue
      return
      end
      SUBROUTINE SSCAL(N,SA,SX,INCX)
!***BEGIN PROLOGUE  SSCAL
!***DATE WRITTEN   791001   (YYMMDD)
!***REVISION DATE  820801   (YYMMDD)
!***CATEGORY NO.  D1A6
!***KEYWORDS  BLAS,LINEAR ALGEBRA,SCALE,VECTOR
!***AUTHOR  LAWSON, C. L., (JPL)
!           HANSON, R. J., (SNLA)
!           KINCAID, D. R., (U. OF TEXAS)
!           KROGH, F. T., (JPL)
!***PURPOSE  S.P. vector scale x = a*x
!***DESCRIPTION
!
!                B L A S  Subprogram
!    Description of Parameters
!
!     --Input--
!        N  number of elements in input vector(s)
!       SA  single precision scale factor
!       SX  single precision vector with N elements
!     INCX  storage spacing between elements of SX
!
!     --Output--
!       SX  single precision result (unchanged if N .LE. 0)
!
!     Replace single precision SX by single precision SA*SX.
!     For I = 0 to N-1, replace SX(1+I*INCX) with  SA * SX(1+I*INCX)
!***REFERENCES  LAWSON C.L., HANSON R.J., KINCAID D.R., KROGH F.T.,
!                 *BASIC LINEAR ALGEBRA SUBPROGRAMS FOR FORTRAN USAGE*,
!                 ALGORITHM NO. 539, TRANSACTIONS ON MATHEMATICAL
!                 SOFTWARE, VOLUME 5, NUMBER 3, SEPTEMBER 1979, 308-323
!***ROUTINES CALLED  (NONE)
!***END PROLOGUE  SSCAL
!
      REAL SA,SX(*)
!***FIRST EXECUTABLE STATEMENT  SSCAL
      IF(N.LE.0)RETURN
      IF(INCX.EQ.1)GO TO  20
!
!        CODE FOR INCREMENTS NOT EQUAL TO 1.
!
      NS = N*INCX
          DO 10 I = 1,NS,INCX
          SX(I) = SA*SX(I)
   10     CONTINUE
      RETURN
!
!        CODE FOR INCREMENTS EQUAL TO 1.
!
!
!        CLEAN-UP LOOP SO REMAINING VECTOR LENGTH IS A MULTIPLE OF 5.
!
   20 M = MOD(N,5)
      IF( M .EQ. 0 ) GO TO 40
      DO 30 I = 1,M
        SX(I) = SA*SX(I)
   30 CONTINUE
      IF( N .LT. 5 ) RETURN
   40 MP1 = M + 1
      DO 50 I = MP1,N,5
        SX(I) = SA*SX(I)
        SX(I + 1) = SA*SX(I + 1)
        SX(I + 2) = SA*SX(I + 2)
        SX(I + 3) = SA*SX(I + 3)
        SX(I + 4) = SA*SX(I + 4)
   50 CONTINUE
      RETURN
      END SUBROUTINE SSCAL
      SUBROUTINE SSCORE(X,N,IWRITE,XEOS,IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE EXPONENTIAL (OR SAVAGE) SCORES
!              OF THE N ELEMENTS OF THE SINGLE PRECISION VECTOR X, AND
!              PUTS THE RESULTING N SCORES INTO THE SINGLE PRECISION
!              VECTOR XEOS.
!
!              THE MEAN ORDER STATISTICS FOR THE EXPONENTIAL
!              DISTRIBUTION ARE
!
!                 1/N, 1/N + 1/(N-1), 1/N + 1/(N-1) + 1/(N-2)
!
!              THE SAVAGE (OR EXPONENTIAL SCORES) ARE THEN OBTAINED BY
!              SUBTRACTING 1 FROM THE EXPONENTIAL MEAN ORDER STATISTICS.
!
!              SAVAGE SCORES ARE TYPICALLY USED IN THE CONTEXT OF
!              NON-PARAMETRIC STATISTICS.
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                OBSERVATIONS TO BE SCORED.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XEOS   = THE SINGLE PRECISION VECTOR INTO WHICH
!                                THE SCORES FROM X WILL BE PLACED.
!     OUTPUT--THE SINGLE PRECISION VECTOR XEOS CONTAINING THE NORMAL
!             ORDER SCORES (IN ASCENDING ORDER) OF THE VALUES
!             IN THE SINGLE PRECISION VECTOR X.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     COMMENT--THE FIRST AND THIRD ARGUMENTS IN THE CALLING SEQUENCE MAY
!              BE IDENTICAL; THAT IS, AN 'IN PLACE' SCORING IS
!              PERMITTED.
!     REFERENCES--HIGGINS (2004), "INTRODUCTION TO MODERN NONPARAMETRIC
!                 STATISTICS", DUXBURY ADVANCED SERIES, P. 50.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2023.05
!     ORIGINAL VERSION--MAY       2023.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION XEOS(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='SSCO'
      ISUBN2='RE  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CORE')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF SSCORE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)N,IBUGA3,ISUBRO
   53   FORMAT('N,IBUGA3,ISUBRO = ',I8,(2X,A4))
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.LT.1)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN SAVAGE SCORES--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      THE NUMBER OF OBSERVATIONS IS LESS THAN 1.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,118)N
  118   FORMAT('      THE NUMBER OF OBSERVATIONS IS ',I8)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!               ********************************************
!               **  STEP 2--                              **
!               **  GENERATE THE SAVAGE SCORES            **
!               ********************************************
!
        DO 211 K=1,N
          DSUM=0.0D0
          DO 212 J=1,K
            DVAL=1.0D0/DBLE(N-J+1)
            DSUM=DSUM + DVAL
  212     CONTINUE
          XEOS(K)=REAL(DSUM) - 1.0
  211     CONTINUE
!
!
!               ******************************
!               **  STEP 4--                **
!               **  WRITE OUT A FEW LINES   **
!               **  OF SUMMARY INFORMATION  **
!               **  ABOUT THE CODING.       **
!               ******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IINDX=1
        WRITE(ICOUT,912)IINDX,XEOS(IINDX)
  912   FORMAT('THE SAVAGE SCORE OF ROW ',I10,' = ',G15.7)
        CALL DPWRST('XXX','BUG ')
        IINDX=N
        WRITE(ICOUT,912)IINDX,XEOS(IINDX)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CORE')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF SSCORE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR
 9012   FORMAT('IERROR = ',A4)
        CALL DPWRST('XXX','BUG ')
        DO 9015 I=1,N
          WRITE(ICOUT,9016)I,X(I),XEOS(I)
 9016     FORMAT('I,X(I),XEOS(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
 9015   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE SSCORE
      SUBROUTINE SSIEV(A,LDA,N,E,WORK,JOB,INFO)
!***BEGIN PROLOGUE  SSIEV
!***DATE WRITTEN   800808   (YYMMDD)
!***REVISION DATE  820801   (YYMMDD)
!***CATEGORY NO.  D4A1
!***KEYWORDS  EIGENVALUE,EIGENVECTOR,MATRIX,REAL,SYMMETRIC
!***AUTHOR  KAHANER, D. K., (NBS)
!           MOLER, C. B., (U. OF NEW MEXICO)
!           STEWART, G. W., (U. OF MARYLAND)
!***PURPOSE  To compute the eigenvalues and, optionally, the eigen-
!            vectors of a real SYMMETRIC matrix.
!***DESCRIPTION
!
!     LICEPACK.  This version dated 08/08/80.
!     David Kahaner, Cleve Moler, Pete Stewart
!          N.B.S.       U.N.M.     N.B.S./U.MD.
!
!     Abstract
!      SSIEV computes the eigenvalues and, optionally, the eigenvectors
!      of a real symmetric matrix.
!
!     Call Sequence Parameters-
!       (The values of parameters marked with * (star) will be  changed
!         by SSIEV.)
!
!       A*      REAL (LDA,N)
!               real symmetric input matrix.
!               Only the diagonal and upper triangle of A must be input,
!               as SSIEV copies the upper triangle to the lower.
!               That is, the user must define A(I,J), I=1,..N, and J=I,.
!               ..,N.
!               On return from SSIEV, if the user has set JOB
!               = 0        the lower triangle of A has been altered.
!               = nonzero  the N eigenvectors of A are stored in its
!               first N columns.  See also INFO below.
!
!       LDA     INTEGER
!               set by the user to
!               the leading dimension of the array A.
!
!       N       INTEGER
!               set by the user to
!               the order of the matrix A and
!               the number of elements in E.
!
!       E*      REAL (N)
!               on return from SSIEV, E contains the N
!               eigenvalues of A.  See also INFO below.
!
!       WORK*   REAL (2*N)
!               temporary storage vector.  Contents changed by SSIEV.
!
!       JOB     INTEGER
!               set by user on input
!               = 0         only calculate eigenvalues of A.
!               = nonzero   calculate eigenvalues and eigenvectors of A.
!
!       INFO*   INTEGER
!               on return from SSIEV, the value of INFO is
!               = 0 for normal return.
!               = K if the eigenvalue iteration fails to converge.
!                   eigenvalues and vectors 1 through K-1 are correct.
!
!
!     Error Messages-
!          No. 1   recoverable  N is greater than LDA
!          No. 2   recoverable  N is less than one
!
!     Subroutines Used
!
!     EISPACK- TRED1, TRED2, TQLRAT, IMTQL2
!     SLATEC-  XERROR
!***REFERENCES  (NONE)
!***ROUTINES CALLED  IMTQL2,TQLRAT,TRED1,TRED2,XERROR
!***END PROLOGUE  SSIEV
      INTEGER INFO,JOB,LDA,N
      REAL A(LDA,N),E(N),WORK(1)
!***FIRST EXECUTABLE STATEMENT  SSIEV
       IF(N .GT. LDA)THEN
!CCCC    WRITE(*,*) 'FROM SSIEV: N .GT. LDA.'
         INFO = -1
         RETURN
       ENDIF
       IF(N .LT. 1) THEN
!CCCC    WRITE(*,*) 'FROM SSIEV: N .LT. 1'
         INFO = -2
         RETURN
       ENDIF
!
!       CHECK N=1 CASE
!
      E(1) = A(1,1)
      INFO = 0
      IF(N .EQ. 1) RETURN
!
!     COPY UPPER TRIANGLE TO LOWER
!
      DO 10 J=1,N
         DO 11 I=1,J
            A(J,I)=A(I,J)
   11    CONTINUE
   10 CONTINUE
!
      IF(JOB.NE.0) GO TO 20
!
!     EIGENVALUES ONLY
!
      CALL TRED1(LDA,N,A,E,WORK(1),WORK(N+1))
      CALL TQLRAT(N,E,WORK(N+1),INFO)
      RETURN
!
!     EIGENVALUES AND EIGENVECTORS
!
   20 CALL TRED2(LDA,N,A,E,WORK,A)
      CALL IMTQL2(LDA,N,E,WORK,A,INFO)
      RETURN
      END SUBROUTINE SSIEV
      SUBROUTINE SSNC(P1,P2,ALPHA,BETA,N,IC,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE
!              BINOMIAL BASED SINGLE SAMPLE PLAN (N,C).
!     INPUT  ARGUMENTS--P1     = THE SINGLE PRECISION VALUE FOR
!                                THE ACCEPTABLE QUALITY LEVEL.
!                     --P2     = THE SINGLE PRECISION VALUE FOR
!                                THE LOT TOLERANCE PERCENT DEFECTIVE
!                     --ALPHA  = PROBABILITY FOR AQL.
!                     --BETA   = PROBABILITY FOR LTPD.
!     OUTPUT ARGUMENTS--N      = THE COMPUTED SAMPLE SIZE.
!                     --IC     = ACCEPTABLE NUMBER OF DEFECTIVES.
!     OTHER DATAPAC   SUBROUTINES NEEDED--BINCDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--MONTGOMERY, STATISTICAL QUALITY CONTROL,
!                 ALGORITHM IS FORTRAN TRANSLATION OF A BASIC CODE
!                 PROVIDED BY JACK PRINS.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-075-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--99/3
!     ORIGINAL VERSION--MARCH     1999.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DCDF
!
      REAL L
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,11)
   11   FORMAT('AT THE BEGINNING OF SSNC')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IERROR='NO'
      MAXIT=10000
      I=0
  100 CONTINUE
      IF(I.GT.MAXIT)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,101)
  101   FORMAT('***** MAXIMUM NUMBER OF ITERATIONS EXCEEDED FOR THE ',   &
               'BINOMIAL SINGLE SAMPLE PLAN')
        CALL DPWRST('XXX','BUG ')
        N=0
        IC=0
        GO TO 9000
      ENDIF
      IDF=2 + 2*I
      P=1.0 - BETA
      CALL CHSPPF(P,IDF,PPF)
      L=0.5*(REAL(I) + (-0.5 + 1.0/P2)*PPF)
!
      IDF=2 + 2*I
      P=ALPHA
      CALL CHSPPF(P,IDF,PPF)
      U=0.5*(REAL(I) + (-0.5 + 1.0/P1)*PPF)
!
      IF(INT(U)-INT(L).LT.1)THEN
        I=I+1
        GO TO 100
      ENDIF
!
      IF(U.GT.L)THEN
        N=INT(U)
      ELSE
        N=INT(L)
      ENDIF
      IC=I
!
  300 CONTINUE
      N=N-1
      CALL BINCDF(DBLE(IC),DBLE(P2),N,DCDF)
      S=REAL(DCDF)
      IF(S.GT.BETA)GO TO 400
      BCDF=S
      GO TO 300
!
  400 CONTINUE
      N=N+1
      CALL BINCDF(DBLE(IC),DBLE(P1),N,DCDF)
      S=REAL(DCDF)
      ACDF=S
!
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1001)
 1001 FORMAT('BINOMIAL SINGLE SAMPLE PLAN')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1011)P1
 1011 FORMAT('     P1 (= Acceptable Quality Level)          = ',F7.4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1021)P2
 1021 FORMAT('     P2 (= Lot Tolerance Percent Defective)   = ',F7.4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1031)ALPHA
 1031 FORMAT('     ALPHA                                    = ',F7.4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1041)BETA
 1041 FORMAT('     BETA                                     = ',F7.4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1051)N
 1051 FORMAT('     Computed Sample Size                     = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1061)IC
 1061 FORMAT('     Computed Acceptance Number              = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
!
      WRITE(ICOUT,1071)
 1071 FORMAT('The sample size and acceptance number are saved in')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1081)
 1081 FORMAT('the internal parameters SSN and SSC respectively.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE SSNC
      SUBROUTINE SSORT(X,Y,N,KFLAG)
!
!      NOTE: This subroutine used in computing the consensus mean
!            using the Iyer and Wang generalized tolerance interval
!            approach.
!
!            Modified for Dataplot 3/2006.
!
!***BEGIN PROLOGUE  SSORT
!***DATE WRITTEN   761101   (YYMMDD)
!***REVISION DATE  820801   (YYMMDD)
!***CATEGORY NO.  N6A2B1
!***KEYWORDS  QUICKSORT,SINGLETON QUICKSORT,SORT,SORTING
!***AUTHOR  JONES, R. E., (SNLA)
!           WISNIEWSKI, J. A., (SNLA)
!***PURPOSE  SSORT sorts array X and optionally makes the same
!            interchanges in array Y.  The array X may be sorted in
!            increasing order or decreasing order.  A slightly modified
!            QUICKSORT algorithm is used.
!***DESCRIPTION
!
!     Written by Rondall E. Jones
!     Modified by John A. Wisniewski to use the Singleton quicksort
!     algorithm.  Date 18 November 1976.
!
!     Abstract
!         SSORT sorts array X and optionally makes the same
!         interchanges in array Y.  The array X may be sorted in
!         increasing order or decreasing order.  A slightly modified
!         quicksort algorithm is used.
!
!     Reference
!         Singleton, R. C., Algorithm 347, An Efficient Algorithm for
!         Sorting with Minimal Storage, CACM,12(3),1969,185-7.
!
!     Description of Parameters
!         X - array of values to be sorted   (usually abscissas)
!         Y - array to be (optionally) carried along
!         N - number of values in array X to be sorted
!         KFLAG - control parameter
!             =2  means sort X in increasing order and carry Y along.
!             =1  means sort X in increasing order (ignoring Y)
!             =-1 means sort X in decreasing order (ignoring Y)
!             =-2 means sort X in decreasing order and carry Y along.
!***REFERENCES  SINGLETON,R.C., ALGORITHM 347, AN EFFICIENT ALGORITHM
!                 FOR SORTING WITH MINIMAL STORAGE, CACM,12(3),1969,
!                 185-7.
!***END PROLOGUE  SSORT
      integer n, kflag
      double precision X(N),Y(N)
      integer IL(21),IU(21)
!
      double precision t, tt, r, ty, tty
!
      INCLUDE 'DPCOP2.INC'
!
!***FIRST EXECUTABLE STATEMENT  SSORT
      NN = N
      IF (NN.LT.1) THEN
         WRITE(ICOUT,1)
    1    FORMAT('*****ERROR FROM SSORT--')
         CALL DPWRST('XXX','WRIT')
         WRITE(ICOUT,2)
    2    FORMAT('     THE NUMBER OF VALUES TO BE SORTED WAS NOT ',   &
                'POSITIVE.')
         CALL DPWRST('XXX','WRIT')
         RETURN
      ENDIF
      KK = IABS(KFLAG)
      IF ((KK.EQ.1).OR.(KK.EQ.2)) GO TO 15
         WRITE(ICOUT,1)
         CALL DPWRST('XXX','WRIT')
         WRITE(ICOUT,3)
    3    FORMAT('     THE SORT CONTROL PARAMETER, K, WAS NOT ',   &
                '2, 1, -1, OR -2.')
         CALL DPWRST('XXX','WRIT')
         RETURN
!
! ALTER ARRAY X TO GET DECREASING ORDER IF NEEDED
!
   15 IF (KFLAG.GE.1) GO TO 30
      DO 20 I=1,NN
         X(I) = -X(I)
   20 CONTINUE
   30 CONTINUE
      GO TO (100,200),KK
!
! SORT X ONLY
!
  100 CONTINUE
      M=1
      I=1
      J=NN
      R=.375d0
  110 IF (I .EQ. J) GO TO 155
      IF (R .GT. .5898437d0) GO TO 120
      R=R+3.90625d-2
      GO TO 125
  120 R=R-.21875d0
  125 K=I
!                                  SELECT A CENTRAL ELEMENT OF THE
!                                  ARRAY AND SAVE IT IN LOCATION T
      IJ = I + INT(FLOAT (J-I) * R)
      T=X(IJ)
!                                  IF FIRST ELEMENT OF ARRAY IS GREATER
!                                  THAN T, INTERCHANGE WITH T
      IF (X(I) .LE. T) GO TO 130
      X(IJ)=X(I)
      X(I)=T
      T=X(IJ)
  130 L=J
!                                  IF LAST ELEMENT OF ARRAY IS LESS THAN
!                                  T, INTERCHANGE WITH T
      IF (X(J) .GE. T) GO TO 140
      X(IJ)=X(J)
      X(J)=T
      T=X(IJ)
!                                  IF FIRST ELEMENT OF ARRAY IS GREATER
!                                  THAN T, INTERCHANGE WITH T
      IF (X(I) .LE. T) GO TO 140
      X(IJ)=X(I)
      X(I)=T
      T=X(IJ)
      GO TO 140
  135 TT=X(L)
      X(L)=X(K)
      X(K)=TT
!                                  FIND AN ELEMENT IN THE SECOND HALF OF
!                                  THE ARRAY WHICH IS SMALLER THAN T
  140 L=L-1
      IF (X(L) .GT. T) GO TO 140
!                                  FIND AN ELEMENT IN THE FIRST HALF OF
!                                  THE ARRAY WHICH IS GREATER THAN T
  145 K=K+1
      IF (X(K) .LT. T) GO TO 145
!                                  INTERCHANGE THESE ELEMENTS
      IF (K .LE. L) GO TO 135
!                                  SAVE UPPER AND LOWER SUBSCRIPTS OF
!                                  THE ARRAY YET TO BE SORTED
      IF (L-I .LE. J-K) GO TO 150
      IL(M)=I
      IU(M)=L
      I=K
      M=M+1
      GO TO 160
  150 IL(M)=K
      IU(M)=J
      J=L
      M=M+1
      GO TO 160
!                                  BEGIN AGAIN ON ANOTHER PORTION OF
!                                  THE UNSORTED ARRAY
  155 M=M-1
      IF (M .EQ. 0) GO TO 300
      I=IL(M)
      J=IU(M)
  160 IF (J-I .GE. 1) GO TO 125
      IF (I .EQ. 1) GO TO 110
      I=I-1
  165 I=I+1
      IF (I .EQ. J) GO TO 155
      T=X(I+1)
      IF (X(I) .LE. T) GO TO 165
      K=I
  170 X(K+1)=X(K)
      K=K-1
      IF (T .LT. X(K)) GO TO 170
      X(K+1)=T
      GO TO 165
!
! SORT X AND CARRY Y ALONG
!
  200 CONTINUE
      M=1
      I=1
      J=NN
      R=.375d0
  210 IF (I .EQ. J) GO TO 255
      IF (R .GT. .5898437d0) GO TO 220
      R=R+3.90625d-2
      GO TO 225
  220 R=R-.21875d0
  225 K=I
!                                  SELECT A CENTRAL ELEMENT OF THE
!                                  ARRAY AND SAVE IT IN LOCATION T
      IJ = I + INT(FLOAT (J-I) *R)
      T=X(IJ)
      TY= Y(IJ)
!                                  IF FIRST ELEMENT OF ARRAY IS GREATER
!                                  THAN T, INTERCHANGE WITH T
      IF (X(I) .LE. T) GO TO 230
      X(IJ)=X(I)
      X(I)=T
      T=X(IJ)
       Y(IJ)= Y(I)
       Y(I)=TY
      TY= Y(IJ)
  230 L=J
!                                  IF LAST ELEMENT OF ARRAY IS LESS THAN
!                                  T, INTERCHANGE WITH T
      IF (X(J) .GE. T) GO TO 240
      X(IJ)=X(J)
      X(J)=T
      T=X(IJ)
       Y(IJ)= Y(J)
       Y(J)=TY
      TY= Y(IJ)
!                                  IF FIRST ELEMENT OF ARRAY IS GREATER
!                                  THAN T, INTERCHANGE WITH T
      IF (X(I) .LE. T) GO TO 240
      X(IJ)=X(I)
      X(I)=T
      T=X(IJ)
       Y(IJ)= Y(I)
       Y(I)=TY
      TY= Y(IJ)
      GO TO 240
  235 TT=X(L)
      X(L)=X(K)
      X(K)=TT
      TTY= Y(L)
       Y(L)= Y(K)
       Y(K)=TTY
!                                  FIND AN ELEMENT IN THE SECOND HALF OF
!                                  THE ARRAY WHICH IS SMALLER THAN T
  240 L=L-1
      IF (X(L) .GT. T) GO TO 240
!                                  FIND AN ELEMENT IN THE FIRST HALF OF
!                                  THE ARRAY WHICH IS GREATER THAN T
  245 K=K+1
      IF (X(K) .LT. T) GO TO 245
!                                  INTERCHANGE THESE ELEMENTS
      IF (K .LE. L) GO TO 235
!                                  SAVE UPPER AND LOWER SUBSCRIPTS OF
!                                  THE ARRAY YET TO BE SORTED
      IF (L-I .LE. J-K) GO TO 250
      IL(M)=I
      IU(M)=L
      I=K
      M=M+1
      GO TO 260
  250 IL(M)=K
      IU(M)=J
      J=L
      M=M+1
      GO TO 260
!                                  BEGIN AGAIN ON ANOTHER PORTION OF
!                                  THE UNSORTED ARRAY
  255 M=M-1
      IF (M .EQ. 0) GO TO 300
      I=IL(M)
      J=IU(M)
  260 IF (J-I .GE. 1) GO TO 225
      IF (I .EQ. 1) GO TO 210
      I=I-1
  265 I=I+1
      IF (I .EQ. J) GO TO 255
      T=X(I+1)
      TY= Y(I+1)
      IF (X(I) .LE. T) GO TO 265
      K=I
  270 X(K+1)=X(K)
       Y(K+1)= Y(K)
      K=K-1
      IF (T .LT. X(K)) GO TO 270
      X(K+1)=T
       Y(K+1)=TY
      GO TO 265
!
! CLEAN UP
!
  300 CONTINUE
      IF (KFLAG.GE.1) RETURN
      DO 310 I=1,NN
         X(I) = -X(I)
  310 CONTINUE
      RETURN
      END SUBROUTINE SSORT
      SUBROUTINE SSQ(X,N,XCAP,IWRITE,XSSQ,IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE SUM OF SQUARES
!
!                  SSQ = SUM[i=1 to n][X(i)**2]
!
!              OF THE DATA IN THE INPUT VECTOR X.
!
!              SOME AUTHORS RECOMMEND CAPPING THE VALUE OF
!              OUTLIERS TO LESSEN THE EFFECT OF SEVERE OUTLIERS
!              (THIS CAP IS TYPICALLY SET TO EITHER +/-3 OR
!              +/- 4).  SET XOUT TO CPUMIN IF CAPPING IS NOT
!              DESIRED.
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!                     --XCAP   = OPTIONAL CAP VALUE
!     OUTPUT ARGUMENTS--XSSQ   = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SUM OF SQUARES.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE SUM OF SQUARES.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2012.2
!     ORIGINAL VERSION--FEBRUARY  2012.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DSUM
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='SSQ '
      ISUBN2='    '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'SSQ ')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF SSQ--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,N,XCAP
   52   FORMAT('IBUGA3,N,XCAP = ',A4,2X,I8,2X,G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN SUM OF SQUARES--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE RESPONSE ',   &
               'VARIABLE IS LESS THAN 1.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS = ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               *************************************
!               **  STEP 2--                       **
!               **  COMPUTE THE SUM OF SQUARES.    **
!               *************************************
!
      DSUM=0.0D0
      IF(XCAP.EQ.CPUMIN)THEN
        DO 200 I=1,N
          DX=X(I)
          DSUM=DSUM + DX*DX
  200   CONTINUE
      ELSE
        DO 300 I=1,N
          DX=X(I)
          IF(DABS(DX).GT.XCAP)THEN
            IF(DX.GT.0.0D0)THEN
              DX=ABS(XCAP)
            ELSE
              DX=-ABS(XCAP)
            ENDIF
          ENDIF
          DSUM=DSUM + DX*DX
  300   CONTINUE
      ENDIF
      XSSQ=REAL(DSUM)
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)N,XSSQ
  811   FORMAT('THE SUM OF SQUARES OF THE ',I8,   &
               ' OBSERVATIONS = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'SSQ')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END OF SSQ--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)IERROR,N,DSUM,XSSQ
 9013   FORMAT('IERROR,N,DSUM,XSSQ = ',A4,2X,I8,2G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE SSQ
      SUBROUTINE SSQMEA(X,N,IWRITE,XSSQ,IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE SUM OF SQUARES FROM THE
!              MEAN
!
!                  SSQ = SUM[i=1 to n][(X(i) - XBAR)**2]
!
!              OF THE DATA IN THE INPUT VECTOR X.
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XSSQ   = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SUM OF SQUARES FROM THE MEAN.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE SUM OF SQUARES
!             FROM THE MEAN
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2013.2
!     ORIGINAL VERSION--FEBRUARY  2013.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DX
      DOUBLE PRECISION DSUM
      DOUBLE PRECISION DXBAR
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='SSQM'
      ISUBN2='EA  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'QMEA')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF SSQMEA--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,N
   52   FORMAT('IBUGA3,N = ',A4,2X,I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN SUM OF SQUARES FROM THE MEAN--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE RESPONSE ',   &
               'VARIABLE IS LESS THAN 1.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS = ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               *************************************
!               **  STEP 2--                       **
!               **  COMPUTE THE SUM OF SQUARES.    **
!               *************************************
!
      DN=DBLE(N)
      DSUM=0.0D0
      DO 100 I=1,N
        DX=X(I)
        DSUM=DSUM + DX
  100 CONTINUE
      DXBAR=DSUM/DN
!
      DSUM=0.0D0
      DO 200 I=1,N
        DX=X(I) - DXBAR
        DSUM=DSUM + DX*DX
  200 CONTINUE
!
      XSSQ=REAL(DSUM)
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)N,XSSQ
  811   FORMAT('THE SUM OF SQUARES FROM THE MEAN OF THE ',I8,   &
               ' OBSERVATIONS = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'QMEA')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END OF SSQMEA--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)IERROR,N,DXBAR,DSUM,XSSQ
 9013   FORMAT('IERROR,N,DXBAR,DSUM,XSSQ = ',A4,2X,I8,3G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE SSQMEA
      SUBROUTINE SSQTOT(Y,X,N,XDIST,YTEMP,   &
                        GRPMEA,GRPSD,GRPNI,NDIST,IWRITE,ICASE,   &
                        XSSQTO,XSSQTR,XSSQE,XSSX,DFTO,DFTR,DFE,   &
                        MSTR,MSE,FVAL,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--FOR THE RESPONSE VARIABLE Y AND THE GROUP-ID VARIABLE X,
!              THIS SUBROUTINE COMPUTES:
!
!              1. THE TOTAL SUM OF SQUARES FOR A ONE-FACTOR ANOVA
!
!                 SSQTOT = SUM[i=1 to k][SUM[j=1 to N(i)][(Y(ij) - YMEAN)**2]
!
!                 WHERE YMEAN IS THE GRAND MEAN
!
!              2. THE RESIDUAL (ERROR) SUM OF SQUARES (WITHIN LAB) FOR A
!                 ONE-FACTOR ANOVA
!
!                 SSQRE = SUM[i=1 to k][SUM[j=1 to N(i)][(Y(ij) - YMEAN(i))**2]
!
!                 WHERE YMEAN(i) IS THE MEAN OF THE i-TH GROUP
!
!              3. THE TREATMENT (BETWEEN LAB) SUM OF SQUARES FOR A
!                 ONE-FACTOR ANOVA
!
!                 SSQE = SUM[i=1 to k][(YMEAN(i) - YMEAN)**2]
!
!     INPUT  ARGUMENTS--Y      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --X      = THE SINGLE PRECISION VECTOR CONTAINING
!                                THE GROUP-ID.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTORS Y AND X.
!     OUTPUT ARGUMENTS--XSSQTO = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED TOTAL SUM OF SQUARES.
!                       XSSQTR = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED TREATMENT SUM OF SQUARES.
!                       XSSE   = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED RESIDUAL SUM OF SQUARES.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUES OF THE TOTAL SUM OF
!             SQUARES, THE TREATMENT SUM OF SQUARES AND THE RESIDUAL
!             SUM OF SQUARES FOR A ONE-FACTOR MODEL.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2023.08
!     ORIGINAL VERSION--AUGUST    2023.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ICASE
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      REAL MSE
      REAL MSTR
!
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DSUM3
!
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION XDIST(*)
      DIMENSION YTEMP(*)
      DIMENSION GRPMEA(*)
      DIMENSION GRPSD(*)
      DIMENSION GRPNI(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='SSQT'
      ISUBN2='OT  '
      IERROR='NO'
!
      XSSQTO=CPUMIN
      XSSQTR=CPUMIN
      XSSQER=CPUMIN
      XSSQX=CPUMIN
      DFTO=CPUMIN
      DFTR=CPUMIN
      DFE=CPUMIN
      MSTR=CPUMIN
      MSE=CPUMIN
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'QTOT')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF SSQTOT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N
   52   FORMAT('IBUGA3,ISUBRO,N = ',2(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,Y(I),X(I)
   56     FORMAT('I,Y(I),X(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N.LT.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN TOTAL SUM OF SQUARES (SSQTOT)--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE RESPONSE ',   &
               'VARIABLE IS LESS THAN 4.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS = ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               *****************************************
!               **  STEP 2--                           **
!               **  DETERMINE THE DISTINCT VALUES OF X **
!               *****************************************
!
      CALL DISTIN(X,N,IWRITE,XDIST,NDIST,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      NTEMP=N/NDIST
      IF(NTEMP.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,122)
  122   FORMAT('      THE NUMBER OF GROUPS IS GREATER THAN N/2.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,124)NDIST
  124   FORMAT('      THE NUMBER OF GROUPS IS      ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,126)N
  126   FORMAT('      THE NUMBER OF OBSERVATION IS ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               *************************************
!               **  STEP 3--                       **
!               **  COMPUTE THE SUMS OF SQUARES    **
!               *************************************
!
      CALL MEAN(Y,N,IWRITE,YMEAN,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
      DSUM1=0.0D0
      DSUM2=0.0D0
      DSUM3=0.0D0
!
      DO 210 K=1,NDIST
        HOLD=XDIST(K)
        NTEMP=0
        DO 220 I=1,N
          IF(X(I).EQ.HOLD)THEN
            NTEMP=NTEMP+1
            YTEMP(NTEMP)=Y(I)
            AVAL=(Y(I) - YMEAN)**2
            DSUM1=DSUM1 + DBLE(AVAL)
          ENDIF
  220   CONTINUE
!
        IF(NTEMP.LE.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,111)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,222)K,HOLD
  222     FORMAT('      GROUP ',I6,' (VALUE: ',G15.7,') HAS NO ',   &
                 'OBSERVATIONS.')
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
!
        GRPNI(K)=REAL(NTEMP)
        CALL MEAN(YTEMP,NTEMP,IWRITE,GMEAN,IBUGA3,IERROR)
        CALL SD(YTEMP,NTEMP,IWRITE,GSD,IBUGA3,IERROR)
        GRPMEA(K)=GMEAN
        GRPSD(K)=GSD
        DO 230 I=1,NTEMP
          AVAL=(YTEMP(I) - GMEAN)**2
          DSUM2=DSUM2 + DBLE(AVAL)
          DSUM3=DSUM3 + DBLE(NTEMP)*DBLE(GMEAN)**2
  230   CONTINUE
!
  210 CONTINUE
!
      XSSQTO=REAL(DSUM1)
      XSSQE=REAL(DSUM2)
      XSSX=REAL(DSUM3)
      XSSQTR=XSSQTO - XSSQE
      DFTR=REAL(NDIST-1)
      DFTO=REAL(N-1)
      DFE=REAL(N-NDIST)
      MSTR=XSSQTR/DFTR
      MSE=XSSQE/DFE
      FVAL=MSTR/MSE
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IF(ICASE.EQ.'SSTO')THEN
          WRITE(ICOUT,811)N,XSSQTO
  811     FORMAT('THE TOTAL SUM OF SQUARES OF THE ',I8,   &
                 ' OBSERVATIONS = ',G15.7)
          CALL DPWRST('XXX','BUG ')
        ELSEIF(ICASE.EQ.'SSQE')THEN
          WRITE(ICOUT,812)N,XSSQE
  812     FORMAT('THE ERROR SUM OF SQUARES OF THE ',I8,   &
                 ' OBSERVATIONS = ',G15.7)
          CALL DPWRST('XXX','BUG ')
        ELSEIF(ICASE.EQ.'SSTR')THEN
          WRITE(ICOUT,813)N,XSSQTR
  813     FORMAT('THE TREATMENT SUM OF SQUARES OF THE ',I8,   &
                 ' OBSERVATIONS = ',G15.7)
          CALL DPWRST('XXX','BUG ')
        ELSEIF(ICASE.EQ.'DFTR')THEN
          WRITE(ICOUT,814)N,DFTR
  814     FORMAT('THE TREATMENT DEGREES OF FREEDOM OF THE ',I8,   &
                 ' OBSERVATIONS = ',G15.7)
          CALL DPWRST('XXX','BUG ')
        ELSEIF(ICASE.EQ.'DFTO')THEN
          WRITE(ICOUT,815)N,DFTO
  815     FORMAT('THE TOTAL DEGREES OF FREEDOM OF THE ',I8,   &
                 ' OBSERVATIONS = ',G15.7)
          CALL DPWRST('XXX','BUG ')
        ELSEIF(ICASE.EQ.'DFER')THEN
          WRITE(ICOUT,816)N,DFER
  816     FORMAT('THE ERROR DEGREES OF FREEDOM OF THE ',I8,   &
                 ' OBSERVATIONS = ',G15.7)
          CALL DPWRST('XXX','BUG ')
        ELSEIF(ICASE.EQ.'MSTR')THEN
          WRITE(ICOUT,817)N,MSTR
  817     FORMAT('THE TREATMENT MEAN SQUARE OF THE ',I8,   &
                 ' OBSERVATIONS = ',G15.7)
          CALL DPWRST('XXX','BUG ')
        ELSEIF(ICASE.EQ.'MSER')THEN
          WRITE(ICOUT,818)N,MSER
  818     FORMAT('THE ERROR MEAN SQUARE OF THE ',I8,   &
                 ' OBSERVATIONS = ',G15.7)
          CALL DPWRST('XXX','BUG ')
        ELSEIF(ICASE.EQ.'FVAL')THEN
          WRITE(ICOUT,819)N,FVAL
  819     FORMAT('THE ONE WAY ANOVA F-VALUE OF THE ',I8,   &
                 ' OBSERVATIONS = ',G15.7)
          CALL DPWRST('XXX','BUG ')
        ELSEIF(ICASE.EQ.'SSX ')THEN
          WRITE(ICOUT,820)N,XSSX
  820     FORMAT('THE SSX OF THE ',I8,' OBSERVATIONS = ',G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'QTOT')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END OF SSQ--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)IERROR,DSUM1,DSUM2
 9013   FORMAT('IERROR,DSUM1,DSUM2 = ',A4,2X,2G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)XSSQTO,XSSQTR,XSSQE,XSSX,DFTO,DFTR,DFER
 9015   FORMAT('XSSQTO,XSSQTR,XSSQE,XSSX,DFTO,DFTR,DFER = ',7G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9017)MSTR,MSER,FVAL
 9017   FORMAT('MSTR,MSER,FVAL = ',3G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 9020 I=1,NDIST
          WRITE(ICOUT,9027)I,GRPMEA(I),GRPSD(I),GRPNI(I)
 9027     FORMAT('I,GRPMEA(I),GRPSD(I),GRPNI(I) = ',I6,3G15.7)
          CALL DPWRST('XXX','BUG ')
 9020   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE SSQTOT
      SUBROUTINE SSVDC(X,LDX,N,P,S,E,U,LDU,V,LDV,WORK,JOB,INFO)
!***BEGIN PROLOGUE  SSVDC
!***DATE WRITTEN   790319   (YYMMDD)
!***REVISION DATE  820801   (YYMMDD)
!***CATEGORY NO.  D6
!***KEYWORDS  LINEAR ALGEBRA,LINPACK,MATRIX,
!             SINGULAR VALUE DECOMPOSITION
!***AUTHOR  STEWART, G. W., (U. OF MARYLAND)
!***PURPOSE  Perform the singular value decomposition of a real NXP
!            matrix
!***DESCRIPTION
!
!     SSVDC is a subroutine to reduce a real NxP matrix X by
!     orthogonal transformations U and V to diagonal form.  The
!     diagonal elements S(I) are the singular values of X.  The
!     columns of U are the corresponding left singular vectors,
!     and the columns of V the right singular vectors.
!
!     On Entry
!
!         X         REAL(LDX,P), where LDX .GE. N.
!                   X contains the matrix whose singular value
!                   decomposition is to be computed.  X is
!                   destroyed by SSVDC.
!
!         LDX       INTEGER
!                   LDX is the leading dimension of the array X.
!
!         N         INTEGER
!                   N is the number of rows of the matrix X.
!
!         P         INTEGER
!                   P is the number of columns of the matrix X.
!
!         LDU       INTEGER
!                   LDU is the leading dimension of the array U.
!                   (See below).
!
!         LDV       INTEGER
!                   LDV is the leading dimension of the array V.
!                   (See below).
!
!         WORK      REAL(N)
!                   work is a scratch array.
!
!         JOB       INTEGER
!                   JOB controls the computation of the singular
!                   vectors.  It has the decimal expansion AB
!                   with the following meaning
!
!                        A .EQ. 0  Do not compute the left singular
!                                  vectors.
!                        A .EQ. 1  Return the N left singular vectors
!                                  in U.
!                        A .GE. 2  Return the first MIN(N,P) singular
!                                  vectors in U.
!                        B .EQ. 0  Do not compute the right singular
!                                  vectors.
!                        B .EQ. 1  Return the right singular vectors
!                                  in V.
!
!     On Return
!
!         S         REAL(MM), where MM=MIN(N+1,P).
!                   The first MIN(N,P) entries of S contain the
!                   singular values of X arranged in descending
!                   order of magnitude.
!
!         E         REAL(P).
!                   E ordinarily contains zeros.  However, see the
!                   discussion of INFO for exceptions.
!
!         U         REAL(LDU,K), where LDU .GE. N.  If JOBA .EQ. 1, then
!                                   K .EQ. N.  If JOBA .GE. 2 , then
!                                   K .EQ. MIN(N,P).
!                   U contains the matrix of right singular vectors.
!                   U is not referenced if JOBA .EQ. 0.  If N .LE. P
!                   or if JOBA .EQ. 2, then U may be identified with X
!                   in the subroutine call.
!
!         V         REAL(LDV,P), where LDV .GE. P.
!                   V contains the matrix of right singular vectors.
!                   V is not referenced if JOB .EQ. 0.  If P .LE. N,
!                   then V may be identified with X in the
!                   subroutine call.
!
!         INFO      INTEGER.
!                   the singular values (and their corresponding
!                   singular vectors) S(INFO+1),S(INFO+2),...,S(M)
!                   are correct (here M=MIN(N,P)).  Thus if
!                   INFO .EQ. 0, all the singular values and their
!                   vectors are correct.  In any event, the matrix
!                   B = TRANS(U)*X*V is the bidiagonal matrix
!                   with the elements of S on its diagonal and the
!                   elements of E on its super-diagonal (TRANS(U)
!                   is the transpose of U).  Thus the singular
!                   values of X and B are the same.
!
!     LINPACK.  This version dated 03/19/79 .
!     G. W. Stewart, University of Maryland, Argonne National Lab.
!
!     ***** Uses the following functions and subprograms.
!
!     External SROT
!     BLAS SAXPY,SDOT,SSCAL,SSWAP,SNRM2,SROTG
!     Fortran ABS,AMAX1,MAX0,MIN0,MOD,SQRT
!***REFERENCES  DONGARRA J.J., BUNCH J.R., MOLER C.B., STEWART G.W.,
!                 *LINPACK USERS  GUIDE*, SIAM, 1979.
!***ROUTINES CALLED  SAXPY,SDOT,SNRM2,SROT,SROTG,SSCAL,SSWAP
!***END PROLOGUE  SSVDC
      INTEGER LDX,N,P,LDU,LDV,JOB,INFO
      REAL X(LDX,*),S(*),E(*),U(LDU,*),V(LDV,*),WORK(*)
!
!
      INTEGER I,ITER,J,JOBU,K,KASE,KK,L,LL,LLS,LM1,LP1,LS,LU,M,MAXIT,   &
              MM,MM1,MP1,NCT,NCTP1,NCU,NRT,NRTP1
!CCCC REAL SDOT,T,R
      REAL SDOT,T
      REAL B,C,CS,EL,EMM1,F,G,SNRM2,SCALE,SHIFT,SL,SM,SN,SMM1,T1,TEST,   &
           ZTEST
      LOGICAL WANTU,WANTV
!
!     SET THE MAXIMUM NUMBER OF ITERATIONS.
!
!***FIRST EXECUTABLE STATEMENT  SSVDC
      MAXIT = 30
      LS = 0
      L=0
!
!     DETERMINE WHAT IS TO BE COMPUTED.
!
      WANTU = .FALSE.
      WANTV = .FALSE.
      JOBU = MOD(JOB,100)/10
      NCU = N
      IF (JOBU .GT. 1) NCU = MIN0(N,P)
      IF (JOBU .NE. 0) WANTU = .TRUE.
      IF (MOD(JOB,10) .NE. 0) WANTV = .TRUE.
!
!     REDUCE X TO BIDIAGONAL FORM, STORING THE DIAGONAL ELEMENTS
!     IN S AND THE SUPER-DIAGONAL ELEMENTS IN E.
!
      INFO = 0
      NCT = MIN0(N-1,P)
      NRT = MAX0(0,MIN0(P-2,N))
      LU = MAX0(NCT,NRT)
      IF (LU .LT. 1) GO TO 170
      DO 160 L = 1, LU
         LP1 = L + 1
         IF (L .GT. NCT) GO TO 20
!
!           COMPUTE THE TRANSFORMATION FOR THE L-TH COLUMN AND
!           PLACE THE L-TH DIAGONAL IN S(L).
!
            S(L) = SNRM2(N-L+1,X(L,L),1)
            IF (S(L) .EQ. 0.0E0) GO TO 10
               IF (X(L,L) .NE. 0.0E0) S(L) = SIGN(S(L),X(L,L))
               CALL SSCAL(N-L+1,1.0E0/S(L),X(L,L),1)
               X(L,L) = 1.0E0 + X(L,L)
   10       CONTINUE
            S(L) = -S(L)
   20    CONTINUE
         IF (P .LT. LP1) GO TO 50
         DO 40 J = LP1, P
            IF (L .GT. NCT) GO TO 30
            IF (S(L) .EQ. 0.0E0) GO TO 30
!
!              APPLY THE TRANSFORMATION.
!
               T = -SDOT(N-L+1,X(L,L),1,X(L,J),1)/X(L,L)
               CALL SAXPY(N-L+1,T,X(L,L),1,X(L,J),1)
   30       CONTINUE
!
!           PLACE THE L-TH ROW OF X INTO  E FOR THE
!           SUBSEQUENT CALCULATION OF THE ROW TRANSFORMATION.
!
            E(J) = X(L,J)
   40    CONTINUE
   50    CONTINUE
         IF (.NOT.WANTU .OR. L .GT. NCT) GO TO 70
!
!           PLACE THE TRANSFORMATION IN U FOR SUBSEQUENT BACK
!           MULTIPLICATION.
!
            DO 60 I = L, N
               U(I,L) = X(I,L)
   60       CONTINUE
   70    CONTINUE
         IF (L .GT. NRT) GO TO 150
!
!           COMPUTE THE L-TH ROW TRANSFORMATION AND PLACE THE
!           L-TH SUPER-DIAGONAL IN E(L).
!
            E(L) = SNRM2(P-L,E(LP1),1)
            IF (E(L) .EQ. 0.0E0) GO TO 80
               IF (E(LP1) .NE. 0.0E0) E(L) = SIGN(E(L),E(LP1))
               CALL SSCAL(P-L,1.0E0/E(L),E(LP1),1)
               E(LP1) = 1.0E0 + E(LP1)
   80       CONTINUE
            E(L) = -E(L)
            IF (LP1 .GT. N .OR. E(L) .EQ. 0.0E0) GO TO 120
!
!              APPLY THE TRANSFORMATION.
!
               DO 90 I = LP1, N
                  WORK(I) = 0.0E0
   90          CONTINUE
               DO 100 J = LP1, P
                  CALL SAXPY(N-L,E(J),X(LP1,J),1,WORK(LP1),1)
  100          CONTINUE
               DO 110 J = LP1, P
                  CALL SAXPY(N-L,-E(J)/E(LP1),WORK(LP1),1,X(LP1,J),1)
  110          CONTINUE
  120       CONTINUE
            IF (.NOT.WANTV) GO TO 140
!
!              PLACE THE TRANSFORMATION IN V FOR SUBSEQUENT
!              BACK MULTIPLICATION.
!
               DO 130 I = LP1, P
                  V(I,L) = E(I)
  130          CONTINUE
  140       CONTINUE
  150    CONTINUE
  160 CONTINUE
  170 CONTINUE
!
!     SET UP THE FINAL BIDIAGONAL MATRIX OR ORDER M.
!
      M = MIN0(P,N+1)
      NCTP1 = NCT + 1
      NRTP1 = NRT + 1
      IF (NCT .LT. P) S(NCTP1) = X(NCTP1,NCTP1)
      IF (N .LT. M) S(M) = 0.0E0
      IF (NRTP1 .LT. M) E(NRTP1) = X(NRTP1,M)
      E(M) = 0.0E0
!
!     IF REQUIRED, GENERATE U.
!
      IF (.NOT.WANTU) GO TO 300
         IF (NCU .LT. NCTP1) GO TO 200
         DO 190 J = NCTP1, NCU
            DO 180 I = 1, N
               U(I,J) = 0.0E0
  180       CONTINUE
            U(J,J) = 1.0E0
  190    CONTINUE
  200    CONTINUE
         IF (NCT .LT. 1) GO TO 290
         DO 280 LL = 1, NCT
            L = NCT - LL + 1
            IF (S(L) .EQ. 0.0E0) GO TO 250
               LP1 = L + 1
               IF (NCU .LT. LP1) GO TO 220
               DO 210 J = LP1, NCU
                  T = -SDOT(N-L+1,U(L,L),1,U(L,J),1)/U(L,L)
                  CALL SAXPY(N-L+1,T,U(L,L),1,U(L,J),1)
  210          CONTINUE
  220          CONTINUE
               CALL SSCAL(N-L+1,-1.0E0,U(L,L),1)
               U(L,L) = 1.0E0 + U(L,L)
               LM1 = L - 1
               IF (LM1 .LT. 1) GO TO 240
               DO 230 I = 1, LM1
                  U(I,L) = 0.0E0
  230          CONTINUE
  240          CONTINUE
            GO TO 270
  250       CONTINUE
               DO 260 I = 1, N
                  U(I,L) = 0.0E0
  260          CONTINUE
               U(L,L) = 1.0E0
  270       CONTINUE
  280    CONTINUE
  290    CONTINUE
  300 CONTINUE
!
!     IF IT IS REQUIRED, GENERATE V.
!
      IF (.NOT.WANTV) GO TO 350
         DO 340 LL = 1, P
            L = P - LL + 1
            LP1 = L + 1
            IF (L .GT. NRT) GO TO 320
            IF (E(L) .EQ. 0.0E0) GO TO 320
               DO 310 J = LP1, P
                  T = -SDOT(P-L,V(LP1,L),1,V(LP1,J),1)/V(LP1,L)
                  CALL SAXPY(P-L,T,V(LP1,L),1,V(LP1,J),1)
  310          CONTINUE
  320       CONTINUE
            DO 330 I = 1, P
               V(I,L) = 0.0E0
  330       CONTINUE
            V(L,L) = 1.0E0
  340    CONTINUE
  350 CONTINUE
!
!     MAIN ITERATION LOOP FOR THE SINGULAR VALUES.
!
      MM = M
      ITER = 0
  360 CONTINUE
!
!        QUIT IF ALL THE SINGULAR VALUES HAVE BEEN FOUND.
!
!     ...EXIT
         IF (M .EQ. 0) GO TO 620
!
!        IF TOO MANY ITERATIONS HAVE BEEN PERFORMED, SET
!        FLAG AND RETURN.
!
         IF (ITER .LT. MAXIT) GO TO 370
            INFO = M
!     ......EXIT
            GO TO 620
  370    CONTINUE
!
!        THIS SECTION OF THE PROGRAM INSPECTS FOR
!        NEGLIGIBLE ELEMENTS IN THE S AND E ARRAYS.  ON
!        COMPLETION THE VARIABLES KASE AND L ARE SET AS FOLLOWS.
!
!           KASE = 1     IF S(M) AND E(L-1) ARE NEGLIGIBLE AND L.LT.M
!           KASE = 2     IF S(L) IS NEGLIGIBLE AND L.LT.M
!           KASE = 3     IF E(L-1) IS NEGLIGIBLE, L.LT.M, AND
!                        S(L), ..., S(M) ARE NOT NEGLIGIBLE (QR STEP).
!           KASE = 4     IF E(M-1) IS NEGLIGIBLE (CONVERGENCE).
!
         DO 390 LL = 1, M
            L = M - LL
!        ...EXIT
            IF (L .EQ. 0) GO TO 400
            TEST = ABS(S(L)) + ABS(S(L+1))
            ZTEST = TEST + ABS(E(L))
            IF (ZTEST .NE. TEST) GO TO 380
               E(L) = 0.0E0
!        ......EXIT
               GO TO 400
  380       CONTINUE
  390    CONTINUE
  400    CONTINUE
         IF (L .NE. M - 1) GO TO 410
            KASE = 4
         GO TO 480
  410    CONTINUE
            LP1 = L + 1
            MP1 = M + 1
            DO 430 LLS = LP1, MP1
               LS = M - LLS + LP1
!           ...EXIT
               IF (LS .EQ. L) GO TO 440
               TEST = 0.0E0
               IF (LS .NE. M) TEST = TEST + ABS(E(LS))
               IF (LS .NE. L + 1) TEST = TEST + ABS(E(LS-1))
               ZTEST = TEST + ABS(S(LS))
               IF (ZTEST .NE. TEST) GO TO 420
                  S(LS) = 0.0E0
!           ......EXIT
                  GO TO 440
  420          CONTINUE
  430       CONTINUE
  440       CONTINUE
            IF (LS .NE. L) GO TO 450
               KASE = 3
            GO TO 470
  450       CONTINUE
            IF (LS .NE. M) GO TO 460
               KASE = 1
            GO TO 470
  460       CONTINUE
               KASE = 2
               L = LS
  470       CONTINUE
  480    CONTINUE
         L = L + 1
!
!        PERFORM THE TASK INDICATED BY KASE.
!
         GO TO (490,520,540,570), KASE
!
!        DEFLATE NEGLIGIBLE S(M).
!
  490    CONTINUE
            MM1 = M - 1
            F = E(M-1)
            E(M-1) = 0.0E0
            DO 510 KK = L, MM1
               K = MM1 - KK + L
               T1 = S(K)
               CALL SROTG(T1,F,CS,SN)
               S(K) = T1
               IF (K .EQ. L) GO TO 500
                  F = -SN*E(K-1)
                  E(K-1) = CS*E(K-1)
  500          CONTINUE
               IF (WANTV) CALL SROT(P,V(1,K),1,V(1,M),1,CS,SN)
  510       CONTINUE
         GO TO 610
!
!        SPLIT AT NEGLIGIBLE S(L).
!
  520    CONTINUE
            F = E(L-1)
            E(L-1) = 0.0E0
            DO 530 K = L, M
               T1 = S(K)
               CALL SROTG(T1,F,CS,SN)
               S(K) = T1
               F = -SN*E(K)
               E(K) = CS*E(K)
               IF (WANTU) CALL SROT(N,U(1,K),1,U(1,L-1),1,CS,SN)
  530       CONTINUE
         GO TO 610
!
!        PERFORM ONE QR STEP.
!
  540    CONTINUE
!
!           CALCULATE THE SHIFT.
!
            SCALE = AMAX1(ABS(S(M)),ABS(S(M-1)),ABS(E(M-1)),ABS(S(L)),   &
                          ABS(E(L)))
            SM = S(M)/SCALE
            SMM1 = S(M-1)/SCALE
            EMM1 = E(M-1)/SCALE
            SL = S(L)/SCALE
            EL = E(L)/SCALE
            B = ((SMM1 + SM)*(SMM1 - SM) + EMM1**2)/2.0E0
            C = (SM*EMM1)**2
            SHIFT = 0.0E0
            IF (B .EQ. 0.0E0 .AND. C .EQ. 0.0E0) GO TO 550
               SHIFT = SQRT(B**2+C)
               IF (B .LT. 0.0E0) SHIFT = -SHIFT
               SHIFT = C/(B + SHIFT)
  550       CONTINUE
            F = (SL + SM)*(SL - SM) - SHIFT
            G = SL*EL
!
!           CHASE ZEROS.
!
            MM1 = M - 1
            DO 560 K = L, MM1
               CALL SROTG(F,G,CS,SN)
               IF (K .NE. L) E(K-1) = F
               F = CS*S(K) + SN*E(K)
               E(K) = CS*E(K) - SN*S(K)
               G = SN*S(K+1)
               S(K+1) = CS*S(K+1)
               IF (WANTV) CALL SROT(P,V(1,K),1,V(1,K+1),1,CS,SN)
               CALL SROTG(F,G,CS,SN)
               S(K) = F
               F = CS*E(K) + SN*S(K+1)
               S(K+1) = -SN*E(K) + CS*S(K+1)
               G = SN*E(K+1)
               E(K+1) = CS*E(K+1)
               IF (WANTU .AND. K .LT. N)   &
                  CALL SROT(N,U(1,K),1,U(1,K+1),1,CS,SN)
  560       CONTINUE
            E(M-1) = F
            ITER = ITER + 1
         GO TO 610
!
!        CONVERGENCE.
!
  570    CONTINUE
!
!           MAKE THE SINGULAR VALUE  POSITIVE.
!
            IF (S(L) .GE. 0.0E0) GO TO 580
               S(L) = -S(L)
               IF (WANTV) CALL SSCAL(P,-1.0E0,V(1,L),1)
  580       CONTINUE
!
!           ORDER THE SINGULAR VALUE.
!
  590       IF (L .EQ. MM) GO TO 600
!           ...EXIT
               IF (S(L) .GE. S(L+1)) GO TO 600
               T = S(L)
               S(L) = S(L+1)
               S(L+1) = T
               IF (WANTV .AND. L .LT. P)   &
                  CALL SSWAP(P,V(1,L),1,V(1,L+1),1)
               IF (WANTU .AND. L .LT. N)   &
                  CALL SSWAP(N,U(1,L),1,U(1,L+1),1)
               L = L + 1
            GO TO 590
  600       CONTINUE
            ITER = 0
            M = M - 1
  610    CONTINUE
      GO TO 360
  620 CONTINUE
      RETURN
      END SUBROUTINE SSVDC
      SUBROUTINE SSWAP(N,SX,INCX,SY,INCY)
!***BEGIN PROLOGUE  SSWAP
!***DATE WRITTEN   791001   (YYMMDD)
!***REVISION DATE  820801   (YYMMDD)
!***CATEGORY NO.  D1A5
!***KEYWORDS  BLAS,INTERCHANGE,LINEAR ALGEBRA,VECTOR
!***AUTHOR  LAWSON, C. L., (JPL)
!           HANSON, R. J., (SNLA)
!           KINCAID, D. R., (U. OF TEXAS)
!           KROGH, F. T., (JPL)
!***PURPOSE  Interchange s.p vectors
!***DESCRIPTION
!
!                B L A S  Subprogram
!    Description of Parameters
!
!     --Input--
!        N  number of elements in input vector(s)
!       SX  single precision vector with N elements
!     INCX  storage spacing between elements of SX
!       SY  single precision vector with N elements
!     INCY  storage spacing between elements of SY
!
!     --Output--
!       SX  input vector SY (unchanged if N .LE. 0)
!       SY  input vector SX (unchanged if N .LE. 0)
!
!     Interchange single precision SX and single precision SY.
!     For I = 0 to N-1, interchange  SX(LX+I*INCX) and SY(LY+I*INCY),
!     where LX = 1 if INCX .GE. 0, else LX = (-INCX)*N, and LY is
!     defined in a similar way using INCY.
!***REFERENCES  LAWSON C.L., HANSON R.J., KINCAID D.R., KROGH F.T.,
!                 *BASIC LINEAR ALGEBRA SUBPROGRAMS FOR FORTRAN USAGE*,
!                 ALGORITHM NO. 539, TRANSACTIONS ON MATHEMATICAL
!                 SOFTWARE, VOLUME 5, NUMBER 3, SEPTEMBER 1979, 308-323
!***ROUTINES CALLED  (NONE)
!***END PROLOGUE  SSWAP
!
      REAL SX(*),SY(*),STEMP1,STEMP2,STEMP3
!***FIRST EXECUTABLE STATEMENT  SSWAP
      IF(N.LE.0)RETURN
!CCCC JUNE 2008: MODIFY FOLLOWING LINE SO THAT IT DOES NOT
!CCCC            GENERATE WARNING MESSAGE ON FORTRAN 95 COMPILERS.
!
!CCCC IF(INCX.EQ.INCY) IF(INCX-1) 5,20,60
      IF(INCX.EQ.INCY) THEN
        IF(INCX-1.LT.0)THEN
          GO TO 5
        ELSEIF(INCX-1.EQ.0)THEN
          GO TO 20
        ELSE
          GO TO 60
        ENDIF
      ENDIF
    5 CONTINUE
!
!       CODE FOR UNEQUAL OR NONPOSITIVE INCREMENTS.
!
      IX = 1
      IY = 1
      IF(INCX.LT.0)IX = (-N+1)*INCX + 1
      IF(INCY.LT.0)IY = (-N+1)*INCY + 1
      DO 10 I = 1,N
        STEMP1 = SX(IX)
        SX(IX) = SY(IY)
        SY(IY) = STEMP1
        IX = IX + INCX
        IY = IY + INCY
   10 CONTINUE
      RETURN
!
!       CODE FOR BOTH INCREMENTS EQUAL TO 1
!
!
!       CLEAN-UP LOOP SO REMAINING VECTOR LENGTH IS A MULTIPLE OF 3.
!
   20 M = MOD(N,3)
      IF( M .EQ. 0 ) GO TO 40
      DO 30 I = 1,M
        STEMP1 = SX(I)
        SX(I) = SY(I)
        SY(I) = STEMP1
   30 CONTINUE
      IF( N .LT. 3 ) RETURN
   40 MP1 = M + 1
      DO 50 I = MP1,N,3
        STEMP1 = SX(I)
        STEMP2 = SX(I+1)
        STEMP3 = SX(I+2)
        SX(I) = SY(I)
        SX(I+1) = SY(I+1)
        SX(I+2) = SY(I+2)
        SY(I) = STEMP1
        SY(I+1) = STEMP2
        SY(I+2) = STEMP3
   50 CONTINUE
      RETURN
   60 CONTINUE
!
!     CODE FOR EQUAL, POSITIVE, NONUNIT INCREMENTS.
!
      NS = N*INCX
        DO 70 I=1,NS,INCX
        STEMP1 = SX(I)
        SX(I) = SY(I)
        SY(I) = STEMP1
   70   CONTINUE
      RETURN
      END SUBROUTINE SSWAP
      SUBROUTINE START1(A,X,Y,IMX,NS,CN,XC,YC,ISUBRO,IBUGG3)
!
!     PURPOSE--XX
!
!     WRITTEN BY--DAVID W. BEHRINGER NOAA/AOML (MIAMI).
!                 AS PART OF NOAA'S CONCX V.3   MARCH 1988.
!     ORIGINAL VERSION (IN DATAPLOT)--AUGUST    1988.
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGG3
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOCP.INC'
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!CCCC DIMENSION A(IMX,2),X(2),Y(2)   AUGUST 1988
!
      DIMENSION A(MAXIMX,2)
      DIMENSION X(2)
      DIMENSION Y(2)
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'ART1')THEN
        WRITE(ICOUT,51)IMX,MAXIMX
   51   FORMAT('START1: IMX,MAXIMX = ',2I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
        DNM=A(1,1)-A(1,2)
        IF (DNM.NE.0.) THEN
          R=(CN-A(1,2))/DNM
        ELSE
          R=-1.
        END IF
        IF ((R.GT.0..AND.R.LT.1.).OR.   &
           (R.EQ.0..AND.DNM.LT.0.).OR.   &
           (R.EQ.1..AND.DNM.GT.0.)) THEN
          XC=X(1)
          YC=Y(2)+R*(Y(1)-Y(2))
        ELSE
          NS=-1
        END IF
      RETURN
      END SUBROUTINE START1
